-- BARYCZ

-- Spot 1: Łąki (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70000, 'Barycz - Odcinek Łąki Dolne', 'barycz-laki-dolne', 'RIVER', 51.4929782, 17.1509168, 'Dolnośląskie', 'Łąki', 'Barycz w tym miejscu jest leniwa, ale skrywa głębokie rynny przy trzcinowiskach. To idealne stanowisko dla miłośników lekkiego gruntu oraz technicznego spławika. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dorodnych linów oraz złotych karasi. Wiosną warto zapolować na jaziową „srebrną łuskę” żerującą na płytszych przelewach. Uciąg jest znikomy, więc koszyki o wadze 20 gramów w zupełności wystarczą do stabilnego łowienia. Miejsce jest wyjątkowo zaciszne i osłonięte od wiatru gęstą ścianą przybrzeżnej roślinności.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70000, 'Nizinna Mała', 'Leniwy nurt, liczne meandry', 15.0, 1.5, 'Piaszczysto-muliste', 'Trzcinowiska', 'Lin, Karaś złoty, Jaź', 'Kraina leszcza', 'Obszar Natura 2000', false);

-- Spot 2: Łąki (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70001, 'Barycz - Podmyte Korzenie Łąki', 'barycz-podmyte-korzenie-laki', 'RIVER', 51.4895556, 17.1223052, 'Dolnośląskie', 'Łąki', 'Odcinek rzeki charakteryzuje się licznymi nawisami drzew, pod którymi chętnie ustawiają się klenie. Woda płynie tu nieco żwawiej, tworząc ciekawe zawirowania przy mocno podmytych brzegach. Spinningiści znajdą tutaj doskonałe warunki do prowadzenia małych woblerów oraz smużaków. Rybostan obfituje w szczupaki, które czają się w gęstych kępach roślinności podwodnej. Dno pozostaje zróżnicowane z przewagą twardego piasku w głównym nurcie rzeki. Jest to punkt wybitnie techniczny, wymagający precyzyjnych rzutów i cichego podejścia do stanowiska.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70001, 'Nizinna Mała', 'Urozmaicone zatorami', 12.0, 1.2, 'Piasek i glina', 'Zwalone drzewa', 'Kleń, Szczupak, Okoń', 'Kraina leszcza', 'Dolina Baryczy', false);

-- Spot 3: Ruda Żmigrodzka (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70002, 'Barycz - Ruda Żmigrodzka Zakole', 'barycz-ruda-zmigrodzka-zakole', 'RIVER', 51.4864458, 17.0915818, 'Dolnośląskie', 'Ruda Żmigrodzka', 'Barycz w okolicach Rudy Żmigrodzkiej to królestwo nizinnego krajobrazu z szerokimi zakolami. Głębokość w tym rejonie rzadko przekracza dwa metry, co sprzyja rozwojowi bogatej flory. Wędkarze stacjonarni mogą liczyć na regularne brania leszczy oraz płoci o pokaźnych rozmiarach. Strategiczne rozmieszczenie zanęty na granicy nurtu i spokojnej wody przynosi tutaj najlepsze rezultaty. Brzeg jest tu dość wysoki, co daje doskonałą perspektywę do obserwacji żerujących przy powierzchni ryb. Wieczorami na piaszczystych łachach często słychać głośne i agresywne uderzenia polujących boleni.','PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70002, 'Nizinna Mała', 'Szerokie rozlewisko', 20.0, 1.8, 'Piaszczyste', 'Brak stałych budowli', 'Leszcz, Płoć, Boleń', 'Kraina leszcza', 'Brak', false);

-- Spot 4: Ruda Żmigrodzka (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70003, 'Barycz - Ruda Żmigrodzka Przewężenie', 'barycz-ruda-zmigrodzka-przewezenie', 'RIVER', 51.4814919, 17.0629755, 'Dolnośląskie', 'Ruda Żmigrodzka', 'W tym miejscu rzeka wyraźnie się zwęża, co powoduje przyspieszenie nurtu i wymywanie głębszych dołków. Jest to klasyczne miejsce na gruntową zasiadkę z nastawieniem na większe ryby spokojnego żeru. Brzegi są gęsto porośnięte wikliną, co tworzy naturalne parawany chroniące wędkarza przed wiatrem. Woda jest tu dobrze natleniona, co przyciąga aktywne ryby nawet w upalne, letnie dni. Dno twarde i czyste pozwala na komfortowe prowadzenie przynęt spinningowych bez obaw o częste zaczepy. Dojazd polną drogą jest możliwy, jednak wymaga dużej ostrożności po intensywnych opadach deszczu.','PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70003, 'Nizinna Mała', 'Nurt przyspieszony', 10.0, 2.2, 'Twarde, żwirowe', 'Zwaliska kamieni', 'Jaź, Kleń, Brzana (sporadycznie)', 'Kraina leszcza', 'Brak', false);

-- Spot 5: Kowalowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70004, 'Barycz - Kowalowo Płanie', 'barycz-kowalowo-planie', 'RIVER', 51.5685277, 16.6656974, 'Dolnośląskie', 'Kowalowo', 'Barycz pod Kowalowem to odcinek o charakterze niemal kanałowym ze stabilnym poziomem wody. Dominują tu spokojne płanie, które są domem dla rekordowych wzdręg oraz dorodnych okoni. Roślinność brzegowa jest tu rzadsza, co ułatwia dostęp do lustra wody mniej mobilnym wędkarzom. Wykorzystanie długiego wędziska typu bat pozwala na bardzo precyzyjne punktowanie ryb w pasie przybrzeżnym. Dno jest tu równomierne i pokryte cienką warstwą osadów organicznych przyciągających rybią drobnicę. To doskonałe łowisko na rodzinne wypady, zapewniające częste brania i bliski kontakt z naturą.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70004, 'Nizinna Mała', 'Uregulowane, spokojne', 18.0, 1.4, 'Muliste', 'Grążele', 'Wzdręga, Okoń, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 6: Wąsosz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70005, 'Barycz - Wąsosz (Mosty)', 'barycz-wasosz-mosty', 'RIVER', 51.5796227, 16.6424911, 'Dolnośląskie', 'Wąsosz', 'Barycz w Wąsoszu to miejsce o zmiennym charakterze, gdzie rzeka zaczyna nieco bardziej meandrować. Woda pod mostami tworzy głębokie rynny, które są naturalnym schronieniem dla sandacza i szczupaka. Dno w tym rejonie jest twarde i żwirowe, z nielicznymi naniesionymi kłodami drzew. Uciąg jest umiarkowany, co pozwala na precyzyjne operowanie lekkimi jigami w okolicach filarów. Latem brzegi porastają grążele, w których cieniu czają się dorodne klenie oraz jazie. To stanowisko jest szczególnie cenione przez spinningistów szukających technicznych wyzwań w miejskim krajobrazie.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70005, 'Nizinna Mała', 'Uregulowane koryto z rynnami', 14.0, 1.6, 'Żwirowo-kamieniste', 'Filary mostów, opaski', 'Sandacz, Szczupak, Jaź', 'Kraina leszcza', 'Brak', false);

-- Spot 7: Grabowno (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70006, 'Barycz - Grabowno Zachodnie', 'barycz-grabowno-zachodnie', 'RIVER', 51.5899361, 16.6187575, 'Dolnośląskie', 'Grabowno', 'Odcinek w Grabownie to kwintesencja nizinnej rzeki z licznymi zastoiskami i wstecznymi prądami. Wąskie koryto wymusza na wędkarzu stosowanie krótkich wędzisk, ułatwiających manewrowanie między gęstymi krzakami. Dno jest tu piaszczyste z lokalnymi warstwami mułu, co sprzyja bytowaniu dużych stad leszczy. Warkocze powstające za naturalnymi przeszkodami to pewne miejsca na spotkanie z żerującym boleniem. Nurt jest spokojny, dzięki czemu łowienie na delikatne zestawy z drgającą szczytówką przynosi doskonałe efekty. Cisza panująca w tej okolicy sprawia, że ryby są mniej płochliwe, ale wymagają bardzo dyskretnego podejścia.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70006, 'Nizinna Mała', 'Dzika, zarośnięta', 10.0, 1.2, 'Piaszczysto-muliste', 'Zatory z gałęzi', 'Leszcz, Boleń, Płoć', 'Kraina leszcza', 'Obszar chroniony', false);

-- Spot 8: Wierzowice Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70007, 'Barycz - Wierzowice Wielkie Rozlewisko', 'barycz-wierzowice-wielkie', 'RIVER', 51.5951497, 16.5909999, 'Dolnośląskie', 'Wierzowice Wielkie', 'Wierzowice Wielkie oferują dostęp do szerokich rozlewisk Baryczy, gdzie rzeka wyraźnie zwalnia swój bieg. Główny nurt przesuwa się tu bliżej stromego brzegu, tworząc wymyte jamy idealne dla sumów. Dno charakteryzuje się dużą ilością roślinności podwodnej, która stanowi schronienie dla narybku i drapieżników. Przy dnie często można spotkać liny, które chętnie pobierają przynętę w pobliżu pasów trzcin. Uciąg jest niemal niewyczuwalny, co umożliwia stosowanie najlżejszych spławików typu waggler. To miejsce słynie wśród lokalnych wędkarzy jako jedna z najlepszych „linowych” miejscówek w regionie.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70007, 'Nizinna Mała', 'Szerokie, wolno płynące', 22.0, 2.0, 'Zarośnięte, miękkie', 'Trzcinowiska', 'Lin, Sum, Karaś srebrzysty', 'Kraina leszcza', 'Brak', false);

-- Spot 9: Grabowno (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70008, 'Barycz - Grabowno (Zakręt)', 'barycz-grabowno-zakret', 'RIVER', 51.6070663, 16.5692735, 'Dolnośląskie', 'Grabowno', 'Drugi punkt w Grabownie to odcinek o urozmaiconej linii brzegowej z wieloma zatoczkami. Woda w tym miejscu jest nieco głębsza, sięgając w najniższych punktach rynny nawet do trzech metrów. Dno jest zróżnicowane, przechodząc z twardego piasku w żyzną glinę przy burtach. Podmyte korzenie starych wierzb to bankowe stanowiska dla kleni i okoni uderzających w małe obrotówki. Nurt rzeki jest jednostajny i przewidywalny, co ułatwia systematyczne nęcenie pola łowiska. Wieczorne wyprawy z martwą rybką mogą zakończyć się tu emocjonującym holem solidnego sandacza.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70008, 'Nizinna Mała', 'Głębokie zakola', 12.0, 2.5, 'Piasek i glina', 'Zwalone drzewa', 'Sandacz, Kleń, Okoń', 'Kraina leszcza', 'Brak', false);

-- Spot 10: Ryczeń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70009, 'Barycz - Ryczeń (Jaz)', 'barycz-ryczen-jaz', 'RIVER', 51.6120211, 16.541416, 'Dolnośląskie', 'Ryczeń', 'Ryczeń to odcinek Baryczy, który wędkarze wybierają ze względu na unikalne połączenie rzeki z systemem melioracyjnym. Woda ma tu nieco większą przejrzystość, co zmusza do stosowania bardzo cienkich przyponów żyłkowych. Dno jest przeważnie twarde, co sprawia, że jest to doskonałe miejsce do nauki prowadzenia gum na lekkich główkach. Uciąg wody jest uzależniony od pracy okolicznych urządzeń hydrotechnicznych, co znacząco wpływa na aktywność żerowania ryb. Dominują tu jazie i płocie, które przyciągają miłośników delikatnego feedera oraz metody przystawki. Dostęp do wody jest wygodny, co czyni to miejsce idealnym na szybki, popołudniowy wypad z jedną wędką.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70009, 'Nizinna Mała', 'Koryto zmodernizowane', 15.0, 1.5, 'Twarde', 'Jazy, śluzy', 'Jaź, Płoć, Okoń', 'Kraina leszcza', 'Zakaz połowu w bliskiej odległości od śluz', false);

-- Spot 11: Ryczeń (Dolny odcinek)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70010, 'Barycz - Ryczeń Zachodni', 'barycz-ryczen-zachodni', 'RIVER', 51.6140968, 16.5122781, 'Dolnośląskie', 'Ryczeń', 'Ten odcinek rzeki charakteryzuje się piaszczystym dnem z licznymi, twardymi przykosami. Nurt jest tu wyraźnie zaznaczony, co sprzyja dotlenieniu wody nawet w okresach letnich niżówek. Wędkarze mogą liczyć na regularne brania kleni, które chętnie ustawiają się w cieniu nadbrzeżnych krzewów. Najlepszą metodą na tym fragmencie rzeki jest lekki spinning z wykorzystaniem małych woblerów o agresywnej pracy. Wieczorami na płytsze przelewy wychodzą żerować jazie, które można kusić na przynęty roślinne lub drobne owady. Brzeg jest tu naturalny i miejscami stromy, co wymaga zachowania ostrożności przy schodzeniu do samej wody.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70010, 'Nizinna Mała', 'Nurt wyraźny, dno piaszczyste', 14.0, 1.3, 'Piasek i drobny żwir', 'Podmyte brzegi', 'Kleń, Jaź, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 12: Ryczeń (Granica lasu)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70011, 'Barycz - Ryczeń Leśna Prosta', 'barycz-ryczen-lesna-prosta', 'RIVER', 51.6216909, 16.4859002, 'Dolnośląskie', 'Ryczeń', 'Barycz wchodzi tutaj w bardziej zalesiony teren, co owocuje dużą ilością zwalonych drzew w korycie. Takie naturalne zatory tworzą głębokie doły, w których często stacjonują rekordowe szczupaki. Dno staje się tutaj bardziej zróżnicowane z przewagą gliny i naniesionego detrytusu organicznego. Spokojna woda przy brzegach to idealne miejsce na stacjonarną zasiadkę z nastawieniem na dorodnego lina. Uciąg rzeki jest tu minimalny, co pozwala na precyzyjne punktowanie zanętą wybranego pola łowiska. Jest to odcinek wybitnie techniczny, nagradzający wędkarzy potrafiących precyzyjnie kłaść zestaw obok przeszkód.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70011, 'Nizinna Mała', 'Meandrująca wśród lasu', 12.0, 1.8, 'Gliniano-muliste', 'Zatopione pnie (karpy)', 'Szczupak, Lin, Okoń', 'Kraina leszcza', 'Dolina Baryczy', false);

-- Spot 13: Osetno (Okolice mostu)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70012, 'Barycz - Osetno Mostowe Rynny', 'barycz-osetno-mostowe-rynny', 'RIVER', 51.6316699, 16.4604932, 'Dolnośląskie', 'Osetno', 'W okolicach Osetna rzeka posiada specyficzny mikroklimat ze względu na bliskość starych konstrukcji hydrotechnicznych. Pod filarami oraz na obrzeżach nurtu tworzą się głębokie rynny o twardym, kamienistym dnie. To idealne żerowisko dla sandaczy, które wychodzą na polowanie w okresach porannych i wieczornych mgieł. Nurt rzeki jest tu średni, co ułatwia prowadzenie cięższych gum oraz kogutów przy samym dnie. W klatkach między naturalnymi opaskami często meldują się stada grubych leszczy i certy. Łowisko jest łatwo dostępne z obu brzegów, co czyni je bardzo popularnym punktem na mapie lokalnych wędkarzy.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70012, 'Nizinna Mała', 'Uregulowane koryto z rynnami', 16.0, 2.2, 'Kamienisto-żwirowe', 'Filary mostu, umocnienia', 'Sandacz, Leszcz, Certa', 'Kraina leszcza', 'Brak', false);

-- Spot 14: Osetno (Łąki)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70013, 'Barycz - Osetno Łąkowe Zakola', 'barycz-osetno-lakowe-zakola', 'RIVER', 51.6402236, 16.4346148, 'Dolnośląskie', 'Osetno', 'Na tym odcinku Barycz szeroko rozlewa się pośród łąk, tworząc malownicze i spokojne zakola. Dno jest tu w większości piaszczyste, z rzadka porośnięte kępami moczarki kanadyjskiej i rdestnicy. Płytkie, nagrzane słońcem woda przyciąga duże ilości białorybu, głównie płoci oraz krasnopiórek. To idealne miejsce na metodę „drgającej szczytówki” lub klasyczną przystawkę ze spławikiem. Uciąg jest niemal niezauważalny, co pozwala na stosowanie bardzo lekkich i czułych zestawów końcowych. Brak drzew na brzegach ułatwia dalekie rzuty i holowanie ryb bez ryzyka zaplątania zestawu w gałęzie.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70013, 'Nizinna Mała', 'Rozlewiska łąkowe', 20.0, 1.4, 'Piasek', 'Roślinność zanurzona', 'Płoć, Wzdręga, Boleń', 'Kraina leszcza', 'Brak', false);

-- Spot 15: Lipowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70014, 'Barycz - Lipowiec Ujście', 'barycz-lipowiec-ujscie', 'RIVER', 51.642999, 16.4058932, 'Dolnośląskie', 'Lipowiec', 'Odcinek w Lipowcu to jedno z ostatnich stanowisk przed ujściem Baryczy do wielkiej rzeki Odry. Woda ma tu specyficzny charakter, gdyż często występuje tu tzw. cofka przy wysokich stanach wód głównych. Dno jest tu bardzo bogate w pokarm, co przyciąga niemal wszystkie gatunki ryb występujące w dorzeczu. Można tu liczyć na spotkanie z potężnym sumem, który chętnie patroluje głębsze partie koryta. Uciąg jest zmienny i mocno uzależniony od poziomu wody w Odrze, co wymaga od wędkarza elastyczności. Miejsce to jest dzikie i rzadko odwiedzane, co gwarantuje spokój i bliski kontakt z surową naturą rzeczną.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70014, 'Nizinna Średnia', 'Ujściowy charakter', 25.0, 2.5, 'Zróżnicowane (piach/glina)', 'Zmienne ukształtowanie', 'Sum, Boleń, Brzana', 'Kraina leszcza', 'Obszar Natura 2000', true);

-- Spot 16: Lipowiec (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70015, 'Barycz - Lipowiec (Dziki Odcinek)', 'barycz-lipowiec-dziki', 'RIVER', 51.6490089, 16.3765631, 'Dolnośląskie', 'Lipowiec', 'Barycz w okolicach Lipowca to odcinek o charakterze niemal dzikim, gdzie nurt wyraźnie żłobi zewnętrzne łuki zakoli. Dno jest tutaj piaszczysto-gliniaste z licznymi rynnami, które sięgają dwóch metrów głębokości. Spinningiści mogą tu liczyć na spotkanie z walecznym boleniem, który chętnie patroluje środek nurtu. Brzegi są porośnięte gęstą wikliną, co wymaga od wędkarza umiejętności precyzyjnych rzutów spod siebie. Uciąg rzeki jest umiarkowany, dlatego koszyki zanętowe o wadze 30-40 gramów będą optymalnym wyborem. Wieczorne zasiadki na grunt często owocują braniami dorodnych leszczy oraz sporych krąpi.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70015, 'Nizinna Mała', 'Nurt wyraźny, dno piaszczyste', 18.0, 1.6, 'Piasek i glina', 'Podmyte brzegi', 'Boleń, Leszcz, Krąp', 'Kraina leszcza', 'Brak', false);

-- Spot 17: Żabin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70016, 'Barycz - Żabin (Leśne Zakole)', 'barycz-zabin-zakole', 'RIVER', 51.663583, 16.3593414, 'Dolnośląskie', 'Żabin', 'Odcinek rzeki przy Żabinie to raj dla miłośników cichego podchodzenia klenia oraz jazia. Woda płynie tu spokojnie, a liczne zwalone pnie drzew tworzą doskonałe stanowiska dla drapieżników. Dno jest w przeważającej części pokryte drobnym żwirem, co sprzyja tarłu wielu gatunków ryb. Warto tu zastosować technikę przepływanki z przystawką, celując w głębsze partie koryta pod drugim brzegiem. Roślinność brzegowa jest na tyle rzadka, że pozwala na komfortowe wędkowanie dłuższą odległościówką. Czystość wody w tym miejscu sprawia, że ryby są wyjątkowo ostrożne i wymagają stosowania cienkich przyponów fluorocarbonowych.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70016, 'Nizinna Mała', 'Spokojny nurt, zatory', 15.0, 1.4, 'Żwirowe', 'Zwalone drzewa', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 18: Bartodzieje
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70017, 'Barycz - Bartodzieje (Podmyte Burty)', 'barycz-bartodzieje-burty', 'RIVER', 51.6776657, 16.3393033, 'Dolnośląskie', 'Bartodzieje', 'W Bartodziejach Barycz staje się rzeką nieprzewidywalną, z częstymi zmianami głębokości na krótkich odcinkach. Dominują tu podmyte burty, pod którymi w ciągu dnia odpoczywają szczupaki oraz większe okonie. Nurt jest jednostajny, a dno charakteryzuje się występowaniem twardych, gliniastych progów. Dobrym rozwiązaniem jest łowienie na martwą rybkę, co na tym odcinku często przynosi rekordowe rezultaty. Stanowiska wędkarskie są naturalne i wymagają wydeptania, co podkreśla dziki charakter tego łowiska. Ze względu na bliskość lasu, komary bywają tu uciążliwe, ale aktywność ryb w pełni to wynagradza.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70017, 'Nizinna Mała', 'Zmienna głębokość', 14.0, 1.8, 'Glina i piach', 'Burty brzegowe', 'Szczupak, Okoń, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 19: Klimontów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70018, 'Barycz - Klimontów (Rozlewisko)', 'barycz-klimontow-rozlewisko', 'RIVER', 51.691394, 16.3199656, 'Dolnośląskie', 'Klimontów', 'Klimontów oferuje dostęp do bardzo ciekawego technicznie fragmentu rzeki z licznymi wstecznymi prądami. Woda w zakolach potrafi wymyć głębokie doły, które są ulubionym miejscem bytowania sumów. Dno jest tu mocno zróżnicowane, od piaszczystych łach po muliste zatoczki z grążelami. Spinningowanie wzdłuż pasów roślinności zanurzonej to sprawdzona metoda na tutejsze dorodne drapieżniki. Uciąg jest tu słaby, co czyni ten odcinek idealnym do testowania nowych mieszanek zanętowych na białoryb. Dostęp do wody jest dość dobry, a otwarty teren pozwala na swobodne operowanie dłuższą wędką gruntową.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70018, 'Nizinna Mała', 'Niskie brzegi, szerokie zakola', 20.0, 1.5, 'Piasek i muł', 'Kępy grążeli', 'Sum, Leszcz, Wzdręga', 'Kraina leszcza', 'Brak', false);

-- Spot 21: Szlichtyngowa (Ujście do Odry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70020, 'Barycz - Szlichtyngowa (Ujście)', 'barycz-szlichtyngowa-ujscie', 'RIVER', 51.6860672, 16.2576105, 'Lubuskie', 'Szlichtyngowa', 'Barycz w rejonie Szlichtyngowej to fascynujący odcinek ujściowy, gdzie rzeka bezpośrednio łączy się z potężną Odrą. Woda w tym miejscu często wykazuje zjawisko cofki, co sprawia, że głębokość w rynnach drastycznie wzrasta. Dno jest tu twarde, piaszczyste i wymyte przez ścierające się nurty obu rzek. To strategiczne miejsce dla łowców okazów, gdyż wchodzą tu wielkie odrzańskie sumy oraz sandacze. Uciąg jest zmienny, dlatego warto mieć w torbie ciężarki o szerokim spektrum wagowym. Brzegi są dzikie, ale zapewniają kilka dogodnych stanowisk do oddawania dalekich rzutów w stronę głównego nurtu.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70020, 'Nizinna Średnia', 'Ujściowy, zmienny nurt', 30.0, 2.8, 'Twarde, piaszczyste', 'Naturalne rynny', 'Sum, Sandacz, Boleń, Brzana', 'Kraina leszcza', 'Strefa przyujściowa', true);

-- Spot 22: Płoski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70021, 'Barycz - Płoski (Łąkowy Odcinek)', 'barycz-ploski-laki', 'RIVER', 51.5451969, 16.7017762, 'Dolnośląskie', 'Płoski', 'Odcinek w Płoskach charakteryzuje się kameralną atmosferą i krystalicznie czystą wodą płynącą wśród łąk. Koryto jest tu dość wąskie, co ułatwia precyzyjne podawanie przynęty pod przeciwległy brzeg. Dominującym gatunkiem jest tu kleń oraz jaź, które doskonale reagują na małe smużaki i obrotówki. Dno jest w większości piaszczyste, z wyraźnymi kępami roślinności podwodnej stanowiącej kryjówki dla szczupaka. Nurt jest jednostajny i łagodny, idealny do prowadzenia zestawów spławikowych typu bolonka. Dojazd na miejsce jest bezproblemowy, a liczne ścieżki pozwalają na długie, spinningowe marsze wzdłuż rzeki.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70021, 'Nizinna Mała', 'Naturalne, meandrujące', 12.0, 1.3, 'Piasek i roślinność', 'Kępy moczarki', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 23: Ruda Żmigrodzka (Punkt 3)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70022, 'Barycz - Ruda Żmigrodzka (Ostoja)', 'barycz-ruda-zmigrodzka-ostoja', 'RIVER', 51.4824933, 17.0164008, 'Dolnośląskie', 'Ruda Żmigrodzka', 'Ruda Żmigrodzka to serce Parku Krajobrazowego Dolina Baryczy, co przekłada się na niesamowitą rybność odcinka. Rzeka w tym miejscu mocno meandruje, tworząc głębokie rynny na zewnętrznych łukach koryta. Dno jest tu miękkie i żyzne, co sprzyja bytowaniu potężnych linów oraz złotych karasi. Uciąg jest minimalny, więc lekkie zestawy typu feeder z koszykiem 15-20 gramów sprawdzą się idealnie. Przybrzeżne pasy trzcin są ostoją dla szczupaków, które chętnie atakują większe, gumowe przynęty. Cisza i spokój panujące na łowisku wymagają od wędkarza pełnego kamuflażu i braku głośnych zachowań.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70022, 'Nizinna Mała', 'Bardzo kręte koryto', 15.0, 1.8, 'Mulisto-gliniaste', 'Zarośla trzcinowe', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Rezerwat przyrody (sprawdź regulamin)', false);

-- Spot 24: Osiek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70023, 'Barycz - Osiek (Zatory)', 'barycz-osiek-zatory', 'RIVER', 51.4813749, 16.9857179, 'Dolnośląskie', 'Osiek', 'Okolice Osieka to klasyczna nizinna woda z bardzo bogatą infrastrukturą naturalnych kryjówek dla ryb. Można tu spotkać liczne zatory z gałęzi, za którymi woda wyraźnie zwalnia, tworząc bezpieczne ostoje dla białorybu. Głębokość jest tu stabilna i oscyluje wokół półtora metra w głównym nurcie. Dno gliniaste jest doskonałym podłożem dla larw owadów, co przyciąga stada wyrośniętych płoci i krąpi. Wędkarze spławikowi docenią ten odcinek za brak uciążliwych zaczepów przy dnie w wybranych rynnach. To świetne miejsce na kilkugodzinną sesję z batem, gwarantującą dużą częstotliwość brań mniejszych osobników.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70023, 'Nizinna Mała', 'Spokojna rzeka nizinna', 13.0, 1.5, 'Gliniaste', 'Naturalne zatory', 'Płoć, Krąp, Okoń', 'Kraina leszcza', 'Brak', false);

-- Spot 25: Kanclerzowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70024, 'Barycz - Kanclerzowice (Płytkie Płanie)', 'barycz-kanclerzowice-planie', 'RIVER', 51.4813369, 16.9564485, 'Dolnośląskie', 'Kanclerzowice', 'W Kanclerzowicach Barycz płynie otwartym terenem, co sprzyja aktywności ryb lubiących nasłonecznione partie wody. Dno jest tu piaszczyste z lokalnymi wypłyceniami, na których w słoneczne dni żerują stada uklei. Nurt jest na tyle słaby, że pozwala na skuteczne łowienie delikatnymi zestawami bez obciążenia własnego. Podmyte brzegi na prostych odcinkach skrywają ładne okonie, które agresywnie reagują na boczny trok. Brak wysokich drzew ułatwia wędkowanie podczas wietrznych dni, ograniczając ryzyko splątania zestawu. To łowisko polecane szczególnie początkującym adeptom wędkarstwa ze względu na łatwy dostęp do lustra wody.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70024, 'Nizinna Mała', 'Odkryte koryto', 10.0, 1.1, 'Piaszczyste', 'Brak większych przeszkód', 'Okoń, Ukleja, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 26: Żmigródek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70025, 'Barycz - Żmigródek (Most Kolejowy)', 'barycz-zmigrodek-most', 'RIVER', 51.4817002, 16.9272294, 'Dolnośląskie', 'Żmigródek', 'Żmigródek to odcinek o nieco większej presji wędkarskiej, ale wciąż oferujący szanse na spotkanie z rekordową rybą. Rzeka staje się tu nieco głębsza, a nurt wyraźniej żłobi koryto przy betonowych wzmocnieniach mostowych. Dno jest tu twarde i czyste, co jest kluczowe dla miłośników nocnego łowienia sandacza na trupka. Przy wyższym stanie wody warto szukać ryb w spokojniejszych zatoczkach za naturalnymi przelewami. Gatunkiem dominującym na tym fragmencie są leszcze, które bardzo dobrze reagują na nęcenie grubszą frakcją. Stanowiska są tu dobrze przygotowane i stabilne, co pozwala na komfortowe rozłożenie profesjonalnego sprzętu gruntowego.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70025, 'Nizinna Mała', 'Uregulowane koryto miejskie', 18.0, 2.1, 'Twarde, piaszczyste', 'Betonowe wzmocnienia, filary', 'Leszcz, Sandacz, Jaź', 'Kraina leszcza', 'Okolice mostu kolejowego', false);

-- Spot 27: Żmigród
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70026, 'Barycz - Żmigród (Park)', 'barycz-zmigrod-park', 'RIVER', 51.4806131, 16.8969152, 'Dolnośląskie', 'Żmigród', 'Odcinek w Żmigrodzie to klasyczne miejskie łowisko z bardzo dobrym dostępem do linii brzegowej. Rzeka płynie tu uregulowanym korytem, ale skrywa głębokie rynny w okolicach zabytkowego parku. Dno jest piaszczysto-żwirowe, co przyciąga stada aktywnych kleni oraz jelców żerujących w nurcie. Warto skupić się na łowieniu lekkim feederem, celując w miejsca z wyraźniejszym uciągiem wody. Roślinność przybrzeżna jest tu systematycznie przycinana, co ułatwia rozstawienie profesjonalnego stanowiska wędkarskiego. To idealne miejsce na szybki wypad, gdzie szansa na branie wyrośniętego leszcza jest bardzo wysoka.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70026, 'Nizinna Mała', 'Uregulowane koryto miejskie', 16.0, 1.4, 'Piaszczysto-żwirowe', 'Umocnienia brzegowe', 'Leszcz, Kleń, Jelec', 'Kraina leszcza', 'Brak', false);

-- Spot 28: Wróbliniec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70027, 'Barycz - Wróbliniec (Górny bieg)', 'barycz-wrobliniec-gora', 'RIVER', 51.5461369, 17.5585641, 'Dolnośląskie', 'Milicz', 'Wróbliniec to górny odcinek Baryczy, gdzie rzeka ma charakter niemal potoku o bystrym nurcie. Woda jest tu płytka i bardzo przejrzysta, co wymaga od wędkarza zachowania szczególnej ciszy. Dno pokryte jest grubym żwirem oraz otoczakami, tworząc idealne warunki dla ryb lubiących tlen. Spinningiści znajdą tutaj doskonałe rynny do prowadzenia mikrojigów w poszukiwaniu dorodnych okoni. Ze względu na wąskie koryto, najskuteczniejszą techniką jest podawanie przynęty precyzyjnie pod nawisy traw. To dzikie stanowisko rzadko odwiedzane przez ludzi, co gwarantuje pełny spokój podczas wędkowania.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70027, 'Nizinna Mała', 'Bystry, wąski nurt', 8.0, 0.8, 'Żwirowe', 'Naturalne progi', 'Okoń, Pstrąg potokowy (sporadycznie), Jaź', 'Kraina pstrąga/lipienia', 'Dolina Baryczy', false);

-- Spot 29: Henrykowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70028, 'Barycz - Henrykowice (Moczary)', 'barycz-henrykowice-moczary', 'RIVER', 51.5444332, 17.5273718, 'Dolnośląskie', 'Milicz', 'Odcinek w Henrykowicach charakteryzuje się powolnym przepływem i bardzo silnym zakrzaczeniem brzegów. Woda jest tu ciemniejsza, o lekko torfowym zabarwieniu, co sprzyja bytowaniu dużych linów. Dno jest miękkie i obfituje w pokarm naturalny, przyciągając ryby spokojnego żeru z całego dorzecza. Najlepsze efekty daje tu metoda spławikowa z wykorzystaniem naturalnych przynęt takich jak czerwony robak. Wiele stanowisk wymaga przedzierania się przez gęste zarośla, ale trud ten wynagradzają waleczne szczupaki. To typowa „dzicz”, gdzie woda żyje własnym rytmem, a ryby rzadko widują haczyk.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70028, 'Nizinna Mała', 'Leniwy nurt, bagniste brzegi', 10.0, 1.2, 'Muliste', 'Zalane krzewy', 'Lin, Szczupak, Karaś złoty', 'Kraina leszcza', 'Brak', false);

-- Spot 30: Gądkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70029, 'Barycz - Gądkowice (Leśny Odcinek)', 'barycz-gadkowice-las', 'RIVER', 51.5470161, 17.4986338, 'Dolnośląskie', 'Milicz', 'W Gądkowicach Barycz przepływa przez tereny leśne, co skutkuje dużą ilością zwalonych pni w wodzie. Każdy taki zator to potencjalne stanowisko dla grubego klenia lub czającego się w cieniu szczupaka. Nurt jest tu zmienny, z licznymi przyspieszeniami na zwężeniach i spokojną wodą w zatoczkach. Dno jest piaszczyste, ale w dołkach za przeszkodami często zalega warstwa liści i gałęzi. Wędkarze spinningowi powinni uzbroić się w przynęty z systemem antyzaczepowym ze względu na liczne przeszkody. To łowisko wymagające technicznie, ale dające szansę na kontakt z prawdziwymi okazami dzikiej rzeki.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70029, 'Nizinna Mała', 'Leśna rzeka z zatorami', 11.0, 1.5, 'Piasek i detrytus', 'Zwalone drzewa', 'Kleń, Szczupak, Okoń', 'Kraina leszcza', 'Obszar Natura 2000', false);

-- Spot 31: Pracze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70030, 'Barycz - Pracze (Łąkowe Zakola)', 'barycz-pracze-zakola', 'RIVER', 51.4994277, 17.2065476, 'Dolnośląskie', 'Sułów', 'Okolice Pracz to szeroko rozlane zakola Baryczy, otoczone malowniczymi nadwarciańskimi łąkami. Woda ma tu umiarkowany uciąg, co sprzyja systematycznemu nęceniu i łowieniu na feedera. Dno jest przeważnie piaszczyste i równe, co znacznie ogranicza liczbę rrywanych zestawów końcowych. W nurcie często meldują się ładne jazie, które agresywnie atakują białe robaki oraz kukurydzę. Brzegi są niskie i trawiaste, co zapewnia ogromny komfort przy podbieraniu większych ryb. Jest to świetne miejsce na rodzinne wędkowanie, gdzie każdy znajdzie dogodne i bezpieczne miejsce na brzegu.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70030, 'Nizinna Mała', 'Szerokie, otwarte zakola', 18.0, 1.6, 'Piaszczyste', 'Brak', 'Jaź, Leszcz, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 32: Sułów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70031, 'Barycz - Sułów (Jaz)', 'barycz-sulow-jaz', 'RIVER', 51.4906099, 17.1805041, 'Dolnośląskie', 'Sułów', 'Sułów to jedno z najbardziej znanych łowisk na Baryczy, słynące z potężnej budowli hydrotechnicznej. Woda poniżej jazu jest silnie natleniona i wzburzona, co przyciąga brzany oraz duże klenie. Dno w tym miejscu jest twarde, kamieniste i bardzo stabilne, mimo silnego uciągu wody. Wędkarze najczęściej stosują tu ciężkie koszyki zanętowe, które stabilizują zestaw w głównym nurcie. Należy pamiętać o zachowaniu przepisowej odległości od urządzeń piętrzących wodę podczas wędkowania. To łowisko dla osób ceniących dynamiczną wodę i siłowe hole ryb przyzwyczajonych do walki z prądem.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70031, 'Nizinna Mała', 'Woda płynąca, uregulowana', 20.0, 2.0, 'Kamienisto-betonowe', 'Jaz, śluzy', 'Brzana, Kleń, Boleń', 'Kraina brzany', 'Obręb ochronny przy jazie', false);

-- Spot 33: Topola Wielka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70032, 'Barycz - Topola Wielka (Górna)', 'barycz-topola-wielka', 'RIVER', 51.5820367, 17.7378311, 'Wielkopolskie', 'Topola Wielka', 'Barycz w Topoli Wielkiej to kameralny odcinek o charakterze niemal kanałowym. Woda płynie tu spokojnym, uregulowanym korytem, co sprzyja rekreacyjnemu łowieniu na spławik. Dno jest w większości piaszczyste, z rzadka porośnięte roślinnością zanurzoną. Dominującymi gatunkami są tu płocie, wzdręgi oraz niewielkie okonie czające się przy brzegach. Ze względu na niewielką szerokość rzeki, warto stosować lekkie zestawy i ciche podejście do stanowiska. Jest to świetne miejsce na trening przed zawodami spławikowymi lub szybki wypad z batem.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70032, 'Nizinna Mała', 'Uregulowane koryto', 8.0, 1.1, 'Piaszczyste', 'Brak', 'Płoć, Wzdręga, Okoń', 'Kraina leszcza', 'Brak', false);

-- Spot 34: Tarchały Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70033, 'Barycz - Tarchały Wielkie (Zakola)', 'barycz-tarchaly-wielkie', 'RIVER', 51.5804901, 17.7031868, 'Wielkopolskie', 'Tarchały Wielkie', 'Odcinek rzeki w Tarchałach Wielkich to typowa nizinna woda z wyraźnie zaznaczonymi zakolami. Nurt jest tu zmienny, przyspieszający na przewężeniach, co stwarza świetne warunki dla kleni. Dno charakteryzuje się występowaniem twardych, gliniastych blatów oraz podmytych burt. Spinningiści często meldują tu brania szczupaków, które wybierają zacienione miejsca pod nawisami traw. Uciąg rzeki pozwala na komfortowe łowienie lekkim feederem przy użyciu koszyków o wadze do 20 gramów. Brzegi są łatwo dostępne, choć wymagają odpowiedniego obuwia ze względu na podmokły charakter łąk.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70033, 'Nizinna Mała', 'Naturalne zakola', 10.0, 1.3, 'Gliniaste', 'Podmyte burty', 'Kleń, Szczupak, Jaź', 'Kraina leszcza', 'Brak', false);

-- Spot 35: Odolanów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70034, 'Barycz - Odolanów (Węzeł)', 'barycz-odolanow-wezel', 'RIVER', 51.57694, 17.674509, 'Wielkopolskie', 'Odolanów', 'Barycz w Odolanowie to jeden z najbardziej technicznych odcinków w górnym biegu rzeki. Miejska zabudowa i liczne umocnienia hydrotechniczne tworzą zróżnicowane stanowiska dla ryb drapieżnych. Woda pod mostami żłobi głębsze rynny, w których często stacjonują wyrośnięte okonie i klenie. Dno jest tu w dużej mierze twarde, piaszczysto-żwirowe, co ułatwia prowadzenie przynęt gumowych. W okresach letnich poziom wody bywa niski, co wymusza na wędkarzach szukanie ryb w głębszych patiach koryta. To doskonała baza wypadowa dla spinningistów lubiących dynamiczne łowienie w ruchu.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70034, 'Nizinna Mała', 'Uregulowane koryto miejskie', 12.0, 1.4, 'Piaszczysto-żwirowe', 'Mosty, murki oporowe', 'Okoń, Kleń, Szczupak', 'Kraina leszcza', 'Odcinek miejski', false);

-- Spot 36: Boników
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70035, 'Barycz - Boników (Torfowiska)', 'barycz-bonikow-torfowiska', 'RIVER', 51.5653078, 17.6513219, 'Wielkopolskie', 'Odolanów', 'Odcinek w Bonikowie to fragment rzeki płynący wśród rozległych kompleksów łąkowych i torfowisk. Barycz staje się tu nieco szersza, a jej nurt wyraźnie zwalnia w stronę leniwego przepływu. Muliste dno i bogactwo fauny bezkręgowej przyciąga w to miejsce dorodne liny oraz karasie. Wędkarze gruntowi powinni stawiać na przynęty zwierzęce, które najlepiej sprawdzają się w tej ciemniejszej wodzie. Liczne kępy grążeli i strzałki wodnej stanowią naturalną osłonę dla czających się w zasadzce szczupaków. Cisza panująca na tym odcinku sprawia, że jest to idealne łowisko dla osób szukających ucieczki od miejskiego zgiełku.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70035, 'Nizinna Mała', 'Leniwy nurt, rozlewiska', 14.0, 1.5, 'Muliste', 'Kępy grążeli', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Obszar Chronionego Krajobrazu', false);

-- Spot 37: Raczyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70036, 'Barycz - Raczyce (Meandry)', 'barycz-raczyce-meandry', 'RIVER', 51.5633288, 17.6224365, 'Wielkopolskie', 'Odolanów', 'W Raczycach rzeka Barycz zachowuje swój naturalny wdzięk, meandrując przez dziewicze tereny doliny. Koryto rzeki obfituje w liczne zagłębienia i piaszczyste przykosy, na których żerują stadne jazie. Nurt jest umiarkowany, co sprzyja łowieniu na przepływankę z lekkim spławikiem typu bombka. Dno jest zróżnicowane, piaszczysto-gliniaste, z niewielką ilością zaczepów w postaci zatopionych gałęzi. Jesienią miejsce to staje się mekką dla spinningistów polujących na aktywne szczupaki i wyrośnięte pasiak. Dobry dojazd oraz dogodne miejsca do parkowania czynią ten odcinek bardzo przyjaznym dla zmotoryzowanych wędkarzy.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70036, 'Nizinna Mała', 'Meandrujące', 11.0, 1.2, 'Piasek i glina', 'Brak', 'Jaź, Szczupak, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 38: Uciechów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70037, 'Barycz - Uciechów (Łąki)', 'barycz-uciechow-laki', 'RIVER', 51.5573914, 17.5943585, 'Wielkopolskie', 'Odolanów', 'Barycz w Uciechowie to odcinek o charakterze wybitnie nizinnym, płynący wśród rozległych i otwartych łąk. Dno jest tu piaszczyste, z rzadka przerywane kępami rdestnicy oraz moczarki kanadyjskiej. Nurt płynie spokojnie, co sprzyja łowieniu na bardzo czułe zestawy spławikowe oraz lekki feeder. Wędkarze mogą liczyć na regularne brania płoci oraz dorodnych wzdręg żerujących w pasie przybrzeżnym. Brzegi są niskie i łatwo dostępne, co ułatwia bezpieczne podebranie ryby bez konieczności wchodzenia do wody. To doskonałe miejsce na relaks z wędką w ciszy, z dala od głównej zabudowy miejscowości.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70037, 'Nizinna Mała', 'Spokojny nurt, otwarte koryto', 9.0, 1.2, 'Piaszczyste', 'Brak', 'Płoć, Wzdręga, Jaź', 'Kraina leszcza', 'Brak', false);

-- Spot 39: Ruda Milicka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70038, 'Barycz - Ruda Milicka (Ostoja)', 'barycz-ruda-milicka-ostoja', 'RIVER', 51.5561903, 17.3727799, 'Dolnośląskie', 'Milicz', 'Ruda Milicka to strategiczny punkt na mapie Baryczy, położony w samym sercu Parku Krajobrazowego. Woda ma tutaj ciemniejszy odcień i umiarkowany uciąg, a koryto jest gęsto porośnięte trzcinowiskami. Dno gliniasto-muliste kryje pokaźne liny oraz karasie, które są wizytówką tego fragmentu rzeki. Spinningiści powinni szukać szczupaków w pobliżu jazów i zastawek regulujących poziom wody w okolicznych stawach. Ze względu na ochronę przyrody, należy zachować szczególną dyskrecję i dbać o czystość na zajmowanym stanowisku. Najlepsze efekty przynosi tu łowienie o świcie, gdy ryby wychodzą na żer w płytkie partie brzegowe.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70038, 'Nizinna Mała', 'Przywodna, wśród stawów', 12.0, 1.5, 'Gliniasto-muliste', 'Jazy stawowe', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Obszar Natura 2000', false);

-- Spot 40: Gądkowice (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70039, 'Barycz - Gądkowice (Rozlewisko Dolne)', 'barycz-gadkowice-rozlewisko-dolne', 'RIVER', 51.552999, 17.4709833, 'Dolnośląskie', 'Milicz', 'Odcinek w Gądkowicach charakteryzuje się szerokim korytem i wolnym przepływem wody bogatej w osady organiczne. To idealne miejsce na stacjonarną zasiadkę z cięższym zestawem spławikowym nastawionym na grubego leszcza. Dno jest miękkie, ale stabilne, co pozwala na skuteczne nęcenie grubszą frakcją zanętową i pelletem. W cieniu nadbrzeżnych drzew często chowają się dorodne klenie, które można skusić smużakiem lub czereśnią. Nurt rzeki jest tu niemal niezauważalny, co czyni łowisko bardzo komfortowym nawet podczas wietrznej pogody. Stanowiska są tu dobrze wydeptane, jednak warto zabrać ze sobą długi podbierak ze względu na pas trzcin.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70039, 'Nizinna Mała', 'Szerokie, wolne koryto', 15.0, 1.8, 'Muliste', 'Brak', 'Leszcz, Płoć, Kleń', 'Kraina leszcza', 'Brak', false);

-- Spot 41: Gądkowice (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70040, 'Barycz - Gądkowice (Meandry Leśne)', 'barycz-gadkowice-meandry-lesne', 'RIVER', 51.5584854, 17.4409041, 'Dolnośląskie', 'Milicz', 'Nieco dalej w górę nurtu rzeka zaczyna gwałtownie meandrować, tworząc głębokie i ciemne jamy pod korzeniami. To klasyczne stanowiska szczupakowe, gdzie drapieżniki czekają na przepływającą drobnicę w absolutnym bezruchu. Dno jest tu urozmaicone, piaszczysto-żwirowe z licznymi naniesionymi gałęziami, co wymaga od wędkarza dużej precyzji. Spinningowanie z wykorzystaniem gum na lekkich główkach pozwala na dokładne spenetrowanie każdej przybrzeżnej rynny. Uciąg wody w tym miejscu jest nieco silniejszy, co wyraźnie natlenia wodę i aktywizuje ryby do żerowania. Bliskość lasu gwarantuje cień w upalne dni, ale utrudnia dalekie rzuty klasyczną wędką gruntową.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70040, 'Nizinna Mała', 'Meandrująca, leśna', 10.0, 2.0, 'Piaszczysto-żwirowe', 'Zwalone drzewa', 'Szczupak, Okoń, Kleń', 'Kraina leszcza', 'Dolina Baryczy', false);

-- Spot 42: Nowy Zamek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70041, 'Barycz - Nowy Zamek (Jaz)', 'barycz-nowy-zamek-jaz', 'RIVER', 51.5580638, 17.4079341, 'Dolnośląskie', 'Milicz', 'Nowy Zamek to jedno z najbardziej technicznych miejsc na tym odcinku ze względu na obecność spiętrzeń. Woda poniżej progu jest mocno napowietrzona i niesie dużo pokarmu, co przyciąga stadne ryby z dołu rzeki. Dno jest twarde i wymyte do gołego żwiru, co czyni je idealnym poligonem dla łowców brzan. Nurt jest tu rwaną linią, wymagającą stosowania cięższych i bardziej stabilnych zestawów końcowych typu feeder. Warkocze powstające za konstrukcją to pewne miejsca na spotkanie z agresywnym boleniem polującym przy powierzchni. Należy pamiętać o zachowaniu dystansu od budowli wodnej zgodnie z aktualnym regulaminem amatorskiego połowu ryb.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70041, 'Nizinna Mała', 'Nurt przyspieszony, techniczny', 14.0, 1.4, 'Żwirowe', 'Jaz, betonowe progi', 'Brzana, Kleń, Boleń', 'Kraina brzany', 'Strefa ochronna przy jazie', false);

-- Spot 43: Gajdówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70042, 'Barycz - Gajdówka (Zator)', 'barycz-gajdowka-zator', 'RIVER', 51.5530882, 17.3303758, 'Dolnośląskie', 'Milicz', 'Gajdówka to odcinek rzeki płynący przez gęsto zarośnięte tereny, co nadaje mu unikalnego, dzikiego charakteru. Koryto rzeki jest tu węższe, a nurt wyraźnie żłobi głębokie rynny pod brzegami porośniętymi starodrzewem. Dno jest piaszczyste z lokalnymi naniesieniami mułu w zakolach, gdzie często można spotkać wyrośnięte krąpie. Spinningiści cenią to miejsce za dużą populację okonia, który chętnie grupuje się przy zatopionych gałęziach. Dojście do wody wymaga przedzierania się przez zarośla, co skutecznie eliminuje przypadkowych turystów i zapewnia spokój. To łowisko dla osób ceniących kontakt z naturą i potrafiących łowić w trudnych, technicznych warunkach.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70042, 'Nizinna Mała', 'Zarośnięte, naturalne koryto', 8.0, 1.3, 'Piasek i muł', 'Zatory z gałęzi', 'Okoń, Krąp, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 44: Milicz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70043, 'Barycz - Milicz (Odcinek Miejski)', 'barycz-milicz-miejska', 'RIVER', 51.53043, 17.250583, 'Dolnośląskie', 'Milicz', 'Miejski odcinek Baryczy w Miliczu to miejsce, gdzie tradycja wędkarska łączy się z doskonałą infrastrukturą brzegową. Rzeka płynie tu szerokim, uregulowanym korytem, oferując wygodne stanowiska na obu brzegach dla wędkarzy stacjonarnych. Dno jest wyrównane, piaszczyste i w większości pozbawione uciążliwych zaczepów, co sprzyja metodzie spławikowej. Dominują tu leszcze oraz jazie, które bardzo dobrze reagują na systematyczne nęcenie drobną zanętą spożywczą. Uciąg wody jest stały i umiarkowany, co pozwala na idealną prezentację przynęty w głównym nurcie rzeki. To łowisko idealne na popołudniowy relaks, zapewniające dużą częstotliwość brań białorybu niemal przez cały rok.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70043, 'Nizinna Mała', 'Uregulowane, wyrównane', 18.0, 1.6, 'Piaszczyste', 'Umocnienia brzegowe', 'Leszcz, Jaź, Płoć', 'Kraina leszcza', 'Odcinek miejski', false);

-- Spot 45: Wszewilki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70044, 'Barycz - Wszewilki (Starorzecze)', 'barycz-wszewilki-starorzecze', 'RIVER', 51.5423966, 17.3063917, 'Dolnośląskie', 'Milicz', 'Odcinek we Wszewilkach charakteryzuje się kameralnym korytem o umiarkowanym uciągu wody. Dno jest tu piaszczysto-muliste, co tworzy idealne warunki dla dorodnych linów i złotych karasi. Wzdłuż brzegów gęsto rosną trzciny, które są naturalną kryjówką dla szczupaków czających się w zasadzce. Wędkarze spławikowi docenią ten fragment za brak silnych wirów i przewidywalną pracę zestawu. Najlepsze efekty daje tu precyzyjne nęcenie punktowe w pasie roślinności przybrzeżnej. Dojazd do wody jest dogodny, choć wymaga pokonania krótkiego odcinka drogi gruntowej przez łąki.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
