-- Spot 46: Milicz (ul. Krotoszyńska/Stawna)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70045, 'Barycz - Milicz (Wschodnia)', 'barycz-milicz-wschodnia', 'RIVER', 51.535206, 17.2788502, 'Dolnośląskie', 'Milicz', 'Barycz we wschodniej części Milicza to odcinek o nieco silniejszym uciągu i twardszym dnie. Nurt rzeki wyraźnie żłobi rynnę w środkowej części koryta, gdzie często ustawiają się klenie. Betonowe umocnienia przy przepustach to doskonałe miejsca na spinningowe polowanie za okoniem. Warto tu zastosować metodę lekkiego feedera z wykorzystaniem czerwonych robaków jako przynęty. Dominują tu jazie oraz wyrośnięte płocie, które bardzo dobrze reagują na nęcenie drobnym pelletem. Stanowiska są stabilne i często odwiedzane przez lokalnych wędkarzy ze względu na łatwy dostęp.', 'PZW Wrocław');

