-- Spot 47: Świętoszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70046, 'Barycz - Świętoszyn (Meandry)', 'barycz-swietoszyn-meandry', 'RIVER', 51.516719, 17.2318575, 'Dolnośląskie', 'Milicz', 'Odcinek w Świętoszynie to jeden z najbardziej malowniczych fragmentów rzeki, obfitujący w dzikie zakola. Woda jest tu głęboka na zewnętrznych łukach, tworząc ciemne i bezpieczne schronienia dla ryb. Dno piaszczyste z licznymi naniesionymi gałęziami wymaga od spinningisty dużej uwagi przy prowadzeniu wabika. To idealne miejsce na polowanie na szczupaka przy użyciu dużych, wolno prowadzonych wahadłówek. Nurt rzeki jest zmienny, co sprawia, że ryby są tu bardzo aktywne i waleczne podczas holu. Cisza i brak bliskiej zabudowy sprawiają, że można tu liczyć na bliski kontakt z naturą.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70046, 'Nizinna Mała', 'Bardzo kręte koryto', 12.0, 1.8, 'Piaszczyste', 'Zwalone drzewa', 'Szczupak, Okoń, Jaź', 'Kraina leszcza', 'Dolina Baryczy', false);

-- Spot 48: Bychowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70047, 'Barycz - Bychowo (Głębokie Doły)', 'barycz-bychowo-doly', 'RIVER', 51.4923671, 16.8725497, 'Dolnośląskie', 'Żmigród', 'Barycz w Bychowie słynie z głębokich rynien, które utrzymują się nawet podczas letnich upałów. Dno jest tu w dużej mierze gliniaste, co sprawia, że woda bywa lekko mętna po opadach. To wymarzone miejsce dla łowców brzan, które chętnie żerują w najsilniejszym nurcie rzeki. Spinningiści z sukcesami stosują tu cięższe jigi, szukając sandaczy w najgłębszych patiach koryta. Uciąg jest tu wyraźnie wyczuwalny, co wymusza stosowanie koszyków zanętowych o masie powyżej 30 gramów. Brzegi są dość strome, co daje wędkarzowi dobrą widoczność, ale utrudnia podebranie ryby bez długiego podbieraka.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70047, 'Nizinna Mała', 'Nurt silny, koryto żłobione', 15.0, 2.2, 'Gliniaste', 'Naturalne progi', 'Brzana, Sandacz, Leszcz', 'Kraina brzany', 'Brak', false);

-- Spot 49: Kędzie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70048, 'Barycz - Kędzie (Zastoiska)', 'barycz-kedzie-zastoiska', 'RIVER', 51.5020046, 16.8481086, 'Dolnośląskie', 'Wąsosz', 'W okolicach miejscowości Kędzie rzeka zwalnia, tworząc szerokie i spokojne zastoiska wody. Dno jest tu miękkie, piaszczysto-muliste, obfitujące w larwy ochotki i inne bezkręgowce. Jest to doskonały odcinek dla miłośników metody spławikowej, szczególnie przy łowieniu wyrośniętych wzdręg. Roślinność podwodna tworzy gęste dywany, które są domem dla licznej populacji okonia. Niskie i trawiaste brzegi pozwalają na komfortowe rozstawienie stanowiska nawet z dużą ilością sprzętu. To łowisko o niskiej presji wędkarskiej, co gwarantuje spokój podczas długich, weekendowych zasiadek.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70048, 'Nizinna Mała', 'Nurt wolny, koryto szerokie', 18.0, 1.5, 'Muliste', 'Dywny roślinne', 'Wzdręga, Okoń, Leszcz', 'Kraina leszcza', 'Brak', false);

-- Spot 50: Chodlewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70049, 'Barycz - Chodlewo (Pod Nawisami)', 'barycz-chodlewo-nawisy', 'RIVER', 51.5115001, 16.8235176, 'Dolnośląskie', 'Wąsosz', 'Odcinek w Chodlewie to królestwo kleni i jazi żerujących pod nawisami starych wierzb. Rzeka płynie tu naturalnym korytem z licznymi przewężeniami, gdzie woda wyraźnie przyspiesza. Dno jest twarde, piaszczyste, z rzadkimi kamiennymi narzutami przy brzegach. spinningista powinien skupić się na precyzyjnym podawaniu małych woblerów tuż pod sam przeciwległy brzeg. W chłodniejsze dni warto spróbować metody gruntowej z wykorzystaniem aromatyzowanego ciasta lub pelletu. To miejsce wymaga od wędkarza dużej dyskrecji, gdyż ryby w tej krystalicznej wodzie są wyjątkowo płochliwe.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70049, 'Nizinna Mała', 'Nurt zmienny, brzegi zadrzewione', 11.0, 1.2, 'Twarde, piaszczyste', 'Nawisy drzew', 'Kleń, Jaź, Okoń', 'Kraina leszcza', 'Brak', false);

-- Spot 51: Bartków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70050, 'Barycz - Bartków (Równia)', 'barycz-bartkow-rownia', 'RIVER', 51.5149612, 16.7594454, 'Dolnośląskie', 'Wąsosz', 'W Bartkowie Barycz przybiera charakter spokojnej równi o bardzo wyrównanej głębokości koryta. Dno jest piaszczyste i wolne od zaczepów, co ułatwia łowienie na dłuższą odległość. To idealne miejsce na zasiadkę z metodą „method feeder” w poszukiwaniu rzecznych leszczy. Woda jest tu dobrze nasłoneczniona, co sprzyja aktywności ryb spokojnego żeru niemal przez cały dzień. Przy brzegach można zaobserwować liczne stada uklei, które przyciągają w to miejsce drapieżne bolenie. Dobry dostęp do wody i możliwość zaparkowania auta w pobliżu brzegu to duże atuty tego odcinka.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70050, 'Nizinna Mała', 'Koryto proste, wyrównane', 14.0, 1.4, 'Piaszczyste', 'Brak', 'Leszcz, Boleń, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 52: Ługi
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70051, 'Barycz - Ługi (Zastoiska)', 'barycz-lugi-zastoiska', 'RIVER', 51.527796, 16.7387223, 'Dolnośląskie', 'Wąsosz', 'Barycz w miejscowości Ługi to odcinek o charakterze wybitnie nizinnym z licznymi zastoiskami wody. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dorodnych linów oraz karasi srebrzystych. Nurt płynie leniwie, pozwalając na precyzyjne nęcenie punktowe przy użyciu lekkich zestawów spławikowych. Przy brzegach znajdziemy pasy trzcin, które są naturalną bazą wypadową dla szczupaków czających się na drobnicę. Wędkarze cenią to miejsce za święty spokój i brak dużej presji ze strony turystów kajakowych. Dojazd prowadzi przez drogi polne, które po deszczu mogą wymagać auta z wyższym zawieszeniem.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70051, 'Nizinna Mała', 'Spokojny nurt, koryto naturalne', 12.0, 1.4, 'Piaszczysto-muliste', 'Pasy trzcin', 'Lin, Karaś, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 53: Bartków (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70052, 'Barycz - Bartków (Rynny)', 'barycz-bartkow-rynny', 'RIVER', 51.5061727, 16.7920479, 'Dolnośląskie', 'Wąsosz', 'Okolice Bartkowa to odcinek rzeki z wyraźnie zaznaczonymi rynnami w środkowej części koryta. Dno jest tu twarde, piaszczyste, co czyni je idealnym poligonem dla spinningistów polujących na okonie. Uciąg wody jest stabilny, co ułatwia prowadzenie przynęt takich jak obrotówki czy małe jigi. Wieczorami na piaszczyste łachy wychodzą żerować jazie, które agresywnie zbierają owady z powierzchni wody. Brzeg jest tu w większości niski, porośnięty trawą, co zapewnia wysoki komfort podczas wielogodzinnych zasiadek. To świetne łowisko dla osób szukających powtarzalnych wyników w połowie białorybu na klasycznego feedera.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70052, 'Nizinna Mała', 'Nurt stabilny, koryto proste', 11.0, 1.3, 'Piaszczyste', 'Brak', 'Okoń, Jaź, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 54: Spalony
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70053, 'Barycz - Spalony (Bystrze)', 'barycz-spalony-bystrze', 'RIVER', 51.608908, 18.0302646, 'Wielkopolskie', 'Odolanów', 'W Spalonym Barycz ma charakter niemalże potoku, z bardzo wąskim korytem i bystrym nurtem. Woda jest tu płytka i krystalicznie czysta, co zmusza wędkarza do pełnego maskowania na brzegu. Dno żwirowo-kamieniste jest doskonałym siedliskiem dla kleni, które grupują się w cieniu nawisów drzew. Spinningista powinien postawić na mikro-przynęty, które najlepiej imitują naturalny pokarm występujący w tym rejonie. Ze względu na specyfikę terenu, łowienie długimi wędziskami jest tu mocno utrudnione przez gęstą roślinność. To wymagające technicznie stanowisko, które potrafi nagrodzić wytrwałych wędkarzy pięknymi, dzikimi rybami.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70053, 'Nizinna Mała', 'Wąski, szybki nurt', 5.0, 0.7, 'Żwirowo-kamieniste', 'Nawisy drzew', 'Kleń, Okoń, Jaź', 'Kraina pstrąga (potencjalnie)', 'Brak', false);

-- Spot 55: Wydarta
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70054, 'Barycz - Wydarta (Prosta)', 'barycz-wydarta-prosta', 'RIVER', 51.6123942, 18.0012793, 'Wielkopolskie', 'Odolanów', 'Odcinek w Wydartej to klasyczna „rzeczna prosta” z kilkoma bardzo ciekawymi wymyciami pod samym brzegiem. Dno piaszczyste z lokalnymi warstwami gliny sprzyja bytowaniu płoci oraz wyrośniętych krąpi. Nurt jest tu jednostajny, co pozwala na idealne ustawienie zestawu z tzw. „przystawką” spławikową. Ryby w tym miejscu są bardzo waleczne i świetnie reagują na nęcenie gruboziarnistą zanętą z dodatkiem kukurydzy. Brzeg jest dostępny i suchy, co czyni go dobrym wyborem na rodzinne wypady z wędką. To bezpieczne łowisko, gdzie rzadko dochodzi do zerwania zestawu na podwodnych przeszkodach.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70054, 'Nizinna Mała', 'Uregulowane, jednostajne', 8.0, 1.0, 'Piaszczysto-gliniaste', 'Brak', 'Płoć, Krąp, Ukleja', 'Kraina leszcza', 'Brak', false);

-- Spot 56: Strzyżew (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70055, 'Barycz - Strzyżew (Zakola)', 'barycz-strzyzew-zakola', 'RIVER', 51.6063541, 17.9739475, 'Wielkopolskie', 'Odolanów', 'Strzyżew oferuje dostęp do Baryczy w miejscu, gdzie rzeka zaczyna tworzyć głębsze zakola o mulistym dnie. Są to wymarzone warunki dla leszczy, które w tym rejonie osiągają naprawdę imponujące rozmiary. Uciąg wody jest znikomy, więc koszyki zanętowe o wadze 15-20 gramów będą tutaj w zupełności wystarczające. Warto szukać ryb na pograniczu głównego nurtu i spokojniejszej wody, gdzie gromadzi się najwięcej pokarmu. Roślinność brzegowa jest dość gęsta, co tworzy naturalne parawany chroniące wędkarza przed wiatrem. To techniczne łowisko, które wymaga od wędkarza cierpliwości i precyzyjnego budowania pola nęcenia.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70055, 'Nizinna Mała', 'Leniwy nurt, zakola', 10.0, 1.5, 'Muliste', 'Podmokłe brzegi', 'Leszcz, Płoć, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 57: Strzyżew (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70056, 'Barycz - Strzyżew (Zwaliska)', 'barycz-strzyzew-zwaliska', 'RIVER', 51.6040767, 17.9449593, 'Wielkopolskie', 'Odolanów', 'Drugi punkt w Strzyżewie to odcinek z bardzo dużą ilością zwalonych pni, tworzących naturalne kryjówki dla drapieżników. Dno jest tu mocno urozmaicone, z licznymi górkami i dołkami, co przyciąga duże okonie. Spinningiści z sukcesem stosują tu gumy na lekkich główkach, obławiając każdą napotkaną w wodzie przeszkodę. Nurt rzeki jest tu nieco żywszy, co wyraźnie natlenia wodę i pobudza ryby do aktywnego żerowania. Brzegi są wysokie i strome, dlatego warto zabrać ze sobą długi podbierak do bezpiecznego lądowania ryb. To dziki i nieprzewidywalny fragment rzeki, który zawsze może zaskoczyć braniem dorodnego szczupaka.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70056, 'Nizinna Mała', 'Naturalne zatory leśne', 9.0, 1.8, 'Piasek i korzenie', 'Zwalone drzewa', 'Okoń, Szczupak, Kleń', 'Kraina leszcza', 'Brak', false);

-- Spot 58: Bogufałów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70057, 'Barycz - Bogufałów (Równia)', 'barycz-bogufalow-rownia', 'RIVER', 51.5999849, 17.9165216, 'Wielkopolskie', 'Odolanów', 'Bogufałów to odcinek o charakterze uregulowanym, gdzie rzeka płynie szerokim korytem o wyrównanej głębokości. Dno jest piaszczyste i bardzo czyste, co sprawia, że jest to idealne miejsce do łowienia metodą odległościową. Dominują tu jazie oraz płocie, które bardzo dobrze reagują na nęcenie luźną zanętą sypaną prosto do wody. Uciąg jest stały i przewidywalny, co pozwala na komfortowe prowadzenie spławika na długich dystansach. Dostęp do wody jest wzorcowy, a płaski brzeg pozwala na wygodne rozstawienie siedziska i całego osprzętu. To stanowisko polecane szczególnie tym, którzy cenią sobie czystość i wygodę podczas wędkowania.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70057, 'Nizinna Mała', 'Uregulowane, szerokie', 12.0, 1.2, 'Piaszczyste', 'Brak', 'Jaź, Płoć, Ukleja', 'Kraina leszcza', 'Brak', false);

-- Spot 59: Smardowskie Olendry
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70058, 'Barycz - Smardowskie Olendry', 'barycz-smardowskie-olendry', 'RIVER', 51.5938542, 17.8818957, 'Wielkopolskie', 'Ostrów Wielkopolski', 'Barycz w Smardowskich Olendrach to odcinek o charakterze wybitnie kameralnym, płynący wśród mozaiki pól i łąk. Koryto rzeki jest tu dość wąskie, co sprzyja precyzyjnemu łowieniu kleni na małe smużaki i obrotówki. Dno jest piaszczyste z licznymi kępami roślinności zanurzonej, stanowiącej doskonałą kryjówkę dla wyrośniętych okoni. Nurt jest jednostajny i łagodny, co pozwala na komfortowe stosowanie lekkich zestawów spławikowych typu bat. Przy brzegach znajdziemy liczne zastoiska wody, gdzie w słoneczne dni chętnie żerują stada dorodnych wzdręg. To doskonałe miejsce dla wędkarzy ceniących ciszę oraz możliwość aktywnego poszukiwania ryb w ruchu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70058, 'Nizinna Mała', 'Naturalne, wąskie koryto', 6.0, 0.9, 'Piaszczyste', 'Brak', 'Kleń, Okoń, Wzdręga', 'Kraina leszcza', 'Brak', false);

-- Spot 60: gmina Przygodzice (Odcinek Łąkowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70059, 'Barycz - Przygodzice (Odcinek Środkowy)', 'barycz-przygodzice-srodek', 'RIVER', 51.5883675, 17.8503911, 'Wielkopolskie', 'Przygodzice', 'Odcinek rzeki w gminie Przygodzice charakteryzuje się bardzo czystą wodą i piaszczystym, miejscami żwirowym dnem. Rzeka płynie tu uregulowanym korytem, ale liczne podmyte brzegi tworzą techniczne stanowiska dla drapieżników. Głównym celem wypraw są tutaj jazie oraz płocie, które bardzo dobrze reagują na nęcenie luźną zanętą sypaną w nurt. Uciąg jest umiarkowany, co wymaga stosowania dociążonych zestawów spławikowych przy łowieniu na tzw. przepływankę. Warto zwrócić uwagę na głębsze rynny przy zakolach, gdzie często odpoczywają szczupaki po rannym żerowaniu. Brzegi są niskie i trawiaste, co zapewnia ogromny komfort przy rozkładaniu stanowiska gruntowego.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70059, 'Nizinna Mała', 'Uregulowane koryto nizinne', 9.0, 1.1, 'Piasek i drobny żwir', 'Podmyte burty', 'Jaź, Płoć, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 61: Przygodzice (Blisko Stawów)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70060, 'Barycz - Przygodzice (Węzeł Stawowy)', 'barycz-przygodzice-stawy', 'RIVER', 51.5822477, 17.8231674, 'Wielkopolskie', 'Przygodzice', 'Lokalizacja ta znajduje się w bezpośrednim sąsiedztwie kompleksów stawowych, co znacząco wpływa na różnorodność rybostanu w rzece. Barycz staje się tu nieco szersza, a jej nurt zwalnia pod wpływem licznych urządzeń hydrotechnicznych. Dno jest zróżnicowane, z przewagą gliny i naniesionego mułu, co przyciąga dorodne liny oraz karasie złote. Wędkarze spinningowi mogą tu liczyć na spotkanie z sandaczem, który często zapuszcza się w te rejony z głębszych patii dorzecza. Należy pamiętać o zachowaniu czujności, gdyż woda bywa tu technicznie trudna ze względu na sporą ilość roślinności podwodnej. To strategiczny punkt, łączący charakter rzeki nizinnej z bogactwem ekosystemu stawowego.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70060, 'Nizinna Mała', 'Leniwy nurt, wpływ stawów', 12.0, 1.4, 'Gliniano-muliste', 'Mnichy, zastawki', 'Lin, Karaś złoty, Sandacz', 'Kraina leszcza', 'Obszar Chronionego Krajobrazu', false);

-- Spot 62: Janków Przygodzki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70061, 'Barycz - Janków Przygodzki', 'barycz-jankow-przygodzki', 'RIVER', 51.584801, 17.7922496, 'Wielkopolskie', 'Przygodzice', 'W Jankowie Przygodzkim Barycz oferuje wędkarzom szerokie rozlewiska o bardzo spokojnym, niemal stojącym nurcie wody. Dno jest tu miękkie i żyzne, obfitujące w pokarm, co przyciąga duże stada leszczy oraz krąpi. To idealne miejsce na całodniową zasiadkę z metodą feeder, celując w najgłębsze partie koryta sięgające dwóch metrów. Przy brzegach dominują pasy wysokich trzcin, które stanowią bezpieczną ostoję dla licznej populacji lina. W chłodniejsze dni warto spróbować łowienia na martwą rybkę, gdyż miejsce to słynie z brania grubych, jesiennych szczupaków. Dojazd na łowisko jest komfortowy, a liczne zatoczki pozwalają na swobodne zaparkowanie auta w bliskiej odległości od brzegu.', 'PZW Kalisz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70061, 'Nizinna Mała', 'Szerokie rozlewiska', 15.0, 1.8, 'Muliste', 'Trzcinowiska', 'Leszcz, Lin, Szczupak', 'Kraina leszcza', 'Brak', false);

-- BOBR

-- Spot 63: Jelenia Góra
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70062, 'Bóbr - Jelenia Góra (Górski Bieg)', 'bobr-jelenia-gora-gorski', 'RIVER', 50.9193305, 15.7063012, 'Dolnośląskie', 'Jelenia Góra', 'Bóbr w Jeleniej Górze to klasyczna rzeka górska o krystalicznie czystej wodzie i bardzo silnym nurcie. Dno jest tu wyścielone grubymi otoczakami oraz płytami skalnymi, które tworzą liczne kryjówki dla ryb łososiowatych. To doskonałe łowisko dla muszkarzy polujących na pstrągi potokowe oraz lipienie na krótką nimfę. Woda jest tu płytka, ale posiada liczne banie i rynny, gdzie gromadzą się największe okazy. Niezbędne jest używanie woderów z kolcami, gdyż kamienie są bardzo śliskie i niebezpieczne przy brodzeniu. To techniczny odcinek wymagający precyzyjnych rzutów i doskonałego czytania wody pod prąd.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, method_bans, boat_fishing_allowed)
VALUES (70062, 'Górska', 'Bystry nurt, koryto skaliste', 25.0, 0.8, 'Głazy, otoczaki', 'Naturalne progi skalne', 'Pstrąg potokowy, Lipień, Głowacica', 'Kraina pstrąga', 'Odcinek górski - tylko sztuczne przynęty', 'Zakaz używania przynęt naturalnych', false);

-- Spot 64: Małomice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70063, 'Bóbr - Małomice (Przełom)', 'bobr-malomice-przelom', 'RIVER', 51.5613127, 15.4522281, 'Lubuskie', 'Małomice', 'Odcinek Bobru w Małomicach charakteryzuje się przejściowym charakterem rzeki, łączącym cechy wody podgórskiej i nizinnej. Dominują tu piaszczyste rynny przeplatane żwirowymi bystrzami, które są ulubionym miejscem żerowania brzan. Wędkarze spinningowi mogą liczyć na spotkanie z walecznym kleniem oraz szczupakiem czającym się w przybrzeżnych zastoiskach. Nurt jest tu zmienny, co wymusza stosowanie różnorodnego obciążenia w zależności od wybranego stanowiska. Brzegi są częściowo zalesione, co zapewnia naturalny cień i spokój podczas wielogodzinnych wypraw. To bardzo rybny fragment rzeki, który regularnie zaskakuje wędkarzy różnorodnością poławianych gatunków.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70063, 'Podgórska', 'Nurt umiarkowany, meandry', 30.0, 1.2, 'Piasek i żwir', 'Brak', 'Brzana, Kleń, Szczupak', 'Kraina brzany', 'Brak', false);

-- Spot 65: Żagań (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70064, 'Bóbr - Żagań (Miejska Kaskada)', 'bobr-zagan-miejska', 'RIVER', 51.6075902, 15.3331934, 'Lubuskie', 'Żagań', 'Bóbr w Żaganiu to odcinek słynący z silnej populacji rzecznych drapieżników oraz potężnych ryb reofilnych. Rzeka płynie tu uregulowanym korytem, a jej dno jest w dużej mierze kamieniste z licznymi kamiennymi opaskami. Warkocze tworzące się przy filarach mostów to bankowe miejsca na spotkanie z żerującym boleniem i sandaczem. Uciąg wody jest tu znaczący, co wymaga od wędkarzy gruntowych stosowania ciężkich, trójkątnych koszyków zanętowych. Przy brzegach można spotkać głębokie rynny, które są doskonałym siedliskiem dla dużych sumów. To łowisko wymagające mocnego sprzętu, zdolnego sprostać sile ryb walczących w głównym nurcie.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70064, 'Nizinna Wielka', 'Uregulowane, nurt silny', 40.0, 2.0, 'Kamieniste', 'Opaski, filary mostów', 'Boleń, Sandacz, Sum, Brzana', 'Kraina brzany', 'Odcinek miejski', true);

-- Spot 66: Żagań (Punkt 2 - Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70065, 'Bóbr - Żagań (Dzikie Starorzecza)', 'bobr-zagan-polnoc', 'RIVER', 51.6471222, 15.2970507, 'Lubuskie', 'Żagań', 'Północny odcinek Bobru za Żaganiem to rzeka dzika i nieprzewidywalna, z dużą ilością zwalonych drzew w nurcie. Takie naturalne zatory tworzą głębokie doły, w których stacjonują rekordowe szczupaki i grube okonie. Dno staje się tu bardziej piaszczyste, ale nadal występują twarde, gliniaste burty sprzyjające kleniom. Wędkarze cenią to miejsce za niską presję i możliwość łowienia w całkowitym odosobnieniu. Nurt rzeki jest jednostajny, co sprzyja precyzyjnemu prowadzeniu przynęt spinningowych wzdłuż brzegowych faszyn. Jest to techniczny poligon dla spinningistów, którzy nie boją się trudnych warunków i licznych zaczepów.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70065, 'Nizinna Wielka', 'Naturalne, zatory leśne', 35.0, 1.8, 'Piasek i glina', 'Zwalone drzewa', 'Szczupak, Okoń, Kleń', 'Kraina leszcza', 'Brak', true);

-- Spot 67: Dychów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70066, 'Bóbr - Dychów (Elektrownia)', 'bobr-dychow-elektrownia', 'RIVER', 51.9913117, 15.0587275, 'Lubuskie', 'Krosno Odrzańskie', 'Odcinek w Dychowie jest silnie uzależniony od pracy tamtejszej elektrowni wodnej, co wpływa na zmienny poziom i siłę nurtu. Woda jest tu głęboka, a koryto rzeki posiada charakterystyczne betonowe i kamienne umocnienia brzegowe. To legendarne miejsce na sandacza, który chętnie żeruje na twardym, wymytym dnie poniżej spiętrzeń. Wędkarze gruntowi z sukcesami łowią tu potężne leszcze i brzany, stosując ciężkie zestawy z dużą ilością robaków. Ze względu na gwałtowne zmiany stanu wody, należy zachować szczególną ostrożność podczas brodzenia lub ustawiania stanowisk przy samym lustrze. To wyjątkowe łowisko dla profesjonalistów, którzy potrafią dostosować taktykę do dynamicznie zmieniających się warunków hydrologicznych.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70066, 'Nizinna Wielka', 'Kanałowy, głęboki', 50.0, 3.5, 'Betonowo-kamienne', 'Zapory, kanały zrzutowe', 'Sandacz, Leszcz, Brzana, Sum', 'Kraina leszcza', 'Strefa przyelektrowniana', true);

-- Spot 68: Gorzupia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70067, 'Bóbr - Gorzupia (Przełom)', 'bobr-gorzupia-przelom', 'RIVER', 51.7370734, 15.2591356, 'Lubuskie', 'Żagań', 'Odcinek w Gorzupi charakteryzuje się szybkim nurtem i licznymi, kamienistymi przelewami, które świetnie natleniają wodę. Dno jest tu w większości twarde, usiane otoczakami, co czyni to miejsce bankową miejscówką na rzeczną brzanę. Spinningiści z sukcesami polują tutaj na waleczne klenie oraz jazie, które ustawiają się w cieniu nadbrzeżnych faszyn. Uciąg rzeki wymusza stosowanie cięższych zestawów gruntowych z płaskimi ciężarkami, które stabilnie trzymają się dna w głównym nurcie. Przy brzegach znajdziemy liczne rynny, gdzie wieczorami na polowanie wychodzą sandacze oraz większe okonie. To techniczne łowisko, które nagradza wędkarzy potrafiących precyzyjnie czytać ukształtowanie dna i ruchy wody.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70067, 'Nizinna Mała', 'Nurt szybki, kamienisty', 35.0, 1.4, 'Kamienie i żwir', 'Opaski kamienne', 'Brzana, Kleń, Sandacz', 'Kraina brzany', 'Brak', true);

-- Spot 69: Cieszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70068, 'Bóbr - Cieszów (Dzikie Zakola)', 'bobr-cieszow-dzikie-zakola', 'RIVER', 51.8330733, 15.2054374, 'Lubuskie', 'Nowogród Bobrzański', 'Odcinek w Cieszowie to kwintesencja dzikiego Bobru z licznymi powalonymi drzewami i podmytymi burtami. Rzeka mocno tu meandruje, tworząc głębokie na ponad dwa metry doły na zewnętrznych łukach koryta. Dno jest urozmaicone, piaszczysto-gliniaste, co sprzyja bytowaniu dużych szczupaków oraz rekordowych okoni. Spinningowanie w tym miejscu wymaga dużej precyzji rzutów, aby umieścić przynętę tuż obok zatopionych korzeni. Uciąg jest umiarkowany, co pozwala na komfortowe łowienie lekkim feederem przy użyciu koszyków o wadze 40-50 gramów. To łowisko o niskiej presji, idealne dla osób szukających spokoju i szansy na spotkanie z prawdziwym rzecznym potworem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70068, 'Nizinna Mała', 'Bardzo kręte, zatory', 40.0, 1.8, 'Piasek i glina', 'Zwalone drzewa', 'Szczupak, Okoń, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 70: Łagoda
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70069, 'Bóbr - Łagoda (Przykosy)', 'bobr-lagoda-przykosy', 'RIVER', 51.8717782, 15.166581, 'Lubuskie', 'Nowogród Bobrzański', 'W Łagodzie Bóbr rozlewa się nieco szerzej, tworząc liczne piaszczyste przykosy i rozległe płanie. Nurt rzeki jest tu jednostajny, co sprzyja systematycznemu nęceniu i łowieniu białorybu metodą odległościową. Dno jest przeważnie piaszczyste, ale w rynnach blisko nurtu można natrafić na twardsze, żwirowe fragmenty. Jest to doskonałe miejsce na nocne polowanie za sumem, który chętnie odwiedza tutejsze głębokie jamy pod przeciwległym brzegiem. Wędkarze często meldują tu brania dużych stadnych leszczy oraz jelców, które doskonale reagują na białe robaki. Brzeg jest łatwo dostępny i płaski, co czyni ten odcinek bardzo komfortowym dla osób z dużą ilością sprzętu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70069, 'Nizinna Mała', 'Szerokie, wolne płanie', 45.0, 1.6, 'Piaszczyste', 'Brak', 'Leszcz, Sum, Jaź', 'Kraina leszcza', 'Brak', true);

-- Spot 71: Nowogród Bobrzański
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70070, 'Bóbr - Nowogród Bobrzański (Zimowisko)', 'bobr-nowogrod-bobrzanski-zimowisko', 'RIVER', 51.7804947, 15.2399602, 'Lubuskie', 'Nowogród Bobrzański', 'Odcinek w samym Nowogrodzie Bobrzańskim to legendarne łowisko, szczególnie cenione w chłodniejszych miesiącach roku. Rzeka posiada tu głębokie koryto z licznymi betonowymi umocnieniami, które stabilizują nurt i tworzą bezpieczne stanowiska. Dno jest twarde i czyste, co sprawia, że sandacze chętnie wybierają te rejony na swoje jesienne żerowiska. Spinningiści z sukcesem stosują tu metodę opadu, obławiając każdą nierówność dna przy pomocy gumowych wabików. W okresach letnich na powierzchni wody widać intensywne ataki boleni, które polują w warkoczach powstających za filarami. To miejsce o dużej presji, ale zasobność wody w ryby reofilne w pełni rekompensuje towarzystwo innych wędkarzy.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70070, 'Nizinna Mała', 'Uregulowane, głębokie', 42.0, 2.5, 'Twarde', 'Umocnienia betonowe', 'Sandacz, Boleń, Leszcz', 'Kraina brzany', 'Odcinek miejski', true);

-- Spot 72: Sobota
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70071, 'Bóbr - Sobota (Skalny Nurt)', 'bobr-sobota-skalny-nurt', 'RIVER', 51.0726709, 15.6508371, 'Dolnośląskie', 'Lwówek Śląski', 'Bóbr w Sobocie to rzeka o charakterze podgórskim, z bardzo czystą wodą i kamienisto-skalistym podłożem. Nurt jest tu rwanym i szybki, tworząc liczne bystrza oraz głębokie, spokojniejsze banie za dużymi głazami. To królestwo pstrąga potokowego i lipienia, które doskonale reagują na techniki muchowe oraz lekki spinning. Wędkarze gruntowi mogą tu liczyć na spotkanie z potężnymi brzanami, które są symbolem tego odcinka rzeki. Brodzanie wymaga dużej ostrożności ze względu na śliskie kamienie oraz niespodziewane uskoki dna w głównym nurcie. Miejsce to zachwyca dzikością i surowym krajobrazem, będąc jednym z najpiękniejszych fragmentów Bobru na Dolnym Śląsku.', 'PZW Jelenia Góra');

