-- Spot 73: Wleń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70072, 'Bóbr - Wleń (Odcinek Specjalny)', 'bobr-wlen-os', 'RIVER', 51.018411, 15.6680087, 'Dolnośląskie', 'Wleń', 'Wleń to jeden z najsłynniejszych odcinków muchowych w Polsce, położony poniżej zapory w Pilchowicach. Stała niska temperatura wody wypływającej z jeziora sprawia, że pstrągi i lipienie żerują tu intensywnie przez cały rok. Koryto jest szerokie i kamieniste, z licznymi rynnami, które wymagają precyzyjnego prowadzenia nimfy lub suchej muchy. Wędkowanie w tym miejscu wymaga posiadania specjalnych uprawnień, gdyż jest to odcinek o zaostrzonym rygorze ochronnym. Największe pstrągi potokowe potrafią tu zaskoczyć siłą, wykorzystując bystry nurt do ucieczki w głąb koryta. Malownicze położenie miasteczka i krystaliczna woda sprawiają, że każda wyprawa do Wlenia jest niezapomnianym przeżyciem.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, method_bans, boat_fishing_allowed)
VALUES (70072, 'Górska', 'Szeroki nurt górski', 35.0, 1.0, 'Otoczaki i żwir', 'Brak', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Odcinek Specjalny (No Kill)', 'Tylko sztuczna mucha, haki bezzadziorowe', false);

-- Spot 74: Lwówek Śląski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70073, 'Bóbr - Lwówek Śląski (Skalne Rynny)', 'bobr-lwowek-slaski-rynny', 'RIVER', 51.1070921, 15.6046895, 'Dolnośląskie', 'Lwówek Śląski', 'Bóbr w Lwówku Śląskim to klasyczna rzeka podgórska o bardzo zróżnicowanym nurcie i kamienisto-żwirowym dnie. Występują tu liczne naturalne przelewy kamienne oraz głębokie rynny, w których grupują się brzany oraz dorodne klenie. Muszkarze często odwiedzają ten odcinek w poszukiwaniu pięknych lipieni i pstrągów potokowych podczas wiosennych rójek owadów. Miłośnicy spinningu powinni skupić się na głębokich jamach przy brzegach, gdzie w cieniu nawisów często czatują szczupaki. Uciąg jest tu stały i dość silny, co wymaga stosowania dociążonych przynęt lub ciężkich koszyków zanętowych. Dostęp do wody jest wygodny, co czyni to miejsce bardzo popularnym punktem dla lokalnych i przyjezdnych wędkarzy.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70073, 'Podgórska', 'Nurt zmienny, rynny skalne', 30.0, 1.2, 'Kamienie i żwir', 'Naturalne progi', 'Brzana, Kleń, Lipień, Pstrąg potokowy', 'Kraina brzany', 'Brak', false);

-- Spot 75: Pilchowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70074, 'Bóbr - Pilchowice (Poniżej Zapory)', 'bobr-pilchowice-ponizej-zapory', 'RIVER', 50.9726776, 15.6422418, 'Dolnośląskie', 'Jelenia Góra', 'Odcinek Bobru poniżej zapory w Pilchowicach jest legendarnym łowiskiem słynącym z krystalicznej i bardzo zimnej wody. Stały zrzut wody ze zbiornika utrzymuje niską temperaturę przez cały rok, co sprzyja bytowaniu medalowych pstrągów. Dno wyścielone jest grubym otoczakiem i dużymi głazami, co tworzy mnóstwo technicznych stanowisk dla muszkarzy. Wędkarze mogą liczyć na spotkanie z potężnymi pstrągami potokowymi, które wykorzystują bystry nurt do niezwykle silnej walki. Jest to odcinek o zaostrzonych rygorach ochronnych, dlatego przed łowieniem należy dokładnie sprawdzić aktualny regulamin okręgu. Malowniczy widok na zaporę oraz dziki wąwóz sprawiają, że każda wyprawa w to miejsce jest niezapomnianym przeżyciem.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, method_bans, boat_fishing_allowed)
VALUES (70074, 'Górska', 'Bystry nurt górski', 25.0, 1.0, 'Głazy i otoczaki', 'Zapora wodna', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Odcinek o szczególnym rygorze', 'Tylko przynęty sztuczne, haki bezzadziorowe', false);

-- Spot 76: Bukówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70075, 'Bóbr - Bukówka (Górski Potok)', 'bobr-bukowka-potok', 'RIVER', 50.7146631, 15.9541238, 'Dolnośląskie', 'Lubawka', 'Bóbr w okolicach Bukówki to wciąż dziki potok górski, położony tuż poniżej źródeł oraz tutejszego zbiornika zaporowego. Woda jest tu płytka i przejrzysta, płynąca bystrym nurtem przez malowniczą dolinę w Sudetach. Na tym odcinku dominują pstrągi potokowe oraz niewielkie, ale kolorowe głowacze białopłetwe żyjące pod kamieniami. Dno jest niemal w całości kamieniste, co wymaga od wędkarza brodzącego specjalistycznego obuwia z filcem dla bezpieczeństwa. Metody gruntowe praktycznie tu nie istnieją, a jedyną skuteczną techniką jest precyzyjna mucha lub ultra-lekki spinning. To idealne miejsce dla osób szukających absolutnej samotności i prawdziwego górskiego wędkarstwa w surowych warunkach.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70075, 'Górska', 'Potok górski, wąski', 10.0, 0.6, 'Kamieniste', 'Brak', 'Pstrąg potokowy', 'Kraina pstrąga', 'Brak', false);

-- Spot 77: Włodzice Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70076, 'Bóbr - Włodzice Wielkie (Żwirowe Płanie)', 'bobr-wlodzice-wielkie-planie', 'RIVER', 51.179565, 15.5413552, 'Dolnośląskie', 'Lwówek Śląski', 'Poniżej Lwówka Śląskiego, w miejscowości Włodzice Wielkie, rzeka zaczyna się rozszerzać, a nurt nieco stabilizować. Dno pozostaje w większości żwirowe z piaszczystymi łachami w spokojniejszych miejscach, co przyciąga duże stada jelców i płoci. Królową tego odcinka jest brzana, która potężnie walczy w głównym prądzie i świetnie reaguje na ciężki feeder. Szczupaki i wyrośnięte okonie zasiedlają spokojniejsze zatoczki oraz starorzecza położone wzdłuż brzegów porośniętych wikliną. Dojazd do wody jest relatywnie łatwy przez łąki, jednak należy uważać na grząskie fragmenty po intensywnych opadach deszczu. Miejsce to oferuje idealny miks łowiska podgórskiego i nizinnego, dając szansę na sukces w wielu technikach.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70076, 'Podgórska', 'Szerokie koryto, nurt umiarkowany', 35.0, 1.5, 'Żwir i piasek', 'Podmyte brzegi', 'Brzana, Leszcz, Szczupak, Kleń', 'Kraina brzany', 'Brak', false);

-- Spot 78: Stara Oleszna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70077, 'Bóbr - Stara Oleszna (Leśny Odcinek)', 'bobr-stara-oleszna-las', 'RIVER', 51.4117933, 15.5960941, 'Dolnośląskie', 'Bolesławiec', 'Bóbr w Starej Olesznej przybiera bardziej nizinny charakter, choć nadal zachowuje swoją siłę podczas wyższych stanów wód. Rzeka meandruje tu przez gęste lasy, tworząc głębokie zakola z piaszczystym dnem i licznymi zwalonymi drzewami. Jest to doskonała lokalizacja dla łowców szczupaków, którzy używają dużych gum lub woblerów w pobliżu podwodnych przeszkód. Potężne klenie i jazie grupują się pod nawisami gałęzi, stanowiąc nie lada wyzwanie dla fanów lekkiego spinningu. Wędkarze gruntowi mogą liczyć na regularne brania leszczy i krąpi w głębszych, wolniej płynących odcinkach rzeki. Otaczająca cisza i dzika przyroda sprawiają, że jest to jeden z najatrakcyjniejszych punktów na spokojny weekend z wędką.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70077, 'Nizinna Średnia', 'Meandrujące, leśne koryto', 38.0, 1.8, 'Piasek i glina', 'Zwalone drzewa', 'Szczupak, Kleń, Leszcz, Jaź', 'Kraina leszcza', 'Brak', true);

-- Spot 79: Dąbrowica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70078, 'Bóbr - Dąbrowica (Podgórski Przełom)', 'bobr-dabrowica-przelom', 'RIVER', 50.8810951, 15.8062425, 'Dolnośląskie', 'Jelenia Góra', 'Bóbr w Dąbrowicy to odcinek o charakterze podgórskim, gdzie rzeka zaczyna zwalniać po opuszczeniu ciasnych dolin. Dno jest tu usiane otoczakami i grubym żwirem, co tworzy idealne warunki dla stadnych kleni oraz brzan. Nurt jest jednostajny, ale posiada liczne zawirowania przy brzegowych opaskach faszynowych. Wędkarze spinningowi mogą liczyć na spotkanie z pstrągiem potokowym, który często zapuszcza się w te rejony z górnego biegu. Najskuteczniejszą metodą jest tu lekka przepływanka lub spinning z wykorzystaniem małych woblerów. To spokojne łowisko o umiarkowanej presji, oferujące doskonałe warunki do całodniowego relaksu z wędką.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70078, 'Podgórska', 'Umiarkowany nurt, koryto naturalne', 28.0, 1.1, 'Otoczaki i żwir', 'Opaski faszynowe', 'Kleń, Brzana, Pstrąg potokowy', 'Kraina brzany', 'Brak', false);

-- Spot 80: Janiszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70079, 'Bóbr - Janiszów (Górski Potok)', 'bobr-janiszow-potok', 'RIVER', 50.754943, 15.9867448, 'Dolnośląskie', 'Kamienna Góra', 'Górny bieg rzeki w Janiszowie to królestwo czystej wody i kamienistych bystrzy. Koryto jest tu stosunkowo wąskie, co wymaga od wędkarza dużej precyzji w podawaniu przynęty. Dno wyłożone jest drobnymi kamieniami, a w głębszych rynnach można spotkać pięknie wybarwione pstrągi. To idealne miejsce dla miłośników ultra-lekkiego spinningu oraz techniki muchowej. Nurt jest tu rwanym i szybki, dlatego warto szukać ryb w cieniu nadbrzeżnych krzewów i za większymi głazami. Ze względu na niską temperaturę wody, ryby są tu aktywne niemal przez cały rok, co przyciąga koneserów górskiego łowienia.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70079, 'Górska', 'Bystry nurt, wąskie koryto', 12.0, 0.7, 'Kamieniste', 'Brak', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Woda krainy pstrąga i lipienia', false);

-- Spot 81: Kamienna Góra
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70080, 'Bóbr - Kamienna Góra (Miejski)', 'bobr-kamienna-gora-miejski', 'RIVER', 50.7866642, 16.0388369, 'Dolnośląskie', 'Kamienna Góra', 'Miejski odcinek w Kamiennej Górze charakteryzuje się licznymi progami i umocnieniami brzegowymi. Woda pod mostami żłobi głębokie jamy, w których często grupują się wyrośnięte klenie oraz jazie. Dno jest tu twarde, piaszczysto-kamieniste, z niewielką ilością zaczepów w głównym nurcie. Uciąg rzeki jest tu znaczący, co wymusza stosowanie dociążonych zestawów gruntowych z płaskim ciężarkiem. To świetne miejsce do nauki łowienia na tzw. przystawkę ze spławikiem, szczególnie w okresach wyższych stanów wody. Warto zwrócić uwagę na wyloty kanałów burzowych, gdzie ryby chętnie żerują na nanoszonym pokarmie naturalnym.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70080, 'Podgórska', 'Uregulowane, progi betonowe', 20.0, 1.2, 'Piaszczysto-kamieniste', 'Mosty, progi', 'Kleń, Jaź, Pstrąg potokowy', 'Kraina brzany', 'Odcinek miejski', false);

-- Spot 82: Marciszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70081, 'Bóbr - Marciszów (Kraina Lipienia)', 'bobr-marciszow-lipien', 'RIVER', 50.8333506, 16.0345941, 'Dolnośląskie', 'Marciszów', 'Marciszów to jeden z najbardziej technicznych odcinków Bobru, słynący z pięknych lipieni i pstrągów. Rzeka płynie tu bystrym nurtem, tworząc malownicze banie i rynny za naturalnymi przeszkodami. Dno jest urozmaicone, z przewagą grubych otoczaków, co wymaga od wędkarza brodzącego specjalistycznego obuwia. To idealny poligon dla muszkarzy stosujących krótką nimfę lub suchą muchę w okresach rójek chruścika. Ryby w tym miejscu są wyjątkowo waleczne, wykorzystując siłę prądu podczas holu w głąb koryta. Malownicza okolica i krystaliczna woda sprawiają, że jest to jedno z ulubionych łowisk w tym regionie Dolnego Śląska.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70081, 'Górska', 'Szybki nurt, naturalne banie', 22.0, 0.9, 'Grube otoczaki', 'Brak', 'Lipień, Pstrąg potokowy', 'Kraina pstrąga', 'Brak', false);

-- Spot 83: Ciechanowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70082, 'Bóbr - Ciechanowice (Brzanowe Pole)', 'bobr-ciechanowice-brzana', 'RIVER', 50.8690775, 15.9913021, 'Dolnośląskie', 'Marciszów', 'Odcinek w Ciechanowicach oferuje wędkarzom dziki charakter rzeki z licznymi nawisami drzew i podmytymi burtami. Bóbr płynie tu krętym korytem, a dno jest zróżnicowane — od piaszczystych łach po gliniaste progi. Jest to doskonała lokalizacja dla łowców brzan, które świetnie reagują na ciężki feeder z dużą ilością robaków. Spinningiści znajdą tutaj liczne kryjówki szczupaka, szczególnie w spokojniejszych zatoczkach za zwalonymi pniemi. Uciąg jest umiarkowany, co pozwala na komfortowe łowienie przy użyciu standardowych zestawów rzecznych. Cisza panująca wzdłuż brzegów pozwala na pełne skupienie i podziwianie uroków sudeckiej przyrody.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70082, 'Podgórska', 'Meandrujące, naturalne', 25.0, 1.3, 'Piasek i glina', 'Podmyte burty, zatory', 'Brzana, Szczupak, Kleń', 'Kraina brzany', 'Brak', false);

-- Spot 84: Janowice Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70083, 'Bóbr - Janowice Wielkie (Skalisty Nurt)', 'bobr-janowice-wielkie-skaly', 'RIVER', 50.8816798, 15.9224844, 'Dolnośląskie', 'Janowice Wielkie', 'Janowice Wielkie to brama do Rudaw Janowickich, gdzie Bóbr przybiera postać gwałtownego, skalistego nurtu. Woda rozbija się tu o liczne granitowe głazy, tworząc natlenione warkocze i głębokie, spokojniejsze lustra wody. To klasyczne stanowiska pstrągowe, wymagające od wędkarza cichego podejścia i precyzyjnych rzutów spinningowych. Dno jest stabilne, ale śliskie, z przewagą dużych kamieni i płyt skalnych. Nurt rzeki jest tu niezwykle dynamiczny, co sprawia, że każda brana ryba dostarcza ogromnych emocji podczas holu. Jest to miejsce szczególnie polecane dla koneserów dzikiej rzeki, którzy nie boją się trudnego terenu i zimnej wody.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70083, 'Górska', 'Przełom skalny, rwanym nurt', 24.0, 0.8, 'Płyty skalne i głazy', 'Naturalne kaskady', 'Pstrąg potokowy, Lipień, Głowacz', 'Kraina pstrąga', 'Woda krainy pstrąga i lipienia', false);

-- Spot 85: Leszno Górne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70084, 'Bóbr - Leszno Górne (Równia)', 'bobr-leszno-gorne-rownia', 'RIVER', 51.4737519, 15.6059013, 'Lubuskie', 'Szprotawa', 'W Lesznie Górnym Bóbr zmienia swoje oblicze, stając się rzeką nizinną o szerokim korycie i wolniejszym nurcie. Dno jest tu piaszczyste, z rzadka porośnięte roślinnością podwodną, co przyciąga duże stada leszczy oraz krąpi. To doskonałe miejsce na nocną zasiadkę z martwą rybką w poszukiwaniu sandacza lub suma. Spinningiści z sukcesem obławiają tutaj piaszczyste przykosy, na których żerują stadne bolenie oraz piękne okonie. Uciąg jest stabilny, co pozwala na idealną prezentację przynęty przy użyciu lekkich zestawów gruntowych. Brzegi są łatwo dostępne i płaskie, co czyni ten odcinek bardzo przyjaznym dla wędkarzy zmotoryzowanych.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70084, 'Nizinna Wielka', 'Szerokie koryto nizinne', 45.0, 1.8, 'Piaszczyste', 'Przykosy', 'Leszcz, Sandacz, Boleń, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 86: Bolesławiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70085, 'Bóbr - Bolesławiec (Miejski)', 'bobr-boleslawiec-miejski', 'RIVER', 51.2649807, 15.546978, 'Dolnośląskie', 'Bolesławiec', 'Bóbr w Bolesławcu to techniczny odcinek miejski z licznymi kamiennymi opaskami i rynnami. Nurt jest tu zmienny, co sprzyja bytowaniu zarówno kleni, jak i dorodnych brzan. Dno jest przeważnie twarde, kamienisto-żwirowe, co ułatwia prowadzenie przynęt spinningowych wzdłuż filarów mostowych. Warkocze powstające przy murkach oporowych to doskonałe miejsca na spotkanie z boleniem polującym na drobnicę. Dla wędkarzy gruntowych polecane są głębsze doły poniżej progów, gdzie często gromadzą się leszcze. Miejsce jest łatwo dostępne z obu brzegów i oferuje komfortowe warunki do całodziennego wędkowania.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70085, 'Podgórska', 'Uregulowane, rynny kamienne', 35.0, 1.4, 'Kamienisto-żwirowe', 'Mosty, opaski betonowe', 'Brzana, Kleń, Boleń, Leszcz', 'Kraina brzany', 'Odcinek miejski', false);

-- Spot 87: Łąka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70086, 'Bóbr - Łąka (Naturalny)', 'bobr-laka-naturalny', 'RIVER', 51.3085502, 15.5668646, 'Dolnośląskie', 'Bolesławiec', 'W miejscowości Łąka rzeka zachowuje swój naturalny wdzięk, meandrując przez tereny nizinne o piaszczystym dnie. Odcinek ten słynie z licznych zastoisk oraz pasów trzcin, które są idealnym schronieniem dla szczupaków. Nurt rzeki jest tu łagodny, co pozwala na skuteczne stosowanie lekkich zestawów spławikowych oraz feedera. W rynnach pod drugim brzegiem często można spotkać wyrośnięte krąpie oraz dorodne jazie żerujące przy powierzchni. Podmyte burty i zwalone do wody gałęzie wymagają od spinningisty precyzyjnych rzutów i cierpliwego prowadzenia wabika. Jest to spokojne łowisko o niskiej presji, gwarantujące bliski kontakt z dziką naturą dorzecza Bobru.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70086, 'Nizinna Średnia', 'Meandrujące, naturalne', 38.0, 1.6, 'Piaszczyste', 'Zastoiska, trzcinowiska', 'Szczupak, Jaź, Krąp', 'Kraina leszcza', 'Brak', true);

-- Spot 88: Golnice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70087, 'Bóbr - Golnice (Leśny)', 'bobr-golnice-lesny', 'RIVER', 51.3526144, 15.583561, 'Dolnośląskie', 'Bolesławiec', 'Golnice oferują wędkarzom Bóbr w jego najbardziej malowniczym, leśnym wydaniu z licznymi powalonymi drzewami. Rzeka żłobi tu głębokie koryto, a dno jest urozmaicone gliniastymi progami i piaszczystymi przykosami. To klasyczne miejsce na ciężki spinning w poszukiwaniu rekordowych szczupaków i wyrośniętych okoni. Uciąg wody jest wyraźnie odczuwalny, co sprzyja natlenieniu wody i aktywności ryb reofilnych takich jak klenie. Wędkarze stacjonarni powinni szukać ryb w głębokich jamach, nęcąc grubszą frakcją w celu zwabienia stad leszczy. Dojazd do wody wymaga pokonania leśnych duktów, dlatego warto zadbać o odpowiednie przygotowanie logistyczne wyprawy.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70087, 'Nizinna Średnia', 'Leśne, zatory', 40.0, 1.8, 'Piasek i glina', 'Zwalone drzewa', 'Szczupak, Okoń, Leszcz, Kleń', 'Kraina leszcza', 'Brak', true);

-- Spot 89: Miodnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70088, 'Bóbr - Miodnica (Płanie)', 'bobr-miodnica-planie', 'RIVER', 51.6908157, 15.2784125, 'Lubuskie', 'Żagań', 'Miodnica to odcinek przedujściowy w stronę Żagania, gdzie rzeka rozlewa się szeroko na piaszczystych płaniach. Dno jest tu w większości twarde i piaszczyste, z rzadkimi rynnami o charakterze gliniastym. To idealny teren dla łowców boleni, które widowiskowo polują na tutejszych przelewach i piaszczystych łachach. Nurt jest jednostajny, co ułatwia łowienie metodą odległościową oraz klasycznym, rzecznym feederem. Wieczorami na płytsze partie wody wychodzą żerować sandacze, które można skutecznie kusić wąskimi woblerami. Miejsce to jest bardzo przestronne, co zapewnia wędkarzom swobodę i brak konieczności walki o wolne stanowisko.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70088, 'Nizinna Wielka', 'Szerokie płanie', 45.0, 1.5, 'Piaszczyste', 'Przykosy', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 90: Kraszowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70089, 'Bóbr - Kraszowice (Bystrza)', 'bobr-kraszowice-bystrza', 'RIVER', 51.2193322, 15.5073632, 'Dolnośląskie', 'Bolesławiec', 'Kraszowice to odcinek o charakterze podgórskim, położony powyżej Bolesławca, z bardzo dynamicznym nurtem. Dno wyścielone jest tu otoczakami i żwirem, co tworzy doskonałe siedlisko dla pstrągów potokowych oraz lipieni. Rzeka posiada liczne bystrza i kaskady, które wymagają od wędkarza umiejętności technicznego brodzenia pod prąd. Spinningiści z sukcesem stosują tu małe obrotówki oraz mikrojigi, obławiając cienie rzucane przez nadbrzeżne drzewa. Uciąg wody jest tu rwanym i silny, co wymusza stosowanie dociążonych przynęt, aby dotrzeć do ryb trzymających się dna. Cisza i surowy, kamienisty krajobraz sprawiają, że jest to łowisko wyjątkowe dla koneserów górskiej wody.', 'PZW Jelenia Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70089, 'Podgórska', 'Bystry nurt, kaskady', 30.0, 0.9, 'Otoczaki i żwir', 'Naturalne progi', 'Pstrąg potokowy, Lipień, Brzana', 'Kraina pstrąga', 'Woda krainy pstrąga i lipienia', false);

-- Spot 91: Leszno Dolne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70090, 'Bóbr - Leszno Dolne (Rozlewisko)', 'bobr-leszno-dolne-rozlewisko', 'RIVER', 51.5188087, 15.5995749, 'Lubuskie', 'Szprotawa', 'Bóbr w Lesznie Dolnym to rzeka o charakterze przejściowym, gdzie woda zaczyna nabierać typowo nizinnych cech. Dno jest tu zróżnicowane — od piaszczystych łach po muliste zatoczki, w których chętnie przebywają liny. Nurt jest spokojny i przewidywalny, co sprzyja precyzyjnemu nęczeniu pola łowiska przy użyciu zanęt spożywczych. Wzdłuż brzegów porośniętych wikliną często meldują się ładne jazie oraz płocie o pokaźnych rozmiarach. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia gum na lekkich główkach w poszukiwaniu okoni i szczupaków. Dogodny dostęp do lustra wody sprawia, że jest to popularne miejsce na weekendowe zasiadki dla całych rodzin.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70090, 'Nizinna Średnia', 'Spokojny nurt, szerokie koryto', 42.0, 1.7, 'Piasek i muł', 'Zatoczki z wikliną', 'Leszcz, Płoć, Szczupak, Lin', 'Kraina leszcza', 'Brak', true);

-- BRDA

-- Spot 92: gmina Tuchola (Woziwoda)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70091, 'Brda - Woziwoda (Leśny Przełom)', 'brda-woziwoda-przelom', 'RIVER', 53.6885979, 17.8491464, 'Kujawsko-Pomorskie', 'Tuchola', 'Brda w rejonie Woziwody to absolutna perła Borów Tucholskich, charakteryzująca się krystaliczną wodą i bardzo szybkim nurtem. Koryto rzeki jest tu usiane powalonymi drzewami, które tworzą naturalne kryjówki dla pstrągów potokowych. Dno jest w przeważającej części twarde i żwirowe, z wyraźnie zaznaczonymi rynnami o głębokości do półtora metra. Spinningiści z sukcesami stosują tu małe woblery i jigi, obławiając cienie rzucane przez gęsty starodrzew. Uciąg rzeki wymaga od wędkarza dużej precyzji w prowadzeniu przynęty oraz zachowania absolutnej ciszy na brzegu. To techniczne łowisko, które nagradza cierpliwych łowców ryb łososiowatych unikalnym kontaktem z dziką naturą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70091, 'Podgórska', 'Nurt szybki, liczne zwaliska', 15.0, 1.2, 'Żwir i kamienie', 'Zwalone sosny', 'Pstrąg potokowy, Lipień, Jaź', 'Kraina pstrąga', 'Obszar Natura 2000', false);

-- Spot 93: gmina Tuchola (Gołąbek)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70092, 'Brda - Gołąbek (Meandry)', 'brda-golabek-meandry', 'RIVER', 53.65323, 17.9300786, 'Kujawsko-Pomorskie', 'Tuchola', 'W okolicach Gołąbka Brda zaczyna szeroko meandrować, tworząc malownicze i głębokie zakola o piaszczysto-żwirowym dnie. Nurt jest tu nieco łagodniejszy niż powyżej, co sprzyja bytowaniu dorodnych kleni oraz jazi żerujących przy powierzchni. Podmyte burty brzegowe skrywają liczne okonie, które agresywnie reagują na małe obrotówki i twistery. Wędkarze często stosują tu metodę lekkiej przepływanki, celując w ryby spokojnego żeru gromadzące się w zakolach. Roślinność podwodna jest tu bogata, co zapewnia schronienie dla narybku i wymusza stosowanie celnych rzutów w oczka wody. Brzegi są dość strome, ale oferują kilka stabilnych stanowisk idealnych na kilkugodzinną sesję spinningową.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70092, 'Nizinna Mała', 'Meandrująca, naturalna', 18.0, 1.4, 'Piasek i żwir', 'Podmyte brzegi', 'Kleń, Jaź, Okoń', 'Kraina leszcza', 'Brak', false);

-- Spot 94: Tuchola (Rudzki Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70093, 'Brda - Rudzki Most (Szeroka)', 'brda-rudzki-most-szeroka', 'RIVER', 53.5543312, 17.8890606, 'Kujawsko-Pomorskie', 'Tuchola', 'Rudzki Most to kultowe miejsce na mapie Brdy, gdzie rzeka wyraźnie się rozszerza i nabiera większej głębokości. Dno jest tu zróżnicowane, piaszczyste z lokalnymi twardymi płatami gliny, co przyciąga duże stada leszczy. Uciąg jest umiarkowany i przewidywalny, dzięki czemu jest to doskonałe miejsce do łowienia metodą feederową. Warkocze powstające za filarami mostu to tradycyjne żerowisko boleni oraz wyrośniętych kleni polujących na ukleje. Wiele stanowisk jest tu dobrze przygotowanych i łatwo dostępnych, co czyni ten odcinek popularnym wśród wędkarzy stacjonarnych. Wieczorne wyprawy z martwą rybką często owocują tu braniami sandaczy żerujących w rynnach głównego nurtu.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70093, 'Nizinna Średnia', 'Uregulowane, szerokie koryto', 25.0, 2.2, 'Piasek i glina', 'Filary mostu', 'Leszcz, Boleń, Sandacz', 'Kraina leszcza', 'Brak', true);

-- Spot 95: Piła (Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70094, 'Brda - Piła (Głębokie Płanie)', 'brda-pila-planie', 'RIVER', 53.5184156, 17.8817043, 'Kujawsko-Pomorskie', 'Gostycyn', 'Odcinek w miejscowości Piła charakteryzuje się występowaniem szerokich i stosunkowo głębokich płani o mulisto-piaszczystym dnie. Rzeka płynie tu spokojnie, co sprzyja rozwojowi gęstych pasów trzcin oraz grążeli przy brzegach. Jest to wymarzone stanowisko dla łowców szczupaków, którzy z sukcesem stosują tu większe gumy oraz woblery. Wędkarze gruntowi mogą liczyć na spotkanie z dorodnymi linami, które chętnie odwiedzają tutejsze zaciszne zatoczki. Uciąg wody jest minimalny, co pozwala na komfortowe łowienie na delikatne zestawy spławikowe nawet podczas wiatru. Cisza i spokój panujące w tej okolicy sprawiają, że jest to doskonałe miejsce na relaksującą, całodniową zasiadkę.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70094, 'Nizinna Średnia', 'Spokojny nurt, rozlewiska', 30.0, 2.5, 'Muł i piasek', 'Kępy grążeli', 'Szczupak, Lin, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 96: gmina Gostycyn (Piekiełko)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70095, 'Brda - Piekiełko (Bystrza)', 'brda-piekielko-bystrza', 'RIVER', 53.482559, 17.8889105, 'Kujawsko-Pomorskie', 'Gostycyn', 'Legendarny odcinek Piekiełko to miejsce o niemal górskim charakterze, gdzie rzeka przedziera się przez głazowiska i kamienne progi. Nurt jest tu niezwykle silny i rwanym, tworząc liczne warkocze oraz natlenione bystrza idealne dla brzan. Dno wyścielone jest dużymi kamieniami i otoczakami, co wymaga od wędkarza brodzącego specjalistycznego obuwia z kolcami. To królestwo pstrąga potokowego oraz lipienia, które doskonale reagują na techniki muchowe i mikro-spinning. Wędkarstwo w tym miejscu wymaga dużej kondycji i umiejętności technicznego czytania dynamicznie zmieniającej się wody. To jeden z najbardziej wymagających, ale zarazem najbardziej satysfakcjonujących fragmentów rzeki w całym dorzeczu.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, method_bans, boat_fishing_allowed)
VALUES (70095, 'Górska', 'Bystry nurt, głazowiska', 20.0, 1.0, 'Głazy i kamienie', 'Naturalne kaskady', 'Brzana, Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Odcinek o silnym prądzie', 'Tylko przynęty sztuczne na wybranych fragmentach', false);

-- Spot 97: Zawada
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70096, 'Brda - Zawada (Górny bieg)', 'brda-zawada-gora', 'RIVER', 53.7718348, 17.2191652, 'Pomorskie', 'Przechlewo', 'Górny bieg Brdy w Zawadzie to wąskie i niezwykle kręte koryto, płynące wśród malowniczych łąk i zagajników. Woda jest tu płytka i bardzo przejrzysta, co sprawia, że ryby są wyjątkowo płochliwe i wymagają dyskretnego podejścia. Dno jest przeważnie piaszczyste, z lokalnymi naniesieniami żwiru w miejscach przyspieszenia nurtu. Spinningiści znajdą tutaj liczne rynny, w których czają się pstrągi potokowe oraz mniejsze szczupaki. Uciąg jest umiarkowany, co pozwala na precyzyjne operowanie lekkimi obrotówkami oraz niewielkimi woblerami typu minnow. Brak wysokiej roślinności na brzegach ułatwia rzuty, jednak wymusza na wędkarzu stosowanie niskiej postawy w celu uniknięcia wykrycia.', 'PZW Słupsk');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70096, 'Nizinna Mała', 'Wąskie, meandrujące koryto', 8.0, 0.8, 'Piasek i żwir', 'Brak', 'Pstrąg potokowy, Szczupak, Płoć', 'Kraina pstrąga', 'Brak', false);

-- Spot 98: gmina Miastko (Źródła)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70097, 'Brda - Starożreby (Źródliskowa)', 'brda-starozreby-zrodla', 'RIVER', 53.9651553, 17.128483, 'Pomorskie', 'Miastko', 'To jeden z najwyżej położonych odcinków Brdy, gdzie rzeka ma charakter niewielkiego, ale niezwykle czystego strumienia. Woda płynie tu przez dzikie tereny leśne, tworząc liczne zakola o głębokości rzadko przekraczającej metr. Dno jest twarde i piaszczyste, a brzegi są gęsto porośnięte krzewami, co wymaga od wędkarza techniki „krótkiego kija”. Dominują tu mniejsze drapieżniki oraz białoryb, który doskonale reaguje na naturalne przynęty podawane metodą spławikową. Nurt rzeki jest tu delikatny i jednostajny, co stwarza idealne warunki do nauki czytania wody rzeźnej. Jest to stanowisko wybitnie kameralne, gdzie przez cały dzień można nie spotkać innego człowieka.', 'PZW Słupsk');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70097, 'Nizinna Mała', 'Strumień, dzikie koryto', 5.0, 0.6, 'Piasek', 'Nawisy krzewów', 'Okoń, Płoć, Pstrąg (mały)', 'Kraina pstrąga', 'Strefa źródliskowa', false);

-- Spot 99: Zapadłe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70098, 'Brda - Zapadłe (Górny Strumień)', 'brda-zapadle-strumien', 'RIVER', 53.961728, 17.1897195, 'Pomorskie', 'Przechlewo', 'W rejonie miejscowości Zapadłe Brda przypomina dziki leśny strumień o bardzo zmiennej dynamice nurtu. Woda jest tu krystalicznie czysta, co sprawia, że pstrągi potokowe są niezwykle czujne i wymagają perfekcyjnego maskowania. Dno jest piaszczysto-żwirowe, z licznymi rynnami wymytymi pod korzeniami starych drzew. Najskuteczniejszą metodą jest tu „podchód” z krótkim spinningiem lub delikatną muchówką. Uciąg jest umiarkowany, ale w przewężeniach potrafi gwałtownie przyspieszyć, tworząc natlenione warkocze. To odcinek dla prawdziwych koneserów wędkarstwa, ceniących samotność i trudne technicznie rzuty w gęstwinie.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70098, 'Nizinna Mała', 'Leśny strumień, kręty', 6.0, 0.7, 'Piasek i żwir', 'Zwalone kłody', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', 'Brak', false);

-- Spot 100: Puszczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70099, 'Brda - Puszczyn (Leśne Meandry)', 'brda-puszczyn-meandry', 'RIVER', 53.4464314, 17.8903788, 'Kujawsko-Pomorskie', 'Gostycyn', 'Brda w Puszczynie to kwintesencja Borów Tucholskich, gdzie rzeka głęboko wcina się w leśny krajobraz. Odcinek ten słynie z bardzo dużej ilości zwalonych drzew, co tworzy naturalne poligon dla łowców grubych kleni i jazi. Dno jest tu twarde i czyste, z przewagą piasku wymytego przez silny nurt na zewnętrznych łukach. Spinningiści z sukcesem stosują tu woblery imitujące owady oraz małe gumy prowadzone w opadzie przy burtach. Uciąg wody jest stały i zdecydowany, co sprzyja dotlenieniu wody nawet w najgorętsze letnie dni. Dojazd jest utrudniony, co gwarantuje niską presję wędkarską i szansę na spotkanie z naprawdę wyrośniętym drapieżnikiem.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70099, 'Nizinna Mała', 'Meandrująca, leśna', 18.0, 1.5, 'Piasek', 'Naturalne zatory', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', 'Brak', false);

-- Spot 101: Sucha
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70100, 'Brda - Sucha (Strefa Cofki)', 'brda-sucha-cofka', 'RIVER', 53.4194366, 17.9319111, 'Kujawsko-Pomorskie', 'Koronowo', 'W miejscowości Sucha Brda zaczyna tracić swój nurtowy charakter, wchodząc powoli w strefę cofki Zalewu Koronowskiego. Rzeka wyraźnie się rozszerza, a jej nurt staje się leniwy, co sprzyja osadzaniu się drobniejszego piasku i mułu na dnie. To idealne miejsce na gruntową zasiadkę z nastawieniem na dorodne leszcze oraz wyrośnięte krąpie. Brzegi są gęsto porośnięte trzciną, w której cieniu czają się szczupaki czekające na jesienne ochłodzenie wody. Wędkarze często stosują tu klasycznego feedera, wykorzystując brak uciążliwego uciągu do precyzyjnego nęcenia. Spokój tej okolicy i bliskość szerokiej wody sprawiają, że ryby często migrują tutaj w poszukiwaniu pokarmu.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70100, 'Nizinna Średnia', 'Wolny nurt, szerokie koryto', 25.0, 2.0, 'Piaszczysto-muliste', 'Pasy trzcin', 'Leszcz, Krąp, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 102: Bieniek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70101, 'Brda - Bieniek (Rozlewisko)', 'brda-bieniek-rozlewisko', 'RIVER', 53.3880431, 17.9697208, 'Kujawsko-Pomorskie', 'Koronowo', 'Bieniek to odcinek o bardzo szerokim korycie, stanowiący bezpośrednie przedpole jeziora zaporowego w Koronowie. Głębokość w rynnie przekracza tu często 3 metry, co czyni to łowisko atrakcyjnym dla poszukiwaczy grubego okonia i sandacza. Dno jest mocno zróżnicowane, od piaszczystych blatów po głębokie jamy z naniesionym detrytusem organicznym. Uciąg jest niemal niewyczuwalny, dlatego wędkarze mogą stosować bardzo lekkie zestawy spławikowe typu odległościówka. Jest to świetny punkt do łowienia z łodzi, co pozwala na obłowienie niedostępnych z brzegu kęp grążeli. To łowisko słynie z dużej populacji białorybu, który grupuje się tutaj przed zbliżającą się zimą.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70101, 'Nizinna Średnia', 'Bardzo szerokie, wolne', 40.0, 3.2, 'Zróżnicowane', 'Grążele', 'Okoń, Sandacz, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 103: Koronowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70102, 'Brda - Koronowo (Odcinek Dolny)', 'brda-koronowo-dolna', 'RIVER', 53.3500734, 17.9751656, 'Kujawsko-Pomorskie', 'Koronowo', 'Dolny odcinek Brdy w Koronowie, poniżej zapory, to techniczne łowisko o zmiennym stanie wody i charakterze miejskim. Nurt bywa tu rwany, uzależniony od pracy elektrowni wodnej, co znacząco wpływa na aktywność żerowania ryb. Dno jest twarde, piaszczysto-kamieniste, z betonowymi umocnieniami brzegowymi w rejonie mostów i kładek. Spinningiści cenią to miejsce za populację kleni i okoni, które doskonale reagują na małe gumy prowadzone agresywnym skokiem. Wędkarze gruntowi powinni szukać ryb w głębokich rynnach pod drugim brzegiem, gdzie dno jest bardziej stabilne. To miejsce łączy w sobie wygodę miejskiej infrastruktury z szansą na kontakt z rybami przychodzącymi „z dołu” rzeki.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70102, 'Nizinna Średnia', 'Uregulowane, nurt zmienny', 30.0, 2.5, 'Twarde, piaszczyste', 'Betonowe umocnienia', 'Kleń, Okoń, Płoć', 'Kraina leszcza', 'Odcinek pod zaporką', false);

-- Spot 104: Rytel
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70103, 'Brda - Rytel (Szybki Nurt)', 'brda-rytel-szybki-nurt', 'RIVER', 53.7339284, 17.8100515, 'Pomorskie', 'Czersk', 'Rytel to legendarny punkt na Brdzie, gdzie rzeka płynie wartko, a jej charakterystyka przypomina wody podgórskie. Pomimo zniszczeń w drzewostanie sprzed lat, rzeka wciąż oferuje doskonałe warunki dla kleni, jazi i pstrągów. Dno jest tu w większości żwirowe i bardzo twarde, co sprzyja prowadzeniu przynęt spinningowych bez częstych zaczepów. Uciąg jest silny i jednostajny, dlatego wędkarze spławikowi najczęściej wybierają tutaj metodę bolońską. Warkocze powstające za przeszkodami to bankowe miejsca na spotkanie z żerującą brzaną, która rzadko, ale regularnie się tu melduje. To łowisko o dużym znaczeniu turystycznym, dlatego w sezonie warto wędkować tu o świcie, przed pojawieniem się kajakarzy.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70103, 'Podgórska', 'Szybki nurt, żwirowe dno', 16.0, 1.2, 'Żwir i piasek', 'Pale drewniane', 'Kleń, Jaź, Brzana', 'Kraina pstrąga', 'Brak', false);

-- Spot 105: Duża Klonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70104, 'Brda - Duża Klonia (Dzika Przystań)', 'brda-duza-klonia-dzika', 'RIVER', 53.7706607, 17.724622, 'Kujawsko-Pomorskie', 'Tuchola', 'W rejonie Dużej Klonii Brda przedziera się przez najgęstsze partie Borów Tucholskich, tworząc niezwykle dziki i naturalny krajobraz. Rzeka jest tu głęboka i ciemna, z dnem pokrytym warstwą liści i licznymi zatopionymi kłodami sosnowymi. To królestwo szczupaka, który znajduje tu idealne warunki do zasadzek w cieniu nadbrzeżnych olszyn. Nurt rzeki jest umiarkowany, co pozwala na precyzyjne spinningowanie lekkimi, płytko chodzącymi woblerami. Wędkarze gruntowi mogą liczyć na sporadyczne, ale za to bardzo duże liny żerujące w mulistych zatoczkach. Brak łatwego dojazdu autem sprawia, że jest to łowisko dla wytrwałych pasjonatów, gotowych na piesze wyprawy wzdłuż koryta.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70104, 'Nizinna Mała', 'Leśna, naturalna, głęboka', 20.0, 1.8, 'Piasek i detrytus', 'Zwalone drzewa', 'Szczupak, Lin, Okoń', 'Kraina leszcza', 'Brak', false);

-- Spot 106: Czernica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70105, 'Brda - Czernica (Leśne Przejście)', 'brda-czernica-lesne', 'RIVER', 53.8340606, 17.6519489, 'Pomorskie', 'Brusy', 'Brda w okolicach Czernicy to odcinek o niezwykle czystej wodzie, płynący przez malownicze tereny leśne. Dno jest tu w większości twarde i piaszczyste, z licznymi rynnami wymytymi przez jednostajny nurt. Wędkarze spinningowi mogą liczyć na regularne brania wyrośniętych okoni czających się przy podmytych brzegach. Spokojniejszy uciąg wody sprzyja również miłośnikom lekkiego feedera, celującym w dorodne płocie i krąpie. Brzegi są częściowo zalesione, co zapewnia naturalny cień w upalne dni i osłonę przed wiatrem. To idealne miejsce na techniczne łowienie w ruchu, wymagające od wędkarza precyzyjnych rzutów pod nawisy drzew.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70105, 'Nizinna Mała', 'Spokojny nurt, koryto naturalne', 12.0, 1.4, 'Piaszczyste', 'Zwalone kłody', 'Okoń, Płoć, Krąp', 'Kraina leszcza', false);

-- Spot 107: Turowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70106, 'Brda - Turowiec (Zatory)', 'brda-turowiec-zatory', 'RIVER', 53.799799, 17.6710722, 'Pomorskie', 'Brusy', 'Odcinek w Turowcu charakteryzuje się dość szybkim przepływem wody i licznymi naturalnymi przeszkodami w korycie. Liczne zwalone pnie drzew tworzą doskonałe stanowiska dla drapieżników, głównie szczupaków i większych okoni. Dno jest urozmaicone, piaszczysto-żwirowe, co sprzyja dotlenieniu wody i aktywności ryb reofilnych. Warto skupić się na obławianiu głębszych dołków powstających za zatorami z gałęzi. Uciąg rzeki jest tu zdecydowany, dlatego wędkarze gruntowi powinni stosować koszyki o masie co najmniej 30-40 gramów. Brak dużej presji wędkarskiej sprawia, że ryby są tu mniej płochliwe, ale nadal wymagają cichego podejścia.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70106, 'Nizinna Mała', 'Nurt zdecydowany, liczne zatory', 14.0, 1.5, 'Piaszczysto-żwirowe', 'Zwalone drzewa', 'Szczupak, Okoń, Jaź', 'Kraina leszcza', false);

-- Spot 108: Swornegacie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70107, 'Brda - Swornegacie (Przesmyk)', 'brda-swornegacie-przesmyk', 'RIVER', 53.8588955, 17.4977204, 'Pomorskie', 'Chojnice', 'Swornegacie to jeden z najbardziej rozpoznawalnych punktów na Brdzie, łączący jeziora Karsińskie i Witoczno. Rzeka rozlewa się tu szeroko, a jej koryto jest gęsto porośnięte pasami trzcin i grążeli. Jest to wymarzone łowisko dla łowców białorybu, szczególnie dorodnych leszczy, jazi oraz wyrośniętych wzdręg. Dno jest piaszczyste z lokalnymi warstwami mułu, co przyciąga ryby żerujące na bogatym pokarmie naturalnym. Nurt jest tu bardzo łagodny, co pozwala na komfortowe łowienie na delikatne zestawy spławikowe oraz odległościówki. Ze względu na wzmożony ruch turystyczny w sezonie, najlepsze wyniki osiąga się tu o świcie i po zmroku.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70107, 'Nizinna Średnia', 'Szerokie rozlewisko jeziorne', 25.0, 2.0, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Jaź, Wzdręga', 'Kraina leszcza', true);

-- Spot 109: Kopernica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70108, 'Brda - Kopernica (Bory)', 'brda-kopernica-bory', 'RIVER', 53.8069662, 17.4823708, 'Pomorskie', 'Chojnice', 'W Kopernicy Brda płynie przez gęste Bory Tucholskie, zachowując swój dziki i nieprzewidywalny charakter. Głębokość w rynnach sięga tu często dwóch metrów, a dno jest usiane zatopionymi korzeniami starych olch. To doskonałe miejsce dla spinningistów polujących na szczupaki, które znajdują tu idealne warunki do zasadzek. Uciąg wody jest stały i umiarkowany, co sprzyja precyzyjnemu prowadzeniu przynęt typu woblery i duże gumy. Brzegi są naturalne i miejscami trudnodostępne, co skutecznie eliminuje przypadkowych turystów. Wieczorne zasiadki z martwą rybką w głębszych partiach koryta mogą zaowocować braniem okazałego sandacza lub węgorza.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70108, 'Nizinna Mała', 'Leśna, dzika rzeka', 18.0, 1.8, 'Piaszczyste', 'Podmyte korzenie', 'Szczupak, Okoń, Sandacz', 'Kraina leszcza', false);

-- Spot 110: Lisewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70109, 'Brda - Lisewo (Bystrza)', 'brda-lisewo-bystrza', 'RIVER', 53.7810277, 17.2783035, 'Pomorskie', 'Przechlewo', 'Lisewo oferuje dostęp do Brdy o charakterze podgórskim z bardzo czystą wodą i twardym, żwirowym dnem. Nurt rzeki jest tu rwanym i szybki, tworząc liczne bystrza oraz natlenione warkocze za głazami. To królestwo pstrąga potokowego i lipienia, które wyśmienicie reagują na techniki muchowe i mikro-spinning. Wędkarze powinni skupić się na precyzyjnym obławianiu cieni rzucanych przez nadbrzeżne krzewy. Brodzenie jest tu możliwe, ale wymaga zachowania dużej ostrożności ze względu na silny prąd i śliskie podłoże. To elitarne łowisko, które wymaga od wędkarza wysokich umiejętności technicznych oraz stosowania bardzo cienkich przyponów.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70109, 'Podgórska', 'Bystry nurt, żwirowe dno', 10.0, 1.0, 'Żwirowe', 'Naturalne bystrza', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- Spot 111: Płaszczyca
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70110, 'Brda - Płaszczyca (Meandry)', 'brda-plaszczyca-meandry', 'RIVER', 53.7835005, 17.339469, 'Pomorskie', 'Przechlewo', 'Odcinek w Płaszczycy charakteryzuje się wąskim korytem i dużą dynamiką przepływu wody. Rzeka mocno tu meandruje, wymywając głębokie jamy na zewnętrznych łukach koryta, które są domem dla dużych kleni. Dno jest piaszczysto-żwirowe, wolne od większych ilości mułu, co zapewnia rybom doskonałe warunki tlenowe. Spinningista znajdzie tu mnóstwo technicznych miejsc do prowadzenia małych błystek obrotowych pod prąd. Uciąg jest silny, co wymusza stosowanie przynęt o agresywnej pracy, dobrze trzymających się w nurcie. Stanowiska brzegowe są nieliczne i wymagają wydeptania, co podkreśla surowy i naturalny klimat tego fragmentu rzeki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70110, 'Nizinna Mała', 'Wąskie, głębokie meandry', 8.0, 1.3, 'Piasek i żwir', 'Podmyte brzegi', 'Kleń, Okoń, Szczupak', 'Kraina leszcza', false);

-- Spot 112: Ciecholewy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70111, 'Brda - Ciecholewy (Łąki)', 'brda-ciecholewy-laki', 'RIVER', 53.8137508, 17.3724443, 'Pomorskie', 'Konarzyny', 'Ciecholewy to odcinek Brdy płynący pośród rozległych łąk, oferujący bardzo dobrą widoczność tafli wody. Rzeka posiada tu wyrównaną głębokość z kilkoma piaszczystymi przykosami, na których żerują stadne ukleje. Jest to świetne miejsce na metodę lekkiego gruntu, celującą w jaziową „srebrną łuskę” oraz dorodne płocie. Nurt jest jednostajny i łagodny, co pozwala na bardzo naturalną prezentację przynęty na zestawie spławikowym. Dno jest czyste i piaszczyste, co minimalizuje ryzyko zerwania zestawu na podwodnych przeszkodach. To łowisko idealne na popołudniowy relaks, zapewniające dużą częstotliwość brań białorybu przy zachowaniu ciszy na brzegu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70111, 'Nizinna Mała', 'Otwarty, łąkowy charakter', 15.0, 1.2, 'Piaszczyste', 'Brak', 'Płoć, Jaź, Ukleja', 'Kraina leszcza', false);

-- Spot 113: Nowa Brda
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70112, 'Brda - Nowa Brda (Dziki Przełom)', 'brda-nowa-brda-dziki', 'RIVER', 53.8793006, 17.2111237, 'Pomorskie', 'Przechlewo', 'Brda w Nowej Brdzie to jeden z najbardziej pierwotnych odcinków rzeki, płynący przez gęste, niedostępne lasy. Woda jest tu niezwykle czysta, a nurt rwie wartko po piaszczysto-żwirowym dnie usianym zwalonymi drzewami. To elitarne łowisko pstrąga potokowego, który znajduje tu idealne warunki do bytowania w głębokich rynnach pod korzeniami. Spinningowanie wymaga tu mistrzowskiej precyzji ze względu na wszechobecne przeszkody i wąskie koryto. Uciąg jest stały i zdecydowany, co sprzyja aktywności ryb łososiowatych niemal przez cały sezon. Miejsce to gwarantuje absolutną ciszę i brak kontaktu z cywilizacją, co jest rzadkością na tak popularnych szlakach.', 'PZW Słupsk');

