VALUES (70112, 'Podgórska', 'Leśna, naturalna, zatory', 7.0, 0.9, 'Żwir i piasek', 'Zwalone sosny', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', 'Brak', false);

-- Spot 114: gmina Przechlewo (Odcinek Dolny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70113, 'Brda - Przechlewo (Leśne Zakola)', 'brda-przechlewo-lesne', 'RIVER', 53.8448058, 17.1936719, 'Pomorskie', 'Przechlewo', 'Odcinek w gminie Przechlewo charakteryzuje się licznymi, ostrymi zakolami, które wymywają głębokie na ponad dwa metry jamy. Dno jest tu mocno zróżnicowane, piaszczyste z lokalnymi twardymi płatami gliny, co przyciąga dorodne jazie. Podmyte burty brzegowe są stałą kryjówką dla szczupaków, które chętnie atakują większe, wolno prowadzone gumy. Nurt jest tu umiarkowany, co pozwala na skuteczne łowienie lekkim feederem przy użyciu koszyków o wadze 20-30 gramów. Roślinność brzegowa jest dość gęsta, tworząc naturalne parawany dla wędkarzy polujących na płochliwe klenie. To bardzo rybny fragment rzeki, który regularnie zaskakuje wędkarzy różnorodnością gatunków migrujących z pobliskich jezior.', 'PZW Słupsk');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70113, 'Nizinna Mała', 'Bardzo kręte, meandrujące', 12.0, 1.4, 'Piasek i glina', 'Podmyte brzegi', 'Jaź, Szczupak, Płoć', 'Kraina leszcza', 'Brak', false);

-- Spot 115: Łubianka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70114, 'Brda - Łubianka (Szyja)', 'brda-lubianka-szyja', 'RIVER', 53.8115353, 17.2179764, 'Pomorskie', 'Przechlewo', 'W rejonie Łubianki Brda płynie przez otwarty teren łąkowy, co zapewnia doskonałą widoczność i ułatwia rzuty dłuższą odległościówką. Rzeka posiada tu wyrównaną głębokość z kilkoma piaszczystymi przykosami, na których żerują stadne ukleje i jelce. Nurt jest jednostajny i łagodny, co pozwala na bardzo naturalną prezentację przynęty na zestawie spławikowym. Dno jest czyste i piaszczyste, co minimalizuje ryzyko zerwania zestawu na podwodnych przeszkodach, sprzyjając początkującym. To świetne miejsce na metodę lekkiego gruntu, celującą w jaziową „srebrną łuskę” oraz dorodne płocie o świcie. Dostęp do wody jest wyjątkowo wygodny, co czyni ten odcinek bardzo przyjaznym dla wędkarzy zmotoryzowanych.', 'PZW Słupsk');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70114, 'Nizinna Mała', 'Otwarty, łąkowy charakter', 10.0, 1.1, 'Piaszczyste', 'Brak', 'Płoć, Jaź, Jelce', 'Kraina leszcza', 'Brak', false);

-- Spot 116: Kiełpiński Most
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70115, 'Brda - Kiełpiński Most (Głębokie Płanie)', 'brda-kielpinski-most', 'RIVER', 53.6190144, 17.9492158, 'Kujawsko-Pomorskie', 'Tuchola', 'Kiełpiński Most to klasyczna rzeczna równia o stabilnym uciągu i szerokim korycie w sercu Borów Tucholskich. Głębokość rzeki jest tu znacząca, a dno charakteryzuje się występowaniem twardych, gliniastych blatów idealnych dla leszczy. Spinningiści z sukcesami obławiają tutejsze kamienne opaski, na których często żerują piękne okonie i sandacze. Nurt rzeki pozwala na precyzyjne operowanie zestawem bolońskim, co czyni to miejsce mekką dla spławikowców. Przy filarach mostu tworzą się atrakcyjne warkocze, w których chętnie ustawiają się bolenie polujące na ukleję. To stanowisko oferuje duży komfort wędkowania dzięki stabilnym brzegom i dobremu dostępowi do samej wody.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70115, 'Nizinna Średnia', 'Uregulowane, głębokie', 20.0, 2.0, 'Glina i piasek', 'Filary mostu, opaski', 'Leszcz, Okoń, Sandacz', 'Kraina leszcza', 'Brak', true);

-- Spot 117: Tuchola (Plaskosz)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70116, 'Brda - Tuchola Plaskosz (Zakręt)', 'brda-tuchola-plaskosz', 'RIVER', 53.5886685, 17.9164896, 'Kujawsko-Pomorskie', 'Tuchola', 'Odcinek w rejonie Tucholi, zwany Plaskoszem, to miejsce o bardzo wysokim brzegu i rwie płynącej głęboko w dole. Rzeka tworzy tu spektakularne zakola, a dno jest usiane dużymi kamieniami i głazami narzutowymi. To królestwo brzan, które potężnie walczą w głównym nurcie i świetnie reagują na ciężki feeder z serem. Warkocze powstające za naturalnymi przeszkodami to bankowe miejsca na spotkanie z żerującym kleniem i boleniem. Uciąg wody jest tu rwanym i nieprzewidywalny, co wymaga od wędkarza dużej kondycji przy schodzeniu na stanowiska. Miejsce to zachwyca dzikością krajobrazu, przypominając momentami rzeki o charakterze podgórskim.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70116, 'Podgórska', 'Szybki nurt, wysokie brzegi', 22.0, 1.5, 'Kamieniste', 'Głazy narzutowe', 'Brzana, Kleń, Jaź', 'Kraina brzany', 'Brak', false);

-- Spot 118: Koronowo (Grabina)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70117, 'Brda - Koronowo (Grabina)', 'brda-koronowo-grabina', 'RIVER', 53.3147408, 17.9623445, 'Kujawsko-Pomorskie', 'Koronowo', 'Barycz w Koronowie poniżej zapory to odcinek o charakterze kanałowym ze stabilnym poziomem wody i uregulowanymi brzegami. Woda jest tu głęboka, a dno wyrównane i piaszczyste, co sprzyja metodzie „method feeder” w poszukiwaniu leszczy. Często spotyka się tu ryby migrujące z głównego koryta Wisły, w tym piękne certy oraz płocie. Uciąg wody jest umiarkowany i przewidywalny, co pozwala na idealną prezentację przynęty na długich dystansach. W cieniu nadbrzeżnych krzewów często chowają się dorodne okonie, które agresywnie reagują na boczny trok. To łowisko idealne na popołudniowy relaks, zapewniające dużą częstotliwość brań białorybu niemal przez cały rok.', 'PZW Bydgoszcz');

