-- Spot 119: Samociążek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70118, 'Brda - Samociążek (Kanalizacja)', 'brda-samociazek-kanal', 'RIVER', 53.2786124, 17.9541175, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Samociążek to odcinek słynący z kanału rzutowego elektrowni, gdzie woda jest dobrze natleniona i przyciąga stada białorybu. Dno jest tu twarde, piaszczysto-betonowe, z dużą ilością pokarmu naturalnego wymywanego przez silny nurt. Jest to doskonałe łowisko dla miłośników odległościówki oraz ciężkiego feedera, nastawionych na wyrośnięte krąpie i leszcze. W okresach letnich na powierzchni wody widać intensywne ataki boleni polujących w warkoczach przy śluzach. Uciąg jest silny i uzależniony od pracy turbin, co wymusza stosowanie dociążonych zestawów gruntowych. Miejsce to jest bardzo popularne wśród bydgoskich wędkarzy ze względu na gwarancję brań nawet w trudniejszych pogodowo dniach.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70118, 'Nizinna Średnia', 'Uregulowane koryto, kanał', 40.0, 3.0, 'Twarde', 'Kanały zrzutowe, śluzy', 'Leszcz, Krąp, Boleń', 'Kraina leszcza', 'Obręb ochronny przy elektrowni', true);

-- Spot 120: Tryszczyn (Elektrownia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70119, 'Brda - Tryszczyn (Poniżej Elektrowni)', 'brda-tryszczyn-elektrownia', 'RIVER', 53.2431097, 17.9391451, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Odcinek w Tryszczynie poniżej zapory elektrowni charakteryzuje się zmiennym uciągiem wody i twardym, kamienistym dnem. Silny nurt poniżej zrzutu tworzy doskonale natlenione warkocze, które przyciągają stada brzan oraz kleni. Wędkarze spinningowi mogą tu liczyć na spotkanie z walecznym boleniem polującym przy betonowych umocnieniach. W rynnach o głębokości do trzech metrów często stacjonują sandacze, reagujące na agresywny opad gumowych przynęt. Należy zachować szczególną ostrożność, gdyż poziom wody może się gwałtownie podnieść w zależności od pracy turbin. To techniczne łowisko dla profesjonalistów, wymagające stosowania ciężkich zestawów i stabilnych podpórek gruntowych.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70119, 'Nizinna Średnia', 'Uregulowane, nurt zmienny', 35.0, 2.5, 'Kamienisto-betonowe', 'Zapora, kanały zrzutowe', 'Brzana, Sandacz, Boleń', 'Kraina brzany', 'Obręb ochronny przy elektrowni', true);

-- Spot 121: Tryszczyn (Leśny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70120, 'Brda - Tryszczyn (Leśne Zakole)', 'brda-tryszczyn-lesne', 'RIVER', 53.207186, 17.9350198, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Nieco dalej od elektrowni Brda wkracza w malowniczy las, tworząc głębokie zakola o piaszczystym dnie. Rzeka jest tu szeroka i płynie jednostajnie, co sprzyja systematycznemu nęceniu stadnych leszczy oraz krąpi. Podmyte brzegi porośnięte wikliną skrywają wyrośnięte okonie, które chętnie uderzają w małe błystki obrotowe. To doskonałe miejsce na nocne polowanie za sumem, który chętnie odwiedza tutejsze jamy pod przeciwległym brzegiem. Uciąg jest umiarkowany, co pozwala na komfortowe łowienie metodą bolońską oraz klasycznym feederem. Cisza panująca wzdłuż leśnego brzegu zapewnia doskonały relaks i szansę na kontakt z dziką naturą.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70120, 'Nizinna Średnia', 'Meandrująca, leśna', 40.0, 2.0, 'Piasek i glina', 'Zwalone drzewa', 'Leszcz, Sum, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 122: Bydgoszcz (Opławiec)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70121, 'Brda - Bydgoszcz (Opławiec)', 'brda-bydgoszcz-oplawiec', 'RIVER', 53.1731606, 17.9602809, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Opławiec to jedno z ulubionych łowisk bydgoszczan, oferujące rzekę o krystalicznej wodzie i żwirowym podłożu. Nurt jest tu rwanym i dość szybki, co nadaje Brdzie charakter rzeki niemal górskiej w tym regionie. To legendarne miejsce na klenia i jazia, które doskonale reagują na techniki spinningowe oraz lekką przepływankę. Dno jest czyste i twarde, z nielicznymi zaczepami w postaci zatopionych faszynowych umocnień. Brzegi są łatwo dostępne i porośnięte trawą, co zapewnia ogromny komfort przy rozkładaniu profesjonalnego siedziska. Wczesną wiosną można tu liczyć na wejście dużych płoci, które migrują w górę nurtu z miejskich odcinków rzeki.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70121, 'Nizinna Średnia', 'Naturalne, dno twarde', 25.0, 1.5, 'Żwir i piasek', 'Opaski faszynowe', 'Kleń, Jaź, Płoć', 'Kraina brzany', 'Brak', false);

-- Spot 123: Bydgoszcz (Smukała)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70122, 'Brda - Bydgoszcz (Smukała)', 'brda-bydgoszcz-smukala', 'RIVER', 53.1374674, 17.973413, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Bóbr w Smukale to odcinek pod wpływem pracy kolejnej elektrowni, co wymusza na wędkarzach dostosowanie się do skoków poziomu wody. Dno jest tu mocno urozmaicone kamiennymi narzutami i głębokimi rynnami, sięgającymi nawet czterech metrów. To wymarzone stanowisko dla łowców drapieżników, szczególnie grubych okoni oraz czatujących w nurcie sandaczy. Wędkarze gruntowi stosują tu ciężkie koszyki, celując w leszcze i certy, które chętnie żerują przy samym dnie. Uciąg rzeki potrafi być bardzo silny, co wymaga użycia solidnego sprzętu i mocnych żyłek przyponowych. Miejsce to łączy w sobie urok podmiejskiej przyrody z szansą na kontakt z rybami rekordowych rozmiarów.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70122, 'Nizinna Średnia', 'Uregulowane, głębokie', 30.0, 3.5, 'Kamienie i piasek', 'Zapora, mosty', 'Okoń, Sandacz, Certa', 'Kraina leszcza', 'Obręb ochronny przy elektrowni', true);

-- Spot 124: gmina Przechlewo (Górna Brda)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70123, 'Brda - Przechlewo (Dziki Strumień)', 'brda-przechlewo-strumien', 'RIVER', 53.9274978, 17.2092823, 'Pomorskie', 'Przechlewo', 'W górnym biegu w gminie Przechlewo Brda przypomina dziki leśny strumień o wyjątkowo bystrym nurcie. Koryto jest tu wąskie i usiane zwalonymi drzewami, co tworzy idealne warunki dla pstrąga potokowego. Woda jest krystalicznie czysta, co zmusza wędkarza do pełnego maskowania i bardzo dyskretnego podejścia do stanowiska. Dno jest piaszczysto-żwirowe, z rzadkimi rynnami wymytymi pod brzegowymi olszynami. Najskuteczniejszą techniką na tym odcinku jest precyzyjna mucha lub ultra-lekki spinning z wykorzystaniem mikrojigów. To odcinek dla prawdziwych koneserów ceniących samotność i techniczne łowienie w surowych, leśnych warunkach.', 'PZW Słupsk');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70123, 'Nizinna Mała', 'Wąskie, dzikie koryto', 6.0, 0.8, 'Piasek i żwir', 'Zwalone kłody', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', 'Brak', false);

-- Spot 125: Bydgoszcz (Centrum / Wyspa Młyńska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70124, 'Brda - Bydgoszcz (Centrum)', 'brda-bydgoszcz-centrum', 'RIVER', 53.1212346, 18.0271269, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Miejski odcinek Brdy w samym sercu Bydgoszczy to techniczne łowisko z głębokimi rynnami przy betonowych bulwarach. Dno jest tu twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu w okolicach filarów mostowych i kładek. Czysta woda sprzyja bytowaniu dużej populacji kleni i jazi, które chętnie żerują w cieniu miejskiej architektury. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka lub lekkie jigi prowadzone przy murach oporowych. Uciąg rzeki jest tu umiarkowany, co pozwala na precyzyjne operowanie zestawami spławikowymi typu bolonka. Wieczorami, przy sztucznym oświetleniu bulwarów, można liczyć na widowiskowe brania drapieżników polujących na ukleje.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70124, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 30.0, 3.5, 'Twarde, piaszczyste', 'Bulwary, mosty, śluzy', 'Kleń, Jaź, Okoń, Płoć', 'Kraina brzany', 'Odcinek miejski', false);

-- Spot 126: Bydgoszcz (Brdyujście)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70125, 'Brda - Bydgoszcz (Brdyujście)', 'brda-bydgoszcz-brdyujscie', 'RIVER', 53.122726, 18.0890913, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Odcinek w Brdyujściu to miejsce, gdzie rzeka przygotowuje się do połączenia z Wisłą, nabierając szerokiego i głębokiego charakteru. Woda płynie tu leniwie, a dno jest zróżnicowane — od piaszczystych blatów po muliste rynny sięgające nawet pięciu metrów głębokości. To legendarne łowisko rekordowych leszczy i krąpi, które wchodzą tutaj masowo z nurtu Wisły. Wędkarze gruntowi stosują tu ciężkie feedery, celując w ryby żerujące na pograniczu spokojnej wody i głównego nurtu. Wzdłuż brzegów znajdują się liczne kępy grążeli, w których jesienią czają się potężne szczupaki i sandacze. Dzięki bliskości toru regatowego, dostęp do wody jest tu bardzo dobry, a stanowiska są stabilne i przestronne.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70125, 'Nizinna Wielka', 'Szerokie rozlewisko ujściowe', 50.0, 4.5, 'Piasek i muł', 'Śluzy, falochrony', 'Leszcz, Krąp, Szczupak, Sandacz', 'Kraina leszcza', 'Strefa przyujściowa', true);

-- Spot 127: Stachowo (Górna Brda)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70126, 'Brda - Stachowo (Górne Przełomy)', 'brda-stachowo-przelomy', 'RIVER', 54.0163049, 17.0647136, 'Pomorskie', 'Miastko', 'W rejonie Stachowa Brda zachowuje swój pierwotny, niemal potokowy charakter z krystalicznie czystą i zimną wodą. Koryto rzeki jest tu wąskie, a nurt rwie wartko przez dzikie tereny leśne i podmokłe łąki. Dno jest twarde, żwirowo-piaszczyste, z licznymi mikrowarkoczami powstającymi za kamieniami i zwalonymi gałęziami. To klasyczne stanowisko pstrągowe, wymagające od wędkarza dużej kondycji i umiejętności cichego podchodu pod prąd. Spinningiści z sukcesami obławiają tutejsze rynny przy użyciu małych obrotówek oraz woblerów o agresywnej pracy. Ze względu na dziki charakter brzegu, jest to łowisko o bardzo niskiej presji, nagradzające wytrwałych łowców ryb łososiowatych.', 'PZW Słupsk');

