VALUES (70126, 'Nizinna Mała', 'Wąski strumień, nurt szybki', 5.0, 0.6, 'Żwir i piasek', 'Naturalne zatory', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', 'Strefa chroniona Natura 2000', false);

-- Spot 128: gmina Brusy (Drzewicz)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70127, 'Brda - Brusy (Drzewicz)', 'brda-brusy-drzewicz', 'RIVER', 53.8663824, 17.5578075, 'Pomorskie', 'Chojnice', 'Odcinek w gminie Brusy, w rejonie Drzewicza, to rzeka o szerokim korycie łącząca systemy jezior Borów Tucholskich. Woda ma tu umiarkowany uciąg i przepływa przez tereny o bogatej roślinności wynurzonej, co tworzy idealne warunki dla jazi i kleni. Dno jest piaszczyste, z lokalnymi naniesieniami mułu w zatoczkach, gdzie chętnie żerują wyrośnięte płocie oraz lin. spinningista znajdzie tutaj dogodne miejsca do prowadzenia gum na lekkich główkach w poszukiwaniu szczupaków czających się w trzcinowiskach. To łowisko słynie z bardzo dużej przejrzystości wody, co zmusza do stosowania cienkich i niewidocznych przyponów fluorocarbonowych. Bliskość bazy turystycznej ułatwia dostęp do wody, ale w sezonie letnim wymaga wędkowania we wczesnych godzinach porannych.', 'PZW Bydgoszcz');

