VALUES (70127, 'Nizinna Mała', 'Spokojna rzeka jeziorna', 20.0, 1.8, 'Piasek i detrytus', 'Pasy trzcin', 'Jaź, Kleń, Szczupak, Płoć', 'Kraina leszcza', 'Brak', true);

