-- Spot 129: Gulczewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70128, 'Bug - Gulczewo (Przykosy)', 'bug-gulczewo-przykosy', 'RIVER', 52.5397862, 21.3707927, 'Mazowieckie', 'Wyszków', 'Bug w Gulczewie to odcinek o klasycznym, nizinnym charakterze z licznymi piaszczystymi przykosami. Nurt rzeki jest tu dość żwawy, co sprzyja dotlenieniu wody nawet podczas letnich upałów. Dno jest w przeważającej części twarde i piaszczyste, z rzadkimi rynnami wymytymi pod zwalonymi drzewami. To doskonałe miejsce dla łowców boleni, które widowiskowo polują na tutejszych przelewach i piaszczystych łachach. Wędkarze gruntowi powinni szukać głębszych dołków na zakrętach, nęcąc grubszą frakcją w celu zwabienia leszczy. Dojazd do samej wody jest możliwy polnymi drogami, jednak wymaga zachowania ostrożności po intensywnych opadach.', 'PZW Warszawa');

