-- Spot 130: Dręszew
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70129, 'Bug - Dręszew (Głębokie Płanie)', 'bug-dreszew-planie', 'RIVER', 52.5325466, 21.2970185, 'Mazowieckie', 'Radzymin', 'W Dręszewie rzeka Bug płynie szerokim korytem, oferując wędkarzom liczne i stabilne stanowiska brzegowe. Dno jest zróżnicowane, piaszczysto-gliniaste, z wyraźnymi uskokami rzeźbiącymi ciekawe jamy dla sumów. Odcinek ten słynie z bogatej populacji leszcza oraz krąpia, które bardzo dobrze reagują na systematyczne nęcenie. Spinningiści z sukcesem obławiają tutejsze kamienne opaski, na których wieczorami żerują sandacze i okonie. Uciąg wody jest umiarkowany, co pozwala na komfortowe łowienie metodą feederową z koszykami 40-60 gramów. To spokojne łowisko o niskiej presji, idealne na całodniową zasiadkę w otoczeniu nadbużańskiej przyrody.', 'PZW Warszawa');

