VALUES (70129, 'Nizinna Wielka', 'Szerokie płanie, nurt umiarkowany', 140.0, 2.2, 'Piasek i glina', 'Opaski kamienne', 'Leszcz, Krąp, Sandacz, Sum', 'Kraina leszcza', true);

-- Spot 131: Janki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70130, 'Bug - Janki (Karczowiska)', 'bug-janki-karczowiska', 'RIVER', 52.5329186, 21.2199623, 'Mazowieckie', 'Somianka', 'Okolice Janek to jeden z trudniejszych technicznie odcinków rzeki ze względu na dużą ilość zatopionych przeszkód. Bug mocno tu meandruje, wymywając głębokie na kilka metrów jamy pod stromymi brzegami porośniętymi wikliną. Dno jest usiane korzeniami, co tworzy idealne warunki dla szczupaków czających się w zasadzkach. Uciąg jest silny i rwanym, dlatego warto stosować dociążone zestawy spinningowe i wytrzymałe plecionki. Wędkarze gruntowi celujący w brzany powinni szukać twardych, żwirowych fragmentów dna w głównym nurcie. Miejsce to wymaga od wędkarza dużego doświadczenia w czytaniu wody i cierpliwości przy uwalnianiu zaczepów.', 'PZW Warszawa');

