VALUES (70130, 'Nizinna Wielka', 'Meandrująca, zatory', 110.0, 2.5, 'Piasek i korzenie (karcz)', 'Zatopione drzewa', 'Szczupak, Brzana, Okoń', 'Kraina brzany/leszcza', true);

-- Spot 132: Kuligów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70131, 'Bug - Kuligów (Rozlewisko)', 'bug-kuligow-rozlewisko', 'RIVER', 52.5101173, 21.1561206, 'Mazowieckie', 'Kuligów', 'Kuligów to legendarne łowisko, położone na szerokim rozlewisku przed samym ujściem do Zalewu Zegrzyńskiego. Rzeka wyraźnie tu zwalnia, a jej koryto staje się głębokie i mulisto-piaszczyste na spokojnych płaniach. To wymarzone miejsce dla łowców rekordowych leszczy, jazi oraz wyrośniętych płoci wchodzących z jeziora. Spinningiści cenią ten odcinek za doskonałe warunki do prowadzenia gum w opadzie w poszukiwaniu sandaczy. Liczne kępy grążeli przy brzegach stanowią stałą bazę dla szczupaków oraz dużych, stadnych okoni. Stanowiska są tu bardzo liczne i wygodne, co przyciąga rzesze wędkarzy szczególnie w weekendowe poranki.', 'PZW Warszawa');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70131, 'Nizinna Wielka', 'Szerokie rozlewisko ujściowe', 180.0, 3.0, 'Muł i piasek', 'Roślinność zanurzona', 'Leszcz, Jaź, Sandacz, Okoń', 'Kraina leszcza', true);

-- Spot 133: Arciechów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70132, 'Bug - Arciechów (Cypel)', 'bug-arciechow-cypel', 'RIVER', 52.5053271, 21.0796895, 'Mazowieckie', 'Serock', 'Arciechów to strategiczny punkt, gdzie wody Bugu łączą się z Narwią, tworząc ogromne i bardzo rybne rozlewisko. Głębokość rzeki jest tu znacząca, a dno charakteryzuje się występowaniem twardych, gliniastych blatów idealnych dla sumów. To strategiczne miejsce dla łowców okazów, gdyż krzyżują się tu szlaki migracyjne wielu gatunków drapieżników. Nurt rzeki jest tu zmienny i mocno uzależniony od poziomu piętrzenia wody na zaporze w Dębem. Wędkarze gruntowi z sukcesami łowią tu potężne leszcze, stosując ciężkie zestawy zdolne utrzymać się w nurcie. Ze względu na dużą przestrzeń wodną, jest to również doskonały poligon dla wędkarzy łowiących z łodzi.', 'PZW Warszawa');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70132, 'Nizinna Wielka', 'Ujściowy, charakter jeziorny', 350.0, 4.0, 'Glina i piach', 'Trzcinowiska', 'Sum, Leszcz, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 134: Brok
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70133, 'Bug - Brok (Nadbużańskie Łachy)', 'bug-brok-lachy', 'RIVER', 52.7027587, 21.8910816, 'Mazowieckie', 'Brok', 'Bug w Broku zachwyca naturalnym krajobrazem i niezwykle urozmaiconą linią brzegową z wieloma piaszczystymi łachami. Rzeka posiada tu wyrównaną głębokość z kilkoma bardzo głębokimi rynnami wymytymi na zewnętrznych zakolach. Dno jest piaszczyste, co sprzyja bytowaniu brzan oraz kleni, które doskonale reagują na metodę przepływanki. Spinningiści znajdą tutaj doskonałe rynny do prowadzenia woblerów w poszukiwaniu boleni polujących pod samym brzegiem. Uciąg wody jest stały i zdecydowany, co sprzyja natlenieniu wody i aktywności ryb przez całą dobę. Dogodny dostęp do lustra wody w rejonie miejskiej plaży czyni to miejsce bardzo popularnym punktem wypadowym.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70133, 'Nizinna Wielka', 'Szerokie, meandrujące koryto', 100.0, 1.8, 'Piaszczyste', 'Łachy, piaszczyste przykosy', 'Brzana, Kleń, Boleń, Jaź', 'Kraina brzany', true);

-- Spot 135: Płatkownica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70134, 'Bug - Płatkownica (Dzikie Zakręty)', 'bug-platkownica-zakrety', 'RIVER', 52.6849161, 21.8226286, 'Mazowieckie', 'Sadowne', 'Odcinek w Płatkownicy charakteryzuje się dzikim charakterem koryta z bardzo dużą ilością zwalonych do wody drzew. Bug płynie tu krętym korytem, a jego dno jest mocno pofałdowane z licznymi górkami i głębokimi dołkami. Jest to doskonała lokalizacja dla łowców szczupaków, którzy precyzyjnie obławiają każdą podwodną przeszkodę. Wędkarze stacjonarni powinni szukać ryb w głębokich jamach, nęcąc ziarnami kukurydzy w celu przyciągnięcia dużych jazi. Uciąg jest umiarkowany, co pozwala na komfortowe łowienie feederem bez ryzyka ciągłego przemieszczania zestawu. Cisza i surowy, nadbużański krajobraz sprawiają, że jest to łowisko wyjątkowe dla osób szukających ucieczki od cywilizacji.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70134, 'Nizinna Wielka', 'Naturalne, kręte koryto', 90.0, 2.2, 'Piasek i glina', 'Zwalone drzewa (karpy)', 'Szczupak, Jaź, Brzana', 'Kraina leszcza', true);

-- Spot 136: Mołożew-Dwór
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70135, 'Bug - Mołożew-Dwór (Podlaski Przełom)', 'bug-molozerw-dwor', 'RIVER', 52.4618832, 22.5305879, 'Mazowieckie', 'Sokołów Podlaski', 'Bug w Mołożewie to odcinek o niezwykle dzikim charakterze, z licznymi piaszczystymi przykosami i głębokimi rynnami. Nurt rzeki jest tu dość żwawy, co sprzyja dotlenieniu wody nawet podczas letnich niżówek. Dno jest w przeważającej części twarde i piaszczyste, z rzadkimi rynnami wymytymi pod zwalonymi drzewami. To doskonałe miejsce dla łowców boleni, które widowiskowo polują na tutejszych przelewach i piaszczystych łachach. Wędkarze gruntowi powinni szukać głębszych dołków na zakrętach, nęcąc grubszą frakcją w celu zwabienia stadnych leszczy. Dojazd do samej wody jest możliwy polnymi drogami, jednak wymaga zachowania ostrożności po intensywnych opadach.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70135, 'Nizinna Wielka', 'Dzika, nieuregulowana', 130.0, 1.8, 'Piaszczyste', 'Przykosy, piaszczyste łachy', 'Boleń, Leszcz, Brzana', 'Kraina leszcza', true);

-- Spot 137: Bużyski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70136, 'Bug - Bużyski (Rynna Podlaska)', 'bug-buzyski', 'RIVER', 52.5073623, 22.5227382, 'Mazowieckie', 'Korczew', 'Bużyski to jeden z najciekawszych technicznie odcinków rzeki Bug w regionie Podlaskiego Przełomu. Rzeka płynie tu szerokim korytem, oferując wędkarzom liczne piaszczyste łachy oraz głębokie rynny pod stromymi burtami. Dno jest zróżnicowane, piaszczysto-gliniaste, z wyraźnymi uskokami rzeźbiącymi ciekawe kryjówki dla sumów. Spinningiści z sukcesem obławiają tutejsze kamienne narzuty, na których wieczorami żerują sandacze i okonie. Uciąg wody jest umiarkowany, co pozwala na komfortowe łowienie metodą feederową z koszykami o wadze 60 gramów. To spokojne łowisko o niskiej presji, idealne na całodniową zasiadkę w otoczeniu dzikiej, nadbużańskiej przyrody.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70136, 'Nizinna Wielka', 'Nurt umiarkowany, szerokie płanie', 140.0, 2.2, 'Piasek i glina', 'Opaski kamienne', 'Leszcz, Sandacz, Sum', 'Kraina leszcza', true);

-- Spot 138: Granne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70137, 'Bug - Granne (Mostowa Przykosa)', 'bug-granne', 'RIVER', 52.5485433, 22.490106, 'Podlaskie', 'Siemiatycze', 'Bug w Grannem słynie z malowniczych zakoli oraz rozległych, piaszczystych przykos, które są domem dla dużych boleni. W rejonie mostu nurt wyraźnie przyspiesza, żłobiąc dno i tworząc atrakcyjne warkocze za naturalnymi przeszkodami. Dno jest przeważnie piaszczyste, jednak w głębszych rynnach można natrafić na twardsze, żwirowe fragmenty idealne dla brzan. Wędkarze stacjonarni często wybierają spokojniejsze klatki między przykosami, celując w dorodne leszcze oraz jazie. Uciąg rzeki wymaga stosowania dociążonych zestawów, które stabilnie utrzymają przynętę w głównym nurcie rzeki. Brzeg jest tu łatwo dostępny, co czyni ten odcinek popularnym punktem wypadowym dla wędkarzy z całego regionu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70137, 'Nizinna Wielka', 'Szybki nurt, zmienna głębokość', 120.0, 1.5, 'Piasek i żwir', 'Filary mostu, przykosy', 'Boleń, Brzana, Jaź', 'Kraina brzany', true);

-- Spot 139: gmina Jabłonna Lacka (Wieska-Gródek)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70138, 'Bug - Jabłonna Lacka (Karczowisko)', 'bug-jablonna-lacka', 'RIVER', 52.5869676, 22.450966, 'Mazowieckie', 'Sokołów Podlaski', 'Odcinek Bugu w gminie Jabłonna Lacka charakteryzuje się dzikim charakterem koryta z bardzo dużą ilością zwalonych drzew. Rzeka mocno tu meandruje, wymywając głębokie na kilka metrów jamy, które są idealnym schronieniem dla sumów. Dno jest usiane korzeniami, co tworzy naturalne kryjówki dla szczupaków czających się w brzegowych zastoiskach. Wędkarze spinningowi powinni skupić się na precyzyjnym obławianiu karczów, wykorzystując gumy na ciężkich główkach jigowych. Silny uciąg rzeki w tym miejscu sprawia, że ryby są niezwykle waleczne i silne podczas holu. Jest to techniczny odcinek rzeki, który wymaga od wędkarza umiejętności czytania wody i sporej dozy cierpliwości.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70138, 'Nizinna Wielka', 'Meandrująca, zatory leśne', 110.0, 2.5, 'Piasek i korzenie (karcz)', 'Zwalone drzewa', 'Sum, Szczupak, Brzana', 'Kraina brzany/leszcza', true);

-- Spot 140: Kiezie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70139, 'Bug - Kiezie (Zastoiska)', 'bug-kiezie', 'RIVER', 52.6142465, 22.3914503, 'Podlaskie', 'Drohiczyn', 'Kiezie to spokojny odcinek rzeki Bug, gdzie nurt zwalnia, tworząc szerokie płanie o piaszczysto-mulistym dnie. Jest to wymarzone miejsce dla miłośników metody gruntowej, nastawionych na połów dużych jazi oraz wyrośniętych płoci. Przy brzegach znajdziemy liczne pasy trzcin, które są naturalną bazą wypadową dla szczupaków i okoni. Niska presja wędkarska sprawia, że ryby są tu mniej płochliwe, co pozwala na skuteczne nęcenie blisko brzegu. Uciąg jest na tyle słaby, że pozwala na stosowanie lżejszych koszyków zanętowych, co poprawia czułość całego zestawu. To doskonałe miejsce na weekendową zasiadkę, gwarantujące ciszę i bliski kontakt z surową naturą nadbużańskiego krajobrazu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70139, 'Nizinna Wielka', 'Nurt wolny, szerokie koryto', 150.0, 1.6, 'Piasek i muł', 'Pasy trzcin', 'Jaź, Płoć, Szczupak', 'Kraina leszcza', true);

-- Spot 141: Kamianka Nadbużna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70140, 'Bug - Kamianka (Gliniaste Blaty)', 'bug-kamianka-nadbuzna', 'RIVER', 52.6550139, 22.3501341, 'Mazowieckie', 'Brok', 'Kamianka Nadbużna oferuje wędkarzom dostęp do rzeki o bardzo urozmaiconej linii brzegowej z licznymi zakolami. Woda w tym miejscu jest dość głęboka, sięgając w najniższych punktach rynny nawet do trzech metrów głębokości. Dno charakteryzuje się występowaniem twardych, gliniastych blatów, które są ulubionym miejscem żerowania brzan i kleni. Warkocze powstające za naturalnymi przeszkodami to bankowe miejsca na spotkanie z agresywnym boleniem polującym przy powierzchni. Nurt rzeki jest jednostajny i przewidywalny, co ułatwia systematyczne nęcenie pola łowiska i utrzymanie w nim ryb. Wieczorne wyprawy z martwą rybką mogą zakończyć się tu emocjonującym holem solidnego sandacza lub suma.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70140, 'Nizinna Wielka', 'Głębokie zakola', 100.0, 2.8, 'Twarde, gliniaste', 'Zwaliska kamieni', 'Brzana, Sandacz, Boleń', 'Kraina brzany', true);

-- Spot 142: Łęg Nurski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70141, 'Bug - Łęg Nurski (Dzika Burta)', 'bug-leg-nurski', 'RIVER', 52.6700116, 22.27899912, 'Mazowieckie', 'Nur', 'Odcinek w Łęgu Nurskim to kwintesencja środkowego Bugu z rozległymi przykosami i dzikimi, podmytymi burtami. Rzeka posiada tu wyraźnie zaznaczony nurt główny, który niesie duże ilości pokarmu, przyciągając stada białorybu. Dno pozostaje zróżnicowane, z przewagą twardego piasku oraz lokalnymi, żwirowymi rynnami idealnymi pod technikę bolońską. Wędkarze spinningowi znajdą tutaj liczne zwalone drzewa, które stanowią bezpieczne schronienie dla wyrośniętych szczupaków i okoni. Uciąg wody jest zdecydowany, co wymusza stosowanie dociążonych zestawów gruntowych zdolnych utrzymać się w głównym prądzie. Cisza i brak bliskiej zabudowy sprawiają, że ryby żerują tu śmiało, dając szansę na kontakt z prawdziwym okazem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70141, 'Nizinna Wielka', 'Dzika rzeka, podmyte brzegi', 110.0, 2.0, 'Piasek i żwir', 'Podmyte korzenie', 'Szczupak, Leszcz, Kleń', 'Kraina leszcza', true);

-- Spot 143: Zakrzewo-Słomy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70142, 'Bug - Zakrzewo-Słomy (Ostra Burta)', 'bug-zakrzewo-slomy', 'RIVER', 52.6968786, 22.2189066, 'Mazowieckie', 'Nur', 'Odcinek w Zakrzewie-Słomach charakteryzuje się bardzo wysoką, podmytą burtą, pod którą nurt żłobi głębokie rynny. To klasyczne stanowisko dla łowców sumów, którzy znajdują tu doskonałe warunki do stacjonarnej zasiadki zrywkową metodą. Dno jest tu twarde, gliniaste, z licznymi karczami stanowiącymi naturalne schronienie dla rekordowych drapieżników. Spinningiści z sukcesami obławiają tutejsze warkocze, celując w żerujące w głównym nurcie bolenie i sandacze. Uciąg rzeki jest tu zdecydowany i stabilny, co sprzyja natlenieniu wody nawet podczas letnich upałów. To dzikie i nieprzewidywalne łowisko, które wymaga od wędkarza sporego doświadczenia w czytaniu nurtu i wytrzymałości sprzętowej.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70142, 'Nizinna Wielka', 'Dzika, z wysoką burtą', 115.0, 2.5, 'Glina i korzenie', 'Podmyte brzegi', 'Sum, Sandacz, Boleń', 'Kraina brzany/leszcza', true);

-- Spot 144: Drohiczyn (Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70143, 'Bug - Drohiczyn (Pod Zamkową Górą)', 'bug-drohiczyn-wschod', 'RIVER', 52.3931357, 22.6919116, 'Podlaskie', 'Drohiczyn', 'Bug w Drohiczynie pod Górą Zamkową to jedno z najbardziej malowniczych i rybnych miejsc na całym Podlasiu. Rzeka płynie tu szerokim korytem o urozmaiconym dnie, z licznymi piaszczystymi przykosami i głębokimi rynnami w nurcie. To prawdziwe królestwo jazi i kleni, które doskonale reagują na techniki spinningowe oraz lekką przepływankę. Warkocze powstające za kamiennymi umocnieniami brzegowymi to bankowe punkty na spotkanie z walecznym boleniem. Uciąg rzeki jest tu umiarkowany, co pozwala na komfortowe łowienie feederem przy użyciu koszyków o wadze 60-80 gramów. Dostęp do wody jest doskonały, co przyciąga rzesze wędkarzy szukających zarówno ryb, jak i pięknych krajobrazów.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70143, 'Nizinna Wielka', 'Naturalna, szeroka', 150.0, 2.0, 'Piasek i żwir', 'Opaski kamienne', 'Jaź, Kleń, Boleń', 'Kraina brzany', true);

-- Spot 145: Drohiczyn (Zachód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70144, 'Bug - Drohiczyn (Wólka Zamkowa)', 'bug-drohiczyn-zachod', 'RIVER', 52.3876884, 22.6179528, 'Podlaskie', 'Drohiczyn', 'Zachodni odcinek w okolicach Drohiczyna oferuje wędkarzom dzikie koryto z dużą ilością zwalonych do wody drzew. Rzeka mocno tu meandruje, co skutkuje powstaniem głębokich rynien na zewnętrznych łukach, idealnych dla sandaczy. Dno charakteryzuje się występowaniem twardych, piaszczystych blatów oraz gliniastych uskoków sprzyjających brzanom. Spinningiści cenią to miejsce za populację grubego okonia, który chętnie grupuje się przy zatopionych gałęziach. Uciąg wody jest tu stały i przewidywalny, ułatwiając systematyczne nęcenie wybranych stanowisk gruntowych. To techniczne łowisko, które nagradza precyzję w podawaniu przynęt tuż obok podwodnych przeszkód.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70144, 'Nizinna Wielka', 'Meandrująca, dzika', 130.0, 2.2, 'Piasek i glina', 'Zwalone drzewa', 'Sandacz, Brzana, Okoń', 'Kraina leszcza', true);

-- Spot 146: Tonkiele
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70145, 'Bug - Tonkiele (Mostowe Przykosy)', 'bug-tonkiele', 'RIVER', 52.4176745, 22.5575709, 'Podlaskie', 'Drohiczyn', 'Odcinek w Tonkielach słynie z potężnych, piaszczystych łach oraz rozległych przykos przed i za mostem kolejowym. Nurt rzeki wyraźnie tu przyspiesza, co stwarza doskonałe warunki dla ryb lubiących silny prąd, takich jak certy. Dno piaszczyste z lokalnymi żwirowymi rynnami pozwala na skuteczne łowienie ciężkim feederem lub techniką bolońską. Warkocze powstające przy filarach mostu to doskonałe żerowisko dla kleni i jazi zbierających pokarm z powierzchni. Uciąg rzeki w tym miejscu wymusza stosowanie dociążonych koszyków, które stabilnie utrzymają się na piaszczystym dnie. Stanowiska brzegowe są nieliczne i naturalne, co nadaje temu miejscu wyjątkowo surowy i wędkarski klimat.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70145, 'Nizinna Wielka', 'Nurt szybki, przykosy', 140.0, 1.6, 'Piasek i żwir', 'Filary mostu', 'Certa, Kleń, Jaź', 'Kraina brzany', true);

-- Spot 147: Niemirów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70146, 'Bug - Niemirów (Granica)', 'bug-niemirow-granica', 'RIVER', 52.2832316, 23.1783671, 'Podlaskie', 'Siemiatycze', 'Niemirów to jedno z najbardziej dzikich łowisk na Bugu, położone na samym styku z granicą państwa. Rzeka płynie tu szerokim rozlewiskiem, a jej dno jest w większości piaszczyste z unikalnymi, głębokimi jamami sumowymi. To elitarne miejsce dla łowców okazów, którzy szukają spokoju i szansy na kontakt z niewypłoszonymi rybami. Spinningowanie na tym odcinku wymaga dużej uwagi ze względu na podwodne karcze i zmienność poziomu wody. Nurt rzeki jest tu leniwy, co sprzyja bytowaniu dorodnych leszczy oraz potężnych linów w przybrzeżnych trzcinowiskach. Ze względu na położenie w strefie nadgranicznej, przed wyprawą należy pamiętać o obowiązku posiadania dokumentów tożsamości.', null);

