VALUES (70146, 'Nizinna Wielka', 'Szeroka, wolno płynąca', 180.0, 3.0, 'Piasek i muł', 'Trzcinowiska', 'Sum, Leszcz, Lin', 'Kraina leszcza', true);

-- Spot 148: Sutno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70147, 'Bug - Sutno (Łąkowe Zakola)', 'bug-sutno', 'RIVER', 52.3004291, 23.1100631, 'Podlaskie', 'Mielnik', 'Odcinek w Sutnie charakteryzuje się bardzo czystą wodą i naturalnym korytem płynącym wśród nadbużańskich łąk. Rzeka tworzy tu spektakularne zakola, a dno jest usiane licznymi piaszczystymi łachami idealnymi dla boleni. Wędkarze stacjonarni cenią to miejsce za populację brzany, która świetnie reaguje na ciężkie zestawy z pinką lub gnojakiem. Uciąg wody jest umiarkowany, co ułatwia systematyczne nęcenie stad jazi i płoci żerujących na granicy nurtu. Brzegi są niskie i trawiaste, co zapewnia ogromny komfort przy podebieraniu ryb i rozstawianiu ekwipunku. To łowisko o niskiej presji, gwarantujące ciszę i udane połowy białorybu niemal przez cały sezon.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70147, 'Nizinna Wielka', 'Dzika, łąkowa rzeka', 120.0, 1.8, 'Piaszczyste', 'Brak', 'Brzana, Jaź, Boleń', 'Kraina leszcza', true);

-- Spot 149: Mielnik
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70148, 'Bug - Mielnik (Głębokie Rynny)', 'bug-mielnik', 'RIVER', 52.3241798, 23.0463016, 'Podlaskie', 'Mielnik', 'Bug w Mielniku to jedno z najbardziej technicznych łowisk rzecznych, słynące z głębokich na kilka metrów rynien. Dno jest tu twarde i gliniaste, co stwarza wyśmienite warunki dla brzan oraz dorodnych sandaczy żerujących przy dnie. Spinningiści z sukcesami obławiają tutejsze kamienne opaski, stosując metodę opadu z wykorzystaniem ciężkich główek jigowych. Uciąg wody jest tu znaczący, co wymaga od wędkarza gruntowego stosowania stabilnych koszyków zanętowych o masie powyżej 80 gramów. Warkocze powstające za naturalnymi przeszkodami to bankowe miejsca na spotkanie z dużym kleniem lub boleniem. Miejsce to łączy w sobie surowość nadbużańskiej przyrody z szansą na kontakt z rybami o rekordowych rozmiarach.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70148, 'Nizinna Wielka', 'Głęboka, nurt silny', 140.0, 3.5, 'Twarde, gliniaste', 'Opaski kamienne', 'Brzana, Sandacz, Leszcz', 'Kraina brzany', true);

-- Spot 150: Osłowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70149, 'Bug - Osłowo (Podlaski Przełom)', 'bug-oslowo-przelom', 'RIVER', 52.3474065, 22.9830658, 'Podlaskie', 'Siemiatycze', 'Rzeka Bug w Osłowie to kwintesencja dzikiego Podlasia, gdzie nurt żłobi głębokie rynny tuż przy stromych burtach. Dno jest tu w większości twarde i gliniaste, co sprzyja stacjonarnemu łowieniu grubych brzan oraz kleni. Wędkarze spinningowi powinni szukać boleni polujących na piaszczystych przykosach wychodzących daleko w nurt rzeki. Uciąg jest silny i jednostajny, dlatego zaleca się stosowanie dociążonych koszyków zanętowych o masie przekraczającej 80 gramów. Wiosną miejsce to staje się mekką dla łowców dorodnych jazi, które chętnie zbierają pokarm z powierzchni przy zatopionych krzewach. Brak łatwego dojazdu autem gwarantuje niską presję wędkarską i pełną swobodę w wyborze stanowiska.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70149, 'Nizinna Wielka', 'Dzika, z wysoką burtą', 135.0, 2.5, 'Twarda glina', 'Podmyte brzegi, przykosy', 'Brzana, Kleń, Boleń', 'Kraina brzany', true);

-- Spot 151: Wólka Nadbużna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70150, 'Bug - Wólka Nadbużna', 'bug-wolka-nadbuzna', 'RIVER', 52.3611317, 22.8535151, 'Podlaskie', 'Siemiatycze', 'Odcinek w Wólce Nadbużnej charakteryzuje się szerokim korytem i licznymi, piaszczystymi łachami, które zmieniają swoje położenie po każdym przyborze wody. To legendarne łowisko rekordowych leszczy, które grupują się w głębszych jamach o spokojnym, wstecznym prądzie. Spinningiści z sukcesem obławiają tutejsze karcze, celując w szczupaki i wyrośnięte okonie czające się w cieniu nawisów. Dno piaszczyste z lokalnymi płatami gliny wymaga od wędkarza gruntowego precyzyjnego badania rzeźby terenu przed nęceniem. Uciąg rzeki jest tu umiarkowany, co pozwala na komfortowe łowienie feederem przy użyciu standardowych rzecznych szczytówek. Wieczorami na piaszczyste płycizny wychodzą sandacze, które można skutecznie kusić płytko schodzącymi woblerami.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70150, 'Nizinna Wielka', 'Szerokie rozlewiska, piaszczyste łachy', 150.0, 2.0, 'Piasek i glina', 'Zwalone drzewa', 'Leszcz, Szczupak, Sandacz', 'Kraina leszcza', true);

-- Spot 152: Mężenin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70151, 'Bug - Mężenin (Zakola)', 'bug-mezenin-zakola', 'RIVER', 52.3723242, 22.7816105, 'Mazowieckie', 'Sarnaki', 'Mężenin to odcinek rzeki Bug o niezwykle urozmaiconej linii brzegowej, pełnej dzikich zakoli i piaszczystych przykos. Nurt rzeki wyraźnie przyspiesza na przewężeniach, tworząc natlenione warkocze idealne dla ryb reofilnych takich jak certy. Dno jest tu w dużej mierze twarde i żwirowe, co minimalizuje liczbę zaczepów przy łowieniu metodą przepływanki. Wędkarze stacjonarni cenią to miejsce za populację brzany, która świetnie reaguje na zapachowe ciasta i białe robaki. Brzeg jest tu częściowo zarośnięty, co wymaga od wędkarza przygotowania stanowiska, ale zapewnia doskonały kamuflaż przed rybami. To techniczne łowisko, które nagradza wędkarzy potrafiących precyzyjnie kłaść zestaw w rynnie przy zachowaniu absolutnej ciszy.', 'PZW Biała Podlaska');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70151, 'Nizinna Wielka', 'Meandrujące koryto', 120.0, 1.8, 'Żwir i piasek', 'Przykosy, kamieniste rafy', 'Brzana, Certa, Kleń', 'Kraina brzany', true);

-- Spot 153: Kryłów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70152, 'Bug - Kryłów (Graniczny)', 'bug-krylow-granica', 'RIVER', 50.6779126, 24.0616109, 'Lubelskie', 'Hrubieszów', 'Kryłów to jedno z najdalej wysuniętych na południowy wschód łowisk nadbużańskich, położone na samym styku granicy państwa. Rzeka płynie tu stosunkowo wąskim korytem, a jej nurt jest niezwykle rwanym i nieprzewidywalny po intensywnych opadach. Dno jest mocno pofałdowane z licznymi kamiennymi narzutami, które są ulubionym schronieniem dla sumów i dużych brzan. Spinningiści powinni skupić się na obławianiu rynien pod samym brzegiem, gdzie dno jest twarde i wymyte do gołej gliny. Ze względu na charakter nadgraniczny, wędkowanie wymaga zgłoszenia do odpowiedniej placówki Straży Granicznej przed każdą wyprawą. To łowisko dla koneserów dzikiej wody, którzy nie boją się trudnego terenu i chcą zmierzyć się z naprawdę dziką rybą.', 'PZW Zamość');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70152, 'Nizinna Wielka', 'Wąskie, rwane koryto graniczne', 80.0, 2.8, 'Glina i kamienie', 'Naturalne opaski', 'Sum, Brzana, Boleń', 'Kraina brzany', 'Strefa nadgraniczna', false);

-- Spot 154: Boreczek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70153, 'Bug - Boreczek (Równia)', 'bug-boreczek-rownia', 'RIVER', 52.676139, 22.0429252, 'Mazowieckie', 'Małkinia Górna', 'Boreczek oferuje wędkarzom dostęp do dzikiego Bugu z rozległymi przykosami i głębokimi rynnami w nurcie głównym. Odcinek ten słynie z bardzo dużej populacji jazi, które żerują na granicy szybkiej wody i spokojnych zastoisk. Dno piaszczyste z domieszką żwiru jest doskonałym podłożem dla larw owadów, co przyciąga stadne ryby spokojnego żeru. Spinningowanie w tym miejscu wymaga celnych rzutów w warkocze, gdzie drapieżniki czatują na przemykającą w nurcie drobnicę. Uciąg jest stabilny, co ułatwia utrzymanie zestawu gruntowego w wybranym polu nęcenia przy użyciu płaskich ciężarków. Cisza i brak bliskiej zabudowy sprawiają, że można tu liczyć na bliski kontakt z surową, nadbużańską naturą.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70153, 'Nizinna Wielka', 'Naturalne, piaszczyste koryto', 100.0, 1.5, 'Piasek i żwir', 'Przykosy', 'Jaź, Leszcz, Kleń', 'Kraina leszcza', true);

-- Spot 155: Glina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70154, 'Bug - Glina (Karczowiska)', 'bug-glina-karczowiska', 'RIVER', 52.6809452, 21.9681313, 'Mazowieckie', 'Małkinia Górna', 'Bug w miejscowości Glina to odcinek charakteryzujący się licznymi meandrami i podmytymi burtami o znacznej głębokości. To klasyczne miejsce na ciężki spinning w poszukiwaniu szczupaków i sumów czatujących w podwodnych karczowiskach. Dno jest tu zróżnicowane, od piaszczystych łach po twarde, gliniaste progi wymyte przez silny prąd rzeki. Wędkarze gruntowi powinni szukać ryb w głębokich jamach na zewnętrznych łukach koryta, nęcąc ziarnami kukurydzy i łubinem. Uciąg rzeki w tym miejscu jest zdecydowany, co wymusza stosowanie dociążonych koszyków zdolnych utrzymać się w głównym nurcie. Stanowiska brzegowe są naturalne i często wymagają odpowiedniego obuwia terenowego ze względu na grząskie fragmenty nabrzeża.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70154, 'Nizinna Wielka', 'Meandrująca, zatory', 110.0, 2.5, 'Glina i piasek', 'Zwalone drzewa (karpy)', 'Szczupak, Sum, Brzana', 'Kraina leszcza', true);

-- Spot 156: Wołczyny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70155, 'Bug - Wołczyny (Poleski)', 'bug-wolczyny-polesie', 'RIVER', 51.4436166, 23.6667386, 'Lubelskie', 'Włodawa', 'Wołczyny to odcinek rzeki Bug położony w malowniczym regionie Polesia, oferujący bardzo czystą wodą i naturalne koryto. Rzeka płynie tu szeroko, tworząc liczne wyspy piaszczyste i rozległe płycizny, które są doskonałym żerowiskiem dla boleni. Dno jest w przeważającej części piaszczyste, co ułatwia łowienie metodą odległościową z lekkim spławikiem w strefie przybrzeżnej. Miłośnicy feedera mogą liczyć na regularne brania dużych płoci oraz wyrośniętych krąpi żerujących na piaszczystych blatach. Nurt jest tu łagodny, co czyni to łowisko idealnym na rodzinne wypady z wędką i naukę czytania rzeki. Bliskość obszarów chronionych sprawia, że woda jest tu wyjątkowo rybna, a ryby rzadko spotykają się z dużą presją wędkarską.', 'PZW Chełm');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70155, 'Nizinna Wielka', 'Szeroka, wolno płynąca', 130.0, 1.4, 'Piasek', 'Wyspy piaszczyste', 'Boleń, Płoć, Krąp', 'Kraina leszcza', true);

-- Spot 157: Zgleczewo Panieńskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70156, 'Bug - Zgleczewo Panieńskie (Przykosy)', 'bug-zgleczewo-panienskie', 'RIVER', 52.6973864, 22.1443441, 'Mazowieckie', 'Małkinia Górna', 'Bug w Zgleczewie Panieńskim to odcinek słynący z rozległych, piaszczystych przykos, które są domem dla dużych stad boleni. Nurt rzeki wyraźnie tu przyspiesza, żłobiąc twarde, piaszczyste dno i tworząc atrakcyjne dla ryb reofilnych warkocze. To doskonałe miejsce dla spinningistów polujących na klenie i jazie żerujące tuż pod powierzchnią wody. Wędkarze gruntowi powinni szukać głębszych rynien na zewnętrznych łukach koryta, gdzie dno przechodzi w twardą glinę. Uciąg rzeki w tym miejscu wymusza stosowanie dociążonych koszyków, które stabilnie utrzymają przynętę w głównym nurcie. Stanowiska brzegowe są naturalne i oferują wspaniały widok na dziką, nieuregulowaną dolinę rzeki.', null);

