VALUES (70156, 'Nizinna Wielka', 'Nurt szybki, liczne przykosy', 110.0, 1.6, 'Piasek i glina', 'Przykosy, łachy', 'Boleń, Kleń, Jaź', 'Kraina brzany', true);

-- Spot 158: Rażny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70157, 'Bug - Rażny (Starorzecza)', 'bug-razny', 'RIVER', 52.66041, 21.7600608, 'Mazowieckie', 'Sadowne', 'Odcinek w miejscowości Rażny charakteryzuje się bardzo urozmaiconą linią brzegową z licznymi wejściami do starorzeczy. Główny nurt Bugu płynie tu głębokim korytem, a dno jest usiane licznymi karczami stanowiącymi idealne schronienie dla sumów. Spinningiści z sukcesami obławiają tutejsze podmytki, celując w szczupaki i wyrośnięte okonie czające się w cieniu wiklin. Uciąg wody jest umiarkowany, co sprzyja systematycznemu nęceniu pola łowiska i utrzymaniu w nim stadnych leszczy. Warto zwrócić uwagę na piaszczyste blaty przy wejściach do zatok, gdzie wieczorami chętnie żerują sandacze. To techniczne łowisko, które nagradza wędkarzy potrafiących precyzyjnie kłaść zestaw obok podwodnych przeszkód.', null);

