-- Spot 159: Tuchlin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70158, 'Bug - Tuchlin (Wsteczne Prądy)', 'bug-tuchlin', 'RIVER', 52.6369236, 21.6965464, 'Mazowieckie', 'Brańszczyk', 'Tuchlin oferuje wędkarzom dostęp do rzeki o bardzo zmiennym charakterze, z licznymi wstecznymi prądami i głębokimi dołami. Dno jest tu mocno pofałdowane, przechodząc z piaszczystych łach w twarde, gliniaste rynny sięgające trzech metrów. To wymarzone stanowisko dla łowców brzan, które świetnie reagują na ciężki feeder z dużą ilością robaków krojonych. Spinningowanie wzdłuż brzegowych faszyn pozwala na spotkanie z agresywnym boleniem polującym w głównym nurcie. Uciąg rzeki jest tu zdecydowany, co wymaga od wędkarza stosowania stabilnych koszyków o masie powyżej 60 gramów. Cisza i brak bliskiej zabudowy sprawiają, że ryby żerują tu śmiało, dając szansę na kontakt z prawdziwym okazem.', null);

