VALUES (70158, 'Nizinna Wielka', 'Nurt zdecydowany, głębokie jamy', 105.0, 2.8, 'Glina i piasek', 'Faszynowe umocnienia', 'Brzana, Boleń, Leszcz', 'Kraina brzany', true);

-- Spot 160: Szumin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70159, 'Bug - Szumin (Piaszczysta Równia)', 'bug-szumin', 'RIVER', 52.6135501, 21.6331311, 'Mazowieckie', 'Łochów', 'Szumin to jedno z najbardziej znanych łowisk w dolnym biegu Bugu, charakteryzujące się szerokim korytem i czystą wodą. Rzeka płynie tu spokojnie, tworząc rozległe piaszczyste płanie idealne do łowienia białorybu metodą odległościową. Dno jest przeważnie piaszczyste i wolne od zaczepów, co czyni ten odcinek bardzo przyjaznym dla początkujących wędkarzy. W rynnach przy drugim brzegu często meldują się ładne jazie oraz płocie, które doskonale reagują na nęcenie luźną zanętą. Uciąg jest na tyle słaby, że pozwala na precyzyjne operowanie lekkimi zestawami spławikowymi oraz feederem. Miejsce to jest bardzo popularne na weekendowe zasiadki ze względu na dogodny dostęp do lustra wody i malowniczą okolicę.', null);

