VALUES (70159, 'Nizinna Wielka', 'Szerokie płanie, nurt słaby', 150.0, 1.8, 'Piasek', 'Przykosy', 'Jaź, Płoć, Leszcz', 'Kraina leszcza', true);

-- Spot 161: Suwiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70160, 'Bug - Suwiec (Dzika Burta)', 'bug-suwiec', 'RIVER', 52.5998052, 21.5133199, 'Mazowieckie', 'Wyszków', 'Odcinek w miejscowości Suwiec charakteryzuje się dzikim charakterem koryta z bardzo wysoką, podmytą burtą brzegową. Nurt rzeki wyraźnie tu rwie, żłobiąc głębokie rynny pod korzeniami starych wierzb i olch. Jest to doskonała lokalizacja dla łowców sumów, którzy stacjonarnie polują w najgłębszych patiach koryta rzeki. Dno jest tu twarde, piaszczysto-gliniaste, co sprzyja bytowaniu brzan walczących w głównym prądzie. Spinningiści znajdą tutaj liczne zwalone drzewa, które stanowią bezpieczne schronienie dla wyrośniętych szczupaków i okoni. To techniczne łowisko o wysokim stopniu trudności, nagradzające wytrwałych wędkarzy szansą na kontakt z rybami rekordowych rozmiarów.', null);

