-- Spot 162: Wyszków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70161, 'Bug - Wyszków (Miejski)', 'bug-wyszkow-miejski', 'RIVER', 52.5817612, 21.4451784, 'Mazowieckie', 'Wyszków', 'Miejski odcinek Bugu w Wyszkowie to techniczne łowisko z kamiennymi opaskami i głębokimi rynnami pod mostami. Dno jest tu twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu w okolicach filarów mostowych i kładek. Czysta woda sprzyja bytowaniu dużej populacji jazi i kleni, które chętnie żerują w cieniu miejskiej architektury. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy murach oporowych. Uciąg rzeki jest tu umiarkowany, co pozwala na precyzyjne operowanie zestawami spławikowymi typu bolonka. Wieczorami, przy świetle latarni, można liczyć na widowiskowe brania sandaczy polujących na piaszczystych przykosach.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70161, 'Nizinna Wielka', 'Uregulowane koryto miejskie', 140.0, 2.5, 'Piasek i kamienie', 'Mosty, opaski', 'Jaź, Kleń, Sandacz, Okoń', 'Kraina leszcza', true);

-- Spot 163: Włodawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70162, 'Bug - Włodawa (Granica Państwa)', 'bug-wlodawa-granica', 'RIVER', 51.5454671, 23.5636378, 'Lubelskie', 'Włodawa', 'Bug we Włodawie to odcinek graniczny o niezwykle naturalnym charakterze, gdzie rzeka zachowuje swoją pierwotną dzikość. Koryto jest tu stosunkowo wąskie, a nurt rwie wartko przez piaszczysto-żwirowe dno usiane licznymi karczami. To legendarne łowisko brzan oraz kleni, które znajdują tu idealne warunki do żerowania w natlenionym nurcie. Ze względu na charakter nadgraniczny, wędkowanie wymaga zgłoszenia do Placówki Straży Granicznej przed każdą wyprawą. Spinningiści z sukcesami obławiają tutejsze rynny pod brzegami, celując w szczupaki i wyrośnięte okonie czające się w cieniu wiklin. Miejsce to gwarantuje absolutną ciszę i kontakt z dziką rybą, która nie zna dużej presji wędkarskiej.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70162, 'Nizinna Wielka', 'Wąskie koryto graniczne', 80.0, 2.0, 'Piasek i żwir', 'Podmyte brzegi, zwalone drzewa', 'Brzana, Kleń, Szczupak', 'Kraina brzany', 'Odcinek nadgraniczny', false);

-- BZURA

-- Spot 164: Ostrów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70163, 'Bzura - Ostrów (Łąkowe Meandry)', 'bzura-ostrow-meandry', 'RIVER', 52.0000752, 19.2764214, 'Łódzkie', 'Ozorków', 'Bzura w okolicach Ostrowa to urokliwy, łąkowy odcinek o stosunkowo wąskim korycie i czystej wodzie. Nurt płynie tu jednostajnie, żłobiąc piaszczyste dno z lokalnymi naniesieniami drobnego żwiru w nurcie głównym. To doskonałe miejsce dla spinningistów polujących na klenie oraz jazie przy użyciu mikro-woblerów. Podmyte brzegi i kępy roślinności wynurzonej stanowią świetne schronienie dla licznej populacji okonia. Wędkarze spławikowi mogą liczyć na regularne brania płoci oraz wyrośniętych wzdręg w spokojniejszych zatoczkach. Brak dużej presji wędkarskiej w tym rejonie sprawia, że ryby żerują śmiało, choć wymagają cichego podejścia od strony łąki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70163, 'Nizinna Mała', 'Naturalne, meandrujące', 8.0, 1.1, 'Piaszczysto-żwirowe', 'Zwisające trawy', 'Kleń, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 165: Leśmierz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70164, 'Bzura - Leśmierz (Zastoiska)', 'bzura-lesmierz-zastoiska', 'RIVER', 52.0270359, 19.2724275, 'Łódzkie', 'Ozorków', 'Odcinek w Leśmierzu charakteryzuje się leniwym przepływem wody i nieco głębszym korytem w porównaniu do górnego biegu. Dno jest tu w większości piaszczysto-muliste, co sprzyja bytowaniu dorodnych linów oraz karasi złotych. Wzdłuż brzegów rosną gęste trzciny, które są naturalną kryjówką dla szczupaków czających się na rzeczną drobnicę. Uciąg jest niemal niezauważalny, dlatego idealnie sprawdzają się tu delikatne zestawy spławikowe z lekkim dociążeniem. Wiele stanowisk jest osłoniętych drzewami, co daje komfort łowienia nawet w upalne, letnie popołudnia. To bardzo techniczne łowisko, nagradzające wędkarzy potrafiących precyzyjnie nęcić punktowo w oczkach między roślinnością.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70164, 'Nizinna Mała', 'Leniwy nurt, naturalne', 10.0, 1.4, 'Piaszczysto-muliste', 'Trzcinowiska', 'Lin, Szczupak, Karaś', 'Kraina leszcza', false);

-- Spot 166: Zgierz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70165, 'Bzura - Zgierz (Górna Struna)', 'bzura-zgierz-gora', 'RIVER', 51.856828, 19.4086137, 'Łódzkie', 'Zgierz', 'Bzura w Zgierzu to wąski strumień o uregulowanym korycie, który stanowi początkowy bieg tej rzeki. Mimo niewielkich rozmiarów, woda skrywa w rynnach pod mostami stadne płocie oraz wyrośnięte okonie. Dno jest tu twarde, piaszczyste, z lokalnymi betonowymi umocnieniami brzegowymi ułatwiającymi dostęp do lustra wody. Najskuteczniejszą metodą łowienia jest tu lekki bat lub krótkie wędzisko spinningowe do precyzyjnego obławiania murków. Ryby w tym miejscu są przyzwyczajone do miejskiego zgiełku, co pozwala na skuteczne wędkowanie nawet w środku dnia. To doskonałe miejsce na szybki, miejski wypad z wędką w poszukiwaniu rzecznych pasiastych drapieżników.', 'PZW Łódź');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70165, 'Nizinna Mała', 'Uregulowane koryto miejskie', 5.0, 0.8, 'Piasek i beton', 'Murki oporowe', 'Płoć, Okoń, Kiełb', 'Kraina pstrąga (potencjalnie)', false);

-- Spot 167: Sochaczew (Miejski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70166, 'Bzura - Sochaczew (Bulwary)', 'bzura-sochaczew-bulwary', 'RIVER', 52.2361943, 20.239004, 'Mazowieckie', 'Sochaczew', 'W Sochaczewie Bzura nabiera już poważniejszego, nizinnego charakteru z szerokim korytem i stabilnym uciągiem. Dno jest tu w większości twarde i piaszczyste, z wyraźną rynną w środkowym nurcie, gdzie grupują się leszcze. Miejska infrastruktura i bulwary zapewniają wzorcowy dostęp do stanowisk, co czyni ten odcinek bardzo popularnym. Spinningiści z sukcesami polują tutaj na klenie i bolenie żerujące w warkoczach za filarami mostów. Przy brzegach można spotkać głębsze doły, które w okresach jesiennych są doskonałym siedliskiem dla szczupaka. To łowisko o dużej presji, ale systematyczne nęcenie pozwala na regularne osiąganie satysfakcjonujących wyników.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70166, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 25.0, 1.6, 'Piaszczyste', 'Bulwary, filary mostów', 'Leszcz, Kleń, Boleń', 'Kraina leszcza', false);

-- Spot 168: Sochaczew (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70167, 'Bzura - Sochaczew (Uroczysko)', 'bzura-sochaczew-polnoc', 'RIVER', 52.2578839, 20.2665523, 'Mazowieckie', 'Sochaczew', 'Północny odcinek w Sochaczewie charakteryzuje się bardziej dziką linią brzegową z dużą ilością zwalonych drzew w wodzie. Nurt jest tu rwanym i zmienny, tworząc liczne piaszczyste przykosy i głębokie wymycia pod korzeniami. To wymarzone stanowisko dla spinningistów polujących na szczupaki oraz rekordowe bolenie patrolujące środek rzeki. Dno gliniasto-piaszczyste sprzyja bytowaniu brzan, które potężnie walczą w głównym prądzie wody. Wędkarze gruntowi powinni stosować tu stabilne koszyki zanętowe o masie powyżej 50 gramów, aby utrzymać zestaw w nurcie. Miejsce to wymaga od wędkarza cichego podejścia i umiejętności precyzyjnego rzutu w pobliżu podwodnych karczów.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70167, 'Nizinna Średnia', 'Dzika rzeka z zatorami', 28.0, 1.8, 'Piasek i glina', 'Zwalone drzewa', 'Boleń, Szczupak, Brzana', 'Kraina leszcza', true);

-- Spot 169: Plecewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70168, 'Bzura - Plecewice (Żwirowe Rafy)', 'bzura-plecewice-rafy', 'RIVER', 52.2845908, 20.2738795, 'Mazowieckie', 'Sochaczew', 'Plecewice to odcinek słynący wśród wędkarzy z kamiennych narzutów i naturalnych żwirowych raf w nurcie. Bzura płynie tu szeroko, a jej woda jest dobrze natleniona, co przyciąga stadne ryby reofilne takie jak certy. Dno jest twarde i czyste, co sprawia, że sandacze chętnie wybierają tutejsze rynny na swoje jesienne stanowiska. Spinningiści z sukcesami obławiają piaszczyste przykosy przy pomocy smukłych woblerów imitujących ukleje. Uciąg jest silny i jednostajny, co sprzyja metodzie bolońskiej oraz ciężkiemu feederowi rzecznemu. Brzeg jest łatwo dostępny, a piaszczyste plaże pozwalają na komfortowe rozstawienie ekwipunku nawet przy wyższym stanie wody.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70168, 'Nizinna Średnia', 'Szeroka rzeka z przykosami', 35.0, 2.0, 'Żwir i piasek', 'Kamienne rafy', 'Certa, Sandacz, Leszcz', 'Kraina brzany', true);

-- Spot 170: Konary
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70169, 'Bzura - Konary (Ujście do Wisły)', 'bzura-konary-ujscie', 'RIVER', 52.3105934, 20.2579932, 'Mazowieckie', 'Wyszogród', 'W Konarach Bzura przygotowuje się do połączenia z Wisłą, nabierając głębokiego i bardzo rybnego charakteru. Woda płynie tu leniwie, a dno jest zróżnicowane — od piaszczystych blatów po muliste rynny sięgające trzech metrów głębokości. To legendarne łowisko rekordowych leszczy i krąpi, które masowo wchodzą tutaj z nurtu głównej rzeki. Wzdłuż brzegów znajdują się liczne kępy grążeli, w których jesienią czają się potężne szczupaki i sumy. Uciąg wody jest tu zmienny, silnie uzależniony od poziomu wody na Wiśle, co tworzy tzw. cofkę. Jest to doskonałe miejsce na łowienie z łodzi, pozwalające na swobodne obławianie szerokiego koryta ujściowego.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70169, 'Nizinna Wielka', 'Szerokie rozlewisko ujściowe', 45.0, 3.5, 'Piasek i muł', 'Grążele, zarośla trzcinowe', 'Leszcz, Sum, Szczupak, Krąp', 'Kraina leszcza', true);

-- Spot 171: Witkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70170, 'Bzura - Witkowice (Przedujście)', 'bzura-witkowice-przedujscie', 'RIVER', 52.3376139, 20.2547594, 'Mazowieckie', 'Sochaczew', 'Witkowice to odcinek o charakterze ujściowym, gdzie Bzura leniwie toczy swe wody w stronę Wisły. Głębokość w rynnie przekracza tu często dwa i pół metra, co sprzyja bytowaniu dorodnych leszczy. Dno jest piaszczysto-muliste z licznymi kępami grążeli przy brzegach, w których czają się szczupaki. Uciąg jest słaby i przewidywalny, pozwalając na precyzyjne operowanie lekkimi zestawami gruntowymi. Brzegi są łatwo dostępne i oferują wędkarzom sporo miejsca na rozstawienie profesjonalnych siedzisk. To idealne łowisko na spokojną zasiadkę z nastawieniem na białą rybę i okazowe liny.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70170, 'Nizinna Średnia', 'Leniwy nurt, szerokie koryto', 35.0, 2.2, 'Piaszczysto-muliste', 'Kępy grążeli', 'Leszcz, Szczupak, Lin', 'Kraina leszcza', true);

-- Spot 172: Przęsławice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70171, 'Bzura - Przęsławice (Piaszczyste Płanie)', 'bzura-przeslawice-planie', 'RIVER', 52.3620436, 20.233398, 'Mazowieckie', 'Wyszogród', 'W Przęsławicach Bzura płynie szerokim, uregulowanym korytem o stosunkowo wyrównanej głębokości. Dno jest tu twarde i piaszczyste, co czyni to miejsce doskonałym poligonem dla łowców rzecznych drapieżników. Spinningiści z sukcesami obławiają piaszczyste przykosy w poszukiwaniu boleni i wyrośniętych okoni. Nurt jest jednostajny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad jazi w polu łowienia. Stanowiska brzegowe są nieliczne i naturalne, co nadaje temu fragmentowi rzeki surowy charakter. Jest to świetne miejsce na wiosenne wyprawy, gdy z Wisły wchodzą tu masowo duże płocie i krąpie.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70171, 'Nizinna Średnia', 'Uregulowane koryto, przykosy', 40.0, 1.8, 'Twarde, piaszczyste', 'Piaszczyste przykosy', 'Boleń, Jaź, Krąp', 'Kraina leszcza', true);

-- Spot 173: Kamion
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70172, 'Bzura - Kamion (Ujście)', 'bzura-kamion-ujscie', 'RIVER', 52.3765805, 20.1946099, 'Mazowieckie', 'Wyszogród', 'Odcinek w Kamionie to samo ujście Bzury do Wisły, co czyni go jednym z najbardziej rybnych miejsc w regionie. Występuje tu silne zjawisko cofki, powodujące częste zmiany poziomu wody i uciągu w zależności od stanu Wisły. Dno jest mocno urozmaicone, piaszczysto-gliniaste z licznymi dołami wymytymi przez ścierające się nurty obu rzek. To strategiczne miejsce dla łowców sumów oraz sandaczy, które żerują tu na ogromnych ławicach uklei. Szerokie rozlewisko wymaga stosowania cięższego sprzętu zdolnego posłać zestaw na znaczną odległość. Wędkarstwo z łodzi jest tu wysoce zalecane ze względu na rozległość łowiska i niedostępne pasy trzcin.', 'PZW Warszawa');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70172, 'Nizinna Wielka', 'Szerokie rozlewisko ujściowe', 55.0, 3.5, 'Piasek i glina', 'Trzcinowiska, doły ujściowe', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 174: Antoniew
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70173, 'Bzura - Antoniew (Dziki Meander)', 'bzura-antoniew-meander', 'RIVER', 52.2017115, 20.1835401, 'Mazowieckie', 'Sochaczew', 'Bzura w Antoniewie zachowuje swój naturalny wdzięk, wijąc się malowniczo wśród nadbrzeżnych pól i łąk. Koryto rzeki jest tu węższe, a nurt wyraźniej żłobi piaszczyste dno na zewnętrznych łukach koryta. To królestwo klenia i jazia, które doskonale reagują na techniki spinningowe z wykorzystaniem smużaków. Podmyte burty i zwalone korzenie starych wierzb stanowią bankowe kryjówki dla wyrośniętych okoni. Uciąg jest umiarkowany i pozwala na komfortowe łowienie lekkim feederem z koszykami o masie trzydziestu gramów. Cisza panująca wzdłuż brzegów sprawia, że jest to idealne łowisko dla osób szukających spokoju.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70173, 'Nizinna Mała', 'Naturalne, meandrujące', 15.0, 1.3, 'Piaszczyste', 'Podmyte korzenie', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 175: Kozłów Szlachecki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70174, 'Bzura - Kozłów Szlachecki (Rafy)', 'bzura-kozlow-szlachecki-rafy', 'RIVER', 52.1658365, 20.1448311, 'Mazowieckie', 'Sochaczew', 'W Kozłowie Szlacheckim rzeka przepływa przez tereny o urozmaiconym ukształtowaniu dna z lokalnymi żwirowymi rafami. Woda jest tu dobrze natleniona i płynie żywszym nurtem, co przyciąga ryby reofilne takie jak certy. Dno jest twarde i czyste, co znacznie ogranicza liczbę zaczepów przy prowadzeniu przynęt spinningowych. Warkocze powstające za naturalnymi przeszkodami to ulubione żerowiska boleni patrolujących środek rzeki. Wędkarze stacjonarni z sukcesami stosują tu metodę przepływanki, celując w dorodne płocie i jelce. Brzeg jest częściowo zarośnięty, co wymaga od wędkarza dużej dyskrecji podczas zajmowania stanowiska.', 'PZW Skierniewice');

