-- Spot 176: Bednary
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70175, 'Bzura - Bednary (Zalewiska)', 'bzura-bednary-zalewiska', 'RIVER', 52.1216811, 20.0494011, 'Łódzkie', 'Łowicz', 'Odcinek w Bednarach to klasyczna nizinna rzeka z dużą ilością roślinności zanurzonej i wynurzonej. Bzura płynie tu leniwie, a jej dno jest piaszczysto-muliste, obfitujące w naturalny pokarm dla białorybu. To wymarzone miejsce dla łowców szczupaków, którzy precyzyjnie obławiają oczka w grążelach i trzcinowiskach. Miłośnicy spławika mogą liczyć na regularne brania linów oraz złotych karasi w zacisznych zatoczkach. Uciąg jest znikomy, co pozwala na stosowanie najlżejszych i najbardziej czułych zestawów końcowych. Dojazd do wody jest dogodny, a liczne stanowiska pozwalają na swobodne wędkowanie bez presji sąsiadów.', 'PZW Skierniewice');

