-- Spot 177: Kompina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70176, 'Bzura - Kompina (Przy Moście)', 'bzura-kompina-most', 'RIVER', 52.1330567, 20.0894353, 'Łódzkie', 'Łowicz', 'Bzura w Kompinie to odcinek o niezwykle urozmaiconej rzeźbie dna, szczególnie w rejonie starego jazu i mostu. Nurt rzeki wyraźnie przyspiesza na przewężeniach, tworząc natlenione warkocze idealne dla kleni oraz jazi. Dno jest tu w dużej mierze twarde, piaszczysto-żwirowe, co minimalizuje liczbę zaczepów podczas spinningowania. Wędkarze gruntowi z sukcesami łowią tu dorodne płocie, stosując lekkie feedery z koszykami o masie dwudziestu gramów. Podmyte burty porośnięte wikliną skrywają wyrośnięte okonie, które agresywnie reagują na małe obrotówki. To techniczne łowisko, które nagradza wędkarzy potrafiących precyzyjnie kłaść zestaw na granicy nurtu i spokojnej wody.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70176, 'Nizinna Mała', 'Nurt zmienny, rynny pod mostem', 12.0, 1.4, 'Piaszczysto-żwirowe', 'Warkocze, pale mostowe', 'Kleń, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 178: Urzecze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70177, 'Bzura - Urzecze (Płanie)', 'bzura-urzecze-planie', 'RIVER', 52.105027, 19.7631528, 'Łódzkie', 'Łowicz', 'Odcinek w Urzeczu charakteryzuje się typowo nizinny krajobrazem i leniwie płynącą wodą. Rzeka płynie tu szerokim korytem, a dno jest piaszczysto-muliste z bogatą roślinnością podwodną. To wymarzone miejsce dla łowców szczupaków, którzy precyzyjnie obławiają pasy trzcin oraz kępy grążeli. Miłośnicy spławika mogą liczyć na regularne brania linów oraz złotych karasi w zacisznych, przybrzeżnych zatoczkach. Uciąg jest znikomy, co pozwala na stosowanie najlżejszych i najbardziej czułych spławików typu stałego. Dojazd do wody jest dogodny przez łąki, co zapewnia komfort przy rozkładaniu rozbudowanego stanowiska wędkarskiego.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70177, 'Nizinna Mała', 'Spokojny nurt, koryto naturalne', 15.0, 1.6, 'Piaszczysto-muliste', 'Grążele, trzciny', 'Szczupak, Lin, Karaś', 'Kraina leszcza', false);

-- Spot 179: Strugienice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70178, 'Bzura - Strugienice (Zakola)', 'bzura-strugienice-zakola', 'RIVER', 52.1183667, 19.8030408, 'Łódzkie', 'Łowicz', 'Bzura w Strugienicach to odcinek o naturalnym charakterze, wijący się malowniczo wśród nadbrzeżnych zagajników. Koryto rzeki posiada liczne zakola, gdzie nurt żłobi głębokie rynny pod samym przeciwległym brzegiem. Dno jest tu przeważnie piaszczyste, jednak w rynnach można natrafić na twardsze, gliniaste fragmenty sprzyjające kleniom. Wędkarze często stosują tu metodę lekkiej przepływanki, celując w ryby spokojnego żeru gromadzące się w dołkach. Spinningiści znajdą tutaj doskonałe miejsca do prowadzenia małych gum w poszukiwaniu rzecznych pasiastych drapieżników. Cisza panująca wzdłuż brzegów sprawia, że jest to łowisko idealne na relaksującą zasiadkę w pełnym kontakcie z naturą.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70178, 'Nizinna Mała', 'Meandrująca, naturalna', 10.0, 1.3, 'Piasek i glina', 'Podmyte brzegi', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 180: Maurzyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70179, 'Bzura - Maurzyce (Przy Skansenie)', 'bzura-maurzyce-skansen', 'RIVER', 52.1281459, 19.8441788, 'Łódzkie', 'Łowicz', 'Maurzyce to odcinek Bzury znany z wolniejszego nurtu i dużej ilości roślinności wynurzonej przy brzegach. Rzeka rozlewa się tu szerzej, a jej dno jest w dużej mierze piaszczyste z lokalnymi naniesieniami mułu. To doskonała lokalizacja dla łowców wzdręg, które gromadzą się stadnie w nasłonecznionych oczkach wody między trzcinami. Wędkarze gruntowi powinni szukać ryb w głębszych patiach koryta, nęcąc systematycznie ziarnami kukurydzy i pęczakiem. Uciąg rzeki jest na tyle słaby, że pozwala na idealną prezentację przynęty na bardzo delikatnych żyłkach przyponowych. Dogodny dostęp do lustra wody w rejonie zabytkowego mostu czyni to miejsce bardzo popularnym punktem wypadowym.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70179, 'Nizinna Mała', 'Szeroka, wolno płynąca', 14.0, 1.5, 'Piasek i muł', 'Oczka w trzcinach', 'Wzdręga, Leszcz, Płoć', 'Kraina leszcza', false);

-- Spot 181: Gosławice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70180, 'Bzura - Gosławice (Kameralna)', 'bzura-goslawice-kameralna', 'RIVER', 52.1265449, 19.5937971, 'Łódzkie', 'Bielawy', 'Odcinek w Gosławicach charakteryzuje się kameralnym korytem o umiarkowanym uciągu wody i czystym lustrze. Dno jest tu w większości twarde i piaszczyste, co czyni je idealnym poligonem dla fanów lekkiego spinningu. Główne trofea to waleczne klenie oraz jazie, które agresywnie atakują smużaki prowadzone pod nawisami drzew. Wzdłuż brzegów znajdziemy liczne zastoiska, gdzie w słoneczne dni chętnie żerują stadka dorodnych płoci i jelców. Niska presja wędkarskiej sprawia, że ryby są tu mniej płochliwe i żerują odważnie nawet blisko brzegu. To stanowisko polecane szczególnie tym, którzy cenią sobie spokój i aktywne poszukiwanie ryb w ruchu.', 'PZW Skierniewice');

