VALUES (70180, 'Nizinna Mała', 'Wąska, nurt umiarkowany', 7.0, 1.0, 'Piaszczyste', 'Nawisy wikliny', 'Kleń, Jaź, Jelce', 'Kraina leszcza', false);

-- Spot 182: Witaszewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70181, 'Bzura - Witaszewice (Srebrna Łuska)', 'bzura-witaszewice-srebrna', 'RIVER', 52.0888642, 19.2728418, 'Łódzkie', 'Ozorków', 'Bzura w Witaszewicach to niewielka rzeka o uregulowanym, ale dość głębokim korycie i piaszczystym podłożu. Nurt jest jednostajny i łagodny, co sprzyja precyzyjnemu budowaniu pola nęcenia przy użyciu zanęt sypkich. W rynnach o głębokości powyżej metra często stacjonują wyrośnięte okonie oraz stadne ryby spokojnego żeru. Wędkarze spławikowi najczęściej stosują tu technikę przystawki, obławiając cienie rzucane przez nadbrzeżne wikliny. Ryby w tym miejscu świetnie reagują na nęcenie drobnym pelletem oraz parzoną kukurydzą podawaną małymi porcjami. Brzegi są niskie i trawiaste, co zapewnia ogromny komfort podczas całodniowych zasiadek z lekkim feederem.', 'PZW Łódź');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70181, 'Nizinna Mała', 'Uregulowane koryto, nurt stały', 6.0, 1.2, 'Piaszczyste', 'Brak', 'Płoć, Okoń, Leszcz', 'Kraina leszcza', false);

-- Spot 183: Zagaj
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70182, 'Bzura - Zagaj (Łąkowa)', 'bzura-zagaj-lakowa', 'RIVER', 52.1018368, 19.3134841, 'Łódzkie', 'Ozorków', 'W miejscowości Zagaj Bzura płynie przez otwarte tereny łąkowe, zachowując swój nizinny, spokojny charakter. Rzeka posiada tu wyrównaną głębokość z nielicznymi podmyciami, w których chowają się większe szczupaki. Dno jest czyste i piaszczyste, co pozwala na bezstresowe łowienie metodą odległościową na dużych dystansach. Jest to świetne miejsce na letnie wyprawy, gdy przy powierzchni widać intensywne żerowanie jazi i kleni. Uciąg jest stabilny i przewidywalny, co umożliwia idealne dociążenie zestawu do panujących warunków wodnych. Brak wysokiej roślinności na brzegach znacznie ułatwia rzuty, jednak wymaga od wędkarza pełnego maskowania.', 'PZW Łódź');

