VALUES (70182, 'Nizinna Mała', 'Otwarta rzeka łąkowa', 8.0, 1.1, 'Piaszczyste', 'Lokalne jamy', 'Szczupak, Jaź, Kleń', 'Kraina leszcza', false);

-- Spot 184: Gledzianówek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70183, 'Bzura - Gledzianówek (Łąkowa)', 'bzura-gledzianowek-lakowa', 'RIVER', 52.1134874, 19.3546175, 'Łódzkie', 'Łęczyca', 'Bzura w Gledzianówku to klasyczny przykład nizinnej rzeki wijącej się wśród rozległych łąk. Koryto jest tu dość wąskie, a dno piaszczyste z lokalnymi naniesieniami mułu w zakolach. Nurt płynie spokojnie, co sprzyja rozwojowi bogatej roślinności zanurzonej stanowiącej schronienie dla płoci. Wędkarze spinningowi mogą liczyć na regularne brania okoni, które patrolują cienie przybrzeżnych traw. Uciąg wody jest stabilny i pozwala na komfortowe łowienie lekkim batem lub odległościówką. To stanowisko cenione za ciszę i możliwość wędkowania w całkowitym odosobnieniu od miejskiego zgiełku.', 'PZW Skierniewice');

