-- Spot 185: Ktery
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70184, 'Bzura - Ktery (Głębokie Rynny)', 'bzura-ktery-rynny', 'RIVER', 52.1203725, 19.4054844, 'Łódzkie', 'Kutno', 'Odcinek w miejscowości Ktery charakteryzuje się licznymi meandrami i wyraźnie zaznaczonymi rynnami o twardym dnie. Rzeka żłobi tu głębsze dołki na zewnętrznych łukach koryta, w których chętnie przebywają wyrośnięte klenie. Woda jest dobrze natleniona, co sprzyja aktywności ryb reofilnych żerujących w głównym nurcie. Spinningista znajdzie tutaj mnóstwo technicznych miejsc do precyzyjnego podawania małych woblerów pod zwisające gałęzie. Uciąg jest umiarkowany, co wymaga stosowania koszyków feederowych o masie od dwudziestu do trzydziestu gramów. Brzegi są naturalne i miejscami strome, co wymaga od wędkarza zachowania ostrożności podczas zajmowania stanowiska.', 'PZW Skierniewice');

