-- Spot 186: Siemienice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70185, 'Bzura - Siemienice (Dzika)', 'bzura-siemienice-dzika', 'RIVER', 52.1314015, 19.4466578, 'Łódzkie', 'Kutno', 'Bzura w Siemienicach to odcinek o dzikim charakterze, gdzie rzeka swobodnie kształtuje swoje koryto. Znajdziemy tu liczne zatory z gałęzi oraz podmyte burty, które są naturalnym królestwem szczupaka. Dno jest urozmaicone, piaszczysto-gliniaste, z dużą ilością naturalnego pokarmu dla ryb spokojnego żeru. Wędkarze gruntowi z sukcesami łowią tu dorodne jazie, nęcąc systematycznie parzoną pszenicą lub grubym pęczakiem. Nurt rzeki jest tu zmienny, przyspieszając na przewężeniach i zwalniając w szerokich, spokojnych zatoczkach. To doskonałe miejsce dla tych, którzy nie boją się trudnego terenu i szukają kontaktu z naprawdę waleczną rybą.', 'PZW Skierniewice');

