-- Spot 187: Młogoszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70186, 'Bzura - Młogoszyn (Płanie)', 'bzura-mlogoszyn-planie', 'RIVER', 52.1420504, 19.4893158, 'Łódzkie', 'Kutno', 'W Młogoszynie rzeka nieco się rozszerza, zachowując przy tym stabilny uciąg i jednostajną głębokość koryta. Dno jest przeważnie piaszczyste i czyste, co sprawia, że jest to idealne miejsce do łowienia metodą przepływanki. Dominują tu stada płoci oraz jelców, które doskonale reagują na drobne zanęty sypane prosto w nurt. Spinningiści mogą liczyć na spotkanie z boleniem, który regularnie pokazuje się na powierzchni podczas bicia drobnicy. Stanowiska brzegowe są tu wygodne i łatwo dostępne, co czyni ten odcinek przyjaznym dla wędkarzy z mniejszym doświadczeniem. Wieczorami warto spróbować zasiadki z rosówką w poszukiwaniu dorodnych węgorzy, które zamieszkują tutejsze głębsze rynny.', 'PZW Skierniewice');

