VALUES (70186, 'Nizinna Mała', 'Szerokie, wolne płanie', 14.0, 1.2, 'Piaszczyste', 'Lokalne rynny', 'Płoć, Jelce, Boleń', 'Kraina leszcza', false);

-- Spot 188: Mateuszew
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70187, 'Bzura - Mateuszew (Spokojna)', 'bzura-mateuszew-spokojna', 'RIVER', 52.1398036, 19.5331525, 'Łódzkie', 'Piątek', 'Odcinek w Mateuszewie to kwintesencja spokoju, gdzie rzeka płynie leniwie przez malownicze tereny rolnicze. Koryto jest tu głębokie, a dno w dużej mierze muliste, co sprzyja bytowaniu linów oraz złotych karasi. Gęste pasy trzcin przy brzegach stanowią naturalną osłonę przed wiatrem i doskonałe miejsce do ustawienia zestawu spławikowego. Uciąg jest minimalny, co pozwala na stosowanie najdelikatniejszych szczytówek oraz miniaturowych spławików typu stałego. To łowisko o niskiej presji wędkarskiej, gdzie ryby żerują śmiało i często można spotkać się z braniem okazałego leszcza. Dojazd do wody jest komfortowy, co pozwala na swobodne zaparkowanie auta w bliskiej odległości od stanowiska.', 'PZW Skierniewice');

