VALUES (70187, 'Nizinna Mała', 'Leniwy nurt, koryto głębokie', 9.0, 1.6, 'Muliste', 'Trzcinowiska', 'Lin, Leszcz, Karaś', 'Kraina leszcza', false);

-- Spot 189: Ruda-Bugaj
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70188, 'Bzura - Ruda-Bugaj (Strumień)', 'bzura-ruda-bugaj-strumien', 'RIVER', 51.8387107, 19.2857189, 'Łódzkie', 'Zgierz', 'Bzura w Rudzie-Bugaju ma postać niewielkiej, ale niezwykle urokliwej strugi o rwanym, niemal potokowym nurcie. Woda płynie tu przez zalesiony teren, tworząc liczne meandry z piaszczystym dnem i żwirowymi bystrzami. To elitarne miejsce dla miłośników ultra-lekkiego spinningu, polujących na klenie w cieniu nadbrzeżnych olch. Koryto jest wąskie, co zmusza wędkarza do pełnego maskowania i bardzo precyzyjnych rzutów "krótkim kijem". Mimo niewielkiej szerokości, rzeka skrywa głębsze jamy pod korzeniami drzew, gdzie czają się wyrośnięte i bardzo silne okonie. To łowisko wymagające technicznie, które nagradza wytrwałych pasjonatów dzikiej przyrody i finezyjnego łowienia.', 'PZW Łódź');

