-- Spot 190: Zielkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70189, 'Bzura - Zielkowice (Leszczowa)', 'bzura-zielkowice-leszczowa', 'RIVER', 52.1056737, 19.9797362, 'Łódzkie', 'Łowicz', 'Zielkowice to odcinek Bzury położony tuż pod Łowiczem, gdzie rzeka nabiera pełnego, nizinnego charakteru. Koryto jest tu szerokie i głębokie, a dno piaszczyste z lokalnymi twardymi płatami gliny idealnymi pod feeder. To legendarne miejsce na rekordowe leszczowe stada, które chętnie gromadzą się w głębokich rynnach środkowego nurtu. Uciąg wody jest stały i przewidywalny, co umożliwia systematyczne budowanie pola nęcenia na dużych dystansach. Spinningiści z sukcesami obławiają tutejsze przybrzeżne rynny w poszukiwaniu szczupaków oraz dorodnych okoni. Bliskość miasta i doskonały dostęp do wody sprawiają, że jest to jedno z najchętniej odwiedzanych łowisk w regionie.', 'PZW Skierniewice');

