-- Spot 192: Sobota
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70191, 'Bzura - Sobota (Warkocze)', 'bzura-sobota-warkocze', 'RIVER', 52.1162879, 19.6718222, 'Łódzkie', 'Łowicz', 'Bzura w Sobocie charakteryzuje się dość szerokim korytem i stabilnym uciągiem wody przez cały sezon. Dno jest tu w większości twarde i piaszczyste, z lokalnymi narzutami kamieni w okolicach starego spiętrzenia. Jest to legendarne łowisko dorodnych płoci oraz krąpi, które świetnie reagują na systematyczne nęcenie spożywcze. Spinningiści z sukcesami obławiają tutejsze warkocze, celując w żerujące na powierzchni klenie oraz bolenie. Uciąg rzeki wymaga stosowania koszyków feederowych o masie przekraczającej trzydzieści gramów dla stabilizacji zestawu. Brzeg jest tu łatwo dostępny i oferuje wiele komfortowych stanowisk dla wędkarzy stacjonarnych.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70191, 'Nizinna Mała', 'Uregulowane, nurt stały', 15.0, 1.5, 'Twarde, piaszczyste', 'Kamienne narzuty', 'Płoć, Boleń, Kleń', 'Kraina leszcza', false);

-- Spot 193: Klewków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70192, 'Bzura - Klewków (Cisza)', 'bzura-klewkow-cisza', 'RIVER', 52.1250512, 19.9015101, 'Łódzkie', 'Łowicz', 'Klewków to odcinek rzeki o bardzo spokojnym nurcie i znacznej głębokości, sięgającej w rynnach dwóch metrów. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych linów. Wzdłuż brzegów gęsto rosną trzciny, tworząc naturalne zatoczki idealne do ustawienia zestawu spławikowego z robakiem. Miłośnicy spinningu znajdą tutaj doskonałe miejsca do prowadzenia gum w poszukiwaniu szczupaków czających się w cieniu roślinności. Uciąg jest znikomy, co pozwala na stosowanie najlżejszych i najbardziej czułych wędzisk typu quiver. To łowisko o niskiej presji, gwarantujące ciszę i bliski kontakt z surową, nizinna naturą.', 'PZW Skierniewice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70192, 'Nizinna Mała', 'Spokojny nurt, koryto głębokie', 14.0, 2.0, 'Piaszczysto-muliste', 'Pasy trzcin', 'Leszcz, Lin, Szczupak', 'Kraina leszcza', false);

-- Spot 194: Ozorków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70193, 'Bzura - Ozorków (Miejski)', 'bzura-ozorkow-miejski', 'RIVER', 51.9691338, 19.2857091, 'Łódzkie', 'Ozorków', 'Miejski odcinek w Ozorkowie to techniczna woda o uregulowanym korycie, ale zaskakująco bogatym rybostanie. Rzeka płynie tu jednostajnym nurtem, a dno jest piaszczyste z lokalnymi betonowymi umocnieniami przy murkach. To doskonały poligon dla łowców płoci oraz okoni, które chętnie grupują się przy mostach i przepustach. Spinningowanie na tym fragmencie wymaga dużej precyzji rzutów, aby umieścić przynętę w cieniu rzucanym przez miejską infrastrukturę. Uciąg jest umiarkowany i przewidywalny, co umożliwia idealną prezentację przynęty na bardzo cienkich żyłkach. Mimo miejskiego charakteru, woda jest czysta i przyciąga wędkarzy szukających szybkiego wypadu po pracy.', 'PZW Łódź');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70193, 'Nizinna Mała', 'Uregulowane koryto miejskie', 6.0, 1.0, 'Piasek i beton', 'Mosty, murki', 'Płoć, Okoń, Jaź', 'Kraina leszcza', false);

-- Spot 195: Kowalewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70194, 'Bzura - Kowalewice (Kameralna)', 'bzura-kowalewice-kameralna', 'RIVER', 51.9399625, 19.2765801, 'Łódzkie', 'Zgierz', 'Bzura w Kowalewicach to jeszcze stosunkowo wąska rzeka o charakterze kameralnym i rwanym nurcie. Dno jest tu twarde, piaszczysto-żwirowe, co tworzy doskonałe warunki dla kleni zbierających owady z powierzchni. Koryto posiada liczne przewężenia, gdzie woda gwałtownie przyspiesza, natleniając się na naturalnych kamiennych progach. Spinningista powinien postawić na mikro-przynęty, które najlepiej imitują drobny pokarm naturalny występujący w tym rejonie. Brzegi są częściowo zalesione, co zapewnia naturalny kamuflaż wędkarzowi i cień dla ryb w upalne dni. To wymagające technicznie stanowisko, które potrafi nagrodzić wytrwałych wędkarzy pięknymi okazami rzecznych drapieżników.', 'PZW Łódź');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70194, 'Nizinna Mała', 'Wąskie koryto, nurt rwany', 5.0, 0.8, 'Piaszczysto-żwirowe', 'Kamienne progi', 'Kleń, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 196: Dzierzbiętów Duży
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70195, 'Bzura - Dzierzbiętów Duży (Dzika)', 'bzura-dzierzbietow-duzy', 'RIVER', 52.0416356, 19.2352086, 'Łódzkie', 'Łęczyca', 'Odcinek w Dzierzbiętowie Dużym charakteryzuje się dzikim charakterem i dużą ilością zwalonych do wody pni drzew. Bzura płynie tu krętym korytem, wymywając głębokie jamy na zewnętrznych łukach, które są domem dla sumów. Dno jest mocno urozmaicone, piaszczysto-gliniaste, co sprzyja bytowaniu brzan walczących w głównym prądzie. Spinningowanie w tym miejscu wymaga dużej uwagi ze względu na podwodne karcze i liczne zaczepy. Uciąg jest zdecydowany, co wymusza stosowanie dociążonych koszyków zanętowych zdolnych utrzymać się w rynnie. Jest to łowisko dla doświadczonych wędkarzy, którzy potrafią czytać wodę i nie boją się trudnych warunków terenowych.', 'PZW Łódź');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70195, 'Nizinna Mała', 'Nieuregulowane, zatory', 10.0, 1.8, 'Piasek i glina', 'Zwalone drzewa', 'Sum, Brzana, Szczupak', 'Kraina leszcza', false);

-- Spot 197: Nowomłyny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70196, 'Bzura - Nowomłyny (Młyńska)', 'bzura-nowomlyny-mlynska', 'RIVER', 51.8870097, 19.2332225, 'Łódzkie', 'Zgierz', 'Nowomłyny to miejsce o bardzo ciekawym ukształtowaniu koryta, wynikającym z obecności dawnych urządzeń młyńskich. Rzeka tworzy tu głębokie wymycia i bystrza, w których woda jest wyjątkowo dobrze natleniona i czysta. Dno jest twarde, żwirowo-kamieniste, co czyni ten odcinek bankowym stanowiskiem dla łowców kleni oraz jelców. Warkocze powstające za resztkami pali młyńskich to idealne żerowiska boleni patrolujących tutejszą okolicę o świcie. Wędkarze stacjonarni z sukcesami stosują tu metodę przepływanki, celując w ryby spokojnego żeru gromadzące się w dołkach. To łowisko o unikalnym klimacie, łączące historię regionu z doskonałymi warunkami do uprawiania wędkarstwa rzeźnego.', 'PZW Łódź');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70196, 'Nizinna Mała', 'Bystrza, rynny pomłyńskie', 5.0, 1.2, 'Żwirowo-kamieniste', 'Pale młyńskie', 'Kleń, Boleń, Jelce', 'Kraina leszcza', false);

-- Spot 198: Ruda-Bugaj (Zgierska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70197, 'Bzura - Ruda-Bugaj (Las)', 'bzura-ruda-bugaj-las', 'RIVER', 51.8539225, 19.2489501, 'Łódzkie', 'Zgierz', 'Bzura w Rudzie-Bugaju to kameralny odcinek o krystalicznej wodzie i piaszczysto-żwirowym dnie. Rzeka płynie tu w otoczeniu lasów, co sprzyja obecności ryb reofilnych, takich jak klenie. Nurt jest dość żwawy, tworząc małe warkocze za kamieniami i korzeniami drzew. Spinningiści z sukcesem mogą tu stosować najlżejsze smużaki oraz mikrojigi. Koryto jest wąskie, co wymaga od wędkarza dużej precyzji rzutów i cichego podejścia do brzegu. To doskonałe miejsce na techniczne podchody w poszukiwaniu walecznych okoni czatujących w rynnach.', 'PZW Łódź');

