-- Spot 199: Zgierz (Miejskie Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70198, 'Bzura - Zgierz (Centrum)', 'bzura-zgierz-centrum', 'RIVER', 51.8489217, 19.3661152, 'Łódzkie', 'Zgierz', 'Odcinek w Zgierzu ma charakter typowo miejski, gdzie Bzura płynie uregulowanym korytem o stałym uciągu. Dno jest tu twarde, piaszczyste, z nielicznymi zaczepami w postaci betonowych umocnień przy przepustach. Mimo niewielkiej szerokości, rzeka skrywa stadne płocie oraz wyrośnięte jelce żerujące w głównym nurcie. Najskuteczniejszą metodą jest tu lekki bat lub odległościówka, pozwalająca na precyzyjne operowanie zestawem. Stanowiska są stabilne i łatwo dostępne, co czyni ten fragment idealnym na szybkie sesje wędkarskie. Wieczorami przy brzegach można zaobserwować aktywność mniejszych szczupaków czających się w cieniu roślinności.', 'PZW Łódź');

