VALUES (70198, 'Nizinna Mała', 'Uregulowane koryto miejskie', 5.0, 0.9, 'Piasek i beton', 'Murki oporowe', 'Płoć, Jelce, Szczupak', 'Kraina leszcza', false);

-- Spot 200: Kwiatkówek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70199, 'Bzura - Kwiatkówek (Łąkowy)', 'bzura-kwiatkowek-lakowy', 'RIVER', 52.0685882, 19.2292798, 'Łódzkie', 'Łęczyca', 'Bzura w Kwiatkówku to malowniczy, łąkowy odcinek o naturalnym charakterze i licznych zakolach. Rzeka płynie tu spokojnie, a jej dno jest piaszczysto-muliste z bogatą florą podwodną. To wymarzone miejsce dla łowców szczupaków, którzy precyzyjnie obławiają kępy grążeli i trzcinowiska. Wędkarze stacjonarni mogą liczyć na regularne brania linów oraz złotych karasi w zacisznych zatoczkach. Uciąg jest znikomy, co pozwala na stosowanie najlżejszych i najbardziej czułych spławików stałych. Dojazd przez łąki jest dogodny, choć po opadach może wymagać samochodu o wyższym zawieszeniu.', 'PZW Łódź');

