VALUES (70199, 'Nizinna Mała', 'Meandrująca, naturalna', 10.0, 1.3, 'Piaszczysto-muliste', 'Grążele, trzciny', 'Szczupak, Lin, Karaś', 'Kraina leszcza', false);

-- Spot 201: Radzibórz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70200, 'Bzura - Radzibórz (Dzikie Zakręty)', 'bzura-radziborz-zakrety', 'RIVER', 51.9106585, 19.2543318, 'Łódzkie', 'Ozorków', 'Odcinek w Radziborzu charakteryzuje się dzikim korytem i dużą dynamiką przepływu wody. Bzura mocno tu meandruje, wymywając głębokie doły na zewnętrznych łukach, które są domem dla wyrośniętych kleni. Dno jest tu w przeważającej części twarde, żwirowo-piaszczyste, co sprzyja dotlenieniu wody. Miłośnicy spinningu znajdą tu mnóstwo technicznych miejsc do prowadzenia małych błystek pod nawisami gałęzi. Uciąg jest zdecydowany, co wymusza stosowanie nieco cięższych zestawów niż w innych częściach górnego biegu. To łowisko o niskiej presji, gwarantujące spokój podczas aktywnego poszukiwania rzecznych drapieżników.', 'PZW Łódź');

