VALUES (70200, 'Nizinna Mała', 'Naturalne koryto, rynny', 7.0, 1.2, 'Żwir i piasek', 'Podmyte brzegi', 'Kleń, Okoń, Jaź', 'Kraina leszcza', false);

-- DRAWA

-- Spot 202: gmina Czaplinek (Górna Drawa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70201, 'Drawa - Czaplinek (Źródliskowa)', 'drawa-czaplinek-zrodliskowa', 'RIVER', 53.5414187, 16.0607551, 'Zachodniopomorskie', 'Czaplinek', 'Górny bieg Drawy w gminie Czaplinek to kraina krystalicznie czystej wody i piaszczystego dna. Rzeka płynie tu spokojnie wśród malowniczych łąk, tworząc liczne zakola o głębokości rzadko przekraczającej metr. To idealne miejsce na techniczne polowanie za kleniem i jaziem przy użyciu mikro-woblerów. Podmyte brzegi i pasy roślinności zanurzonej skrywają liczne okonie, które doskonale reagują na małe jigi. Uciąg jest tu łagodny, co pozwala na bardzo naturalną prezentację przynęty na delikatnym zestawie spławikowym. Ze względu na przejrzystość wody, wędkarz musi zachować dużą dyskrecję i stosować cienkie przypony fluorocarbonowe.', 'PZW Koszalin');

