VALUES (70201, 'Nizinna Mała', 'Naturalne, meandrujące', 8.0, 0.8, 'Piaszczyste', 'Pasy roślinności', 'Kleń, Jaź, Okoń', 'Kraina pstrąga', 'Pojezierze Drawskie', false);

-- Spot 203: Pszczewko (Drawieński Park Narodowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70202, 'Drawa - Pszczewko (Kamienny Przełom)', 'drawa-pszczewko-przelom', 'RIVER', 53.232693, 15.7682201, 'Zachodniopomorskie', 'Drawno', 'Odcinek w Pszczewku charakteryzuje się rwanym nurtem i dnem usianym grubymi głazami narzutowymi. Drawa przybiera tu postać rzeki górskiej, tworząc liczne bystrza oraz doskonale natlenione warkocze. To legendarne łowisko pstrąga potokowego oraz lipienia, które wymagają od wędkarza umiejętności technicznego brodzenia. W głębokich rynnach za przeszkodami często stacjonują potężne brzany, które potrafią agresywnie zaatakować ciężkiego feedera. Należy pamiętać, że wędkowanie na tym obszarze podlega rygorystycznym przepisom parku narodowego i wymaga specjalnej licencji. Surowy klimat i siła płynącej wody sprawiają, że jest to jedno z najbardziej wymagających łowisk w regionie.', 'DPN / PZW Gorzów Wlkp.');

