-- Spot 204: Lubieszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70203, 'Drawa - Lubieszewo (Leśna)', 'drawa-lubieszewo-lesna', 'RIVER', 53.4452693, 15.9325317, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Drawa w Lubieszewie przedziera się przez gęste kompleksy leśne, tworząc głębokie i ciemne rynny. Dno jest tu mocno urozmaicone piaszczystymi łachami oraz licznymi zwalonymi drzewami, które są bazą dla szczupaków. Spinningiści z sukcesami polują tu na okonie, wykorzystując gumy na lekkich główkach prowadzone w pobliżu zatopionych kłód. Uciąg wody jest stały i umiarkowany, co sprzyja bytowaniu dorodnych płoci oraz wyrośniętych krąpi. Brzegi są wysokie i porośnięte wikliną, co zapewnia naturalny kamuflaż, ale utrudnia lądowanie większych ryb bez podbieraka. To idealne miejsce na całodniową wyprawę spinningową w poszukiwaniu rzecznych drapieżników w całkowitym odosobnieniu.', 'PZW Szczecin');

