-- Spot 205: Żołędowo (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70204, 'Drawa - Żołędowo (Rynna Pod Brzegiem)', 'drawa-zoledowo-rynna', 'RIVER', 53.4204963, 15.9115834, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Odcinek w Żołędowie oferuje wędkarzom dostęp do rzeki o bardzo urozmaiconym ukształtowaniu koryta. Drawa mocno tu meandruje, żłobiąc głębokie rynny pod samym brzegiem, w których często grupują się leszcze. Dno jest twarde, piaszczysto-gliniaste, co sprzyja systematycznemu nęceniu pola łowiska przy użyciu feedera. Wędkarze stacjonarni mogą liczyć na regularne brania jazi, które chętnie odwiedzają tutejsze spokojniejsze zastoiska. Uciąg rzeki w tym miejscu jest zdecydowany, co wymusza stosowanie koszyków o masie co najmniej czterdziestu gramów. Cisza i brak bliskiej zabudowy sprawiają, że ryby żerują tu śmiało nawet przy niższym stanie wody.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70204, 'Nizinna Średnia', 'Naturalny nurt, rynny', 18.0, 2.2, 'Piasek i glina', 'Podmyte burty', 'Leszcz, Jaź, Płoć', 'Kraina leszcza', 'Brak', true);

-- Spot 206: Żołędowo (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70205, 'Drawa - Żołędowo (Bystrza)', 'drawa-zoledowo-bystrza', 'RIVER', 53.4031631, 15.8766938, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Drugi punkt w Żołędowie to odcinek o nieco żywszym nurcie z piaszczysto-żwirowymi przykosami na środku koryta. Rzeka rozlewa się tu szerzej, tworząc natlenione warkocze, w których wieczorami widowiskowo polują bolenie. To doskonałe miejsce dla spinningistów stosujących smukłe woblery imitujące ukleje prowadzone z prądem wody. Dno jest czyste i twarde, co znacznie ogranicza liczbę zaczepów przy łowieniu na dłuższą odległość. Wędkarze spławikowi z sukcesami stosują tu metodę przepływanki, celując w dorodne płocie i wyrośnięte jelce. Stanowiska brzegowe są nieliczne, co zapewnia wędkarzowi dużą dozę prywatności i spokoju podczas wielogodzinnych zasiadek.', 'PZW Szczecin');

