VALUES (70205, 'Nizinna Średnia', 'Nurt żywy, koryto szerokie', 22.0, 1.5, 'Piasek i żwir', 'Piaszczyste przykosy', 'Boleń, Płoć, Jelce', 'Kraina leszcza', 'Brak', true);

-- Spot 207: Złocieniec (Odcinek Miejski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70206, 'Drawa - Złocieniec (Promenada)', 'drawa-zlocieniec-promenada', 'RIVER', 53.5310096, 15.9682177, 'Zachodniopomorskie', 'Złocieniec', 'Drawa w Złocieńcu to techniczny odcinek o uregulowanym korycie, ale zachowujący naturalny charakter dna. Rzeka płynie tu jednostajnym nurtem, żłobiąc piaszczyste rynny pod brzegowymi murkami i mostami. To doskonałe miejsce dla spinningistów polujących na okonie oraz klenie żerujące w cieniu miejskiej architektury. Wędkarze spławikowi mogą liczyć na regularne brania płoci oraz jelców przy użyciu lekkich zestawów z batem. Uciąg wody jest umiarkowany, co pozwala na precyzyjne nęcenie punktowe w pasie przybrzeżnym. Dzięki wygodnym bulwarom dostęp do lustra wody jest tu wzorcowy, co przyciąga lokalnych pasjonatów wędkarstwa.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70206, 'Nizinna Mała', 'Uregulowane koryto miejskie', 10.0, 1.2, 'Piasek i żwir', 'Mosty, murki oporowe', 'Płoć, Okoń, Kleń', 'Kraina leszcza', 'Odcinek miejski', false);

-- Spot 208: Rzęśnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70207, 'Drawa - Rzęśnica (Leśne Zakola)', 'drawa-rzesnica-zakola', 'RIVER', 53.5463857, 15.9307228, 'Zachodniopomorskie', 'Złocieniec', 'Odcinek w Rzęśnicy charakteryzuje się dzikim charakterem koryta z dużą ilością zwalonych do wody drzew. Drawa mocno tu meandruje, wymywając głębokie na ponad półtora metra jamy pod podmytymi burtami. To wymarzone stanowisko dla spinningistów polujących na szczupaki oraz wyrośnięte okonie czające się w podwodnych karczowiskach. Dno piaszczysto-żwirowe sprzyja aktywności jazi, które chętnie żerują na granicy nurtu i spokojniejszych zastoisk. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza precyzyjnego prowadzenia przynęty. Cisza i brak bliskiej zabudowy sprawiają, że można tu liczyć na kontakt z naprawdę dziką rybą w otoczeniu leśnej głuszy.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70207, 'Nizinna Średnia', 'Meandrująca, leśna', 12.0, 1.5, 'Piasek i żwir', 'Zwalone drzewa', 'Szczupak, Okoń, Jaź', 'Kraina pstrąga', 'Brak', false);

-- Spot 209: gmina Drawsko Pomorskie (Odcinek Poligonowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70208, 'Drawa - Drawsko Pomorskie (Poligon)', 'drawa-drawsko-poligon', 'RIVER', 53.5415545, 15.8859142, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'W rejonie poligonu rzeka Drawa rozlewa się nieco szerzej, płynąc przez tereny o niskiej presji wędkarskiej. Dno jest tu w większości twarde i piaszczyste, z lokalnymi żwirowymi rafami, na których żerują stadne klenie. To idealny teren dla spinningistów polujących na bolenie, które widowiskowo pokazują się na powierzchni podczas bicia drobnicy. Nurt jest jednostajny i łagodny, co sprzyja systematycznemu nęceniu stad leszczy żerujących w rynnach głównego nurtu. Roślinność brzegowa jest tu rzadsza, co ułatwia dostęp do wody, ale wymaga od wędkarza dobrego maskowania. To łowisko słynie z krystalicznej wody, dlatego warto stosować tu najcieńsze możliwe przypony z fluorocarbonu.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70208, 'Nizinna Średnia', 'Szeroka, nurt łagodny', 18.0, 1.4, 'Piasek i żwir', 'Brak', 'Leszcz, Boleń, Kleń', 'Kraina leszcza', 'Tereny wojskowe (ograniczony dostęp)', true);

-- Spot 210: Drawsko Pomorskie (Most Kolejowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70209, 'Drawa - Drawsko Pomorskie (Wschodnia)', 'drawa-drawsko-wschodnia', 'RIVER', 53.5401155, 15.8402734, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Odcinek wschodniej części Drawska Pomorskiego słynie z głębokich rynien wymytych w pobliżu betonowych filarów mostowych. Dno charakteryzuje się występowaniem twardych, gliniastych blatów, które są ulubionym miejscem żerowania dużych jazi i płoci. Uciąg wody jest tu znaczący, co wymaga od wędkarza gruntowego stosowania stabilnych koszyków o masie powyżej czterdziestu gramów. Spinningiści z sukcesami obławiają tutejsze warkocze, stosując gumy na lekkich główkach prowadzone agresywnym skokiem. Brzeg jest tu częściowo umocniony, co ułatwia lądowanie ryb, ale wymusza stosowanie podbieraka o dłuższym gryfie. Wieczorne wyprawy w to miejsce często owocują braniem solidnego sandacza lub wyrośniętego klenia.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70209, 'Nizinna Średnia', 'Uregulowane, nurt silny', 16.0, 2.0, 'Glina i piasek', 'Filary mostu, opaski', 'Jaź, Płoć, Sandacz', 'Kraina leszcza', 'Odcinek miejski', false);

-- Spot 211: Drawsko Pomorskie (Park)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70210, 'Drawa - Drawsko Pomorskie (Park Chopina)', 'drawa-drawsko-park', 'RIVER', 53.5251479, 15.8021129, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Odcinek w parku Chopina to jedno z najwygodniejszych łowisk na Drawie, oferujące płaski, trawisty brzeg i stabilną wodę. Rzeka płynie tu spokojnym korytem o wyrównanej głębokości, z piaszczysto-mulistym dnem obfitującym w pokarm naturalny. To doskonałe miejsce na rodzinne zasiadki z lekkim feederem lub techniką spławikową w poszukiwaniu dorodnych wzdręg. Wzdłuż brzegów rosną kępy grążeli, w których cieniu chętnie ustawiają się okonie czekające na narybek. Uciąg jest znikomy, co pozwala na stosowanie najdelikatniejszych szczytówek i precyzyjną prezentację przynęty. Miejsce to cieszy się dużą popularnością ze względu na doskonały dojazd i możliwość rozstawienia całego ekwipunku tuż przy samej wodzie.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70210, 'Nizinna Średnia', 'Leniwy nurt, parkowa okolica', 15.0, 1.3, 'Piasek i muł', 'Pasy grążeli', 'Wzdręga, Leszcz, Okoń', 'Kraina leszcza', 'Park miejski', false);

-- Spot 212: Złocieniec (Przewężenie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70211, 'Drawa - Złocieniec (Rynna Pod Lasem)', 'drawa-zlocieniec-rynna', 'RIVER', 53.5401542, 16.0152647, 'Zachodniopomorskie', 'Złocieniec', 'W rejonie wylotowym ze Złocieńca Drawa przedziera się przez zwężenie terenu, co powoduje wyraźne przyspieszenie nurtu wody. Dno jest tu twarde i żwirowe, z licznymi mikrowarkoczami powstającymi za naturalnymi przeszkodami w nurcie głównym. Jest to doskonała lokalizacja dla łowców lipieni oraz pstrągów potokowych, które doskonale reagują na techniki muchowe. Spinningista znajdzie tutaj dogodne rynny do prowadzenia małych błystek obrotowych oraz woblerów o agresywnej pracy. Uciąg rzeki wymusza stosowanie dociążonych zestawów, aby dotrzeć do ryb trzymających się przy samym dnie. To bardzo techniczny odcinek rzeki, który wymaga od wędkarza dużej kondycji przy brodzeniu oraz precyzyjnego czytania wody.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70211, 'Podgórska', 'Bystry nurt, przewężenia', 9.0, 0.9, 'Żwir i kamienie', 'Naturalne warkocze', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', 'Brak', false);

-- Spot 213: Siemczyno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70212, 'Drawa - Siemczyno (Rozlewisko)', 'drawa-siemczyno-rozlewisko', 'RIVER', 53.5925208, 16.1263573, 'Zachodniopomorskie', 'Czaplinek', 'Drawa w Siemczynie to odcinek o charakterze wybitnie jeziornym, położony na szerokim rozlewisku przed jeziorem Drawsko. Woda płynie tu niemal niezauważalnie, a koryto jest gęsto porośnięte pasami trzcin oraz rozległymi polami grążeli. To królestwo szczupaka i lina, które znajdują tu idealne warunki do żerowania na bogatym dnie piaszczysto-mulistym. Wędkarze stacjonarni z sukcesami stosują tu metodę odległościową, celując w dorodne płocie i wyrośnięte wzdręgach. Dzięki dużej szerokości rzeki, jest to doskonałe miejsce na łowienie z łodzi, co pozwala na dotarcie do niedostępnych z brzegu partii łowiska. Cisza panująca w tej okolicy oraz malowniczy krajobraz pojezierza sprawiają, że jest to doskonałe miejsce na relaksujący, całodniowy wypoczynek.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70212, 'Nizinna Średnia', 'Spokojna, rozlewisko', 25.0, 2.2, 'Muł i piasek', 'Rozległe trzcinowiska', 'Szczupak, Lin, Leszcz', 'Kraina leszcza', 'Pojezierze Drawskie', true);

-- Spot 214: Rzepowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70213, 'Drawa - Rzepowo (Piaszczyste Płanie)', 'drawa-rzepowo-planie', 'RIVER', 53.5894762, 16.0810581, 'Zachodniopomorskie', 'Złocieniec', 'Drawa w Rzepowie charakteryzuje się bardzo czystą wodą i wyrównanym, piaszczystym dnem koryta. Rzeka płynie tu spokojnie wśród otwartych łąk, co ułatwia rzuty dłuższą odległościówką lub lekkim feederem. To doskonałe miejsce dla łowców jazi i kleni, które doskonale reagują na naturalne przynęty podawane z prądem. Uciąg jest umiarkowany, co pozwala na precyzyjne nęcenie pola łowiska przy użyciu luźnej zanęty sypanej w nurt. Brzegi są niskie i łatwo dostępne, zapewniając wędkarzowi duży komfort podczas całodniowej zasiadki. W rynnach pod drugim brzegiem często stacjonują wyrośnięte płocie, które są symbolem tego rybnego odcinka rzeki.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70213, 'Nizinna Mała', 'Spokojny nurt, koryto naturalne', 12.0, 1.2, 'Piaszczyste', 'Brak', 'Jaź, Kleń, Płoć', 'Kraina leszcza', 'Pojezierze Drawskie', false);

-- Spot 215: Stare Drawsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70214, 'Drawa - Stare Drawsko (Przesmyk)', 'drawa-stare-drawsko', 'RIVER', 53.6021125, 16.1960614, 'Zachodniopomorskie', 'Czaplinek', 'Odcinek w Starym Drawsku stanowi strategiczny łącznik między dużymi jeziorami pojezierza drawskiego. Woda płynie tu leniwie, a koryto jest gęsto porośnięte roślinnością wynurzoną, co sprzyja bytowaniu rekordowych szczupaków. Dno jest piaszczysto-muliste, obfitujące w pokarm naturalny przyciągający duże stada leszczy oraz dorodne liny. Spinningiści z sukcesami obławiają tutejsze pasy trzcin, stosując większe gumy prowadzone powolnym ruchem w toni. Ze względu na wzmożony ruch turystyczny w sezonie, najlepsze wyniki osiąga się tu o świcie i późnym wieczorem. To idealne łowisko dla osób szukających grubego białorybu w bezpośrednim sąsiedztwie historycznych ruin zamku.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70214, 'Nizinna Mała', 'Spokojny, charakter jeziorny', 15.0, 2.0, 'Piasek i muł', 'Trzcinowiska', 'Szczupak, Leszcz, Lin', 'Kraina leszcza', 'Pojezierze Drawskie', true);

-- Spot 216: gmina Drawno (Szyja DPN)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70215, 'Drawa - Drawno (Wjazd do Parku)', 'drawa-drawno-dpn', 'RIVER', 53.207541, 15.7517841, 'Zachodniopomorskie', 'Drawno', 'Wlot Drawy do parku narodowego w Drawnie to odcinek o niezwykle dynamicznym nurcie i żwirowym podłożu. Rzeka zaczyna tu przyspieszać, żłobiąc głębokie rynny i tworząc natlenione warkocze za naturalnymi przeszkodami. Jest to doskonała lokalizacja dla łowców lipieni oraz pstrągów potokowych, które chętnie wybierają te partie wody. Wędkowanie na tym fragmencie wymaga posiadania specjalnej licencji DPN i przestrzegania rygorystycznych zasad ochrony przyrody. Uciąg rzeki wymusza stosowanie dociążonych zestawów muchowych lub spinningowych, aby dotrzeć do ryb trzymających się dna. Malownicze położenie i krystaliczna woda sprawiają, że każda wyprawa w to miejsce dostarcza niezapomnianych wrażeń.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70215, 'Górska', 'Bystry nurt, koryto żwirowe', 18.0, 1.1, 'Żwir i kamienie', 'Bystrza', 'Pstrąg potokowy, Lipień, Jaź', 'Kraina pstrąga', 'Drawieński Park Narodowy', false);

-- Spot 217: Barnimie (Ostępy leśne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70216, 'Drawa - Barnimie (Dzika Rzeka)', 'drawa-barnimie-dzika', 'RIVER', 53.1860732, 15.7793808, 'Zachodniopomorskie', 'Drawno', 'Drawa w Barnimiu to jeden z najbardziej dzikich i nieprzewidywalnych odcinków w całym dorzeczu. Rzeka meandruje tu przez gęste puszcze, a jej koryto usiane jest setkami zwalonych pni starych buków i dębów. To królestwo potężnych brzan, które walczą w głównym nurcie, wykorzystując powalone drzewa jako bezpieczne schronienie. Spinningiści znajdą tutaj doskonałe rynny do prowadzenia ciężkich jigów w poszukiwaniu rekordowych okoni i szczupaków. Nurt rzeki jest tu niezwykle silny, co wymaga od wędkarza brodzącego ogromnej uwagi i profesjonalnego obuwia. Surowość tego miejsca i brak jakiejkolwiek infrastruktury sprawiają, że jest to łowisko tylko dla najbardziej wytrwałych.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70216, 'Górska', 'Przełomowy, liczne zwaliska', 22.0, 1.5, 'Kamieniste', 'Zwalone drzewa', 'Brzana, Pstrąg potokowy, Szczupak', 'Kraina pstrąga', 'Drawieński Park Narodowy', false);

-- Spot 218: Konotop (Wielkie Zakole)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70217, 'Drawa - Konotop (Banie)', 'drawa-konotop-banie', 'RIVER', 53.1627016, 15.8026962, 'Zachodniopomorskie', 'Drawno', 'W rejonie Konotopu rzeka tworzy spektakularne, głębokie banie, w których woda niemal staje w miejscu na zewnętrznych łukach. Głębokość w takich punktach przekracza często trzy metry, co sprzyja zimowaniu dużych stad rzecznych ryb. Dno jest tu mocno zróżnicowane, od gliniastych uskoków po piaszczyste przykosy wychodzące daleko w nurt. To wymarzone miejsce dla łowców kleni, które zbierają się pod nawisami gałęzi, czekając na spływający pokarm. Wędkowanie wymaga tu dużej dyskrecji, ponieważ krystaliczna woda sprawia, że ryby są bardzo płochliwe przy wysokim brzegu. Miejsce to słynie z niespotykanego spokoju i jest rzadko odwiedzane ze względu na trudny dostęp terenowy.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70217, 'Nizinna Średnia', 'Meandrująca, głębokie jamy', 20.0, 3.0, 'Glina i piasek', 'Głębokie banie', 'Kleń, Jaź, Brzana', 'Kraina leszcza', 'Drawieński Park Narodowy', false);

-- Spot 219: Zatom (Równia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70218, 'Drawa - Zatom (Piaszczysta Równia)', 'drawa-zatom-rownia', 'RIVER', 53.141859, 15.8312933, 'Zachodniopomorskie', 'Drawno', 'Odcinek w Zatomiu charakteryzuje się szerokim korytem i nieco wolniejszym przepływem wody niż w górnych partiach parku. Rzeka posiada tu wyrównaną głębokość z nielicznymi piaszczystymi łachami, na których wieczorami żerują jelce i klenie. To idealne miejsce na technikę muchową, pozwalające na swobodne rzuty suchą muchą na otwartym fragmencie koryta. Dno jest czyste i piaszczyste, co czyni to łowisko bardzo przyjaznym dla wędkarzy brodzących w poszukiwaniu rzecznych drapieżników. Roślinność zanurzona tworzy tu gęste dywany, w których chętnie przebywają stadne okonie o pokaźnych rozmiarach. Cisza panująca w tej okolicy i brak sztucznego światła sprawiają, że nocne zasiadki gruntowe bywają tu niezwykle skuteczne.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70218, 'Nizinna Średnia', 'Szerokie płanie nizinne', 25.0, 1.4, 'Piaszczyste', 'Dywany roślinne', 'Kleń, Płoć, Jelce, Okoń', 'Kraina leszcza', 'Drawieński Park Narodowy', false);

-- Spot 220: Bogdanka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70219, 'Drawa - Bogdanka (Leśny Przełom)', 'drawa-bogdanka-przelom', 'RIVER', 53.1398639, 15.8764054, 'Zachodniopomorskie', 'Drawno', 'Bogdanka to jeden z najbardziej malowniczych przystanków na dolnej Drawie, słynący z charakterystycznego mostu i bystrego nurtu. Rzeka płynie tutaj w głębokim wąwozie leśnym, co nadaje jej niemal podgórskiego charakteru. Dno jest twarde, piaszczysto-żwirowe, z licznymi głazami tworzącymi atrakcyjne dla pstrągów i lipieni warkocze. Wędkarze mogą liczyć na spotkanie z dorodnymi kleniami, które doskonale reagują na techniki muchowe oraz spinningowe. Uciąg wody jest stały i zdecydowany, co wymaga od wędkarza brodzącego stabilnego obuwia i dużego skupienia. Ze względu na położenie w sercu parku narodowego, obowiązują tu surowe limity i wymóg posiadania specjalnej licencji DPN.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
