-- Spot 221: gmina Dobiegniew (Sitnica Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70220, 'Drawa - Dobiegniew (Głębokie Rynny)', 'drawa-dobiegniew-rynny', 'RIVER', 53.1139481, 15.8910867, 'Lubuskie', 'Dobiegniew', 'Odcinek Drawy w gminie Dobiegniew charakteryzuje się znaczną głębokością koryta, dochodzącą w rynnach do ponad dwóch metrów. Rzeka płynie tu szerzej, a jej nurt staje się bardziej dostojny i przewidywalny. Dno jest piaszczysto-gliniaste, co sprzyja bytowaniu dorodnych brzan oraz wyrośniętych kleni czatujących przy dnie. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, celując w szczupaki i wyrośnięte okonie. Uciąg rzeki w tym miejscu pozwala na komfortowe łowienie metodą ciężkiej przepływanki z dużym spławikiem. To doskonałe łowisko dla osób szukających ciszy w otoczeniu starych bukowych lasów, z dala od popularnych szlaków turystycznych.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70220, 'Nizinna Średnia', 'Szerokie zakola, nurt stabilny', 25.0, 2.2, 'Piasek i glina', 'Podmyte burty', 'Brzana, Kleń, Szczupak', 'Kraina leszcza', 'Drawieński Park Narodowy', false);

-- Spot 222: Sitnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70221, 'Drawa - Sitnica (Meandry)', 'drawa-sitnica-meandry', 'RIVER', 53.0943857, 15.9221512, 'Lubuskie', 'Dobiegniew', 'Drawa w Sitnicy tworzy spektakularne meandry, żłobiąc dno na zewnętrznych łukach koryta i tworząc głębokie jamy. Woda jest tu krystalicznie czysta, co pozwala na obserwację żerujących ryb przy zachowaniu odpowiedniej dyskrecji. Dno jest przeważnie piaszczyste, z lokalnymi naniesieniami żwiru, na których chętnie przebywają stada jazi. Wędkarze stacjonarni cenią to miejsce za populację grubego białorybu, szczególnie płoci oraz certy migrującej w górę rzeki. Uciąg jest umiarkowany, co ułatwia systematyczne nęcenie pola łowiska i utrzymanie w nim ryb przez dłuższy czas. To techniczny odcinek rzeki, nagradzający precyzję rzutu i umiejętność czytania zmian w nurcie rzeki.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70221, 'Nizinna Średnia', 'Naturalne, silne meandrowanie', 20.0, 1.8, 'Piasek i żwir', 'Zwaliska drzew', 'Jaź, Certa, Płoć', 'Kraina leszcza', 'Drawieński Park Narodowy', false);

-- Spot 223: Moczele
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70222, 'Drawa - Moczele (Bystrza)', 'drawa-moczele-bystrza', 'RIVER', 53.0676584, 15.9287324, 'Lubuskie', 'Dobiegniew', 'Odcinek w Moczelach słynie z bardzo bystrego nurtu i licznych naturalnych zatorów z potężnych pni drzew. Drawa przybiera tu niemal górski charakter, a woda huczy na kamiennych progach i naturalnych bystrzach. To legendarne stanowisko dla łowców potężnych brzan, które znajdują tu idealne warunki tlenowe w głównym nurcie. Spinningiści znajdą tutaj liczne warkocze powstające za przeszkodami, w których czatują bolenie i okonie. Dno jest twarde, kamienisto-żwirowe, co znacznie utrudnia tradycyjne nęcenie, wymagając stosowania dociążonych zanęt. Ze względu na trudny teren i siłę rzeki, jest to łowisko polecane wyłącznie doświadczonym i sprawnym wędkarzom.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70222, 'Górska', 'Bystry nurt, liczne zatory', 18.0, 1.4, 'Kamienisto-żwirowe', 'Naturalne progi, kłody', 'Brzana, Boleń, Okoń', 'Kraina pstrąga', 'Drawieński Park Narodowy', false);

-- Spot 224: Kamienna Knieja
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70223, 'Drawa - Kamienna Knieja (Uroczysko)', 'drawa-kamienna-knieja', 'RIVER', 53.0410264, 15.9388729, 'Lubuskie', 'Dobiegniew', 'Kamienna Knieja to odcinek Drawy o wyjątkowo dzikim krajobrazie, gdzie rzeka opuszcza zwarte kompleksy leśne DPN. Koryto staje się tu nieco szersze, a nurt łagodnieje, tworząc rozległe piaszczyste łachy na wewnętrznych łukach. To wymarzone miejsce dla łowców jazi i kleni, które chętnie zbierają się w cieniu nadbrzeżnych krzewów. Dno piaszczyste z lokalnymi skupiskami roślinności zanurzonej stanowi doskonałe schronienie dla stadnych płoci. Wędkarze spławikowi z sukcesami stosują tu technikę przepływanki, puszczając zestaw na długich dystansach wzdłuż brzegowej linii. Miejsce to zapewnia absolutny spokój i pozwala na pełne obcowanie z przyrodą przy minimalnej presji innych wędkarzy.', 'Drawieński Park Narodowy');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70223, 'Nizinna Średnia', 'Spokojna, szeroka rzeka', 28.0, 1.5, 'Piaszczyste', 'Piaszczyste łachy', 'Jaź, Kleń, Płoć', 'Kraina leszcza', 'Otulina DPN', false);

-- Spot 225: gmina Krzyż Wielkopolski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70224, 'Drawa - Krzyż (Przedujście)', 'drawa-krzyz-przedujscie', 'RIVER', 53.015893, 15.9563501, 'Wielkopolskie', 'Krzyż Wielkopolski', 'Drawa w gminie Krzyż Wielkopolski nabiera cech rzeki nizinnej, płynąc leniwie przez tereny zalewowe. Głębokość rzeki jest tu ustabilizowana, a dno w większości piaszczysto-muliste, co sprzyja rozwojowi bogatej fauny dennej. To idealne łowisko dla miłośników feedera klasycznego, celujących w dorodne leszcze i krąpie żerujące na spokojnych płaniach. Wzdłuż brzegów rosną gęste pasy trzcin, które są naturalną kryjówką dla szczupaków i wyrośniętych linów. Uciąg jest znikomy, co pozwala na stosowanie bardzo delikatnych zestawów z czułymi szczytówkami typu quiver. Dzięki dobremu dostępowi do wody, jest to popularne miejsce na weekendowe zasiadki rodzinne i relaks z wędką.', 'PZW Gorzów Wlkp.');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70224, 'Nizinna Wielka', 'Leniwy nurt, szerokie koryto', 35.0, 2.5, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Lin, Szczupak', 'Kraina leszcza', true);

-- Spot 226: Czarnolesie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70225, 'Drawa - Czarnolesie (Ujście)', 'drawa-czarnolesie-ujscie', 'RIVER', 52.9888195, 15.95511108, 'Wielkopolskie', 'Krzyż Wielkopolski', 'Czarnolesie to strategiczny odcinek rzeki położony tuż przed jej ujściem do Noteci, oferujący bardzo rybne rozlewiska. Występuje tu silne zjawisko mieszania się wód, co przyciąga ogromne ławice białorybu migrujące między obiema rzekami. Dno jest mocno zróżnicowane, piaszczyste z wyraźnymi rynnami ujściowymi, w których stacjonują sandacze i sumy. Spinningiści z sukcesami obławiają tutejsze wyloty starorzeczy, stosując gumy prowadzone agresywnym opadem. Uciąg rzeki jest tu zmienny i uzależniony od poziomu wody w Noteci, co stwarza ciekawe warunki dla doświadczonych wędkarzy. Jest to wybitne łowisko jesienne, gwarantujące częste brania drapieżników polujących na gromadzącą się ukleję.', 'PZW Gorzów Wlkp.');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70225, 'Nizinna Wielka', 'Szerokie rozlewisko ujściowe', 45.0, 3.5, 'Piasek i muł', 'Wyloty starorzeczy', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', true);

-- Spot 227: gmina Dobiegniew (Dolna Drawa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70226, 'Drawa - Dobiegniew (Szerokie Płanie)', 'drawa-dobiegniew-planie', 'RIVER', 52.9619783, 15.961422, 'Lubuskie', 'Dobiegniew', 'Drawa w dolnym biegu gminy Dobiegniew to szeroka rzeka o leniwym nurcie i piaszczystym dnie. Brzegi są tu gęsto porośnięte trzciną, co stanowi idealne tarlisko i schronienie dla dorodnych szczupaków. Wędkarze gruntowi mogą liczyć na regularne brania leszczy żerujących na piaszczystych blatach w głównym nurcie. Uciąg wody jest znikomy, dzięki czemu precyzyjne nęcenie przynosi tu doskonałe efekty przez cały sezon. Spinningiści powinni skupić się na obławianiu pasów roślinności zanurzonej przy użyciu lekkich gum i błystek obrotowych. To spokojne łowisko o ugruntowanej renomie wśród łowców białorybu szukających wytchnienia od cywilizacji.', 'PZW Gorzów Wlkp.');

