VALUES (70226, 'Nizinna Wielka', 'Spokojny nurt, szerokie koryto', 30.0, 2.0, 'Piaszczyste', 'Trzcinowiska', 'Szczupak, Leszcz, Płoć', 'Kraina leszcza', true);

-- Spot 228: Zwierzyniec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70227, 'Drawa - Zwierzyniec (Leśne Zastoiska)', 'drawa-zwierzyniec-lesne', 'RIVER', 52.9370346, 15.9788898, 'Lubuskie', 'Drezdenko', 'W okolicach Zwierzyńca Drawa płynie głębokim korytem przez zwarte kompleksy leśne Puszczy Drawskiej. Dno rzeki jest tu urozmaicone piaszczystymi łachami oraz licznymi, podwodnymi przeszkodami w postaci zwalonych dębów. To doskonałe stanowisko dla łowców sumów, które w tutejszych jamach znajdują idealne warunki do bytowania. Nurt jest umiarkowany, co pozwala na skuteczne łowienie ciężkim feederem z koszykami o masie powyżej pięćdziesięciu gramów. Brzegi są wysokie i miejscami trudno dostępne, co sprzyja zachowaniu naturalnej dzikości tego rybnego odcinka. Wieczorne wyprawy z martwą rybką często owocują tu braniem dorodnego sandacza lub węgorza.', 'PZW Gorzów Wlkp.');

