VALUES (70227, 'Nizinna Wielka', 'Meandrująca rzeka leśna', 35.0, 2.5, 'Piasek i glina', 'Zwalone kłody', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 229: Przeborowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70228, 'Drawa - Przeborowo (Ujściowe Cofki)', 'drawa-przeborowo-ujscie', 'RIVER', 52.9099306, 15.9791314, 'Lubuskie', 'Drezdenko', 'Przeborowo to odcinek Drawy położony blisko ujścia do Noteci, gdzie często występuje zjawisko cofki wodnej. Rzeka rozlewa się tu bardzo szeroko, tworząc bogate w pokarm rozlewiska idealne dla białorybu. Dno jest piaszczysto-muliste z licznymi kępami grążeli żółtych, w których jesienią żerują medalowe szczupaki. To wymarzone miejsce dla spinningistów stosujących duże woblery i ciężkie wahadłówki w celu sprowokowania drapieżnika. Uciąg wody jest zmienny, dlatego warto na bieżąco dostosowywać masę zestawu do aktualnego przepływu rzeki. Stanowiska brzegowe są nieliczne i naturalne, co nadaje temu miejscu wyjątkowy, surowy klimat.', 'PZW Gorzów Wlkp.');

