-- Spot 230: Bielice Nowe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70229, 'Drawa - Bielice Nowe (Koniec Biegu)', 'drawa-bielice-koniec', 'RIVER', 52.882938, 15.9764027, 'Lubuskie', 'Krzyż Wielkopolski', 'Bielice Nowe to ostatni fragment Drawy przed jej ostatecznym połączeniem z wodami rzeki Noteć. Woda płynie tu leniwie, a koryto jest głębokie i stabilne, obfitujące w dorodne leszcze oraz krąpie. Dno jest mocno urozmaicone piaszczystymi blatami, które są ulubionym żerowiskiem dla jazi i cert migrujących. Spinningiści z sukcesami obławiają tutejsze rynny, stosując smukłe woblery imitujące ukleje prowadzone z prądem wody. Uciąg rzeki pozwala na komfortowe łowienie odległościówką, co jest rzadkością na tak dużych rzekach nizinnych. Dzięki krystalicznej wodzie płynącej z północy, ryby są tu wyjątkowo waleczne i zdrowe.', 'PZW Gorzów Wlkp.');

