-- Spot 231: Prostynia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70230, 'Drawa - Prostynia (Poligonowa)', 'drawa-prostynia-poligon', 'RIVER', 53.3093314, 15.7761812, 'Zachodniopomorskie', 'Kalisz Pomorski', 'W rejonie Prostyni Drawa przepływa przez malownicze tereny leśne, zachowując swój krystalicznie czysty i dziki charakter. Nurt rzeki jest tu dość żwawy, żłobiąc piaszczysto-żwirowe dno i tworząc liczne, natlenione bystrza. To wymarzone stanowisko dla łowców jazi oraz kleni, które doskonale reagują na małe woblery i smużaki. Podmyte korzenie starych olch przy brzegach skrywają dorodne okonie, które agresywnie atakują przepływający narybek. Uciąg rzeki wymaga stosowania dociążonych zestawów spinningowych oraz precyzyjnych rzutów pod nawisy nadbrzeżnych drzew. Ze względu na bliskość poligonu drawskiego, panuje tu wyjątkowa cisza i znikoma presja ze strony innych wędkarzy.', 'PZW Szczecin');

