-- Spot 232: Rościn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70231, 'Drawa - Rościn (Żwirowe Rafy)', 'drawa-roscin-rafy', 'RIVER', 53.282415, 15.7716459, 'Zachodniopomorskie', 'Drawno', 'Drawa w Rościnie to odcinek o charakterze niemal podgórskim z bardzo czystą wodą i twardym podłożem. Rzeka tworzy tu liczne żwirowe rafy oraz rynny o głębokości rzadko przekraczającej półtora metra. Jest to klasyczne łowisko pstrąga potokowego, który znajduje tu doskonałe warunki do żerowania w szybkim prądzie. Wędkarze powinni skupić się na cichym podchodzeniu do stanowiska, gdyż przejrzysta woda czyni ryby niezwykle płochliwymi. Uciąg jest silny, co pozwala na widowiskowe prowadzenie suchej muchy lub lekkich mikro-błystek obrotowych. To elitarne miejsce dla koneserów wędkarstwa technicznego, szukających kontaktu z najszlachetniejszymi gatunkami ryb w surowym krajobrazie.', 'PZW Szczecin');

