VALUES (70231, 'Górska', 'Bystry nurt, rafy żwirowe', 12.0, 1.0, 'Żwir i kamienie', 'Naturalne bystrza', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 233: Żołędowo (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70232, 'Drawa - Żołędowo (Północne Zakola)', 'drawa-zoledowo-polnoc', 'RIVER', 53.4036873, 15.8311686, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Północny odcinek w Żołędowie oferuje wędkarzom dostęp do rzeki o bardzo zmiennym i głębokim korycie. Drawa tworzy tu spektakularne zakola, wymywając na zewnętrznych łukach jamy sięgające trzech metrów głębokości. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe z licznymi zatopionymi korzeniami drzew stanowiącymi bazę dla szczupaków. Spinningiści z sukcesami stosują tu metodę opadu, celując w dorodne okonie grupujące się przy dnie rzeki. Uciąg rzeki jest umiarkowany i stabilny, co ułatwia systematyczne nęcenie stad leszczy i jazi. To stanowisko jest idealne dla osób ceniących aktywne poszukiwanie ryb w ruchu wzdłuż malowniczej linii brzegowej.', 'PZW Szczecin');

