-- Spot 234: Poźrzadło Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70233, 'Drawa - Poźrzadło Wielkie (Leśna Cisza)', 'drawa-pozrzadlo-wielkie', 'RIVER', 53.3900076, 15.7896289, 'Zachodniopomorskie', 'Kalisz Pomorski', 'Drawa w Poźrzadle Wielkim płynie przez gęste kompleksy leśne, zachowując swój krystalicznie czysty i dziki charakter. Nurt rzeki jest tu dość żwawy, żłobiąc piaszczysto-żwirowe dno i tworząc liczne, natlenione bystrza. To wymarzone stanowisko dla łowców jazi oraz kleni, które doskonale reagują na małe woblery i smużaki. Podmyte korzenie starych olch przy brzegach skrywają dorodne okonie, które agresywnie atakują przepływający narybek. Uciąg rzeki wymaga stosowania dociążonych zestawów spinningowych oraz precyzyjnych rzutów pod nawisy nadbrzeżnych drzew. Ze względu na oddalenie od głównych szlaków, panuje tu wyjątkowa cisza i znikoma presja ze strony innych wędkarzy.', 'PZW Szczecin');

