-- Spot 235: Mielenko Drawskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70234, 'Drawa - Mielenko Drawskie (Meandry)', 'drawa-mielenko-drawskie', 'RIVER', 53.4999377, 15.8186842, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Odcinek w Mielenku Drawskim charakteryzuje się bardzo krętym korytem i dużą dynamiką przepływu wody. Drawa tworzy tu głębokie jamy na zewnętrznych łukach, które są naturalnym schronieniem dla sumów i dużych szczupaków. Dno jest mocno urozmaicone, piaszczysto-gliniaste, co sprzyja bytowaniu brzan walczących w głównym prądzie. Spinningiści znajdą tutaj doskonałe warunki do prowadzenia ciężkich jigów w głębokich rynnach środkowego nurtu. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga stosowania koszyków o masie powyżej czterdziestu gramów. To techniczne łowisko, które nagradza wędkarzy potrafiących precyzyjnie czytać zmiany w strukturze dna rzeki.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70234, 'Nizinna Średnia', 'Silnie meandrująca, rynny', 16.0, 2.2, 'Glina i piasek', 'Głębokie jamy', 'Szczupak, Sum, Brzana', 'Kraina leszcza', true);

-- Spot 236: Konotop (Drawski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70235, 'Drawa - Konotop (Poligonowa Równia)', 'drawa-konotop-poligon', 'RIVER', 53.4764619, 15.8476849, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'W rejonie Konotopu rzeka przepływa przez otwarte tereny poligonowe, tworząc szerokie i płytkie piaszczyste płanie. Woda jest tu wyjątkowo przejrzysta, co sprzyja aktywności jazi i kleni żerujących na piaszczystych przykosach. To doskonałe miejsce na technikę muchową oraz lekki spinning z wykorzystaniem miniaturowych błystek obrotowych. Nurt jest jednostajny i łagodny, co pozwala na bardzo naturalną prezentację przynęty na długich dystansach. Wędkarze powinni skupić się na cichym podchodzeniu do stanowiska, gdyż ryby na tak czystej wodzie są niezwykle płochliwe. Brak stałej zabudowy i surowy krajobraz sprawiają, że można tu poczuć prawdziwy klimat dzikiej rzeki.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70235, 'Nizinna Średnia', 'Szeroka, nurt łagodny', 22.0, 1.1, 'Piaszczyste', 'Piaszczyste przykosy', 'Jaź, Kleń, Jelce', 'Kraina leszcza', true);

-- Spot 237: Karwice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70236, 'Drawa - Karwice (Warkocze)', 'drawa-karwice-warkocze', 'RIVER', 53.4612103, 15.8869443, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Odcinek w Karwicach słynie z szybciej płynącej wody i twardego, piaszczysto-żwirowego podłoża koryta. Rzeka rozlewa się tu szerzej, tworząc natlenione warkocze, w których wieczorami widowiskowo polują bolenie. To idealne miejsce dla spinningistów stosujących smukłe woblery imitujące ukleje prowadzone z prądem wody. Dno jest czyste i twarde, co znacznie ogranicza liczbę zaczepów przy łowieniu na dłuższą odległość. Wędkarze spławikowi z sukcesami stosują tu metodę przepływanki, celując w dorodne płocie i wyrośnięte jelce. Stanowiska brzegowe są naturalne i zapewniają wędkarzowi dużą dozę prywatności podczas wielogodzinnych zasiadek.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70236, 'Nizinna Średnia', 'Nurt żywy, koryto szerokie', 20.0, 1.4, 'Piasek i żwir', 'Naturalne bystrza', 'Boleń, Płoć, Jelce', 'Kraina leszcza', true);

-- Spot 238: Ogrodno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70237, 'Drawa - Ogrodno (Źródliskowa Pętla)', 'drawa-ogrodno-petla', 'RIVER', 53.7211046, 16.1494505, 'Zachodniopomorskie', 'Połczyn-Zdrój', 'Drawa w rejonie Ogrodna to niewielka rzeka o krystalicznej wodzie, płynąca przez tereny o charakterze źródliskowym. Koryto jest tu wąskie i usiane licznymi zwalonymi drzewami, co tworzy idealne warunki dla pstrąga potokowego. Woda jest bardzo zimna nawet latem, co wymusza na rybach dużą aktywność w poszukiwaniu pokarmu naturalnego. Spinningiści powinni postawić na mikro-przynęty, które najlepiej imitują drobne bezkręgowce występujące w tym rejonie. Brzegi są gęsto porośnięte wikliną, co zapewnia naturalny kamuflaż wędkarzowi i cień dla ryb w słoneczne dni. To wymagające technicznie stanowisko, które potrafi nagrodzić wytrwałych pasjonatów finezyjnego łowienia w ruchu.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70237, 'Podgórska', 'Strumień, nurt rwany', 6.0, 0.7, 'Żwir i piasek', 'Zwalone kłody', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', false);

-- Spot 239: Czarnkowie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70238, 'Drawa - Czarnkowie (Szyja Jeziorna)', 'drawa-czarnkowie-szyja', 'RIVER', 53.6946099, 16.1582559, 'Zachodniopomorskie', 'Złocieniec', 'Odcinek w Czarnkowie stanowi malowniczy łącznik między jeziorami, gdzie Drawa nabiera spokojniejszego, nizinnego charakteru. Woda płynie tu leniwie, a dno jest piaszczysto-muliste z bogatą roślinnością wynurzoną przy brzegach. To wymarzone miejsce dla łowców wzdręg i płoci, które grupują się stadnie w nasłonecznionych zatoczkach. Wędkarze gruntowi powinni szukać ryb w głębszych patiach koryta, nęcąc systematycznie ziarnami kukurydzy i pęczakiem. Uciąg rzeki jest na tyle słaby, że pozwala na idealną prezentację przynęty na bardzo delikatnych zestawach spławikowych. Miejsce to zapewnia absolutny spokój i pozwala na pełne obcowanie z przyrodą Pojezierza Drawskiego.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70238, 'Nizinna Mała', 'Spokojna rzeka pojezierna', 10.0, 1.6, 'Piasek i muł', 'Pasy trzcin', 'Wzdręga, Płoć, Leszcz', 'Kraina leszcza', false);

-- Spot 240: Kluczewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70239, 'Drawa - Kluczewo (Piaszczyste Płanie)', 'drawa-kluczewo-planie', 'RIVER', 53.676208, 16.1925243, 'Zachodniopomorskie', 'Złocieniec', 'Drawa w Kluczewie to odcinek słynący z czystej wody i wyrównanego, piaszczystego dna koryta. Rzeka płynie tu szerzej niż w górnym biegu, tworząc rozległe piaszczyste łachy idealne do łowienia białorybu. To doskonałe miejsce dla miłośników lekkiego spinningu polujących na klenie i jazie zbierające owady z powierzchni. Uciąg jest umiarkowany, co pozwala na komfortowe łowienie metodą odległościową na dużych dystansach. W rynnach pod drugim brzegem często meldują się ładne okonie, które doskonale reagują na małe błystki obrotowe. Bliskość bazy turystycznej sprawia, że dostęp do wody jest tu bardzo dobry, a stanowiska są stabilne.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70239, 'Nizinna Mała', 'Spokojna rzeka nizinna', 12.0, 1.3, 'Piaszczyste', 'Lokalne rynny', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 241: Kluczewo (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70240, 'Drawa - Kluczewo Południe (Jelcowa Równia)', 'drawa-kluczewo-poludnie', 'RIVER', 53.649178, 16.1957673, 'Zachodniopomorskie', 'Złocieniec', 'Drawa w południowej części Kluczewa to odcinek o niezwykle czystej wodzie i urozmaiconym, piaszczysto-żwirowym dnie. Rzeka płynie tu dość wartko, tworząc naturalne warkocze za kamieniami, które są idealnym stanowiskiem dla jelców. Wędkarze spinningowi powinni skupić się na obławianiu rynien pod nawisami drzew, gdzie często czatują dorodne okonie. Nurt jest jednostajny i natleniony, co sprzyja aktywności ryb łososiowatych migrujących w górę biegu rzeki. Dzięki niskiej roślinności brzegowej dostęp do lustra wody jest tu stosunkowo prosty, choć wymaga zachowania pełnej dyskrecji. To techniczne łowisko, które najlepiej sprawdza się przy zastosowaniu lekkich metod spławikowych oraz mikro-spinningu.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70240, 'Nizinna Mała', 'Nurt żywy, koryto piaszczyste', 11.0, 1.2, 'Piasek i żwir', 'Naturalne warkocze', 'Jelec, Okoń, Płoć', 'Kraina pstrąga', false);

-- Spot 242: gmina Kalisz Pomorski (Odcinek Leśny 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70241, 'Drawa - Kalisz Pomorski (Dzika Głusza)', 'drawa-kalisz-pomorski-glusza', 'RIVER', 53.3771618, 15.7497428, 'Zachodniopomorskie', 'Kalisz Pomorski', 'Ten leśny odcinek Drawy w gminie Kalisz Pomorski charakteryzuje się dzikim korytem i dużą ilością zwalonych pni drzew. Rzeka posiada tu wyraźnie zaznaczoną rynnę główną o twardym, piaszczystym podłożu, sprzyjającym bytowaniu dużych jazi. Spinningiści znajdą tutaj doskonałe warunki do prowadzenia gum w opadzie, celując w szczupaki stacjonujące w zakolach. Uciąg jest zdecydowany i stabilny, co wymaga od wędkarza gruntowego stosowania koszyków o masie co najmniej 40 gramów. Brzegi są wysokie i porośnięte gęstą wikliną, co zapewnia naturalny kamuflaż, ale utrudnia podebranie ryby bez długiego gryfu. Miejsce to gwarantuje całkowitą izolację od zgiełku cywilizacji i szansę na kontakt z niewypłoszonymi, rekordowymi okazami ryb.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70241, 'Nizinna Średnia', 'Meandrująca rzeka leśna', 16.0, 1.8, 'Piasek i korzenie', 'Zwalone kłody', 'Jaz, Szczupak, Okoń', 'Kraina leszcza', false);

-- Spot 243: gmina Kalisz Pomorski (Odcinek Leśny 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70242, 'Drawa - Kalisz Pomorski (Rynna Boleniowa)', 'drawa-kalisz-pomorski-rynna', 'RIVER', 53.3516222, 15.7345779, 'Zachodniopomorskie', 'Kalisz Pomorski', 'Drawa w tym rejonie mocno meandruje, żłobiąc głębokie na ponad dwa metry jamy na zewnętrznych łukach swojego koryta. Dno jest mocno urozmaicone piaszczystymi przykosami, które są bankowymi miejscami na spotkanie z żerującym boleniem. Wędkarze stacjonarni z sukcesami stosują tu metodę ciężkiego feedera, nęcąc stadne leszcze grubszą frakcją zanęty spożywczej. Uciąg rzeki potrafi być zmienny, dlatego warto na bieżąco dostosowywać obciążenie zestawu do aktualnego przepływu wody. Liczne zatory z gałęzi tworzą naturalne ostoje dla ryb, ale wymagają od wędkarza dużej precyzji w podawaniu przynęty. To łowisko o ogromnym potencjale jesiennym, gdy drapieżniki agresywnie żerują przed zimą na drobicy gromadzącej się w rynnach.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70242, 'Nizinna Średnia', 'Silne meandry, przykosy', 18.0, 2.2, 'Piasek i glina', 'Przykosy piaszczyste', 'Boleń, Leszcz, Szczupak', 'Kraina leszcza', false);

-- DREWCA

-- Spot 244: Golub-Dobrzyń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70243, 'Drwęca - Golub-Dobrzyń (Pod Zamkiem)', 'drweca-golub-dobrzyn-zamek', 'RIVER', 53.1046877, 19.0312685, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'Drwęca w Golubiu-Dobrzyniu to techniczne łowisko o urozmaiconym dnie, z głębokimi rynnami wymytymi przy filarach mostu. Koryto jest tu dość szerokie, a nurt niesie natlenioną wodę sprzyjającą aktywności dużych kleni oraz boleni. Wędkarze gruntowi powinni szukać ryb w głębszych dołach, stosując ciężkie koszyki o masie powyżej 60 gramów dla stabilizacji zestawu. Piaszczysto-żwirowe dno z lokalnymi gliniastymi burtami to idealne stanowisko dla brzan walczących w głównym prądzie. Spinningiści z sukcesami obławiają tutejsze warkocze, stosując smukłe woblery imitujące ukleje prowadzone z prądem. Dostęp do wody w centrum miasta jest bardzo wygodny, co pozwala na komfortowe rozstawienie profesjonalnego stanowiska.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70243, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 25.0, 2.0, 'Piasek i żwir', 'Filary mostu, opaski', 'Kleń, Brzana, Boleń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 245: Paliwodzizna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70244, 'Drwęca - Paliwodzizna (Łąkowe Meandry)', 'drweca-paliwodzizna-meandry', 'RIVER', 53.0866097, 18.9977529, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'Odcinek w Paliwodziźnie charakteryzuje się naturalnym, mocno meandrującym korytem płynącym wśród rozległych nadbużańskich łąk. Rzeka żłobi tu głębokie jamy na zewnętrznych łukach, które stanowią bezpieczne schronienie dla wyrośniętych szczupaków i okoni. Dno jest przeważnie piaszczyste, z lokalnymi naniesieniami mułu w spokojniejszych zatoczkach, gdzie chętnie żerują leszcze. To wymarzone miejsce dla miłośników metody bolońskiej, pozwalającej na długie i precyzyjne spływy zestawu wzdłuż trzcinowisk. Uciąg wody jest stały i umiarkowany, co sprzyja systematycznemu nęceniu stad jazi oraz płoci. Cisza i brak bliskiej zabudowy sprawiają, że ryby są tu mniej płochliwe, ale wymagają od wędkarza pełnego maskowania na brzegu.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70244, 'Nizinna Średnia', 'Naturalne, meandrujące', 20.0, 1.8, 'Piaszczyste', 'Podmyte burty', 'Szczupak, Leszcz, Jaź', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 246: Elgiszewo (Punkt 1 - Bystrza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70245, 'Drwęca - Elgiszewo (Żwirowe Rafy)', 'drweca-elgiszewo-rafy', 'RIVER', 53.0607475, 18.9259704, 'Kujawsko-Pomorskie', 'Ciechocin', 'Elgiszewo to legendarne łowisko dla muszkarzy i spinningistów, słynące z bystrych odcinków o charakterze podgórskim. Dno jest tu twarde, kamienisto-żwirowe, co tworzy doskonałe warunki dla lipieni oraz migrujących troci wędrownych. Woda jest wyjątkowo dobrze natleniona, a liczne bystrza i warkocze za głazami to bankowe miejsca na klenia. Spinningiści z sukcesami stosują tu micro-jigi oraz małe błystki obrotowe, obławiając cienie przybrzeżnych nawisów. Uciąg rzeki w tym miejscu jest silny, co wymaga od wędkarza brodzącego pewnego kroku i profesjonalnego obuwia. To techniczne łowisko nagradza precyzję rzutu, oferując szansę na kontakt z najszlachetniejszymi gatunkami ryb w Polsce.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70245, 'Podgórska', 'Bystry nurt, koryto żwirowe', 18.0, 1.2, 'Żwir i kamienie', 'Głazy narzutowe, bystrza', 'Lipień, Troć wędrowna, Kleń', 'Kraina pstrąga', 'Rezerwat przyrody Drwęca', false);

-- Spot 247: Elgiszewo (Punkt 2 - Głęboka Rynna)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70246, 'Drwęca - Elgiszewo (Głęboka Płania)', 'drweca-elgiszewo-plania', 'RIVER', 53.0654087, 18.8816623, 'Kujawsko-Pomorskie', 'Ciechocin', 'Nieco niżej w Elgiszewie Drwęca rozlewa się szerzej, nabierając nizinnego charakteru z wyraźnie zaznaczoną rynną główną. Głębokość stabilizuje się tu na poziomie dwóch metrów, z piaszczystym dnem idealnym dla stadnych leszczy. Wędkarze stacjonarni z sukcesami stosują metodę feedera, nęcąc ryby grubszą frakcją zanęty z dodatkiem czerwonych robaków. Przy brzegach znajdują się liczne zatopione korzenie starych wierzb, które są ostoją dla dorodnych okoni. Nurt rzeki pozwala na komfortowe operowanie zestawem spławikowym na długim dystansie, co sprzyja połowom jazi. Dzięki krystalicznej wodzie i statusowi rezerwatu, ryby są tu wyjątkowo waleczne i zdrowe, co gwarantuje udany hol.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70246, 'Nizinna Średnia', 'Szeroka, nurt umiarkowany', 22.0, 2.0, 'Piaszczyste', 'Zatopione korzenie', 'Leszcz, Jaź, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 248: Józefowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70247, 'Drwęca - Józefowo (Leśne Zatorowisko)', 'drweca-jozefowo-leśne', 'RIVER', 53.069773, 18.8372975, 'Kujawsko-Pomorskie', 'Lubicz', 'Drwęca w Józefowie przepływa przez zwarte kompleksy leśne, co skutkuje dużą ilością zwalonych pni drzew w korycie. To wymarzone miejsce dla spinningistów szukających technicznych wyzwań przy obławianiu podwodnych karczowisk. Podmyte burty i piaszczyste przykosy tworzą idealne stanowiska dla szczupaków czatujących na przepływającą drobnicę. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe, z nielicznymi rynnami wymytymi przez silniejszy nurt na zakrętach. Wędkarze spławikowi powinni skupić się na cichym podchodzeniu do stanowiska, gdyż przejrzysta woda czyni ryby bardzo płochliwymi. Wieczorne wyprawy z martwą rybką w to miejsce mogą owocować braniem medalowego sandacza lub węgorza.', 'PZW Toruń');

