-- Spot 249: Młyniec Pierwszy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70248, 'Drwęca - Młyniec (Przy Moście)', 'drweca-mlyniec-most', 'RIVER', 53.0560678, 18.7975049, 'Kujawsko-Pomorskie', 'Lubicz', 'Odcinek w Młyńcu Pierwszym charakteryzuje się wyrównanym nurtem i szerokim korytem z dogodnym dostępem do brzegów. Dno jest twarde i piaszczyste, co czyni to miejsce idealnym dla wędkarzy preferujących technikę lekkiego gruntu. W rynnach przy filarach starego mostu często stacjonują duże klenie oraz jazie, które świetnie reagują na nęcenie pieczywem. Spinningiści cenią ten fragment za obecność boleni, które widowiskowo polują na piaszczystych przykosach środkiem rzeki. Uciąg wody jest umiarkowany i przewidywalny, co pozwala na bardzo naturalną prezentację przynęty na delikatnych żyłkach. Bliskość aglomeracji toruńskiej sprawia, że jest to popularne miejsce na szybki wypad po pracy, oferujące stałe brania białorybu.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70248, 'Nizinna Średnia', 'Uregulowane, nurt stabilny', 24.0, 1.6, 'Piaszczyste', 'Most, piaszczyste łachy', 'Kleń, Jaź, Boleń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 250: Lubicz Dolny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70249, 'Drwęca - Lubicz Dolny (Przełom)', 'drweca-lubicz-dolny', 'RIVER', 53.034134, 18.7695468, 'Kujawsko-Pomorskie', 'Toruń', 'Lubicz Dolny to odcinek słynący z technicznego łowienia troci i łososi w okresie ich jesiennych wędrówek tarłowych. Rzeka płynie tu żwawym nurtem po twardym, kamienisto-żwirowym dnie, tworząc liczne bystrza i natlenione warkocze. To strategiczne miejsce dla spinningistów polujących na klenie czatujące w cieniu filarów mostowych oraz starych budowli hydrotechnicznych. Uciąg jest silny, co wymaga stosowania dociążonych przynęt dobrze trzymających się w głębokim nurcie. Stanowiska brzegowe są nieliczne i wymagają precyzyjnego rzutu pod nawisy przybrzeżnych drzew, gdzie dno gwałtownie opada. Wieczorne wyprawy z muchówką mogą owocować tu emocjonującym holem walecznego lipienia lub grubego pstrąga potokowego.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70249, 'Podgórska', 'Bystry nurt, koryto kamieniste', 22.0, 1.4, 'Kamień i żwir', 'Jazy, progi, mosty', 'Troć wędrowna, Kleń, Lipień', 'Kraina pstrąga', 'Rezerwat przyrody Drwęca', false);

-- Spot 251: Złotoria (Ujście do Wisły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70250, 'Drwęca - Złotoria (Węzeł Wodny)', 'drweca-zlotoria-ujscie', 'RIVER', 52.9953045, 18.719117, 'Kujawsko-Pomorskie', 'Toruń', 'Ujście Drwęcy do Wisły w Złotorii to legendarne łowisko, gdzie mieszające się nurty obu rzek tworzą rybne rozlewisko. Woda płynie tu leniwie, a dno jest zróżnicowane — od piaszczystych blatów po muliste rynny sięgające trzech metrów. To wymarzone miejsce dla łowców rekordowych leszczy i krąpi wchodzących w koryto Drwęcy z nurtu głównego Wisły. Spinningiści cenią ten odcinek za doskonałe warunki do prowadzenia gum w opadzie w poszukiwaniu sandaczy i sumów. Wzdłuż brzegów znajdują się liczne kępy grążeli, w których jesienią stacjonują potężne szczupaki polujące na drobnicę. Ze względu na strategiczne położenie, presja wędkarska bywa tu duża, szczególnie w okresach wzmożonej migracji ryb spokojnego żeru.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70250, 'Nizinna Wielka', 'Szerokie rozlewisko ujściowe', 35.0, 3.0, 'Piasek i muł', 'Połączenie nurtów', 'Leszcz, Sandacz, Szczupak', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 252: Nowy Dwór
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70251, 'Drwęca - Nowy Dwór (Leśne Meandry)', 'drweca-nowy-dwor', 'RIVER', 53.2800781, 19.5020509, 'Kujawsko-Pomorskie', 'Brodnica', 'Odcinek w Nowym Dworze to klasyczny przykład naturalnej, meandrującej rzeki nizinnej o krystalicznie czystej wodzie. Drwęca żłobi tu głębokie jamy na zewnętrznych łukach koryta, które są domem dla wyrośniętych kleni i jazi. Dno jest przeważnie piaszczyste, z lokalnymi żwirowymi łachami sprzyjającymi bytowaniu brzan i dużych stad certy. Wędkarze stacjonarni z sukcesami stosują tu metodę lekkiego feedera z koszykami o masie trzydziestu gramów. Nurt rzeki pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach spławikowych typu bolonka lub przepływanka. Cisza panująca wzdłuż leśnego brzegu zapewnia doskonały relaks i dużą szansę na spotkanie z niewypłoszonym, medalowym okazem.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70251, 'Nizinna Średnia', 'Naturalne, meandrujące', 18.0, 1.8, 'Piasek i żwir', 'Podmyte burty', 'Jaź, Kleń, Brzana', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 253: Karbowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70252, 'Drwęca - Karbowo (Przykosy)', 'drweca-karbowo', 'RIVER', 53.2732893, 19.4583702, 'Kujawsko-Pomorskie', 'Brodnica', 'Karbowo oferuje wędkarzom dostęp do rzeki o urozmaiconym ukształtowaniu koryta z licznymi piaszczystymi przykosami na środku. Rzeka płynie tu szerzej, a jej nurt jest umiarkowany i przewidywalny, co sprzyja systematycznemu nęceniu stad leszczy. Podmyte brzegi porośnięte gęstą wikliną skrywają wyrośnięte okonie, które agresywnie reagują na małe obrotówki i twistery. Spinningista znajdzie tutaj mnóstwo technicznych miejsc do prowadzenia woblerów w poszukiwaniu boleni polujących pod samym brzegiem. Dno pozostaje czyste i twarde, co znacznie ogranicza liczbę zaczepów przy łowieniu z rzutu na dłuższą odległość. To łowisko o relatywnie niskiej presji, gwarantujące spokój podczas aktywnego poszukiwania rzecznych pasiastych drapieżników.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70252, 'Nizinna Średnia', 'Szeroka, nurt umiarkowany', 22.0, 1.6, 'Piaszczyste', 'Piaszczyste przykosy', 'Leszcz, Boleń, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 254: Brodnica (Odcinek Miejski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70253, 'Drwęca - Brodnica (Centrum)', 'drweca-brodnica-centrum', 'RIVER', 53.2565743, 19.4229458, 'Kujawsko-Pomorskie', 'Brodnica', 'Miejski odcinek w Brodnicy to techniczne łowisko z kamiennymi opaskami i głębokimi rynnami pod mostami drogowymi. Dno jest tu twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu sprzyjającymi żerowaniu jazi, kleni i jelców. Czysta woda płynąca przez centrum miasta przyciąga liczne stada płoci, które doskonale reagują na metodę klasycznej przepływanki. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy betonowych murkach i faszynowych umocnieniach. Uciąg rzeki jest umiarkowany, co pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon wędkarski. Wieczorne wyprawy z lekkim spinningiem mogą zakończyć się tu emocjonującym holem sandacza czatującego w warkoczach nurtu.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70253, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 25.0, 2.2, 'Piasek i kamień', 'Filary mostów, opaski', 'Płoć, Jaź, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', false);

-- Spot 255: Brodnica Południe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70254, 'Drwęca - Brodnica Południe', 'drweca-brodnica-poludnie-dzika', 'RIVER', 53.2419076, 19.3847947, 'Kujawsko-Pomorskie', 'Brodnica', 'Drwęca poniżej Brodnicy to odcinek o dzikim charakterze, płynący przez malownicze tereny leśno-łąkowe. Dno jest tu w większości twarde i piaszczyste, z wyraźnymi rynnami pod nawisami starej wikliny. Uciąg wody jest stały i umiarkowany, co sprzyja bytowaniu dorodnych kleni oraz jazi zbierających owady z powierzchni. Wędkarze spinningowi znajdą tu liczne zwalone pnie drzew, które są bankową kryjówką dla szczupaków. Metoda lekkiego feedera z koszykami o masie trzydziestu gramów sprawdza się tu doskonale przy polowaniu na stadne płocie. Ze względu na status rezerwatu, należy zachować szczególną dbałość o naturalne otoczenie i przestrzegać rygorystycznych zasad ochrony przyrody.', 'PZW Toruń');

