-- Spot 256: Kominy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70255, 'Drwęca - Kominy (Zakole)', 'drweca-kominy-zakole', 'RIVER', 53.227346, 19.3465192, 'Kujawsko-Pomorskie', 'Brodnica', 'Odcinek w miejscowości Kominy oferuje wędkarzom dostęp do rzeki o bardzo krętym korycie i zmiennej dynamice nurtu. Drwęca żłobi tu głębokie jamy na zewnętrznych łukach, w których często stacjonują wyrośnięte okonie. Dno piaszczysto-żwirowe sprzyja aktywności brzan, które potężnie walczą w głównym nurcie rzeki. Spinningiści z sukcesami obławiają piaszczyste przykosy, stosując smukłe woblery imitujące ukleje prowadzone z prądem. Roślinność zanurzona tworzy tu gęste dywany, w których cieniu chętnie ustawiają się szczupaki czekające na zdobycz. To techniczne łowisko nagradza precyzję rzutu i umiejętność cichego podchodu do stanowiska przy zachowaniu wysokiej burty.', 'PZW Toruń');

