-- Spot 257: Łapinóż-Rumunki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70256, 'Drwęca - Łapinóż-Rumunki', 'drweca-lapinoz-rumunki', 'RIVER', 53.2139047, 19.3072149, 'Kujawsko-Pomorskie', 'Brodnica', 'W rejonie Łapinóż-Rumunki Drwęca płynie w głębokim wcięciu terenu, co tworzy specyficzny mikroklimat i osłonę przed wiatrem. Nurt jest tu rwanym i dość szybki, co sprzyja natlenieniu wody nawet w najgorętsze dni lata. Dno jest twarde, piaszczysto-gliniaste, z licznymi "karczami" stanowiącymi wyzwanie dla spinningistów. Wędkarze gruntowi z sukcesami łowią tu dorodne certy oraz jelce, wykorzystując metodę lekkiej przepływanki. Podmyte korzenie starych dębów przy brzegach to pewne miejsca na spotkanie z dużym kleniem lub boleniem. Miejsce to zapewnia absolutny spokój, ponieważ dostęp do lustra wody wymaga pokonania dość stromego i zalesionego nabrzeża.', 'PZW Toruń');

