VALUES (70256, 'Nizinna Średnia', 'Nurt żywy, wysokie brzegi', 18.0, 1.4, 'Glina i piasek', 'Podmyte korzenie', 'Certa, Kleń, Boleń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 258: Słoszewy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70257, 'Drwęca - Słoszewy (Głęboka Rynna)', 'drweca-sloszewy-rynna', 'RIVER', 53.2029011, 19.2655669, 'Kujawsko-Pomorskie', 'Brodnica', 'Odcinek w Słoszewach charakteryzuje się szerokim korytem i występowaniem bardzo głębokich rynien w środkowym nurcie rzeki. To wymarzone miejsce dla łowców rekordowych leszczy, które grupują się tu na piaszczysto-mulistych blatach. Uciąg wody jest stabilny, co ułatwia systematyczne nęcenie pola łowiska i utrzymanie w nim ryb spokojnego żeru. Spinningiści z sukcesami obławiają tutejsze spowolnienia nurtu, stosując gumy na ciężkich główkach w poszukiwaniu sandaczy. Brzegi są naturalne i częściowo zarośnięte trzciną, co stwarza doskonałe warunki dla szczupaków polujących na ukleje. To jedno z najbardziej rybnych miejsc w tej części rzeki, cieszące się dużą renomą wśród lokalnych wędkarzy.', 'PZW Toruń');

