-- Spot 259: Pusta Dąbrówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70258, 'Drwęca - Pusta Dąbrówka (Zatory)', 'drweca-pusta-dabrowka-zatory', 'RIVER', 53.1835566, 19.2341269, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'Drwęca w Pustej Dąbrówce przedziera się przez zwężenie terenu, co powoduje wyraźne przyspieszenie przepływu wody. Dno jest tu mocno usiane kamieniami oraz zwalonymi drzewami, tworząc naturalne stopnie i bystrza. Jest to doskonała lokalizacja dla łowców brzan oraz troci wędrownych, które znajdują tu doskonałe warunki tlenowe. Spinningowanie wymaga tu mistrzowskiej precyzji ze względu na wszechobecne przeszkody i dużą prędkość nurtu. Wieczorne wyprawy z suchą muchą mogą owocować widowiskowymi braniami jazi i kleni zbierających pokarm z powierzchni. To surowy odcinek rzeki, który wymaga od wędkarza pełnego skupienia i stosowania wytrzymałych zestawów o podwyższonej odporności na przetarcia.', 'PZW Toruń');

