-- Spot 260: Tomkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70259, 'Drwęca - Tomkowo (Łąkowe Zakola)', 'drweca-tomkowo-meandry', 'RIVER', 53.1619357, 19.2066528, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'Odcinek w Tomkowie charakteryzuje się malowniczym, łąkowym krajobrazem i stosunkowo łagodnym uciągiem wody. Rzeka posiada tu wyrównaną głębokość z nielicznymi piaszczystymi przykosami, na których żerują stadne jelce. To idealne miejsce na letni wypoczynek z wędką spławikową lub lekkim feederem nastawionym na płocie. Dno jest czyste i piaszczyste, co minimalizuje ryzyko utraty zestawu i pozwala na komfortowe wędkowanie początkującym. Spinningiści mogą liczyć na regularne brania okoni patrolujących pasy roślinności zanurzonej wzdłuż obu brzegów. Dzięki wygodnemu dostępowi przez łąki, jest to jedno z chętniej wybieranych miejsc na całodniowe zasiadki rodzinne w otoczeniu natury.', 'PZW Toruń');

