-- Spot 261: Mokry Las
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70260, 'Drwęca - Mokry Las (Leśne Banie)', 'drweca-mokry-las', 'RIVER', 53.1502018, 19.1660733, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'Odcinek w Mokrym Lesie charakteryzuje się bardzo wysokimi burtami i głębokimi baniami na zakrętach koryta. Rzeka płynie tu w gęstym otoczeniu drzew, co skutkuje dużą ilością zwalonych pni stanowiących idealne kryjówki dla sumów. Dno jest tu piaszczysto-gliniaste, z wyraźnymi uskokami rzeźbiącymi ciekawe stanowiska dla spinningistów polujących na szczupaki. Uciąg wody jest stały i zdecydowany, co sprzyja natlenieniu rzeki nawet podczas letnich upałów. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, nęcąc ryby w rynnach głównego nurtu. To wyjątkowo dzikie miejsce, które nagradza wędkarzy potrafiących zachować absolutną ciszę przy podejściu do stanowiska.', 'PZW Toruń');

