-- Spot 262: gmina Golub-Dobrzyń (Równia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70261, 'Drwęca - Golub-Dobrzyń (Równia Łąkowa)', 'drweca-golub-dobrzyn-rownia', 'RIVER', 53.1341935, 19.1297396, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'Odcinek w gminie Golub-Dobrzyń oferuje szerokie i stosunkowo płytkie piaszczyste płanie idealne do łowienia białorybu. Rzeka płynie tu spokojnie wśród rozległych łąk, co ułatwia rzuty dłuższą odległościówką lub lekkim feederem. Dno jest w przeważającej części piaszczyste, z lokalnymi żwirowymi łachami, na których chętnie żerują stadne klenie. To doskonałe miejsce dla spinningistów polujących na bolenie, które widowiskowo pokazują się na powierzchni podczas bicia uklei. Uciąg wody jest umiarkowany, co pozwala na bardzo naturalną prezentację przynęty na delikatnym zestawie spławikowym. Brak wysokiej roślinności brzegowej sprawia, że jest to jedno z najwygodniejszych stanowisk w tym rejonie rzeki.', 'PZW Toruń');

