-- Spot 263: Białkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70262, 'Drwęca - Białkowo (Podmyte Korzenie)', 'drweca-bialkowo', 'RIVER', 53.1189404, 19.0916353, 'Kujawsko-Pomorskie', 'Golub-Dobrzyń', 'W Białkowie Drwęca mocno meandruje, żłobiąc głębokie rynny pod brzegowymi olchami i starymi dębami. To klasyczne łowisko szczupakowe, gdzie drapieżniki czatują w cieniu podwodnych korzeni i zwalonych gałęzi. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe, z dużą ilością naturalnych przeszkód utrudniających łowienie z gruntu. Spinningiści z sukcesami obławiają tutejsze warkocze, stosując gumy na lekkich główkach prowadzone w pobliżu zatopionych kłód. Uciąg rzeki jest tu zdecydowany, co wymusza stosowanie dociążonych zestawów, aby utrzymać przynętę w strefie żerowania ryb. To stanowisko cenione za dużą populację wyrośniętych okoni, które doskonale reagują na agresywnie prowadzone twistery.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70262, 'Nizinna Średnia', 'Meandrująca, nurt silny', 22.0, 1.8, 'Piasek i żwir', 'Podmyte korzenie', 'Szczupak, Okoń, Kleń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 264: Wielki Głęboczek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70263, 'Drwęca - Wielki Głęboczek (Przełom)', 'drweca-wielki-gleboczek', 'RIVER', 53.3183493, 19.5183222, 'Kujawsko-Pomorskie', 'Brodnica', 'Odcinek w Wielkim Głęboczku to jeden z najczystszych fragmentów rzeki, charakteryzujący się bardzo przejrzystą wodą. Drwęca płynie tu żywym nurtem po twardym, żwirowym dnie, co tworzy idealne warunki dla lipieni oraz pstrągów. Warkocze powstające za naturalnymi kamiennymi przeszkodami to bankowe miejsca na spotkanie z dorodnym kleniem. Wędkarze muchowi znajdą tu doskonałe warunki do prowadzenia suchej muchy na otwartych partiach koryta rzeki. Uciąg jest silny i jednostajny, co wymaga od wędkarza brodzącego dużego skupienia i stabilnego obuwia terenowego. Ze względu na krystaliczną wodę, ryby są tu niezwykle płochliwe i wymagają stosowania najcieńszych przyponów fluorocarbonowych.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70263, 'Podgórska', 'Bystry nurt, koryto żwirowe', 15.0, 1.1, 'Żwir i piasek', 'Głazy narzutowe', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', 'Rezerwat przyrody Drwęca', false);

-- Spot 265: Świecie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70264, 'Drwęca - Świecie (Zatory Leśne)', 'drweca-swiecie-zatory', 'RIVER', 53.29528, 19.54335, 'Kujawsko-Pomorskie', 'Brodnica', 'W rejonie miejscowości Świecie rzeka przedziera się przez malownicze lasy, tworząc liczne naturalne zatory. Koryto rzeki jest tu usiane zwalonymi drzewami, co sprzyja bytowaniu rekordowych szczupaków i sumów. Dno jest zróżnicowane, piaszczysto-gliniaste, z głębokimi rynnami wymytymi na zewnętrznych łukach koryta rzeki. Spinningiści z sukcesami obławiają tutejsze karczowiska, stosując metodę opadu z wykorzystaniem ciężkich, gumowych przynęt. Uciąg wody jest stały i umiarkowany, co ułatwia systematyczne nęcenie stad leszczy żerujących przy dnie. Miejsce to zapewnia absolutną ciszę i kontakt z surową, nienaruszoną przyrodą Pojezierza Brodnickiego.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70264, 'Nizinna Średnia', 'Leśna, liczne zatory', 18.0, 2.5, 'Piasek i glina', 'Zwalone kłody', 'Szczupak, Sum, Leszcz', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 266: Kąciki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70265, 'Drwęca - Kąciki (Spokojna Płania)', 'drweca-kaciki-plania', 'RIVER', 53.3679307, 19.5229819, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Odcinek w Kącikach to spokojny fragment Drwęcy z szerokim korytem i jednostajnym przepływem wody. Rzeka posiada tu wyrównaną głębokość z nielicznymi piaszczystymi przykosami, na których żerują stadne ukleje i płocie. To idealne miejsce na letni wypoczynek z lekkim feederem lub techniką spławikową nastawioną na białoryb. Dno jest czyste i piaszczyste, co minimalizuje ryzyko zerwania zestawu na podwodnych przeszkodach terenowych. Spinningiści mogą liczyć na regularne brania okoni patrolujących przybrzeżne pasy roślinności zanurzonej i trzcinowisk. Dzięki wygodnemu dostępowi do wody, jest to popularne miejsce na całodniowe zasiadki rodzinne w otoczeniu natury.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70265, 'Nizinna Średnia', 'Szerokie płanie, nurt łagodny', 22.0, 1.5, 'Piaszczyste', 'Trzcinowiska', 'Płoć, Leszcz, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 267: Nowe Miasto Lubawskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70266, 'Drwęca - Nowe Miasto Lubawskie (Mosty)', 'drweca-nml-miejski', 'RIVER', 53.42684, 19.59643, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Miejski odcinek w Nowym Mieście Lubawskim to techniczne łowisko z kamiennymi opaskami i głębokimi rynnami pod mostami. Dno jest tu twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu sprzyjającymi żerowaniu walecznych jazi oraz kleni. Czysta woda płynąca przez centrum miasta przyciąga liczne stada płoci, które doskonale reagują na metodę przepływanki. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy betonowych murkach oporowych. Uciąg rzeki jest umiarkowany, co pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon wędkarski. Wieczorne wyprawy z lekkim spinningiem mogą zakończyć się tu emocjonującym holem sandacza lub pstrąga.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70266, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 20.0, 1.8, 'Piasek i kamień', 'Filary mostów, opaski', 'Płoć, Jaź, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', false);

-- Spot 268: Smolniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70267, 'Drwęca - Smolniki (Piaszczyste Przykosy)', 'drweca-smolniki', 'RIVER', 53.517455, 19.649385, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Drwęca w Smolnikach to odcinek o niezwykle czystej wodzie i urozmaiconym, piaszczysto-żwirowym dnie koryta. Rzeka płynie tu dość wartko, tworząc naturalne przykosy na środku nurtu, które są idealnym stanowiskiem dla boleni. Wędkarze spinningowi powinni skupić się na obławianiu rynien pod nawisami drzew, gdzie często czatują dorodne okonie. Nurt jest jednostajny i doskonale natleniony, co sprzyja aktywności ryb łososiowatych migrujących w górę biegu rzeki. Dzięki niskiej roślinności brzegowej dostęp do lustra wody jest tu stosunkowo prosty, choć wymaga zachowania pełnej dyskrecji. To techniczne łowisko, które najlepiej sprawdza się przy zastosowaniu lekkich metod spławikowych oraz mikro-spinningu.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70267, 'Nizinna Średnia', 'Nurt żywy, koryto piaszczyste', 18.0, 1.4, 'Piasek i żwir', 'Piaszczyste przykosy', 'Boleń, Jaź, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 269: Pustki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70268, 'Drwęca - Pustki (Leśny Zakręt)', 'drweca-pustki', 'RIVER', 53.4975738, 19.6184388, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Odcinek w miejscowości Pustki charakteryzuje się dzikim korytem z dużą ilością zwalonych pni drzew w wodzie. Drwęca mocno tu meandruje, wymywając głębokie na ponad dwa metry jamy pod podmytymi burtami leśnymi. To wymarzone stanowisko dla spinningistów polujących na szczupaki oraz wyrośnięte okonie czające się w podwodnych karczowiskach. Dno piaszczysto-żwirowe sprzyja aktywności jazi, które chętnie żerują na granicy nurtu i spokojniejszych zastoisk rzecznych. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza precyzyjnego prowadzenia przynęty blisko dna. Cisza i brak bliskiej zabudowy sprawiają, że można tu liczyć na kontakt z dziką rybą w otoczeniu leśnej głuszy.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
