-- Spot 270: Chrośle
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70269, 'Drwęca - Chrośle (Głęboka Rynna)', 'drweca-chrosle', 'RIVER', 53.4732041, 19.5982289, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'W rejonie miejscowości Chrośle rzeka rozlewa się nieco szerzej, płynąc przez tereny o bardzo niskiej presji wędkarskiej. Dno jest tu w większości twarde i piaszczyste, z lokalnymi gliniastymi burtami sprzyjającymi bytowaniu brzan. To idealny teren dla wędkarzy gruntowych polujących na leszcze żerujące w rynnach głównego nurtu rzeki. Nurt jest jednostajny i łagodny, co pozwala na bardzo naturalną prezentację przynęty na delikatnym zestawie feederowym. Roślinność brzegowa tworzy tu gęste pasy trzcin, które stanowią doskonałą osłonę dla szczupaków czatujących na drobnicę. To łowisko słynie z bardzo czystej wody, dlatego warto stosować tu najcieńsze możliwe przypony z fluorocarbonu.', 'PZW Toruń');

