-- Spot 271: Idzbark
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70270, 'Drwęca - Idzbark (Bystrza Górne)', 'drweca-idzbark', 'RIVER', 53.6719935, 20.0338365, 'Warmińsko-Mazurskie', 'Ostróda', 'Górny bieg rzeki w Idzbarku ma charakter niemal potokowy z bardzo rwanym nurtem i żwirowym podłożem. Woda jest tu krystalicznie czysta i zimna, co tworzy idealne warunki dla pstrąga potokowego oraz lipienia. To elitarne łowisko dla muszkarzy, którzy cenią sobie techniczne rzuty suchą muchą pod nawisy nadbrzeżnych krzewów. Koryto jest tu wąskie, a liczne kamienne narzuty tworzą naturalne bystrza i natlenione warkocze. Uciąg rzeki w tym miejscu jest silny, co wymaga od wędkarza brodzącego dużego skupienia i stabilnego obuwia. Miejsce to zapewnia absolutną ciszę i kontakt z dziką rybą w surowym, mazurskim krajobrazie leśnym.', 'PZW Olsztyn');

