-- Spot 272: Ostróda (Młyńska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70271, 'Drwęca - Ostróda (Młyn)', 'drweca-ostroda-mlyn', 'RIVER', 53.7034659, 19.9661982, 'Warmińsko-Mazurskie', 'Ostróda', 'Miejski odcinek w Ostródzie przy starym młynie to techniczne łowisko o bardzo urozmaiconym przepływie wody. Dno jest tu twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu sprzyjającymi żerowaniu dużych płoci oraz kleni. Czysta woda wypływająca z pobliskich jezior przyciąga do miasta liczne stada ryb spokojnego żeru przez cały sezon. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy betonowych murkach oporowych. Uciąg rzeki jest umiarkowany pod mostami, co pozwala na precyzyjne operowanie zestawami spławikowymi typu bolonka. Wieczorne wyprawy z lekkim spinningiem mogą zakończyć się tu emocjonującym holem jazi żerujących tuż pod powierzchnią.', 'PZW Olsztyn');

