-- Spot 273: Ostróda (Wylot)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70272, 'Drwęca - Ostróda (Wylotowa)', 'drweca-ostroda-wylot', 'RIVER', 53.6984962, 19.9095159, 'Warmińsko-Mazurskie', 'Ostróda', 'Wylotowy odcinek z Ostródy to miejsce, gdzie rzeka nabiera pełnego, nizinnego charakteru płynąc szerokim korytem. Głębokość stabilizuje się tu na poziomie półtora metra, z piaszczystym dnem idealnym dla stadnych leszczy i krąpi. Wzdłuż brzegów rosną gęste trzcinowiska, które są naturalną kryjówką dla szczupaków czatujących na rzeczną drobnicę. To doskonałe miejsce na letnie zasiadki z lekkim feederem, celując w ryby migrujące między rzeką a jeziorami. Uciąg jest znikomy i stabilny, co pozwala na stosowanie najdelikatniejszych szczytówek i precyzyjne punktowanie łowiska. Dostęp do wody jest tu bardzo dobry, co czyni ten fragment rzeki ulubionym miejscem dla lokalnych wędkarzy.', 'PZW Olsztyn');

