-- Spot 274: Liwa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70273, 'Drwęca - Liwa (Zakola)', 'drweca-liwa', 'RIVER', 53.6948012, 19.86319, 'Warmińsko-Mazurskie', 'Ostróda', 'Odcinek w Liwie charakteryzuje się bardzo malowniczymi meandrami płynącymi przez tereny leśne i podmokłe łąki. Rzeka posiada tu wyraźnie zaznaczoną rynnę główną, w której grupują się wyrośnięte jazie oraz klenie. Dno jest urozmaicone piaszczystymi łachami oraz licznymi, podwodnymi przeszkodami w postaci zwalonych gałęzi wikliny. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, stosując mikro-woblery prowadzone z prądem wody rzeki. Uciąg rzeki w tym miejscu jest zdecydowany, co sprzyja dotlenieniu wody i wysokiej aktywności ryb przez całą dobę. To doskonałe łowisko dla osób szukających spokoju i technicznego wędkarstwa w otoczeniu nienaruszonej mazurskiej natury.', 'PZW Olsztyn');

