VALUES (70273, 'Nizinna Średnia', 'Meandrująca, naturalna', 14.0, 1.4, 'Piasek i glina', 'Zwalone drzewa', 'Jaź, Kleń, Płoć', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 275: Lubajny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70274, 'Drwęca - Lubajny (Leśny Wąwóz)', 'drweca-lubajny', 'RIVER', 53.6968388, 20.0155959, 'Warmińsko-Mazurskie', 'Ostróda', 'Drwęca w Lubajnach płynie w malowniczej dolinie leśnej, zachowując swój dziki i nieuregulowany charakter. Nurt jest tu umiarkowany, a piaszczyste dno często urozmaicają zwalone pnie drzew stanowiące kryjówki dla szczupaków. Wędkarze spławikowi mogą liczyć na regularne brania wyrośniętych płoci oraz krąpi żerujących w rynnach. To doskonałe miejsce dla spinningistów polujących na okonie przy podmytych brzegach o znacznej głębokości. Uciąg wody jest stały, co pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach gruntowych. Cisza panująca w tej okolicy sprawia, że ryby są mniej płochliwe, co zwiększa szanse na kontakt z okazałym jaziem.', 'PZW Olsztyn');

