-- Spot 276: Liwa (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70275, 'Drwęca - Liwa (Piaszczyste Przykosy)', 'drweca-liwa-punkt-2', 'RIVER', 53.6916886, 19.8158799, 'Warmińsko-Mazurskie', 'Ostróda', 'Odcinek w Liwie charakteryzuje się dość szerokim korytem i występowaniem licznych przykos piaszczystych w nurcie głównym. Rzeka płynie tu stabilnie, żłobiąc dno o charakterze piaszczysto-żwirowym, co przyciąga stadne klenie i jelce. Spinningiści z sukcesami obławiają tutejsze warkocze powstające za naturalnymi przeszkodami w poszukiwaniu boleni. Wzdłuż brzegów rosną gęste pasy trzcin, które stanowią bezpieczne schronienie dla stadnych ryb spokojnego żeru. Uciąg rzeki pozwala na komfortowe łowienie metodą przepływanki z wykorzystaniem lekkich i czułych zestawów spławikowych. Miejsce to zapewnia doskonałe warunki do popołudniowej zasiadki feederowej nakierowanej na wyrośnięte leszcze migrujące z jezior.', 'PZW Olsztyn');

