-- Spot 277: Samborowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70276, 'Drwęca - Samborowo (Żwirowe Rafy)', 'drweca-samborowo', 'RIVER', 53.6660115, 19.8017366, 'Warmińsko-Mazurskie', 'Ostróda', 'W Samborowie Drwęca przedziera się przez tereny o urozmaiconej rzeźbie, co skutkuje licznymi zakolami i głębokimi rynnami. Dno jest tu twarde i w dużej mierze żwirowe, co stwarza wyśmienite warunki tlenowe dla ryb reofilnych. To bankowe stanowisko dla łowców brzan, które znajdują tu dogodne żerowiska w najgłębszych partiach koryta. Spinningista znajdzie tutaj mnóstwo technicznych miejsc do prowadzenia woblerów pod zwisającymi nad wodę gałęziami olch. Uciąg jest zdecydowany i rwie wartko, co wymusza stosowanie dociążonych koszyków zanętowych o masie powyżej czterdziestu gramów. Brzegi są naturalne i miejscami strome, co wymaga od wędkarza zachowania ostrożności podczas podbierania większej ryby.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70276, 'Nizinna Średnia', 'Nurt żywy, dno twarde', 14.0, 2.0, 'Żwirowe', 'Głębokie rynny', 'Brzana, Kleń, Leszcz', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 278: Franciszkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70277, 'Drwęca - Franciszkowo (Spokojna Płania)', 'drweca-franciszkowo', 'RIVER', 53.6434312, 19.7764578, 'Warmińsko-Mazurskie', 'Iława', 'Odcinek we Franciszkowie to kwintesencja nizinnej rzeki o urokliwym charakterze i krystalicznie czystej wodzie. Rzeka płynie tu łagodnym nurtem, żłobiąc piaszczyste dno z nielicznymi naniesionymi mułu w zacisznych zatoczkach. To wymarzone miejsce dla miłośników lekkiego gruntu polujących na dorodne liny oraz złote karasie. W pasie przybrzeżnym występują liczne kępy grążeli, w których jesienią chętnie ustawiają się szczupaki czekające na drobnicę. Uciąg jest stabilny, co pozwala na precyzyjne nęcenie pola łowiska przy użyciu zanęt o drobnej frakcji. Dogodny dostęp do lustra wody sprawia, że jest to chętnie wybierany punkt na rodzinne wypady z wędką.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70277, 'Nizinna Średnia', 'Leniwy nurt, koryto naturalne', 15.0, 1.4, 'Piasek i muł', 'Kępy grążeli', 'Lin, Szczupak, Karaś', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 279: Gierłoż
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70278, 'Drwęca - Gierłoż (Karczowiska)', 'drweca-gierloz', 'RIVER', 53.623451, 19.7456797, 'Warmińsko-Mazurskie', 'Lubawa', 'Drwęca w rejonie Gierłoży zachowuje swój rezerwatowy charakter, oferując wędkarzom dzikie koryto usiane zwalonymi drzewami. Nurt rzeki wyraźnie przyspiesza na przewężeniach, tworząc natlenione bystrza idealne dla jazi oraz wyrośniętych kleni. Dno piaszczysto-gliniaste jest tu mocno urozmaicone, co stwarza doskonałe warunki bytowe dla dużej populacji okonia. Wędkarze stacjonarni z sukcesami stosują metodę przystawki, obławiają głąbokie jamy na zewnętrznych łukach koryta rzeki. Uciąg rzeki wymaga stosowania dociążonych zestawów, które stabilnie utrzymają przynętę w strefie intensywnego żerowania ryb. Miejsce to gwarantuje absolutną ciszę i brak kontaktu z cywilizacją, co sprzyja udanym połowom rzecznych drapieżników.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70278, 'Nizinna Średnia', 'Nieuregulowane, zatory', 12.0, 1.6, 'Piasek i glina', 'Zwalone drzewa', 'Okoń, Kleń, Jaź', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 280: Zybułtowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70279, 'Drwęca - Zybułtowo (Górski Strumień)', 'drweca-zybultowo', 'RIVER', 53.5411416, 20.1883582, 'Warmińsko-Mazurskie', 'Olsztynek', 'W Zybułtowie, blisko swoich źródeł, Drwęca przypomina jeszcze wąski strumień o bardzo bystrym nurcie i żwirowym podłożu. Woda jest tu wyjątkowo zimna i doskonale natleniona, co tworzy idealny biotop dla pstrąga potokowego. To wybitnie techniczne łowisko dla muszkarzy oraz spinningistów preferujących łowienie lekkim sprzętem w surowych warunkach. Koryto posiada liczne naturalne przeszkody, które wymuszają precyzyjne rzuty w małe oczka wolnej wody między korzeniami. Uciąg wody jest rwany, co sprawia, że ryby są tu niezwykle silne i waleczne podczas holu. Ze względu na niewielką szerokość rzeki, kluczowe dla sukcesu jest pełne maskowanie i bardzo dyskretne poruszanie się.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70279, 'Podgórska', 'Wąski strumień, nurt rwany', 4.0, 0.6, 'Żwirowe', 'Naturalne zatory', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', 'Strefa źródliskowa', false);

-- Spot 281: Kiersztanówko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70280, 'Drwęca - Kiersztanówko (Kameralna)', 'drweca-kiersztanowko', 'RIVER', 53.5723675, 20.1571194, 'Warmińsko-Mazurskie', 'Ostróda', 'Odcinek w Kiersztanówku to rzeka o kameralnym charakterze, płynąca meandrami wśród mazurskich pagórków i leśnych zagajników. Dno jest tu twarde i piaszczyste, z wyraźnymi wymyciami rzeźbiącymi ciekawe stanowiska dla ryb spokojnego żeru. To doskonałe miejsce dla łowców jelców oraz dorodnych płoci, które doskonale reagują na drobne przynęty naturalne. Nurt jest jednostajny, co pozwala na bardzo precyzyjne prowadzenie zestawu spławikowego wzdłuż brzegowych burt. Spinningiści mogą liczyć na brania szczupaków czających się w głębszych patiach koryta pod zwalonymi gałęziami olszyn. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem na mapie regionu.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70280, 'Nizinna Mała', 'Meandrująca, koryto naturalne', 6.0, 1.1, 'Piaszczyste', 'Podmyte brzegi', 'Płoć, Jelce, Szczupak', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', false);

-- Spot 282: Rychnowska Wola
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70281, 'Drwęca - Rychnowska Wola (Potokowa)', 'drweca-rychnowska-wola', 'RIVER', 53.6048049, 20.1258839, 'Warmińsko-Mazurskie', 'Ostróda', 'Drwęca w Rychnowskiej Woli to urokliwy, górny odcinek rzeki o charakterze niemal potokowym. Woda jest tu krystalicznie czysta, płynąc wartko po żwirowo-piaszczystym dnie usianym kamieniami. To wyśmienite miejsce dla łowców pstrągów potokowych, którzy potrafią precyzyjnie podać przynętę pod nawisy traw. Nurt tworzy liczne bystrza i natlenione warkocze, w których chętnie przebywają stadne jelce. Spinningowanie wymaga tu pełnej dyskrecji i niskiego profilu, aby nie spłoszyć ryb w płytkiej wodzie. To techniczne łowisko zapewnia doskonałe warunki do treningu rzutów mikro-przynętami w trudnych warunkach terenowych.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70281, 'Podgórska', 'Strumień, nurt rwany', 5.0, 0.7, 'Żwir i kamienie', 'Bystrza', 'Pstrąg potokowy, Jelce, Okoń', 'Kraina pstrąga', 'Rezerwat przyrody Drwęca', false);

-- Spot 283: Ostrowin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70282, 'Drwęca - Ostrowin (Leśne Zakola)', 'drweca-ostrowin', 'RIVER', 53.6459752, 20.0811973, 'Warmińsko-Mazurskie', 'Ostróda', 'Odcinek w Ostrowinie charakteryzuje się naturalnym korytem wijącym się wśród mazurskich lasów i podmokłych łąk. Rzeka posiada tu wyraźnie zaznaczoną rynnę główną, w której grupują się wyrośnięte klenie oraz jazie. Dno jest mocno urozmaicone piaszczystymi łachami oraz licznymi, podwodnymi przeszkodami w postaci zwalonych gałęzi. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, stosując małe woblery prowadzone z prądem rzeki. Uciąg jest zdecydowany, co sprzyja dotlenieniu wody i wysokiej aktywności ryb spokojnego żeru. To doskonałe łowisko dla osób szukających spokoju i technicznego wędkarstwa w otoczeniu nienaruszonej natury.', 'PZW Olsztyn');

