VALUES (70282, 'Nizinna Mała', 'Meandrująca, leśna', 8.0, 1.2, 'Piasek i korzenie', 'Podmyte brzegi', 'Kleń, Jaź, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', false);

-- Spot 284: Zielkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70283, 'Drwęca - Zielkowo (Płania)', 'drweca-zielkowo', 'RIVER', 53.5997057, 19.7237532, 'Warmińsko-Mazurskie', 'Lubawa', 'Drwęca w Zielkowie nabiera pełnego, nizinnego charakteru, płynąc szerokim korytem przez tereny o niskiej presji wędkarskiej. Głębokość rzeki jest tu ustabilizowana, a dno w większości piaszczysto-muliste, co sprzyja rozwojowi bogatej fauny dennej. To idealne łowisko dla miłośników feedera klasycznego, celujących w dorodne leszcze i krąpie żerujące na spokojnych płaniach. Wzdłuż brzegów rosną gęste pasy trzcin, które są naturalną kryjówką dla szczupaków i wyrośniętych linów. Uciąg jest umiarkowany, co pozwala na stosowanie bardzo delikatnych zestawów z czułymi szczytówkami typu quiver. Dzięki dobremu dostępowi do wody, jest to popularne miejsce na weekendowe zasiadki i relaks z wędką.', 'PZW Toruń');

