VALUES (70283, 'Nizinna Średnia', 'Szeroka, nurt łagodny', 18.0, 1.8, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Lin, Szczupak', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 285: Kazanice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70284, 'Drwęca - Kazanice (Kameralna)', 'drweca-kazanice', 'RIVER', 53.5756933, 19.702026, 'Warmińsko-Mazurskie', 'Lubawa', 'Odcinek w Kazanicach to rzeka o kameralnym charakterze, płynąca meandrami wśród pagórków i leśnych zagajników. Dno jest tu twarde i piaszczyste, z wyraźnymi wymyciami rzeźbiącymi ciekawe stanowiska dla ryb spokojnego żeru. To doskonałe miejsce dla łowców jelców oraz dorodnych płoci, które doskonale reagują na drobne przynęty naturalne. Nurt jest jednostajny, co pozwala na bardzo precyzyjne prowadzenie zestawu spławikowego wzdłuż brzegowych burt. Spinningiści mogą liczyć na brania szczupaków czających się w głębszych partiach koryta pod zwalonymi gałęziami olszyn. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem na mapie regionu.', 'PZW Toruń');

