-- Spot 286: Papiernia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70285, 'Drwęca - Papiernia (Przykosy)', 'drweca-papiernia', 'RIVER', 53.5514396, 19.6819235, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Papiernia oferuje wędkarzom dostęp do rzeki o bardzo zmiennym i głębokim korycie z licznymi piaszczystymi przykosami. Rzeka płynie tu szerzej, a jej nurt jest umiarkowany i przewidywalny, co sprzyja systematycznemu nęcenie stad leszczy. Podmyte brzegi porośnięte gęstą wikliną skrywają wyrośnięte okonie, które agresywnie reagują na małe obrotówki i twistery. Spinningista znajdzie tutaj mnóstwo technicznych miejsc do prowadzenia woblerów w poszukiwaniu boleni polujących pod samym brzegiem. Dno pozostaje czyste i twarde, co znacznie ogranicza liczbę zaczepów przy łowieniu z rzutu na dłuższą odległość. To łowisko o relatywnie niskiej presji, gwarantujące spokój podczas aktywnego poszukiwania rzecznych drapieżników.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70285, 'Nizinna Średnia', 'Szeroka, przykosy piaszczyste', 20.0, 1.6, 'Piaszczyste', 'Warkocze przybrzeżne', 'Boleń, Leszcz, Okoń', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', true);

-- Spot 287: Kurzętnik
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70286, 'Drwęca - Kurzętnik (Pod Ruinami)', 'drweca-kurzetnik', 'RIVER', 53.40201, 19.57833, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Drwęca w Kurzętniku to techniczne łowisko z głębokimi rynnami wymytymi pod mostem drogowym i w okolicach ruin zamku. Koryto rzeki jest tu uregulowane, a dno twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu sprzyjającymi żerowaniu jazi. Czysta woda płynąca przez miejscowość przyciąga liczne stada płoci, które doskonale reagują na metodę klasycznej przepływanki. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy faszynowych umocnieniach brzegowych. Uciąg rzeki jest umiarkowany, co pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon wędkarski. Wieczorne wyprawy z lekkim spinningiem mogą zakończyć się tu emocjonującym holem pstrąga lub walecznego klenia.', 'PZW Toruń');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70286, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 22.0, 2.0, 'Piasek i kamień', 'Filary mostu, faszyna', 'Płoć, Jaź, Pstrąg potokowy', 'Kraina leszcza', 'Rezerwat przyrody Drwęca', false);

-- DUNAJEC

-- Spot 288: Piaski Drużków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70287, 'Dunajec - Piaski Drużków (Kamienisko)', 'dunajec-piaski-druzkow', 'RIVER', 49.8099482, 20.6802971, 'Małopolskie', 'Czchów', 'Dunajec w Piaskach Drużków to klasyczny podgórski odcinek z dominującym dnem grubożwirowym i kamienistym. Nurt jest tu wartki i doskonale natleniony, co sprzyja bytowaniu ryb łososiowatych oraz dorodnych brzan. Liczne rynny na zewnętrznych łukach koryta stanowią doskonałe zimowiska dla dużych stad świnek i cert. Wędkarze muchowi cenią to miejsce za przewidywalne rójki owadów oraz dogodne miejsca do brodzenia. Spinningowanie za kleniem pod nawisami wierzb jest szczególnie skuteczne w miesiącach letnich przy stabilnym stanie wody. Należy pamiętać o gwałtownych wahaniach poziomu rzeki wynikających z pracy pobliskiej elektrowni wodnej.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70287, 'Podgórska', 'Bystry nurt, koryto kamieniste', 45.0, 1.2, 'Kamienie i gruby żwir', 'Bystrza, rynny', 'Brzana, Pstrąg potokowy, Świnka', 'Kraina pstrąga', 'Brak', false);

-- Spot 289: Jurków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70288, 'Dunajec - Jurków (Rozlewisko)', 'dunajec-jurkow', 'RIVER', 49.8408297, 20.7128278, 'Małopolskie', 'Czchów', 'Odcinek w Jurkowie charakteryzuje się szerokimi łachami żwirowymi i zróżnicowanym rysunkiem prądów z kilkoma wyspami. Koryto rzeki jest tu w wielu miejscach płytkie, co czyni je idealnym poligonem do łowienia kleni metodą "na upatrzonego". Głębokie doły za dużymi głazami są głównym celem dla łowców głowacic podczas sezonu zimowego. Lokalni wędkarze z sukcesami stosują ciężkie feedery do połowu rekordowych leszczy w spokojniejszych i głębszych partiach rzeki. Woda pozostaje chłodna przez cały rok, wspierając zdrową populację lipienia w szybszych przelewach. Dostęp do brzegów jest dogodny, choć wysoki stan wody po opadach w górach może czasowo uniemożliwić wędkowanie.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70288, 'Podgórska', 'Szerokie koryto, wyspy', 60.0, 1.5, 'Żwirowe', 'Łachy, warkocze', 'Kleń, Głowacica, Lipień', 'Kraina pstrąga', 'Brak', false);

-- Spot 290: Charzewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70289, 'Dunajec - Charzewice (Przełom)', 'dunajec-charzewice', 'RIVER', 49.8632716, 20.7568651, 'Małopolskie', 'Zakliczyn', 'Dunajec w Charzewicach przepływa przez malowniczy krajobraz, tworząc długie i głębokie płanie oddzielone skalistymi bystrzami. Dno składa się z dużych otoczaków i żwiru, zapewniając doskonałe siedlisko dla brzany oraz świnki. Odcinek ten słynie z wieczornych zbiórek ryb, które wywołują intensywne żerowanie powierzchniowe wielu gatunków ryb karpiowatych. Entuzjaści spinningu często polują tu na bolenie patrolujące krawędzie głównego nurtu. Brzegi są naturalnie wzmocnione roślinnością łęgową, oferując mnóstwo cienia i schronienia dla ryb drapieżnych. Jest to techniczne łowisko, gdzie kluczem do sukcesu jest umiejętne czytanie wody i rozumienie styków nurtów.', 'PZW Tarnów');

