VALUES (70289, 'Podgórska', 'Nurt zmienny, rynny', 50.0, 1.8, 'Kamienie i żwir', 'Skaliste progi', 'Świnka, Brzana, Boleń', 'Kraina leszcza', 'Brak', false);

-- Spot 291: Zakliczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70290, 'Dunajec - Zakliczyn (Most)', 'dunajec-zakliczyn-most', 'RIVER', 49.8656485, 20.812631, 'Małopolskie', 'Zakliczyn', 'Odcinek w Zakliczynie jest jednym z najpopularniejszych miejsc na środkowym Dunajcu, znanym ze stabilnej populacji ryb. Duże opaski kamienne w pobliżu mostu tworzą sztuczne wiry i głębokie jamy, w których często przebywają sumy. Rzeka jest tu szeroka, co pozwala zarówno na ciężkie wędkarstwo gruntowe, jak i wyspecjalizowane techniki muchowe. Klenie i jelce są gatunkami dominującymi w płytszych bystrzach, dobrze reagując na małe suche muchy. Wędkarze gruntowi z sukcesami używają białych robaków lub przynęt serowych, aby zwabić brzany z kamienistego dna rzeki. Mimo popularności, odcinek jest wystarczająco długi, aby znaleźć ciche miejsce nawet podczas wędkarskich weekendów.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70290, 'Podgórska', 'Uregulowane koryto, opaski', 55.0, 2.0, 'Kamienie i żwir', 'Opaski kamienne, most', 'Brzana, Sum, Kleń', 'Kraina leszcza', 'Brak', true);

-- Spot 292: Janowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70291, 'Dunajec - Janowice (Zakole)', 'dunajec-janowice', 'RIVER', 49.9005196, 20.8308793, 'Małopolskie', 'Zakliczyn', 'Dunajec w Janowicach cechuje się bardziej naturalnym, meandrującym charakterem z wysokimi, podmytymi brzegami na zewnętrznych łukach. Te pionowe burty tworzą głębokie, zacienione rynny, które są domem dla dużych pstrągów potokowych i szczupaków. Podłoże przechodzi tu stopniowo z dużych kamieni w drobniejszy żwir i piasek w spokojniejszych odcinkach. Jest to doskonała lokalizacja do nocnego łowienia gruntowego z nastawieniem na duże węgorze oraz brzany. Muszkarze doceniają tutejsze długie płanie, które pozwalają na bardzo naturalny dryf nimfy lub streamera. Okoliczne łąki zapewniają łatwy dostęp do wody, jednak wędkarze muszą uważać na okresowo bardzo miękkie brzegi rzeki.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70291, 'Podgórska', 'Naturalne zakola, burty', 50.0, 2.5, 'Żwir i piasek', 'Podmyte burty', 'Węgorz, Brzana, Pstrąg potokowy', 'Kraina leszcza', 'Brak', true);

-- Spot 293: Wielka Wieś
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70292, 'Dunajec - Wielka Wieś (Wojnicz)', 'dunajec-wielka-wies', 'RIVER', 49.9353246, 20.8475168, 'Małopolskie', 'Wojnicz', 'Odcinek w Wielkiej Wsi wyznacza przejście, w którym Dunajec zaczyna się jeszcze bardziej rozszerzać przed osiągnięciem nizin. Nurt pozostaje silny, ale rzeka tworzy rozległe łachy żwirowe, które idealnie nadają się do brodzenia przy niskim stanie wody. Bolenie i szczupaki są tu głównymi drapieżnikami, często polującymi w turbulentnej wodzie poniżej bystrzy. Łowienie gruntowe z ciężkimi oliwkami jest niezbędne, aby utrzymać przynętę w miejscu w obrębie potężnego głównego nurtu. Jest to doskonała lokalizacja do połowu dużych świnek, szczególnie podczas ich wiosennych wędrówek tarłowych. Koryto rzeki jest technicznie wymagające ze względu na obecność licznych zaczepów i dużych zatopionych głazów.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70292, 'Nizinna Średnia', 'Szerokie koryto żwirowe', 65.0, 2.2, 'Gruby żwir', 'Piaszczyste przykosy', 'Boleń, Świnka, Brzana', 'Kraina leszcza', 'Brak', true);

-- Spot 294: Błonie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70293, 'Dunajec - Błonie (Pod Tarnowem)', 'dunajec-blonie-tarnow', 'RIVER', 49.9640302, 20.8813465, 'Małopolskie', 'Tarnów', 'Odcinek w Błoniu to szerokie koryto rzeki o silnym nurcie i dnie usianym grubym żwirem oraz otoczakami. Występują tu liczne rynny o głębokości do dwóch metrów, w których chętnie przebywają dorodne brzany oraz świnki. Spinningiści z sukcesami polują tutaj na bolenie, które patrolują piaszczyste przykosy w głównym nurcie rzeki. Uciąg wody jest zdecydowany, co wymusza stosowanie koszyków feederowych o masie od osiemdziesięciu gramów wzwyż. Brzegi są tu dość wysokie, ale oferują wiele naturalnych i wygodnych stanowisk dla wędkarzy stacjonarnych. Wieczorami na płytszych przelewach często słychać agresywne ataki kleni zbierających owady z powierzchni wody.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70293, 'Nizinna Średnia', 'Szerokie koryto żwirowe', 55.0, 1.8, 'Gruby żwir', 'Rynny prądowe', 'Brzana, Świnka, Boleń', 'Kraina brzany', 'Brak', true);

-- Spot 295: Sieciechowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70294, 'Dunajec - Sieciechowice (Zakole)', 'dunajec-sieciechowice', 'RIVER', 50.0003288, 20.8894837, 'Małopolskie', 'Tarnów', 'Dunajec w Sieciechowicach tworzy malownicze, szerokie zakola z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach koryta. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe z nielicznymi zaczepami w postaci zatopionych pni drzew. To doskonałe łowisko sumowe, gdzie nocne zasiadki z żywcem często kończą się emocjonującymi holami okazowych ryb. Wędkarze gruntowi cenią ten odcinek za populację dużych leszczy, które gromadzą się w spokojniejszych patiach wody. Nurt rzeki jest tu umiarkowany, co pozwala na precyzyjne nęcenie pola łowiska przy użyciu zanęt o grubiej frakcji. Dogodny dojazd do samej wody sprawia, że jest to chętnie wybierane miejsce na wielodniowe biwaki wędkarskie.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70294, 'Nizinna Średnia', 'Naturalne zakola', 60.0, 2.5, 'Piasek i żwir', 'Zwalone kłody', 'Sum, Leszcz, Brzana', 'Kraina brzany', 'Brak', true);

-- Spot 296: Komorów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70295, 'Dunajec - Komorów (Płania)', 'dunajec-komorow', 'RIVER', 50.0350257, 20.905467, 'Małopolskie', 'Tarnów', 'Odcinek w Komorowie charakteryzuje się wyrównanym nurtem i piaszczystym dnem z lokalnymi skupiskami grubszego żwiru. Rzeka płynie tu stabilnie, tworząc szerokie płanie idealne do łowienia białorybu metodą odległościową lub lekkim feederem. Dominują tu duże stada płoci oraz krąpi, które doskonale reagują na systematyczne donęcanie luźną zanętą. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia woblerów w poszukiwaniu jazi żerujących blisko brzegowej linii trzcin. Uciąg wody jest przewidywalny, co pozwala na idealną prezentację przynęty nawet na bardzo delikatnych zestawach. Brak wysokiej roślinności na brzegach znacznie ułatwia rzuty, jednak wymaga od wędkarza pełnego maskowania na stanowisku.', 'PZW Tarnów');

