VALUES (70295, 'Nizinna Średnia', 'Szerokie płanie nizinne', 65.0, 1.5, 'Piasek i żwir', 'Piaszczyste przykosy', 'Płoć, Jaź, Krąp', 'Kraina brzany', 'Brak', true);

-- Spot 297: Bobrowniki Małe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70296, 'Dunajec - Bobrowniki Małe (Warkocze)', 'dunajec-bobrowniki-male', 'RIVER', 50.0708251, 20.8976604, 'Małopolskie', 'Tarnów', 'W Bobrownikach Małych rzeka rozlewa się szeroko, tworząc liczne warkocze za naturalnymi kamiennymi przeszkodami w nurcie. Dno jest twarde, żwirowo-kamieniste, co czyni ten odcinek bankowym stanowiskiem dla łowców dorodnych kleni oraz jazi. To elitarne miejsce dla miłośników ciężkiego spinningu polujących na bolenie patrolujące środek rzeki o świcie. Wędkarze gruntowi z sukcesami stosują tu metodę przepływanki z przytrzymaniem, celując w ryby reofilne takie jak certy. Uciąg wody jest silny i dobrze natleniony, co sprzyja wysokiej aktywności ryb nawet podczas upalnych letnich dni. Brzegi są naturalne i kamieniste, co wymaga od wędkarza zachowania ostrożności podczas brodzenia w pobliżu nurtu.', 'PZW Tarnów');

