VALUES (70296, 'Nizinna Średnia', 'Nurt żywy, koryto żwirowe', 70.0, 1.3, 'Żwir i kamień', 'Warkocze prądowe', 'Boleń, Kleń, Certa', 'Kraina brzany', 'Brak', true);

-- Spot 298: Niedomice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70297, 'Dunajec - Niedomice (Głęboka Rynna)', 'dunajec-niedomice', 'RIVER', 50.1050675, 20.8796851, 'Małopolskie', 'Żabno', 'Odcinek w Niedomicach słynie z występowania głębokich, kilkumetrowych rynien wymytych w pobliżu wysokich, gliniastych burt. To strategiczne miejsce dla łowców sandaczy, które żerują tu na ogromnych ławicach uklei gromadzących się w cieniu brzegów. Dno jest mocno zróżnicowane, od twardej gliny po piaszczyste naniesienia, co stwarza doskonałe warunki dla różnych technik łowienia. Wędkarze gruntowi z sukcesami obławiają tutejsze uskoki dna, nęcąc dorodne leszczowe stada grubym pelletem. Uciąg rzeki jest tu zdecydowany i wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu. Jest to łowisko wymagające technicznie, które nagradza wytrwałych pasjonatów czytania wody i aktywnego poszukiwania drapieżnika.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70297, 'Nizinna Wielka', 'Szeroka rzeka, rynny', 75.0, 3.2, 'Glina i piasek', 'Głębokie rynny', 'Sandacz, Leszcz, Sum', 'Kraina brzany', 'Brak', true);

-- Spot 299: Biskupice Radłowskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70298, 'Dunajec - Biskupice Radłowskie (Przy Moście)', 'dunajec-biskupice-radlowskie', 'RIVER', 50.1365044, 20.8488135, 'Małopolskie', 'Radłów', 'Dunajec w Biskupicach Radłowskich to popularne łowisko z doskonałym dostępem do wody w rejonie mostu drogowego. Pod filarami mostu woda wymyła głębokie doły, które są całoroczną kryjówką dla sumów oraz wyrośniętych brzan. Dno jest tu w dużej mierze piaszczyste z lokalnymi narzutami kamieni stanowiącymi umocnienia brzegowe i podpory. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy faszynowych umocnieniach rzeki. Uciąg wody jest stabilny i pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon. Wieczorne wyprawy z lekkim spinningiem mogą zakończyć się tu emocjonującym holem sandacza lub bolenia czatującego w nurcie.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70298, 'Nizinna Wielka', 'Uregulowane, nurt stabilny', 80.0, 2.0, 'Piasek i kamień', 'Filary mostu, opaski', 'Brzana, Sum, Sandacz', 'Kraina brzany', 'Brak', true);

-- Spot 300: Pasieka Otfinowska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70299, 'Dunajec - Pasieka Otfinowska (Ujście Dunajca)', 'dunajec-pasieka-otfinowska', 'RIVER', 50.1704572, 20.8236273, 'Małopolskie', 'Żabno', 'Odcinek w Pasiece Otfinowskiej charakteryzuje się bardzo szerokim korytem i piaszczystymi przykosami wychodzącymi daleko w nurt. Woda płynie tu leniwie, a dno jest piaszczysto-muliste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych linów. To wymarzone miejsce dla spinningistów polujących na szczupaki, którzy obławiają pasy trzcin oraz kępy grążeli. Uciąg jest znikomy, co pozwala na stosowanie najlżejszych i najbardziej czułych zestawów z drgającą szczytówką. Brzegi są niskie i trawiaste, co zapewnia ogromny komfort podczas całodniowych zasiadek z rodziną. Niska presja wędkarska sprawia, że ryby żerują tu śmiało, co czyni to łowisko niezwykle atrakcyjnym punktem na mapie regionu.', 'PZW Tarnów');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70299, 'Nizinna Wielka', 'Leniwy nurt, szerokie koryto', 90.0, 2.8, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Lin, Szczupak', 'Kraina brzany', 'Brak', true);

-- Spot 301: Janikowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70300, 'Dunajec - Janikowice (Przedujście)', 'dunajec-janikowice', 'RIVER', 50.1943717, 20.7801262, 'Małopolskie', 'Żabno', 'Dunajec w Janikowicach to potężna rzeka nizinna płynąca szerokim korytem tuż przed ujściem do Wisły. Dno jest tu w dużej mierze piaszczyste, z głębokimi rynnami sięgającymi trzech metrów głębokości. To strategiczne miejsce dla łowców sandaczy, które żerują na piaszczystych przykosach środkowego nurtu. Wędkarze gruntowi z sukcesami łowią tu dorodne leszcze, wykorzystując ciężkie koszyki dla stabilizacji zestawu. Uciąg wody jest stabilny i pozwala na komfortowe wędkowanie z łodzi na otwartej toni. Brzegi są niskie i trawiaste, co zapewnia wygodny dostęp do wody dla pasjonatów nocnych zasiadek.', 'PZW Tarnów');

