-- Spot 302: Okręg
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70301, 'Dunajec - Okręg (Ujście do Wisły)', 'dunajec-okreg-ujscie', 'RIVER', 50.2253783, 20.7490503, 'Małopolskie', 'Opatowiec', 'Odcinek w Okręgu to samo ujście Dunajca do Wisły, co czyni go jednym z najbardziej rybnych miejsc w regionie. Mieszające się nurty obu rzek tworzą bogate w tlen i pokarm rozlewisko o zmiennej głębokości. Dno jest piaszczysto-muliste z licznymi kępami grążeli, w których chętnie przebywają szczupaki. To legendarne łowisko sumowe, gdzie potężne drapieżniki żerują na stadach uklei i krąpi. Występuje tu silne zjawisko cofki, wymagające od wędkarza częstej korekty obciążenia zestawu gruntowego. Niska presja wędkarska sprawia, że jest to doskonałe miejsce na relaksującą i efektywną zasiadkę.', 'PZW Tarnów');

