-- Spot 303: Kurów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70302, 'Dunajec - Kurów (Cofka Rożnowska)', 'dunajec-kurow', 'RIVER', 49.6914969, 20.6580017, 'Małopolskie', 'Nowy Sącz', 'Dunajec w Kurowie to odcinek cofkowy Jeziora Rożnowskiego o bardzo urozmaiconej rzeźbie dna. Rzeka płynie tu wolniej, osadzając żwir i piasek, co stwarza idealne warunki dla boleni. W rynnach o głębokości przekraczającej dwa metry stacjonują duże klenie oraz wyrośnięte jazie. Spinningiści z sukcesami obławiają filary mostu, szukając sandaczy czatujących w cieniu konstrukcji. Uciąg wody jest umiarkowany i zależy w dużej mierze od poziomu piętrzenia na zaporze. To łowisko o ogromnym potencjale, wymagające od wędkarza precyzyjnego czytania prądów i zastoisk.', 'PZW Nowy Sącz');

