-- Spot 304: Maszkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70303, 'Dunajec - Maszkowice (Beskidzki)', 'dunajec-maszkowice', 'RIVER', 49.5390218, 20.47315, 'Małopolskie', 'Łącko', 'Maszkowice oferują klasyczny górski Dunajec z rwanym nurtem i dnem usianym grubymi otoczakami. Woda jest tu krystalicznie czysta i zimna, co sprzyja populacji pstrąga potokowego. To elitarne łowisko dla muszkarzy, którzy cenią techniczne rzuty nimfą w głębokie, natlenione rynny. Brzany walczące w głównym prądzie są tutaj częstym i bardzo pożądanym przyłowem spinningowym. Uciąg jest silny, co wymaga od wędkarza brodzącego dużego skupienia i profesjonalnych woderów. Krajobraz Beskidu Sądeckiego otaczający rzekę nadaje każdej wyprawie wędkarskiej wyjątkowego, dzikiego charakteru.', 'PZW Nowy Sącz');

