-- Spot 305: Jazowsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70304, 'Dunajec - Jazowsko (Bystrza)', 'dunajec-jazowsko', 'RIVER', 49.5313952, 20.5273614, 'Małopolskie', 'Stary Sącz', 'Odcinek w Jazowsku to legendarne miejsce na mapie polskich wód pstrągowych i lipieniowych. Koryto rzeki charakteryzuje się licznymi bystrzami oraz szerokimi płaniami o żwirowym podłożu. Ryby łososiowate znajdują tu doskonałe warunki tlenowe dzięki dynamicznemu przepływowi wody. Spinningista znajdzie tutaj mnóstwo technicznych warkoczy powstających za dużymi głazami w nurcie. Uciąg jest bardzo zdecydowany, co wymusza stosowanie przynęt o agresywnej pracy i dużej masie. Wieczorne rójki owadów prowokują tu widowiskowe żerowanie powierzchniowe kleni oraz wyrośniętych jazi.', 'PZW Nowy Sącz');

