-- Spot 306: Naszacowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70305, 'Dunajec - Naszacowice (Płania)', 'dunajec-naszacowice', 'RIVER', 49.5519978, 20.5732688, 'Małopolskie', 'Stary Sącz', 'Dunajec w Naszacowicach to odcinek przejściowy, gdzie rzeka zaczyna nieco zwalniać swój bieg. Dno pozostaje twarde i kamieniste, ale pojawiają się piaszczyste łachy na wewnętrznych łukach. To królestwo świnek i brzan, które stadnie żerują na żwirowych rafach w głównym nurcie. Wędkarze spławikowi z sukcesami stosują tu metodę bolonki, puszczając zestaw na długich dystansach. Podmyte burty porośnięte wikliną skrywają wyrośnięte okonie, które agresywnie atakują małe twistery. Dogodny dostęp do rzeki sprawia, że jest to popularne miejsce na aktywne popołudnie z wędką.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70305, 'Podgórska', 'Nurt umiarkowany, rafy', 45.0, 1.5, 'Żwirowe', 'Piaszczyste łachy', 'Świnka, Brzana, Okoń', 'Kraina brzany', false);

-- Spot 307: Tylmanowa (Brzeg Górny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70306, 'Dunajec - Tylmanowa (Brzeg Górny)', 'dunajec-tylmanowa-gora', 'RIVER', 49.5057305, 20.3981239, 'Małopolskie', 'Krościenko', 'Dunajec w Tylmanowej to jeden z najbardziej technicznych odcinków rzeki o charakterze wybitnie górskim. Koryto wypełnione jest licznymi bystrzami oraz głębokimi rynnami o twardym, kamienistym dnie. Jest to wymarzone miejsce dla muszkarzy polujących na dorodne pstrągi potokowe oraz lipienie. Nurt rzeki jest tu bardzo silny, co wymaga od wędkarza dużej sprawności fizycznej podczas brodzenia. Woda pozostaje chłodna i doskonale natleniona przez cały rok, sprzyjając wysokiej aktywności ryb łososiowatych. To stanowisko oferuje surowy, górski krajobraz oraz szansę na kontakt z dziką i waleczną rybą.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70306, 'Górska', 'Bystry nurt, przełomowy', 35.0, 1.2, 'Kamieniste (otoczaki)', 'Bystrza, rynny', 'Pstrąg potokowy, Lipień, Brzana', 'Kraina pstrąga', 'Brak', false);

-- Spot 308: Gronie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70307, 'Dunajec - Gronie (Przełom)', 'dunajec-gronie', 'RIVER', 49.542276, 20.4078718, 'Małopolskie', 'Nowy Sącz', 'Odcinek w miejscowości Gronie charakteryzuje się rwanym nurtem i licznymi warkoczami powstającymi za dużymi głazami. Podłoże jest tu twarde, złożone z grubych otoczaków, które są naturalnym schronieniem dla brzan oraz świnek. Spinningiści z sukcesami obławiają tutejsze głębokie doły w poszukiwaniu wyrośniętych kleni żerujących w głównym prądzie. Uciąg wody jest bardzo zdecydowany, co wymusza stosowanie dociążonych przynęt o agresywnej pracy. Wędkarze muchowi chętnie odwiedzają to miejsce ze względu na obfite rójki owadów prowokujące ryby do zbierania z powierzchni. Należy zachować szczególną ostrożność przy wysokich stanach wody, które mogą gwałtownie zmienić rzeźbę koryta.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70307, 'Górska', 'Przełomowy, skalisty', 40.0, 1.4, 'Kamieniste', 'Głazy, warkocze', 'Brzana, Świnka, Kleń', 'Kraina pstrąga', 'Brak', false);

-- Spot 309: Tylmanowa (Kłodne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70308, 'Dunajec - Tylmanowa (Kłodne)', 'dunajec-tylmanowa-klodne', 'RIVER', 49.4741794, 20.4365667, 'Małopolskie', 'Krościenko', 'Dolny odcinek rzeki w Tylmanowej słynie z widowiskowych przełomów i rynien o głębokości przekraczającej półtora metra. Dno jest tu mocno urozmaicone skalnymi uskokami, które stanowią bankowe kryjówki dla okazałych pstrągów. To idealna lokalizacja do stosowania ciężkich nimf prowadzonych tuż przy samym dnie rzeki. Uciąg rzeki jest dynamiczny i wymaga od wędkarza stosowania solidnego obuwia z kolcami do bezpiecznego brodzenia. Warkocze tworzące się przy brzegach są ulubionym miejscem bytowania stadnych lipieni o pokaźnych rozmiarach. Cisza i otoczenie gór sprawiają, że każda zasiadka w tym miejscu jest wyjątkowym przeżyciem estetycznym.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70308, 'Górska', 'Głębokie rynny, nurt bystry', 30.0, 1.6, 'Skalisto-kamieniste', 'Uskoki skalne', 'Pstrąg potokowy, Lipień, Głowacica', 'Kraina pstrąga', 'Brak', false);

-- Spot 310: Krościenko nad Dunajcem (OS)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70309, 'Dunajec - Krościenko (Odcinek Specjalny)', 'dunajec-kroscienko-os', 'RIVER', 49.4275674, 20.44103, 'Małopolskie', 'Krościenko nad Dunajcem', 'Dunajec w Krościenku to serce słynnego odcinka specjalnego, objętego rygorystycznymi zasadami połowu "złów i wypuść". Rzeka płynie tu szerokim korytem, łącząc szybkie bystrza z rozległymi, żwirowymi płaniami. Jest to jedno z najlepszych łowisk w Polsce, gdzie można liczyć na spotkanie z rekordowymi pstrągami potokowymi. Spinningowanie jest tu dozwolone wyłącznie przy użyciu przynęt z hakami pozbawionymi zadziorów. Nurt rzeki jest tu przewidywalny, co pozwala na komfortowe wędkowanie z brzegowych kamienisk. To elitarne łowisko przyciąga pasjonatów z całego kraju, gwarantując niezapomniane emocje podczas holu walecznych drapieżników.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70309, 'Górska', 'Szerokie koryto, zróżnicowane', 45.0, 1.3, 'Żwirowo-kamieniste', 'Płanie żwirowe', 'Pstrąg potokowy, Lipień, Głowacica', 'Kraina pstrąga', 'OS Dunajec (Catch & Release)', false);

-- Spot 311: Sromowce Wyżne (Poniżej Zapory)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70310, 'Dunajec - Sromowce Wyżne', 'dunajec-sromowce-wyzne', 'RIVER', 49.39978, 20.3545044, 'Małopolskie', 'Czorsztyn', 'Odcinek w Sromowcach Wyżnych znajduje się bezpośrednio poniżej zapory, co gwarantuje stabilną temperaturę wody przez cały sezon. Koryto rzeki charakteryzuje się tu równomiernym uciągiem oraz dnem pokrytym drobnym i średnim żwirem. To wymarzone miejsce dla łowców lipieni, które masowo gromadzą się na tutejszych natlenionych płaniach. Wędkarze muchowi z sukcesami stosują tu metodę krótkiej nimfy oraz suchej muchy w słoneczne dni. Podmyte brzegi porośnięte wikliną skrywają wyrośnięte klenie, które agresywnie reagują na mikro-spinning. Należy bacznie obserwować poziom wody, który może ulec zmianie w wyniku zrzutów z elektrowni wodnej.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70310, 'Górska', 'Uregulowany wypływ spod zapory', 35.0, 1.0, 'Żwirowe', 'Równe płanie', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', 'Strefa przyzaporowa', false);

-- Spot 312: Ostrowsko (Podhalański)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70311, 'Dunajec - Ostrowsko', 'dunajec-ostrowsko', 'RIVER', 49.4790662, 20.1228436, 'Małopolskie', 'Nowy Targ', 'Dunajec w Ostrowsku to odcinek o charakterze podhalańskim, położony w szerokiej dolinie z widokiem na Tatry. Rzeka rozlewa się tu szerzej, tworząc liczne piaszczysto-żwirowe łachy i płytkie, natlenione bystrza. Podłoże jest tu mocno zróżnicowane, co sprzyja bytowaniu świnek oraz licznych stad kleni. To doskonałe miejsce dla początkujących muszkarzy ze względu na łatwy dostęp do wody i brak wysokich drzew. Uciąg rzeki jest umiarkowany i pozwala na swobodne brodzenie w poszukiwaniu rzecznych drapieżników. Wieczorne wyprawy z lekkim spinningiem często owocują tu braniem dorodnych okoni lub jazi.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70311, 'Podgórska', 'Szeroka dolina, koryto żwirowe', 40.0, 0.8, 'Żwirowo-piaszczyste', 'Bystrza, łachy', 'Świnka, Kleń, Pstrąg potokowy', 'Kraina pstrąga', 'Brak', false);

-- Spot 313: Knurów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70312, 'Dunajec - Knurów (Podhalański)', 'dunajec-knurow', 'RIVER', 49.47655, 20.18095, 'Małopolskie', 'Nowy Targ', 'Dunajec w Knurowie to klasyczna podhalańska rzeka z szerokim korytem i dnem usianym otoczakami. Miejsce to znajduje się powyżej cofki Zbiornika Czorsztyńskiego, co sprawia, że poziom wody bywa tu zmienny. Jest to doskonały poligon dla muszkarzy polujących na lipienie oraz pstrągi w szybkich bystrzach. Dno składa się z luźnych kamieni i żwiru, co umożliwia stosunkowo łatwe brodzenie w porównaniu do niższych odcinków. Wczesną wiosną można tu zaobserwować migrujące w górę rzeki głowacice szukające tarlisk. Malownicze otoczenie z widokiem na Gorce dodaje każdej wyprawie wędkarskiej wyjątkowego, górskiego klimatu.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70312, 'Górska', 'Szerokie koryto żwirowe', 30.0, 0.8, 'Otoczaki i żwir', 'Bystrza, łachy', 'Pstrąg potokowy, Lipień, Głowacica', 'Kraina pstrąga', 'Brak', false);

-- Spot 314: Nowy Targ (Połączenie Dunajców)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70313, 'Dunajec - Nowy Targ (Widły)', 'dunajec-nowy-targ-widly', 'RIVER', 49.4845892, 20.0435327, 'Małopolskie', 'Nowy Targ', 'Punkt w Nowym Targu to miejsce, gdzie Biały i Czarny Dunajec łączą się, tworząc właściwy bieg rzeki. Odcinek ten charakteryzuje się typowo górskim charakterem z bardzo rwanym nurtem i kamienistym dnem. Jest to jedno z najlepszych łowisk pstrągowych w regionie, szczególnie efektywne podczas porannych rójek owadów. Woda jest tu krystalicznie czysta i bardzo zimna, co wspiera zdrową populację pstrąga potokowego i lipienia. Wędkarze najczęściej stosują tu suchą muchę lub nimfę, obławiając cienie za dużymi głazami w nurcie. Dostęp do wody od strony miasta jest bardzo dobry, jednak wymaga dyskrecji, aby nie spłoszyć ryb.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70313, 'Górska', 'Bystry nurt, połączenie nurtów', 25.0, 0.7, 'Kamieniste', 'Głazy, warkocze', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', 'Brak', false);

-- Spot 315: Rdziostów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70314, 'Dunajec - Rdziostów (Pod Sączem)', 'dunajec-rdziostow', 'RIVER', 49.657495, 20.6791174, 'Małopolskie', 'Nowy Sącz', 'Rdziostów to wymagający technicznie odcinek położony niedaleko Nowego Sącza, gdzie Dunajec zaczyna wyraźnie rozszerzać swoje koryto. Nurt pozostaje tu silny, żłobiąc głębokie rynny przy brzegach, w których często stacjonują dorodne brzany. Wędkarze używający ciężkich feederów mogą liczyć na sukcesy, celując w żwirowe przykosy na środku rzeki. Dno stanowi mieszankę dużych kamieni rzecznych i grubego piasku, tworząc zróżnicowane siedliska dla wielu gatunków ryb. Wieczorami powierzchnia wody często "gotuje się" od aktywności dużych kleni zbierających owady spod nawisów drzew. Lokalizacja ta wymaga ostrożnego brodzenia ze względu na śliskie kamienie oraz nieprzewidywalną głębokość dołków.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70314, 'Podgórska', 'Nurt zdecydowany, rynny', 40.0, 1.5, 'Kamienie i gruby żwir', 'Rynny brzegowe', 'Brzana, Kleń, Świnka', 'Kraina brzany', 'Brak', false);

-- Spot 316: Rożnów (Poniżej Zapory)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70315, 'Dunajec - Rożnów (Elektrownia)', 'dunajec-roznow-zapora', 'RIVER', 49.7613074, 20.663057, 'Małopolskie', 'Czchów', 'Odcinek w Rożnowie znajduje się bezpośrednio poniżej zapory, co tworzy unikalne warunki ze stałą temperaturą wody przez cały rok. Przepływ rzeki jest tu regulowany przez pracę elektrowni, więc wędkarze muszą stale monitorować nagłe zmiany poziomu wody. Miejsce to słynie z populacji dużych głowacic oraz drapieżników żerujących w głębokiej, dobrze natlenionej wodzie. Poniżej zapory dno jest kamieniste i oferuje wiele kryjówek dla okazałych sandaczy oraz wyrośniętych okoni. To strategiczny punkt dla spinningistów używających ciężkiego sprzętu do rzutów w turbulentną wodę przy wypływie. Brzegi są częściowo umocnione, co zapewnia stabilne stanowiska do długich sesji gruntowych lub spinningowych.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70315, 'Podgórska', 'Uregulowany wypływ spod zapory', 50.0, 2.0, 'Kamieniste', 'Betonowe umocnienia', 'Głowacica, Sandacz, Okoń', 'Kraina pstrąga', 'Strefa przyzaporowa', true);

-- Spot 317: Stadła
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70316, 'Dunajec - Stadła (Rafy Żwirowe)', 'dunajec-stadla', 'RIVER', 49.5780368, 20.615023, 'Małopolskie', 'Stary Sącz', 'Dunajec w Stadłach to odcinek przejściowy, gdzie górski potok zaczyna nabierać cech dużej rzeki podgórskiej. Koryto rzeki jest tu szerokie i zdominowane przez żwirowe płanie, które są ulubionym tarliskiem świnek oraz brzan. Muszkarze często odwiedzają ten spot ze względu na stabilne warunki do łowienia na suchą muchę. Małe wyspy i boczne odnogi tworzą zróżnicowane prądy, w których chowają się duże pstrągi oraz klenie. Przejrzystość wody jest zazwyczaj doskonała, co wymusza stosowanie cienkich przyponów fluorocarbonowych, aby oszukać ryby. Spot jest łatwo dostępny z drogi głównej, co czyni go popularnym wyborem na szybkie, popołudniowe wypady.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70316, 'Podgórska', 'Szerokie koryto żwirowe', 45.0, 1.2, 'Żwir i otoczaki', 'Wyspy żwirowe', 'Świnka, Brzana, Pstrąg potokowy', 'Kraina brzany', 'Brak', false);

-- Spot 318: Świniarsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70317, 'Dunajec - Świniarsko (Przełom Pod Sączem)', 'dunajec-swiniarsko', 'RIVER', 49.5987444, 20.661593, 'Małopolskie', 'Nowy Sącz', 'Świniarsko oferuje zróżnicowany odcinek Dunajca z mieszanką szybkich bystrzy i głębokich, spokojnych rynien. Dno rzeki składa się głównie z grubego żwiru, co zapewnia doskonałe warunki dla ryb prądolubnych. Duże głazy rozrzucone w nurcie tworzą natlenione warkocze, w których drapieżne pstrągi czekają na spływający pokarm. Łowienie metodą gruntową na sery lub białe robaki jest tu bardzo skuteczne przy połowie silnych brzan. Podczas wiosennych przyborów rzeka bywa tu groźna, ale po ustabilizowaniu wody staje się rajem dla spinningistów. Wysokie brzegi stanowią doskonały punkt obserwacyjny, pozwalający zlokalizować żerujące ryby przed wejściem do wody.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70317, 'Podgórska', 'Zróżnicowany nurt, rynny', 42.0, 1.4, 'Gruby żwir', 'Głazy narzutowe', 'Brzana, Pstrąg potokowy, Kleń', 'Kraina brzany', 'Brak', false);

-- Spot 319: Maniowy (Zachód / Cofka Czorsztyńska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70318, 'Dunajec - Maniowy (Cofka)', 'dunajec-maniowy-zachod', 'RIVER', 49.4612396, 20.2318723, 'Małopolskie', 'Czorsztyn', 'Dunajec w tym miejscu powoli traci swój górski pęd, wpływając w ramy Zbiornika Czorsztyńskiego. Jest to klasyczna cofka, gdzie osadzający się namuł i piasek tworzą idealne warunki dla żerujących leszczy. Wędkarze często polują tu na sandacze, które patrolują stoki starego koryta rzeki ukrytego pod lustrem wody. Brzegi są tu zmienne i mocno zależne od aktualnego poziomu retencji na zaporze w Niedzicy. Ze względu na sporą głębokość, skuteczną metodą jest ciężki spinning oraz klasyczny feeder z koszykiem o sporej gramaturze. To miejsce słynie z widowiskowych wschodów słońca nad taflą jeziora, co umila każdą poranną zasiadkę.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70318, 'Podgórska', 'Cofka zbiornika, nurt zanikający', 120.0, 4.5, 'Piaszczysto-muliste', 'Stare koryto rzeki', 'Sandacz, Leszcz, Okoń', 'Kraina brzany', 'Zbiornik Czorsztyński', true);

-- Spot 320: Maniowy (Wschód / Zatoka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70319, 'Dunajec - Maniowy (Wschód)', 'dunajec-maniowy-wschod', 'RIVER', 49.4397604, 20.2784641, 'Małopolskie', 'Niedzica', 'Wschodni odcinek w rejonie Maniów to rozległa zatoka, w której nurt rzeki jest niemal niewyczuwalny. Dno staje się tu bardziej muliste, co sprzyja populacji linów oraz dorodnych karasi srebrzystych. Spinningiści obławiający ten fragment z łodzi mogą liczyć na spotkanie z okazałymi szczupakami czającymi się w pasach trzcin. Woda nagrzewa się tu szybciej niż w głównym korycie, co przyciąga ryby spokojnego żeru już wczesną wiosną. Ukształtowanie linii brzegowej pozwala na znalezienie zacisznego stanowiska nawet przy silniejszym wietrze wiejącym od strony gór. Jest to świetny punkt wypadowy dla osób łączących pasję wędkarską z rodzinnym wypoczynkiem nad wodą.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70319, 'Podgórska', 'Zatoka o charakterze jeziornym', 200.0, 5.0, 'Muliste', 'Trzcinowiska', 'Szczupak, Lin, Karaś', 'Kraina leszcza', 'Zbiornik Czorsztyński', true);

-- Spot 321: Sromowce Niżne (Serce Pienin)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70320, 'Dunajec - Sromowce Niżne', 'dunajec-sromowce-nizne', 'RIVER', 49.3943857, 20.4106241, 'Małopolskie', 'Krościenko', 'Sromowce Niżne oferują jeden z najbardziej spektakularnych widoków wędkarskich w całej Polsce, z Trzema Koronami w tle. Dunajec płynie tu wartko po skalistym dnie, tworząc głębokie rynny i potężne warkocze prądowe. To absolutne królestwo pstrąga potokowego oraz lipienia, które wymagają od muszkarza najwyższego kunsztu. Rzeka stanowi tu granicę państwową, dlatego należy pamiętać o przepisach dotyczących połowu w pasie granicznym. Silny uciąg wymusza stosowanie ciężkich nimf oraz precyzyjne operowanie zestawem między wystającymi głazami. Spotkanie z miedzianą brzaną w tym nurcie to test wytrzymałości dla każdego wędziska i kołowrotka.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70320, 'Górska', 'Przełomowy, skalisty, graniczny', 40.0, 1.3, 'Kamienisto-skaliste', 'Warkocze, bystrza', 'Pstrąg potokowy, Lipień, Brzana', 'Kraina pstrąga', 'Pas graniczny', false);

-- Spot 322: Znamirowice (Jezioro Rożnowskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70321, 'Dunajec - Znamirowice', 'dunajec-znamirowice', 'RIVER', 53.7225155, 20.6864076, 'Małopolskie', 'Nowy Sącz', 'Znamirowice to punkt, w którym Dunajec staje się częścią malowniczego Jeziora Rożnowskiego. Strome brzegi i znaczna głębokość sprawiają, że jest to doskonałe stanowisko dla łowców sandaczy oraz sumów. Wzdłuż podwodnych stoków starego koryta często grupują się potężne stada leszczy i dorodnych płoci. Spinningowanie z wysokich, skalistych brzegów wymaga precyzji, ale nagradza braniami pięknych, pasiastych okoni. Woda w tym rejonie jest mocno natleniona dzięki stałemu przepływowi rzeki, co sprzyja aktywności ryb przez całą dobę. Dla zmotoryzowanych wędkarzy dostęp do wody jest ułatwiony dzięki licznym ośrodkom wypoczynkowym zlokalizowanym w tej okolicy.', 'PZW Nowy Sącz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70321, 'Podgórska', 'Zalewowe koryto rzeki', 300.0, 8.0, 'Piaszczysto-muliste', 'Podwodne stoki koryta', 'Sandacz, Sum, Leszcz', 'Kraina brzany', 'Zbiornik Rożnowski', true);

-- LIWIEC

-- Spot 323: Oszczerze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70322, 'Liwiec - Oszczerze (Naturalne Zakola)', 'liwiec-oszczerze', 'RIVER', 52.2941003, 22.0224747, 'Mazowieckie', 'Siedlce', 'Liwiec w Oszczerzu to niewielka rzeka nizinna o bardzo naturalnym i krętym korycie. Piaszczyste dno z lokalnymi naniesieniami mułu sprzyja bytowaniu dorodnych linów oraz płoci. Uciąg jest tu łagodny, co pozwala na precyzyjne operowanie lekkim zestawem spławikowym. Liczne zakola z podmytymi brzegami są idealnym stanowiskiem dla szczupaków czatujących w cieniu traw. Wędkarze gruntowi często znajdują tu spokojne zatoczki idealne do zasiadki na lina lub karasia. Przejrzystość wody jest wysoka, co wymaga od wędkarza zachowania pełnej dyskrecji na brzegu.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70322, 'Nizinna Mała', 'Meandrująca, naturalna', 8.0, 1.1, 'Piaszczyste', 'Podmyte brzegi', 'Szczupak, Lin, Płoć', 'Kraina leszcza', false);

-- Spot 324: Wyszków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70323, 'Liwiec - Wyszków (Piaszczyste Płanie)', 'liwiec-wyszkow-siedlecki', 'RIVER', 52.3064406, 22.0005102, 'Mazowieckie', 'Węgrów', 'Odcinek w Wyszkowie charakteryzuje się wyrównanym nurtem i szerokim korytem o piaszczystym podłożu. Rzeka płynie tu przez otwarte tereny łąkowe, co ułatwia rzuty dłuższą odległościówką lub lekkim feederem. Podmyte burty i pasy roślinności zanurzonej skrywają liczne okonie, które agresywnie reagują na małe jigi. To doskonałe miejsce dla spinningistów polujących na klenie żerujące w głównym prądzie wody. Uciąg rzeki jest stabilny, co umożliwia skuteczne nęcenie pola łowiska przy użyciu zanęt sypkich. Dzięki dobremu dostępowi do wody jest to popularne miejsce na szybki wypad z wędką po pracy.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70323, 'Nizinna Mała', 'Szerokie płanie, nurt łagodny', 12.0, 1.2, 'Piaszczyste', 'Pasy roślinności', 'Kleń, Okoń, Jaź', 'Kraina leszcza', false);

-- Spot 325: Karczewiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70324, 'Liwiec - Karczewiec (Leśne Zatory)', 'liwiec-karczewiec', 'RIVER', 52.3207754, 21.9824995, 'Mazowieckie', 'Węgrów', 'Liwiec w Karczewcu to odcinek o dzikim charakterze z dużą ilością zwalonych pni drzew w korycie. Rzeka mocno tu meandruje, żłobiąc głębokie rynny pod brzegowymi olchami i wierzbami. To wymarzone stanowisko dla łowców szczupaków, którzy precyzyjnie obławiają podwodne karczowiska. Dno piaszczysto-żwirowe sprzyja aktywności jazi, które chętnie żerują na granicy nurtu i zastoisk. Uciąg rzeki jest tu zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu. Cisza i brak bliskiej zabudowy sprawiają, że można tu liczyć na kontakt z medalowym okazem.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70324, 'Nizinna Mała', 'Nieuregulowane, liczne zatory', 10.0, 1.5, 'Piasek i żwir', 'Zwalone drzewa', 'Szczupak, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 326: Grodzisk
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70325, 'Liwiec - Grodzisk (Przykosy)', 'liwiec-grodzisk', 'RIVER', 52.3388164, 21.9816927, 'Mazowieckie', 'Węgrów', 'W Grodzisku koryto Liwca nieco się rozszerza, zachowując przy tym piaszczyste i czyste podłoże. Rzeka posiada tu liczne piaszczyste przykosy, które są bankowymi miejscami na spotkanie z żerującym kleniem. Wędkarze stacjonarni z sukcesami stosują tu metodę lekkiego feedera, celując w stadne płocie. Nurt jest jednostajny i łagodny, co pozwala na bardzo naturalną prezentację przynęty na spławiku. Przy brzegach występują kępy grążeli, w których cieniu latem chętnie ustawiają się wyrośnięte okonie. Dogodny dojazd przez łąki sprawia, że jest to chętnie wybierane miejsce na całodniowe zasiadki rodzinne.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70325, 'Nizinna Mała', 'Szeroka rzeka łąkowa', 15.0, 1.0, 'Piaszczyste', 'Piaszczyste przykosy', 'Kleń, Płoć, Okoń', 'Kraina leszcza', false);

-- Spot 327: Jarnice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70326, 'Liwiec - Jarnice (Rynny)', 'liwiec-jarnice', 'RIVER', 52.3567408, 21.9792178, 'Mazowieckie', 'Węgrów', 'Odcinek w Jarnicach to malownicza rzeka nizinna płynąca szerokim korytem o urozmaiconym dnie. Występują tu głębokie rynny na zewnętrznych łukach, w których często stacjonują wyrośnięte leszcze. To idealna lokalizacja dla spinningistów polujących na klenie z wykorzystaniem małych woblerów i smużaków. Uciąg jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu stad jazi w polu łowienia. Pasy trzcin przy brzegach stanowią naturalną osłonę przed wiatrem i doskonałe miejsce dla szczupaka. Przejrzysta woda wymaga od wędkarza stosowania cienkich przyponów fluorocarbonowych dla lepszych efektów.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70326, 'Nizinna Mała', 'Naturalne, głębokie rynny', 14.0, 1.6, 'Piasek i glina', 'Trzcinowiska', 'Leszcz, Jaź, Kleń', 'Kraina leszcza', false);

-- Spot 328: Liw (Pod Zamkiem)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70327, 'Liwiec - Liw (Pod Zamkiem)', 'liwiec-liw-zamek', 'RIVER', 52.3745042, 21.9726292, 'Mazowieckie', 'Węgrów', 'Liwiec w miejscowości Liw to techniczne łowisko z głębokimi rynnami wymytymi w rejonie mostu. Dno jest tu twarde, piaszczysto-żwirowe, z licznymi załamaniami nurtu sprzyjającymi drapieżnikom. Pod murami historycznego zamku rzeka płynie spokojniej, tworząc idealne warunki dla lina i wzdręgi. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy opaskach. Uciąg rzeki jest stabilny i pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon. Bardzo dobry dostęp do wody czyni to miejsce jednym z najpopularniejszych punktów wędkarskich na tej rzece.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70327, 'Nizinna Mała', 'Uregulowane koryto, dno twarde', 16.0, 1.4, 'Piasek i żwir', 'Most, kamienne opaski', 'Okoń, Jaź, Lin', 'Kraina leszcza', false);

-- Spot 329: Węgrów (Południe/Wylot)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70328, 'Liwiec - Węgrów (Wylot)', 'liwiec-wegrow-wylot', 'RIVER', 52.3851757, 21.9964577, 'Mazowieckie', 'Węgrów', 'Liwiec w Węgrowie na tym odcinku charakteryzuje się szerokim korytem i piaszczystym dnem z licznymi rynnami. Woda płynie tu stabilnym nurtem, co sprzyja bytowaniu dorodnych kleni oraz jazi zbierających owady z powierzchni. Wędkarze stacjonarni z sukcesami stosują metodę lekkiego feedera, nęcąc ryby w głębszych partiach głównego nurtu. Przy brzegach występują kępy roślinności zanurzonej, które stanowią doskonałe schronienie dla wyrośniętych okoni. Uciąg rzeki jest umiarkowany i pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon. Dojazd do wody jest bardzo dogodny, co czyni to miejsce popularnym punktem wypadowym dla lokalnych pasjonatów.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70328, 'Nizinna Mała', 'Szeroka, nurt stabilny', 18.0, 1.4, 'Piaszczyste', 'Pasy roślinności', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 330: Węgrów (Centrum/Miejski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70329, 'Liwiec - Węgrów (Miejski)', 'liwiec-wegrow-miejski', 'RIVER', 52.4025858, 22.0045732, 'Mazowieckie', 'Węgrów', 'Miejski odcinek w Węgrowie to techniczne łowisko z uregulowanymi brzegami i betonowymi opaskami pod mostem. Dno jest tu twarde, piaszczysto-żwirowe, co przyciąga liczne stada jelców oraz płoci żerujących w rynnach. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy murkach oporowych. Woda jest wyjątkowo czysta, co pozwala na obserwację żerujących jazi w cieniu filarów mostowych. Uciąg jest umiarkowany i przewidywalny, umożliwiając idealną prezentację przynęty na bardzo delikatnych żyłkach. Pomimo miejskiego charakteru, rzeka skrywa tu medalowe okazy ryb reofilnych, które doskonale reagują na drobne przynęty.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70329, 'Nizinna Mała', 'Uregulowane koryto miejskie', 15.0, 1.2, 'Piasek i żwir', 'Most, opaski betonowe', 'Jelec, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 331: Węgrów (Północ/Meandry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70330, 'Liwiec - Węgrów (Północne Meandry)', 'liwiec-wegrow-polnoc', 'RIVER', 52.4171155, 21.9859944, 'Mazowieckie', 'Węgrów', 'Na północ od Węgrowa Liwiec zaczyna mocno meandrować, tworząc głębokie jamy na zewnętrznych łukach koryta. Dno jest piaszczyste z wyraźnymi przykosami, które są bankowymi miejscami na spotkanie z żerującym kleniem. Wzdłuż brzegów rosną gęste pasy trzcin, będące naturalną kryjówką dla szczupaków czatujących na ukleje. Wędkarze spławikowi z sukcesami stosują tu metodę bolonki, puszczając zestaw na długich dystansach wzdłuż krawędzi nurtu. Uciąg rzeki w tym miejscu jest zmienny, przyspieszając na przewężeniach i zwalniając w szerokich zakolach. Cisza panująca w tej okolicy i brak bliskiej zabudowy gwarantują spokojną zasiadkę w pełnym kontakcie z naturą.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70330, 'Nizinna Mała', 'Naturalne meandry', 12.0, 1.5, 'Piaszczyste', 'Trzcinowiska', 'Szczupak, Kleń, Jaź', 'Kraina leszcza', false);

-- Spot 332: Starawieś (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70331, 'Liwiec - Starawieś (Klonowa)', 'liwiec-starawies-klonowa', 'RIVER', 52.427347, 21.961709, 'Mazowieckie', 'Węgrów', 'Odcinek w Starowsi to kwintesencja mazowieckiej rzeki o krystalicznie czystej wodzie i urokliwych, piaszczystych plażach. Koryto rzeki charakteryzuje się tu równomiernym uciągiem oraz dnem usianym lokalnie żwirowymi rafkami. To wymarzone miejsce dla spinningistów polujących na klenie z wykorzystaniem smużaków oraz mikro-woblerów. Podmyte korzenie starych wierzb skrywają wyrośnięte okonie, które agresywnie atakują przepływający narybek. Niskie brzegi ułatwiają dostęp do wody, jednak wymagają od wędkarza pełnego maskowania ze względu na przejrzystość toni. Miejsce to słynie z doskonałych warunków do wieczornego łowienia jazi metodą suchej muchy.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70331, 'Nizinna Mała', 'Naturalna, łąkowa', 14.0, 1.0, 'Piaszczyste', 'Podmyte korzenie', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 333: Starawieś (Punkt 2/Przewężenie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70332, 'Liwiec - Starawieś (Rynna)', 'liwiec-starawies-rynna', 'RIVER', 52.4441526, 21.9492978, 'Mazowieckie', 'Węgrów', 'W tym rejonie Liwiec przedziera się przez naturalne przewężenie, co skutkuje wyraźnym przyspieszeniem nurtu wody. Dno jest tu twarde, piaszczysto-gliniaste, z głęboką rynną wyżłobioną pośrodku koryta rzeki. Wędkarze gruntowi z sukcesami stosują tu metodę lekkiego feedera, celując w dorodne stadne płocie oraz leszcze. Uciąg jest na tyle silny, że wymaga stosowania dociążonych koszyków zanętowych zdolnych utrzymać zestaw w nurcie. Stanowiska brzegowe są naturalne i częściowo osłonięte wysoką trawą, co zapewnia intymność podczas łowienia. To wybitnie techniczny odcinek rzeki, który nagradza precyzyjne nęcenie i umiejętność czytania zmian w strukturze dna.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70332, 'Nizinna Mała', 'Nurt przyspieszony, rynna', 10.0, 1.8, 'Glina i piasek', 'Rynna prądowa', 'Płoć, Leszcz, Jaź', 'Kraina leszcza', false);

-- Spot 334: Borzychy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70333, 'Liwiec - Borzychy (Leśny Spokój)', 'liwiec-borzychy-las', 'RIVER', 52.4513191, 21.9222048, 'Mazowieckie', 'Liw', 'Odcinek w Borzychach to rzeka o wybitnie dzikim charakterze, płynąca w bezpośrednim sąsiedztwie kompleksów leśnych. Dno jest tu mocno urozmaicone zatorami z pni drzew, które stanowią bankowe kryjówki dla rekordowych szczupaków. Spinningiści znajdą tutaj doskonałe warunki do prowadzenia gum w opadzie w głębokich wymyciach nurtu. Woda jest wyjątkowo natleniona, co sprzyja aktywności wyrośniętych okoni oraz kleni żerujących w głównym prądzie. Uciąg rzeki jest umiarkowany, a brzegi są wysokie i porośnięte wikliną, co wymaga od wędkarza dużej sprawności. Niska presja wędkarska sprawia, że ryby żerują tu śmiało, czyniąc to łowisko jednym z najciekawszych w regionie.', 'PZW Siedlce');

