-- Spot 335: Borzychy (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70334, 'Liwiec - Borzychy (Piaszczyste Meandry)', 'liwiec-borzychy-meandry', 'RIVER', 52.4607167, 21.8967281, 'Mazowieckie', 'Węgrów', 'Liwiec w rejonie Borzychów charakteryzuje się piaszczystym dnem oraz licznymi, malowniczymi meandrami. Woda jest tu wyjątkowo czysta, co sprzyja bytowaniu ostrożnych kleni i jazi. Głębokość w rynnach rzadko przekracza półtora metra, jednak lokalne dołki pod brzegami mogą być znacznie głębsze. Spinningiści powinni skupić się na obławianiu nawisów drzew, gdzie drapieżniki czatują na owady i drobnicę. Uciąg rzeki jest łagodny, co pozwala na komfortowe łowienie lekkimi zestawami spławikowymi typu bat lub bolonka. Ze względu na przejrzystość toni, kluczowe dla sukcesu jest ciche poruszanie się wzdłuż trawiastego nabrzeża.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70334, 'Nizinna Mała', 'Naturalne meandry', 12.0, 1.2, 'Piaszczyste', 'Podmyte brzegi', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 336: Paplin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70335, 'Liwiec - Paplin (Przykosy)', 'liwiec-paplin', 'RIVER', 52.4701349, 21.8709939, 'Mazowieckie', 'Łochów', 'Odcinek w Paplinie oferuje wędkarzom dostęp do rzeki o urozmaiconej rzeźbie dna z piaszczystymi przykosami. Nurt w tym miejscu jest stabilny, co ułatwia precyzyjne nęcenie pola łowiska przy użyciu zanęt sypkich. W korycie rzeki występują liczne kępy roślinności zanurzonej, które są naturalnym schronieniem dla wyrośniętych okoni. To doskonałe miejsce do polowania na jaziową „srebrną łuskę” przy użyciu technik przepływanki. Brzegi są tu stosunkowo niskie, co zapewnia komfortowe warunki do rozstawienia profesjonalnego stanowiska wędkarskiego. Wieczorami na płytszych przelewach często widać aktywność boleni patrolujących krawędź głównego nurtu rzeki.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70335, 'Nizinna Mała', 'Szeroka, nurt stabilny', 15.0, 1.3, 'Piasek i żwir', 'Piaszczyste przykosy', 'Jaź, Okoń, Boleń', 'Kraina leszcza', false);

-- Spot 337: Kalinowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70336, 'Liwiec - Kalinowiec (Łąkowa Płania)', 'liwiec-kalinowiec', 'RIVER', 52.475172, 21.8426399, 'Mazowieckie', 'Łochów', 'Liwiec w Kalinowcu płynie szerokim korytem przez tereny o typowo nizinnym, łąkowym charakterze. Dno jest tu w większości twarde i piaszczyste, co minimalizuje ryzyko częstych zaczepów przy łowieniu z gruntu. Gatunkiem dominującym na tym odcinku jest płoć, która doskonale reaguje na nęcenie drobną frakcją zanęty. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia woblerów w poszukiwaniu szczupaków czających się w trzcinowiskach. Głębokość jest wyrównana, co sprzyja systematycznemu badaniu rzeki metodą lekkiego spinningu lub bocznego troka. Niska presja wędkarska w tym rejonie sprawia, że ryby żerują śmiało nawet w godzinach południowych.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70336, 'Nizinna Mała', 'Szeroka, otwarta rzeka', 18.0, 1.1, 'Piaszczyste', 'Trzcinowiska', 'Płoć, Szczupak, Okoń', 'Kraina leszcza', false);

-- Spot 338: Purzec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70337, 'Liwiec - Purzec (Górny Bieg)', 'liwiec-purzec', 'RIVER', 52.2192805, 22.2823519, 'Mazowieckie', 'Siedlce', 'Górny bieg Liwca w Purzcu to kameralna woda o niewielkiej szerokości i bardzo zmiennej głębokości. Rzeka płynie tu wąskim korytem, wymywając głębokie jamy pod korzeniami nadbrzeżnych olch i wierzb. Jest to wymarzone miejsce dla pasjonatów technicznego spinningu polujących na klenie przy użyciu smużaków. Dno piaszczysto-muliste obfituje w naturalny pokarm, co przyciąga stadka dorodnych płoci oraz jelców. Uciąg wody jest tu zróżnicowany, przyspieszając na przewężeniach i zwalniając w urokliwych, zacisznych zatoczkach. Stanowiska brzegowe są naturalne i wymagają od wędkarza pełnego kamuflażu oraz cichego podejścia do lustra wody.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70337, 'Nizinna Mała', 'Wąska struga, meandrująca', 5.0, 0.8, 'Piasek i muł', 'Podmyte korzenie', 'Kleń, Płoć, Jelec', 'Kraina leszcza', false);

-- Spot 339: Strzała
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70338, 'Liwiec - Strzała (Miejska Struga)', 'liwiec-strzała', 'RIVER', 52.2128979, 22.254652, 'Mazowieckie', 'Siedlce', 'Odcinek rzeki w Strzale charakteryzuje się dość regularnym korytem o umiarkowanym uciągu i piaszczystym podłożu. Rzeka przepływa tu przez otwarte tereny, co sprzyja łowieniu metodą odległościową przy użyciu lekkich spławików. To doskonały poligon dla łowców białorybu, gdzie dominują płocie, krąpie oraz okresowo pojawiające się jazie. Woda jest dobrze natleniona, co przekłada się na wysoką kondycję i waleczność tutejszych ryb rzecznych. Nieliczne pasy trzcin przy brzegach stanowią bankowe kryjówki dla szczupaków żerujących na drobnej uklei. Dzięki bliskości Siedlec, miejsce to jest chętnie odwiedzane przez wędkarzy szukających szybkiego relaksu po pracy.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70338, 'Nizinna Mała', 'Uregulowane koryto, nurt stały', 6.0, 0.9, 'Piaszczyste', 'Pasy trzcin', 'Płoć, Krąp, Szczupak', 'Kraina leszcza', false);

-- Spot 340: Chodów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70339, 'Liwiec - Chodów (Zakola Podmiejskie)', 'liwiec-chodów', 'RIVER', 52.209721, 22.2254051, 'Mazowieckie', 'Siedlce', 'Liwiec w Chodowie to urokliwa struga o naturalnym charakterze, wijąca się wśród podmiejskich łąk i zagajników. Dno jest tu mocno urozmaicone, piaszczyste z lokalnymi dołkami o twardym, gliniastym podłożu na zakrętach. To idealne miejsce na wiosenną zasiadkę z lekkim feederem w poszukiwaniu pierwszych aktywnych płoci i jelców. Nurt rzeki jest stabilny, co pozwala na precyzyjną prezentację przynęty na bardzo cienkich żyłkach przyponowych. Spinningiści z sukcesami obławiają tutejsze rynny małymi obrotówkami, celując w żerujące w toni okonie. Kameralna atmosfera tego łowiska sprzyja wyciszeniu, oferując jednocześnie szansę na kontakt z dziką fauną rzeczną.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70339, 'Nizinna Mała', 'Naturalna struga, kręta', 5.5, 1.0, 'Piasek i glina', 'Lokalne rynny', 'Płoć, Jelec, Okoń', 'Kraina leszcza', false);

-- Spot 341: Wyłazy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70340, 'Liwiec - Wyłazy (Łąkowy Spokój)', 'liwiec-wylazy', 'RIVER', 52.2196515, 22.2007897, 'Mazowieckie', 'Siedlce', 'Liwiec w Wyłazach to kwintesencja kameralnej rzeki nizinnej płynącej przez otwarte tereny łąkowe. Koryto jest tu wąskie, a dno w przeważającej mierze piaszczyste z nielicznymi kępami roślinności zanurzonej. To idealne miejsce dla łowców kleni i jazi, którzy preferują precyzyjne podawanie małych woblerów pod nawisy traw. Uciąg wody jest stabilny, co pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach spławikowych. Przejrzystość wody wymusza na wędkarzu zachowanie dużej ostrożności i ciche poruszanie się wzdłuż linii brzegowej. Miejsce to rzadko odwiedzane przez tłumy, gwarantuje spokój i bliski kontakt z naturą Mazowsza.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70340, 'Nizinna Mała', 'Wąska struga, piaszczysta', 5.0, 0.9, 'Piaszczyste', 'Kępy roślinności', 'Kleń, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 342: Kisielany-Żmichy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70341, 'Liwiec - Kisielany-Żmichy (Rynny)', 'liwiec-kisielany-zmichy', 'RIVER', 52.2282407, 22.1749281, 'Mazowieckie', 'Siedlce', 'Odcinek w Kisielanach-Żmichach charakteryzuje się licznymi meandrami i wyraźnie zaznaczonymi rynnami na zewnętrznych łukach koryta. Rzeka żłobi tu głębsze dołki pod podmytymi brzegami, które stanowią bankowe kryjówki dla wyrośniętych okoni. Dno piaszczyste z lokalnymi naniesieniami mułu sprzyja bytowaniu stadnych płoci oraz okresowo pojawiających się leszczy. Spinningiści z sukcesami obławiają tutejsze spowolnienia nurtu, stosując lekkie obrotówki i twistery na małych główkach. Uciąg jest umiarkowany, co ułatwia punktowe nęcenie łowiska przy użyciu lekkich mieszanek zanętowych. Dzięki naturalnemu ukształtowaniu terenu, każdy zakręt rzeki oferuje nowe, technicznie ciekawe stanowisko do oddania rzutu.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70341, 'Nizinna Mała', 'Meandrująca, głębokie łuki', 6.5, 1.2, 'Piasek i muł', 'Podmyte burty', 'Okoń, Płoć, Leszcz', 'Kraina leszcza', false);

-- Spot 343: Niwiski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70342, 'Liwiec - Niwiski (Płanie)', 'liwiec-niwiski', 'RIVER', 52.2365704, 22.1488442, 'Mazowieckie', 'Siedlce', 'Liwiec w Niwiskach płynie łagodnie, tworząc szerokie i stosunkowo płytkie piaszczyste płanie idealne do brodzenia. Koryto jest tu częściowo zarośnięte roślinnością wynurzoną, co stwarza doskonałe warunki tlenowe dla ryb prądolubnych. To wymarzone stanowisko dla miłośników lekkiej przepływanki celujących w dorodne jelce oraz płocie. Spinningiści znajdą tutaj liczne kępy grążeli, pod którymi w słoneczne dni chętnie ustawiają się szczupaki. Uciąg wody jest znikomy, co pozwala na stosowanie najczulszych zestawów z bardzo lekkimi spławikami typu piórko. To łowisko o relatywnie niskiej presji, nagradzające wytrwałych wędkarzy pięknym ubarwieniem dzikich ryb rzecznych.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70342, 'Nizinna Mała', 'Szeroka i płytka', 8.0, 0.7, 'Piaszczyste', 'Grążele, roślinność wynurzona', 'Jelec, Płoć, Szczupak', 'Kraina leszcza', false);

-- Spot 344: Żuków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70343, 'Liwiec - Żuków (Bystrza)', 'liwiec-zukow', 'RIVER', 52.2429233, 22.1210603, 'Mazowieckie', 'Węgrów', 'W rejonie Żukowa rzeka przedziera się przez naturalne zwężenia, co powoduje lokalne przyspieszenie nurtu i natlenienie wody. Dno jest tu twarde, piaszczysto-żwirowe, z wyraźnymi wymyciami pod starymi olszynami rosnącymi tuż przy wodzie. To klasyczne stanowisko kleniowe, gdzie ryby doskonale reagują na smużaki i małe przynęty gumowe. Wędkarze gruntowi z sukcesami stosują tu metodę przystawki, obławiając głębsze rynny w poszukiwaniu jazi. Uciąg rzeki wymaga stosowania dociążonych zestawów, które stabilnie utrzymają przynętę w strefie intensywnego żerowania ryb. Miejsce to zapewnia intymną atmosferę i daje szansę na kontakt z walecznymi mieszkańcami mazowieckich rzek.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70343, 'Nizinna Mała', 'Nurt przyspieszony, koryto twarde', 6.0, 1.0, 'Piasek i żwir', 'Podmyte korzenie olch', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 345: Zaliwie-Piegawki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70344, 'Liwiec - Zaliwie-Piegawki (Plaże)', 'liwiec-zaliwie-piegawki', 'RIVER', 52.2520013, 22.0952482, 'Mazowieckie', 'Mokobody', 'Zaliwie-Piegawki oferują dostęp do rzeki o wyjątkowo urokliwym, łąkowym charakterze i krystalicznie czystej wodzie. Liwiec w tym miejscu tworzy rozległe piaszczyste łachy, które są ulubionym żerowiskiem stadnych płoci i jelców. To idealna lokalizacja na letni wypad z batem, wymagająca jednak pełnego maskowania ze strony wędkarza. Nurt jest stabilny i przewidywalny, co umożliwia precyzyjne operowanie zestawem spławikowym na długich dystansach. Pod nawisami traw przy brzegach często meldują się ładne okonie, które agresywnie atakują przepływający narybek. Dogodny dojazd przez łąki sprawia, że jest to chętnie wybierane miejsce na kilkugodzinne sesje z wędką.', 'PZW Siedlce');

