VALUES (70344, 'Nizinna Mała', 'Otwarta rzeka łąkowa', 10.0, 0.8, 'Piaszczyste', 'Piaszczyste łachy', 'Płoć, Jelec, Okoń', 'Kraina leszcza', false);

-- Spot 346: Zaliwie-Szpinki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70345, 'Liwiec - Zaliwie-Szpinki (Karczowiska)', 'liwiec-zaliwie-szpinki', 'RIVER', 52.2688409, 22.0848568, 'Mazowieckie', 'Mokobody', 'Odcinek w Zaliwiu-Szpinkach słynie z głębokich wymyć koryta i dużej ilości naturalnych przeszkód w postaci zatopionych gałęzi. Rzeka mocno tu meandruje, a wysokie brzegi stanowią doskonały punkt obserwacyjny do lokalizacji żerujących ryb. To wybitnie techniczne łowisko szczupakowe, gdzie precyzyjne podanie gumy w pobliżu karczu jest kluczem do sukcesu. Dno piaszczysto-gliniaste obfituje w kryjówki dla wyrośniętych jazi, które chętnie pobierają przynęty naturalne w toni. Uciąg rzeki pozwala na swobodne stosowanie lekkich metod feederowych z koszykami o małej gramaturze. Miejsce to gwarantuje ciszę i spokój, oferując jednocześnie emocjonujące hole ryb w trudnym, pełnym zaczepów terenie.', 'PZW Siedlce');

