VALUES (70345, 'Nizinna Mała', 'Mocno meandrująca, zatory', 9.0, 1.5, 'Piasek i glina', 'Zwalone gałęzie, karcze', 'Szczupak, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 347: Kapuściaki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70346, 'Liwiec - Kapuściaki (Łąkowe Zakola)', 'liwiec-kapusciaki', 'RIVER', 52.2813553, 22.063568, 'Mazowieckie', 'Mokobody', 'Liwiec w Kapuściakach to odcinek o niezwykle naturalnym charakterze, wijący się pośród rozległych nadliwieckich łąk. Koryto rzeki jest tutaj stosunkowo wąskie, co sprzyja precyzyjnemu łowieniu lekkim spinningiem pod przeciwległym brzegiem. Dno piaszczyste z licznymi rynnami i dołkami tworzy idealne warunki dla stadnych jelców oraz dorodnych płoci. Woda zachowuje wysoką przejrzystość, co wymaga od wędkarza pełnej dyskrecji i cichego podchodzenia do linii brzegowej. Podmyte korzenie nadbrzeżnych wierzb stanowią bankowe kryjówki dla kleni, które chętnie reagują na małe woblery i smużaki. Uciąg rzeki jest umiarkowany i przewidywalny, co pozwala na skuteczne nęcenie i utrzymanie ryb w polu łowienia przez dłuższy czas.', 'PZW Siedlce');

