-- Spot 348: Starowola
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70347, 'Liwiec - Starowola (Szerokie Płanie)', 'liwiec-starowola', 'RIVER', 52.4996858, 21.717944, 'Mazowieckie', 'Łochów', 'Odcinek rzeki w Starowoli charakteryzuje się znacznym rozszerzeniem koryta i występowaniem szerokich piaszczystych płani. Liwiec płynie tu majestatycznie, żłobiąc dno o charakterze piaszczysto-żwirowym, co sprzyja bytowaniu dużych jazi. Wędkarze stacjonarni z sukcesami stosują tu metodę lekkiego feedera, nęcąc ryby na krawędzi rynny głównego nurtu. Przy brzegach występują pasy trzcin oraz kępy grążeli, które są naturalnym terytorium łowieckim dla szczupaków. Uciąg wody stabilizuje się, co pozwala na swobodne operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Dzięki otwartemu terenowi dostęp do wody jest bardzo dogodny, a liczne piaszczyste plaże ułatwiają bezpieczne podebranie ryby.', 'PZW Siedlce');

