VALUES (70347, 'Nizinna Mała', 'Szeroka rzeka łąkowa', 20.0, 1.3, 'Piasek i żwir', 'Piaszczyste łachy', 'Jaź, Płoć, Szczupak', 'Kraina leszcza', false);

-- Spot 349: Zawiszyn (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70348, 'Liwiec - Zawiszyn (Leśna Głusza)', 'liwiec-zawiszyn-las', 'RIVER', 52.5117618, 21.6949613, 'Mazowieckie', 'Łochów', 'W Zawiszynie Liwiec przedziera się przez zwarte kompleksy leśne, co nadaje mu dzikiego i surowego charakteru. Koryto rzeki usiane jest zwalonymi pniemi drzew, które tworzą techniczne i wymagające stanowiska dla spinningistów. To wymarzone miejsce dla łowców okoni, które grupują się w cieniu podwodnych karczowisk i zatorów. Dno jest tu mocno urozmaicone, piaszczysto-gliniaste, z głębokimi rynnami wymytymi na zewnętrznych łukach rzeki. Uciąg rzeki wyraźnie przyspiesza na przewężeniach, co sprzyja natlenieniu wody i wysokiej aktywności ryb reofilnych. Ze względu na trudny teren, łowisko to cieszy się niską presją, oferując szansę na kontakt z niewypłoszonymi okazami.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70348, 'Nizinna Mała', 'Nieuregulowane koryto leśne', 15.0, 1.6, 'Piasek i glina', 'Zwalone kłody', 'Okoń, Kleń, Szczupak', 'Kraina leszcza', false);

-- Spot 350: Zawiszyn (Punkt 2 / Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70349, 'Liwiec - Zawiszyn (Rynna Mostowa)', 'liwiec-zawiszyn-most', 'RIVER', 52.5088657, 21.6656005, 'Mazowieckie', 'Łochów', 'Odcinek przy moście w Zawiszynie to techniczne łowisko z głębokimi rynnami wymytymi pod filarami konstrukcji. Rzeka płynie tu szeroko, a twarde piaszczysto-kamieniste dno sprzyja żerowaniu dużych kleni i jazi. Wędkarze spławikowi z sukcesami stosują metodę przepływanki, puszczając zestaw wzdłuż brzegowych opasek faszynowych. Spinningiści cenią to miejsce za obecność boleni, które regularnie pokazują się na piaszczystych przykosach poniżej mostu. Uciąg wody jest stały i umiarkowany, co ułatwia precyzyjne nęcenie i utrzymanie stad białorybu w polu widzenia. Bardzo dobry dojazd do samej wody sprawia, że jest to jedno z najpopularniejszych stanowisk w tej części regionu.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70349, 'Nizinna Mała', 'Uregulowane pod mostem', 22.0, 1.8, 'Piasek i kamień', 'Filary mostu, faszyna', 'Kleń, Jaź, Boleń', 'Kraina leszcza', false);

-- Spot 351: Borzymy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70350, 'Liwiec - Borzymy (Koniec Biegu)', 'liwiec-borzymy', 'RIVER', 52.5112915, 21.6358493, 'Mazowieckie', 'Jarchlino', 'Liwiec w Borzymach staje się rzeką dostojną i głęboką, zbliżając się do końcowego etapu swojego biegu. Dno jest tu w większości piaszczyste z lokalnymi naniesieniami mułu, co tworzy idealne warunki dla rekordowych leszczy. To doskonałe miejsce dla spinningistów polujących na szczupaki, którzy obławiają liczne zatoczki z roślinnością wynurzoną. Uciąg rzeki jest tu znikomy, co pozwala na stosowanie najdelikatniejszych technik feederowych z czułymi szczytówkami. Brzegi są niskie i trawiaste, co zapewnia ogromny komfort podczas długich, wielogodzinnych zasiadek z wędką. Czystość wody wciąż pozostaje na wysokim poziomie, co przekłada się na waleczność i zdrową kondycję tutejszych ryb.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70350, 'Nizinna Średnia', 'Spokojna rzeka przedujściowa', 25.0, 2.0, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', false);

-- Spot 352: Kaliska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70351, 'Liwiec - Kaliska (Przedujście do Bugu)', 'liwiec-kaliska', 'RIVER', 52.5277917, 21.622851, 'Mazowieckie', 'Łochów', 'Kaliska to jeden z ostatnich odcinków Liwca przed jego ostatecznym połączeniem z wodami potężnego Bugu. Rzeka rozlewa się tu szeroko, tworząc rybne płanie o urozmaiconym, piaszczysto-żwirowym podłożu. To strategiczne miejsce dla łowców białorybu, gdzie migrujące stada jazi i płoci grupują się przed wejściem w nurt Bugu. Spinningiści z sukcesami polują tutaj na sandacze i sumy, które coraz częściej zapuszczają się w ujściowy odcinek rzeki. Uciąg wody jest umiarkowany i przewidywalny, co umożliwia idealną prezentację przynęty na każdą odległość. Malownicze otoczenie i bliskość ujścia sprawiają, że wędkarz może liczyć tu na branie ryby życia w każdych warunkach.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70351, 'Nizinna Średnia', 'Szerokie ujście rzeki', 30.0, 2.2, 'Piasek i żwir', 'Piaszczyste przykosy', 'Jaź, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 353: Pogorzelec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70352, 'Liwiec - Pogorzelec (Szerokie Przykosy)', 'liwiec-pogorzelec', 'RIVER', 52.5416172, 21.6031596, 'Mazowieckie', 'Łochów', 'Liwiec w Pogorzelcu to odcinek o szerokim korycie i piaszczystym dnie, idealny do brodzenia podczas letnich niżówek. Rzeka płynie tu dostojnie, tworząc liczne przykosy, na których chętnie żerują stadne klenie oraz jazie. Spinningiści cenią to miejsce za populację szczupaka, który czatuje w pasach roślinności przybrzeżnej. Woda jest wyjątkowo przejrzysta, co wymaga od wędkarza stosowania cienkich przyponów z fluorocarbonu. Uciąg jest umiarkowany, co pozwala na skuteczne nęcenie łowiska lekkimi zanętami spożywczymi. Ze względu na walory rekreacyjne okolicy, najlepiej łowić tu o świcie, gdy presja turystyczna jest znikoma.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70352, 'Nizinna Mała', 'Szeroka, nurt stabilny', 24.0, 1.2, 'Piaszczyste', 'Piaszczyste przykosy', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', false);

-- Spot 354: Puste Łąki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70353, 'Liwiec - Puste Łąki (Meandry)', 'liwiec-puste-laki', 'RIVER', 52.5595068, 21.5982811, 'Mazowieckie', 'Wyszków', 'Odcinek w Pustych Łąkach to jeden z najbardziej malowniczych fragmentów Liwca, wijący się wśród otwartych przestrzeni i lasów sosnowych. Rzeka posiada tu naturalne meandry z głębszymi rynnami na zewnętrznych łukach, dochodzącymi do półtora metra głębokości. To doskonałe stanowisko dla łowców okoni, które doskonale reagują na małe gumy prowadzone agresywnym skokiem po piasku. Wędkarze spławikowi z sukcesami łowią tu dorodne płocie oraz wzdręgi, wykorzystując metodę cichego podejścia do brzegu. Nurt jest stabilny, co umożliwia bardzo naturalną prezentację przynęty na delikatnych zestawach z długim wędziskiem. Niska roślinność brzegowa ułatwia rzuty, ale zmusza wędkarza do zachowania pełnej dyskrecji przed płochliwymi rybami.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70353, 'Nizinna Mała', 'Naturalne meandry', 20.0, 1.4, 'Piasek i żwir', 'Podmyte burty', 'Okoń, Płoć, Wzdręga', 'Kraina leszcza', false);

-- Spot 355: Nadkole
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70354, 'Liwiec - Nadkole (Podskarbie)', 'liwiec-nadkole', 'RIVER', 52.5763581, 21.587562, 'Mazowieckie', 'Wyszków', 'Liwiec w Nadkolu przygotowuje się do połączenia z Bugiem, nabierając cech większej rzeki nizinnej o zróżnicowanym uciągu. Wysokie brzegi porośnięte starymi drzewami tworzą głębokie cienie, w których chętnie przebywają wyrośnięte klenie i bolenie. Dno jest piaszczysto-żwirowe, z licznymi "karczami" stanowiącymi bankowe schronienia dla drapieżników czekających na drobnicę. To strategiczne miejsce, gdzie ryby z Bugu często wchodzą na żerowanie w czystszej wodzie Liwca. Spinningowanie dużymi woblerami może przynieść tu niespodziankę w postaci medalowego szczupaka lub wyrośniętego sandacza. Uciąg rzeki w tym miejscu bywa zmienny i uzależniony od poziomu wody w głównym korycie pobliskiego Bugu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70354, 'Nizinna Mała', 'Nurt zmienny, wysokie brzegi', 22.0, 1.8, 'Piasek i żwir', 'Zwalone drzewa', 'Kleń, Boleń, Szczupak', 'Kraina leszcza', true);

-- Spot 356: Świniotop
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70355, 'Liwiec - Świniotop (Ujście)', 'liwiec-swiniotop', 'RIVER', 52.5934978, 21.5777116, 'Mazowieckie', 'Wyszków', 'Świniotop to ostatnia prosta przed ujściem, gdzie rzeka rozlewa się najszerzej i wyraźnie zwalnia swój bieg. Dno jest tu w większości piaszczyste z lokalnymi naniesieniami mułu, co przyciąga duże stada leszczy oraz krąpi. To wymarzone miejsce dla spinningistów polujących na szczupaki, którzy obławiają pasy trzcin oraz kępy roślinności zanurzonej. Woda jest dobrze natleniona i bogata w pokarm, co przekłada się na wysoką kondycję i waleczność tutejszego białorybu. Uciąg jest znikomy, co pozwala na stosowanie najdelikatniejszych technik feederowych z czułymi, drgającymi szczytówkami. Dzięki bardzo dobremu dostępowi do wody, jest to popularne miejsce na weekendowe biwaki i długie sesje wędkarskie.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70355, 'Nizinna Średnia', 'Leniwy nurt, szerokie koryto', 30.0, 2.0, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Krąp, Szczupak', 'Kraina leszcza', true);

-- Spot 357: Wólka Paplińska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70356, 'Liwiec - Wólka Paplińska (Zakola)', 'liwiec-wolka-paplinska', 'RIVER', 52.4777923, 21.8131423, 'Mazowieckie', 'Łochów', 'Odcinek w Wólce Paplińskiej charakteryzuje się bardzo czystą wodą i twardym, piaszczystym podłożu koryta rzeki. Liwiec tworzy tu klasyczne, łąkowe zakola z podmyłymi burtami, które skrywają wyrośnięte jazie oraz klenie. Spinningiści z sukcesami stosują tu metodę "na upatrzonego", podając smużaki tuż pod zwisające nad lustro wody trawy. Uciąg jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu stad ryb w polu widzenia wędkarza. Przy brzegach można spotkać liczne dołki o głębokości ponad metra, będące doskonałą bazą dla żerujących stad okoni. To kameralne łowisko zapewnia doskonały odpoczynek od zgiełku i szansę na kontakt z bardzo dziką rybą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70356, 'Nizinna Mała', 'Meandrująca, koryto naturalne', 14.0, 1.1, 'Piaszczyste', 'Podmyte korzenie', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 358: Bednarze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70357, 'Liwiec - Bednarze (Piaszczysta)', 'liwiec-bednarze', 'RIVER', 52.4779425, 21.7832853, 'Mazowieckie', 'Łochów', 'Liwiec w Bednarzach to rzeka o wybitnie piaszczystym charakterze, płynąca meandrami wśród mazowieckich pagórków i zagajników. Dno jest tu czyste i bezpieczne dla brodzących, co pozwala na dotarcie do najciekawszych miejsc niedostępnych z wysokiego brzegu. To idealne miejsce na letnią zasiadkę z batem lub lekką bolonką w poszukiwaniu stadnych jelców oraz płoci. Nurt rzeki jest jednostajny, co umożliwia precyzyjną prezentację przynęty na bardzo cienkich i delikatnych żyłkach przyponowych. Podmyte korzenie nadbrzeżnych olch stanowią bankowe kryjówki dla kleni, które agresywnie atakują mikro-woblery w toni. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem na mapie regionu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70357, 'Nizinna Mała', 'Meandrująca, czysty piasek', 15.0, 1.0, 'Piaszczyste', 'Podmyte korzenie', 'Jelec, Płoć, Kleń', 'Kraina leszcza', false);

-- Spot 359: Sekłak
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70358, 'Liwiec - Sekłak (Piaszczyste Płanie)', 'liwiec-seklak', 'RIVER', 52.4873224, 21.757886, 'Mazowieckie', 'Łochów', 'Liwiec w Sekłaku to uroczy fragment rzeki nizinnej, charakteryzujący się bardzo naturalnym korytem i czystą wodą. Piaszczyste dno z lokalnymi rynnami tworzy wyśmienite warunki do żerowania dla dorodnych stad jazi oraz kleni. Wędkarze spinningowi powinni skupić się na obławianiu podmytych burt, gdzie w cieniu traw czatują wyrośnięte okonie. Uciąg jest tu umiarkowany, co pozwala na precyzyjne nęcenie pola łowiska przy użyciu lekkich zanęt spożywczych. Brzegi są niskie i trawiaste, co zapewnia komfortowe warunki do rozstawienia stanowiska podczas całodniowej zasiadki. Ze względu na wysoką przejrzystość toni, kluczowe dla sukcesu jest ciche poruszanie się i pełne maskowanie na stanowisku.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70358, 'Nizinna Mała', 'Naturalna, szeroka', 18.0, 1.2, 'Piaszczyste', 'Piaszczyste łachy', 'Jaź, Kleń, Okoń', 'Kraina leszcza', false);

-- Spot 360: Radzików-Oczki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70359, 'Liwiec - Radzików-Oczki (Źródliska)', 'liwiec-radzikow-oczki', 'RIVER', 52.1585412, 22.5231934, 'Mazowieckie', 'Siedlce', 'W Radzikowie-Oczkach Liwiec przypomina jeszcze wąski, kameralny strumień wijący się wśród podlaskich łąk. Koryto rzeki jest tu wyjątkowo wąskie, co wymusza na wędkarzu stosowanie krótkich i bardzo precyzyjnych wędzisk. Piaszczysto-muliste dno obfituje w naturalny pokarm, przyciągając stadka mniejszych płoci oraz walecznych jelców. To doskonałe miejsce dla pasjonatów technicznego spinningu, którzy szukają wyzwań w łowieniu pod nawisami gęstych krzewów. Nurt rzeki jest tu stabilny i łagodny, co sprzyja nauce czytania wody na mikro-przestrzeni koryta. Miejsce to zapewnia absolutny spokój oraz szansę na spotkanie z dziką przyrodą w jej najczystszej postaci.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70359, 'Nizinna Mała', 'Wąski strumień', 3.0, 0.6, 'Piasek i muł', 'Zarośla nadrzeczne', 'Płoć, Jelec, Kleń', 'Kraina leszcza', false);

-- Spot 361: Wielgorz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70360, 'Liwiec - Wielgorz (Meandry Górne)', 'liwiec-wielgorz', 'RIVER', 52.1714012, 22.4976755, 'Mazowieckie', 'Siedlce', 'Odcinek rzeki w Wielgorzu to rzeka o wybitnie dzikim charakterze, płynąca meandrami przez tereny podmokłe i zagajniki. Rzeka posiada tu wyraźnie zaznaczoną rynnę główną, w której grupują się wyrośnięte klenie żerujące w toni. Dno jest mocno urozmaicone, piaszczyste z lokalnymi dołkami o twardym podłożu na każdym ostrzejszym zakręcie. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, stosując mikro-woblery i smużaki imitujące owady wpadające do wody. Uciąg wody jest umiarkowany i pozwala na swobodne stosowanie lekkich metod spławikowych z cienkimi zestawami. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem regionu.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70360, 'Nizinna Mała', 'Silne meandry', 5.0, 0.9, 'Piaszczyste', 'Podmyte burty', 'Kleń, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 362: Pieńki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70361, 'Liwiec - Pieńki (Leśny Charakter)', 'liwiec-pienki', 'RIVER', 52.1781476, 22.4698396, 'Mazowieckie', 'Siedlce', 'Liwiec w Pieńkach przepływa przez malownicze tereny leśne, co nadaje mu surowego i bardzo naturalnego wyglądu. Koryto jest tu usiane licznymi zwalonymi pniemi drzew, tworząc techniczne i wymagające stanowiska dla spinningistów. Pod korzeniami starych olch przy brzegach skrywają się dorodne okonie, które agresywnie atakują każdą przepływającą obok przynętę. Dno jest tu w większości twarde i piaszczyste, co minimalizuje ryzyko częstych zaczepów przy łowieniu z rzutu. Uciąg rzeki w tym miejscu jest zdecydowany, co sprzyja natlenieniu wody i wysokiej aktywności ryb rzecznych. To stanowisko gwarantuje wędkarzowi całkowitą izolację od zgiełku cywilizacji i szansę na kontakt z niewypłoszonym okazem.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70361, 'Nizinna Mała', 'Naturalna rzeka leśna', 6.0, 1.1, 'Piasek i korzenie', 'Zwalone kłody', 'Okoń, Szczupak, Kleń', 'Kraina leszcza', false);

-- Spot 363: Leśniczówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70362, 'Liwiec - Leśniczówka (Bystrza)', 'liwiec-lesniczowka', 'RIVER', 52.180241, 22.4405725, 'Mazowieckie', 'Siedlce', 'W rejonie Leśniczówki rzeka przedziera się przez naturalne przewężenia, tworząc lokalne bystrza o piaszczysto-żwirowym podłożu koryta. Woda jest tu wyjątkowo przejrzysta i dobrze natleniona, co przyciąga stadne jelce oraz okresowo pojawiające się jazie. To wymarzone miejsce dla miłośników lekkiej przepływanki, którzy cenią sobie precyzyjną prezentację przynęty na długich dystansach. Podmyte brzegi porośnięte gęstą wikliną skrywają wyrośnięte okonie, które doskonale reagują na małe obrotówki i twistery. Uciąg rzeki pozwala na komfortowe operowanie delikatnymi zestawami bez konieczności stosowania nadmiernie ciężkich obciążeń ołowianych. Cisza panująca wzdłuż leśnego brzegu zapewnia doskonały relaks oraz szansę na owocny połów w kameralnych warunkach.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70362, 'Nizinna Mała', 'Nurt przyspieszony', 5.5, 0.8, 'Piasek i żwir', 'Podmyte korzenie', 'Jelec, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 364: Pruszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70363, 'Liwiec - Pruszyn (Podmiejski)', 'liwiec-pruszyn', 'RIVER', 52.190563, 22.4163293, 'Mazowieckie', 'Siedlce', 'Odcinek w Pruszynie to rzeka o stabilnym nurcie i korycie częściowo uregulowanym, co zapewnia wygodny dostęp do wody. Dno jest tu wyrównane, w większości piaszczyste, co czyni to miejsce idealnym dla wędkarzy preferujących technikę lekkiego gruntu. Gatunkiem dominującym na tym fragmencie jest płoć, która bardzo dobrze reaguje na nęcenie drobną frakcją zanęty spożywczej. Spinningiści mogą liczyć na regularne brania okoni patrolujących przybrzeżne pasy roślinności zanurzonej i nieliczne trzcinowiska. Głębokość jest tu stabilna i rzadko przekracza metr, co sprzyja aktywnemu brodzeniu w poszukiwaniu rzecznych drapieżników. Bliskość Siedlec sprawia, że jest to chętnie wybierany punkt na szybkie i bezproblemowe popołudnie z wędką.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70363, 'Nizinna Mała', 'Uregulowane koryto', 7.0, 1.0, 'Piaszczyste', 'Roślinność zanurzona', 'Płoć, Okoń, Jelec', 'Kraina leszcza', false);

-- Spot 365: Wólka Leśna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70364, 'Liwiec - Wólka Leśna (Zakola)', 'liwiec-wolka-lesna', 'RIVER', 52.2025829, 22.3931424, 'Mazowieckie', 'Siedlce', 'Liwiec w Wólce Leśnej płynie wąskim, silnie meandrującym korytem przez tereny leśno-łąkowe. Dno jest tu piaszczyste, z wyraźnymi rynnami na łukach, które stanowią bezpieczne schronienie dla dorodnych kleni. Spinningiści z sukcesami polują tu na okonie, wykorzystując mikro-jigi prowadzone wzdłuż podmytych korzeni. Uciąg wody jest stały i umiarkowany, co sprzyja naturalnej prezentacji przynęt na delikatnych zestawach. Przejrzystość toni wymaga od wędkarza zachowania pełnej dyskrecji i cichego przemieszczania się brzegiem rzeki. To techniczne łowisko nagradza cierpliwość, oferując kontakt z dziką rybą w bardzo kameralnych warunkach.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70364, 'Nizinna Mała', 'Naturalna struga, kręta', 4.5, 0.8, 'Piaszczyste', 'Podmyte brzegi', 'Kleń, Okoń, Płoć', 'Kraina leszcza', false);

-- Spot 366: Golice-Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70365, 'Liwiec - Golice-Kolonia (Rynna)', 'liwiec-golice-kolonia', 'RIVER', 52.2157618, 22.3730102, 'Mazowieckie', 'Siedlce', 'Odcinek w Golicach-Kolonii charakteryzuje się wyrównanym nurtem i brzegami porośniętymi gęstą wikliną. Koryto rzeki posiada tu kilka głębszych dołków, w których grupują się wyrośnięte płocie oraz stadne jelce. Wędkarze spławikowi chętnie stosują tu lekkie baty, nęcąc ryby drobną frakcją zanęty z dodatkiem pinek. Podłoże jest twarde i piaszczyste, co ułatwia brodzenie i precyzyjne podanie przynęty w główny prąd wody. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia smużaków pod nawisami traw w poszukiwaniu jazi. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, czyniąc to łowisko atrakcyjnym punktem na mapie regionu.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70365, 'Nizinna Mała', 'Nurt jednostajny, dno piaszczyste', 5.0, 0.9, 'Piasek i żwir', 'Pasy wikliny', 'Płoć, Jelec, Kleń', 'Kraina leszcza', false);

-- Spot 367: Krześlin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70366, 'Liwiec - Krześlin (Kładka)', 'liwiec-krzeslin', 'RIVER', 52.2229241, 22.3459782, 'Mazowieckie', 'Siedlce', 'Liwiec w Krześlinie to malowniczy fragment rzeki o zmiennej dynamice przepływu i krystalicznie czystej wodzie. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe, z wyraźnymi przewężeniami rzeźbiącymi ciekawe stanowiska dla drapieżników. To wymarzone miejsce dla spinningistów polujących na szczupaki, które czatują w cieniu podwodnej roślinności zanurzonej. Uciąg wody wyraźnie przyspiesza na lokalnych bystrzach, co sprzyja natlenieniu rzeki i wysokiej aktywności ryb. Wędkarze stacjonarni z sukcesami łowią tu dorodne wzdręgi, wykorzystując technikę lekkiej przepływanki przy brzegowych trzcinach. Stanowiska są tu naturalne i częściowo osłonięte, co zapewnia wędkarzowi dużą dozę prywatności podczas zasiadki.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70366, 'Nizinna Mała', 'Bystrza piaszczyste', 6.0, 0.7, 'Piasek i żwir', 'Roślinność zanurzona', 'Szczupak, Wzdręga, Kleń', 'Kraina leszcza', false);

-- Spot 368: Borki Siedleckie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70367, 'Liwiec - Borki Siedleckie (Przełom)', 'liwiec-borki-siedleckie', 'RIVER', 52.2184789, 22.3169944, 'Mazowieckie', 'Siedlce', 'Odcinek w Borkach Siedleckich to miejsce, gdzie Liwiec zaczyna nabierać nieco głębszego charakteru przed wpłynięciem do miasta. Rzeka tworzy tu szerokie zakola z wysokimi burtami, pod którymi woda wymyła głębokie rynny. Jest to doskonałe łowisko jaziowe, szczególnie skuteczne wczesną wiosną podczas migracji ryb z niższych partii. Dno piaszczysto-gliniaste zapewnia rybom obfite żerowiska, co przekłada się na ich zdrową kondycję i waleczność. Spinningiści z sukcesami obławiają tutejsze spowolnienia nurtu, celując w dorodne okonie grupujące się przy dnie. Dobry dojazd do wody sprawia, że jest to chętnie wybierane miejsce na szybkie sesje z lekkim feederem.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70367, 'Nizinna Mała', 'Głębokie zakola, burty', 7.0, 1.3, 'Piasek i glina', 'Głębokie rynny', 'Jaź, Okoń, Leszcz', 'Kraina leszcza', false);

-- Spot 369: Ptaszki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70368, 'Liwiec - Ptaszki (Górny Strumień)', 'liwiec-ptaszki', 'RIVER', 52.1479769, 22.5589471, 'Mazowieckie', 'Mordy', 'W Ptaszkach Liwiec ma postać kameralnego strumienia płynącego meandrami wśród podlaskich łąk i pól. Rzeka jest tu wyjątkowo wąska, co sprawia, że technika podchodzenia do ryby staje się kluczowa. Podłoże jest piaszczyste, z lokalnymi dołkami o twardym dnie, w których chętnie przebywają mniejsze klenie. To idealne miejsce na rozpoczęcie przygody z ultra-lekkim spinningiem przy użyciu najmniejszych dostępnych przynęt. Woda zachowuje tu niespotykaną przejrzystość, pozwalając na widowiskowe łowienie "na upatrzonego" w słoneczne dni. Pomimo niewielkich rozmiarów rzeki, można tu liczyć na emocjonujące hole ryb w trudnym, pełnym zarośli terenie.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70368, 'Nizinna Mała', 'Wąski strumień łąkowy', 3.0, 0.5, 'Piaszczyste', 'Zarośla nadrzeczne', 'Kleń, Płoć, Okoń', 'Kraina leszcza', false);

-- Spot 370: Klimy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70369, 'Liwiec - Klimy (Źródliska)', 'liwiec-klimy', 'RIVER', 52.1370124, 22.5900952, 'Mazowieckie', 'Mordy', 'Klimy to odcinek położony bardzo blisko obszaru źródliskowego Liwca, gdzie rzeka dopiero formuje swoje koryto. Woda płynie tu leniwie wśród niskich brzegów, tworząc liczne mikro-zastoiska bogate w naturalną faunę denną. Dno piaszczysto-muliste sprzyja populacji drobnej płoci oraz kiełbia, które są głównymi mieszkańcami tego fragmentu rzeki. Jest to łowisko o bardzo niskiej presji, odwiedzane głównie przez koneserów ceniących absolutny spokój. Szerokość rzeki rzadko przekracza tu dwa metry, co wymusza stosowanie krótkich i precyzyjnych wędzisk typu "trout area". To miejsce stanowi unikalną okazję do obserwacji rzeki w jej najbardziej pierwotnej i najczystszej formie.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70369, 'Nizinna Mała', 'Strumień źródliskowy', 2.5, 0.4, 'Piasek i muł', 'Brak dużych struktur', 'Płoć, Kiełb, Okoń', 'Kraina leszcza', false);

-- Spot 371: Wesółka (Obszar Źródliskowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70370, 'Liwiec - Wesółka (Źródlisko)', 'liwiec-wesolka-zrodlo', 'RIVER', 52.0919528, 22.6458818, 'Lubelskie', 'Mordy', 'Liwiec w Wesółce to niemal początkowy punkt biegu rzeki, mający postać wąskiej strugi wijącej się wśród pól i łąk. Woda jest tu krystalicznie czysta i płynie płytkim korytem o piaszczysto-mulistym podłożu, sprzyjającym drobnej faunie dennej. To specyficzne łowisko dla pasjonatów mikro-wędkarstwa, gdzie dominują stadka płoci oraz liczne kiełbie. Ze względu na minimalną szerokość koryta, kluczowe jest zachowanie absolutnej ciszy i operowanie bardzo krótkim wędziskiem. Nurt jest tu ledwo wyczuwalny, co pozwala na stosowanie najlżejszych dostępnych zestawów spławikowych o gramaturze poniżej jednego grama. Miejsce to rzadko odwiedzane przez wędkarzy, oferuje unikalną szansę na obserwację rzeki w jej najbardziej pierwotnej i naturalnej formie.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70370, 'Nizinna Mała', 'Wąska struga polna', 2.0, 0.4, 'Piasek i muł', 'Brak dużych struktur', 'Płoć, Kiełb, Okoń', 'Kraina leszcza', false);

-- Spot 372: Próchenki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70371, 'Liwiec - Próchenki (Kameralna)', 'liwiec-prochenki', 'RIVER', 52.1065099, 22.6261743, 'Mazowieckie', 'Mordy', 'Odcinek rzeki w Próchenkach to rzeka o kameralnym charakterze, płynąca meandrami wśród niskich, trawiastych brzegów. Dno jest tu twarde i piaszczyste, z wyraźnymi wymyciami rzeźbiącymi mikro-rynny, w których chętnie przebywają mniejsze klenie. To doskonałe miejsce dla łowców jelców oraz płoci, które doskonale reagują na drobne przynęty naturalne podawane na delikatnym zestawie. Nurt jest jednostajny i łagodny, co pozwala na bardzo precyzyjne prowadzenie spławika wzdłuż brzegowych burt. Spinningiści mogą liczyć na brania okoni patrolujących nieliczne kępy roślinności zanurzonej w płytkich partiach wody. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem dla wędkarzy szukających spokoju.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70371, 'Nizinna Mała', 'Naturalna struga, kręta', 2.5, 0.5, 'Piaszczyste', 'Lokalne rynny', 'Płoć, Jelec, Kleń', 'Kraina leszcza', false);

-- Spot 373: Szydłówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70372, 'Liwiec - Szydłówka (Piaszczysta)', 'liwiec-szydlowka', 'RIVER', 52.1201635, 22.606672, 'Mazowieckie', 'Mordy', 'Liwiec w Szydłówce to odcinek o charakterze uregulowanej strugi, zachowujący jednak wysoką czystość wody i piaszczyste podłoże. Rzeka płynie tu prostymi odcinkami, co ułatwia precyzyjne nęcenie pola łowiska przy użyciu drobnej frakcji zanęty spożywczej. Głębokość stabilizuje się na poziomie pół metra, a dno jest wolne od większych przeszkód terenowych, co minimalizuje ryzyko zerwania zestawu. To idealne miejsce na wiosenną zasiadkę z batem w poszukiwaniu pierwszych aktywnych płoci oraz walecznych jelców. Spinningiści z sukcesami obławiają tutejsze brzegi mikro-obrotówkami, celując w żerujące w toni okonie. Dogodny dojazd przez łąki sprawia, że jest to chętnie wybierane miejsce na szybki i bezproblemowy relaks z wędką w otoczeniu natury.', 'PZW Siedlce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70372, 'Nizinna Mała', 'Uregulowane koryto, nurt stały', 3.0, 0.6, 'Piaszczyste', 'Roślinność zanurzona', 'Płoć, Jelec, Okoń', 'Kraina leszcza', false);

-- Spot 374: Barcikowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70373, 'Łyna - Barcikowo (Warmińskie Meandry)', 'lyna-barcikowo', 'RIVER', 53.9588914, 20.4160748, 'Warmińsko-Mazurskie', 'Dobre Miasto', 'Łyna w Barcikowie to odcinek o charakterze wybitnie meandrującym, płynący w głębokiej dolinie wśród warmińskich wzgórz. Koryto rzeki posiada tu liczne podmyte burty, które są naturalnym schronieniem dla dorodnych kleni oraz jazi. Dno jest przeważnie piaszczyste, z lokalnymi żwirowymi łachami sprzyjającymi bytowaniu ryb prądolubnych. Spinningiści z sukcesami obławiają tutejsze warkocze, stosując małe woblery i smużaki prowadzone blisko brzegowych traw. Uciąg wody jest stały i umiarkowany, co umożliwia precyzyjne nęcenie pola łowiska przy użyciu lekkich zanęt. To ciche i techniczne łowisko, wymagające od wędkarza pełnej dyskrecji ze względu na wysoką przejrzystość toni.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70373, 'Nizinna Średnia', 'Silnie meandrująca, naturalna', 18.0, 1.4, 'Piasek i żwir', 'Podmyte burty', 'Kleń, Jaź, Płoć', 'Kraina leszcza', true);

-- Spot 375: Wichrowo (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70374, 'Łyna - Wichrowo (Leśny Przełom)', 'lyna-wichrowo-poludnie', 'RIVER', 54.003454, 20.4056092, 'Warmińsko-Mazurskie', 'Dobre Miasto', 'Leśny odcinek Łyny w okolicach Wichrowa charakteryzuje się dzikim charakterem i dużą ilością zwalonych pni drzew w korycie. Rzeka przedziera się tu przez zwarte kompleksy leśne, żłobiąc głębokie rynny pod brzegowymi olchami. To wymarzone stanowisko dla łowców szczupaków, którzy precyzyjnie obławiają podwodne karczowiska ciężkimi gumami. Dno piaszczysto-gliniaste zapewnia rybom obfite żerowiska, co przekłada się na ich zdrową kondycję i waleczność. Uciąg rzeki wyraźnie przyspiesza na przewężeniach, co sprzyja natlenieniu wody i wysokiej aktywności ryb. Stanowiska brzegowe są naturalne i wymagają od wędkarza sprawności fizycznej oraz cichego podejścia do lustra wody.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70374, 'Nizinna Średnia', 'Dzikie koryto leśne', 15.0, 1.8, 'Piasek i glina', 'Zwalone kłody', 'Szczupak, Okoń, Jaź', 'Kraina leszcza', false);

-- Spot 376: Wichrowo (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70375, 'Łyna - Wichrowo (Piaszczyste Przykosy)', 'lyna-wichrowo-polnoc', 'RIVER', 54.0471599, 20.4244815, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński', 'Północny fragment rzeki w Wichrowie to miejsce o urozmaiconej rzeźbie dna z licznymi piaszczystymi przykosami na środku. Łyna płynie tu szerzej, a jej nurt staje się bardziej dostojny i przewidywalny dla wędkarzy gruntowych. Wzdłuż brzegów występują pasy roślinności zanurzonej, które stanowią bezpieczne schronienie dla stadnych płoci i okoni. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia woblerów w poszukiwaniu boleni patrolujących krawędzie głównego nurtu. Głębokość stabilizuje się na poziomie półtora metra, co pozwala na komfortowe łowienie metodą odległościową lub lekkim feederem. Niska presja wędkarska w tym rejonie sprawia, że ryby żerują śmiało nawet w słoneczne dni.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70375, 'Nizinna Średnia', 'Szerokie płanie, nurt stabilny', 22.0, 1.5, 'Piaszczyste', 'Przykosy piaszczyste', 'Boleń, Płoć, Okoń', 'Kraina leszcza', true);

-- Spot 377: gmina Lidzbark Warmiński
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70376, 'Łyna - Lidzbark Warmiński (Rynny)', 'lyna-lidzbark-rynny', 'RIVER', 54.0920752, 20.4328057, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński', 'Łyna w gminie Lidzbark Warmiński nabiera pełnego, nizinnego charakteru, płynąc szerokim korytem przez tereny otwarte. Dno jest tu w większości twarde i piaszczyste, z wyraźnymi rynnami wymytymi na zewnętrznych łukach rzeki. To idealne miejsce dla miłośników feedera klasycznego, celujących w dorodne leszcze oraz krąpie żerujące przy dnie. Wzdłuż brzegów rosną gęste trzcinowiska, będące naturalną bazą dla szczupaków czatujących na rzeczną drobnicę. Uciąg wody jest umiarkowany, co pozwala na stosowanie najdelikatniejszych szczytówek i precyzyjne punktowanie łowiska. Dogodny dojazd do wody sprawia, że jest to chętnie wybierane miejsce na całodniowe zasiadki rodzinne.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70376, 'Nizinna Średnia', 'Uregulowane, nurt stabilny', 25.0, 2.2, 'Twardy piasek', 'Trzcinowiska', 'Leszcz, Krąp, Szczupak', 'Kraina leszcza', true);

-- Spot 378: Długołęka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70377, 'Łyna - Długołęka (Zakola)', 'lyna-dlugoleka-zakola', 'RIVER', 54.110954, 20.5031608, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński', 'Odcinek w Długołęce oferuje wędkarzom dostęp do rzeki o bardzo krętym korycie i zmiennej dynamice przepływu wody. Łyna tworzy tu głębokie jamy pod wysokimi burtami, które są naturalną kryjówką dla sumów oraz wyrośniętych kleni. Dno piaszczysto-żwirowe sprzyja aktywności ryb reofilnych, które doskonale reagują na techniki spinningowe oraz muchowe. Uciąg rzeki wymaga stosowania dociążonych zestawów, które stabilnie utrzymają przynętę w strefie intensywnego żerowania ryb. Przy brzegach można spotkać liczne zatory z gałęzi, tworzące technicznie wymagające, ale niezwykle rybne stanowiska. To malownicze łowisko zapewnia doskonały odpoczynek i szansę na kontakt z bardzo dziką fauną rzeczną.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70377, 'Nizinna Średnia', 'Meandrująca, głęboka', 20.0, 2.5, 'Piasek i żwir', 'Głębokie jamy', 'Sum, Kleń, Brzana', 'Kraina leszcza', true);

-- Spot 379: Olsztyn (Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70378, 'Łyna - Olsztyn (Śródmieście)', 'lyna-olsztyn-centrum', 'RIVER', 53.7786126, 20.4741199, 'Warmińsko-Mazurskie', 'Olsztyn', 'Miejski odcinek Łyny w Olsztynie to techniczne łowisko z kamiennymi opaskami i głębokimi rynnami pod mostami śródmieścia. Pomimo miejskiego otoczenia, rzeka zachowuje tu czystą wodę i dużą populację walecznych kleni oraz jazi. Dno jest twarde, piaszczysto-kamieniste, z licznymi załamaniami nurtu sprzyjającymi drapieżnikom żerującym w warkoczach. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy betonowych murkach oporowych. Uciąg rzeki jest umiarkowany, co pozwala na precyzyjne operowanie zestawami spławikowymi przez cały sezon wędkarski. Dobrze przygotowana infrastruktura brzegowa w parkach ułatwia dostęp do najciekawszych miejsc bez konieczności używania woderów.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70378, 'Nizinna Mała', 'Uregulowane koryto miejskie', 12.0, 1.3, 'Kamień i piasek', 'Mosty, murki oporowe', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 380: Ruś (Przełom Górny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70379, 'Łyna - Ruś (Warmiński Przełom)', 'lyna-rus-przelom', 'RIVER', 53.6455518, 20.5045494, 'Warmińsko-Mazurskie', 'Olsztyn', 'Łyna w okolicach Rusi charakteryzuje się niezwykle bystrym nurtem i kamienistym dnem, co nadaje jej charakter rzeki górskiej. Rzeka płynie tu w głębokim jarze leśnym, tworząc liczne bystrza i natlenione warkocze idealne dla pstrągów potokowych. To techniczne łowisko dla muszkarzy i spinningistów, którzy muszą mierzyć się z dużą ilością zwalonych pni drzew. Woda jest krystalicznie czysta, co pozwala na obserwację żerujących ryb, ale wymaga od wędkarza pełnego maskowania. Uciąg rzeki jest bardzo zdecydowany, wymuszając stosowanie przynęt dobrze trzymających się w silnym prądzie wody. Ze względu na walory przyrodnicze i bliskość rezerwatu, panuje tu wyjątkowa cisza sprzyjająca skutecznym podchodom pod stanowiska.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70379, 'Podgórska', 'Bystry nurt, koryto kamieniste', 10.0, 1.0, 'Kamień i żwir', 'Głazy, zatory drzewne', 'Pstrąg potokowy, Kleń, Okoń', 'Kraina pstrąga', 'Obszar Chronionego Krajobrazu', false);

-- Spot 381: Ruś (Wylot na Olsztyn)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70380, 'Łyna - Ruś (Meandry Północne)', 'lyna-rus-polnoc', 'RIVER', 53.6904287, 20.4940651, 'Warmińsko-Mazurskie', 'Olsztyn', 'Poniżej miejscowości Ruś rzeka zaczyna nieco zwalniać, tworząc malownicze meandry wśród podmokłych łąk i zagajników. Dno pozostaje twarde, piaszczysto-żwirowe, z wyraźnymi rynnami na zewnętrznych łukach koryta rzeki. To doskonałe miejsce dla łowców dorodnych kleni oraz jazi, które doskonale reagują na małe woblery i smużaki. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni czatujących w cieniu nadbrzeżnej roślinności. Uciąg jest umiarkowany, co pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach spławikowych. Miejsce to zapewnia świetny kompromis między dzikością rzeki a relatywnie łatwym dostępem do linii brzegowej.', 'PZW Olsztyn');

