VALUES (70380, 'Nizinna Mała', 'Meandrująca, nurt umiarkowany', 12.0, 1.2, 'Piasek i żwir', 'Podmyte burty', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 382: Jaroty (Olsztyn Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70381, 'Łyna - Jaroty (Leśna Struga)', 'lyna-olsztyn-jaroty', 'RIVER', 53.7308715, 20.4590025, 'Warmińsko-Mazurskie', 'Olsztyn', 'Łyna w rejonie Jarot przepływa przez tereny leśne na obrzeżach miasta, zachowując swój naturalny i kameralny charakter. Koryto rzeki jest tu dość wąskie, a dno usiane zatopionymi korzeniami, co sprzyja bytowaniu szczupaków i okoni. To idealne miejsce na szybki wypad ze spinningiem, oferujące liczne techniczne stanowiska pod nawisami drzew. Wędkarze spławikowi z sukcesami łowią tu waleczne jelce oraz płocie, wykorzystując metodę lekkiej przepływanki. Nurt jest stabilny, co umożliwia precyzyjne punktowanie łowiska nawet przy użyciu bardzo lekkich zestawów spławikowych. Pomimo bliskości dużych osiedli, odcinek ten zachowuje dużą dozę dzikości i oferuje czystą, dobrze natlenioną wodę.', 'PZW Olsztyn');

