VALUES (70381, 'Nizinna Mała', 'Wąskie koryto leśne', 8.0, 0.9, 'Piasek i korzenie', 'Zwalone gałęzie', 'Szczupak, Płoć, Jelec', 'Kraina leszcza', false);

-- Spot 383: Barkweda
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70382, 'Łyna - Barkweda (Rozlewisko)', 'lyna-barkweda-rozlewisko', 'RIVER', 53.8614173, 20.394257, 'Warmińsko-Mazurskie', 'Dobre Miasto', 'W Barkwedzie Łyna rozlewa się szeroko, tworząc rybne płanie o urozmaiconym, piaszczysto-mulistym podłożu koryta. To strategiczne miejsce dla łowców białorybu, gdzie dorodne leszcze i krąpie grupują się w spokojniejszych patiach wody. Spinningiści cenią ten odcinek za populację szczupaka, który chętnie stacjonuje w pobliżu pasów trzcin i grążeli. Uciąg wody jest tu zróżnicowany, przyspieszając wyraźnie w rejonie starego mostu i zwalniając na rozlewiskach. To wymarzone miejsce na wiosenne zasiadki feederowe, celujące w ryby migrujące między rzeką a pobliskimi jeziorami. Bardzo dobry dostęp do wody sprawia, że jest to jedno z najpopularniejszych stanowisk wędkarskich w regionie.', 'PZW Olsztyn');

