VALUES (70382, 'Nizinna Średnia', 'Szerokie rozlewisko, nurt zmienny', 25.0, 2.0, 'Piasek i muł', 'Trzcinowiska, most', 'Leszcz, Szczupak, Jaź', 'Kraina leszcza', true);

-- Spot 384: Morawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70383, 'Łyna - Morawa (Dolna Płania)', 'lyna-morawa', 'RIVER', 54.1912508, 20.6715527, 'Warmińsko-Mazurskie', 'Bartoszyce', 'Odcinek w Morawie charakteryzuje się szerokim korytem i stabilnym nurtem typowym dla dolnego biegu Łyny. Rzeka płynie tu dostojnie przez tereny łąkowe, żłobiąc dno o charakterze piaszczysto-gliniastym z głębokimi rynnami. To idealne łowisko dla miłośników ciężkiego feedera, celujących w rekordowe leszcze oraz wyrośnięte brzany rzeczne. Spinningiści z sukcesami polują tu na bolenie patrolujące środek rzeki oraz sandacze trzymające się głębszych dołków. Uciąg rzeki pozwala na swobodne łowienie z łodzi, co daje dostęp do najciekawszych miejsc niedostępnych z brzegu. Przejrzystość wody jest tu mniejsza niż w górnym biegu, co sprzyja żerowaniu drapieżników w ciągu całego dnia.', 'PZW Olsztyn');

