-- Spot 385: Sortławki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70384, 'Łyna - Sortławki (Graniczne Rynny)', 'lyna-sortlawki', 'RIVER', 54.2149845, 20.7372686, 'Warmińsko-Mazurskie', 'Bartoszyce', 'Sortławki to jeden z ostatnich odcinków rzeki przed granicą państwa, oferujący wędkarzom dostęp do potężnej wody nizinnej. Łyna rozlewa się tu bardzo szeroko, tworząc liczne zakola z głębokimi rynnami sięgającymi ponad trzy metry głębokości. To doskonałe łowisko sumowe, gdzie nocne zasiadki często kończą się emocjonującymi holami bardzo dużych ryb. Dno jest mocno urozmaicone piaszczystymi przykosami, które są ulubionym żerowiskiem dla stadnych jazi i cert. Uciąg wody jest zdecydowany, co wymaga stosowania dociążonych zestawów gruntowych zdolnych utrzymać przynętę w nurcie. Miejsce to zapewnia absolutny spokój i szansę na kontakt z dziką, niewypłoszoną rybą w otoczeniu surowego krajobrazu północnej Warmii.', 'PZW Olsztyn');

