VALUES (70384, 'Nizinna Wielka', 'Potężna rzeka nizinna', 40.0, 3.5, 'Piasek i glina', 'Przykosy piaszczyste', 'Sum, Jaź, Certa', 'Kraina leszcza', true);

-- Spot 386: Bartoszyce (Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70385, 'Łyna - Bartoszyce (Miejska Płania)', 'lyna-bartoszyce-centrum', 'RIVER', 54.2480011, 20.7922222, 'Warmińsko-Mazurskie', 'Bartoszyce', 'Łyna w centrum Bartoszyc to głęboka rzeka nizinna o szerokim korycie i spokojnym nurcie. Dno jest piaszczysto-muliste, co sprzyja bytowaniu dorodnych leszczy oraz potężnych sumów żerujących w rynnach. Spinningiści z powodzeniem polują tutaj na sandacze, wykorzystując gumy prowadzone agresywnym opadem przy filarach mostowych. Uciąg wody jest stabilny i przewidywalny, umożliwiając precyzyjne operowanie ciężkim zestawem feederowym. Infrastruktura brzegowa w mieście jest dobrze rozwinięta, co zapewnia komfortowe stanowiska nawet podczas gorszej pogody. Wieczorne wyprawy z martwą rybką często kończą się tu braniem medalowego drapieżnika czatującego w mętnej toni.', 'PZW Olsztyn');

