-- Spot 387: Bartoszyce (Wylot na Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70386, 'Łyna - Bartoszyce (Przekop)', 'lyna-bartoszyce-wylot', 'RIVER', 54.261925, 20.8660542, 'Warmińsko-Mazurskie', 'Bartoszyce', 'Opuszczając Bartoszyce, Łyna płynie przez tereny łąkowe, zachowując znaczną głębokość i stabilne, wysokie brzegi. Koryto posiada tu wyraźnie zaznaczoną rynnę główną, w której grupują się wyrośnięte brzany oraz wyrośnięte okonie. To doskonałe łowisko dla spinningistów stosujących długie rzuty w poprzek nurtu w poszukiwaniu boleni. Dno jest tu twardsze, piaszczysto-gliniaste, co sprzyja aktywności ryb reofilnych nawet w okresach letnich upałów. Uciąg wody pozwala na komfortowe łowienie metodą bolonki przy zastosowaniu dociążonych zestawów z dużym spławikiem. Miejsce to zapewnia intymność i dużą szansę na kontakt z dziką rybą z dala od miejskiego zgiełku.', 'PZW Olsztyn');

