-- Spot 388: Wiatrowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70387, 'Łyna - Wiatrowiec (Meandry Dolne)', 'lyna-wiatrowiec', 'RIVER', 54.251481, 20.9416308, 'Warmińsko-Mazurskie', 'Sępopol', 'W rejonie Wiatrowca rzeka tworzy spektakularne meandry, żłobiąc dno na zewnętrznych łukach i tworząc jamy o głębokości do czterech metrów. To wymarzone miejsce dla łowców okazowych sumów, które znajdują tu doskonałe warunki do stacjonowania. Dno jest mocno urozmaicone piaszczystymi przykosami, będącymi naturalną stołówką dla stadnych jazi i cert. Spinningowanie z wysokich burt wymaga precyzji, ale nagradza braniami szczupaków czatujących w podmytych korzeniach drzew. Nurt rzeki jest tu majestatyczny i wolny, co sprzyja wielogodzinnym zasiadkom z ciężkim feederem lub żywcem. Surowy krajobraz północnej Warmii dodaje temu łowisku wyjątkowego, dzikiego uroku sprzyjającego wypoczynkowi.', 'PZW Olsztyn');

