-- Spot 389: Sępopol (Widły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70388, 'Łyna - Sępopol (Ujście Gubra)', 'lyna-sepopol-widly', 'RIVER', 54.2691412, 21.0126885, 'Warmińsko-Mazurskie', 'Sępopol', 'W Sępopolu Łyna łączy się z rzeką Guber, co tworzy niezwykle rybny węzeł wodny o dużej dynamice przepływu. Rozlewisko pod miastem charakteryzuje się znaczną głębokością i obecnością licznych piaszczystych łach wychodzących daleko w nurt. To idealne miejsce na połów okazowych brzan, które znajdują tu doskonałe warunki tlenowe w głównym nurcie. Wędkarze stacjonarni cenią tutejsze brzegi za stałe brania certy oraz wyrośniętego jazia w okresach migracji ryb. Spinningista znajdzie tu liczne warkocze prądowe, w których chętnie ustawiają się bolenie polujące na rzeczną drobnicę. Dostęp do rzeki jest swobodny, a naturalne otoczenie sprzyja wyciszeniu i długim sesjom z wędką w ręku.', 'PZW Olsztyn');

