-- Spot 390: Masuny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70389, 'Łyna - Masuny (Zakola Graniczne)', 'lyna-masuny', 'RIVER', 54.3099622, 21.0467091, 'Warmińsko-Mazurskie', 'Sępopol', 'Odcinek w Masunach to jedna z ostatnich dostępnych lokalizacji przed granicą państwa, oferująca dziką i nieprzewidywalną wodę. Łyna rozlewa się tu szeroko, płynąc leniwie przez podmokłe tereny o bardzo niskiej presji wędkarskiej. Dno jest przeważnie mulisto-piaszczyste z licznymi kępami grążeli żółtych, w których cieniu latem stacjonują potężne szczupaki. To doskonałe łowisko dla miłośników spławika nastawionych na lina oraz dużego karasia srebrzystego. Uciąg rzeki jest tu znikomy, co pozwala na stosowanie najdelikatniejszych technik feederowych z czułą szczytówką. Ze względu na bliskość pasa granicznego, panuje tu absolutna cisza, przerywana jedynie odgłosami natury i ryb.', 'PZW Olsztyn');

