-- Spot 391: Stanislavskoye (Granica)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70390, 'Łyna - Stanislavskoye (Punkt Graniczny)', 'lyna-granica-polnoc', 'RIVER', 54.3519035, 21.0184349, 'Warmińsko-Mazurskie', 'Sępopol', 'Punkt w rejonie Stanislavskoye wyznacza finalny odcinek Łyny na terytorium Polski przed jej przejściem w kierunku północnym. Rzeka osiąga tu swoje maksymalne parametry szerokości, tworząc potężne koryto o bardzo stabilnych warunkach wodnych. To elitarne łowisko dla łowców sumów i sandaczy, które wykorzystują głębokie rynny graniczne jako swoje główne ostoje. Dno jest mocno zamulone na zakrętach, co sprzyja rozwojowi bogatej populacji białorybu, szczególnie leszcza i krąpia. Wędkowanie tutaj wymaga dyscypliny i znajomości przepisów dotyczących pasa granicznego, ale oferuje w zamian kontakt z rybami rzadko widującymi przynętę. Uciąg jest niemal niezauważalny, co czyni ten fragment rzeki podobnym do wydłużonego, głębokiego jeziora przepływowego.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70390, 'Nizinna Wielka', 'Szeroka rzeka graniczna', 55.0, 4.0, 'Muł i piasek', 'Rynny graniczne', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 392: Dywity
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70391, 'Łyna - Dywity (Warkocze)', 'lyna-dywity-warkocze', 'RIVER', 53.8214581, 20.4466153, 'Warmińsko-Mazurskie', 'Olsztyn', 'Łyna w Dywitach charakteryzuje się dość wartkim nurtem i piaszczysto-żwirowym dnem z licznymi kamiennymi narzutami. Rzeka płynie tu w malowniczej dolinie, tworząc głębokie rynny na zewnętrznych łukach koryta. Jest to legendarne miejsce dla łowców kleni i jazi, które doskonale reagują na małe woblery i smużaki. Spinningiści z sukcesami obławiają tutejsze warkocze, szukając okoni czatujących przy zwalonych pniach olch. Uciąg wody jest stały, co pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach spławikowych. Ze względu na czystość wody i urozmaiconą rzeźbę dna, jest to jedno z najciekawszych łowisk w bezpośrednim sąsiedztwie Olsztyna.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70391, 'Nizinna Mała', 'Nurt żywy, koryto piaszczyste', 14.0, 1.2, 'Piasek i żwir', 'Kamienne bystrza', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 393: Lidzbark Warmiński (Zamek)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70392, 'Łyna - Lidzbark Warmiński (Zamek)', 'lyna-lidzbark-zamek', 'RIVER', 54.1269217, 20.5825106, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński', 'Odcinek Łyny w Lidzbarku Warmińskim to techniczne łowisko z uregulowanym korytem i licznymi budowlami hydrotechnicznymi. Pod murami zabytkowego zamku rzeka tworzy głębokie rynny, w których grupują się wyrośnięte leszcze oraz stadne płocie. Spinningiści chętnie obławiają wyloty kanałów i filary mostów w poszukiwaniu sandaczy oraz szczupaków. Dno jest tu twarde, piaszczysto-kamieniste, co zapewnia rybom doskonałe warunki tlenowe przez cały rok. Uciąg rzeki jest umiarkowany, co umożliwia precyzyjne nęcenie łowiska metodą klasycznego feedera lub bolonki. Pomimo miejskiego charakteru, rzeka skrywa tu medalowe okazy ryb reofilnych, które wymagają od wędkarza dużej precyzji i dyskrecji.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70392, 'Nizinna Średnia', 'Uregulowane koryto miejskie', 25.0, 2.0, 'Piasek i kamień', 'Filary mostu, jaz młyński', 'Leszcz, Sandacz, Płoć', 'Kraina leszcza', false);

-- Spot 394: Kabikiejmy Dolne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70393, 'Łyna - Kabikiejmy Dolne (Dolina)', 'lyna-kabikiejmy-dolne', 'RIVER', 53.9038168, 20.4197556, 'Warmińsko-Mazurskie', 'Dobre Miasto', 'Łyna w Kabikiejmach Dolnych to dzika rzeka o niezwykle naturalnym i silnie meandrując korycie. Rzeka płynie tu wśród rozległych łąk, żłobiąc dno o charakterze piaszczysto-gliniastym z licznymi podwyższonymi burtami. To wymarzone miejsce dla spinningistów polujących na szczupaki, które stacjonują w cieniu przybrzeżnych trzcinowisk. W rynnach o głębokości do dwóch metrów często meldują się dorodne klenie, doskonale reagujące na technikę lekkiego gruntu. Uciąg rzeki jest tu zdecydowany, co sprzyja natlenieniu wody i wysokiej aktywności ryb spokojnego żeru. Niska presja wędkarska sprawia, że jest to idealny spot dla osób szukających spokoju i kontaktu z niewypłoszoną rybą.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70393, 'Nizinna Średnia', 'Naturalne meandry', 20.0, 1.8, 'Piasek i glina', 'Trzcinowiska', 'Szczupak, Kleń, Leszcz', 'Kraina leszcza', true);

-- Spot 395: Laskowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70394, 'Narew - Laskowiec (Piaszczyste Przykosy)', 'narew-laskowiec', 'RIVER', 53.12607, 21.6750412, 'Mazowieckie', 'Ostrołęka', 'Narew w Laskowcu to potężna rzeka nizinna o szerokim korycie i licznych piaszczystych przykosach. Nurt jest tu stabilny, co sprzyja bytowaniu rekordowych leszczy oraz wyrośniętych krąpi żerujących na piaszczystym dnie. Spinningiści z sukcesami polują na bolenie, które regularnie uderzają w drobnicę na środku rzeki przy krawędzi nurtu. Dno jest w przeważającej mierze piaszczyste, z głębokimi rynnami wymytymi na zewnętrznych łukach koryta. To doskonałe miejsce dla wędkarzy ceniących ciszę oraz możliwość łowienia z rozległych, czystych plaż rzecznych. Niska presja wędkarska sprawia, że ryby żerują tu śmiało nawet w godzinach południowych przy pełnym słońcu.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70394, 'Nizinna Wielka', 'Szeroka, liczne przykosy', 80.0, 2.5, 'Piaszczyste', 'Przykosy, łachy', 'Leszcz, Boleń, Krąp', 'Kraina leszcza', 'Brak', true);

-- Spot 396: Pysklaki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70395, 'Narew - Pysklaki (Meandry łąkowe)', 'narew-pysklaki', 'RIVER', 53.1101089, 21.6046244, 'Mazowieckie', 'Ostrołęka', 'Odcinek rzeki w Pysklakach charakteryzuje się naturalnym, meandrującym korytem o bardzo urozmaiconym uciągu wody. Rzeka płynie tu wśród podmokłych łąk, żłobiąc dno o piaszczysto-gliniastym charakterze z licznymi podwyższonymi burtami. To wymarzone miejsce dla łowców jazi oraz kleni, które doskonale reagują na smużaki podawane pod nawisy traw. Podmyte brzegi porośnięte gęstą wikliną skrywają wyrośnięte okonie oraz szczupaki czatujące na rzeczną drobnicę. Uciąg rzeki jest umiarkowany, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi przez cały sezon. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką, niewypłoszoną fauną środkowej Narwi.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70395, 'Nizinna Wielka', 'Naturalne meandry', 70.0, 3.0, 'Piasek i glina', 'Podmyte burty', 'Jaź, Kleń, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 397: Ostrołęka (Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70396, 'Narew - Ostrołęka (Miejska)', 'narew-ostroleka-most', 'RIVER', 53.0758925, 21.55163, 'Mazowieckie', 'Ostrołęka', 'Narew w Ostrołęce to techniczne łowisko miejskie z częściowo uregulowanym korytem i konstrukcjami hydrotechnicznymi. Pod filarami mostów woda wymyła głębokie doły, które są całoroczną kryjówką dla sumów oraz sandaczy. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując ciężkie koszyki dla stabilizacji zestawu w nurcie. Dno jest tu twarde, piaszczysto-kamieniste, z wyraźnymi załamaniami prądu sprzyjającymi drapieżnikom żerującym w warkoczach. Spinningowanie w rejonie miejskich bulwarów daje szansę na spotkanie z wyrośniętym boleniem lub walecznym kleniem. Pomimo zurbanizowanego otoczenia, rzeka zachowuje tu wysoką rybność i przyciąga wielu pasjonatów wędkarstwa rzecznego.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70396, 'Nizinna Wielka', 'Uregulowane koryto miejskie', 90.0, 4.0, 'Kamień i twardy piasek', 'Filary mostu, opaski', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 398: Nożewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70397, 'Narew - Nożewo (Dzika Rzeka)', 'narew-nozewo', 'RIVER', 53.034378, 21.5198075, 'Mazowieckie', 'Ostrołęka', 'Odcinek w Nożewie oferuje wędkarzom dostęp do rzeki o bardzo dzikim charakterze z licznymi wyspami i bocznymi odnogami. Koryto rzeki jest tu szerokie, a dno usiane zatopionymi korzeniami, co sprzyja bytowaniu okazałych szczupaków. To strategiczne miejsce dla spinningistów, którzy szukają ryb w turbulentnej wodzie poniżej piaszczystych przykos. W rynnach o głębokości przekraczającej trzy metry stacjonują duże leszcze oraz wyrośnięte krąpie żerujące na faunie dennej. Uciąg rzeki jest tu zdecydowany i wymaga od wędkarza umiejętnego czytania zmian w strukturze prądów wodnych. Surowy krajobraz doliny Narwi nadaje każdej wyprawie wędkarskiej wyjątkowego, niemal pierwotnego charakteru.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70397, 'Nizinna Wielka', 'Wielonurtowe, dzikie', 100.0, 3.5, 'Piasek i karcze', 'Wyspy, zatory', 'Szczupak, Leszcz, Okoń', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 399: Żerań Mały
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70398, 'Narew - Żerań Mały (Płania)', 'narew-zeran-maly', 'RIVER', 52.9904143, 21.503334, 'Mazowieckie', 'Ostrołęka', 'Narew w Żeraniu Małym to spokojna, szeroka rzeka nizinna o piaszczystym dnie i łagodnym nachyleniu brzegów. Woda płynie tu stabilnym nurtem, co sprzyja systematycznemu nęceciu stad leszczy oraz dorodnych płoci. To idealna lokalizacja dla miłośników feedera klasycznego, którzy cenią sobie komfortowe stanowiska na trawiastych brzegach. Spinningiści z sukcesami obławiają tutejsze pasy roślinności zanurzonej, szukając okoni oraz mniejszych szczupaków. Głębokość jest wyrównana, co pozwala na skuteczne badanie łowiska bez konieczności ciągłej zmiany obciążenia zestawu. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do całodniowego wypoczynku z wędką.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70398, 'Nizinna Wielka', 'Szeroka płania', 95.0, 2.8, 'Piaszczyste', 'Roślinność zanurzona', 'Leszcz, Płoć, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 400: Drogoszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70399, 'Narew - Drogoszewo (Rafy)', 'narew-drogoszewo', 'RIVER', 53.1714681, 21.7315773, 'Podlaskie', 'Łomża', 'Odcinek w Drogoszewie charakteryzuje się malowniczymi krajobrazami i czystą wodą płynącą szerokim korytem o urozmaiconym dnie. Rzeka posiada tu liczne żwirowe rafy oraz piaszczyste łachy, które są naturalnym tarliskiem dla ryb reofilnych. To doskonałe łowisko jaziowe, szczególnie efektywne podczas porannych rójek owadów na pograniczu głównego nurtu. Wędkarze gruntowi z sukcesami polują tu na brzany, wykorzystując ciężkie zestawy zdolne utrzymać przynętę w silnym nurcie. Uciąg wody jest żywy i dobrze natleniony, co przekłada się na wysoką kondycję i waleczność tutejszych ryb. Dostęp do wody jest dogodny, a liczne piaszczyste plaże ułatwiają bezpieczne lądowanie nawet większych okazów rzecznych.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70399, 'Nizinna Wielka', 'Nurt żywy, rafy żwirowe', 85.0, 2.2, 'Żwir i piasek', 'Rafy, łachy', 'Jaź, Brzana, Boleń', 'Kraina leszcza', 'Natura 2000', true);


-- Spot 401: Dębniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70400, 'Narew - Dębniki (Dzika)', 'narew-debniki', 'RIVER', 53.2248475, 21.8494408, 'Podlaskie', 'Nowogród', 'Narew w Dębnikach to odcinek o niezwykle dzikim charakterze, płynący wśród rozległych kompleksów leśnych i bagiennych. Koryto rzeki posiada tu liczne zatory z powalonych pni drzew, które stanowią bankowe kryjówki dla rekordowych szczupaków. Dno piaszczysto-żwirowe sprzyja aktywności dużych stad jazi, które doskonale reagują na techniki spinningowe o świcie. Uciąg rzeki jest zdecydowany, co sprzyja natlenieniu wody i wysokiej aktywności ryb reofilnych w głównym nurcie. Spinningiści z sukcesami obławiają tutejsze głębokie wymycia rzeźbiące dno na zewnętrznych łukach rzeki. Miejsce to gwarantuje całkowitą izolację od zgiełku i szansę na kontakt z niewypłoszoną rybą w trudnym terenie.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70400, 'Nizinna Wielka', 'Dzika, zatory drzewne', 80.0, 3.2, 'Piasek i żwir', 'Zwalone kłody', 'Szczupak, Jaź, Okoń', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 402: Radule (Narew Warkoczowa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70401, 'Narew - Radule (Amazonia)', 'narew-radule', 'RIVER', 53.1250905, 22.8124355, 'Podlaskie', 'Białystok', 'Odcinek w Radulach to kwintesencja rzeki warkoczowej, gdzie Narew rozdziela się na liczne, wąskie kanały i odnogi. To unikalne łowisko lina oraz złotego karasia, które znajdują tu doskonałe warunki w zacisznych i mocno porośniętych zatoczkach. Dno jest tu w większości muliste, z ogromną ilością roślinności wynurzonej stanowiącej naturalny filtr dla wody. Wędkarstwo wymaga tu dużej precyzji i stosowania wytrzymałego sprzętu zdolnego do siłowego holu ryb z gęstych trzcinowisk. Uciąg wody w głównych kanałach jest znikomy, co pozwala na stosowanie najdelikatniejszych technik spławikowych. Jest to miejsce o światowej randze przyrodniczej, oferujące wędkowanie w otoczeniu rzadkich gatunków ptaków wodnych i błotnych.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70401, 'Nizinna Wielka', 'Wielokorytowa (warkoczowa)', 30.0, 1.5, 'Muliste', 'Trzcinowiska, kanały', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 403: Rogowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70402, 'Narew - Rogowo (Rozlewiska)', 'narew-rogowo', 'RIVER', 53.1415221, 22.8825856, 'Podlaskie', 'Choroszcz', 'W Rogowie Narew płynie szerokimi rozlewiskami o bardzo urozmaiconej linii brzegowej usianej kępami tataraku. Dno piaszczysto-muliste obfituje w faunę denną, co przyciąga dorodne leszczowe stada żerujące na spokojniejszych płaniach rzeki. Spinningiści cenią ten odcinek za populację szczupaka, który chętnie stacjonuje w pobliżu krawędzi starego koryta rzeki. Uciąg jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu ryb spokojnego żeru w polu łowienia. Bardzo dobry dostęp do wody z brzegów pozwala na wygodne uprawianie wędkarstwa gruntowego z użyciem lekkiego feedera. Wieczorne wyprawy mogą tu zaowocować braniem wyrośniętego okonia, który agresywnie atakuje drobnicę przy brzegowych opaskach roślinności.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70402, 'Nizinna Wielka', 'Szerokie rozlewiska', 120.0, 2.0, 'Piasek i muł', 'Kępy tataraku', 'Leszcz, Szczupak, Okoń', 'Kraina leszcza', 'Otulina NPN', true);


-- Spot 404: Łomża (Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70403, 'Narew - Łomża (Miejskie Rynny)', 'narew-lomza-most', 'RIVER', 53.188545, 22.0913751, 'Podlaskie', 'Łomża', 'Narew w Łomży to potężna rzeka miejska o uregulowanym korycie i dużej dynamice przepływu wody. Pod filarami mostów rzeka wymyła głębokie rynny, które są doskonałym stanowiskiem dla sumów oraz sandaczy. Dno jest tu twarde, piaszczysto-żwirowe, co sprzyja aktywności ryb reofilnych żerujących w głównym nurcie. Wędkarze stacjonarni z sukcesami łowią tu dorodne brzany, wykorzystując ciężkie zestawy gruntowe z przynętami o intensywnym zapachu. Uciąg rzeki w rejonie bulwarów jest stabilny, co umożliwia precyzyjne operowanie zestawami spinningowymi w poszukiwaniu boleni. Miejscowa infrastruktura ułatwia dostęp do rzeki, czyniąc to łowisko jednym z najpopularniejszych punktów na mapie regionu.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70403, 'Nizinna Wielka', 'Uregulowane koryto miejskie', 95.0, 4.2, 'Piasek i żwir', 'Mosty, opaski betonowe', 'Brzana, Sum, Sandacz', 'Kraina leszcza', 'Brak', true);

-- Spot 405: Czarnocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70404, 'Narew - Czarnocin (Łachy)', 'narew-czarnocin', 'RIVER', 53.2284643, 22.0566528, 'Podlaskie', 'Łomża', 'Odcinek w Czarnocinie słynie z rozległych piaszczystych łach, które wychodzą daleko w główny nurt rzeki. Narew płynie tu szeroko, żłobiąc dno o piaszczystym charakterze z wyraźnymi przykosami idealnymi do żerowania kleni. To doskonałe miejsce dla spinningistów polujących na bolenie patrolujące turbulentną wodę na styku nurtu i zastoisk. Wędkarze gruntowi chętnie nęcą tutejsze rynny, celując w dorodne stadne płocie oraz wyrośnięte krąpie. Uciąg rzeki jest tu żywy, co wymaga stosowania koszyków zanętowych o masie przekraczającej siedemdziesiąt gramów dla stabilizacji. Malowniczy krajobraz doliny rzeki oraz niska presja wędkarska sprawiają, że każda wyprawa w to miejsce jest bardzo relaksująca.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70404, 'Nizinna Wielka', 'Szeroka, liczne przykosy', 110.0, 2.8, 'Piaszczyste', 'Piaszczyste łachy', 'Boleń, Kleń, Płoć', 'Kraina leszcza', 'Brak', true);

-- Spot 406: Szablak
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70405, 'Narew - Szablak (Głębokie Zakole)', 'narew-szablak', 'RIVER', 53.2393259, 21.9828398, 'Podlaskie', 'Łomża', 'Narew w Szablaku tworzy jedno z najgłębszych i najbardziej widowiskowych zakoli na środkowym biegu rzeki. Zewnętrzny łuk koryta posiada pionowe, gliniaste burty, pod którymi woda wymyła rynny o głębokości ponad pięciu metrów. To legendarne stanowisko sumowe, gdzie potężne drapieżniki znajdują idealne warunki do stacjonowania przez cały sezon. Spinningiści z sukcesami obławiają tutejsze uskoki dna, szukając sandaczy oraz okazowych okoni żerujących przy dnie. Uciąg rzeki w tym miejscu jest skomplikowany przez liczne wiry wsteczne, co wymaga od wędkarza dużego doświadczenia. Cisza panująca wzdłuż wysokiego brzegu sprzyja wyciszeniu i długim, nocnym zasiadkom z nastawieniem na rybę życia.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70405, 'Nizinna Wielka', 'Silne zakole, głębokie', 85.0, 5.5, 'Glina i piasek', 'Wiry wsteczne, burty', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 407: Strękowa Góra
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70406, 'Narew - Strękowa Góra (Wizna)', 'narew-strekowa-gora', 'RIVER', 53.2208834, 22.5445623, 'Podlaskie', 'Wizna', 'Narew w Strękowej Górze to jeden z najbardziej widowiskowych odcinków rzeki, płynący u stóp wysokich wzgórz morenowych. Koryto jest tu szerokie i głębokie, z wyraźnie zaznaczoną rynną główną, w której stacjonują potężne sumy oraz sandacze. To legendarne łowisko dla spinningistów polujących na bolenie, które regularnie uderzają w drobnicę na piaszczystych przykosach. Dno jest twarde, piaszczysto-żwirowe, co sprzyja aktywności ryb reofilnych takich jak certy oraz wyrośnięte brzany. Uciąg wody jest tu zdecydowany, co wymusza stosowanie dociążonych koszyków zanętowych przy połowie metodą drgającej szczytówki. Wysoki brzeg stanowi doskonały punkt obserwacyjny, pozwalający zlokalizować żerujące stada ryb przed wejściem do wody.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70406, 'Nizinna Wielka', 'Szeroka, nurt żywy', 110.0, 3.5, 'Piasek i żwir', 'Rynny prądowe', 'Sum, Boleń, Brzana', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 408: Giełczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70407, 'Narew - Giełczyn (Rozlewiska)', 'narew-gielczyn', 'RIVER', 53.2168443, 22.4681807, 'Podlaskie', 'Łomża', 'Odcinek w Giełczynie charakteryzuje się naturalnym, meandrującym korytem i rozległymi rozlewiskami o bardzo bogatej roślinności wynurzonej. Rzeka tworzy tu liczne, ciche zatoczki, które są wymarzonym siedliskiem dla lina oraz wyrośniętego złotego karasia. Dno piaszczysto-muliste obfituje w naturalny pokarm, co przyciąga stadne leszcze żerujące na spokojniejszych płaniach rzeki. Spinningiści z sukcesami polują tu na szczupaki, obławiając krawędzie kęp grążeli oraz pasy trzcinowisk przy brzegach. Uciąg jest umiarkowany, co pozwala na komfortowe wędkowanie przy użyciu delikatnych zestawów spławikowych z długim wędziskiem. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, czyniąc to łowisko atrakcyjnym punktem regionu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70407, 'Nizinna Wielka', 'Meandrująca, rozlewiska', 90.0, 2.8, 'Piasek i muł', 'Kępy grążeli', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 409: Złotoria (Połączenie z Narwią)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70408, 'Narew - Złotoria (Ujście Supraśli)', 'narew-zlotoria-ujscie', 'RIVER', 53.1554253, 22.9540019, 'Podlaskie', 'Choroszcz', 'W Złotorii Narew łączy się z rzeką Supraśl, co tworzy niezwykle rybny węzeł wodny o dużej dynamice przepływu. Mieszające się nurty obu rzek tworzą bogate w tlen i pokarm zastoiska, w których chętnie przebywają stadne jazie. To strategiczne miejsce dla łowców boleni, którzy patrolują piaszczyste przykosy poniżej połączenia nurtów rzecznych. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe z licznymi rynnami wymytymi przez silny prąd główny rzeki. Wędkarze gruntowi z sukcesami stosują tu metodę feedera klasycznego, celując w dorodne płocie oraz rekordowe leszcze. Miejsce to zapewnia świetne warunki do aktywnego wypoczynku ze spinningiem w otoczeniu dzikiej, podlaskiej przyrody.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70408, 'Nizinna Wielka', 'Węzeł wodny, szeroka', 130.0, 3.0, 'Piasek i żwir', 'Połączenie nurtów', 'Jaź, Boleń, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 410: Złotoria (Głębokie Zakole)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70409, 'Narew - Złotoria (Zakole Północne)', 'narew-zlotoria-zakole', 'RIVER', 53.1986897, 22.9294799, 'Podlaskie', 'Choroszcz', 'Północny odcinek w Złotorii słynie z głębokich wymyć koryta rzeki, dochodzących lokalnie do czterech metrów głębokości. Rzeka mocno tu meandruje, żłobiąc dno o charakterze gliniasto-piaszczystym z licznymi podwodnymi przeszkodami w postaci korzeni. To doskonałe łowisko sumowe, gdzie nocne zasiadki z żywcem często kończą się emocjonującymi holami okazowych ryb. Spinningiści z sukcesami obławiają tutejsze stoki koryta, szukając sandaczy oraz okazałych okoni żerujących przy dnie rzeki. Uciąg jest stabilny i pozwala na precyzyjne operowanie ciężkimi zestawami gruntowymi zdolnymi utrzymać przynętę w nurcie. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do wielogodzinnych wypraw spinningowych.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70409, 'Nizinna Wielka', 'Meandrująca, głęboka', 95.0, 4.0, 'Glina i piasek', 'Głębokie jamy', 'Sum, Sandacz, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 411: Góra (Polska Amazonia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70410, 'Narew - Góra (Warkoczowa)', 'narew-gora', 'RIVER', 53.228756, 22.873341, 'Podlaskie', 'Tykocin', 'Narew w okolicach miejscowości Góra to klasyczny odcinek warkoczowy, gdzie rzeka rozdziela się na liczne kanały. Podłoże jest tu piaszczysto-muliste, a brzegi porośnięte są gęstymi trzcinowiskami, co stwarza idealne warunki tlenowe dla ryb. Jest to wymarzone miejsce dla łowców linów oraz wzdręg, które gromadzą się w zacisznych odnogach starego koryta. Wędkarstwo wymaga tu dużej precyzji i umiejętnego poruszania się łodzią między licznymi mieliznami oraz kępami roślinności. Uciąg wody w mniejszych kanałach jest znikomy, co pozwala na stosowanie najdelikatniejszych technik spławikowych z lekkim batem. To unikalne łowisko o charakterze bagiennym zapewnia niezapomniane wrażenia estetyczne w samym sercu parku narodowego.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70410, 'Nizinna Wielka', 'Wielokorytowa (warkoczowa)', 35.0, 1.8, 'Piasek i muł', 'Labirynt kanałów', 'Lin, Wzdręga, Szczupak', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 412: Tykocin (Most Zamkowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70411, 'Narew - Tykocin (Miejska)', 'narew-tykocin-most', 'RIVER', 53.2111345, 22.8032932, 'Podlaskie', 'Tykocin', 'Narew w Tykocinie to techniczne łowisko z uregulowanym korytem i historycznymi umocnieniami brzegowymi w rejonie zamku. Pod filarami mostu rzeka wymyła głębokie rynny, które są doskonałą kryjówką dla sandaczy oraz dorodnych kleni rzecznych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując metodę klasycznej przepływanki przy kamiennych opaskach brzegowych. Dno jest tu twarde, piaszczysto-kamieniste, z wyraźnymi załamaniami nurtu sprzyjającymi drapieżnikom żerującym w warkoczach prądowych. Spinningowanie z bulwarów daje szansę na kontakt z wyrośniętym boleniem patrolującym środkową część szerokiego koryta rzeki. Dobra infrastruktura i łatwy dostęp do wody sprawiają, że jest to jedno z najchętniej odwiedzanych miejsc w regionie.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70411, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 100.0, 2.5, 'Piasek i kamień', 'Filary mostu, opaski', 'Leszcz, Sandacz, Boleń', 'Kraina leszcza', 'Otulina NPN', true);

-- Spot 413: Tykocin (Warkoczowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70412, 'Narew - Tykocin (Labirynt)', 'narew-tykocin-labirynt', 'RIVER', 53.2136428, 22.7280499, 'Podlaskie', 'Tykocin', 'Narew w Tykocinie na tym odcinku to prawdziwy labirynt trzcinowisk i bocznych odnóg o niewielkim uciągu. Dno jest tu mocno zamulone, co sprzyja bytowaniu rekordowych linów oraz złotych karasi. Spinningiści z sukcesami obławiają krawędzie roślinności wynurzonej, szukając szczupaków czatujących w cieniu tataraku. Woda jest dobrze natleniona, mimo leniwego przepływu, co zapewnia wysoką kondycję tutejszego białorybu. Dojście do wody jest utrudnione przez podmokłe brzegi, dlatego najskuteczniejszą metodą jest łowienie z łodzi. To magiczne miejsce w otulinie parku narodowego oferuje absolutną ciszę i bliskość dzikiej, nieujarzmionej natury.', 'PZW Białystok');

