VALUES (70412, 'Nizinna Wielka', 'Wielokorytowa, bagienna', 40.0, 1.6, 'Muliste', 'Trzcinowiska, starorzecza', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Otulina NPN', true);

-- Spot 414: Zawady-Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70413, 'Narew - Zawady-Kolonia (Przełom)', 'narew-zawady-kolonia', 'RIVER', 53.210424, 22.6526501, 'Podlaskie', 'Wizna', 'Odcinek w Zawadach-Kolonii charakteryzuje się przejściem rzeki z formy wielokorytowej w jedno, szerokie koryto główne. Dno jest tu w większości piaszczyste, z wyraźnymi rynnami na łukach, które stanowią bezpieczne schronienie dla dorodnych leszczy. Wędkarze gruntowi z sukcesami stosują tu metodę feedera, celując w ryby żerujące na krawędzi piaszczystych przykos. Spinningiści cenią to miejsce za populację bolenia, który regularnie pokazuje się w nurcie poniżej piaszczystych łach. Uciąg wody stabilizuje się, co pozwala na komfortowe operowanie zestawami spławikowymi z długim wędziskiem. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem na mapie regionu.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70413, 'Nizinna Wielka', 'Szeroka, nurt umiarkowany', 85.0, 2.2, 'Piaszczyste', 'Piaszczyste łachy', 'Leszcz, Boleń, Jaź', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 415: Sokołowo Włościańskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70414, 'Narew - Sokołowo Włościańskie', 'narew-sokolowo-wloscianskie', 'RIVER', 52.7795811, 21.3032582, 'Mazowieckie', 'Pułtusk', 'Narew w Sokołowie Włościańskim to potężna rzeka nizinna o szerokim korycie i stabilnym, dość silnym nurcie. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe, z głębokimi rynnami sięgającymi ponad trzy metry głębokości. To strategiczne miejsce dla łowców sumów i sandaczy, które żerują na piaszczystych przykosach środkowego nurtu. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując ciężkie koszyki feederowe dla stabilizacji zestawu. Brzegi są naturalne, częściowo porośnięte wikliną, co oferuje wiele zacisznych stanowisk dla wędkarzy szukających spokoju. Wieczorne wyprawy z lekkim spinningiem mogą zakończyć się tu emocjonującym holem walecznego bolenia lub klenia.', 'PZW Mazowieckie');

