-- Spot 416: Gostkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70415, 'Narew - Gostkowo (Przykosy)', 'narew-gostkowo', 'RIVER', 52.76795, 21.2302739, 'Mazowieckie', 'Pułtusk', 'Odcinek w Gostkowie słynie z rozległych piaszczystych przykos wychodzących daleko w nurt rzeki, tworząc turbulentne warkocze. To wymarzone miejsce dla spinningistów polujących na bolenie, które agresywnie żerują na stadach uklei przy krawędzi nurty. Dno piaszczyste zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką kondycję i waleczność. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w wyrośnięte certy oraz dorodne stadne płocie. Uciąg rzeki jest tu zdecydowany i wymaga od wędkarza umiejętnego czytania prądów wodnych dla poprawnej prezentacji przynęty. Malowniczy krajobraz doliny Narwi nadaje każdej wyprawie wędkarskiej wyjątkowego, dzikiego charakteru sprzyjającego wypoczynkowi.', 'PZW Mazowieckie');

