VALUES (70415, 'Nizinna Wielka', 'Szeroka, nurt żywy', 120.0, 2.5, 'Piaszczyste', 'Przykosy, warkocze', 'Boleń, Certa, Płoć', 'Kraina leszcza', 'Brak', true);

-- Spot 417: Gnojno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70416, 'Narew - Gnojno (Wysoka Skarpa)', 'narew-gnojno', 'RIVER', 52.7781774, 21.1576868, 'Mazowieckie', 'Pułtusk', 'Gnojno to legendarne miejsce na mapie dolnej Narwi, znane z wysokiego brzegu i głębokich rynien przydennych. Rzeka płynie tu szerokim korytem, żłobiąc dno o piaszczysto-gliniastym charakterze z licznymi podwodnymi przeszkodami. To strategiczne stanowisko dla łowców sumów, którzy wykorzystują duże uskoki dna jako naturalne ostoje drapieżników. Spinningiści z sukcesami polują tu na sandacze, stosując ciężkie gumy prowadzone agresywnym opadem w głównym nurcie. Uciąg rzeki jest zdecydowany i wymaga od wędkarza stosowania dociążonych zestawów gruntowych dla zachowania stabilności. Malowniczy widok z wysokiej skarpy pozwala na precyzyjne namierzenie piaszczystych przykos, gdzie regularnie żerują stada boleni.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70416, 'Nizinna Wielka', 'Szeroka, głębokie koryto', 130.0, 4.5, 'Glina i piasek', 'Rynny, skarpy', 'Sum, Sandacz, Boleń', 'Kraina leszcza', 'Brak', true);

-- Spot 418: Pawłówek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70417, 'Narew - Pawłówek (Zatoki)', 'narew-pawlowek', 'RIVER', 52.7412514, 21.1151416, 'Mazowieckie', 'Pułtusk', 'Narew w Pawłówku to odcinek o umiarkowanym nurcie z licznymi, spokojnymi zatokami porośniętymi grążelami oraz tatarakiem. Dno piaszczysto-muliste obfituje w naturalny pokarm, co przyciąga dorodne leszczowe stada oraz wyrośnięte liny. To idealna lokalizacja dla wędkarzy spławikowych, którzy cenią sobie precyzyjne łowienie w "oknach" między roślinnością zanurzoną. Spinningiści z sukcesami obławiają tutejsze stoki starego koryta rzeki, szukając okoni oraz szczupaków czatujących na drobnicę. Uciąg rzeki pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w polu łowienia przez wiele godzin. Dogodny dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na rodzinne biwaki połączone z wędkowaniem.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70417, 'Nizinna Wielka', 'Szeroka, liczne zatoki', 115.0, 2.8, 'Piasek i muł', 'Zatoki, grążele', 'Leszcz, Lin, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 419: Pułtusk (Wenecja Mazowsza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70418, 'Narew - Pułtusk (Miejska Płania)', 'narew-pultusk-centrum', 'RIVER', 52.6960156, 21.0918064, 'Mazowieckie', 'Pułtusk', 'Narew w Pułtusku to potężna rzeka nizinna o szerokim korycie i rozwiniętej sieci kanałów miejskich. Głębokość w rynnie głównej sięga tu czterech metrów, co sprzyja bytowaniu okazałych sumów oraz sandaczy żerujących przy dnie. Spinningiści z sukcesami obławiają rejony mostów oraz betonowe opaski, szukając kleni i okoni patrolujących brzegi. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w rekordowe leszcze, które grupują się w spokojniejszych partiach nurtu. Uciąg wody jest stabilny, jednak intensywny ruch jednostek pływających wymaga od wędkarzy zachowania wzmożonej uwagi. To techniczne łowisko zapewnia doskonały dostęp do wody bezpośrednio z miejskich bulwarów oraz dogodne miejsca do wodowania łodzi.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70418, 'Nizinna Wielka', 'Szeroka, uregulowana miejska', 140.0, 3.5, 'Piasek i glina', 'Kanały miejskie, mosty', 'Leszcz, Sandacz, Sum', 'Kraina leszcza', 'Brak', true);

-- Spot 420: Kruszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70419, 'Narew - Kruszewo (Meandry)', 'narew-kruszewo', 'RIVER', 52.9485876, 21.4707033, 'Mazowieckie', 'Ostrołęka', 'Odcinek w Kruszewie charakteryzuje się naturalnym, meandrującym korytem płynącym wśród rozległych nadnarwiańskich łąk. Rzeka żłobi tu dno o charakterze piaszczysto-gliniastym, tworząc głębokie rynny na zewnętrznych łukach koryta. To doskonałe miejsce dla spinningistów polujących na szczupaki, które chętnie stacjonują w pobliżu pasów roślinności zanurzonej. Wędkarze feederowi z sukcesami łowią tu dorodne płocie oraz krąpie, wykorzystując systematyczne nęcenie na piaszczystych przykosach. Uciąg wody jest umiarkowany, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem dla osób szukających spokoju.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70419, 'Nizinna Wielka', 'Meandrująca, naturalna', 85.0, 2.5, 'Piasek i glina', 'Podmyte brzegi', 'Szczupak, Płoć, Krąp', 'Kraina leszcza', 'Brak', true);

-- Spot 421: Sieluń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70420, 'Narew - Sieluń (Przykosy)', 'narew-sielun', 'RIVER', 52.9220364, 21.4103387, 'Mazowieckie', 'Różan', 'Narew w Sieluniu to szeroka rzeka nizinna słynąca z rozległych piaszczystych łach wychodzących daleko w główny nurt. To strategiczne miejsce dla łowców boleni, które regularnie patrolują krawędzie warkoczy prądowych na środku rzeki. Dno jest tu twarde i piaszczyste, co sprzyja aktywności ryb reofilnych, szczególnie walecznych jazi oraz kleni. Wędkarze gruntowi chętnie nęcą tutejsze głębokie rynny, celując w dorodne stadne leszcze żerujące na faunie dennej. Uciąg rzeki jest zdecydowany i wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu w nurcie. Malowniczy krajobraz doliny Narwi oraz czysta woda sprawiają, że każda wyprawa w to miejsce jest bardzo relaksująca i owocna.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70420, 'Nizinna Wielka', 'Szeroka, liczne przykosy', 100.0, 2.8, 'Piaszczyste', 'Przykosy, warkocze', 'Boleń, Jaź, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 422: Paulinowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70421, 'Narew - Paulinowo (Rynny)', 'narew-paulinowo', 'RIVER', 52.8750795, 21.4143173, 'Mazowieckie', 'Różan', 'Odcinek w Paulinowie oferuje wędkarzom dostęp do rzeki o bardzo urozmaiconej rzeźbie dna z głębokimi rynnami brzegowymi. Rzeka mocno tu meandruje, tworząc liczne techniczne stanowiska pod wysokimi, gliniastymi burtami zewnętrznych łuków. To wymarzone miejsce dla spinningistów polujących na sandacze, którzy stosują ciężkie gumy prowadzone agresywnym opadem. Podmyte korzenie nadbrzeżnych drzew stanowią bankowe kryjówki dla wyrośniętych okoni oraz szczupaków czatujących na drobnicę. Uciąg wody przyspiesza na przewężeniach, co sprzyja natlenieniu rzeki i wysokiej aktywności ryb w ciągu całego dnia. Miejsce to zapewnia intymną atmosferę i daje szansę na kontakt z dziką rybą w otoczeniu nienaruszonej przyrody.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70421, 'Nizinna Wielka', 'Silnie meandrująca, głęboka', 90.0, 3.2, 'Glina i piasek', 'Głębokie jamy', 'Sandacz, Okoń, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 423: Dzbądz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70422, 'Narew - Dzbądz (Plaże)', 'narew-dzbadz', 'RIVER', 52.8357205, 21.4516603, 'Mazowieckie', 'Różan', 'Dzbądz to popularne łowisko nadnarwiańskie, znane z rozległych piaszczystych plaż i dogodnego dostępu do linii brzegowej. Rzeka rozlewa się tu szeroko, tworząc rybne płanie o urozmaiconym, piaszczysto-żwirowym podłożu koryta. To idealna lokalizacja dla miłośników feedera klasycznego, celujących w dorodne leszcze oraz wyrośnięte krąpie. Spinningiści z sukcesami obławiają tutejsze warkocze, szukając boleni oraz kleni żerujących w głównym nurcie wody. Uciąg jest stabilny i pozwala na precyzyjne operowanie zestawami gruntowymi nawet na znacznych odległościach od brzegu. Miejsce to jest chętnie wybierane na wielodniowe biwaki wędkarskie ze względu na komfortowe warunki terenowe i wysoką rybność.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70422, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 110.0, 2.2, 'Piasek i żwir', 'Plaże, przykosy', 'Leszcz, Boleń, Kleń', 'Kraina leszcza', 'Brak', true);

-- Spot 424: Ostrykół Dworski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70423, 'Narew - Ostrykół Dworski (Zakole)', 'narew-ostrykol-dworski', 'RIVER', 52.791729, 21.4703714, 'Mazowieckie', 'Pułtusk', 'Narew w Ostrykole Dworskim tworzy potężne zakole z wysokim brzegiem i głęboką rynną wymytą pod gliniastą burtą. Podłoże jest tu mocno zróżnicowane, od twardej gliny po piaszczyste naniesienia, co stwarza doskonałe warunki dla różnych technik łowienia. To strategiczne miejsce dla łowców okazowych sumów, które wykorzystują głębokie doły jako swoje główne ostoje. Spinningiści z sukcesami polują tu na szczupaki, obławiając pasy trzcin oraz kępy roślinności zanurzonej przy brzegach. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza umiejętnego czytania prądów wodnych i wirów wstecznych. Stanowisko to gwarantuje absolutny spokój i szansę na kontakt z niewypłoszoną rybą w surowym krajobrazie Mazowsza.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70423, 'Nizinna Wielka', 'Szerokie zakole, głębokie', 120.0, 4.0, 'Glina i piasek', 'Wiry wsteczne, burty', 'Sum, Szczupak, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 425: Wólka-Wojciechówek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70424, 'Narew - Wólka-Wojciechówek (Głęboka Rynna)', 'narew-wolka-wojciechowek', 'RIVER', 52.7871613, 21.394497, 'Mazowieckie', 'Pułtusk', 'Narew w Wólce-Wojciechówku to potężna rzeka nizinna o szerokim korycie i wyraźnie zaznaczonych głębokich rynnach. Nurt jest tu stabilny, co sprzyja bytowaniu rekordowych leszczy oraz wyrośniętych krąpi żerujących na piaszczysto-gliniastym dnie. Spinningiści z sukcesami polują tu na sandacze, wykorzystując ciężkie gumy prowadzone agresywnym opadem w głównym prądzie rzeki. Podmyte brzegi porośnięte gęstą wikliną skrywają wyrośnięte okonie oraz szczupaki czatujące na stadka uklei. Uciąg wody jest zdecydowany i wymaga od wędkarza stosowania dociążonych koszyków zanętowych dla poprawnej prezentacji przynęty. To techniczne łowisko zapewnia doskonałe warunki do wielogodzinnych zasiadek gruntowych w otoczeniu dzikiego krajobrazu Mazowsza.', 'PZW Mazowieckie');

