VALUES (70424, 'Nizinna Wielka', 'Szeroka rzeka, rynny', 115.0, 3.2, 'Piasek i glina', 'Rynny prądowe', 'Leszcz, Sandacz, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 426: Nowa Łuka (Wypływ z Siemianówki)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70425, 'Narew - Nowa Łuka (Wypływ)', 'narew-nowa-luka', 'RIVER', 52.9401821, 23.7569254, 'Podlaskie', 'Hajnówka', 'Odcinek w Nowej Łuce znajduje się bezpośrednio poniżej zapory czołowej Zbiornika Siemianówka, co gwarantuje specyficzne warunki tlenowe. Rzeka płynie tu uregulowanym korytem o umiarkowanym uciągu i dnie piaszczysto-mulistym z bogatą roślinnością zanurzoną. To strategiczne miejsce dla łowców szczupaków i okoni, które migrują między rzeką a rozległym zbiornikiem zaporowym. Wędkarze spławikowi z sukcesami łowią tu dorodne liny oraz wzdręgi, wykorzystując zaciszne miejsca przy brzegowych trzcinowiskach. Uciąg wody jest regulowany przez urządzenia hydrotechniczne, co wymusza na wędkarzach częstą korektę obciążenia zestawu. Miejsce to zapewnia bardzo dobry dostęp do wody oraz szansę na kontakt z rybami o pokaźnych rozmiarach.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70425, 'Nizinna Wielka', 'Uregulowany wypływ spod zapory', 25.0, 1.8, 'Piasek i muł', 'Zapora, roślinność', 'Szczupak, Lin, Okoń', 'Kraina leszcza', 'Odcinek przyzaporowy', true);

-- Spot 427: Eliaszuki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70426, 'Narew - Eliaszuki (Torfowiska)', 'narew-eliaszuki', 'RIVER', 52.9336252, 23.682989, 'Podlaskie', 'Narewka', 'Narew w Eliaszukach to rzeka o niezwykle naturalnym i dzikim charakterze, płynąca meandrami wśród rozległych terenów torfowych. Woda ma tu charakterystyczny ciemny kolor, a dno jest w większości piaszczysto-muliste z licznymi podwodnymi przeszkodami. To wymarzone łowisko lina oraz złotego karasia, które znajdują tu doskonałe warunki w zacisznych zakolach rzeki. Spinningiści z sukcesami obławiają tutejsze trzcinowiska, szukając szczupaków żerujących na licznej drobnicy białorybu. Uciąg jest znikomy, co pozwala na stosowanie najdelikatniejszych technik spławikowych z czułym wędziskiem. Niska presja wędkarska oraz trudny dostęp do brzegów gwarantują absolutny spokój i bliski kontakt z surową przyrodą Podlasia.', 'PZW Białystok');

