-- Spot 428: Odrynki (Miejsce Mocy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70427, 'Narew - Odrynki (Rozlewiska)', 'narew-odrynki', 'RIVER', 52.931621, 23.6082675, 'Podlaskie', 'Narew', 'Odcinek w Odrynkach słynie z rozległych rozlewisk otaczających prawosławny Skit Świętych Antoniego i Teodozjusza Pieczerskich. Rzeka tworzy tu labirynt kanałów i zastoisk o piaszczystym dnie, w których chętnie przebywają stadne jazie oraz klenie. To idealne miejsce dla wędkarzy spławikowych celujących w dorodne wzdręgi żerujące w oknach między roślinnością wynurzoną. Uciąg rzeki jest tu zróżnicowany, przyspieszając na głównym korycie i niemal zanikając w licznych odnogach starego koryta. Spinningista znajdzie tutaj mnóstwo technicznych miejsc do prowadzenia lekkich przynęt w poszukiwaniu rzecznych drapieżników. Unikalna atmosfera tego miejsca oraz wszechobecna cisza czynią każdą wyprawę wędkarską niezapomnianym przeżyciem duchowym.', 'PZW Białystok');

