VALUES (70427, 'Nizinna Średnia', 'Wielokorytowa, naturalna', 20.0, 1.2, 'Piaszczyste', 'Starorzecza, trzciny', 'Jaź, Wzdręga, Kleń', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 429: Narew (Miejscowość)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70428, 'Narew - Narew (Głębokie Doły)', 'narew-miejscowosc', 'RIVER', 52.9136159, 23.5398739, 'Podlaskie', 'Narew', 'Narew w samej miejscowości o tej samej nazwie to rzeka o dość szerokim korycie i urozmaiconym, piaszczystym dnie. W rejonie mostu rzeka wymyła głębokie rynny, które są doskonałym stanowiskiem dla sumów oraz sandaczy czatujących w nurcie. Wędkarze gruntowi z sukcesami łowią tu okazałe leszcze, wykorzystując metodę klasycznej przepływanki przy brzegowych opaskach. Uciąg rzeki jest stabilny i umiarkowany, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu w polu łowienia. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy filarach mostowych oraz konstrukcjach faszynowych. Dogodna infrastruktura w miejscowości ułatwia dostęp do wody, czyniąc to łowisko popularnym punktem na mapie regionu.', 'PZW Białystok');

