-- Spot 430: Trześcianka (Kraina Okiennic)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70429, 'Narew - Trześcianka (Zakola łąkowe)', 'narew-trzescianka', 'RIVER', 52.9159914, 23.4647695, 'Podlaskie', 'Zabłudów', 'Trześcianka oferuje dostęp do rzeki o typowo nizinno-łąkowym charakterze, wijącej się malowniczo wśród podlaskich wsi. Liwiec (Narew) w tym miejscu tworzy rozległe zakola z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach koryta. To doskonałe łowisko dla miłośników lekkiego feedera celujących w dorodne płocie oraz krąpie żerujące na piaszczystym dnie. Spinningiści chętnie obławiają tutejsze pasy roślinności zanurzonej, szukając szczupaków czatujących w cieniu brzegowych wierzb. Uciąg jest łagodny, co sprzyja systematycznemu nęceniu i długim, relaksującym sesjom z wędką w otoczeniu Krainy Otwartych Okiennic. Dostęp do wody jest utrudniony przez wysokie trawy, co nagradza wędkarzy szukających ciszy i mniejszej presji wędkarskiej.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70429, 'Nizinna Średnia', 'Meandrująca, łąkowa', 22.0, 1.5, 'Piasek i glina', 'Podmyte burty', 'Płoć, Szczupak, Krąp', 'Kraina leszcza', 'Kraina Otwartych Okiennic', true);

-- Spot 431: Janowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70430, 'Narew - Janowo (Podlaskie Zakola)', 'narew-janowo', 'RIVER', 52.9006381, 23.3942002, 'Podlaskie', 'Narew', 'Narew w Janowie to urokliwy odcinek górnej rzeki płynącej malowniczymi zakolami przez podlaskie pola. Dno jest tu piaszczyste z lokalnymi rynnami, które stanowią doskonałe stanowisko dla stadnych jelców. Wędkarze spławikowi z sukcesami stosują lekką przepływankę, celując w dorodne płocie żerujące w nurcie. Spinningiści znajdą tutaj liczne warkocze powstające za naturalnymi przeszkodami, gdzie chętnie ustawiają się klenie. Uciąg wody jest stabilny i pozwala na bardzo precyzyjne nęcenie pola łowiska luźną zanętą. To kameralne miejsce zapewnia spokój oraz szansę na kontakt z dziką rzeką z dala od miejskiego zgiełku.', 'PZW Białystok');

