-- Spot 432: Kaniuki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70431, 'Narew - Kaniuki (Kraina Okiennic)', 'narew-kaniuki', 'RIVER', 52.892538, 23.3207746, 'Podlaskie', 'Zabłudów', 'Kaniuki oferują dostęp do rzeki o wybitnie meandrującym charakterze w samym sercu Krainy Otwartych Okiennic. Rzeka płynie tu szerzej, żłobiąc głębokie jamy pod wysokimi burtami na zewnętrznych łukach koryta. To doskonałe łowisko szczupakowe, gdzie drapieżniki czatują w pasach trzcinowisk i kępach grążeli. Wędkarze gruntowi chętnie nęcą piaszczyste przykosy, licząc na brania jazi oraz dorodnych leszczy. Uciąg wody jest umiarkowany, co sprzyja systematycznemu nęceniu i długim, relaksującym sesjom z feederem. Przejrzystość toni wymaga od wędkarza pełnej dyskrecji oraz stosowania cienkich przyponów z fluorocarbonu.', 'PZW Białystok');

