-- Spot 433: Izbiszcze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70432, 'Narew - Izbiszcze (Warkoczowa)', 'narew-izbiszcze', 'RIVER', 53.0811062, 22.8791472, 'Podlaskie', 'Choroszcz', 'Izbiszcze to brama do Narwiańskiego Parku Narodowego, gdzie rzeka przybiera unikalną formę warkoczową. Labirynt wąskich kanałów i starorzeczy tworzy idealne warunki dla lina oraz złotego karasia. Podłoże jest tu mocno zamulone, co wymaga stosowania lekkich zestawów spławikowych z czułymi sygnalizatorami. Spinningowanie zarośniętych rynien może zaowocować widowiskowymi atakami szczupaków z powierzchniowej warstwy wody. Uciąg jest znikomy, co pozwala na bardzo precyzyjne podanie przynęty w "okna" między grążelami. Ze względu na ochronę przyrody, wędkowanie tutaj odbywa się w otoczeniu rzadkich ptaków wodno-błotnych.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70432, 'Nizinna Wielka', 'Wielokorytowa (anastomozująca)', 15.0, 1.4, 'Muliste', 'Labirynt kanałów', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 434: Baciuty
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70433, 'Narew - Baciuty (Bagienna)', 'narew-baciuty', 'RIVER', 53.0554294, 22.9429286, 'Podlaskie', 'Łapy', 'Odcinek w Baciutach to dzika Narew płynąca wśród rozległych torfowisk i podmokłych łęgów Parku Narodowego. Rzeka rozdziela się tu na wiele ramion, tworząc mozaikę płytkich piaszczystych łach oraz głębokich, mulistych zastoisk. To strategiczne miejsce dla łowców wzdręg, które grupują się w dobrze natlenionej wodzie przy krawędziach trzcin. Spinningista znajdzie tutaj mnóstwo technicznych wyzwań przy obławianiu bocznych odnóg starego koryta. Uciąg wody jest zmienny, przyspieszając w głównym nurcie i niemal całkowicie zamierając w bocznych kanałach. To surowe i wymagające łowisko, które nagradza wędkarzy potrafiących czytać wodę w środowisku bagiennym.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70433, 'Nizinna Wielka', 'Wielokorytowa, bagienna', 12.0, 1.1, 'Muł i piasek', 'Zastoiska', 'Wzdręga, Szczupak, Lin', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 435: Ploski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70434, 'Narew - Ploski (Przy Moście)', 'narew-ploski', 'RIVER', 52.9016108, 23.2476395, 'Podlaskie', 'Bielsk Podlaski', 'Narew w Ploskach charakteryzuje się dość głębokim korytem i obecnością strategicznego mostu drogowego. Pod filarami mostu rzeka wymyła rynny o głębokości ponad trzech metrów, będące ostoją dla sandaczy. Dno jest tu twardsze, piaszczysto-żwirowe, co sprzyja aktywności sumów żerujących w głównym nurcie. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera, celując w dorodne brzany oraz leszcze. Uciąg rzeki jest zdecydowany i wymaga od wędkarza umiejętnego czytania prądów oraz wirów wstecznych. Dogodny dostęp do brzegów sprawia, że jest to popularny punkt wypadowy dla mieszkańców pobliskich miast.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70434, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 35.0, 2.5, 'Piasek i żwir', 'Filary mostu, głębokie rynny', 'Sandacz, Brzana, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 436: Zajączki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70435, 'Narew - Zajączki (Łąkowe Meandry)', 'narew-zajaczki', 'RIVER', 52.9105371, 23.1744552, 'Podlaskie', 'Juchnowiec Kościelny', 'Zajączki to odcinek o wybitnie naturalnym charakterze, wijący się malowniczo wśród nadnarwiańskich łąk. Rzeka tworzy tu głębokie zakola z wyraźnie zaznaczoną rynną, gdzie chętnie grupują się wyrośnięte jazie. To doskonałe miejsce dla spinningistów polujących na klenie z wykorzystaniem mikro-woblerów i smużaków. Dno piaszczysto-gliniaste zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką waleczność. Uciąg jest umiarkowany, co pozwala na komfortowe nęcenie i utrzymywanie białorybu w polu łowienia. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko atrakcyjnym punktem regionu.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70435, 'Nizinna Średnia', 'Meandrująca, naturalna', 22.0, 1.8, 'Piasek i glina', 'Rynny prądowe', 'Jaź, Kleń, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 437: Suraż
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70436, 'Narew - Suraż (Wrota Parku)', 'narew-suraz', 'RIVER', 52.9287694, 22.9593236, 'Podlaskie', 'Suraż', 'Narew w Surażu to strategiczny punkt, w którym rzeka zaczyna swój unikalny bieg warkoczowy w granicach parku narodowego. Koryto jest tu jeszcze stosunkowo zwarte, o piaszczysto-mulistym dnie i umiarkowanym uciągu wody. To doskonałe łowisko dla miłośników spławika, którzy celują w dorodne liny oraz wzdręgi żerujące przy krawędziach trzcin. Spinningiści z sukcesami obławiają tutejsze starorzecza, szukając szczupaków oraz okazałych okoni czatujących w grążelach. Pod filarami historycznego mostu woda wymyła głębsze rynny, będące doskonałą kryjówką dla kleni oraz jazi. Miejsce to zapewnia świetną bazę wypadową do eksploracji bagiennych odcinków rzeki przy użyciu łodzi lub kajaka.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70436, 'Nizinna Wielka', 'Wielonurtowa, naturalna', 35.0, 1.8, 'Piasek i muł', 'Most, starorzecza', 'Lin, Szczupak, Kleń', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 438: Łapy-Dębowina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70437, 'Narew - Łapy-Dębowina (Bagienna)', 'narew-lapy-debowina', 'RIVER', 52.9689099, 22.9251181, 'Podlaskie', 'Łapy', 'Odcinek w Łapach-Dębowinie charakteryzuje się labiryntem wąskich kanałów i rozległych rozlewisk o bardzo niskiej presji wędkarskiej. Rzeka płynie tu wśród gęstych trzcinowisk, żłobiąc dno o charakterze mulistym z licznymi zastoiskami bogatymi w pokarm. To wymarzone miejsce dla łowców złotego karasia oraz lina, które znajdują tu idealne warunki do spokojnego żerowania. Spinningowanie wymaga tu dużej precyzji, ale nagradza braniami szczupaków z płytkiej, mocno porośniętej wody. Uciąg wody jest niemal niezauważalny, co pozwala na stosowanie najdelikatniejszych technik spławikowych z bardzo lekkim obciążeniem. Surowy, bagienny krajobraz Doliny Narwi sprawia, że każda wyprawa w to miejsce jest unikalnym doświadczeniem przyrodniczym.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70437, 'Nizinna Wielka', 'Wielokorytowa (anastomozująca)', 15.0, 1.4, 'Muliste', 'Trzcinowiska', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 439: Witkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70438, 'Narew - Witkowo (Meandry)', 'narew-witkowo', 'RIVER', 53.1971077, 22.400063, 'Podlaskie', 'Łomża', 'Narew w Witkowie to szeroka rzeka nizinna o bardzo naturalnym korycie i malowniczych, piaszczystych plażach. Rzeka tworzy tu głębokie zakola z wyraźnie zaznaczoną rynną, w której grupują się wyrośnięte leszcze oraz stadne krąpie. Spinningiści z sukcesami obławiają tutejsze piaszczyste przykosy, szukając boleni oraz kleni żerujących w głównym nurcie. Dno piaszczysto-żwirowe zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność i waleczność. Uciąg jest stabilny i pozwala na komfortowe nęcenie pola łowiska przy użyciu klasycznego feedera ruczajowego. To spokojne łowisko, zapewniające wędkarzowi dużą dozę prywatności oraz szansę na kontakt z niewypłoszoną rybą.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70438, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 90.0, 2.5, 'Piasek i żwir', 'Piaszczyste łachy', 'Leszcz, Boleń, Kleń', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 440: Wizna (Ujście Biebrzy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70439, 'Narew - Wizna (Widły)', 'narew-wizna-ujscie', 'RIVER', 53.156343, 22.3683375, 'Podlaskie', 'Wizna', 'Wizna to legendarne miejsce, gdzie Biebrza łączy się z Narwią, tworząc jeden z najrybniejszych węzłów wodnych w Polsce. Mieszające się nurty obu rzek tworzą potężne rozlewisko o bardzo urozmaiconym dnie i znacznej głębokości rynien przydennych. To strategiczne stanowisko dla łowców sumów i sandaczy, które wykorzystują obfitość pokarmu na styku dwóch wielkich ekosystemów. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na rekordowe leszcze oraz dorodne, rzeczne brzany. Uciąg rzeki poniżej połączenia jest silny i wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu. Miejsce to zapewnia niezapomniane emocje wędkarskie w otoczeniu surowego piękna nadnarwiańskich i nadbiebrzańskich łęgów.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70439, 'Nizinna Wielka', 'Potężny węzeł wodny', 140.0, 3.5, 'Piasek i glina', 'Połączenie nurtów', 'Sum, Sandacz, Brzana', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 441: Bronowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70440, 'Narew - Bronowo (Przełom)', 'narew-bronowo', 'RIVER', 53.1334483, 22.3033067, 'Podlaskie', 'Wizna', 'Odcinek w Bronowie charakteryzuje się wysokim, gliniastym brzegiem i głęboką rynną wymytą tuż przy samej burtcie rzeki. Narew płynie tu szerokim korytem, żłobiąc dno o twardym charakterze z licznymi podwodnymi przeszkodami w postaci zatopionych głazów. To wymarzone miejsce dla spinningistów polujących na sandacze, którzy stosują technikę ciężkiego opadu w głębokich dołach. Wędkarze gruntowi z sukcesami łowią tu okazałe certy oraz dorodne płocie, wykorzystując systematyczne nęcenie na krawędzi nurtu. Uciąg rzeki jest zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upadów. Z wysokiej skarpy w Bronowie rozpościera się widok na rozległe torfowiska, co dodaje każdemu wędkowaniu wyjątkowej oprawy wizualnej.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70440, 'Nizinna Wielka', 'Szeroka, wysokie brzegi', 110.0, 3.2, 'Glina i piasek', 'Głębokie rynny', 'Sandacz, Certa, Leszcz', 'Kraina leszcza', 'Natura 2000', true);

-- Spot 442: Pniewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70441, 'Narew - Pniewo (Skarpa)', 'narew-pniewo', 'RIVER', 53.122139, 22.2256336, 'Podlaskie', 'Łomża', 'Pniewo oferuje dostęp do rzeki o bardzo zróżnicowanej rzeźbie dna z głębokimi rynnami i piaszczystymi przykosami środkowymi. Narew płynie tu dostojnie, tworząc silne warkocze prądowe, w których chętnie przebywają waleczne klenie oraz bolenie. To doskonałe łowisko dla miłośników feedera klasycznego, celujących w dorodne leszcze oraz wyrośnięte brzany rzeczne. Dno piaszczysto-żwirowe zapewnia rybom obfite żerowiska, co przekłada się na ich zdrową kondycję i dużą siłę podczas holu. Spinningiści z sukcesami obławiają tutejsze stoki koryta, szukając okoni oraz sandaczy żerujących przy dnie rzeki. Dobry dostęp do wody oraz malownicze otoczenie sprawiają, że jest to chętnie wybierane miejsce na całodniowe zasiadki.', 'PZW Łomża');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70441, 'Nizinna Wielka', 'Szeroka, nurt żywy', 120.0, 2.8, 'Piasek i żwir', 'Warkocze prądowe', 'Boleń, Brzana, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 443: Siemień Nadrzeczny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70442, 'Narew - Siemień Nadrzeczny', 'narew-siemien-nadrzeczny', 'RIVER', 53.1399329, 22.1561117, 'Podlaskie', 'Łomża', 'Narew w Siemieniu Nadrzecznym to szeroka rzeka nizinna charakteryzująca się piaszczystym dnem i licznymi, płytkimi przykosami. Nurt jest tu stabilny, co sprzyja systematycznemu nęceniu stad leszczy żerujących na piaszczystych łachach w głównym prądzie. Spinningiści z sukcesami polują tutaj na bolenie, które regularnie uderzają w drobnicę na krawędzi nurtu i zastoisk. Podmyte brzegi porośnięte wikliną skrywają wyrośnięte okonie, doskonale reagujące na małe jigi i obrotówki. Uciąg rzeki pozwala na komfortowe operowanie zestawami feederowymi o gramaturze koszyka do osiemdziesięciu gramów. To spokojne łowisko zapewnia doskonałe warunki do całodniowego wypoczynku z dala od intensywnej presji wędkarskiej.', 'PZW Łomża');

