VALUES (70442, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 100.0, 2.5, 'Piaszczyste', 'Przykosy, warkocze', 'Leszcz, Boleń, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 444: Dębe (Poniżej Zapory)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70443, 'Narew - Dębe (Poniżej Zapory)', 'narew-debe-zapora', 'RIVER', 52.4889065, 20.9234425, 'Mazowieckie', 'Serock', 'Odcinek w Dębem bezpośrednio poniżej zapory to jedno z najbardziej technicznych i rybnych łowisk na dolnej Narwi. Woda jest tu doskonale natleniona dzięki turbinom elektrowni, co przyciąga ogromne ilości drapieżników, szczególnie sandaczy i sumów. Dno jest twarde, kamienisto-żwirowe, z bardzo silnym i zmiennym nurtem zależnym od aktualnego zrzutu wody. To legendarne miejsce dla spinningistów stosujących ciężkie gumy prowadzone agresywnym opadem w głębokich rynnach przydennych. Wędkarze gruntowi z sukcesami łowią tu dorodne brzany oraz rekordowe leszcze, stosując zestawy o dużym dociążeniu. Należy zachować szczególną ostrożność ze względu na nagłe wahania poziomu wody i silne wiry powstające przy filarach.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70443, 'Nizinna Wielka', 'Uregulowany wypływ spod zapory', 120.0, 4.5, 'Kamień i żwir', 'Zapora, filary mostu', 'Sandacz, Sum, Brzana', 'Kraina leszcza', 'Strefa przyzaporowa', true);

-- Spot 445: Lesznia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70444, 'Narew - Lesznia (Zakola)', 'narew-lesznia', 'RIVER', 52.9146355, 23.100033, 'Podlaskie', 'Suraż', 'Narew w Leszni płynie naturalnym, silnie meandrującym korytem przez malownicze tereny podlaskich łąk. Rzeka posiada tu wyraźnie zaznaczoną rynnę główną, w której grupują się wyrośnięte klenie oraz waleczne jazie. Dno jest piaszczyste z lokalnymi naniesieniami mułu, co stwarza idealne warunki dla ryb spokojnego żeru i drobnych drapieżników. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, stosując mikro-woblery i smużaki imitujące owady. Uciąg wody jest umiarkowany, co pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach spławikowych. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką rzeką w jej najbardziej pierwotnej formie.', 'PZW Białystok');

