VALUES (70444, 'Nizinna Średnia', 'Meandrująca, naturalna', 25.0, 1.4, 'Piasek i muł', 'Podmyte burty', 'Kleń, Jaź, Płoć', 'Kraina leszcza', 'Brak', true);

-- Spot 446: Samułki Duże
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70445, 'Narew - Samułki Duże (Rynny)', 'narew-samulki-duze', 'RIVER', 52.9027756, 23.028031, 'Podlaskie', 'Suraż', 'Odcinek w Samułkach Dużych charakteryzuje się głębokimi wymyciami koryta na zewnętrznych łukach rzeki, sięgającymi dwóch metrów głębokości. Rzeka płynie tu dostojnie, żłobiąc dno o piaszczysto-gliniastym charakterze, co sprzyja bytowaniu dużych stad leszczy. To doskonałe łowisko dla miłośników lekkiego feedera, celujących w ryby żerujące na krawędzi piaszczystych przykos. Spinningiści chętnie obławiają tutejsze pasy roślinności zanurzonej, szukając szczupaków czatujących w cieniu brzegowych wierzb. Uciąg jest stabilny, co umożliwia precyzyjne nęcenie i utrzymywanie białorybu w polu łowienia przez wiele godzin. Cisza panująca wzdłuż trawiastego brzegu zapewnia doskonały relaks oraz szansę na kontakt z niewypłoszoną rybą.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70445, 'Nizinna Średnia', 'Meandrująca, głęboka', 30.0, 2.0, 'Piasek i glina', 'Rynny prądowe', 'Leszcz, Szczupak, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 447: Siemianówka (Cofka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70446, 'Narew - Siemianówka (Wlot)', 'narew-siemianowka-wlot', 'RIVER', 52.902842, 23.8840189, 'Podlaskie', 'Michałowo', 'Narew w Siemianówce to odcinek wejściowy do rozległego zbiornika zaporowego, mający charakter rzeki bagiennej o bardzo leniwym nurcie. Dno jest tu mocno zamulone i porośnięte roślinnością wynurzoną, co tworzy idealne warunki dla lina oraz złotego karasia. To eldorado dla spinningistów polujących na szczupaki, którzy obławiają liczne zatoczki i starorzecza łączące się z korytem głównym. Woda ma charakterystyczny, ciemny kolor torfowy, co wymusza stosowanie przynęt o jaskrawych kolorach lub silnej fali hydroakustycznej. Uciąg rzeki jest tu niemal niezauważalny, a wędkarstwo wymaga dużego skupienia i precyzyjnego podawania zestawu w "okna" między grążelami. Ze względu na bliskość granicy państwa, łowisko to zapewnia absolutną dzikość i kontakt z unikalną fauną Podlasia.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70446, 'Nizinna Średnia', 'Bagienna, nurt zanikający', 20.0, 1.5, 'Muliste', 'Trzcinowiska, grążele', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', 'Obszar Chronionego Krajobrazu', true);

-- Spot 448: Łupianka Stara (Amazonia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70447, 'Narew - Łupianka Stara (Warkoczowa)', 'narew-lupianka-stara', 'RIVER', 53.0256, 22.8808972, 'Podlaskie', 'Łapy', 'Łupianka Stara to serce Narwiańskiego Parku Narodowego, gdzie rzeka przybiera unikalną w Europie formę anastomozującą (wielokorytową). Labirynt wąskich kanałów i rozległych trzcinowisk sprawia, że łowienie z brzegu jest tu niemal niemożliwe bez użycia łodzi. To wymarzone miejsce dla pasjonatów technicznego wędkarstwa, celujących w wyrośnięte wzdręgi oraz waleczne płocie żerujące w oknach roślinności. Dno jest piaszczysto-muliste, a woda krystalicznie czysta, co pozwala na obserwację żerujących ryb w płytszych partiach kanałów. Spinningowanie w tym rejonie to ciągła walka z zaczepami, ale nagrodą są pięknie ubarwione szczupaki i okonie. Miejsce to wymaga od wędkarza wysokiej kultury etycznej ze względu na rygorystyczne przepisy ochrony przyrody obowiązujące w parku.', 'PZW Białystok');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70447, 'Nizinna Wielka', 'Wielokorytowa (warkoczowa)', 40.0, 1.2, 'Piasek i muł', 'Labirynt kanałów', 'Wzdręga, Szczupak, Płoć', 'Kraina leszcza', 'Narwiański Park Narodowy', true);

-- Spot 449: Zegrze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70448, 'Narew - Zegrze (Głęboka Płania)', 'narew-zegrze', 'RIVER', 52.4557318, 21.0352621, 'Mazowieckie', 'Legionowo', 'Narew w Zegrzu to potężny odcinek łączący się z Jeziorem Zegrzyńskim, charakteryzujący się bardzo głębokim i szerokim korytem. Nurt jest tu zmienny i zależy w dużej mierze od pracy zapory w Dębem, co wymusza na wędkarzach dużą elastyczność. To legendarne łowisko sandaczowe, gdzie nocne spinningowanie z użyciem ciężkich głów jigowych bywa niezwykle skuteczne. Dno piaszczysto-muliste skrywa liczne garby i dołki, które są naturalnymi ostojami dla wyrośniętych sumów oraz leszczy. Ze względu na wzmożony ruch jednostek pływających, łowienie z łodzi wymaga tu zachowania szczególnej ostrożności i profesjonalnego oznakowania. Doskonała infrastruktura w postaci przystani i parkingów sprawia, że jest to jedno z najchętniej odwiedzanych miejsc w regionie.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70448, 'Nizinna Wielka', 'Szeroka, nurt zmienny', 180.0, 4.5, 'Piasek i muł', 'Głębokie rynny', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', 'Brak', true);

-- Spot 450: Łubienica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70449, 'Narew - Łubienica (Łąkowa)', 'narew-lubienica', 'RIVER', 52.649907, 21.0937463, 'Mazowieckie', 'Pułtusk', 'Odcinek w Łubienicy to klasyczna Narew nizinna o szerokim, majestatycznym nurcie i urozmaiconej linii brzegowej porośniętej gęstą trzciną. Rzeka posiada tu liczne piaszczyste przykosy, które są bankowymi miejscami na spotkanie z żerującym boleniem oraz wyrośniętym kleniem. Wędkarze stacjonarni z sukcesami stosują tu metodę ciężkiego feedera, nęcąc stada leszczy na krawędzi głównego koryta. Dno jest tu w przeważającej mierze piaszczyste, co ułatwia brodzenie w poszukiwaniu rzecznych drapieżników podczas niskich stanów wody. Nurt jest jednostajny, co pozwala na bardzo naturalną prezentację przynęty przy użyciu długich wędzisk spławikowych typu bolonka. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką rzeką z dala od miejskiego zgiełku.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70449, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 110.0, 2.5, 'Piaszczyste', 'Przykosy piaszczyste', 'Boleń, Leszcz, Kleń', 'Kraina leszcza', 'Brak', true);

-- Spot 451: Gzowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70450, 'Narew - Gzowo (Zakole)', 'narew-gzowo', 'RIVER', 52.6063069, 21.1202716, 'Mazowieckie', 'Pułtusk', 'Gzowo oferuje dostęp do rzeki o bardzo zróżnicowanej rzeźbie dna z głębokimi rynnami sięgającymi ponad trzy metry głębokości. Rzeka mocno tu meandruje, żłobiąc dno o charakterze piaszczysto-gliniastym, co sprzyja bytowaniu dużych sumów i sandaczy. Podmyte brzegi porośnięte wikliną skrywają wyrośnięte okonie, które agresywnie atakują przepływający narybek w zacisznych zatoczkach. To doskonałe miejsce dla spinningistów polujących na szczupaki czatujące w oknach między pasami roślinności zanurzonej. Uciąg wody jest tu zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu w nurcie. Niska presja wędkarska w tym rejonie sprawia, że ryby żerują tu odważnie, czyniąc to łowisko atrakcyjnym punktem na mapie.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70450, 'Nizinna Wielka', 'Meandrująca, głęboka', 100.0, 3.2, 'Piasek i glina', 'Podmyte burty', 'Sum, Sandacz, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 452: Dzierżenin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70451, 'Narew - Dzierżenin (Wyspy)', 'narew-dzierzenin', 'RIVER', 52.5638112, 21.0943306, 'Mazowieckie', 'Serock', 'Narew w Dzierżeninie to potężne, szerokie koryto z licznymi wyspami i piaszczystymi łachami wychodzącymi daleko w nurt. Woda płynie tu stabilnie, a dno jest w dużej mierze piaszczyste, co sprzyja systematycznemu nęceniu stad dorodnych leszczy. To strategiczne miejsce dla łowców boleni, którzy patrolują turbulentną wodę na styku nurtu głównego i spokojniejszych odnóg. W rynnach o głębokości przekraczającej dwa metry stacjonują duże krąpie oraz okresowo pojawiające się piękne rzeczne brzany. Uciąg jest umiarkowany, co pozwala na swobodne łowienie z łodzi, dające dostęp do najciekawszych miejsc niedostępnych z brzegu. Bardzo dobry dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na weekendowe biwaki wędkarskie.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70451, 'Nizinna Wielka', 'Wielokorytowa, wyspy', 130.0, 2.8, 'Piaszczyste', 'Wyspy, łachy', 'Leszcz, Boleń, Brzana', 'Kraina leszcza', 'Brak', true);

-- Spot 453: Serock (Widły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70452, 'Narew - Serock (Widły)', 'narew-serock-widly', 'RIVER', 52.5095576, 21.0806999, 'Mazowieckie', 'Serock', 'W Serocku Narew łączy się z Bugiem, tworząc jedno z najbardziej rybnych rozlewisk w centralnej Polsce, znane jako początek Jeziora Zegrzyńskiego. Mieszające się nurty obu potężnych rzek tworzą bogate w tlen i pokarm zastoiska, w których chętnie przebywają sandacze oraz sumy. To legendarne łowisko dla spinningistów, którzy z łodzi obławiają podwodne stoki koryta w poszukiwaniu okazowych drapieżników. Dno jest tu mocno urozmaicone, piaszczysto-muliste, z licznymi "karczami" stanowiącymi bankowe kryjówki dla dużych szczupaków. Uciąg wody jest zmienny i uzależniony od zrzutów wody na zaporze, co wymaga od wędkarza częstej korekty obciążenia zestawu. To elitarne łowisko zapewnia niesamowite emocje, ale wymaga od wędkarza umiejętności czytania bardzo szerokiej i wymagającej wody.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70452, 'Nizinna Wielka', 'Połączenie wielkich rzek', 250.0, 4.0, 'Piasek i muł', 'Karczowiska, stoki koryta', 'Sandacz, Sum, Szczupak', 'Kraina leszcza', 'Brak', true);

-- Spot 454: Stare Orzechowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70453, 'Narew - Stare Orzechowo (Poniżej Dębe)', 'narew-stare-orzechowo', 'RIVER', 52.4881574, 20.8486586, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Odcinek w Starym Orzechowie to rzeka o wybitnie nizinno-łąkowym charakterze, położona poniżej zapory w Dębem. Woda jest tu doskonale natleniona, co przekłada się na wysoką kondycję i waleczność tutejszych brzan oraz wyrośniętych kleni. Dno piaszczysto-żwirowe z licznymi kamiennymi opaskami stanowi idealne żerowisko dla sandaczy i okoni polujących na ukleje. Wędkarze gruntowi z sukcesami łowią tu dorodne płocie, wykorzystując technikę lekkiego feedera w spokojniejszych partiach głównego nurtu. Uciąg rzeki jest tu zdecydowany, co pozwala na precyzyjne operowanie zestawami spinningowymi w poszukiwaniu aktywnych boleni. Niska roślinność brzegowa ułatwia rzuty, jednak wymaga od wędkarza zachowania dyskrecji, aby nie spłoszyć ryb w czystszej wodzie.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70453, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 120.0, 2.2, 'Piasek i żwir', 'Opaski kamienne', 'Brzana, Kleń, Sandacz', 'Kraina leszcza', 'Brak', true);

-- Spot 455: Czarnowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70454, 'Narew - Czarnowo (Przedujście)', 'narew-czarnowo', 'RIVER', 52.47402, 20.7763445, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Narew w Czarnowie to jeden z ostatnich odcinków rzeki przed jej ujściem do Wisły, charakteryzujący się szerokim korytem i dostojnym nurtem. Dno jest tu w przeważającej mierze piaszczyste, z wyraźnymi rynnami na łukach, które stanowią bezpieczne schronienie dla dorodnych leszczy. Spinningiści z sukcesami polują tutaj na sandacze, wykorzystując ciężkie gumy prowadzone agresywnym opadem w głównym prądzie wody. Podmyte brzegi porośnięte wikliną skrywają wyrośnięte okonie, doskonale reagujące na małe jigi i obrotówki podawane blisko burt. Uciąg rzeki jest stabilny, co pozwala na komfortowe operowanie zestawami feederowymi o gramaturze koszyka do stu gramów. To spokojne łowisko zapewnia doskonałe warunki do całodniowego wypoczynku, oferując jednocześnie szansę na kontakt z rekordowymi okazami ryb nizinnych.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70454, 'Nizinna Wielka', 'Szeroka rzeka, nurt stabilny', 130.0, 3.0, 'Piasek i glina', 'Rynny prądowe', 'Sandacz, Leszcz, Okoń', 'Kraina leszcza', 'Brak', true);

-- Spot 456: Nowy Dwór Mazowiecki (Ujście Narwi do Wisły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70455, 'Narew - Nowy Dwór Mazowiecki (Ujście)', 'narew-ujscie-modlin', 'RIVER', 52.4384131, 20.7282258, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Ujście Narwi do Wisły w Nowym Dworze Mazowieckim to jedno z najbardziej spektakularnych i rybnych miejsc na mapie centralnej Polski. Mieszanie się wód dwóch potężnych rzek tworzy unikalne warkocze prądowe i głębokie rynny, w których stacjonują największe sumy oraz sandacze. Dno w rejonie Twierdzy Modlin jest twarde, piaszczysto-kamieniste, z licznymi uskokami stanowiącymi bankowe stanowiska dla drapieżników. Wędkarze stacjonarni z sukcesami łowią tu dorodne brzany oraz rekordowe leszcze, stosując bardzo ciężkie zestawy gruntowe odporne na silny nurt. Spinningowanie z brzegu w okolicach spichlerza daje szansę na spotkanie z wyrośniętym boleniem patrolującym strefę styku nurtów. To wymagające technicznie łowisko nagradza wytrwałych wędkarzy rybami życia, wymagając jednak doskonałej znajomości specyfiki dużej wody nizinnej.', 'PZW Mazowieckie');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70455, 'Nizinna Wielka', 'Potężne ujście, styk rzek', 200.0, 4.5, 'Kamień i twardy piasek', 'Warkocze prądowe, usypy', 'Sandacz, Sum, Brzana', 'Kraina leszcza', 'Obszar Chronionego Krajobrazu', true);


-- Spot 457: Stary Korczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70456, 'Nida - Stary Korczyn (Piaszczyste Przykosy)', 'nida-stary-korczyn', 'RIVER', 50.2962123, 20.7536531, 'Świętokrzyskie', 'Busko-Zdrój', 'Nida w Starym Korczynie to rzeka o wybitnie nizinno-łąkowym charakterze z bardzo czystą wodą i piaszczystym podłożem. Koryto posiada tu liczne przykosy, które są naturalnym miejscem żerowania dla stadnych kleni oraz walecznych jazi. Spinningiści z sukcesami obławiają tutejsze warkocze, stosując mikro-woblery imitujące owady wpadające do wody. Uciąg jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu stad ryb białych w polu widzenia wędkarza. Podmyte brzegi porośnięte wikliną skrywają wyrośnięte okonie, które agresywnie atakują każdą przepływającą obok przynętę. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do aktywnego wypoczynku ze spinningiem.', null);

