VALUES (70456, 'Nizinna Mała', 'Meandrująca, czysty piasek', 20.0, 1.1, 'Piaszczyste', 'Piaszczyste przykosy', 'Kleń, Jaź, Płoć', 'Kraina leszcza', false);

-- Spot 458: Nowy Korczyn (Przedujście)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70457, 'Nida - Nowy Korczyn (Ujście)', 'nida-nowy-korczyn-ujscie', 'RIVER', 50.3032636, 20.7796548, 'Świętokrzyskie', 'Nowy Korczyn', 'Odcinek w Nowym Korczynie to miejsce, gdzie Nida przygotowuje się do oddania swoich wód potężnej Wiśle. Rzeka rozlewa się tu szerzej, a dno staje się bardziej zróżnicowane z piaszczysto-żwirowymi rynnami w nurcie. To strategiczne stanowisko dla łowców brzan rzecznych, które wchodzą tu z Wisły w poszukiwaniu czystszej i lepiej natlenionej wody. Spinningiści z sukcesami polują tu na bolenie patrolujące krawędzie warkoczy prądowych przy połączeniu wód rzecznych. Uciąg wody jest zdecydowany, co wymaga stosowania dociążonych zestawów gruntowych dla zachowania stabilności na dnie. Bliskość ujścia sprawia, że wędkarz może liczyć tu na branie ryby życia w każdych warunkach pogodowych.', null);

