-- Spot 459: Podzamcze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70458, 'Nida - Podzamcze (Zakole)', 'nida-podzamcze', 'RIVER', 50.2961512, 20.806364, 'Świętokrzyskie', 'Nowy Korczyn', 'Nida w Podzamczu tworzy głębokie i malownicze zakole z wyraźnie zaznaczoną rynną na zewnętrznym łuku koryta. Podłoże jest tu mocno urozmaicone, piaszczyste z lokalnymi wymyciami gliniastymi, co sprzyja bytowaniu dorodnych leszczy. To doskonałe łowisko dla miłośników lekkiego feedera, którzy cenią sobie precyzyjne nęcenie na krawędzi głównego nurtu. Przy brzegach można spotkać pasy roślinności wynurzonej, będące doskonałą bazą dla szczupaków czatujących na drobnicę. Uciąg wody jest stabilny, co pozwala na bardzo naturalną prezentację przynęty przy użyciu delikatnych zestawów spławikowych. Miejsce to zapewnia intymną atmosferę i daje szansę na kontakt z niewypłoszoną rybą w surowym krajobrazie.', null);

