VALUES (70458, 'Nizinna Średnia', 'Silne zakole, głębokie', 28.0, 1.8, 'Piasek i glina', 'Głębokie jamy', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', false);

-- Spot 460: Grotniki Duże
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70459, 'Nida - Grotniki Duże (Łachy)', 'nida-grotniki-duze', 'RIVER', 50.2967547, 20.8351685, 'Świętokrzyskie', 'Nowy Korczyn', 'Odcinek w Grotnikach Dużych charakteryzuje się rozległymi piaszczystymi łachami, które wychodzą daleko w główny nurt rzeki. Nida płynie tu dostojnie, żłobiąc dno o piaszczystym charakterze z licznymi przykosami idealnymi do żerowania kleni. To wymarzone miejsce dla spinningistów polujących na bolenie patrolujące turbulentną wodę poniżej piaszczystych wysp. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w wyrośnięte certy oraz dorodne stadne płocie. Uciąg rzeki jest tu zdecydowany i wymaga od wędkarza umiejętnego czytania prądów wodnych dla poprawnej prezentacji. Malowniczy widok z niskiego brzegu pozwala na precyzyjne namierzenie żerujących stad ryb przy krawędziach nurtu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70459, 'Nizinna Średnia', 'Szeroka, liczne łachy', 30.0, 1.3, 'Piaszczyste', 'Piaszczyste łachy', 'Boleń, Kleń, Certa', 'Kraina leszcza', true);

-- Spot 461: Szczytniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70460, 'Nida - Szczytniki (Meandry)', 'nida-szczytniki', 'RIVER', 50.3144868, 20.7106007, 'Świętokrzyskie', 'Wiślica', 'Nida w Szczytnikach to odcinek o niezwykle naturalnym charakterze, wijący się malowniczo wśród nadnidziańskich łąk i pól. Rzeka tworzy tu liczne zakola z podmyłymi burtami, które skrywają wyrośnięte jazie oraz dorodne klenie. Spinningiści z sukcesami stosują tu technikę brodzenia, obławiając rynny pod brzegami przy użyciu mikro-jigów oraz małych obrotówek. Dno piaszczyste zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność przez cały sezon. Uciąg jest umiarkowany i przewidywalny, co ułatwia systematyczne nęcenie i utrzymywanie ryb spokojnego żeru w polu łowienia. To kameralne łowisko zapewnia doskonały odpoczynek od zgiełku i szansę na kontakt z bardzo dziką fauną rzeczną.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70460, 'Nizinna Mała', 'Naturalna, meandrująca', 18.0, 1.0, 'Piaszczyste', 'Podmyte burty', 'Kleń, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 462: Niegosławice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70461, 'Nida - Niegosławice (Skarpa)', 'nida-niegoslawice', 'RIVER', 50.4008767, 20.6142006, 'Świętokrzyskie', 'Pińczów', 'Odcinek w Niegosławicach słynie z wysokiego, piaszczystego brzegu i głębokiej rynny wymytej tuż pod gliniastą burtą rzeki. Podłoże jest tu mocno zróżnicowane, co stwarza doskonałe warunki dla różnych gatunków ryb spokojnego żeru, szczególnie leszczy. To strategiczne miejsce dla łowców okazowych brzan, które wykorzystują twarde fragmenty dna jako swoje główne ostoje. Spinningiści z sukcesami polują tu na sandacze, stosując technikę ciężkiego opadu w głębokich dołach poniżej meandrów. Uciąg rzeki jest zdecydowany, co pozwala na precyzyjne operowanie zestawami spinningowymi w poszukiwaniu aktywnych drapieżników. Miejsce to gwarantuje absolutny spokój i szansę na kontakt z niewypłoszoną rybą w surowym krajobrazie regionu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70461, 'Nizinna Średnia', 'Głęboka rynna, nurt żywy', 25.0, 2.0, 'Piasek i glina', 'Rynny prądowe', 'Brzana, Leszcz, Sandacz', 'Kraina leszcza', false);

-- Spot 463: Stawy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70462, 'Nida - Stawy (Górny Bieg)', 'nida-stawy', 'RIVER', 50.5803593, 20.4970413, 'Świętokrzyskie', 'Imielno', 'Nida w miejscowości Stawy to kameralny odcinek rzeki o krystalicznie czystej wodzie i urozmaiconym, piaszczysto-żwirowym dnie. Koryto rzeki jest tu dość wąskie, co sprzyja precyzyjnemu łowieniu kleni na smużaki pod nawisami gęstych nadrzecznych traw. To wymarzone miejsce dla pasjonatów lekkiej przepływanki, celujących w dorodne jelce oraz wyrośnięte płocie rzeczne. Nurt rzeki jest jednostajny i łagodny, co pozwala na bardzo naturalną prezentację przynęty na najcieńszych zestawach. Podmyte korzenie starych wierzb stanowią bankowe kryjówki dla okoni, które agresywnie reagują na mikro-obrotówki prowadzone w toni. Dogodny dojazd przez łąki sprawia, że jest to chętnie wybierane miejsce na szybkie i bezproblemowe sesje z wędką.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70462, 'Nizinna Mała', 'Wąskie koryto, nurt łagodny', 15.0, 0.9, 'Piasek i żwir', 'Podmyte korzenie', 'Kleń, Jelec, Płoć', 'Kraina leszcza', false);

-- Spot 464: Sobowice (Meandry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70463, 'Nida - Sobowice (Piaszczyste Przykosy)', 'nida-sobowice-meandry', 'RIVER', 50.5634428, 20.4867659, 'Świętokrzyskie', 'Imielno', 'Nida w rejonie Sobowic to rzeka o wybitnie piaszczystym dnie i krystalicznej wodzie. Koryto tworzy tu liczne, płytkie przykosy, które są ulubionym żerowiskiem stadnych jelców oraz płoci. To idealne miejsce dla spinningistów stosujących mikro-woblery w poszukiwaniu ostrożnych kleni. Nurt jest łagodny, co pozwala na bardzo naturalną prezentację przynęty na najlżejszych zestawach spławikowych. Brzegi są niskie i trawiaste, co zapewnia doskonały dostęp do wody bez konieczności używania woderów. Miejsce to rzadko odwiedzane przez tłumy, gwarantuje spokój i bliski kontakt z przyrodą Ponidzia.', 'PZW Kielce');

