-- Spot 465: Sobowice (Zakole)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70464, 'Nida - Sobowice (Pod Wierzbami)', 'nida-sobowice-zakole', 'RIVER', 50.54968, 20.46725, 'Świętokrzyskie', 'Imielno', 'Drugi odcinek w Sobowicach charakteryzuje się głębszymi rynnami wymytymi pod zwalonymi wierzbami. Podłoże jest tu bardziej zróżnicowane, piaszczysto-żwirowe, co sprzyja aktywności rzecznych drapieżników. Spinningiści z sukcesami obławiają tutejsze cienie, szukając okoni oraz szczupaków czatujących na drobnicę. Uciąg rzeki w tym miejscu przyspiesza, co wymaga stosowania nieco cięższych główek jigowych dla stabilnego prowadzenia. To strategiczne miejsce dla wędkarzy potrafiących precyzyjnie podawać przynętę pod same nawisy brzegowej roślinności. Niska presja wędkarska sprawia, że ryby żerują tu odważnie nawet w godzinach południowych.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70464, 'Nizinna Mała', 'Naturalne zakola, zatory', 18.0, 1.1, 'Piasek i żwir', 'Podmyte korzenie', 'Okoń, Szczupak, Kleń', 'Kraina leszcza', false);

-- Spot 466: Skowronno Dolne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70465, 'Nida - Skowronno Dolne (Łąki)', 'nida-skowronno-dolne', 'RIVER', 50.5319711, 20.4595826, 'Świętokrzyskie', 'Pińczów', 'Nida w Skowronnie Dolnym płynie szerokim łukiem przez otwarte tereny łąkowe, oferując wędkarzom doskonałą widoczność. Dno jest tu twarde, piaszczyste, z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach koryta. To wymarzone stanowisko dla łowców okazowych brzan, które wchodzą tu w poszukiwaniu pokarmu na żwirowych łachach. Wędkarze stacjonarni z powodzeniem stosują metodę lekkiego feedera z długim przyponem i przynętami zwierzęcymi. Przejrzystość wody wymusza na wędkarzu zachowanie dużej ostrożności i stosowanie cienkich przyponów z fluorocarbonu. Wieczorne wyprawy mogą tu zaowocować braniem pięknego jazia żerującego tuż pod powierzchnią lustra wody.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70465, 'Nizinna Mała', 'Otwarta rzeka łąkowa', 22.0, 0.9, 'Twardy piasek', 'Żwirowe rynny', 'Brzana, Jaź, Kleń', 'Kraina leszcza', false);

-- Spot 467: Sobków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70466, 'Nida - Sobków (Podzamcze)', 'nida-sobkow', 'RIVER', 50.6653727, 20.471323, 'Świętokrzyskie', 'Sobków', 'Odcinek w Sobkowie słynie z malowniczego położenia pod ruinami zamku oraz specyficznej, kamienistej rzeźby dna. Nurt rzeki wyraźnie tu przyspiesza, tworząc natlenione bystrza idealne dla ryb reofilnych takich jak brzany i klenie. To strategiczne miejsce dla spinningistów, którzy wykorzystują warkocze prądowe za filarami starego mostu. Podłoże jest twarde, co minimalizuje ryzyko zaczepów przy prowadzeniu przynęt tuż nad dnem. Uciąg rzeki wymaga stosowania dociążonych zestawów, które stabilnie utrzymają przynętę w strefie intensywnego żerowania ryb. Dzięki unikalnej atmosferze historycznego miejsca, każde wędkowanie w Sobkowie ma swój niepowtarzalny urok.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70466, 'Nizinna Mała', 'Bystrza, koryto kamieniste', 20.0, 0.8, 'Kamień i żwir', 'Filary mostu, rafy', 'Brzana, Kleń, Okoń', 'Kraina leszcza', false);

-- Spot 468: Motkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70467, 'Nida - Motkowice (Rynny Mostowe)', 'nida-motkowice', 'RIVER', 50.6495492, 20.4855349, 'Świętokrzyskie', 'Jędrzejów', 'Nida w Motkowicach charakteryzuje się głębokimi rynnami pod mostem oraz licznymi, naturalnymi meandrami. Dno jest piaszczysto-gliniaste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych krąpi. To doskonałe łowisko dla miłośników przepływanki z przystawką, celujących w ryby żerujące w spowolnieniach nurtu. Spinningiści chętnie obławiają tutejsze podmyte brzegi, szukając szczupaków stacjonujących w pobliżu kęp roślinności wynurzonej. Nurt jest stabilny, co ułatwia precyzyjne nęcenie łowiska i utrzymywanie stad białorybu w polu widzenia. Bardzo dobry dostęp do wody sprawia, że jest to chętnie wybierane miejsce na kilkugodzinne sesje spławikowe.', 'PZW Kielce');

