-- Spot 469: Borszowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70468, 'Nida - Borszowice (Dziki Brzeg)', 'nida-borszowice', 'RIVER', 50.632723, 20.4969108, 'Świętokrzyskie', 'Jędrzejów', 'Nida w Borszowicach to kwintesencja dzikiej rzeki nizinnej o bardzo urozmaiconym, naturalnym koryto. Rzeka żłobi tu głębokie zakola, tworząc technicznie wymagające stanowiska pod wysokimi, piaszczystymi burtami. To idealne miejsce dla łowców okoni, które grupują się w cieniu zatopionych korzeni i powalonych drzew. Uciąg wody jest zróżnicowany, co pozwala na stosowanie wielu technik wędkarstwa spławikowego i gruntowego. Przejrzystość toni sprawia, że każdy ruch wędkarza na brzegu musi być przemyślany i dyskretny. Niska presja w tym rejonie gwarantuje spokój oraz szansę na spotkanie z naprawdę wyrośniętym, rzecznym kleniem.', 'PZW Kielce');

