-- Spot 470: Kliszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70469, 'Nida - Kliszów (Łąkowe Meandry)', 'nida-kliszow', 'RIVER', 50.6148498, 20.5014964, 'Świętokrzyskie', 'Kije', 'Nida w Kliszowie to rzeka o wybitnie piaszczystym dnie i krystalicznie czystej wodzie. Koryto tworzy tu liczne meandry z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach rzeki. To doskonałe łowisko dla spinningistów szukających kleni i jazi pod nawisami nadrzecznych traw. Nurt jest tu łagodny, co pozwala na bardzo naturalną prezentację przynęty na najlżejszych zestawach. Brzegi są niskie i trawiaste, zapewniając wędkarzom bardzo komfortowy dostęp do linii wody. Miejsce to słynie z niskiej presji wędkarskiej, co czyni je idealnym punktem na spokojne zasiadki.', 'PZW Kielce');

