-- Spot 471: Pińczów (Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70470, 'Nida - Pińczów (Rynny Miejskie)', 'nida-pinczow-most', 'RIVER', 50.50991, 20.52948, 'Świętokrzyskie', 'Pińczów', 'Pińczów to jeden z najważniejszych punktów na wędkarskiej mapie Ponidzia z uregulowanym dostępem do wody. Pod filarami mostu rzeka wymyła głębsze rynny, w których chętnie stacjonują sandacze oraz sumy. Dno jest tu twardsze, piaszczysto-żwirowe, co sprzyja aktywności ryb reofilnych takich jak dorodne brzany. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera klasycznego, celując w rekordowe pińczowskie leszcze. Uciąg rzeki jest stabilny, a uregulowane brzegi w rejonie miejskim ułatwiają bezpieczne rozstawienie stanowiska. Wieczorne wyprawy ze spinningiem mogą przynieść tu kontakt z wyrośniętym boleniem patrolującym środkowy nurt.', 'PZW Kielce');

