-- Spot 472: Pińczów (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70471, 'Nida - Pińczów (Płanie Dolne)', 'nida-pinczow-poludnie', 'RIVER', 50.4973539, 20.5504967, 'Świętokrzyskie', 'Pińczów', 'Poniżej centrum Pińczowa Nida zaczyna mocniej meandrować, tworząc szerokie płanie i piaszczyste przykosy. To strategiczne miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności wynurzonej i pasy trzcin. Dno jest urozmaicone, z lokalnymi naniesieniami mułu w zacisznych zatoczkach przy starym korycie rzeki. Woda zachowuje wysoką przejrzystość, co wymaga od wędkarza pełnej dyskrecji i cichego podejścia do brzegów. Podmyte brzegi z korzeniami wierzb stanowią bankowe kryjówki dla wyrośniętych okoni żerujących na drobnicy. Miejsce to jest chętnie wybierane na wielogodzinne sesje spławikowe ze względu na bardzo bogatą populację białorybu.', 'PZW Kielce');

