-- Spot 473: Kowala
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70472, 'Nida - Kowala (Otwarta)', 'nida-kowala', 'RIVER', 50.47947, 20.54692, 'Świętokrzyskie', 'Pińczów', 'Odcinek rzeki w Kowali charakteryzuje się szerokim korytem i bardzo stabilnym, spokojnym nurtem wody. Nida płynie tu wśród rozległych łąk, żłobiąc piaszczyste dno z nielicznymi kępami roślinności zanurzonej. To wymarzone stanowisko dla miłośników lekkiej przepływanki celujących w dorodne jelce oraz rzeczne płocie. Spinningiści znajdą tutaj dogodne miejsca do brodzenia i podawania smużaków na krawędzi głównego prądu rzeki. Przejrzystość wody sprawia, że ryby są tu wyjątkowo płochliwe i wymagają stosowania najcieńszych przyponów. Dogodny dojazd przez polne drogi czyni ten fragment rzeki atrakcyjnym punktem na weekendowe zasiadki.', 'PZW Kielce');

