-- Spot 475: Chroberz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70474, 'Nida - Chroberz (Parkowa)', 'nida-chroberz', 'RIVER', 50.4457372, 20.5498986, 'Świętokrzyskie', 'Złota', 'Odcinek w Chrobrzu słynie z głębokich wymyć koryta rzeki, dochodzących lokalnie do trzech metrów głębokości. Nida płynie tu szeroko, żłobiąc dno o charakterze piaszczysto-żwirowym z wyraźnie zaznaczonymi uskokami dna. To strategiczne miejsce dla łowców okazowych leszczy, którzy stosują tu systematyczne nęcenie grubszą frakcją zanęty. Spinningiści cenią ten fragment rzeki za populację sandacza, który chętnie stacjonuje w cieniu podwodnych karczowisk. Nurt jest dostojny i przewidywalny, co pozwala na komfortowe łowienie metodą bolonki lub lekkiego gruntu. Dzięki bliskości dawnej rezydencji Wielopolskich, otoczenie rzeki ma tu wyjątkowy i bardzo urokliwy charakter.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70474, 'Nizinna Średnia', 'Szeroka, głęboka', 32.0, 2.2, 'Piasek i żwir', 'Zatopione przeszkody', 'Leszcz, Sandacz, Jaź', 'Kraina leszcza', true);

-- Spot 476: Chroberz (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70475, 'Nida - Chroberz (Parkowe Zakole)', 'nida-chroberz-poludnie', 'RIVER', 50.4284643, 20.5585501, 'Świętokrzyskie', 'Pińczów', 'Nida w dolnym Chrobrzu płynie szerokim, majestatycznym łukiem przez tereny dawnego parku pałacowego. Koryto rzeki posiada tu wyraźnie zaznaczone rynny, w których chętnie stacjonują dorodne leszcze oraz waleczne brzany. To doskonałe miejsce dla spinningistów szukających szczupaków w pobliżu pasów roślinności zanurzonej i nielicznych trzcinowisk. Dno piaszczysto-żwirowe zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność przez cały sezon. Uciąg jest stabilny i pozwala na precyzyjne nęcenie pola łowiska przy użyciu klasycznego feedera rzecznego. Bliskość historycznych zabudowań nadaje temu łowisku unikalny charakter, łączący walory wędkarskie z estetycznymi.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70475, 'Nizinna Średnia', 'Szeroka, meandrująca', 30.0, 1.8, 'Piasek i żwir', 'Podmyte burty', 'Leszcz, Brzana, Szczupak', 'Kraina leszcza', true);

-- Spot 477: Rudawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70476, 'Nida - Rudawa (Łąkowa)', 'nida-rudawa', 'RIVER', 50.414703, 20.5767697, 'Świętokrzyskie', 'Pińczów', 'Odcinek w Rudawie to kwintesencja sielskiego krajobrazu Ponidzia z krystalicznie czystą wodą i piaszczystymi łachami. Rzeka płynie tu naturalnym korytem, tworząc liczne meandry z głębszymi dołkami na zewnętrznych łukach rzeki. To idealne miejsce dla pasjonatów lekkiej przepływanki celujących w dorodne jelce oraz rzeczne płocie. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz kleni żerujących pod nawisami traw. Uciąg jest łagodny i przewidywalny, co ułatwia systematyczne nęcenie i utrzymywanie stad białorybu w łowisku. Niska presja wędkarska w tym rejonie gwarantuje spokój i szansę na kontakt z niewypłoszoną rybą.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70476, 'Nizinna Mała', 'Meandrująca, naturalna', 22.0, 1.1, 'Piaszczyste', 'Piaszczyste łachy', 'Jelec, Płoć, Kleń', 'Kraina leszcza', false);

-- Spot 478: Wiślica (Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70477, 'Nida - Wiślica (Pod Grodzskiem)', 'nida-wislica', 'RIVER', 50.33395, 20.68091, 'Świętokrzyskie', 'Wiślica', 'Wiślica oferuje techniczne łowisko w cieniu historycznego grodu, gdzie Nida płynie uregulowanym, ale wciąż rybnym korytem. Pod filarami mostu rzeka wymyła głębokie rynny, które są doskonałą kryjówką dla sandaczy oraz wyrośnięte kleni. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując metodę przystawki ze spławikiem w spokojniejszych partiach nurtu. Dno jest tu twardsze, piaszczysto-kamieniste, co sprzyja aktywności ryb reofilnych żerujących w głównym prądzie rzeki. Uciąg rzeki wymaga stosowania dociążonych zestawów, które stabilnie utrzymają przynętę w strefie intensywnego żerowania ryb. Dzięki dobrze przygotowanej infrastrukturze dostęp do wody jest bardzo dogodny nawet podczas gorszych warunków pogodowych.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70477, 'Nizinna Średnia', 'Uregulowana miejska', 32.0, 1.5, 'Piasek i kamień', 'Filary mostu', 'Sandacz, Kleń, Leszcz', 'Kraina leszcza', false);

-- Spot 479: Żurawniki (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70478, 'Nida - Żurawniki (Przykosy)', 'nida-zurawniki-polnoc', 'RIVER', 50.3895494, 20.6361776, 'Świętokrzyskie', 'Wiślica', 'Nida w rejonie Żurawników to rzeka o bardzo urozmaiconej rzeźbie dna z licznymi piaszczystymi przykosami środkowymi. Koryto mocno tu meandruje, żłobiąc głębokie jamy pod wysokimi burtami, które stanowią bezpieczne schronienie dla jazi. To strategiczne miejsce dla spinningistów polujących na bolenie patrolujące turbulentną wodę na styku nurtu i zastoisk. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia, celując w dorodne stadne płocie oraz wyrośnięte krąpie rzeczne. Uciąg rzeki jest tu zdecydowany, co sprzyja natlenieniu wody i wysokiej aktywności ryb w okresach letnich. Malowniczy widok z niskiego brzegu pozwala na precyzyjne namierzenie żerujących stad ryb przy krawędziach głównego nurtu.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70478, 'Nizinna Średnia', 'Meandrująca, przykosy', 28.0, 1.2, 'Piasek i glina', 'Rynny prądowe', 'Jaź, Boleń, Płoć', 'Kraina leszcza', true);

-- Spot 480: Żurawniki (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70479, 'Nida - Żurawniki (Płanie)', 'nida-zurawniki-poludnie', 'RIVER', 50.3737002, 20.6499984, 'Świętokrzyskie', 'Wiślica', 'Drugi punkt w Żurawnikach charakteryzuje się szerokimi płaniami o wyrównanym dnie i stosunkowo spokojnym nurcie wody. Rzeka płynie tu dostojnie przez otwarte tereny łąkowe, oferując wędkarzom doskonałą widoczność i duży komfort rzutów. To wymarzone stanowisko dla miłośników feedera klasycznego, celujących w dorodne leszcze żerujące na piaszczystym podłożu koryta. Spinningiści chętnie obławiają tutejsze pasy roślinności zanurzonej, szukając szczupaków czatujących w cieniu nielicznych kęp trzcinowisk. Głębokość stabilizuje się na poziomie półtora metra, co pozwala na skuteczne badanie łowiska bez konieczności ciągłej zmiany obciążenia. Niska presja wędkarska w tym rejonie sprawia, że ryby żerują tu śmiało nawet w słoneczne dni.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70479, 'Nizinna Średnia', 'Szeroka płania', 35.0, 1.5, 'Piaszczyste', 'Roślinność zanurzona', 'Leszcz, Szczupak, Krąp', 'Kraina leszcza', true);

-- Spot 481: Jurków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70480, 'Nida - Jurków (Bystrza)', 'nida-jurkow', 'RIVER', 50.35493, 20.6529, 'Świętokrzyskie', 'Wiślica', 'Jurków to odcinek rzeki o wybitnie piaszczystym charakterze z krystaliczną wodą pozwalającą na łowienie „na upatrzonego”. Rzeka tworzy tu liczne zakola z piaszczystymi łachami, które są ulubionym żerowiskiem dla stadnych płoci oraz kleni. To idealne miejsce dla spinningistów stosujących mikro-woblery oraz smużaki podawane pod same nawisy brzegowej wikliny. Dno piaszczysto-żwirowe zapewnia rybom obfite żerowiska, co przekłada się na ich zdrową kondycję i dużą siłę. Uciąg rzeki jest umiarkowany i przewidywalny, co umożliwia precyzyjną prezentację przynęty na najcieńszych zestawach spławikowych. Przejrzystość toni wymaga od wędkarza pełnej dyskrecji oraz cichego poruszania się wzdłuż linii brzegowej rzeki.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70480, 'Nizinna Średnia', 'Meandrująca, płytka', 25.0, 1.0, 'Piasek i żwir', 'Piaszczyste łachy', 'Płoć, Kleń, Jaź', 'Kraina leszcza', false);

-- Spot 482: Bizorędki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70481, 'Nida - Bizorędki (Żwirowe Rafy)', 'nida-bizoredki', 'RIVER', 50.7795256, 20.3520193, 'Świętokrzyskie', 'Jędrzejów', 'Nida w Bizorędkach to odcinek o charakterze niemal podgórskim ze względu na kamieniste dno i żwirowe łachy. Rzeka płynie tu dość wąskim korytem, tworząc liczne warkocze i natlenione rynny idealne dla ryb prądolubnych. To doskonałe miejsce dla spinningistów polujących na waleczne klenie przy użyciu małych, tonących woblerów. Uciąg wody jest żywy, co sprzyja aktywności ryb reofilnych nawet podczas letnich niżówek. Brzegi są naturalne i częściowo porośnięte gęstą wikliną, co wymaga od wędkarza zachowania dużej dyskrecji. Miejsce to zapewnia ciszę i spokój, stanowiąc doskonały punkt startowy dla sesji spinningowych w górnym biegu rzeki.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70481, 'Nizinna Mała', 'Bystry nurt, koryto żwirowe', 12.0, 0.8, 'Kamień i żwir', 'Naturalne bystrza', 'Kleń, Jelec, Okoń', 'Kraina pstrąga', false);

-- Spot 483: Tokarnia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70482, 'Nida - Tokarnia (Skansen)', 'nida-tokarnia', 'RIVER', 50.7512053, 20.4103728, 'Świętokrzyskie', 'Chęciny', 'Odcinek w Tokarni przepływa w sąsiedztwie skansenu, zachowując swój sielski i nieuregulowany charakter koryta. Dno piaszczysto-żwirowe obfituje w mikro-rynny, które są bankowymi kryjówkami dla stadnych jazi i okoni. To wymarzone stanowisko dla pasjonatów technicznego spinningu, którzy potrafią precyzyjne podawać przynęty pod nawisy traw. Nurt rzeki jest jednostajny, co pozwala na bardzo naturalną prezentację lekkich zestawów spławikowych na dystansie. Woda zachowuje tu niespotykaną przejrzystość, co zmusza wędkarza do stosowania najcieńszych przyponów z fluorocarbonu. Bogata fauna denna sprawia, że ryby żerują tu intensywnie, co czyni to łowisko atrakcyjnym przez cały sezon.', 'PZW Kielce');

