-- Spot 484: Brzeźno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70483, 'Nida - Brzeźno (Piaszczysta)', 'nida-brzezno', 'RIVER', 50.7232235, 20.4262233, 'Świętokrzyskie', 'Sobków', 'Nida w Brzeźnie to rzeka wijąca się malowniczymi meandrami wśród rozległych, nasłonecznionych łąk Ponidzia. Koryto posiada tu wyraźnie zaznaczone piaszczyste przykosy, które są ulubionym żerowiskiem kleni polujących na ukleje. To idealna lokalizacja dla spinningistów stosujących metodę brodzenia w poszukiwaniu drapieżników w głównym nurcie wody. Dno jest tu stabilne i piaszczyste, co ułatwia bezpieczne poruszanie się w nurcie przy niskich stanach rzeki. Uciąg wody jest umiarkowany i przewidywalny, co sprzyja punktowemu nęceniu i utrzymywaniu stad ryb w łowisku. Miejsce to charakteryzuje się relatywnie niską presją wędkarską, co pozwala na pełny relaks i bliski kontakt z naturą.', 'PZW Kielce');

