-- Spot 485: Sobków (Las)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70484, 'Nida - Sobków (Warkocze)', 'nida-sobkow-las', 'RIVER', 50.7077727, 20.4408644, 'Świętokrzyskie', 'Sobków', 'W rejonie Sobkowa rzeka przedziera się przez naturalne przewężenia, tworząc lokalne bystrza o twardym podłożu koryta. Dno kamienisto-żwirowe sprzyja natlenieniu wody, co przyciąga waleczne brzany oraz wyrośnięte jelce rzeczne. To doskonałe łowisko dla miłośników lekkiej przepływanki celujących w ryby żerujące w turbulentnej wodzie za mostem. Spinningiści z sukcesami obławiają tutejsze warkocze, stosując agresywne przynęty o silnej fali hydroakustycznej. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza umiejętnego doboru obciążenia zestawu gruntowego. Dzięki unikalnej rzeźbie terenu, odcinek ten oferuje wiele technicznych wyzwań i szansę na spotkanie z rekordowym okazem.', 'PZW Kielce');

