VALUES (70484, 'Nizinna Mała', 'Bystrza, nurt żywy', 20.0, 1.2, 'Kamień i żwir', 'Filary starego mostu', 'Brzana, Kleń, Jelec', 'Kraina leszcza', false);

-- Spot 486: Mokrsko Górne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70485, 'Nida - Mokrsko Górne (Rynny)', 'nida-mokrsko-gorne', 'RIVER', 50.6896639, 20.4422718, 'Świętokrzyskie', 'Jędrzejów', 'Nida w Mokrsku Górnym to odcinek o szerokim korycie i stabilnym nurcie, typowy dla środkowego biegu rzeki. Rzeka żłobi tu dno o charakterze piaszczysto-gliniastym, tworząc głębokie rynny na zewnętrznych łukach silnych meandrów. To doskonałe miejsce dla łowców okazowych leszczy, którzy stosują tu systematyczne nęcenie grubą frakcją zanęty. Spinningiści z sukcesami obławiają tutejsze spowolnienia, szukając szczupaków czatujących w pobliżu kęp roślinności wynurzonej. Uciąg rzeki jest dostojny, co sprzyja wielogodzinnym zasiadkom z feederem klasycznym na piaszczystych płaniach. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, co czyni to łowisko bardzo atrakcyjnym punktem regionu.', 'PZW Kielce');

