-- Spot 487: Kopernia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70486, 'Nida - Kopernia (Płania)', 'nida-kopernia', 'RIVER', 50.5225282, 20.4839209, 'Świętokrzyskie', 'Pińczów', 'Odcinek w Koperni charakteryzuje się rozległymi rozlewiskami i obecnością licznych piaszczystych łach wychodzących daleko w nurt. Nida płynie tu szeroko, tworząc rybne płanie idealne do letnich zasiadek z lekkim gruntem lub spławikiem. Dno piaszczyste obfituje w naturalny pokarm, co przyciąga duże stada płoci oraz dorodnych rzecznych jazi. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia smużaków na krawędzi głównego nurtu w poszukiwaniu kleni. Uciąg wody jest łagodny, co pozwala na stosowanie najczulszych sygnalizatorów brania i bardzo lekkich koszyków zanętowych. Malownicze otoczenie i łatwy dostęp do brzegów sprawiają, że jest to chętnie wybierane miejsce na rodzinne wędkowanie.', 'PZW Kielce');

