-- Spot 488: Bizorędki (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70487, 'Nida - Bizorędki (Leśna Struga)', 'nida-bizoredki-lesna', 'RIVER', 50.7830962, 20.3809117, 'Świętokrzyskie', 'Jędrzejów', 'Nida w rejonie Bizorędek to odcinek o charakterze leśno-łąkowym z bardzo urozmaiconym, piaszczystym dnem. Rzeka płynie tu naturalnym korytem, tworząc głębokie rynny pod zwalonymi wierzbami i pasy przybrzeżnych trzcin. To doskonałe łowisko dla miłośników lekkiego spinningu celujących w waleczne klenie oraz rzeczne okonie. Przejrzystość wody jest tu wzorcowa, co wymaga od wędkarza pełnego maskowania oraz stosowania delikatnych zestawów z fluorocarbonu. Uciąg jest umiarkowany, co sprzyja naturalnej prezentacji przynęty na krawędzi nurtu oraz w spokojniejszych zastoiskach. Miejsce to zapewnia ciszę i doskonałe warunki do całodniowego kontaktu z dziką przyrodą Ponidzia.', 'PZW Kielce');

