-- Spot 489: Choiny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70488, 'Nida - Choiny (Zakole)', 'nida-choiny', 'RIVER', 50.7694913, 20.3996613, 'Świętokrzyskie', 'Chęciny', 'Odcinek w Choinach charakteryzuje się licznymi meandrami i silnie podmytymi brzegami, które stanowią bankowe kryjówki dla jazi. Nida płynie tu dostojnie, żłobiąc dno o charakterze piaszczysto-gliniastym z wyraźnie zaznaczonymi rynnami prądowymi. To wymarzone stanowisko dla pasjonatów przepływanki z przystawką, celujących w dorodne płocie oraz stadne leszcze. Spinningiści chętnie obławiają tutejsze spowolnienia nurtu, szukając szczupaków czatujących w cieniu nadrzecznych zarośli wiklinowych. Uciąg wody jest stabilny, co pozwala na precyzyjne nęcenie pola łowiska i utrzymywanie ryb w polu widzenia. Niska presja wędkarska w tym rejonie sprawia, że każda wyprawa nad wodę jest okazją do relaksu.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70488, 'Nizinna Mała', 'Meandrująca, naturalna', 14.0, 1.1, 'Piasek i glina', 'Podmyte burty', 'Jaź, Leszcz, Szczupak', 'Kraina leszcza', false);

-- Spot 490: Radków (Biała Nida)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70489, 'Nida - Radków (Biała Nida)', 'nida-radkow', 'RIVER', 50.7295822, 20.0018849, 'Świętokrzyskie', 'Włoszczowa', 'W Radkowie rzeka ma charakter kameralnej strugi wijącej się wśród torfowisk i podmokłych łąk. Podłoże jest tu piaszczysto-muliste z licznymi kępami roślinności wynurzonej, co stwarza idealne warunki dla linów. To strategiczne miejsce dla łowców wzdręg, które grupują się w dobrze natlenionych oknach między grążelami i trzcinami. Spinningowanie wymaga tu dużej precyzji ze względu na wąskie koryto i liczne nawisy gałęzi nad lustrem wody. Uciąg wody jest znikomy, co pozwala na stosowanie najczulszych spławików typu piórko i bardzo lekkich obciążeń ołowianych. Surowy krajobraz doliny rzeki zapewnia wędkarzowi całkowitą izolację od zgiełku i szansę na kontakt z dziką rybą.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70489, 'Nizinna Mała', 'Kameralna struga, bagienna', 6.0, 0.7, 'Piasek i muł', 'Grążele, trzcinowiska', 'Lin, Wzdręga, Szczupak', 'Kraina leszcza', false);

-- Spot 491: Dąbie (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70490, 'Nida - Dąbie (Piaszczysta)', 'nida-dabie-1', 'RIVER', 50.7317319, 20.0335665, 'Świętokrzyskie', 'Włoszczowa', 'Nida w rejonie miejscowości Dąbie to rzeka o wybitnie piaszczystym dnie z krystaliczną wodą pozwalającą na obserwację ryb. Koryto tworzy tu liczne, płytkie płanie idealne do brodzenia i precyzyjnego podawania małych przynęt spinningowych. To wymarzone stanowisko dla łowców jelców oraz kleni, które doskonale reagują na smużaki prowadzone w głównym nurcie. Uciąg jest jednostajny i łagodny, co sprzyja systematycznemu nęceniu łowiska drobną frakcją zanęty spożywczej. Brzegi są niskie i łatwo dostępne, co ułatwia bezpieczne lądowanie ryby bez konieczności używania wysokich woderów. Miejsce to słynie z doskonałych warunków tlenowych, co przekłada się na wysoką aktywność ryb przez cały sezon.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70490, 'Nizinna Mała', 'Szeroka, piaszczysta płania', 12.0, 0.6, 'Piaszczyste', 'Piaszczyste łachy', 'Jelec, Kleń, Płoć', 'Kraina leszcza', false);

-- Spot 492: Dąbie (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70491, 'Nida - Dąbie (Rynna)', 'nida-dabie-2', 'RIVER', 52.4881574, 20.8486586, 'Świętokrzyskie', 'Włoszczowa', 'Drugi punkt w Dąbiu obejmuje odcinek o silniejszym nurcie z wyraźnie zaznaczoną rynną wymytą na zewnętrznym łuku koryta. Podłoże jest tu twardsze, piaszczysto-żwirowe, co sprzyja aktywności rzecznych drapieżników takich jak okonie i mniejsze szczupaki. Wędkarze stacjonarni z sukcesami stosują tu metodę lekkiego feedera, celując w ryby żerujące na krawędzi piaszczystych przykos. Przejrzystość toni wymaga od wędkarza zachowania dużej ostrożności, aby nie spłoszyć ryb żerujących w płytszych partiach wody. Uciąg rzeki pozwala na komfortowe operowanie zestawem spławikowym i precyzyjne prowadzenie przynęty wzdłuż brzegowych burt gliniastych. To technicznie ciekawe łowisko zapewnia wędkarzowi dużą satysfakcję z czytania wody i dobierania odpowiednich technik połowu.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70491, 'Nizinna Mała', 'Nurt żywy, koryto twarde', 14.0, 0.9, 'Piasek i żwir', 'Rynna prądowa', 'Okoń, Szczupak, Kleń', 'Kraina leszcza', false);

-- Spot 493: Nad Stawami
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70492, 'Nida - Nad Stawami (Rozlewisko)', 'nida-nad-stawami', 'RIVER', 50.7182705, 20.0865563, 'Świętokrzyskie', 'Małogoszcz', 'Odcinek Nad Stawami charakteryzuje się szerokimi rozlewiskami i obecnością licznych piaszczystych łach wychodzących daleko w nurt rzeki. Rzeka płynie tu spokojnie, żłobiąc dno o piaszczystym charakterze z lokalnymi naniesieniami mułu w zacisznych zatoczkach wstecznych. To doskonałe łowisko dla miłośników spławika celujących w dorodne wzdręgi oraz wyrośnięte liny rzeczne. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia lekkich przynęt na krawędzi nurtu głównego w poszukiwaniu jazi. Uciąg wody jest zróżnicowany, co pozwala na eksperymentowanie z gramaturą zestawu i sposobem podania przynęty naturalnej. Malownicze otoczenie i łatwy dostęp do brzegów sprawiają, że jest to chętnie wybierane miejsce na rodzinne wędkowanie.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70492, 'Nizinna Mała', 'Szerokie rozlewiska, nurt zmienny', 18.0, 1.2, 'Piasek i muł', 'Zatoki, łachy', 'Lin, Wzdręga, Jaź', 'Kraina leszcza', false);

-- Spot 494: Nad Stawami (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70493, 'Biała Nida - Nad Stawami (Koryto)', 'biala-nida-nad-stawami-2', 'RIVER', 50.712571, 20.1159962, 'Świętokrzyskie', 'Małogoszcz', 'Biała Nida w rejonie Nad Stawami to odcinek o bardzo zmiennej dynamice przepływu, sąsiadujący z kompleksem zbiorników hodowlanych. Koryto rzeki posiada tu liczne, piaszczyste wymycia dna oraz pasy roślinności zanurzonej, które są doskonałą bazą dla płoci. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając okoni oraz szczupaków czatujących na drobnicę. Uciąg wody jest umiarkowany i pozwala na bardzo naturalną prezentację przynęty na delikatnych zestawach spławikowych. Podłoże jest w przeważającej mierze piaszczyste, co ułatwia bezpieczne brodzenie podczas letnich okresów niskiego stanu wody. To technicznie ciekawe łowisko zapewnia wędkarzowi dużą dozę prywatności oraz szansę na kontakt z niewypłoszoną rybą rzeczną.', 'PZW Kielce');

