-- Spot 495: Popowice (Zakole)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70494, 'Biała Nida - Popowice (Pod Olszami)', 'biala-nida-popowice-zakole', 'RIVER', 50.7046117, 20.1416352, 'Świętokrzyskie', 'Małogoszcz', 'Odcinek w Popowicach charakteryzuje się silnie meandrującym korytem z wysokimi burtami porośniętymi starymi olszami. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach koryta, które są bankowymi kryjówkami dla wyrośniętych kleni. To wymarzone stanowisko dla pasjonatów lekkiej przepływanki celujących w dorodne jelce żerujące w głównym nurcie wody. Dno piaszczysto-żwirowe zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność przez cały sezon. Spinningiści chętnie obławiają tutejsze podmyte korzenie, szukając okoni czatujących w cieniu nadrzecznej roślinności brzegowej. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz doskonałe warunki do aktywnego wypoczynku z wędką.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70494, 'Nizinna Mała', 'Silnie meandrująca, naturalna', 12.0, 1.1, 'Piasek i żwir', 'Podmyte burty', 'Kleń, Jelec, Okoń', 'Kraina leszcza', false);

-- Spot 496: Popowice (Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70495, 'Biała Nida - Popowice (Płania)', 'biala-nida-popowice-wschod', 'RIVER', 50.7051925, 20.170268, 'Świętokrzyskie', 'Oksa', 'Drugi punkt w Popowicach obejmuje odcinek o szerokim korycie i wyrównanym piaszczystym dnie o charakterze płani. Nurt rzeki stabilizuje się tutaj, co sprzyja systematycznemu nęceniu stad jazi oraz dorodnych płoci rzecznych. To idealne miejsce dla wędkarzy spławikowych celujących w ryby żerujące na krawędzi pasów roślinności wynurzonej. Woda zachowuje wzorcową przejrzystość, co wymusza na wędkarzu zachowanie dużej ostrożności i stosowanie cienkich przyponów. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia smużaków na krawędzi głównego nurtu w poszukiwaniu kleni. Bardzo dobra dostępność brzegów sprawia, że jest to chętnie wybierane miejsce na szybkie sesje z lekkim gruntem.', 'PZW Kielce');

