VALUES (70495, 'Nizinna Mała', 'Szeroka płania, nurt stabilny', 14.0, 0.9, 'Piaszczyste', 'Piaszczyste łachy', 'Jaź, Płoć, Kleń', 'Kraina leszcza', false);

-- Spot 497: Tyniec-Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70496, 'Biała Nida - Tyniec-Kolonia', 'biala-nida-tyniec-kolonia', 'RIVER', 50.7130393, 20.1961955, 'Świętokrzyskie', 'Jędrzejów', 'Biała Nida w Tyńcu-Kolonii to kameralna rzeka wijąca się malowniczo wśród nadnidziańskich łąk i zagajników. Koryto posiada tu liczne zakola z podmyłymi burtami, które skrywają wyrośnięte jazie oraz mniejsze szczupaki. To doskonałe łowisko dla miłośników lekkiego spinningu stosujących mikro-jigi prowadzone wzdłuż brzegowej wikliny. Dno piaszczyste z lokalnymi naniesieniami mułu obfituje w naturalny pokarm, co przyciąga dorodne leszczowe stada. Uciąg jest umiarkowany, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Niska presja wędkarska sprawia, że ryby żerują tu odważnie, czyniąc to łowisko bardzo atrakcyjnym punktem regionu.', 'PZW Kielce');

