-- Spot 498: Chorzewa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70497, 'Biała Nida - Chorzewa (Bystrza)', 'biala-nida-chorzewa', 'RIVER', 50.7187817, 20.2249696, 'Świętokrzyskie', 'Jędrzejów', 'W Chorzewie rzeka przedziera się przez naturalne zwężenia, tworząc lokalne bystrza o twardym piaszczysto-żwirowym podłożu koryta. Woda jest tu wyjątkowo przejrzysta i dobrze natleniona, co przyciąga waleczne jelce oraz okresowo pojawiające się pstrągi. To wymarzone miejsce dla spinningistów stosujących agresywne przynęty o silnej fali hydroakustycznej w głównym nurcie. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza umiejętnego doboru obciążenia zestawu gruntowego. Podmyte brzegi porośnięte gęstą wikliną skrywają wyrośnięte okonie, które agresywnie atakują mikro-woblery w toni. Malowniczy krajobraz doliny rzeki zapewnia doskonały relaks oraz szansę na kontakt z bardzo dziką rybą rzeczną.', 'PZW Kielce');

