-- Spot 500: Mniszek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70499, 'Biała Nida - Mniszek (Łąkowe Meandry)', 'biala-nida-mniszek', 'RIVER', 50.7260545, 20.2804107, 'Świętokrzyskie', 'Małogoszcz', 'Biała Nida w Mniszku to urokliwa, wąska rzeka wijąca się pośród rozległych nadnidziańskich łąk. Koryto posiada tu piaszczyste dno z licznymi, płytkimi przykosami, które są idealnym stanowiskiem dla stadnych jelców. To doskonałe miejsce dla spinningistów stosujących mikro-woblery w poszukiwaniu ostrożnych kleni żerujących pod nawisami traw. Nurt jest łagodny i stabilny, co pozwala na bardzo naturalną prezentację przynęty na najlżejszych zestawach spławikowych. Przejrzystość wody wymaga od wędkarza zachowania dużej ostrożności i stosowania cienkich przyponów z wysokiej jakości fluorocarbonu. Miejsce to zapewnia całkowity spokój oraz szansę na kontakt z dziką rzeką w jej najbardziej naturalnej formie.', 'PZW Kielce');

