-- Spot 503: Perzyny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70502, 'Biała Nida - Perzyny (Źródliska)', 'biala-nida-perzyny', 'RIVER', 50.6737736, 19.9258463, 'Świętokrzyskie', 'Moskorzew', 'W Perzynach rzeka ma postać kameralnego strumienia, będącego jednym z początkowych fragmentów biegu Białej Nidy. Podłoże jest tu piaszczysto-muliste, a rzeka płynie leniwie wśród gęstych trzcinowisk i podmokłych nieużytków. To idealne miejsce dla miłośników mikro-jigingu, szukających okoni w mikrozastoiskach i cieniach brzegowej roślinności. Ze względu na minimalną szerokość koryta, kluczowe dla sukcesu jest zachowanie absolutnej ciszy i operowanie krótkim wędziskiem. Uciąg wody jest niemal niezauważalny, co pozwala na stosowanie najczulszych spławików typu piórko z lekkim obciążeniem. To dzikie i rzadko odwiedzane łowisko nagradza cierpliwych wędkarzy kontaktem z pierwotną naturą regionu Świętokrzyskiego.', 'PZW Kielce');

