VALUES (70502, 'Nizinna Mała', 'Strumień polny, wąski', 3.0, 0.5, 'Piasek i muł', 'Gęste trzcinowiska', 'Okoń, Płoć, Kiełb', 'Kraina leszcza', false);

-- Spot 504: Dzierzgów (Punkt 1)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70503, 'Biała Nida - Dzierzgów (Most Południowy)', 'biala-nida-dzierzgow-1', 'RIVER', 50.6908977, 19.9346172, 'Świętokrzyskie', 'Radków', 'Biała Nida w Dzierzgowie to rzeka o wybitnie meandrującym charakterze, tworząca liczne zakola z głębokimi rynnami pod burtami. Pod filarami mostu rzeka wymyła twardsze piaszczyste dołki, które są naturalną kryjówką dla małych szczupaków i okoni. To doskonałe miejsce dla spinningistów stosujących lekkie obrotówki i twistery prowadzone agresywnie w pobliżu brzegowej wikliny. Uciąg rzeki w tym miejscu jest zmienny, przyspieszając na łukach, co sprzyja natlenieniu wody i aktywności ryb. Wędkarze spławikowi z sukcesami łowią tu waleczne płocie, wykorzystując metodę lekkiej przepływanki z przystawką. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką rybą w otoczeniu starych zagajników.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70503, 'Nizinna Mała', 'Meandrująca, naturalna', 5.0, 0.8, 'Piasek i glina', 'Podmyte brzegi', 'Szczupak, Okoń, Płoć', 'Kraina leszcza', false);

-- Spot 505: Dzierzgów (Punkt 2)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70504, 'Biała Nida - Dzierzgów (Północ)', 'biala-nida-dzierzgow-2', 'RIVER', 50.7067111, 19.9485968, 'Świętokrzyskie', 'Radków', 'Północny odcinek w Dzierzgowie oferuje dostęp do rzeki o nieco szerszym korycie i bardziej wyrównanym piaszczystym dnie. Rzeka płynie tu dostojnie przez tereny łąkowe, żłobiąc rynny o głębokości dochodzącej do jednego metra na zewnętrznych zakrętach. To idealne stanowisko dla miłośników bata lub lekkiej bolonki, celujących w stadne jelce oraz rzeczne klenie. Woda zachowuje wysoką przejrzystość, co wymaga od wędkarza maskowania się za nadbrzeżną roślinnością podczas podchodzenia do wody. Uciąg jest stabilny, co umożliwia precyzyjne podanie zanęty i utrzymanie stad białorybu w polu łowienia przez dłuższy czas. Dzięki sielskiemu krajobrazowi, odcinek ten jest chętnie wybierany na spokojne, popołudniowe sesje z wędką w ręku.', 'PZW Kielce');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70504, 'Nizinna Mała', 'Szeroka płania, nurt łagodny', 6.5, 0.9, 'Piaszczyste', 'Piaszczyste łachy', 'Jelec, Kleń, Płoć', 'Kraina leszcza', false);

-- Spot 506: Radków (Górny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70505, 'Biała Nida - Radków (Górne Bystrza)', 'biala-nida-radkow-gora', 'RIVER', 50.7175538, 19.9722432, 'Świętokrzyskie', 'Radków', 'W górnym Radkowie Biała Nida przedziera się przez naturalne zwężenia terenu, tworząc lokalne bystrza o żwirowym podłożu koryta. Woda jest tu wyjątkowo zimna i dobrze natleniona, co przyciąga waleczne jelce oraz okresowo pojawiające się mniejsze pstrągi. To wymarzone miejsce dla spinningistów stosujących mikro-woblery w głównym nurcie, celujących w rzeczne drapieżniki żerujące w toni. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza umiejętnego doboru obciążenia zestawu spławikowego. Podmyte korzenie brzegowych olch stanowią bankowe kryjówki dla okoni, które agresywnie atakują każdą przepływającą obok przynętę. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do technicznego wędkarstwa rzecznego.', 'PZW Kielce');

