VALUES (70505, 'Nizinna Mała', 'Nurt przyspieszony, żwirowa', 5.5, 0.7, 'Żwir i piasek', 'Naturalne bystrza', 'Jelec, Okoń, Pstrąg potokowy', 'Kraina pstrąga', false);

-- Spot 507: Głęboczek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70506, 'Noteć - Głęboczek (Leniwy Nurt)', 'notec-gleboczek', 'RIVER', 52.8468626, 15.7604594, 'Lubuskie', 'Drezdenko', 'Noteć w Głęboczku to klasyczny odcinek rzeki nizinnej o bardzo wolnym przepływie wody i szerokim korycie. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dorodnych leszczy oraz krąpi żerujących w spokojniejszych partiach nurtu. To doskonałe łowisko dla miłośników feedera klasycznego, którzy mogą tu precyzyjnie nęcić pola przy użyciu cięższych zanęt. Spinningiści z sukcesami polują na szczupaki, obławiając pasy trzcinowisk oraz kępy roślinności wynurzonej przy brzegach. Uciąg rzeki jest przewidywalny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do całodniowego kontaktu z naturą.', 'PZW Gorzów Wlkp.');

