-- Spot 508: Trzebicz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70507, 'Noteć - Trzebicz (Rynny)', 'notec-trzebicz', 'RIVER', 52.8032144, 15.7375943, 'Lubuskie', 'Drezdenko', 'Odcinek w Trzebiczu charakteryzuje się wyrównanym nurtem i obecnością głębszych rynien wymytych wzdłuż piaszczystych burt rzeki. Podłoże jest tu twardsze, piaszczyste, co sprzyja aktywności ryb spokojnego żeru, szczególnie płoci oraz cert. Wędkarze stacjonarni z sukcesami stosują tu metodę odległościową, puszczając zestaw wzdłuż brzegowych opasek faszynowych. Spinningiści cenią ten fragment rzeki za populację okonia, który chętnie gromadzi się w cieniu podwodnych przeszkód terenowych. Uciąg wody pozwala na precyzyjne nęcenie łowiska i utrzymywanie stad białorybu w polu widzenia przez wiele godzin. Dobry dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na szybkie sesje spławikowe.', 'PZW Gorzów Wlkp.');

