-- Spot 509: Zielątkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70508, 'Noteć - Zielątkowo (Zakola)', 'notec-zielatkowo', 'RIVER', 52.7818736, 15.6697537, 'Lubuskie', 'Drezdenko', 'W Zielątkowie Noteć tworzy łagodne zakola, żłobiąc dno o piaszczysto-gliniastym charakterze z lokalnymi naniesieniami mułu. To strategiczne miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności wynurzonej w zacisznych zatoczkach wstecznych. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne stadne leszcze oraz wyrośnięte liny rzeczne. Uciąg rzeki stabilizuje się, co umożliwia precyzyjne podanie zestawu gruntowego na znaczną odległość od brzegu. Woda zachowuje tu umiarkowaną przejrzystość, co sprzyja żerowaniu drapieżników w ciągu całego dnia nawet przy słonecznej pogodzie. Malowniczy krajobraz doliny rzeki oraz niska presja wędkarska sprawiają, że każda wyprawa w to miejsce jest bardzo relaksująca.', 'PZW Gorzów Wlkp.');

