VALUES (70508, 'Nizinna Wielka', 'Meandrująca, naturalna', 40.0, 2.5, 'Piasek i glina', 'Zatoki wsteczne', 'Szczupak, Leszcz, Lin', 'Kraina leszcza', true);

-- Spot 510: Goszczanowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70509, 'Noteć - Goszczanowiec (Płania)', 'notec-goszczanowiec', 'RIVER', 52.7666483, 15.5975528, 'Lubuskie', 'Drezdenko', 'Odcinek rzeki w Goszczanowcu to typowa płania o szerokim korycie i jednostajnym, bardzo wolnym przepływie wody. Dno jest tu mocno zamulone, co tworzy idealne warunki dla ryb lubiących spokojną wodę, takich jak liny i wzdręgi. To doskonałe łowisko dla wędkarzy spławikowych, którzy cenią sobie precyzyjne łowienie w "oknach" między roślinnością zanurzoną. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych trzcinowiskach. Głębokość jest wyrównana, co pozwala na skuteczne badanie łowiska bez konieczności ciągłej zmiany obciążenia zestawu. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do wielogodzinnych zasiadek spławikowych.', 'PZW Gorzów Wlkp.');

