VALUES (70509, 'Nizinna Wielka', 'Szeroka płania, nurt wolny', 42.0, 2.4, 'Muliste', 'Trzcinowiska', 'Lin, Wzdręga, Okoń', 'Kraina leszcza', true);

-- Spot 511: Lipki Małe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70510, 'Noteć - Lipki Małe (Starorzecza)', 'notec-lipki-male', 'RIVER', 52.7636776, 15.5225798, 'Lubuskie', 'Gorzów Wlkp.', 'Noteć w Lipkach Małych charakteryzuje się obecnością licznych starorzeczy i bocznych kanałów łączących się z głównym korytem. Rzeka płynie tu dostojnie, oferując wędkarzom bardzo urozmaiconą linię brzegową z pasami tataraku i grążeli. To wymarzone miejsce dla łowców szczupaków oraz dużych okoni, które grupują się w dobrze natlenionej wodzie wlotów kanałów. Wędkarze gruntowi z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie na piaszczystych płaniach środkowych. Uciąg jest znikomy, co sprzyja stosowaniu najdelikatniejszych technik spławikowych oraz lekkich drgających szczytówek. Dogodny dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na rodzinne biwaki wędkarskie.', 'PZW Gorzów Wlkp.');

