-- Spot 512: Santok (Ujście do Warty)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70511, 'Noteć - Santok (Ujście)', 'notec-santok-ujscie', 'RIVER', 52.7407058, 15.4552446, 'Lubuskie', 'Gorzów Wlkp.', 'Ujście Noteci do Warty w Santoku to jedno z najbardziej rybnych i strategicznych miejsc wędkarskich w regionie. Mieszanie się nurtów obu rzek tworzy specyficzne warunki tlenowe i pokarmowe, które przyciągają sandacze, sumy oraz bolenie. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe z głębokimi rynnami sięgającymi ponad trzy metry głębokości. Spinningiści z sukcesami obławiają strefę styku wód, szukając drapieżników żerujących na uklejach w turbulentnym nurcie. Wędkarze gruntowi chętnie nęcą tutejsze płanie, licząc na rekordowe leszcze oraz dorodne rzeczne brzany. To wymagające technicznie łowisko nagradza wytrwałych wędkarzy rybami życia, oferując jednocześnie wspaniały widok na historyczny Santok.', 'PZW Gorzów Wlkp.');

