-- Spot 513: gmina Kcynia (Łąki Nadnoteckie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70512, 'Noteć - gmina Kcynia (Płania)', 'notec-kcynia', 'RIVER', 53.0930906, 17.419755, 'Kujawsko-Pomorskie', 'Kcynia', 'Noteć w gminie Kcynia to odcinek rzeki o bardzo wolnym przepływie i uregulowanym korycie o charakterze kanałowym. Dno jest tu w przeważającej mierze muliste, co sprzyja bytowaniu dorodnych linów oraz złotych karasi w przybrzeżnych pasach trzcin. To doskonałe łowisko dla wędkarzy spławikowych, którzy cenią sobie precyzyjne nęcenie w oknach między roślinnością zanurzoną. Spinningiści z sukcesami polują tu na szczupaki, obławiając leniwe zakola przy użyciu lekko dociążonych gum. Uciąg wody jest niemal niezauważalny, co pozwala na stosowanie najdelikatniejszych zestawów z czułymi spławikami typu piórko. Miejsce to zapewnia ciszę i doskonałe warunki do wielogodzinnych zasiadek w otoczeniu rozległych nadnoteckich torfowisk.', 'PZW Bydgoszcz');

