-- Spot 514: Mieczkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70513, 'Noteć - Mieczkowo (Zatoki)', 'notec-mieczkowo', 'RIVER', 53.0822325, 17.3449536, 'Kujawsko-Pomorskie', 'Kcynia', 'Odcinek w Mieczkowie charakteryzuje się wyrównanym nurtem i obecnością niewielkich zatok wstecznych przy brzegach. Podłoże rzeki jest tu piaszczysto-muliste, co przyciąga duże stada leszczy żerujących na piaszczystych płaniach koryta. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera klasycznego, celując w ryby grupujące się w pobliżu głównego nurtu. Spinningiści cenią ten fragment rzeki za populację okonia, który chętnie stacjonuje w cieniu podwodnych karczowisk i faszyny. Uciąg wody stabilizuje się, co umożliwia precyzyjne podanie zanęty i utrzymanie białorybu w polu łowienia. Dogodny dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na rodzinne biwaki wędkarskie.', 'PZW Bydgoszcz');

