-- Spot 515: Żuławka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70514, 'Noteć - Żuławka (Rynny Brzegowe)', 'notec-zulawka', 'RIVER', 53.0844761, 17.269074, 'Wielkopolskie', 'Wyrzysk', 'Noteć w Żuławce to rzeka o dość głębokim korycie z wyraźnie zaznaczonymi rynnami przydennymi na łukach. Rzeka płynie tu stabilnie, żłobiąc dno o piaszczystym charakterze z lokalnymi naniesieniami twardej gliny. To strategiczne miejsce dla łowców okazowych leszczy, którzy stosują systematyczne nęcenie grubszą frakcją zanęty na krawędzi nurtu. Spinningiści z sukcesami obławiają tutejsze spadki dna, szukając sandaczy oraz szczupaków czatujących w głębszej wodzie. Uciąg rzeki przyspiesza w przewężeniach, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upadów. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do technicznego wędkarstwa rzecznego.', 'PZW Piła');

