-- Spot 516: Krostkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70515, 'Noteć - Krostkowo (Przykosy)', 'notec-krostkowo', 'RIVER', 53.087798, 17.1930858, 'Wielkopolskie', 'Białośliwie', 'Odcinek w Krostkowie słynie z rozległych piaszczystych przykos wychodzących daleko w nurt rzeki, tworzących rybne warkocze. To wymarzone miejsce dla spinningistów polujących na bolenie, które agresywnie żerują na stadach uklei przy krawędzi nurtu. Dno piaszczyste zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność i waleczność. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia, celując w dorodne płocie oraz wyrośnięte krąpie rzeczne. Uciąg rzeki jest tu zdecydowany i wymaga od wędkarza umiejętnego czytania prądów wodnych dla poprawnej prezentacji przynęty. Malowniczy krajobraz doliny Noteci nadaje każdej wyprawie wędkarskiej wyjątkowego, dzikiego charakteru sprzyjającego wypoczynkowi.', 'PZW Piła');

