-- Spot 517: gmina Białośliwie (Łęgi)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70516, 'Noteć - gmina Białośliwie (Starorzecza)', 'notec-bialosliwie', 'RIVER', 53.0741864, 17.1203621, 'Wielkopolskie', 'Białośliwie', 'Noteć w gminie Białośliwie charakteryzuje się obecnością licznych starorzeczy i kanałów łączących się z korytem głównym. Rzeka płynie tu dostojnie, oferując wędkarzom bardzo urozmaiconą linię brzegową z kępami grążeli i tataraku. To wymarzone miejsce dla łowców szczupaków oraz dużych okoni, które grupują się w cieniu podwodnej roślinności zanurzonej. Wędkarze gruntowi z sukcesami łowią tu okazałe leszcze, wykorzystując metodę lekkiej drgającej szczytówki na piaszczystych płaniach. Uciąg jest znikomy, co sprzyja stosowaniu najdelikatniejszych technik spławikowych oraz precyzyjnemu nęceniu punktowemu. Dogodny dostęp do brzegów i liczne stanowiska sprawiają, że jest to chętnie wybierane miejsce na całodniowe zasiadki.', 'PZW Piła');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70516, 'Nizinna Wielka', 'Szeroka, liczne zatoki', 35.0, 2.5, 'Piasek i muł', 'Grążele, starorzecza', 'Leszcz, Szczupak, Okoń', 'Kraina leszcza', true);

-- Spot 518: Wolsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70517, 'Noteć - Wolsko (Płania Środkowa)', 'notec-wolsko', 'RIVER', 53.0685759, 17.0452171, 'Wielkopolskie', 'Miasteczko Krajeńskie', 'Odcinek rzeki w Wolsku to typowa szeroka płania o wyrównanym dnie i jednostajnym, bardzo wolnym przepływie wody. Dno jest tu piaszczysto-muliste, co tworzy idealne warunki dla ryb spokojnego żeru, szczególnie dużych leszczy i linów. To doskonałe łowisko dla wędkarzy spławikowych, którzy cenią sobie precyzyjne łowienie w zacisznych miejscach pod przeciwległym brzegiem. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych trzcinowiskach i umocnieniach. Głębokość jest wyrównana, co pozwala na skuteczne badanie łowiska bez konieczności ciągłej zmiany gramatury zestawu. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do długich, relaksujących sesji z feederem.', 'PZW Piła');

