-- Spot 519: Sadłogoszcz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70518, 'Noteć - Sadłogoszcz (Uregulowana)', 'notec-sadlogoszcz', 'RIVER', 52.8605026, 18.0152821, 'Kujawsko-Pomorskie', 'Barcin', 'Noteć w Sadłogoszczy to odcinek rzeki o wybitnie kanałowym charakterze z betonowymi umocnieniami brzegowymi i bardzo wolnym nurtem. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych krąpi żerujących wzdłuż osi koryta. To idealne łowisko dla wędkarzy spławikowych, którzy mogą tu precyzyjne nęcić pole przy użyciu ciężkich zanęt o intensywnym zapachu. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych opaskach faszynowych. Uciąg wody jest stabilny i przewidywalny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do technicznego wędkarstwa spławikowego.', 'PZW Bydgoszcz');

