-- Spot 520: Barcin (Miejskie Nabrzeże)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70519, 'Noteć - Barcin (Bulwary)', 'notec-barcin', 'RIVER', 52.8651895, 17.9401417, 'Kujawsko-Pomorskie', 'Barcin', 'Noteć w Barcinie to techniczne łowisko miejskie charakteryzujące się wyrównanym nurtem i dużą populacją ryb spokojnego żeru. Woda jest tu stosunkowo głęboka, co przyciąga dorodne płocie oraz leszcze, które chętnie gromadzą się w pobliżu miejskich bulwarów. To doskonałe miejsce dla miłośników tyczki i bata, pozwalające na precyzyjne nęcenie i powtarzalne połowy białorybu. Spinningiści z sukcesami obławiają rejony mostów, szukając okoni oraz szczupaków czatujących w cieniu konstrukcji hydrotechnicznych. Uciąg wody stabilizuje się, co umożliwia precyzyjne podanie zanęty i utrzymanie stad ryb w polu łowienia przez wiele godzin. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko popularnym punktem na mapie regionu.', 'PZW Bydgoszcz');

