-- Spot 521: Łącko (Cofka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70520, 'Noteć - Łącko (Rozlewiska)', 'notec-lacko', 'RIVER', 52.8238007, 18.1014637, 'Kujawsko-Pomorskie', 'Pakość', 'Odcinek w Łącku ma charakter szerokiego rozlewiska o piaszczysto-mulistym dnie i bardzo słabym przepływie wody. Rzeka płynie tu wśród rozległych łąk, żłobiąc dno o charakterze rynnowym z licznymi kępami grążeli przy brzegach. To wymarzone miejsce dla łowców linów oraz wzdręg, które znajdują tu idealne warunki do spokojnego żerowania w zacisznych zatoczkach. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne stadne leszcze oraz wyrośnięte płocie rzeczne. Uciąg rzeki jest znikomy, co sprzyja stosowaniu najdelikatniejszych technik spławikowych oraz precyzyjnemu nęceniu punktowemu. Malowniczy krajobraz oraz cisza sprawiają, że każda wyprawa w to miejsce jest bardzo relaksująca i owocna.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70520, 'Nizinna Wielka', 'Szeroka, rozlewiskowa', 35.0, 2.0, 'Piasek i muł', 'Kępy grążeli', 'Lin, Wzdręga, Leszcz', 'Kraina leszcza', true);

-- Spot 522: Łabiszyn (Wyspa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70521, 'Noteć - Łabiszyn (Przy Śluzie)', 'notec-labiszyn', 'RIVER', 52.9465975, 17.9179488, 'Kujawsko-Pomorskie', 'Łabiszyn', 'Noteć w Łabiszynie charakteryzuje się obecnością historycznych urządzeń hydrotechnicznych i podziałem koryta na odnogi. Woda poniżej śluzy jest dobrze natleniona, co przyciąga sandacze oraz duże okonie żerujące w turbulentnym nurcie. To technicznie trudne łowisko wymaga od spinningistów precyzyjnego prowadzenia przynęty wzdłuż betonowych opasek i uskoków dna. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie, wykorzystując systematyczne nęcenie na piaszczystych płaniach koryta głównego. Uciąg wody jest zmienny i uzależniony od pracy śluzy, co wymusza na wędkarzach częstą korektę obciążenia zestawu. To jedno z najciekawszych łowisk w regionie, oferujące szansę na spotkanie z rekordową rybą w otoczeniu zabytkowej architektury.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70521, 'Nizinna Wielka', 'Zróżnicowana, śluzy', 30.0, 2.8, 'Twardy piasek', 'Śluzy, filary mostu', 'Sandacz, Płoć, Okoń', 'Kraina leszcza', true);

-- Spot 523: Tur
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70522, 'Noteć - Tur (Łęgi)', 'notec-tur', 'RIVER', 53.0786764, 17.7482785, 'Kujawsko-Pomorskie', 'Nakło nad Notecią', 'Noteć w rejonie miejscowości Tur to rzeka o bardzo naturalnym charakterze, płynąca meandrami wśród rozległych nadnoteckich łęgów. Koryto rzeki posiada tu piaszczyste dno z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach koryta. To doskonałe miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności wynurzonej i pasy trzcinowisk. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na brania dorodnych leszczy oraz walecznych jazi. Uciąg rzeki jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w polu łowienia przez wiele godzin. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz doskonałe warunki do aktywnego wypoczynku ze spinningiem.', 'PZW Bydgoszcz');

