VALUES (70522, 'Nizinna Wielka', 'Meandrująca, naturalna', 28.0, 2.0, 'Piaszczyste', 'Zwalone drzewa', 'Szczupak, Leszcz, Jaź', 'Kraina leszcza', true);

-- Spot 524: Chobielin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70523, 'Noteć - Chobielin (Warkocze)', 'notec-chobielin', 'RIVER', 53.107474, 17.6905113, 'Kujawsko-Pomorskie', 'Nakło nad Notecią', 'Noteć w Chobielinie charakteryzuje się szybszym nurtem i obecnością licznych piaszczystych przykos wychodzących daleko w koryto. Rzeka tworzy tu techniczne stanowiska pod wysokimi, gliniastymi burtami, które stanowią bezpieczne schronienie dla dorodnych kleni. To wymarzone miejsce dla spinningistów polujących na bolenie patrolujące turbulentną wodę na styku nurtu i zastoisk. Wędkarze gruntowi z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie grubszą frakcją zanęty w rynnach przydennych. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga od wędkarza umiejętnego czytania prądów i wirów wstecznych. Malowniczy krajobraz doliny Noteci oraz twarde dno sprawiają, że każda wyprawa w to miejsce jest bardzo satysfakcjonująca.', 'PZW Bydgoszcz');

