-- Spot 525: Występ
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70524, 'Noteć - Występ (Kanałowa)', 'notec-wystep', 'RIVER', 53.1247585, 17.6207429, 'Kujawsko-Pomorskie', 'Nakło nad Notecią', 'Noteć w miejscowości Występ to odcinek o wybitnie kanałowym charakterze z uregulowanym korytem i betonowymi umocnieniami brzegowymi. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych krąpi żerujących wzdłuż osi koryta. To idealne łowisko dla wędkarzy spławikowych celujących w dorodne płocie, które doskonale reagują na precyzyjne nęcenie tyczką lub batem. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych opaskach faszynowych. Uciąg wody jest stabilny i przewidywalny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi przez cały sezon. Dobra dostępność brzegów i bliskość Nakła sprawiają, że jest to chętnie wybierane miejsce na szybkie sesje wędkarskie.', 'PZW Bydgoszcz');

