-- Spot 526: Pszczółczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70525, 'Noteć - Pszczółczyn (Łąkowa)', 'notec-pszczolczyn', 'RIVER', 53.0303934, 17.9069352, 'Kujawsko-Pomorskie', 'Łabiszyn', 'Odcinek w Pszczółczynie charakteryzuje się naturalnym, meandrującym korytem płynącym wśród rozległych nadnoteckich łąk i torfowisk. Rzeka żłobi tu dno o piaszczystym charakterze z lokalnymi naniesieniami mułu w zacisznych zakolach wstecznych. To doskonałe miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności wynurzonej i pasy trzcinowisk. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne stadne leszcze oraz wyrośnięte liny rzeczne. Uciąg wody jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu białorybu w polu łowienia przez wiele godzin. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz doskonałe warunki do aktywnego wypoczynku ze spinningiem.', 'PZW Bydgoszcz');

