-- Spot 527: Nowe Dąbie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70526, 'Noteć - Nowe Dąbie (Zakola)', 'notec-nowe-dabie', 'RIVER', 52.9953775, 17.9590389, 'Kujawsko-Pomorskie', 'Łabiszyn', 'Noteć w Nowym Dąbiu to rzeka o bardzo urozmaiconym dnie i malowniczych zakolach z wyraźnie zaznaczonymi rynnami prądowymi. Podłoże jest tu mocno zróżnicowane, od twardego piasku po gliniaste burty, co stwarza idealne warunki dla jazi. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz kleni żerujących pod nawisami nadrzecznych wierzb. Uciąg jest stabilny, co pozwala na komfortowe operowanie zestawami spławikowymi z długim wędziskiem na krawędzi nurtu. W rynnach o głębokości dochodzącej do dwóch metrów stacjonują duże krąpie oraz okresowo pojawiające się dorodne płocie. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką rybą w surowym krajobrazie Doliny Noteci.', 'PZW Bydgoszcz');

