-- Spot 528: Wieleń (Miejska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70527, 'Noteć - Wieleń (Rynny)', 'notec-wielen', 'RIVER', 52.896427, 16.1776055, 'Wielkopolskie', 'Wieleń', 'Noteć w Wieleniu to potężna rzeka nizinna o szerokim korycie i wyraźnie zaznaczonej rynnie głównej o dużym znaczeniu wędkarskim. Dno jest tu twarde, piaszczysto-żwirowe, co sprzyja aktywności ryb reofilnych takich jak dorodne certy oraz rzeczne brzany. To strategiczne miejsce dla łowców sumów i sandaczy, które wykorzystują głębokie doły pod filarami mostów jako swoje ostoje. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując metodę ciężkiego feedera dla stabilizacji zestawu w nurcie. Uciąg rzeki w tym miejscu jest zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upadów. Dobra infrastruktura i łatwy dostęp do wody z miejskich nabrzeży czynią to łowisko popularnym punktem w regionie.', 'PZW Nadnotecki');

