-- Spot 529: Jaryń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70528, 'Noteć - Jaryń (Przykosy)', 'notec-jaryn', 'RIVER', 52.8768631, 16.1103281, 'Wielkopolskie', 'Wieleń', 'Odcinek w Jaryniu słynie z rozległych piaszczystych przykos wychodzących daleko w główny nurt rzeki, tworzących rybne warkocze. To wymarzone miejsce dla spinningistów polujących na bolenie, które agresywnie żerują na stadach uklei przy krawędzi nurtu. Dno piaszczyste zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność i waleczność podczas holu. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia, celując w dorodne płocie oraz wyrośnięte krąpie rzeczne. Uciąg rzeki jest tu zdecydowany i wymaga od wędkarza umiejętnego czytania prądów wodnych dla poprawnej prezentacji przynęty. Malowniczy krajobraz pradoliny Noteci nadaje każdej wyprawie wędkarskiej wyjątkowego, dzikiego charakteru sprzyjającego wypoczynkowi.', 'PZW Nadnotecki');

