-- Spot 531: Krzyż Wielkopolski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70530, 'Noteć - Krzyż Wielkopolski (Płania)', 'notec-krzyz-wlkp', 'RIVER', 52.8616359, 16.001654, 'Wielkopolskie', 'Krzyż Wielkopolski', 'Noteć w Krzyżu to potężna rzeka nizinna o szerokim korycie i leniwym, bardzo stabilnym nurcie wody. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu ogromnych stad leszczy oraz wyrośniętych krąpi żerujących na piaszczystych płaniach. To idealne łowisko dla wędkarzy spławikowych, którzy mogą tu precyzyjne nęcić pole przy użyciu ciężkich zanęt o intensywnym zapachu. Spinningiści z sukcesami polują tutaj na szczupaki, obławiając pasy trzcinowisk oraz kępy roślinności wynurzonej przy brzegach. Uciąg rzeki jest przewidywalny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Dobra infrastruktura i łatwy dostęp do wody z miejskich nabrzeży czynią to łowisko popularnym punktem w regionie.', 'PZW Nadnotecki');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70530, 'Nizinna Wielka', 'Szeroka, uregulowana', 50.0, 3.0, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', true);

-- Spot 532: Stare Bielice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70531, 'Noteć - Stare Bielice (Rynny)', 'notec-stare-bielice', 'RIVER', 52.8476294, 15.9291339, 'Lubuskie', 'Drezdenko', 'Odcinek w Starych Bielicach charakteryzuje się naturalnym, meandrującym korytem płynącym wśród rozległych nadnoteckich łąk. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach koryta, które są doskonałym schronieniem dla dorodnych leszczy. To strategiczne miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności wynurzonej w zacisznych zatoczkach wstecznych. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w wyrośnięte liny oraz rzeczne krąpie. Uciąg wody jest umiarkowany, co sprzyja systematycznemu nęceniu i utrzymywaniu białorybu w polu łowienia przez wiele godzin. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz doskonałe warunki do aktywnego wypoczynku ze spinningiem.', 'PZW Gorzów Wlkp.');

