VALUES (70531, 'Nizinna Wielka', 'Meandrująca, naturalna', 45.0, 2.5, 'Piasek i glina', 'Głębokie rynny', 'Leszcz, Szczupak, Lin', 'Kraina leszcza', true);

-- Spot 533: Drezdenko (Stara Noteć)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70532, 'Noteć - Drezdenko (Miejskie Bystrza)', 'notec-drezdenko', 'RIVER', 52.850899, 15.8547145, 'Lubuskie', 'Drezdenko', 'Noteć w Drezdenku to techniczne łowisko charakteryzujące się obecnością licznych konstrukcji hydrotechnicznych i umocnień brzegowych. Pod filarami mostów woda wymyła twardsze piaszczyste dołki, gdzie chętnie stacjonują drapieżniki czatujące na spływającą nurtem drobnicę. To doskonałe miejsce dla spinningistów szukających sandaczy oraz okazowych okoni żerujących przy betonowych opaskach faszynowych. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie, wykorzystując metodę lekkiej przepływanki z przystawką. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upadów. Dobra dostępność brzegów i miejska infrastruktura ułatwiają bezpieczne rozstawienie stanowiska wędkarskiego bezpośrednio z bulwarów.', 'PZW Gorzów Wlkp.');

