VALUES (70532, 'Nizinna Wielka', 'Uregulowana miejska', 40.0, 2.8, 'Piasek i żwir', 'Mosty, opaski', 'Sandacz, Płoć, Okoń', 'Kraina leszcza', true);

-- Spot 534: Synogać
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70533, 'Noteć - Synogać (Górna Struga)', 'notec-synogac', 'RIVER', 52.4097879, 18.5241334, 'Kujawsko-Pomorskie', 'Kruszwica', 'Noteć w Synogaci to kameralny odcinek rzeki o wybitnie kanałowym charakterze i bardzo wolnym przepływie wody. Podłoże jest tu mocno zamulone i porośnięte roślinnością wynurzoną, co tworzy idealne warunki dla lina oraz złotego karasia. To eldorado dla miłośników spławika, którzy cenią sobie precyzyjne łowienie w zacisznych miejscach pod nawisami nadrzecznych traw. Spinningowanie wymaga tu dużej precyzji ze względu na wąskie koryto i liczne pasy przybrzeżnych trzcinowisk. Uciąg rzeki jest niemal niezauważalny, co pozwala na stosowanie najczulszych spławików typu piórko z lekkim obciążeniem. Surowy krajobraz doliny rzeki zapewnia wędkarzowi całkowitą izolację od zgiełku i szansę na kontakt z dziką rybą.', 'PZW Bydgoszcz');

