-- Spot 535: Teresewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70534, 'Noteć - Teresewo (Torfowiska)', 'notec-teresewo', 'RIVER', 52.3921159, 18.4561868, 'Kujawsko-Pomorskie', 'Kruszwica', 'Odcinek w Teresewie płynie naturalnym, silnie meandrującym korytem przez malownicze tereny kujawskich torfowisk. Woda ma tutaj charakterystyczny ciemny kolor, a dno jest w większości piaszczysto-muliste z licznymi podwodnymi przeszkodami. To wymarzone łowisko wzdręg oraz wyrośniętych rzecznych płoci, które grupują się w dobrze natlenionych oknach między grążelami. Spinningiści z sukcesami obławiają tutejsze trzcinowiska, szukając szczupaków czatujących w cieniu nadrzecznej roślinności. Uciąg jest znikomy, co pozwala na bardzo naturalną prezentację przynęty na najdelikatniejszych zestawach spławikowych. Niska presja wędkarska oraz trudny dostęp do brzegów gwarantują absolutny spokój i bliski kontakt z surową przyrodą.', 'PZW Bydgoszcz');

