VALUES (70534, 'Nizinna Mała', 'Meandrująca, bagienna', 8.0, 1.2, 'Piasek i muł', 'Grążele, trzciny', 'Wzdręga, Szczupak, Płoć', 'Kraina leszcza', false);

-- Spot 536: Stara Ruda
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70535, 'Noteć - Stara Ruda (Cofka Gopła)', 'notec-stara-ruda', 'RIVER', 52.4146167, 18.3921017, 'Kujawsko-Pomorskie', 'Kruszwica', 'Noteć w Starej Rudzie to odcinek bezpośrednio sąsiadujący z jeziorem Gopło, co ma kluczowy wpływ na migrację tutejszych ryb. Rzeka posiada tu szersze koryto o wyrównanym piaszczystym dnie i bogatej roślinności zanurzonej w nurcie. To strategiczne miejsce dla łowców okoni, które gromadzą się tutaj w dużych stadach podczas jesiennych żerów. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w dorodne leszcze oraz wyrośnięte krąpie migrujące ze zbiornika. Uciąg wody jest łagodny, co pozwala na komfortowe nęcenie łowiska i utrzymywanie stad białorybu w polu widzenia. Dogodny dojazd przez polne drogi sprawia, że jest to chętnie wybierane miejsce na weekendowe zasiadki z lekkim gruntem.', 'PZW Bydgoszcz');

