-- Spot 537: Lubotyń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70536, 'Noteć - Lubotyń (Kanałowa)', 'notec-lubotyn', 'RIVER', 52.4180939, 18.602928, 'Wielkopolskie', 'Koło', 'Noteć w Lubotyniu to odcinek o wybitnie kanałowym charakterze, stanowiący część systemu łączącego dorzecza Wisły i Odry. Woda płynie tu leniwie, a dno jest w dużej mierze zamulone i porośnięte gęstą roślinnością wynurzoną. To doskonałe miejsce dla łowców linów oraz wzdręg, które znajdują tu schronienie w licznych zatoczkach przy trzcinowiskach. Wędkarze spławikowi z sukcesami stosują tu metodę bata, nęcąc drobne ryby białego żeru wzdłuż betonowych umocnień brzegowych. Uciąg jest znikomy, co pozwala na stosowanie najczulszych zestawów z lekkimi spławikami typu piórko dla lepszej sygnalizacji. Dzięki sielskiemu otoczeniu, odcinek ten zapewnia wędkarzowi całkowitą izolację od zgiełku i szansę na kontakt z dziką rybą.', 'PZW Konin');

