-- Spot 538: Młodocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70537, 'Noteć - Młodocin (Zakole)', 'notec-mlodocin', 'RIVER', 52.8802629, 17.8684436, 'Kujawsko-Pomorskie', 'Barcin', 'Odcinek rzeki w Młodocinie charakteryzuje się naturalnym, meandrującym korytem płynącym wśród rozległych nadnoteckich łąk. Rzeka żłobi tu piaszczyste dno z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach koryta, co sprzyja bytowaniu dorodnych leszczy. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz kleni żerujących pod nawisami nadrzecznych wierzb. Uciąg wody jest umiarkowany i przewidywalny, co ułatwia systematyczne nęcenie i utrzymywanie stad białorybu w polu łowienia. Woda zachowuje tu umiarkowaną przejrzystość, co sprzyja żerowaniu szczupaków czatujących w pobliżu kęp roślinności zanurzonej rzeki. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz doskonałe warunki do całodniowego kontaktu z naturą.', 'PZW Bydgoszcz');

