-- Spot 539: Mielnica Duża
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70538, 'Noteć - Mielnica Duża (Wlot do Gopła)', 'notec-mielnica-duza', 'RIVER', 52.4869266, 18.3859819, 'Wielkopolskie', 'Skulsk', 'Noteć w rejonie Mielnicy Dużej to odcinek wejściowy do jeziora Gopło, mający charakter szerokiego kanału o piaszczysto-mulistym dnie. Rzeka płynie tu stabilnie, tworząc rybne płanie idealne do letnich zasiadek z lekkim gruntem lub spławikiem rzecznym. To strategiczne miejsce dla łowców okoni, które grupują się tutaj w dużych stadach podczas jesiennych żerów. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne leszcze oraz wyrośnięte krąpie migrujące ze zbiornika. Uciąg jest łagodny, co pozwala na stosowanie najdelikatniejszych technik spławikowych oraz precyzyjne nęcenie punktowe łowiska. Dogodny dojazd przez polne drogi sprawia, że jest to chętnie wybierane miejsce na weekendowe sesje wędkarskie.', 'PZW Konin');

