-- Spot 540: Mietlica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70539, 'Noteć - Mietlica (Rynna Gopła)', 'notec-mietlica', 'RIVER', 52.5407973, 18.3796629, 'Kujawsko-Pomorskie', 'Kruszwica', 'W Mietlicy Noteć traci swój rzeczny charakter, rozlewając się w szerokie plosa południowej części jeziora Gopło. Dno jest tu mocno zróżnicowane, piaszczysto-muliste z licznymi górkami podwodnymi stanowiącymi naturalne ostoje dla sandaczy. To doskonałe łowisko dla spinningistów obławiających stoki koryta rzeki przepływającej przez jezioro w poszukiwaniu okazowych okoni. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszczowe stada, wykorzystując metodę feedera klasycznego na znacznych odległościach. Uciąg wody jest niemal niezauważalny, a kluczowe znaczenie ma tu znajomość batymetrii dawnego koryta rzeki Noteci. Miejsce to słynie z bogactwa ryb spokojnego żeru i jest doskonałym punktem do wodowania łodzi wędkarskich.', 'PZW Bydgoszcz');

