VALUES (70539, 'Nizinna Wielka', 'Jeziorna (koryto w jeziorze)', 150.0, 4.5, 'Muł i piasek', 'Górki podwodne', 'Sandacz, Okoń, Leszcz', 'Kraina leszcza', true);

-- Spot 541: Popowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70540, 'Noteć - Popowo (Trzcinowiska)', 'notec-popowo', 'RIVER', 52.5849526, 18.3638901, 'Kujawsko-Pomorskie', 'Kruszwica', 'Noteć w Popowie to odcinek rynnowy jeziora Gopło, gdzie koryto rzeki jest wyraźnie zaznaczone i obfituje w przeszkody. Rzeka płynie tu dostojnie, oferując wędkarzom bardzo urozmaiconą linię brzegową z pasami tataraku i grążeli żółtych. To wymarzone miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności wynurzonej przy użyciu lekkich przynęt powierzchniowych. Wędkarze gruntowi z sukcesami łowią tu rekordowe leszcze, wykorzystując systematyczne nęcenie na piaszczystych płaniach koryta głównego. Uciąg jest znikomy, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem rzecznym. Niska presja wędkarska w tym rejonie oraz dziki charakter brzegów sprzyjają wielogodzinnym, skutecznym zasiadkom nad wodą.', 'PZW Bydgoszcz');

