VALUES (70540, 'Nizinna Wielka', 'Szeroka, jeziorna', 200.0, 3.8, 'Piasek i muł', 'Pasy trzcin', 'Szczupak, Leszcz, Płoć', 'Kraina leszcza', true);

-- Spot 542: Kruszwica (Wypływ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70541, 'Noteć - Kruszwica (Pod Wieżą)', 'notec-kruszwica-most', 'RIVER', 52.6495731, 18.3459955, 'Kujawsko-Pomorskie', 'Kruszwica', 'Noteć w Kruszwicy wypływa z jeziora Gopło, przechodząc w uregulowane koryto o szerokim znaczeniu dla żeglugi i wędkarstwa. Pod mostami woda wymyła głębsze rynny, które są doskonałym stanowiskiem dla sandaczy oraz dorodnych kleni rzecznych. To techniczne łowisko miejskie charakteryzuje się wyrównanym nurtem i obecnością licznych konstrukcji hydrotechnicznych sprzyjających drapieżnikom rzecznym. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz leszcze, wykorzystując metodę bata przy miejskich bulwarach. Uciąg wody stabilizuje się poniżej wypływu z jeziora, co pozwala na precyzyjne nęcenie i utrzymywanie stad ryb. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko jednym z najpopularniejszych punktów w całym regionie.', 'PZW Bydgoszcz');

