-- Spot 543: Przedecz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70542, 'Noteć - Przedecz (Źródliska)', 'notec-przedecz', 'RIVER', 52.341649, 18.902458, 'Wielkopolskie', 'Przedecz', 'Odcinek rzeki Noteć w Przedczu to jej górny, niemal źródliskowy bieg o charakterze wąskiej, polnej strugi rzecznej. Woda płynie tu dość wartko, żłobiąc piaszczyste dno z licznymi mikro-rynami ukrytymi wśród gęstych traw brzegowych. To idealne miejsce dla pasjonatów mikro-jigingu, szukających okoni w niewielkich zastoiskach i cieniach nadrzecznych krzewów wikliny. Ze względu na minimalną szerokość koryta, kluczowe dla sukcesu jest zachowanie absolutnej ciszy i dyskrecji podczas podejścia. Uciąg wody jest zróżnicowany, co pozwala na eksperymentowanie z gramaturą zestawu i sposobem podania przynęty naturalnej. To dzikie i rzadko odwiedzane łowisko nagradza wytrwałych wędkarzy kontaktem z pierwotną naturą i niewypłoszoną rybą.', 'PZW Konin');

