-- Spot 545: Gaj Stolarski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70544, 'Noteć - Gaj Stolarski (Zarośnięta)', 'notec-gaj-stolarski', 'RIVER', 52.3699972, 18.7538045, 'Wielkopolskie', 'Babiak', 'Odcinek w Gaju Stolarskim charakteryzuje się naturalnym korytem o bardzo niskiej presji wędkarskiej i dużej ilości roślinności zanurzonej. Rzeka żłobi tu piaszczysto-muliste dno, tworząc zaciszne zatoczki idealne dla złotego karasia oraz lina rzeki Noteci. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie, wykorzystując systematyczne nęcenie w "oknach" między grążelami i tatarakiem. Spinningiści chętnie obławiają tutejsze spowolnienia nurtu, szukając okoni oraz mniejszych szczupaków czatujących pod nawisami traw. Uciąg wody jest stabilny i leniwy, co ułatwia precyzyjne podanie lekkiej przynęty naturalnej na delikatnym zestawie. To technicznie wymagające łowisko nagradza wytrwałych wędkarzy szansą na spotkanie z rybą w jej naturalnym ekosystemie.', 'PZW Konin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70544, 'Nizinna Mała', 'Meandrująca, zarośnięta', 7.0, 1.0, 'Piasek i muł', 'Kępy grążeli', 'Lin, Karaś złoty, Szczupak', 'Kraina leszcza', false);

-- Spot 546: Lubotyń (Górny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70545, 'Noteć - Lubotyń (Łąkowa)', 'notec-lubotyn-gora', 'RIVER', 52.4077258, 18.7108211, 'Wielkopolskie', 'Sompolno', 'Noteć w górnej części Lubotynia to rzeka o dość wyrównanym nurcie i piaszczystym dnie z lokalnymi naniesieniami gliny. Koryto jest tu częściowo uregulowane, co ułatwia dostęp do linii brzegowej miłośnikom techniki drgającej szczytówki lub bata. To doskonałe miejsce dla łowców jelców oraz kleni, które doskonale reagują na małe przynęty podawane w głównym prądzie. Uciąg jest umiarkowany, co sprzyja natlenieniu wody i wysokiej aktywności ryb spokojnego żeru przez cały sezon wędkarski. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia smużaków na krawędzi nurtu głównego w poszukiwaniu rzecznych drapieżników. Niska presja w tym rejonie zapewnia spokój oraz szansę na kontakt z bardzo dziką i waleczną rybą.', 'PZW Konin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70545, 'Nizinna Mała', 'Uregulowana, nurt stabilny', 12.0, 1.2, 'Piasek i glina', 'Podmyte brzegi', 'Kleń, Jelec, Płoć', 'Kraina leszcza', false);

-- Spot 547: Polichno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70546, 'Noteć - Polichno (Rynny)', 'notec-polichno', 'RIVER', 53.1166935, 17.5425874, 'Kujawsko-Pomorskie', 'Nakło nad Notecią', 'Noteć w Polichnie to rzeka o szerokim korycie i wyraźnie zaznaczonej rynnie głównej o dużym znaczeniu dla wędkarzy. Dno jest tu twarde, piaszczysto-żwirowe, co sprzyja aktywności ryb reofilnych żerujących w strefie o najsilniejszym uciągu. To strategiczne miejsce dla łowców okazowych leszczy, którzy stosują tu systematyczne nęcenie grubszą frakcją zanęty feederowej. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych opaskach faszynowych i mostach. Uciąg rzeki jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich okresów niskiego stanu. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko popularnym punktem w całym regionie Nakła.', 'PZW Bydgoszcz');

