VALUES (70546, 'Nizinna Wielka', 'Szeroka, nurt żywy', 32.0, 2.8, 'Piasek i żwir', 'Opaski faszynowe', 'Leszcz, Okoń, Krąp', 'Kraina leszcza', true);

-- Spot 548: Rosko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70547, 'Noteć - Rosko (Pradolina)', 'notec-rosko', 'RIVER', 52.891378, 16.3524475, 'Wielkopolskie', 'Wieleń', 'Odcinek w Rosku charakteryzuje się szerokimi rozlewiskami i obecnością piaszczystych łach wychodzących daleko w główny nurt rzeki. Noteć płynie tu majestatycznie przez Pradolinę Toruńsko-Eberswaldzką, żłobiąc dno o piaszczysto-mulistym charakterze z licznymi przykosami. To wymarzone miejsce dla spinningistów polujących na szczupaki czatujące w cieniu nadrzecznej roślinności brzegowej. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na brania rekordowych stad leszczy oraz dorodnych krąpi. Uciąg wody jest łagodny, co pozwala na stosowanie najdelikatniejszych technik spławikowych oraz precyzyjne nęcenie punktowe łowiska. Dogodny dojazd przez rozległe łąki sprawia, że jest to chętnie wybierane miejsce na wielodniowe biwaki wędkarskie.', 'PZW Nadnotecki');

