VALUES (70547, 'Nizinna Wielka', 'Szeroka płania, nurt łagodny', 45.0, 2.5, 'Piasek i muł', 'Piaszczyste łachy', 'Leszcz, Szczupak, Krąp', 'Kraina leszcza', true);

-- Spot 549: Góra nad Notecią
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70548, 'Noteć - Góra nad Notecią (Warkocze)', 'notec-gora-nad-notecia', 'RIVER', 52.8861035, 16.4962912, 'Wielkopolskie', 'Czarnków', 'Noteć w Górze nad Notecią to potężna rzeka nizinna słynąca z rozległych przykos i silnych warkoczy prądowych na środku nurtu. Podłoże jest tu mocno zróżnicowane, piaszczyste z lokalnymi naniesieniami żwiru, co stwarza doskonałe warunki dla ryb drapieżnych. To strategiczne stanowisko dla łowców sandaczy oraz boleni, które agresywnie żerują na stadach uklei przy krawędzi nurtu. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując metodę feedera klasycznego na znacznych odległościach od brzegu. Uciąg rzeki jest zdecydowany, co wymaga od wędkarza stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu. Miejsce to zapewnia niezapomniane emocje wędkarskie w surowym krajobrazie pradoliny rzeki Noteci.', 'PZW Nadnotecki');

