VALUES (70548, 'Nizinna Wielka', 'Szeroka, nurt żywy', 48.0, 3.0, 'Piasek i żwir', 'Warkocze prądowe', 'Sandacz, Boleń, Leszcz', 'Kraina leszcza', true);

-- Spot 550: Wymysław
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70549, 'Noteć - Wymysław (Łęgi)', 'notec-wymyslaw', 'RIVER', 53.0593333, 16.9713156, 'Wielkopolskie', 'Chodzież', 'Noteć w Wymysłowie to odcinek rzeki o bardzo szerokim korycie i jednostajnym, powolnym przepływie wody przez rozległe łęgi. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych krąpi żerujących na piaszczystych płaniach. To doskonałe łowisko dla wędkarzy spławikowych, którzy cenią sobie precyzyjne nęcenie tyczką wzdłuż brzegowych pasów trzcinowisk. Spinningiści z sukcesami polują tu na szczupaki, obławiając krawędzie roślinności wynurzonej przy użyciu lekko dociążonych wahadłówek. Uciąg rzeki jest niemal niezauważalny, co pozwala na stosowanie najdelikatniejszych zestawów z czułymi spławikami typu piórko. Miejsce to zapewnia ciszę i doskonałe warunki do całodniowego kontaktu z naturą w surowym krajobrazie pradoliny.', 'PZW Nadnotecki');

