VALUES (70549, 'Nizinna Wielka', 'Szeroka płania, nurt wolny', 38.0, 2.5, 'Piasek i muł', 'Trzcinowiska', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', true);

-- Spot 551: Krzewina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70550, 'Noteć - Krzewina (Zastoiska)', 'notec-krzewina', 'RIVER', 53.0525577, 16.897124, 'Wielkopolskie', 'Kaczory', 'Odcinek w Krzewinie charakteryzuje się wyrównanym nurtem i obecnością licznych zatok wstecznych o piaszczysto-mulistym podłożu koryta. Rzeka płynie tu dostojnie, tworząc rybne płanie idealne do letnich zasiadek z lekkim gruntem lub klasycznym feederem. To strategiczne miejsce dla łowców linów oraz wzdręg, które znajdują tu doskonałe warunki w zacisznych oknach między grążelami. Spinningiści cenią ten fragment rzeki za populację okonia, który chętnie stacjonuje w cieniu podwodnych karczowisk i faszyny. Uciąg wody stabilizuje się, co umożliwia precyzyjne podanie zanęty i utrzymywanie białorybu w polu łowienia przez wiele godzin. Dogodny dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na rodzinne biwaki wędkarskie.', 'PZW Nadnotecki');

