VALUES (70550, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 40.0, 2.2, 'Piasek i muł', 'Zatoki wsteczne', 'Lin, Okoń, Leszcz', 'Kraina leszcza', true);

-- Spot 552: Dziembówko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70551, 'Noteć - Dziembówko (Rynny)', 'notec-dziembowko', 'RIVER', 53.0525817, 16.8211714, 'Wielkopolskie', 'Piła', 'Noteć w Dziembówku to rzeka o dość głębokim korycie z wyraźnie zaznaczonymi rynnami przydennymi na łukach koryta głównego. Podłoże jest tu mocno zróżnicowane, od twardego piasku po gliniaste burty, co stwarza idealne warunki dla jazi. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz kleni żerujących pod nawisami nadrzecznych wierzb. Uciąg jest stabilny i zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upadów rzeki. W rynnach o głębokości dochodzącej do trzech metrów stacjonują duże leszcze oraz okresowo pojawiające się dorodne płocie. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką rybą w malowniczym otoczeniu Doliny Noteci.', 'PZW Nadnotecki');

