-- Spot 553: Ujście (Widły z Gwdą)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70552, 'Noteć - Ujście (Widły)', 'notec-ujscie-widly', 'RIVER', 53.0546551, 16.7444829, 'Wielkopolskie', 'Ujście', 'Ujście to strategiczny punkt wędkarski, gdzie do Noteci wpada rzeka Gwda, znacznie zwiększając jej masę i natlenienie. Mieszanie się nurtów obu rzek tworzy specyficzne warunki pokarmowe, które przyciągają sandacze, sumy oraz dorodne bolenie. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe z głębokimi rynnami wymytymi przez silniejszy nurt rzeki Gwdy. Spinningiści z sukcesami obławiają strefę styku wód, szukając drapieżników żerujących na uklejach w turbulentnym nurcie. Wędkarze gruntowi chętnie nęcą tutejsze płanie, licząc na rekordowe leszcze oraz dorodne rzeczne brzany wchodzące z prądem. To wymagające technicznie łowisko nagradza wytrwałych wędkarzy rybami życia w otoczeniu historycznej zabudowy miasta.', 'PZW Nadnotecki');

