VALUES (70552, 'Nizinna Wielka', 'Potężny węzeł wodny', 55.0, 3.5, 'Piasek i żwir', 'Połączenie nurtów', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', true);

-- Spot 554: Mirosław
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70553, 'Noteć - Mirosław (Przykosy)', 'notec-miroslaw', 'RIVER', 53.0561003, 16.6690331, 'Wielkopolskie', 'Ujście', 'Noteć w Mirosławiu słynie z rozległych piaszczystych przykos wychodzących daleko w główny nurt rzeki, tworząc rybne warkocze. To wymarzone miejsce dla spinningistów polujących na bolenie, które agresywnie żerują na stadach uklei przy krawędzi nurtu. Dno piaszczyste zapewnia rybom doskonałe warunki tlenowe, co przekłada się na ich wysoką aktywność i waleczność. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia, celując w dorodne płocie oraz wyrośnięte krąpie rzeczne żerujące na stokach. Uciąg rzeki jest tu zdecydowany i wymaga od wędkarza umiejętnego czytania prądów wodnych dla poprawnej prezentacji przynęty. Malowniczy krajobraz pradoliny Noteci nadaje każdej wyprawie wędkarskiej wyjątkowego, dzikiego charakteru sprzyjającego wypoczynkowi.', 'PZW Nadnotecki');

