-- Spot 555: Romanowo Górne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70554, 'Noteć - Romanowo Górne (Płania)', 'notec-romanowo-gorne', 'RIVER', 52.9815931, 16.5667062, 'Wielkopolskie', 'Czarnków', 'Odcinek rzeki w Romanowie Górnym to typowa szeroka płania o wyrównanym dnie i jednostajnym, bardzo stabilnym przepływie wody. Dno jest tu piaszczysto-muliste, co tworzy idealne warunki dla ryb spokojnego żeru, szczególnie dużych leszczy i linów. To doskonałe łowisko dla wędkarzy spławikowych, którzy cenią sobie precyzyjne łowienie w zacisznych miejscach pod przeciwległym brzegiem. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych trzcinowiskach i starorzeczach. Głębokość jest wyrównana, co pozwala na skuteczne badanie łowiska bez konieczności częstej zmiany gramatury zestawu. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do długich, relaksujących sesji z feederem.', 'PZW Nadnotecki');

