INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70555, 'Noteć - Romanowo Dolne (Płanie)', 'notec-romanowo-dolne', 'RIVER', 52.9366533, 16.5605138, 'Wielkopolskie', 'Czarnków', 'Noteć w Romanowie Dolnym płynie szeroką pradoliną, tworząc rozległe płanie o piaszczysto-mulistym dnie. Rzeka posiada tu wyrównany, bardzo powolny nurt, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych krąpi. To idealne łowisko dla wędkarzy spławikowych, którzy mogą tu precyzyjnie nęcić pola przy użyciu cięższych zanęt gruntowych. Spinningiści z sukcesami obławiają tutejsze pasy trzcinowisk, szukając szczupaków czatujących w cieniu roślinności wynurzonej. Uciąg jest niemal niezauważalny, co pozwala na stosowanie najdelikatniejszych zestawów z czułymi spławikami typu piórko. Dobra dostępność brzegów sprawia, że jest to chętnie wybierane miejsce na całodniowe zasiadki feederowe.', 'PZW Nadnotecki');

