-- Spot 557: Walkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70556, 'Noteć - Walkowice (Zatoki)', 'notec-walkowice', 'RIVER', 53.0258029, 16.5902625, 'Wielkopolskie', 'Chodzież', 'Odcinek w Walkowicach charakteryzuje się bardzo urozmaiconą linią brzegową z licznymi zatokami wstecznymi i starorzeczami. Rzeka płynie tu dostojnie, oferując wędkarzom piaszczysto-muliste dno z bogatą fauną denną przyciągającą stadne ryby białego żeru. To strategiczne miejsce dla łowców linów oraz wzdręg, które znajdują tu doskonałe warunki w zacisznych oknach między grążelami. Spinningiści cenią ten fragment rzeki za populację okonia, który chętnie stacjonuje w cieniu podwodnych karczowisk i faszyny. Uciąg wody jest stabilny i leniwy, co umożliwia precyzyjne podanie zanęty i utrzymywanie ryb w polu łowienia. Malowniczy krajobraz pradoliny Noteci oraz niska presja wędkarska sprawiają, że każda wyprawa w to miejsce jest bardzo relaksująca.', 'PZW Nadnotecki');

