-- Spot 558: Wrzeszczyna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70557, 'Noteć - Wrzeszczyna (Rynny)', 'notec-wrzeszczyna', 'RIVER', 52.8886785, 16.2519926, 'Wielkopolskie', 'Wieleń', 'Noteć we Wrzeszczynie to potężna rzeka nizinna o szerokim korycie i wyraźnie zaznaczonej rynnie głównej o dużym znaczeniu wędkarskim. Dno jest tu twardsze, piaszczysto-żwirowe, co sprzyja aktywności ryb reofilnych takich jak dorodne certy oraz rzeczne brzany. To doskonałe stanowisko dla łowców sumów i sandaczy, które wykorzystują głębokie rynny pod brzegowymi opaskami jako swoje ostoje. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując metodę ciężkiego feedera dla stabilizacji zestawu w nurcie. Uciąg rzeki jest tu zdecydowany, co wymaga od wędkarza umiejętnego czytania prądów wodnych i wirów wstecznych. Stanowisko to gwarantuje absolutny spokój oraz szansę na kontakt z niewypłoszoną, dużą rybą rzeczną w surowym krajobrazie.', 'PZW Nadnotecki');

