-- Spot 559: Rynarzewo (Noteć Leniwa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70558, 'Noteć - Rynarzewo (Kanałowa)', 'notec-rynarzewo', 'RIVER', 53.0702703, 17.822503, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'W Rynarzewie Noteć przyjmuje formę uregulowanego kanału o bardzo wolnym przepływie wody i piaszczysto-mulistym podłożu koryta. Rzeka płynie tu wśród rozległych torfowisk, co nadaje wodzie charakterystyczny, ciemniejszy kolor sprzyjający aktywności linów oraz złotych karasi. To wymarzone łowisko dla miłośników tyczki i bata, pozwalające na precyzyjne nęcenie i powtarzalne połowy białorybu. Spinningiści z sukcesami obławiają tutejsze pasy trzcinowisk, szukając okoni oraz mniejszych szczupaków czatujących w przybrzeżnych cieniach. Uciąg jest znikomy, co pozwala na stosowanie najdelikatniejszych technik spławikowych oraz precyzyjne nęcenie punktowe łowiska. Dogodny dostęp do brzegów oraz wysoka rybność sprawiają, że jest to chętnie wybierane miejsce na rodzinne zasiadki.', 'PZW Bydgoszcz');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70558, 'Nizinna Wielka', 'Uregulowana, kanałowa', 25.0, 2.2, 'Piasek i muł', 'Trzcinowiska', 'Lin, Karaś złoty, Płoć', 'Kraina leszcza', true);

-- Spot 560: Bogołomia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70559, 'Noteć - Bogołomia (Struga)', 'notec-bogolomia', 'RIVER', 52.374892, 19.0069861, 'Wielkopolskie', 'Przedecz', 'Noteć w Bogołomii to górny odcinek rzeki o charakterze wąskiej, polnej strugi wijącej się wśród torfowisk i nieużytków. Koryto jest tu płytkie, o mulistym dnie z licznymi kępami roślinności wynurzonej stanowiącej schronienie dla mniejszych drapieżników. To idealne miejsce dla pasjonatów mikro-jigingu, szukających okoni w niewielkich zastoiskach i cieniach nadrzecznych krzewów wikliny. Ze względu na minimalną szerokość koryta, kluczowe dla sukcesu jest zachowanie absolutnej ciszy i dyskrecji podczas podejścia. Uciąg wody jest niemal niezauważalny, co pozwala na stosowanie najczulszych spławików typu piórko z lekkim obciążeniem rzutowym. Dziki charakter tego mało znanego łowiska nagradza wytrwałych wędkarzy kontaktem z pierwotną naturą i niewypłoszoną rybą.', 'PZW Konin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70559, 'Nizinna Mała', 'Wąska struga, płytka', 6.0, 0.7, 'Muliste', 'Zatory roślinne', 'Okoń, Płoć, Kiełb', 'Kraina leszcza', false);

-- Spot 561: Przedbojewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70560, 'Noteć - Przedbojewice (Przy Gople)', 'notec-przedbojewice', 'RIVER', 52.7326171, 18.2811101, 'Kujawsko-Pomorskie', 'Kruszwica', 'Odcinek w Przedbojewicach charakteryzuje się wyrównanym nurtem i uregulowanym korytem o charakterze kanałowym w rejonie jeziora Gopło. Podłoże jest tu piaszczysto-muliste, a brzegi porośnięte gęstymi trzcinowiskami stanowią idealne tarlisko dla wielu gatunków ryb spokojnego żeru. To doskonałe łowisko dla wędkarzy spławikowych celujących w dorodne liny oraz wzdręgi żerujące w oknach roślinności wynurzonej. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy brzegowych opaskach faszynowych i betonowych. Uciąg rzeki jest znikomy, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w polu łowienia przez wiele godzin. Dobra infrastruktura i łatwy dostęp do wody sprawiają, że jest to chętnie wybierane miejsce na szybkie sesje feederowe.', 'PZW Bydgoszcz');

