-- Spot 562: Krusza Podlotowa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70561, 'Noteć - Krusza Podlotowa (Kanałowa)', 'notec-krusza-podlotowa', 'RIVER', 52.7511341, 18.2127346, 'Kujawsko-Pomorskie', 'Inowrocław', 'Noteć w Kruszy Podlotowej to odcinek o typowo kanałowym charakterze, z uregulowaną linią brzegową i bardzo powolnym nurcie. Dno jest tu w przeważającej mierze piaszczysto-muliste, co stwarza idealne warunki dla ryb spokojnego żeru, szczególnie dużych leszczy i krąpi. To doskonałe łowisko dla miłośników tyczki i bata, pozwalające na precyzyjne nęcenie i powtarzalne połowy wzdłuż osi koryta. Spinningiści z sukcesami obławiają tutejsze pasy trzcinowisk, szukając okoni oraz mniejszych szczupaków czatujących przy betonowych umocnieniach. Uciąg wody jest znikomy, co pozwala na stosowanie najczulszych zestawów spławikowych i bardzo lekkich koszyków zanętowych. Spokojna okolica i łatwy dostęp do brzegów sprawia, że jest to chętnie wybierane miejsce na techniczne sesje spławikowe z dala od miejskiego zgiełku.', 'PZW Bydgoszcz');

