VALUES (70561, 'Nizinna Wielka', 'Uregulowana, kanałowa', 20.0, 2.2, 'Piasek i muł', 'Betonowe opaski', 'Leszcz, Płoć, Okoń', 'Kraina leszcza', true);

-- Spot 563: Kościelec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70562, 'Noteć - Kościelec (Płania)', 'notec-koscielec', 'RIVER', 52.7784986, 18.1530542, 'Kujawsko-Pomorskie', 'Inowrocław', 'Odcinek rzeki w Kościelcu charakteryzuje się wyrównanym nurtem i obecnością piaszczystych płani o głębokości dochodzącej do dwóch i pół metra. Rzeka płynie tu dostojnie przez tereny Kujaw, oferując wędkarzom twarde, piaszczyste dno z lokalnymi wymyciami gliniastymi pod brzegami. To strategiczne miejsce dla łowców jazi oraz kleni, które doskonale reagują na techniki spinningowe z użyciem mikro-woblerów. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia, celując w dorodne płocie oraz wyrośnięte liny żerujące w pobliżu brzegowej roślinności. Uciąg wody jest stabilny, co umożliwia precyzyjne nęcenie i utrzymywanie stad białorybu w polu łowienia przez wiele godzin. Dzięki sielskiemu krajobrazowi i obfitości ryb spokojnego żeru, łowisko to cieszy się dużą popularnością wśród lokalnych pasjonatów feedera klasycznego.', 'PZW Bydgoszcz');

