VALUES (70562, 'Nizinna Wielka', 'Szeroka płania, uregulowana', 25.0, 2.5, 'Piasek i glina', 'Trzcinowiska', 'Jaź, Płoć, Leszcz', 'Kraina leszcza', true);



-- Spot 564: Kłodzko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70563, 'Nysa Kłodzka - Kłodzko (Miejska)', 'nysa-klodzka-klodzko', 'RIVER', 50.4397728, 16.6578018, 'Dolnośląskie', 'Kłodzko', 'Nysa Kłodzka w Kłodzku to techniczne łowisko miejskie o charakterze górskim z licznymi progami i umocnieniami brzegowymi. Dno jest tu twarde, kamieniste, co sprzyja bytowaniu pstrągów potokowych oraz lipieni żerujących w rynnach pod murami obronnymi. Spinningiści z sukcesami obławiają rejony pod jazami, szukając kleni i pstrągów w turbulentnej, dobrze natlenionej wodzie. Uciąg rzeki jest tu zdecydowany, co wymaga od wędkarza umiejętnego prowadzenia przynęty w silnym nurcie głównym. Wędkarze muchowi chętnie wykorzystują płytkie bystrza powyżej mostów do łowienia lipieni na małe, suche muchy. Mimo zurbanizowanego otoczenia, rzeka zachowuje tu dużą rybność i zapewnia emocjonujące hole ryb reofilnych bezpośrednio z bulwarów.', 'PZW Wałbrzych');

