VALUES (70563, 'Górska', 'Uregulowana, progi', 25.0, 1.2, 'Kamieniste', 'Jazy, progi betonowe', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', 'Górskie - kraina pstrąga', false);

-- Spot 565: Ławica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70564, 'Nysa Kłodzka - Ławica (Dzika)', 'nysa-klodzka-lawica', 'RIVER', 50.4797713, 16.6644131, 'Dolnośląskie', 'Kłodzko', 'Odcinek w Ławicy charakteryzuje się naturalnym korytem rzeki górskiej z licznymi żwirowymi łachami i bystrzami. Nysa płynie tu dostojnie, żłobiąc głębokie doły pod wysokimi, skalistymi burtami brzegowymi na zewnętrznych łukach rzeki. To doskonałe łowisko dla pasjonatów spinningu celujących w pstrągi potokowe stacjonujące w cieniu zatopionych głazów i korzeni. Podłoże jest kamieniste z lokalnymi naniesieniami grubego żwiru, co stwarza idealne warunki dla lipieni i jelców. Uciąg rzeki jest tu żywy i skomplikowany przez liczne przeszkody terenowe, co wymaga dużej precyzji w podawaniu przynęty. Niska presja wędkarska w tym rejonie sprawia, że ryby żerują tu odważnie, czyniąc to miejsce bardzo atrakcyjnym.', 'PZW Wałbrzych');

