VALUES (70564, 'Górska', 'Naturalne bystrza', 20.0, 0.9, 'Kamień i żwir', 'Skaliste burty', 'Pstrąg potokowy, Lipień, Jelec', 'Kraina pstrąga', 'Kraina pstrąga', false);

-- Spot 566: Morzyszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70565, 'Nysa Kłodzka - Morzyszów (Przełom)', 'nysa-klodzka-morzyszow', 'RIVER', 50.5004959, 16.692146, 'Dolnośląskie', 'Bardo', 'Nysa Kłodzka w Morzyszowie to malowniczy odcinek wejściowy do Przełomu Bardzkiego o bardzo urozmaiconym, kamienistym dnie koryta. Rzeka tworzy tu głębokie rynny i warkocze prądowe, w których chętnie przebywają waleczne brzany oraz klenie. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając pstrągów potokowych żerujących na granicy głównego nurtu. Uciąg wody jest silny i zdecydowany, co wymaga stosowania dociążonych przynęt dla stabilnego prowadzenia w toni rzeki. Wędkarze muchowi cenią ten fragment rzeki za obfitość lipieni, które regularnie zbierają owady z powierzchni w płytkich bystrzach. Dziki charakter brzegów i krystalicznie czysta woda zapewniają wędkarzowi całkowitą izolację oraz szansę na kontakt z rekordową rybą.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70565, 'Górska', 'Przełom rzeki, kamienista', 22.0, 1.4, 'Kamieniste', 'Warkocze prądowe', 'Brzana, Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Kraina pstrąga', false);

-- Spot 567: Bardo (Przełom Bardzki)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70566, 'Nysa Kłodzka - Bardo (Górskie Bystrza)', 'nysa-klodzka-bardo', 'RIVER', 50.5042669, 16.7368999, 'Dolnośląskie', 'Bardo', 'Bardo to legendarne łowisko położone w sercu Przełomu Bardzkiego, gdzie rzeka przedziera się przez skaliste wzniesienia Sudetów. Dno jest tu ekstremalnie twarde, usiane dużymi głazami, co tworzy idealne stanowiska dla brzan oraz pstrągów potokowych. Spinningiści polują tu na okazy kleni, obławiając cienie i warkocze powstające za naturalnymi przeszkodami w nurcie rzeki. Uciąg wody jest bardzo silny i nieprzewidywalny, co czyni to miejsce wymagającym technicznie poligonem dla zaawansowanych wędkarzy. W okresach letnich bystrza pod Bardem są doskonałym miejscem do łowienia lipieni na nimfy oraz małe suche muchy. Doskonała infrastruktura i dogodny dostęp do brzegów w samym mieście ułatwiają organizację szybkich, ale emocjonujących wypraw wędkarskich.', 'PZW Wałbrzych');

