VALUES (70566, 'Górska', 'Przełomowa, bystra', 30.0, 1.0, 'Skaliste', 'Głazy, warkocze', 'Brzana, Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Kraina pstrąga', false);

-- Spot 568: Suszka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70567, 'Nysa Kłodzka - Suszka (Podgórska)', 'nysa-klodzka-suszka', 'RIVER', 50.5260978, 16.8251476, 'Dolnośląskie', 'Bardo', 'Odcinek w Suszce charakteryzuje się szerszym korytem rzeki i przejściem charakteru rzeki z górskiego na wybitnie podgórski. Nysa płynie tu spokojniej, tworząc rozległe żwirowe łachy i rynny o głębokości dochodzącej do półtora metra głębokości. To strategiczne miejsce dla łowców brzan i kleni, które grupują się w dobrze natlenionej wodzie środkowego nurtu. Podłoże jest piaszczysto-żwirowe z lokalnymi wymyciami gliniastymi, co sprzyja bytowaniu świnek oraz jelców żerujących na dnie. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia woblerów w poszukiwaniu szczupaków czatujących w pobliżu brzegowych nawisów traw. Niska presja wędkarska oraz malownicze otoczenie sprawiają, że jest to chętnie wybierane miejsce na relaksujące sesje spinningowe.', 'PZW Wałbrzych');

