-- Spot 569: Kamieniec Ząbkowicki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70568, 'Nysa Kłodzka - Kamieniec Ząbkowicki', 'nysa-klodzka-kamieniec-zabkowicki', 'RIVER', 50.5144553, 16.864097, 'Dolnośląskie', 'Ząbkowice Śląskie', 'Nysa Kłodzka w Kamieńcu Ząbkowickim to techniczne łowisko o urozmaiconym charakterze ze względu na pobliskie spiętrzenia i jazy. Woda poniżej progu jest doskonale natleniona, co przyciąga sandacze, okonie oraz wyrośnięte klenie rzeczne żerujące w nurcie. Dno jest tu twarde, kamienisto-żwirowe, z wyraźnie zaznaczonymi rynnami wymytymi przez silniejszy prąd wody poniżej elektrowni. Wędkarze gruntowi z sukcesami łowią tu dorodne brzany oraz świnki, wykorzystując metodę lekkiego feedera z dociążonym zestawem. Uciąg rzeki jest stabilny, ale zależy od pracy turbin, co wymusza na wędkarzach częstą korektę masy przynęt. Malownicze sąsiedztwo pałacu Marianny Orańskiej dodaje każdemu wędkowaniu w tym miejscu wyjątkowego, bardzo historycznego charakteru i oprawy.', 'PZW Wałbrzych');

