-- Spot 570: Byczeń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70569, 'Nysa Kłodzka - Byczeń (Podgórski Nurt)', 'nysa-klodzka-byczen', 'RIVER', 50.5178434, 16.9075229, 'Dolnośląskie', 'Kamieniec Ząbkowicki', 'Nysa Kłodzka w Byczniu to odcinek przejściowy między krainą pstrąga a rejonem wielkich zbiorników zaporowych kaskady Nysy. Koryto rzeki jest tu dość szerokie, o dnie usianym grubym żwirem i kamieniami, co sprzyja bytowaniu silnych brzan. Spinningiści z sukcesami polują tu na klenie, wykorzystując liczne warkocze prądowe powstające za naturalnymi przeszkodami w nurcie. Uciąg wody jest zdecydowany, co wymaga od wędkarza stosowania dociążonych zestawów gruntowych z krótkim przyponem. W rynnach o głębokości do półtora metra często stacjonują świnki, doskonale reagujące na systematyczne nęcenie drobnym pelletem. Miejsce to zapewnia ciszę oraz bardzo czystą wodę, co przekłada się na wysoką kondycję i waleczność tutejszych ryb.', 'PZW Wałbrzych');

