-- Spot 571: Paczków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70570, 'Nysa Kłodzka - Paczków (Węzeł)', 'nysa-klodzka-paczkow', 'RIVER', 50.4724408, 16.9953007, 'Opolskie', 'Paczków', 'Odcinek w Paczkowie to strategiczne łowisko położone pomiędzy zbiornikami Kozielno a Otmuchów, charakteryzujące się dużą dynamiką wody. Rzeka płynie tu uregulowanym korytem, żłobiąc dno o charakterze piaszczysto-żwirowym z wyraźnie zaznaczonymi rynnami przydennymi. To doskonałe stanowisko dla łowców drapieżników, szczególnie sandaczy migrujących okresowo między sąsiednimi akwenami zaporowymi. Wędkarze stacjonarni z sukcesami łowią tu dorodne brzany, wykorzystując metodę ciężkiego feedera w głównym nurcie rzeki. Pod filarami mostów woda wymyła głębokie doły, które są naturalną kryjówką dla dużych okoni oraz rzecznych szczupaków. Łatwy dostęp do brzegów oraz specyfika węzła między zbiornikami sprawiają, że rybostan jest tu wyjątkowo bogaty i zróżnicowany.', 'PZW Opole');

