-- Spot 572: Otmuchów (Poniżej Zapory)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70571, 'Nysa Kłodzka - Otmuchów (Zrzut)', 'nysa-klodzka-otmuchow-zrzut', 'RIVER', 50.4590685, 17.1499595, 'Opolskie', 'Otmuchów', 'Nysa Kłodzka poniżej zapory w Otmuchowie to jedno z najbardziej technicznych i rybnych łowisk w południowo-zachodniej Polsce. Woda wypływająca ze zbiornika jest silnie natleniona, co przyciąga rekordowe brzany oraz sandacze żerujące w turbulentnym nurcie. Dno jest tu twarde, kamieniste, usiane betonowymi elementami umocnień, co wymaga od spinningistów precyzyjnego prowadzenia przynęty. To strategiczne miejsce dla łowców okazowych kleni, które doskonale reagują na woblery typu crankbait podawane w warkocze prądowe. Uciąg wody jest uzależniony od zrzutów z elektrowni, co wymusza na wędkarzach częstą adaptację ciężaru zestawów gruntowych. Specyficzny mikroklimat poniżej tamy oraz obecność ryb trofealnych czynią ten odcinek obowiązkowym punktem dla zaawansowanych pasjonatów rzeki.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70571, 'Nizinna Wielka', 'Techniczna, przy zaporska', 40.0, 2.5, 'Beton i kamień', 'Zrzut wody, elektrownia', 'Sandacz, Brzana, Kleń', 'Kraina leszcza', 'Odcinek specjalny (okresowo)', false);

-- Spot 573: Lasocice (Poniżej Zbiornika Nyskiego)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70572, 'Nysa Kłodzka - Lasocice (Szeroka)', 'nysa-klodzka-lasocice', 'RIVER', 50.5443377, 17.4754364, 'Opolskie', 'Nysa', 'Odcinek w Lasocicach znajduje się poniżej zbiornika Nyskiego, gdzie rzeka przybiera charakter dojrzałej, szerokiej arterii nizinno-podgórskiej. Koryto posiada tu piaszczysto-żwirowe dno z wyraźnymi uskokami, które stanowią bankowe stanowiska dla sandaczy żerujących o zmierzchu. Wędkarze gruntowi chętnie nęcą tutejsze płanie, licząc na brania rekordowych leszczy oraz dorodnych cert wchodzących z dołu rzeki. Spinningiści z sukcesami obławiają podmyte brzegi porośnięte wikliną, szukając szczupaków czatujących w cieniu roślinności wynurzonej. Uciąg rzeki jest tu stabilny, co pozwala na komfortowe operowanie zestawami spinningowymi oraz precyzyjne nęcenie pola łowienia. Szerokie koryto i liczne przeszkody w toni sprawiają, że ryby mają tu doskonałe warunki do wzrostu i osiągania imponujących rozmiarów.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70572, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 45.0, 2.2, 'Piasek i żwir', 'Rynny prądowe', 'Sandacz, Leszcz, Certa', 'Kraina leszcza', 'Brak', true);

-- Spot 574: Sidzina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70573, 'Nysa Kłodzka - Sidzina (Meandry)', 'nysa-klodzka-sidzina', 'RIVER', 50.5721719, 17.4714538, 'Opolskie', 'Nysa', 'Nysa Kłodzka w Sidzinie to rzeka wijąca się malowniczo wśród pól, zachowująca swój podgórski charakter dzięki żwirowemu podłożu. Koryto tworzy tu liczne meandry z głębokimi rynnami na zewnętrznych łukach, które są bezpieczną ostoją dla brzan i świnek. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia woblerów w poszukiwaniu boleni patrolujących krawędzie nurtu głównego. Woda zachowuje wysoką przejrzystość, co wymusza na wędkarzu zachowanie dużej ostrożności i stosowanie przyponów z fluorocarbonu. Wędkarze stacjonarni z sukcesami stosują tu metodę bolonki, puszczając zestaw na długim dystansie wzdłuż żwirowych przykos. Niska presja wędkarska w tym rejonie oraz naturalny charakter brzegów gwarantuje spokój oraz szansę na kontakt z bardzo dziką rybą.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70573, 'Nizinna Wielka', 'Meandrująca, naturalna', 38.0, 1.6, 'Żwir i piasek', 'Głębokie rynny', 'Brzana, Boleń, Świnka', 'Kraina leszcza', 'Brak', false);



-- Spot 575: Malerzowice Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70574, 'Nysa Kłodzka - Malerzowice Wielkie', 'nysa-klodzka-malerzowice', 'RIVER', 50.5991648, 17.4672938, 'Opolskie', 'Nysa', 'Nysa Kłodzka w Malerzowicach Wielkich charakteryzuje się szerokim korytem i wyraźnie zaznaczoną rynną główną o piaszczysto-żwirowym dnie. Rzeka płynie tu stabilnie, tworząc techniczne stanowiska pod wysokimi burtami brzegowymi, które skrywają wyrośnięte brzany. To strategiczne miejsce dla spinningistów szukających sandaczy czatujących w głębszych dołkach na krawędzi nurtu. Wędkarze gruntowi z sukcesami łowią tu dorodne leszcze, wykorzystując metodę feedera klasycznego z dociążonym zestawem. Uciąg rzeki jest zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upadów. Malowniczy krajobraz i stosunkowo niska presja wędkarska sprawiają, że jest to chętnie wybierane miejsce na całodniowe sesje rzeczne.', 'PZW Opole');

