VALUES (70574, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 42.0, 2.0, 'Piasek i żwir', 'Rynny prądowe', 'Sandacz, Brzana, Leszcz', 'Kraina leszcza', true);

-- Spot 576: Krasna Góra
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70575, 'Nysa Kłodzka - Krasna Góra (Zakola)', 'nysa-klodzka-krasna-gora', 'RIVER', 50.6269594, 17.4777202, 'Opolskie', 'Niemodlin', 'Odcinek w Krasnej Górze charakteryzuje się licznymi naturalnymi meandrami i obecnością piaszczystych przykos wychodzących daleko w nurt. Nysa żłobi tu dno o zróżnicowanym charakterze, tworząc głębokie jamy na zewnętrznych łukach koryta idealne dla sumów. To doskonałe łowisko dla spinningistów polujących na bolenie patrolujące turbulentną wodę na styku nurtu głównego i zastoisk. Wędkarze stacjonarni chętnie nęcą tutejsze płanie żwirowe, celując w waleczne brzany oraz dorodne świnki. Uciąg wody jest tu żywy i wymaga od wędkarza umiejętnego czytania prądów dla poprawnej prezentacji przynęty. Dzikie brzegi porośnięte gęstą roślinnością zapewniają intymną atmosferę i szansę na kontakt z niewypłoszoną rybą.', 'PZW Opole');

