-- Spot 577: Osiek Grodkowski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70576, 'Nysa Kłodzka - Osiek Grodkowski', 'nysa-klodzka-osiek-grodkowski', 'RIVER', 50.7040264, 17.5014687, 'Opolskie', 'Grodków', 'Noteć w Osieku Grodkowskim to odcinek o wyrównanym nurcie i piaszczysto-żwirowym podłożu koryta z nielicznymi podwodnymi przeszkodami. Rzeka płynie tu dostojnie, oferując wędkarzom dogodne płanie do letnich zasiadek z lekkim gruntem lub spławikiem. To strategiczne miejsce dla łowców okazowych kleni, które doskonale reagują na małe woblery prowadzone wzdłuż brzegowych wiklin. Woda zachowuje tu umiarkowaną przejrzystość, co sprzyja aktywności szczupaków czatujących w pobliżu kęp roślinności zanurzonej. Uciąg rzeki pozwala na precyzyjne nęcenie punktowe i utrzymywanie stad białorybu w polu łowienia przez wiele godzin. Dogodny dojazd przez polne drogi sprawia, że jest to chętnie wybierane miejsce na weekendowe wyprawy spinningowe.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70576, 'Nizinna Wielka', 'Szeroka, nurt łagodny', 40.0, 1.5, 'Piasek i żwir', 'Podmyte korzenie', 'Kleń, Szczupak, Leszcz', 'Kraina leszcza', false);

-- Spot 578: Michałów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70577, 'Nysa Kłodzka - Michałów (Przykosy)', 'nysa-klodzka-michalow', 'RIVER', 50.7313156, 17.5269125, 'Opolskie', 'Lewin Brzeski', 'Nysa Kłodzka w Michałowie słynie z rozległych piaszczystych przykos i warkoczy prądowych idealnych do łowienia ryb reofilnych. Podłoże jest tu twarde, piaszczyste, co stwarza doskonałe warunki tlenowe dla żerujących brzan oraz cert rzecznych. Spinningiści z sukcesami polują tutaj na bolenie, wykorzystując technikę szybkiego prowadzenia przynęty w powierzchniowych partiach wody. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych przy metodzie feederowej. Podmyte brzegi z korzeniami drzew stanowią bankowe kryjówki dla wyrośniętych okoni oraz mniejszych szczupaków. Miejsce to zapewnia doskonały odpoczynek w sielskim krajobrazie przy jednoczesnej szansie na rekordowe wyniki wędkarskie.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70577, 'Nizinna Wielka', 'Szeroka, piaszczysta', 48.0, 1.4, 'Piaszczyste', 'Przykosy piaszczyste', 'Boleń, Brzana, Certa', 'Kraina leszcza', true);

-- Spot 579: Kantorowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70578, 'Nysa Kłodzka - Kantorowice (Starorzecza)', 'nysa-klodzka-kantorowice', 'RIVER', 50.7351461, 17.5700293, 'Opolskie', 'Lewin Brzeski', 'Odcinek w Kantorowicach charakteryzuje się obecnością licznych starorzeczy i kanałów bocznych łączących się z korytem głównym rzeki. Rzeka płynie tu spokojnie, żłobiąc dno o charakterze piaszczysto-mulistym z bogatą roślinnością wynurzoną przy brzegach. To wymarzone miejsce dla łowców szczupaków, którzy obławiają zaciszne zatoki i pasy trzcinowisk przy użyciu przynęt powierzchniowych. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne liny oraz rzeczne leszcze. Uciąg wody jest zróżnicowany, co pozwala na eksperymentowanie z wieloma technikami połowu w zależności od aktywności ryb. Dzięki unikalnej strukturze koryta, odcinek ten oferuje jedne z najbardziej urozmaiconych stanowisk wędkarskich w całym regionie.', 'PZW Opole');

