VALUES (70578, 'Nizinna Wielka', 'Szeroka, liczne zatoki', 50.0, 2.2, 'Piasek i muł', 'Starorzecza, zatoki', 'Szczupak, Lin, Leszcz', 'Kraina leszcza', true);

-- Spot 580: Lewin Brzeski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70579, 'Nysa Kłodzka - Lewin Brzeski (Mosty)', 'nysa-klodzka-lewin-brzeski', 'RIVER', 50.7482941, 17.6083726, 'Opolskie', 'Lewin Brzeski', 'Lewin Brzeski to techniczne łowisko o uregulowanym charakterze miejskim z głębokimi rynnami wymytymi pod filarami mostów. Woda poniżej miejskich spiętrzeń jest doskonale natleniona, co przyciąga sandacze oraz duże okonie żerujące na uklejach. To strategiczne miejsce dla spinningistów, którzy wykorzystują betonowe umocnienia brzegowe do precyzyjnego prowadzenia przynęt w nurcie. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz leszcze, wykorzystując metodę bata lub tyczki przy bulwarach. Uciąg rzeki stabilizuje się w rejonie miejskim, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w łowisku. Dobra infrastruktura i łatwy dostęp do wody czynią to miejsce popularnym punktem spotkań wędkarzy z całego Opolszczyzny.', 'PZW Opole');

