VALUES (70579, 'Nizinna Wielka', 'Uregulowana miejska', 55.0, 2.8, 'Twardy piasek', 'Mosty, bulwary', 'Sandacz, Płoć, Leszcz', 'Kraina leszcza', true);

-- Spot 581: Lewin Brzeski (Odcinek Dolny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70580, 'Nysa Kłodzka - Lewin Brzeski (Płonie)', 'nysa-klodzka-lewin-dolny', 'RIVER', 50.7521863, 17.6591339, 'Opolskie', 'Lewin Brzeski', 'Nysa Kłodzka poniżej Lewina Brzeskiego to szeroka rzeka nizinna o bardzo ustabilizowanym i leniwym nurcie. Dno jest tu piaszczysto-muliste, co sprzyja bytowaniu dużych stad leszczy oraz wyrośniętych krąpi żerujących wzdłuż osi koryta. To idealne miejsce dla wędkarzy spławikowych, którzy cenią sobie precyzyjne nęcenie tyczką w pobliżu brzegowych trzcinowisk. Spinningiści z sukcesami obławiają tutejsze spowolnienia, szukając szczupaków czatujących w cieniu roślinności zanurzonej. Uciąg wody jest znikomy, co pozwala na stosowanie najdelikatniejszych technik spławikowych z czułymi sygnalizatorami brania. Dogodny dostęp do wody oraz bogata populacja białorybu czynią ten odcinek doskonałym punktem na relaksujące, całodniowe zasiadki.', 'PZW Opole');

