-- Spot 582: Wronów (Przedujście do Odry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70581, 'Nysa Kłodzka - Wronów (Ujście)', 'nysa-klodzka-wronow', 'RIVER', 50.789068, 17.6770383, 'Opolskie', 'Brzeg', 'Odcinek we Wronowie to ostatnie kilometry biegu Nysy Kłodzkiej przed jej spektakularnym połączeniem z Odrą. Rzeka żłobi tu głębokie rynny, w których chętnie stacjonują sandacze oraz duże sumy migrujące z głównego nurtu Odry. To strategiczne miejsce dla spinningistów polujących na bolenie, które agresywnie żerują na stadach uklei przy krawędzi nurtu. Dno jest piaszczysto-żwirowe, co zapewnia rybom doskonałe warunki tlenowe i obfitość naturalnego pokarmu dennego. Wędkarze gruntowi z sukcesami łowią tu dorodne brzany oraz leszcze, wykorzystując dociążone zestawy odporne na zmienne prądy wody. Bliskość ujścia sprawia, że wędkarz może tu liczyć na kontakt z rekordowymi okazami ryb nizinnych praktycznie przez cały sezon.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70581, 'Nizinna Wielka', 'Szeroka, nurt żywy', 60.0, 3.5, 'Piasek i żwir', 'Rynny prądowe', 'Sandacz, Brzana, Sum', 'Kraina leszcza', true);

-- Spot 583: Długopole-Zdrój
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70582, 'Nysa Kłodzka - Długopole-Zdrój (Górska)', 'nysa-klodzka-dlugopole-zdroj', 'RIVER', 50.2429833, 16.6319232, 'Dolnośląskie', 'Bystrzyca Kłodzka', 'Nysa Kłodzka w Długopolu-Zdroju to klasyczna rzeka górska o krystalicznie czystej, zimnej wodzie i kamienistym dnie. Koryto jest tu usiane dużymi głazami, które tworzą idealne stanowiska dla pstrągów potokowych i lipieni żerujących w bystrzach. To doskonałe łowisko dla muszkarzy, którzy cenią sobie możliwość brodzenia i łowienia techniką nimfy w rynnach prądowych. Spinningiści z sukcesami polują tutaj na waleczne klenie, wykorzystując małe woblery i obrotówki podawane pod przeciwległy brzeg. Uciąg rzeki jest bardzo silny i nieprzewidywalny, co wymaga od wędkarza pełnej koncentracji i odpowiedniego obuwia do brodzenia. Malownicze położenie w uzdrowiskowej części doliny nadaje każdemu wędkowaniu w tym miejscu wyjątkowego, bardzo spokojnego charakteru.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70582, 'Górska', 'Bystra, kamienista', 15.0, 0.8, 'Kamienie i głazy', 'Warkocze prądowe', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 584: Gorzanów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70583, 'Nysa Kłodzka - Gorzanów (Meandry)', 'nysa-klodzka-gorzanow', 'RIVER', 50.3464305, 16.6350668, 'Dolnośląskie', 'Bystrzyca Kłodzka', 'Odcinek w Gorzanowie charakteryzuje się naturalnym, meandrującym korytem o urozmaiconej rzeźbie dna z piaszczysto-żwirowymi łachami. Rzeka tworzy tu liczne zakola z głębokimi rynnami pod wysokimi burtami, które są bankowymi kryjówkami dla wyrośniętych kleni. To wymarzone miejsce dla spinningistów, którzy szukają pstrągów potokowych stacjonujących w cieniu zatopionych korzeni i nadrzecznych wierzb. Uciąg wody jest zróżnicowany, co pozwala na eksperymentowanie z wieloma technikami połowu w zależności od stanu wody. W płytkich bystrzach powyżej mostów często można zaobserwować żerujące lipienie, które doskonale reagują na małe suche muchy. Niska presja wędkarska sprawia, że ryby są tu mniej płochliwe, co ułatwia skuteczne polowanie na okazowe egzemplarze.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70583, 'Górska', 'Meandrująca, naturalna', 18.0, 1.0, 'Żwir i kamień', 'Podmyte brzegi', 'Pstrąg potokowy, Kleń, Lipień', 'Kraina pstrąga', false);

-- Spot 585: Roztoki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70584, 'Nysa Kłodzka - Roztoki (Górny Bieg)', 'nysa-klodzka-roztoki', 'RIVER', 50.1795201, 16.6688942, 'Dolnośląskie', 'Międzylesie', 'Nysa Kłodzka w Roztokach to odcinek o wybitnie górskim charakterze, płynący wąskim korytem wśród sudeckich krajobrazów. Woda jest tu wyjątkowo zimna i dobrze natleniona, co sprzyja bytności pstrąga potokowego w jego najbardziej dzikiej formie. Podłoże składa się głównie z otoczaków i żwiru, tworząc liczne mikro-rynny i płytkie przelewy idealne do łowienia na nimfę. To łowisko wymagające technicznie, gdzie kluczem do sukcesu jest dyskretne podejście do wody i precyzyjne podanie przynęty. Uciąg rzeki jest żywy, ale stabilny, co pozwala na naturalną prezentację muszek w mniejszych warkoczach prądowych. Miejsce to zapewnia absolutny spokój oraz szansę na kontakt z niewypłoszoną rybą w otoczeniu gęstych nadrzecznych zagajników.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70584, 'Górska', 'Wąska, bystra', 12.0, 0.6, 'Otoczaki i żwir', 'Mikro-rynny', 'Pstrąg potokowy, Głowacz, Kiełb', 'Kraina pstrąga', false);

-- Spot 586: Długopole Dolne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70585, 'Nysa Kłodzka - Długopole Dolne (Bystrza)', 'nysa-klodzka-dlugopole-dolne', 'RIVER', 50.2691752, 16.6432364, 'Dolnośląskie', 'Bystrzyca Kłodzka', 'Odcinek w Długopolu Dolnym to techniczne łowisko górskie słynące z licznych bystrz i głębokich rynien wymytych w twardym podłożu. Rzeka płynie tu dynamicznie, żłobiąc dno kamienisto-żwirowe, co stwarza doskonałe warunki tlenowe dla lipieni i pstrągów. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając kleni żerujących w pobliżu nurtu głównego. Uciąg jest silny, co wymusza stosowanie nieco cięższych przynęt w celu sprowadzenia ich w pobliże dna koryta. Wędkarze muchowi chętnie wykorzystują spowolnienia nurtu poniżej bystrz, gdzie ryby grupują się w poszukiwaniu spływającego z prądem pokarmu. Dzięki naturalnej rzeźbie terenu, odcinek ten oferuje jedne z najbardziej malowniczych stanowisk wędkarskich w całej Kotlinie Kłodzkiej.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70585, 'Górska', 'Nurt żywy, bystrza', 16.0, 0.9, 'Kamień i żwir', 'Rynny prądowe', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);


-- Spot 587: Bystrzyca Kłodzka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70586, 'Nysa Kłodzka - Bystrzyca Kłodzka (Miejskie Bystrza)', 'nysa-klodzka-bystrzyca-klodzka', 'RIVER', 50.3010938, 16.6575853, 'Dolnośląskie', 'Bystrzyca Kłodzka', 'Nysa Kłodzka w Bystrzycy Kłodzkiej to dynamiczne łowisko górskie o krystalicznej wodzie i bardzo twardym, kamienistym dnie. Rzeka płynie tu w uregulowanym korycie, tworząc liczne warkocze i natlenione rynny pod historycznymi murami miasta. To doskonałe miejsce dla spinningistów polujących na pstrągi potokowe oraz klenie przy użyciu małych woblerów i obrotówek. Wędkarze muchowi chętnie wykorzystują tutejsze progi do łowienia lipieni metodą krótkiej nimfy w głębszych partiach nurtu. Uciąg jest silny i zdecydowany, co wymaga od wędkarza dużej precyzji w prowadzeniu przynęty wzdłuż brzegowych umocnień. Bliskość miejskiej infrastruktury sprawia, że jest to chętnie wybierane miejsce na szybkie, ale niezwykle emocjonujące sesje spinningowe.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70586, 'Górska', 'Uregulowana, nurt żywy', 18.0, 1.0, 'Kamieniste', 'Progi, warkocze', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', 'Górskie - kraina pstrąga', false);

-- Spot 588: Długopole Górne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70587, 'Nysa Kłodzka - Długopole Górne (Górskie Płanie)', 'nysa-klodzka-dlugopole-gorne', 'RIVER', 50.2062373, 16.6625337, 'Dolnośląskie', 'Międzylesie', 'Odcinek w Długopolu Górnym charakteryzuje się naturalnym korytem o umiarkowanym spadku i dnie usianym żwirem oraz otoczakami. Rzeka tworzy tu malownicze zakola z głębszymi rynnami na zewnętrznych łukach, które stanowią bankowe kryjówki dla pstrągów. To wymarzone miejsce dla muszkarzy celujących w lipienie zbierające suchą muchę z powierzchni krystalicznie czystej wody. Uciąg wody jest tu zróżnicowany, co pozwala na eksperymentowanie z wieloma technikami połowu w zależności od stanu rzeki. Brzegi są niskie i łatwo dostępne, co ułatwia bezpieczne brodzenie bez konieczności używania wysokich spodniobutów. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz doskonałe warunki do technicznego wędkarstwa muchowego w surowym krajobrazie.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70587, 'Górska', 'Naturalne bystrza', 15.0, 0.8, 'Żwir i otoczaki', 'Piaszczyste łachy', 'Pstrąg potokowy, Lipień, Jelec', 'Kraina pstrąga', 'Kraina pstrąga', false);

-- Spot 589: Smreczyna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70588, 'Nysa Kłodzka - Smreczyna (Źródliskowa)', 'nysa-klodzka-smreczyna', 'RIVER', 50.1287129, 16.6685879, 'Dolnośląskie', 'Międzylesie', 'Nysa Kłodzka w Smreczynie to niemal źródliskowy odcinek rzeki o charakterze wąskiej, górskiej strugi wijącej się wśród łąk. Podłoże jest tu wybitnie kamieniste, a woda zachowuje niską temperaturę nawet podczas upalnych letnich miesięcy. To idealne miejsce dla pasjonatów mikro-jigingu oraz ultralekkiego spinningu szukających pstrągów w niewielkich dołkach pod burtami. Ze względu na minimalną szerokość koryta, kluczowe dla sukcesu jest zachowanie absolutnej dyskrecji podczas podejścia do wody. Uciąg jest żywy, tworząc liczne mikro-warkocze za kamieniami, które są naturalną bazą pokarmową dla ryb łososiowatych. To dzikie i rzadko odwiedzane łowisko nagradza wytrwałych wędkarzy kontaktem z pierwotną naturą w najbardziej południowej części Kotliny Kłodzkiej.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70588, 'Górska', 'Wąska struga górka', 6.0, 0.5, 'Kamieniste', 'Zatory z głazów', 'Pstrąg potokowy, Głowacz, Kiełb', 'Kraina pstrąga', 'Kraina pstrąga', false);


-- Spot 590: Otmuchów (Szeroka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70589, 'Nysa Kłodzka - Otmuchów (Poniżej Zapory)', 'nysa-klodzka-otmuchow-dolna', 'RIVER', 50.456442, 17.192303, 'Opolskie', 'Otmuchów', 'Odcinek rzeki poniżej zbiornika w Otmuchowie to potężna arteria o szerokim korycie i silnie natlenionej wodzie. Dno jest tu twarde, piaszczysto-żwirowe, co sprzyja aktywności rekordowych brzan żerujących w głównym nurcie rzeki. Spinningiści z sukcesami polują tu na sandacze, wykorzystując technikę ciężkiego opadu w głębokich rynnach wymytych przez zrzuty wody. Uciąg jest uzależniony od pracy elektrowni, co wymusza na wędkarzach częstą korektę masy stosowanych koszyków zanętowych. Wędkarze stacjonarni chętnie nęcą tutejsze płanie żwirowe, celując w wyrośnięte certy oraz dorodne leszczowe stada wchodzące z prądem. To wymagające technicznie łowisko nagradza wytrwałych wędkarzy rybami życia, oferując jednocześnie doskonałe warunki do dalekich rzutów.', 'PZW Opole');

