VALUES (70589, 'Nizinna Wielka', 'Szeroka, nurt techniczny', 45.0, 2.8, 'Piasek i żwir', 'Opaski betonowe', 'Brzana, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 591: Otmuchów (Cofka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70590, 'Nysa Kłodzka - Otmuchów (Wlot)', 'nysa-klodzka-otmuchow-cofka', 'RIVER', 50.4736964, 17.0597442, 'Opolskie', 'Paczków', 'Cofka zbiornika Otmuchów to strategiczne łowisko o zmiennej dynamice wody, uzależnionej od aktualnego poziomu retencji akwenu. Rzeka rozlewa się tu szerzej, żłobiąc piaszczyste dno z licznymi osadami, które przyciągają duże stada leszczy oraz krąpi. To doskonałe miejsce dla łowców drapieżników, szczególnie sandaczy i sumów migrujących okresowo między rzeką a jeziorem zaporowym. Wędkarze gruntowi z sukcesami łowią tu dorodne płocie, wykorzystując systematyczne nęcenie na krawędzi głównego koryta. Uciąg wody jest łagodny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Niska presja wędkarska oraz unikalna specyfika miejsca styku rzeki z jeziorem sprawiają, że rybostan jest tu wyjątkowo zróżnicowany.', 'PZW Opole');

