VALUES (70590, 'Nizinna Wielka', 'Cofka zbiornika', 100.0, 3.5, 'Piasek i muł', 'Zalane płanie', 'Sandacz, Leszcz, Sum', 'Kraina leszcza', true);

-- Spot 592: Mrokocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70591, 'Nysa Kłodzka - Mrokocin (Meandry)', 'nysa-klodzka-mrokocin', 'RIVER', 50.4852049, 16.9542891, 'Dolnośląskie', 'Paczków', 'Nysa Kłodzka w Mrokocinie to odcinek o wybitnie podgórskim charakterze z naturalnym, silnie meandrującym korytem rzecznym. Rzeka tworzy tu głębokie rynny pod wysokimi, gliniastymi burtami, które stanowią bezpieczną ostoję dla brzan oraz wyrośniętych kleni. Podłoże jest żwirowo-kamieniste, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając pstrągów potokowych w pobliżu zatopionych korzeni drzew. Uciąg jest zdecydowany i żywy, co wymaga od wędkarza umiejętnego czytania prądów oraz wirów wstecznych dla poprawnej prezentacji. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z dziką rybą w otoczeniu sielskiego, nadnyskiego krajobrazu.', 'PZW Wałbrzych');

