-- Spot 593: Nysa (Cofka Jeziora Nyskiego)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70592, 'Nysa Kłodzka - Nysa (Wlot)', 'nysa-klodzka-nysa-wlot', 'RIVER', 50.4629383, 17.3058762, 'Opolskie', 'Nysa', 'Nysa Kłodzka w samej Nysie, tuż przed wlotem do Jeziora Nyskiego, to łowisko o bardzo zmiennej dynamice wody. Dno jest tu piaszczysto-żwirowe z licznymi rynnami wymytymi przez nurt rzeki wchodzący w spokojniejsze plosy zbiornika. To strategiczne miejsce dla spinningistów szukających sandaczy oraz dużych okoni migrujących okresowo z jeziora w górę rzeki. Wędkarze stacjonarni z powodzeniem łowią tu dorodne leszcze oraz płocie, wykorzystując metodę feedera klasycznego na krawędzi nurtu. Uciąg zależy od poziomu retencji zbiornika, co wymusza na wędkarzu częstą adaptację gramatury stosowanych obciążeń zestawu. Miejskie nabrzeża zapewniają bardzo komfortowy dostęp do wody, czyniąc to miejsce popularnym punktem spotkań lokalnych pasjonatów wędkarstwa.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70592, 'Nizinna Wielka', 'Cofka zbiornika, szeroka', 80.0, 3.0, 'Piasek i żwir', 'Rynny wlotowe', 'Sandacz, Okoń, Leszcz', 'Kraina leszcza', true);

-- Spot 594: Piątkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70593, 'Nysa Kłodzka - Piątkowice (Przykosy)', 'nysa-klodzka-piatkowice', 'RIVER', 50.4981871, 17.4526357, 'Opolskie', 'Nysa', 'Odcinek w Piątkowicach charakteryzuje się szerokim korytem i obecnością piaszczystych przykos wychodzących daleko w główny nurt rzeki. Podłoże jest tu twarde, piaszczyste, co stwarza doskonałe warunki tlenowe dla walecznych brzan oraz rzecznych boleni. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając kleni żerujących na uklejach pod nawisami brzegowej roślinności. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w dorodne leszcze oraz rzadziej spotykane certy wchodzące z dolnych odcinków. Uciąg wody jest tu stabilny i zdecydowany, co sprzyja naturalnej prezentacji przynęty wzdłuż głębokich rynien przydennych. Malowniczy krajobraz doliny rzeki oraz niska presja wędkarska gwarantują spokój podczas całodniowych sesji z wędką w ręku.', 'PZW Opole');

