VALUES (70593, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 45.0, 1.8, 'Piaszczyste', 'Przykosy piaszczyste', 'Brzana, Boleń, Leszcz', 'Kraina leszcza', true);

-- Spot 595: Stobrawa (UJŚCIE DO ODRY)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70594, 'Nysa Kłodzka - Stobrawa (Ujście)', 'nysa-klodzka-ujscie-stobrawa', 'RIVER', 50.8134012, 17.6573166, 'Opolskie', 'Brzeg', 'Ujście Nysy Kłodzkiej do Odry w Stobrawie to jedno z najbardziej spektakularnych i rybnych miejsc na mapie całego województwa opolskiego. Zderzenie dwóch potężnych rzek tworzy unikalne warunki pokarmowe, które przyciągają rekordowe sumy, sandacze oraz bolenie. Dno jest tu mocno urozmaicone, piaszczysto-kamieniste z głębokimi dołami wymytymi przez krzyżujące się nurty obu wielkich cieków. To wymarzone stanowisko dla spinningistów, którzy obławiają strefę styku wód w poszukiwaniu drapieżników żerujących w turbulentnej wodzie. Wędkarze stacjonarni z sukcesami łowią tu okazałe brzany oraz rekordowe leszcze, wykorzystując bardzo ciężkie zestawy gruntowe odporne na silny uciąg. To wymagające technicznie łowisko nagradza wytrwałych wędkarzy rybami życia, stanowiąc godne zwieńczenie całego biegu rzeki.', 'PZW Opole');

