-- Spot 596: Przyłęk
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70595, 'Nysa Kłodzka - Przyłęk (Bystrza)', 'nysa-klodzka-przylek', 'RIVER', 50.5108429, 16.7782278, 'Dolnośląskie', 'Bardo', 'Nysa Kłodzka w Przyłęku to techniczne łowisko górskie położone poniżej Barda, gdzie rzeka zachowuje swój bystry i nieprzewidywalny charakter. Koryto jest tu usiane dużymi otoczakami i głazami, które tworzą idealne stanowiska dla pstrągów potokowych oraz walecznych brzan. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając kleni żerujących w cieniu podwodnych przeszkód terenowych. Woda jest wyjątkowo czysta i dobrze natleniona, co przekłada się na wysoką aktywność ryb nawet podczas letnich upałów. Wędkarze muchowi chętnie wykorzystują płytkie bystrza do łowienia lipieni metodą suchej muchy na krawędziach głównego nurtu. Naturalna rzeźba terenu oraz surowy krajobraz Sudetów sprawiają, że każda wyprawa w to miejsce ma swój niepowtarzalny urok.', 'PZW Wałbrzych');

