-- Spot 597: Nysa (Poniżej Zapory)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70596, 'Nysa Kłodzka - Nysa (Zrzut Miejski)', 'nysa-klodzka-nysa-miasto-zrzut', 'RIVER', 50.4811923, 17.3377361, 'Opolskie', 'Nysa', 'Odcinek rzeki w samej Nysie poniżej zapory zbiornika to legendarne łowisko słynące z obecności rekordowych sandaczy i sumów. Woda wypływająca z turbin jest silnie natleniona i niesie duże ilości pokarmu, co aktywuje drapieżniki do bardzo intensywnego żerowania. Dno jest tu twarde, kamienisto-betonowe, usiane licznymi uskokami stanowiącymi bankowe stanowiska dla ryb stacjonujących w nurcie. To strategiczne miejsce dla spinningistów, którzy wykorzystują warkocze prądowe do precyzyjnego prowadzenia ciężkich gumowych przynęt blisko twardego dna. Wędkarze gruntowi z sukcesami łowią tu dorodne brzany oraz okazowe płocie, wykorzystując systematyczne nęcenie w głębokich rynnach przydennych. Uciąg zależy od aktualnej pracy elektrowni, co wymusza na wędkarzach stałą czujność i częstą korektę masy stosowanych zestawów.', 'PZW Opole');

