-- Spot 598: Złotogłowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70597, 'Nysa Kłodzka - Złotogłowice', 'nysa-klodzka-zlotoglowice', 'RIVER', 50.4855203, 17.3800471, 'Opolskie', 'Nysa', 'Nysa Kłodzka w Złotogłowicach to odcinek o charakterze podgórsko-nizinnym z piaszczysto-żwirowym dnem i licznymi podmyłymi burtami. Rzeka płynie tu szerokim korytem, żłobiąc głębokie rynny na zewnętrznych łukach meandrów, które skrywają wyrośnięte leszczowe stada. To doskonałe łowisko dla spinningistów szukających okoni oraz szczupaków stacjonujących w pobliżu nadrzecznych nawisów traw i wiklin. Uciąg jest stabilny i zdecydowany, co sprzyja naturalnej prezentacji przynęty przy użyciu techniki bolonki lub feedera klasycznego. Woda zachowuje umiarkowaną przejrzystość, co wymaga od wędkarza zachowania dyskrecji i stosowania cienkich przyponów z fluorocarbonu. Spokojna okolica oraz bogata populacja ryb spokojnego żeru czynią ten fragment rzeki bardzo atrakcyjnym punktem na mapie regionu.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70597, 'Nizinna Wielka', 'Meandrująca, szeroka', 35.0, 1.8, 'Piasek i żwir', 'Podmyte brzegi', 'Leszcz, Okoń, Płoć', 'Kraina leszcza', false);



-- Spot 599: Pisary
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70598, 'Nysa Kłodzka - Pisary (Źródliskowa)', 'nysa-klodzka-pisary', 'RIVER', 50.13094, 16.73484, 'Dolnośląskie', 'Międzylesie', 'Nysa Kłodzka w Pisarach to dziki, górski potok płynący przez malownicze tereny u podnóża Masywu Śnieżnika. Woda jest tu krystalicznie czysta, lodowata i niezwykle bystra, co tworzy idealne warunki dla pstrąga potokowego. Dno usiane jest grubymi otoczakami i głazami, które wymuszają na wędkarzu technikę precyzyjnego rzutu pod prąd. To łowisko dla purystów, wymagające absolutnej ciszy i umiejętności cichego skradania się wzdłuż zarośniętych brzegów. Wąskie koryto rzeki sprawia, że każdy większy pstrąg jest tu prawdziwym trofeum wypracowanym w trudnych warunkach. Niska presja wędkarska gwarantuje kontakt z rybami, które rzadko widują sztuczne przynęty spinningowe czy muchowe.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70598, 'Górska', 'Wąska, bardzo bystra', 5.0, 0.5, 'Głazy i otoczaki', 'Naturalne progi', 'Pstrąg potokowy, Głowacz', 'Kraina pstrąga', 'Górskie - kraina pstrąga', false);

-- Spot 600: Potoczek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70599, 'Nysa Kłodzka - Potoczek (Górna Struga)', 'nysa-klodzka-potoczek', 'RIVER', 50.15636, 16.74985, 'Dolnośląskie', 'Międzylesie', 'W rejonie miejscowości Potoczek rzeka ma charakter kameralnej, górskiej strugi o bardzo dużym spadku koryta. Nurt przecina tu liczne naturalne zatory z gałęzi i skał, tworząc głębokie rynny z silnie natlenioną wodą. Jest to królestwo pstrąga potokowego oraz głowacza, które znajdują tu schronienie w cieniu nadrzecznych olszyn. Ze względu na niewielką szerokość rzeki, kluczowe jest stosowanie krótkich wędzisk pozwalających na techniczne operowanie pod nawisami. Podłoże jest stabilne, kamienisto-żwirowe, co sprzyja bezpiecznemu brodzeniu podczas poszukiwania kolejnych stanowisk ryb. Miejsce to zachwyca swoją surowością i oferuje wędkarzowi powrót do korzeni wędkarstwa pstrągowego.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70599, 'Górska', 'Leśna struga, bystra', 6.0, 0.6, 'Kamień i żwir', 'Zwalone drzewa', 'Pstrąg potokowy, Kiełb', 'Kraina pstrąga', 'Górskie - kraina pstrąga', false);

-- Spot 601: Nowa Wieś
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70600, 'Nysa Kłodzka - Nowa Wieś (Bystrza)', 'nysa-klodzka-nowa-wies', 'RIVER', 50.1641584, 16.790166, 'Dolnośląskie', 'Międzylesie', 'Nysa Kłodzka w Nowej Wsi to odcinek o wybitnie górskim profilu, charakteryzujący się licznymi bystrzami i przelewami. Woda płynie tu dynamicznie, żłobiąc dno złożone z twardych skał sudeckich oraz drobniejszego żwiru w zatokach. To strategiczne miejsce dla łowców pstrągów, którzy potrafią czytać wodę i odnajdywać ryby w mikro-warkoczach za głazami. Uciąg rzeki jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas najgorętszych dni lata. Wędkarze muchowi chętnie stosują tu ciężkie nimfy, aby sprowadzić przynętę w pobliże dna najgłębszych rynien. Malownicze otoczenie gór sprawia, że każda chwila spędzona nad wodą jest formą aktywnej medytacji w sercu natury.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70600, 'Górska', 'Nurt żywy, skalista', 12.0, 0.7, 'Skały i żwir', 'Przełomy kamieniste', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Górskie - kraina pstrąga', false);

-- Spot 602: Krosnowice (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70601, 'Nysa Kłodzka - Krosnowice (Podgórski Nurt)', 'nysa-klodzka-krosnowice-1', 'RIVER', 50.3733072, 16.6388393, 'Dolnośląskie', 'Kłodzko', 'Odcinek w Krosnowicach to przejście rzeki z charakteru górskiego w podgórski, gdzie koryto staje się szersze i nieco głębsze. Nysa tworzy tu liczne zakola z wyraźnie zaznaczonymi rynnami prądowymi, w których chętnie stacjonują duże klenie oraz lipienie. Podłoże jest zróżnicowane, piaszczysto-żwirowe z lokalnymi partiami większych kamieni wymytych przez silniejszy prąd. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz okazowych pstrągów potokowych. Uciąg rzeki stabilizuje się, co pozwala na naturalną prezentację przynęty przy użyciu technik przepływanki z czułym spławikiem. To doskonałe miejsce dla wędkarzy ceniących różnorodność gatunkową i komfortowy dostęp do linii brzegowej rzeki.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70601, 'Górska', 'Meandrująca, żwirowa', 20.0, 1.1, 'Żwir i piasek', 'Rynny prądowe', 'Kleń, Lipień, Pstrąg potokowy', 'Kraina pstrąga', 'Kraina pstrąga', false);


-- Spot 603: Krosnowice (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70602, 'Nysa Kłodzka - Krosnowice (Burtowa)', 'nysa-klodzka-krosnowice-2', 'RIVER', 50.399407, 16.6280286, 'Dolnośląskie', 'Kłodzko', 'Północny odcinek w Krosnowicach oferuje urozmaicone stanowiska pod wysokimi, piaszczysto-gliniastymi burtami. Rzeka żłobi tu dno o charakterze żwirowym, tworząc technicznie ciekawe rynny idealne dla walecznych brzan i świnek. Spinningiści chętnie obławiają tutejsze spowolnienia nurtu, szukając szczupaków stacjonujących w pobliżu kęp roślinności wynurzonej. Nurt jest tu stabilny, co ułatwia systematyczne nęcenie i utrzymywanie stad białorybu in polu łowienia przez wiele godzin. Przejrzystość wody wymusza na wędkarzu zachowanie dużej ostrożności oraz stosowanie delikatnych zestawów z fluorocarbonu. Miejsce to łączy w sobie urok rzeki podgórskiej z rybnością typową dla środkowych biegów sudeckich rzek.', 'PZW Wałbrzych');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70602, 'Nizinna Wielka', 'Szeroka, rynny brzegowe', 25.0, 1.4, 'Żwir i glina', 'Podmyte burty', 'Brzana, Świnka, Szczupak', 'Kraina lipienia', false);

-- Spot 604: Głębinów (Cofka Jeziora Nyskiego)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70603, 'Nysa Kłodzka - Głębinów (Wlot)', 'nysa-klodzka-glebinow', 'RIVER', 50.4602541, 17.2538482, 'Opolskie', 'Nysa', 'Głębinów to unikalne łowisko położone nad samym Jeziorem Nyskim, gdzie Nysa Kłodzka przechodzi w szerokie plosa zbiornika zaporowego. Woda w tym rejonie jest głęboka i bogata w osady denne, co tworzy idealne warunki dla sandaczy, sumów oraz potężnych leszczy. To strategiczne miejsce dla spinningistów, którzy obławiają stoki dawnego koryta rzeki w poszukiwaniu drapieżników migrujących z jeziora. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz krąpie, wykorzystując metodę feedera klasycznego na piaszczystych blatach. Uciąg wody jest tu znikomy i uzależniony od aktualnej pracy elektrowni wodnej na tamie w Nysie. Doskonała infrastruktura turystyczna sprawia, że jest to chętnie wybierane miejsce na wielodniowe biwaki wędkarskie z łodzią.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70603, 'Nizinna Wielka', 'Cofka zbiornika', 150.0, 4.0, 'Muł i piasek', 'Koryto w jeziorze', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', true);

-- Spot 605: Kopice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70604, 'Nysa Kłodzka - Kopice (Łęgowa)', 'nysa-klodzka-kopice', 'RIVER', 50.6542648, 17.4826435, 'Opolskie', 'Grodków', 'Nysa Kłodzka w Kopicach to szeroka, nizinna rzeka o bardzo malowniczym przebiegu przez tereny leśne i łąkowe. Koryto posiada tu piaszczysto-żwirowe dno z wyraźnie zaznaczonymi przykosami, które są ulubionym żerowiskiem dla boleni. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając sandaczy stacjonujących w głębszych rynnach na łukach rzeki. Wędkarze gruntowi chętnie nęcą tutejsze płanie, licząc na brania rekordowych brzan oraz dorodnych świnek wchodzących z dołu rzeki. Uciąg jest zdecydowany i żywy, co sprzyja doskonałemu natlenieniu wody nawet podczas najgorętszych miesięcy w roku. To technicznie wymagające łowisko nagradza wytrwałych wędkarzy rybami życia, oferując jednocześnie spokój i bliskość surowej natury.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70604, 'Nizinna Wielka', 'Szeroka, nurt żywy', 45.0, 2.2, 'Piasek i żwir', 'Przykosy piaszczyste', 'Boleń, Brzana, Sandacz', 'Kraina leszcza', true);


