-- Spot 608: Przewóz (Lubuskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70607, 'Odra - Przewóz (Dzika Rzeka)', 'odra-przewoz-lubuskie', 'RIVER', 51.9489921, 15.7759391, 'Lubuskie', 'Zielona Góra', 'Odra w rejonie Przewozu to odcinek o wybitnie naturalnym charakterze, płynący szerokim korytem przez malownicze tereny pradoliny. Rzeka tworzy tu liczne, piaszczyste przykosy i rozległe warkocze prądowe, w których chętnie stacjonują bolenie oraz sandacze. Dno jest tu piaszczysto-żwirowe z głębokimi rynnami na łukach, stanowiącymi bezpieczne schronienie dla dorodnych leszczy. Spinningiści z sukcesami obławiają tutejsze główki, wykorzystując turbulentną wodę na styku nurtu głównego i spokojnych zatok. Uciąg jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji walecznych brzan żerujących w nurcie. Niska presja wędkarska oraz dzikość brzegów sprawiają, że każda wyprawa w to miejsce jest wyjątkowym doświadczeniem.', 'PZW Zielona Góra');

