-- Spot 609: Wrocław (Opatowice/Trestno)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70608, 'Odra - Wrocław (Trestno)', 'odra-wroclaw-trestno', 'RIVER', 51.097924, 17.1311245, 'Dolnośląskie', 'Wrocław', 'Odra na wejściu do Wrocławia w rejonie Trestna to techniczne łowisko o zróżnicowanej głębokości i licznych umocnieniach faszynowych. Rzeka posiada tu wyraźnie zaznaczone koryto z rynnami przydennymi, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców okazowych leszczy oraz amurów, które chętnie odwiedzają tutejsze spokojniejsze płanie przybrzeżne. Spinningiści z sukcesami obławiają rejony polderów i wlotów kanałów, szukając okoni oraz mniejszych szczupaków czatujących w roślinności. Uciąg wody stabilizuje się poniżej progu opatowickiego, co pozwala na komfortowe operowanie zestawami feederowymi z dociążonym koszykiem. Dobry dostęp do brzegów oraz specyfika granicy miasta sprawiają, że rybostan jest tu wyjątkowo zróżnicowany i bogaty.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70608, 'Nizinna Wielka', 'Uregulowana, nurt stabilny', 100.0, 3.2, 'Twardy piasek', 'Opaski, poldery', 'Sandacz, Leszcz, Amur', 'Kraina leszcza', true);

-- Spot 610: Jeszkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70609, 'Odra - Jeszkowice (Zakola)', 'odra-jeszkowice', 'RIVER', 51.051863, 17.2158623, 'Dolnośląskie', 'Wrocław', 'Odcinek rzeki w Jeszkowicach słynie z głębokich rynien i silnie zarysowanych meandrów rzeki swobodnie płynącej powyżej Wrocławskiego Węzła Wodnego. Dno jest tu mocno urozmaicone, piaszczysto-gliniaste z licznymi podwodnymi przeszkodami w postaci zatopionych drzew i karczowisk. To wymarzone stanowisko dla łowców sumów, którzy wykorzystują tutejsze jamy jako swoje główne ostoje podczas dziennego odpoczynku. Wędkarze gruntowi chętnie nęcą piaszczyste płanie przy głuchych głowach, licząc na brania rekordowych stad leszczowych oraz dorodnych krąpi. Uciąg jest tu zdecydowany, co wymaga stosowania ciężkich zestawów i solidnego dociążenia przynęty naturalnej na haku. Malowniczy krajobraz oraz dzika natura brzegów gwarantują spokój oraz szansę na kontakt z niewypłoszoną, dużą rybą rzeczną.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70609, 'Nizinna Wielka', 'Szeroka, naturalne meandry', 110.0, 3.8, 'Piasek i glina', 'Zwalone drzewa', 'Sum, Leszcz, Sandacz', 'Kraina leszcza', true);

-- Spot 611: Wrocław (Rędzin)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70610, 'Odra - Wrocław (Rędzin)', 'odra-wroclaw-redzin', 'RIVER', 51.1590163, 16.9522385, 'Dolnośląskie', 'Wrocław', 'Odra w rejonie stopnia wodnego Rędzin to technicznie wymagające łowisko miejskie o dużej dynamice przepływu wody. Pod filarami mostu Rędzińskiego rzeka wymyła głębokie rynny, które są doskonałym stanowiskiem dla sandaczy oraz boleni patrolujących warkocze. To strategiczne miejsce dla spinningistów, którzy wykorzystują betonowe umocnienia i progi do precyzyjnego prowadzenia przynęt w silnym nurcie. Woda poniżej śluzy jest doskonale natleniona, co przyciąga rekordowe brzany oraz duże klenie żerujące w turbulentnym prądzie wody. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie, wykorzystując metodę bata lub ciężkiego feedera na krawędzi nurtu głównego. Infrastruktura i dogodny dostęp czynią to miejsce jednym z najpopularniejszych punktów spotkań wrocławskich wędkarzy przez cały rok.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70610, 'Nizinna Wielka', 'Uregulowana, techniczna', 130.0, 4.0, 'Beton i kamień', 'Śluzy, mosty, progi', 'Sandacz, Boleń, Brzana', 'Kraina leszcza', true);

-- Spot 612: Wrocław (Pracze Odrzańskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70611, 'Odra - Wrocław (Pracze Odrzańskie)', 'odra-pracze-odrzanskie', 'RIVER', 51.1991937, 16.9181213, 'Dolnośląskie', 'Wrocław', 'Odcinek Odry w Praczach Odrzańskich charakteryzuje się przejściem rzeki w charakter bardziej naturalny i dziki po opuszczeniu centrum Wrocławia. Koryto posiada tu piaszczysto-żwirowe dno z licznymi podmyłymi burtami, które skrywają wyrośnięte klenie oraz mniejsze szczupaki. To doskonałe łowisko dla spinningistów szukających okoni stacjonujących w pobliżu nadrzecznych nawisów wikliny i pasów roślinności zanurzonej. Uciąg jest stabilny i zdecydowany, co sprzyja naturalnej prezentacji przynęty przy użyciu techniki przepływanki z ciężkim spławikiem rzecznym. W rynnach o głębokości do trzech metrów często grupują się duże leszcze, które doskonale reagują na systematyczne nęcenie grubą zanętą. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z rybą rzeczną w otoczeniu sielskiego, nadodrzańskiego krajobrazu.', 'PZW Wrocław');

