VALUES (70611, 'Nizinna Wielka', 'Meandrująca, naturalna', 115.0, 2.5, 'Piasek i żwir', 'Podmyte burty', 'Kleń, Okoń, Leszcz', 'Kraina leszcza', true);

-- Spot 613: Wojszyn (Głogów)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70612, 'Odra - Wojszyn (Krainy Główek)', 'odra-wojszyn', 'RIVER', 51.6780633, 16.1966019, 'Dolnośląskie', 'Głogów', 'Odra w Wojszynie to klasyczne łowisko nizinne słynące z regularnej linii główek o piaszczystych korytach i głębokich klatkach między nimi. Każda ostroga tworzy unikalne warunki pokarmowe, gdzie w warkoczu prądowym czatują sandacze, a w zastoiskach żerują dorodne leszcze. To strategiczne miejsce dla spinningistów, którzy obławiają szczyty główek w poszukiwaniu boleni patrolujących turbulentną wodę na styku nurtów. Dno jest tu twarde, piaszczyste, z głębokimi rynnami wymytymi na końcu każdej budowli regulacyjnej, co sprzyja sumom. Wędkarze gruntowi chętnie nęcą tutejsze zatoki, celując w rekordowe płocie oraz liny, które znajdują tu schronienie przed silnym prądem. Systematyczne nęcenie na stokach główek pozwala na uzyskanie powtarzalnych wyników i kontakt z naprawdę wielką, rzeczną rybą.', 'PZW Legnica');

