-- Spot 614: Kobylice (Kędzierzyn-Koźle)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70613, 'Odra - Kobylice (Rynny prądowe)', 'odra-kobylice', 'RIVER', 50.3181825, 18.1853656, 'Opolskie', 'Kędzierzyn-Koźle', 'Odra w Kobylicach to odcinek o silnie uregulowanym korycie z wyraźnie zaznaczoną rynną główną i licznymi opaskami faszynowymi. Dno jest tu twarde, piaszczysto-żwirowe, co sprzyja aktywności brzan oraz dorodnych kleni żerujących w najsilniejszym nurcie rzeki. To strategiczne miejsce dla spinningistów polujących na sandacze, które wykorzystują głębokie doły przy budowlach regulacyjnych jako swoje ostoje. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, stosując metodę ciężkiego feedera dla stabilizacji zestawu na dnie. Uciąg rzeki jest zdecydowany i stabilny, co pozwala na precyzyjne nęcenie punktowe grubszą frakcją zanęty spożywczej. Miejsce to zapewnia doskonałe warunki do technicznego wędkarstwa rzecznego w surowym, industrialno-naturalnym krajobrazie Opolszczyzny.', 'PZW Opole');

