-- Spot 615: Opole (Miejskie Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70614, 'Odra - Opole (Pod Mostami)', 'odra-opole-bulwary', 'RIVER', 50.6596797, 17.9174683, 'Opolskie', 'Opole', 'Miejski odcinek Odry w Opolu to techniczne łowisko o bardzo zróżnicowanej głębokości i licznymi konstrukcjami hydrotechnicznymi w nurcie. Pod filarami mostów rzeka wymyła głębokie rynny, w których chętnie stacjonują sandacze oraz duże okonie żerujące na uklejach. To doskonałe miejsce dla spinningistów szukających boleni patrolujących turbulentną wodę poniżej miejskich śluz i progów wodnych. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz leszcze, wykorzystując metodę bata lub tyczki przy bulwarach. Uciąg wody jest kontrolowany przez pracę jazów, co wymaga od wędkarza częstej adaptacji masy stosowanych obciążeń zestawu. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko jednym z najpopularniejszych punktów w całym regionie.', 'PZW Opole');

