VALUES (70614, 'Nizinna Wielka', 'Uregulowana miejska', 110.0, 4.0, 'Twardy piasek', 'Śluzy, filary mostów', 'Sandacz, Płoć, Boleń', 'Kraina leszcza', true);

-- Spot 616: Rzeczyca (Lubuskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70615, 'Odra - Rzeczyca (Warkocze)', 'odra-rzeczyca-lubuskie', 'RIVER', 51.246056, 16.5572168, 'Dolnośląskie', 'Głogów', 'Odra w Rzeczycy charakteryzuje się szerokim korytem i obecnością piaszczystych przykos wychodzących daleko w główny nurt rzeki. Rzeka tworzy tu silne warkocze prądowe, które są strategicznym miejscem żerowania dla boleni oraz sandaczy w godzinach wieczornych. Dno jest piaszczysto-żwirowe z głębokimi rynnami na łukach, stanowiącymi bezpieczne schronienie dla dorodnych stad leszczowych. Spinningiści z sukcesami obławiają tutejsze główki, wykorzystując turbulentną wodę na styku nurtu głównego i spokojniejszych zatok przybrzeżnych. Uciąg rzeki jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności walecznych brzan żerujących w nurcie. Malowniczy krajobraz oraz niska presja wędkarska gwarantują spokój podczas całodniowych sesji z ciężkim feederem lub spinningiem.', 'PZW Wrocław');

