-- Spot 617: Głogów (Portowe Zacisze)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70616, 'Odra - Głogów (Zatoki)', 'odra-glogow-zatoki', 'RIVER', 51.6663889, 16.123445, 'Dolnośląskie', 'Głogów', 'Odcinek Odry w Głogowie słynie z głębokich rynien przydennych oraz obecności starych basenów portowych łączących się z nurtem. To wymarzone miejsce dla łowców szczupaków i sandaczy, którzy obławiają krawędzie roślinności zanurzonej i uskoki dna przy portach. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz liny, wykorzystując systematyczne nęcenie na piaszczysto-mulistych płaniach przybrzeżnych. Uciąg rzeki w tym miejscu stabilizuje się, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w łowisku. Pod filarami głogowskich mostów woda wymyła głębokie doły, które są naturalną kryjówką dla sumów oraz dorodnych rzecznych kleni. Miejsce to zapewnia bardzo dobre warunki techniczne i jest chętnie wybierane na wielogodzinne zasiadki z drgającą szczytówką.', 'PZW Legnica');

