-- Spot 618: Inoujście (Estuarium)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70617, 'Odra - Inoujście (Styk z Zalewem)', 'odra-inoujscie', 'RIVER', 53.5265773, 14.633592, 'Zachodniopomorskie', 'Goleniów', 'Odra w Inoujściu to potężna arteria o charakterze estuarium, gdzie nurt rzeki miesza się z wodami Roztoki Odrzańskiej. To strategiczne miejsce dla łowców drapieżników, szczególnie sandaczy i wielkich okoni migrujących okresowo między rzeką a Zalewem Szczecińskim. Dno jest tu mocno urozmaicone, mulisto-piaszczyste z głębokimi torami wodnymi stanowiącymi główne szlaki komunikacyjne ryb. Wędkarze z sukcesami stosują tu techniki wertykalne oraz ciężki spinning, obławiając stoki głębokich rynien o silnym uciągu. Uciąg wody jest tu uzależniony od zjawisk "cofki" i wiatrów, co czyni to łowisko niezwykle nieprzewidywalnym i technicznie trudnym. Miejsce to nagradza wytrwałych wędkarzy rybami o imponujących rozmiarach, rzadko spotykanych w innych częściach biegu rzeki.', 'PZW Szczecin');

