-- Spot 619: Police (Kanał Policki)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70618, 'Odra - Police (Dominacja Białorybu)', 'odra-police', 'RIVER', 53.5724847, 14.5960013, 'Zachodniopomorskie', 'Police', 'Odcinek Odry w Policach to szeroka, głęboka rzeka o specyfice ujściowej z silnym wpływem zjawisk hydrologicznych z Bałtyku. Koryto posiada tu piaszczysto-muliste dno z wyraźnie zaznaczonymi rynnami, które są ulubionym miejscem żerowania ogromnych stad leszczy. To doskonałe łowisko dla wędkarzy feederowych celujących w rekordowe płocie, które wchodzą tu masowo podczas wiosennych i jesiennych ciągów. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka oraz ciężkie jigi prowadzone agresywnie w pobliżu toru wodnego. Uciąg rzeki bywa tu zmienny, co wymaga od wędkarza posiadania szerokiego wachlarza obciążeń dla poprawnej prezentacji przynęty. Dogodna infrastruktura portowa i liczne stanowiska brzegowe czynią ten fragment Odry bardzo atrakcyjnym dla wędkarzy z całego Pomorza Zachodniego.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70618, 'Nizinna Wielka', 'Szeroka ujściowa', 350.0, 5.5, 'Piasek i muł', 'Umocnienia portowe', 'Leszcz, Płoć, Okoń', 'Kraina leszcza', true);

-- Spot 620: Radoszyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70619, 'Odra - Radoszyce (Głębokie Główki)', 'odra-radoszyce', 'RIVER', 51.5764731, 16.4104521, 'Dolnośląskie', 'Ścinawa', 'Odra w Radoszycach to odcinek słynący z potężnych ostróg i głębokich klatek między główkami. Dno jest tu twarde i piaszczyste, co sprzyja bytowaniu sandaczy oraz boleni żerujących na uklejach. To idealne miejsce dla łowców rzecznych sumów, które odpoczywają w najgłębszych rynnach na końcach główek. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, nęcąc ryby w warkoczach prądowych za szczytami ostróg. Uciąg rzeki jest zdecydowany, co wymaga stosowania dociążonych zestawów feederowych z solidnym mocowaniem na dnie. Dzikie brzegi porośnięte wikliną zapewniają doskonałe warunki do dyskretnego podejścia i skutecznego spinningowania.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70619, 'Nizinna Wielka', 'Uregulowana, główki', 140.0, 3.0, 'Piaszczyste', 'Główki, rynny szczytowe', 'Sandacz, Boleń, Sum', 'Kraina leszcza', true);

-- Spot 621: Bełcz Wielki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70620, 'Odra - Bełcz Wielki (Piaszczyste Przykosy)', 'odra-belcz-wielki', 'RIVER', 51.6086609, 16.358409, 'Dolnośląskie', 'Głogów', 'Odcinek w Bełczu Wielkim charakteryzuje się szerokim korytem oraz licznymi, naturalnymi piaszczystymi przykosami wychodzącymi w główny nurt. Rzeka żłobi tu głębokie jamy, w których chętnie stacjonują sandacze szukające natlenionej wody poniżej kamienistych raf. To strategiczne miejsce dla spinningistów, którzy wykorzystują turbulentne prądy do agresywnego prowadzenia ciężkich gumowych przynęt. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w stadne leszczowe trofea oraz dorodne, rzeczne krąpie. Uciąg rzeki jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. Miejsce to gwarantuje absolutny spokój oraz szansę na kontakt z niewypłoszoną, naprawdę dużą rybą odrzańską.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70620, 'Nizinna Wielka', 'Szeroka, przykosy', 150.0, 2.5, 'Piasek i żwir', 'Przykosy, jamy', 'Sandacz, Leszcz, Boleń', 'Kraina leszcza', true);

-- Spot 622: Wietszyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70621, 'Odra - Wietszyce (Warkocze Prądowe)', 'odra-wietszyce', 'RIVER', 51.6444488, 16.3116011, 'Dolnośląskie', 'Głogów', 'Odra w Wietszycach to kwintesencja dolnośląskiej rzeki nizinnej o urozmaiconym dnie i doskonale uformowanych główkach regulacyjnych. Koryto rzeki posiada tu piaszczysto-żwirowe dno z wyraźnymi uskokami, które stanowią bankowe stanowiska dla kleni oraz brzan. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni patrolujących krawędzie nurtu głównego i zastoisk. Wędkarze stacjonarni chętnie nęcą tutejsze zatoki, licząc na brania rekordowych płoci oraz linów w zacisznych klatkach. Uciąg wody jest stabilny, co pozwala na komfortowe operowanie zestawami spławikowymi oraz precyzyjne nęcenie punktowe rzeki. Niska presja wędkarska w tym rejonie oraz dziki charakter brzegów sprzyjają wielogodzinnym, skutecznym zasiadkom nad wodą.', 'PZW Legnica');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70621, 'Nizinna Wielka', 'Uregulowana, nurt stabilny', 145.0, 2.8, 'Piasek i żwir', 'Główki, warkocze', 'Kleń, Brzana, Boleń', 'Kraina leszcza', true);

-- Spot 623: Bystrzyca (k. Oławy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70622, 'Odra - Bystrzyca (Oławska Opaska)', 'odra-bystrzyca-olawska', 'RIVER', 50.9206478, 17.3990139, 'Dolnośląskie', 'Oława', 'Odcinek w Bystrzycy koło Oławy to techniczne łowisko o zróżnicowanej głębokości i obecności licznych opasek faszynowych przy brzegach. Rzeka posiada tu wyraźnie zaznaczone koryto z głębokimi rynnami, które są ulubionym schronieniem dla sandaczy żerujących o świcie. To doskonałe miejsce dla łowców okazowych brzan, które znajdują tu odpowiedni uciąg i twarde, piaszczyste podłoże. Spinningiści z sukcesami obławiają rejony podmytych wierzb, szukając okoni oraz mniejszych szczupaków czatujących w przybrzeżnej roślinności. Uciąg rzeki jest stabilny, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu w polu łowienia. Bliskość ujść mniejszych dopływów sprawia, że rybostan jest tu wyjątkowo zróżnicowany i atrakcyjny dla wędkarzy.', 'PZW Wrocław');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70622, 'Nizinna Wielka', 'Uregulowana, opaski', 100.0, 3.5, 'Piasek i glina', 'Opaski faszynowe', 'Sandacz, Brzana, Leszcz', 'Kraina leszcza', true);

-- Spot 624: Prędocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70623, 'Odra - Prędocin (Szczyty Główek)', 'odra-predocin', 'RIVER', 50.8534202, 17.5924771, 'Opolskie', 'Brzeg', 'Odra w Prędocinie to szeroka rzeka o dojrzałym charakterze nizinno-regulacyjnym z doskonale zachowanymi ostrogami i pasami faszyny. Dno jest tu mocno urozmaicone, piaszczysto-żwirowe z licznymi rynnami wymytymi przez silniejszy nurt na łukach koryta. To strategiczne miejsce dla łowców sandaczy, którzy wykorzystują uskoki dna na końcach główek jako swoje ostoje. Wędkarze gruntowi z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie na piaszczystych blatach koryta głównego. Uciąg wody jest zdecydowany, co sprzyja wysokiej aktywności ryb reofilnych i wymaga stosowania solidnych obciążeń zestawów. Spokojna okolica oraz bogata populacja drapieżników czynią ten fragment Odry bardzo atrakcyjnym punktem na mapie Opolszczyzny.', 'PZW Opole');

