VALUES (70623, 'Nizinna Wielka', 'Uregulowana, główki', 110.0, 3.2, 'Piasek i żwir', 'Rynny przygłówkowe', 'Sandacz, Leszcz, Brzana', 'Kraina leszcza', true);

-- Spot 625: Pawłów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70624, 'Odra - Pawłów (Piaszczyste Płanie)', 'odra-pawlow', 'RIVER', 50.8503717, 17.5199207, 'Opolskie', 'Brzeg', 'Odcinek w Pawłowie charakteryzuje się obecnością rozległych płani i piaszczystych przykos, które zmieniają swój kształt przy każdym większym wezbraniu rzeki. Rzeka płynie tu dostojnie, oferując wędkarzom bardzo urozmaiconą linię brzegową z zatokami pełnymi drobnicy i drapieżników. To wymarzone miejsce dla łowców boleni, które agresywnie atakują stada uklei przy turbulentnych warkoczach prądowych rzeki. Wędkarze stacjonarni chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne płocie oraz rzeczne leszcze żerujące na dnie. Uciąg wody jest umiarkowany i przewidywalny, co sprzyja punktowemu nęceniu i utrzymywaniu stad ryb w łowisku. Dogodny dostęp do wody sprawia, że jest to chętnie wybierane miejsce na weekendowe sesje z lekkim gruntem.', 'PZW Opole');

