VALUES (70624, 'Nizinna Wielka', 'Szeroka, piaszczysta', 120.0, 2.8, 'Piaszczyste', 'Przykosy, płanie', 'Boleń, Leszcz, Płoć', 'Kraina leszcza', true);

-- Spot 626: Wrocław (Centrum / Ostrów Tumski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70625, 'Odra - Wrocław (Centrum)', 'odra-wroclaw-centrum', 'RIVER', 51.1153817, 17.0353782, 'Dolnośląskie', 'Wrocław', 'Odra w samym sercu Wrocławia to unikalne łowisko miejskie charakteryzujące się betonowymi bulwarami i licznymi wyspami. Podłoże jest tu twarde, piaszczysto-kamieniste, z głębokimi rynnami wymytymi pod filarami historycznych mostów. To strategiczne miejsce dla łowców okazowych sandaczy oraz okoni żerujących na uklejach w cieniu konstrukcji. Spinningiści z sukcesami obławiają rejony murów oporowych, wykorzystując warkocze prądowe powstające przy rozwidleniach koryta. Uciąg wody jest tu regulowany przez gęstą sieć jazów i śluz, co wymaga częstej adaptacji gramatury przynęt. Bliskość miejskiej infrastruktury i oświetlenie brzegów czynią to miejsce doskonałym punktem do wieczornego polowania na drapieżniki.', 'PZW Wrocław');

