VALUES (70625, 'Nizinna Wielka', 'Uregulowana miejska', 110.0, 4.2, 'Kamień i piasek', 'Mosty, bulwary', 'Sandacz, Okoń, Boleń', 'Kraina leszcza', true);

-- Spot 627: Bohumín (Granica CZ/PL)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70626, 'Odra - Bohumín (Meandry Graniczne)', 'odra-bohumin', 'RIVER', 49.9285641, 18.3431061, 'Morawsko-Śląski', 'Bohumín', 'Odra w Bohumínie to odcinek graniczny o charakterze naturalnym z licznymi meandrami i piaszczystymi łachami. Rzeka płynie tu dość wartko, żłobiąc dno o charakterze piaszczysto-żwirowym z wyraźnymi uskokami przy brzegach. To doskonałe łowisko dla wędkarzy szukających kleni oraz brzan stacjonujących w natlenionych bystrzach. Wędkarze gruntowi chętnie nęcą tutejsze spowolnienia nurtu, celując w dorodne płocie oraz rzeczne leszcze. Uciąg wody jest tu naturalny i zależny od opadów w górach, co nadaje każdej wyprawie dzikiego charakteru. Specyfika granicznego położenia i niska presja wędkarska sprawiają, że ryby żerują tu bardzo odważnie przez cały sezon.', 'ČRS (Czech Fishing Union)');

