VALUES (70626, 'Nizinna Wielka', 'Meandrująca, naturalna', 40.0, 1.8, 'Piasek i żwir', 'Piaszczyste łachy', 'Brzana, Kleń, Leszcz', 'Kraina leszcza', false);

-- Spot 628: Racibórz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70627, 'Odra - Racibórz (Górna)', 'odra-raciborz', 'RIVER', 50.1183491, 18.2319126, 'Śląskie', 'Racibórz', 'Odra w Raciborzu to górny bieg rzeki o uregulowanym korycie, pozostający pod silnym wpływem zbiornika Racibórz Dolny. Podłoże jest tu twarde, kamienisto-żwirowe, co stwarza idealne warunki dla ryb reofilnych takich jak świnki i certy. To strategiczne miejsce dla łowców sandaczy, którzy obławiają uskoki dna w pobliżu miejskich stopni wodnych. Spinningiści z sukcesami polują tu na klenie, wykorzystując małe woblery prowadzone wzdłuż brzegowych opasek faszynowych. Uciąg rzeki jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb w okresach letnich. Dobra infrastruktura i łatwy dostęp do brzegów czynią to łowisko popularnym punktem na mapie regionu śląskiego.', 'PZW Katowice');

