VALUES (70627, 'Nizinna Wielka', 'Uregulowana, nurt żywy', 50.0, 2.0, 'Kamień i żwir', 'Jazy, opaski', 'Sandacz, Świnka, Kleń', 'Kraina leszcza', false);

-- Spot 629: Vítkov (Góry Odrzańskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70628, 'Odra - Vítkov (Przełom Górski)', 'odra-vitkov', 'RIVER', 49.7224513, 17.7197389, 'Morawsko-Śląski', 'Vítkov', 'Odra w rejonie Vítkova to niemal źródliskowy, górski odcinek rzeki płynący przez malownicze tereny Oderskich Wierchów. Woda jest tu krystalicznie czysta, lodowata i bardzo bystra, żłobiąc dno usiane grubymi otoczakami i głazami. To eldorado dla muszkarzy oraz spinningistów szukających pstrągów potokowych w ich najbardziej naturalnym środowisku. Ze względu na niewielką szerokość koryta, kluczowe do sukcesu jest dyskretne podejście do wody i precyzyjne podanie przynęty. Liczne mikro-rynny i naturalne progi tworzą doskonałe stanowiska dla ryb łososiowatych żerujących w turbulentnym nurcie. Dziki charakter tego regionu zapewnia wędkarzowi całkowitą izolację od cywilizacji i szansę na kontakt z niewypłoszoną rybą.', 'ČRS (Czech Fishing Union)');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70628, 'Górska', 'Dziki potok górski', 8.0, 0.6, 'Głazy i otoczaki', 'Naturalne bystrza', 'Pstrąg potokowy, Głowacz', 'Kraina pstrąga', 'Pstrągowa', false);

-- Spot 630: Jakubčovice nad Odrou
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70629, 'Odra - Jakubčovice (Górskie Bystrza)', 'odra-jakubcovice', 'RIVER', 49.6984981, 17.779066, 'Morawsko-Śląski', 'Odry', 'Odra w Jakubčovicach to klasyczny potok górski o dużej dynamice przepływu i kamienistym dnie. Rzeka tworzy tu liczne bystrza i przelewy, które są naturalną bazą pokarmową dla pstrągów oraz lipieni. Spinningiści z sukcesami polują tu na okazy pstrąga potokowego, wykorzystując małe obrotówki prowadzone za naturalnymi przeszkodami. Podłoże składa się z twardych skał i żwiru, co ułatwia bezpieczne brodzenie w poszukiwaniu najlepszych stanowisk. Uciąg wody jest bardzo silny, co wymaga stosowania dociążonych nimf lub mikro-jigów w celu sprowadzenia przynęty do dna. Malownicze położenie w dolinie i wysoka przejrzystość wody nadają każdej wyprawie wyjątkowego, sudeckiego klimatu.', 'ČRS (Czech Fishing Union)');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, special_sections, boat_fishing_allowed)
VALUES (70629, 'Górska', 'Bystra, skalista', 10.0, 0.7, 'Skały i żwir', 'Zatory skalne', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', 'Pstrągowa', false);

-- Spot 631: Odry (Czechy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70630, 'Odra - Miasto Odry (Lipieniowa)', 'odra-miasto-odry', 'RIVER', 49.6673593, 17.8293943, 'Morawsko-Śląski', 'Odry', 'Odra w miejscowości Odry to techniczne łowisko górskie o urozmaiconej rzeźbie dna i kamienistym podłożu. Koryto rzeki posiada tu wyraźnie zaznaczone warkocze prądowe, stanowiące ulubione stanowiska dla lipieni i jelców. To doskonałe miejsce dla wędkarzy muchowych, którzy cenią sobie możliwość brodzenia i łowienia techniką suchej muchy. Spinningiści z sukcesami obławiają tutejsze głębokie rynny pod brzegowymi nawisami traw w poszukiwaniu pstrągów. Uciąg rzeki jest tu zdecydowany, ale stabilny, co sprzyja systematycznemu badaniu łowiska mikro-przynętami. Dobra infrastruktura w samym mieście oraz wysoka rybność odcinka przyciągają pasjonatów wędkarstwa górskiego z całego regionu.', 'ČRS (Czech Fishing Union)');

