VALUES (70630, 'Górska', 'Podgórska, nurt stabilny', 15.0, 0.9, 'Kamień i żwir', 'Warkocze prądowe', 'Lipień, Pstrąg potokowy, Jelec', 'Kraina lipienia', 'Pstrągowa', false);



-- Spot 646: Oława (Polska - Odra miejska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70645, 'Odra - Oława (Główki)', 'odra-pl-olawa', 'RIVER', 50.9597413, 17.30547, 'Dolnośląskie', 'Oława', 'Odra w Oławie to klasyczny odcinek uregulowanej rzeki nizinnej z dobrze wykształconym systemem ostróg brzegowych. Koryto rzeki posiada tu piaszczysto-żwirowe dno z głębokimi rynnami wymytymi na końcach główek, gdzie stacjonują sandacze. To strategiczne miejsce dla łowców okazowych leszczy, którzy wykorzystują warkocze prądowe do nęcenia stad ryb białego żeru. Spinningiści z sukcesami polują tu na bolenie patrolujące turbulentną wodę na styku nurtu głównego i spokojnych klatek. Uciąg wody jest zdecydowany i stabilny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. Dobra infrastruktura i łatwy dostęp do brzegów czynią to łowisko jednym z najpopularniejszych punktów na mapie Dolnego Śląska.', 'PZW Wrocław');

