-- Spot 647: Jelcz-Laskowice (Ratowice - Stopień wodny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70646, 'Odra PL - Jelcz-Laskowice (Ratowice)', 'odra-pl-jelcz-laskowice', 'RIVER', 51.0058438, 17.3050098, 'Dolnośląskie', 'Wrocław', 'Odcinek w rejonie Jelcza-Laskowic, przy stopniu wodnym Ratowice, charakteryzuje się dużą dynamiką wody i silnym natlenieniem poniżej jazu. Rzeka wymyła tu głębokie doły pod betonowymi umocnieniami, które są naturalnym stanowiskiem dla sumów oraz sandaczy. To doskonałe miejsce dla spinningistów szukających boleni oraz kleni żerujących w turbulentnym nurcie warkoczy prądowych. Wędkarze gruntowi z sukcesami łowią tu waleczne brzany, wykorzystując ciężkie zestawy feederowe z dociążonym koszykiem zanętowym. Uciąg wody jest tu bardzo silny i zależy od pracy śluzy, co wymaga od wędkarza częstej adaptacji techniki łowienia. Miejsce to słynie z bogactwa ryb drapieżnych i jest uważane za jedno z technicznie najciekawszych łowisk w aglomeracji wrocławskiej.', 'PZW Wrocław');

