VALUES (70646, 'Nizinna Wielka', 'Techniczna, stopień wodny', 120.0, 4.0, 'Twardy piasek', 'Jaz, śluza, progi', 'Sum, Sandacz, Brzana', 'Kraina leszcza', true);

-- Spot 648: Roszków (Meandry Graniczne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70647, 'Odra PL - Roszków (Graniczna)', 'odra-pl-roszkow', 'RIVER', 49.9733294, 18.3070313, 'Śląskie', 'Racibórz', 'Odra w Roszkowie to wyjątkowy odcinek o charakterze naturalnym, gdzie rzeka swobodnie meandruje wzdłuż granicy z Czechami. Podłoże jest tu twarde, żwirowo-kamieniste, co stwarza idealne warunki dla ryb reofilnych takich jak świnki oraz rzeczne klenie. To doskonałe łowisko dla spinningistów ceniących brodzenie i polowanie na pstrągi potokowe okresowo pojawiające się w tym rejonie. Uciąg rzeki jest żywy i zmienny, tworząc liczne bystrza oraz głębokie rynny pod wysokimi, podmywanymi burtami. Niska presja wędkarska oraz utrudniony dostęp do brzegów gwarantują kontakt z dziką rybą w surowym krajobrazie Górnego Śląska. Miejsce to wymaga od wędkarza umiejętności czytania nurtu i dyskretnego podejścia do stanowiska w krystalicznie czystej, płytkiej wodzie.', 'PZW Katowice');

