VALUES (70647, 'Górska', 'Naturalna, meandrująca', 45.0, 1.2, 'Żwir i kamień', 'Podmyte burty', 'Kleń, Brzana, Świnka', 'Kraina pstrąga', false);

-- Spot 649: Łomy (Lubuskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70648, 'Odra PL - Łomy (Lubuski Nurt)', 'odra-pl-lomy', 'RIVER', 52.0740028, 14.8066853, 'Lubuskie', 'Krosno Odrzańskie', 'Odra w Łomach to szeroka, potężna rzeka nizinna charakteryzująca się długimi seriami główek regulacyjnych i rozległymi płaniami. Dno jest tu piaszczysto-żwirowe z wyraźnymi uskokami na krawędzi nurtu głównego, gdzie stacjonują rekordowe sandacze. To wymarzone miejsce dla spinningistów polujących na bolenie żerujące agresywnie przy szczytach ostróg brzegowych. Wędkarze gruntowi chętnie nęcą tutejsze zatoki między główkami, celując w dorodne leszczowe stada oraz rzeczne krąpie. Uciąg wody jest tu stabilny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w polu łowienia przez wiele godzin. Malowniczy krajobraz lubuskiej doliny Odry oraz wysoka rybność odcinka przyciągają pasjonatów ciężkiego feedera z całego kraju.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70648, 'Nizinna Wielka', 'Szeroka, główki', 160.0, 3.5, 'Piasek i żwir', 'Główki, przykosy', 'Sandacz, Boleń, Leszcz', 'Kraina leszcza', true);

-- Spot 650: Opole (Groszowice)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70649, 'Odra - Opole (Groszowice)', 'odra-opole-groszowice', 'RIVER', 50.5876778, 17.964902, 'Opolskie', 'Opole', 'Odra w Groszowicach to odcinek o szerokim korycie i wyraźnie zaznaczonej rynnie głównej o charakterze piaszczysto-żwirowym. Rzeka płynie tu stabilnie, żłobiąc dno z nielicznymi podwodnymi przeszkodami w postaci zatopionych faszyn i kamieni. To strategiczne miejsce dla łowców sandaczy, którzy obławiają uskoki dna w pobliżu betonowych opasek brzegowych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując metodę ciężkiego feedera na krawędzi nurtu głównego. Uciąg wody jest umiarkowany i przewidywalny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad ryb białego żeru. Dobra dostępność brzegów sprawia, że jest to chętnie wybierane miejsce na całodniowe zasiadki w południowej części miasta.', 'PZW Opole');

