VALUES (70649, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 105.0, 3.2, 'Piasek i żwir', 'Opaski brzegowe', 'Sandacz, Leszcz, Płoć', 'Kraina leszcza', true);

-- Spot 651: Brzeg Dolny (Stopień Wodny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70650, 'Odra - Brzeg Dolny (Zrzut Elektrowni)', 'odra-brzeg-dolny-zapora', 'RIVER', 51.2581649, 16.7541599, 'Dolnośląskie', 'Brzeg Dolny', 'Odra w Brzegu Dolnym to jedno z najbardziej technicznych łowisk w regionie ze względu na obecność potężnego stopnia wodnego. Woda poniżej jazu jest silnie natleniona i niesie ogromne ilości pokarmu, co przyciąga rekordowe sumy oraz sandacze. To wymarzone miejsce dla spinningistów, którzy polują na bolenie patrolujące turbulentną wodę w silnych warkoczach prądowych. Dno jest tu bardzo twarde, kamienisto-betonowe, co wymaga stosowania dociążonych przynęt dla stabilnej prezentacji w nurcie. Wędkarze gruntowi chętnie nęcą tutejsze głębokie rynny, licząc na brania walecznych brzan oraz rzecznych kleni. Specyfika pracy elektrowni decyduje o aktywności ryb, co czyni ten odcinek łowiskiem dla doświadczonych i bardzo cierpliwych pasjonatów.', 'PZW Wrocław');

