VALUES (70650, 'Nizinna Wielka', 'Techniczna, stopień wodny', 130.0, 4.5, 'Beton i kamień', 'Jaz, elektrownia', 'Sum, Sandacz, Brzana', 'Kraina leszcza', false);

-- Spot 652: Pogalewo Małe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70651, 'Odra - Pogalewo Małe (Oczyszczony Nurt)', 'odra-pogalewo-male', 'RIVER', 51.2449811, 16.6835503, 'Dolnośląskie', 'Brzeg Dolny', 'Odcinek w Pogalewie Małym charakteryzuje się przejściem rzeki w charakter bardziej naturalny po opuszczeniu strefy oddziaływania stopnia wodnego. Rzeka żłobi tu głębokie rynny w piaszczysto-żwirowym dnie, tworząc bankowe stanowiska dla dużych kleni i jazi. To doskonałe łowisko dla spinningistów szukających szczupaków stacjonujących w pobliżu brzegowych nawisów traw i wiklin. Uciąg jest stabilny i zdecydowany, co sprzyja naturalnej prezentacji przynęty przy użyciu techniki przepływanki z ciężkim spławikiem. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie, wykorzystując systematyczne nęcenie na krawędzi głównego koryta. Malowniczy krajobraz doliny Odry oraz wysoka rybność odcinka przyciągają wędkarzy szukających spokoju i szansy na rekordowe wyniki.', 'PZW Wrocław');

