VALUES (70651, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 115.0, 2.8, 'Piasek i żwir', 'Podmyte brzegi', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', true);

-- Spot 653: Popielów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70652, 'Odra - Popielów (Zatopione Główki)', 'odra-popielow', 'RIVER', 50.7946592, 17.7164695, 'Opolskie', 'Opole', 'Odra w Popielowie to odcinek słynący z licznych, starych główek regulacyjnych, które przy wysokim stanie wody tworzą rybne warkocze. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z głębokimi rynnami wymytymi na szczytach ostróg brzegowych. To strategiczne miejsce dla łowców boleni, które agresywnie atakują stada uklei na styku nurtu głównego i spokojnych zatok. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na brania rekordowych stad leszczy oraz dorodnych cert. Uciąg rzeki w tym miejscu wymaga stosowania dociążonych koszyków zanętowych dla poprawnej stabilizacji zestawu na dnie. Dzikie brzegi porośnięte gęstą roślinnością zapewniają intymną atmosferę i szansę na kontakt z niewypłoszoną rybą rzeczną.', 'PZW Opole');

