VALUES (70652, 'Nizinna Wielka', 'Uregulowana, główki', 120.0, 3.0, 'Piasek i glina', 'Główki, warkocze', 'Boleń, Leszcz, Certa', 'Kraina leszcza', true);

-- Spot 654: Ostrava (Hrušov - soutok s Ostravicí)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70653, 'Odra - Ostrava (Hrušov)', 'odra-ostrava-hrusov', 'RIVER', 49.8605347, 18.2519672, 'Morawsko-Śląski', 'Ostrava', 'Odra v ostravském Hrušově je technicky zajímavý revír v místě významného soutoku s řekou Ostravicí. Větší průtok pod soutokem vytváří hluboké proudné rýhy v pískovém dně, které jsou domovem velkých parm a ostroretek. Je to strategické místo pro lov candátů na přívlač, kteří využívají kalnější vodu z přítoku k efektivnímu lovu drobné ryby. Rybáři zde s oblibou využívají zpevněné břehy pro pohodlný lov na feeder nebo položenou v hlavním tahu řeky. Tah vody je zde citelný a vyžaduje správné čtení proudnic pro úspěšnou prezentaci nástrahy přímo u dna. Navzdory průmyslovému okolí je zde rybí obsádka velmi bohatá díky migračním cestám ryb z dolních úseků toku.', 'ČRS - MO Ostrava');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70653, 'Mimopstruhová', 'Soutoková, hluboká', 45.0, 2.5, 'Písek a jíl', 'Mostní pilíře, soutok', 'Parma obecná, Candát obecný, Ostroretka stěhovavá', 'Pásmo parmové', false);

-- Spot 655: Ostrava (Antošovice - Hraniční pásmo)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70654, 'Odra - Ostrava (Antošovice)', 'odra-ostrava-antosovice', 'RIVER', 49.8884836, 18.3075065, 'Morawsko-Śląski', 'Ostrava', 'Odra v oblasti Antošovic se blíží k hranici s Polskem a koryto zde získává přírodnější charakter s četnými štěrkovými lavicemi. Řeka zde protéká klidnější oblastí mimo hlavní městskou zástavbu, což zaručuje nižší rybářský tlak a klidný lov. Dno je štěrkopískové s občasnými nánosy padlých větví, které tvoří přirozené úkryty pro velké tlouště a okouny. Přívlačoví rybáři zde s úspěchem loví štiky v tišinách za přírodními překážkami v korytě. Metoda lehkého feederu přináší výsledky v podobě pěkných plotic a cejnů, kteří se shromažďují v mírnějších proudech. Tato lokalita je ideální pro rybáře vyhledávající spojení mezi městským a divokým charakterem řeky Odry.', 'ČRS - MO Ostrava');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70654, 'Mimopstruhová', 'Přírodní, štěrková', 38.0, 1.8, 'Štěrk a písek', 'Štěrkové lavice', 'Jelec tloušť, Štika obecná, Plotice obecná', 'Pásmo parmové', false);

-- Spot 656: Lubnów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70655, 'Odra - Lubnów (Długie Główki)', 'odra-lubnow', 'RIVER', 51.2359781, 16.8713233, 'Dolnośląskie', 'Brzeg Dolny', 'Odra w Lubnowie to klasyczne łowisko nizinne słynące z regularnej linii długich ostróg brzegowych i głębokich rynien szczytowych. Podłoże jest tu twarde, piaszczysto-żwirowe, co stwarza idealne warunki tlenowe dla walecznych brzan oraz rzecznych boleni. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając sandaczy stacjonujących w cieniu podwodnych kamiennych raf. Wędkarze gruntowi chętnie nęcą tutejsze zatoki między główkami, celując w rekordowe leszcze oraz dorodne płocie żerujące na stokach. Uciąg rzeki jest tu zdecydowany i stabilny, co sprzyja naturalnej prezentacji przynęty w głównym nurcie koryta. Malowniczy krajobraz doliny Odry oraz wysoka rybność odcinka przyciągają wędkarzy szukających spokoju i szansy na rekordowe wyniki.', 'PZW Wrocław');

