VALUES (70655, 'Nizinna Wielka', 'Uregulowana, główki', 115.0, 3.0, 'Piasek i żwir', 'Główki, rynny', 'Sandacz, Boleń, Brzana', 'Kraina leszcza', true);

-- Spot 657: Stobrawa (Widły z Nysą Kłodzką)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70656, 'Odra - Stobrawa (Ujście Nysy)', 'odra-stobrawa', 'RIVER', 50.8204891, 17.6567944, 'Opolskie', 'Brzeg', 'Ujście Nysy Kłodzkiej do Odry w Stobrawie to jeden z najbardziej strategicznych punktów wędkarskich, gdzie zderzenie dwóch nurtów tworzy unikalne warunki tlenowe. Woda poniżej połączenia rzek jest głęboka i turbulentna, co przyciąga rekordowe sumy oraz sandacze żerujące na licznej drobnicy. To wymarzone miejsce dla spinningistów, którzy obławiają strefę styku wód w poszukiwaniu boleni patrolujących warkocze prądowe. Dno jest tu mocno urozmaicone, piaszczysto-kamieniste, z głębokimi dołami wymytymi przez krzyżujące się prądy obu rzek. Wędkarze stacjonarni z sukcesami łowią tu okazałe brzany, wykorzystując bardzo ciężkie zestawy gruntowe odporne na silny uciąg. Miejsce to zapewnia niezapomniane emocje wędkarskie w surowym, naturalnym krajobrazie na styku dwóch wielkich dorzeczy.', 'PZW Opole');

