VALUES (70656, 'Nizinna Wielka', 'Ujście rzeki, nurt żywy', 130.0, 4.0, 'Kamień i piasek', 'Warkocze prądowe', 'Sum, Sandacz, Brzana', 'Kraina leszcza', true);

-- Spot 658: Brzeg (Miejska)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70657, 'Odra - Brzeg (Bulwary)', 'odra-brzeg-miejska', 'RIVER', 50.8747728, 17.4555974, 'Opolskie', 'Brzeg', 'Miejski odcinek Odry w Brzegu to techniczne łowisko o uregulowanym charakterze z głębokimi rynnami pod filarami historycznych mostów. Podłoże jest tu twarde, piaszczysto-betonowe, co przyciąga sandacze oraz duże klenie szukające schronienia w cieniu konstrukcji. To doskonałe miejsce dla spinningistów, którzy wykorzystują miejskie umocnienia brzegowe do precyzyjnego prowadzenia przynęt w nurcie. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz płocie, wykorzystując metodę bata lub ciężkiego feedera rzecznego. Uciąg wody jest stabilny, co pozwala na komfortowe nęcenie i utrzymywanie stad ryb białego żeru w polu łowienia. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko popularnym punktem spotkań wędkarzy z całego regionu.', 'PZW Opole');

