VALUES (70657, 'Nizinna Wielka', 'Uregulowana miejska', 100.0, 3.5, 'Twardy piasek', 'Mosty, bulwary', 'Sandacz, Leszcz, Kleń', 'Kraina leszcza', true);

-- Spot 659: Żelazna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70658, 'Odra - Żelazna (Płanie)', 'odra-zelazna', 'RIVER', 50.7166171, 17.8807051, 'Opolskie', 'Opole', 'Odcinek w Żelaznej charakteryzuje się szerokim korytem i obecnością rozległych płani o piaszczysto-mulistym dnie powyżej Opola. Rzeka płynie tu dostojnie, oferując wędkarzom bardzo urozmaiconą linię brzegową z zatokami pełnymi roślinności wynurzonej. To doskonałe łowisko dla wędkarzy feederowych celujących w dorodne płocie oraz leszcze, które grupują się na krawędzi nurtu głównego. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz mniejszych szczupaków czatujących w cieniu wiklin. Uciąg rzeki jest tu łagodny, co pozwala na stosowanie najdelikatniejszych technik spławikowych oraz precyzyjne nęcenie punktowe. Miejsce to zapewnia ciszę i doskonałe warunki do całodniowego kontaktu z naturą w sielskim, nadodrzańskim krajobrazie.', 'PZW Opole');

