VALUES (70658, 'Nizinna Wielka', 'Szeroka płania, nurt łagodny', 110.0, 2.5, 'Piasek i muł', 'Zatoki brzegowe', 'Płoć, Leszcz, Okoń', 'Kraina leszcza', true);

-- Spot 660: Dobrzeń Mały (Elektrownia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70659, 'Odra - Dobrzeń Mały (Ciepła Woda)', 'odra-dobrzen-maly', 'RIVER', 50.7536966, 17.8275307, 'Opolskie', 'Opole', 'Odra w Dobrzeniu Małym to unikalne łowisko pozostające pod silnym wpływem zrzutów wody z Elektrowni Opole oraz ujścia Małej Panwi. Woda jest tu silnie natleniona i często cieplejsza niż w innych odcinkach, co aktywuje ryby do żerowania nawet w okresie zimowym. To strategiczne miejsce dla łowców walecznych brzan oraz jazi, które doskonale reagują na techniki spinningowe i gruntowe w silnym nurcie. Dno jest piaszczysto-żwirowe z licznymi kamienistymi rafami, które stanowią bankowe stanowiska dla drapieżników żerujących o zmierzchu. Uciąg wody jest tu zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu na dnie rzeki. Dzięki specyficznym warunkom termicznym, odcinek ten oferuje jedne z najbardziej stabilnych wyników wędkarskich w całym województwie.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70659, 'Nizinna Wielka', 'Techniczna, ujściowa', 115.0, 3.2, 'Piasek i żwir', 'Zrzut wody, kamieniste rafy', 'Brzana, Jaź, Sandacz', 'Kraina leszcza', true);

-- Spot 661: Krapkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70660, 'Odra - Krapkowice (Jazy)', 'odra-krapkowice', 'RIVER', 50.4652861, 17.9963176, 'Opolskie', 'Krapkowice', 'Krapkowicki odcinek Odry to techniczne łowisko miejskie zdominowane przez obecność stopnia wodnego i betonowych umocnień koryta. Woda poniżej jazu jest turbulentna i doskonale natleniona, co przyciąga sandacze, sumy oraz dorodne okonie żerujące na uklejach. To strategiczne miejsce dla spinningistów, którzy wykorzystują głębokie doły pod murami oporowymi do precyzyjnego prowadzenia ciężkich jigów. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie w rynnach wymytych przez silny prąd rzeki. Uciąg wody jest uzależniony od aktualnej pracy urządzeń hydrotechnicznych, co wymusza na wędkarzach częstą adaptację ciężaru zestawów. Dobra infrastruktura i bliskość centrum miasta czynią to miejsce bardzo atrakcyjnym dla pasjonatów technicznego wędkarstwa rzecznego.', 'PZW Opole');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70660, 'Nizinna Wielka', 'Uregulowana, techniczna', 120.0, 4.0, 'Beton i twardy piasek', 'Jazy, śluzy', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', false);

-- Spot 662: Odrowąż
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70661, 'Odra - Odrowąż (Meandry)', 'odra-odrowaz', 'RIVER', 50.504712, 17.9465501, 'Opolskie', 'Krapkowice', 'Odra w Odrowążu to malowniczy odcinek charakteryzujący się naturalnymi meandrami i głębokimi rynnami na zewnętrznych łukach koryta. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z licznymi podmyłymi burtami, które stanowią bezpieczną ostoję dla rekordowych brzan. To doskonałe łowisko dla wędkarzy feederowych celujących w duże leszcze oraz rzeczne płocie żerujące na krawędziach nurtu. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni oraz kleni pod nadrzecznymi nawisami wikliny. Uciąg wody jest stabilny i żywy, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich miesięcy o niskim stanie rzeki. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z niewypłoszoną rybą w otoczeniu dzikiej, nadodrzańskiej przyrody.', 'PZW Opole');

