VALUES (70661, 'Nizinna Wielka', 'Meandrująca, naturalna', 100.0, 2.5, 'Piasek i glina', 'Podmyte brzegi', 'Leszcz, Brzana, Boleń', 'Kraina leszcza', true);

-- Spot 663: Rozwadza (Śluza Januszkowice)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70662, 'Odra - Rozwadza (Rejon Śluzy)', 'odra-rozwadza', 'RIVER', 50.4287768, 18.0632806, 'Opolskie', 'Zdzieszowice', 'Odra w Rozwadzy to techniczne łowisko o silnie uregulowanym charakterze, pozostające pod bezpośrednim wpływem pracy śluzy Januszkowice. Koryto rzeki posiada tu twarde, piaszczysto-betonowe dno z głębokimi rynnami wymytymi przez zrzuty wody z urządzeń hydrotechnicznych. To strategiczne miejsce dla łowców okazowych sandaczy, które wykorzystują uskoki dna przy murach oporowych jako swoje ostoje. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze oraz rekordowe krąpie, wykorzystując metodę ciężkiego feedera rzecznego. Uciąg wody jest tu zdecydowany i zależy od aktualnej pracy stopnia wodnego, co wymaga od wędkarza częstej adaptacji masy zestawu. Dobra infrastruktura brzegowa i natleniona woda sprawiają, że ryby są tu aktywne praktycznie przez cały sezon wędkarski.', 'PZW Opole');

