-- Spot 664: Racibórz (Bulwary Miejskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70663, 'Odra - Racibórz (Miejska)', 'odra-raciborz-centrum', 'RIVER', 50.0604297, 18.2291826, 'Śląskie', 'Racibórz', 'Odra w Raciborzu to odcinek górnej rzeki o urozmaiconym, żwirowo-kamienistym dnie i żywym nurcie wody. Pod mostami i w rejonie miejskich bulwarów rzeka wymyła głębokie doły, które są naturalną kryjówką dla dużych kleni oraz jazi. To doskonałe łowisko dla spinningistów polujących na pstrągi potokowe, które okresowo spływają tu z wyższych, górskich partii dorzecza. Wędkarze gruntowi chętnie nęcą tutejsze płanie żwirowe, celując w waleczne brzany oraz świnki doskonale czujące się w silnym prądzie. Uciąg rzeki jest stabilny, co sprzyja naturalnej prezentacji przynęty przy użyciu techniki przepływanki z ciężkim spławikiem. Miejska infrastruktura zapewnia komfortowy dostęp do linii brzegowej, czyniąc to miejsce popularnym punktem spotkań pasjonatów wędkarstwa podgórskiego.', 'PZW Katowice');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70663, 'Nizinna Wielka', 'Podgórska, nurt żywy', 45.0, 1.8, 'Żwir i kamień', 'Mosty, progi', 'Kleń, Brzana, Pstrąg potokowy', 'Kraina lipienia', false);

-- Spot 665: Grzegorzowice (Prom)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70664, 'Odra - Grzegorzowice (Głęboka Rynna)', 'odra-grzegorzowice', 'RIVER', 50.1761672, 18.2533475, 'Śląskie', 'Racibórz', 'Odcinek w Grzegorzowicach charakteryzuje się naturalnym przebiegiem koryta z wyraźnie zaznaczonymi rynnami prądowymi na łukach rzeki. Podłoże jest tu piaszczysto-żwirowe z licznymi podmyłymi burtami, które stanowią bezpieczną ostoję dla rekordowych kleni oraz boleni. To strategiczne miejsce dla spinningistów szukających sandaczy czatujących w głębszych dołkach wymytych przez nurt w rejonie dawnej przeprawy promowej. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz certy, wykorzystując systematyczne nęcenie na krawędzi nurtu głównego. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały rok. Malowniczy krajobraz doliny górnej Odry oraz niska presja wędkarska gwarantują spokój i szansę na kontakt z dziką rybą.', 'PZW Katowice');

