-- Spot 666: Przewóz (Górna Odra)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70665, 'Odra - Przewóz (Bystrza)', 'odra-przewoz-slaskie', 'RIVER', 50.2212773, 18.2509074, 'Opolskie', 'Kędzierzyn-Koźle', 'Odra w Przewozie to technicznie wymagające łowisko o charakterze podgórskim z licznymi żwirowymi łachami i bystrzami. Rzeka tworzy tu techniczne stanowiska pod nawisami nadrzecznych wierzb, które skrywają dorodne klenie żerujące pod powierzchnią. To doskonałe miejsce dla spinningistów polujących na bolenie, wykorzystujących turbulentną wodę na styku nurtu głównego i bocznych zastoisk. Wędkarze gruntowi chętnie nęcą tutejsze rynny, licząc na brania walecznych brzan oraz świnek wchodzących w rzekę z dopływów. Uciąg wody jest tu żywy i zmienny, co wymaga od wędkarza umiejętnego czytania prądów oraz wirów wstecznych. Niska presja wędkarska w tym rejonie zapewnia intymną atmosferę i szansę na sukcesy przy użyciu delikatnych zestawów spławikowych.', 'PZW Opole');

