-- Spot 667: Roszowicki Las
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70666, 'Odra - Roszowicki Las (Główki)', 'odra-roszowicki-las', 'RIVER', 50.2651625, 18.2300666, 'Opolskie', 'Kędzierzyn-Koźle', 'Odra w Roszowickim Lesie to odcinek uregulowany z dobrze zachowanymi główkami i głębokimi klatkami między nimi. Podłoże jest tu piaszczysto-żwirowe z wyraźnymi uskokami na szczytach ostróg, gdzie chętnie stacjonują sandacze oraz duże okonie. To strategiczne miejsce dla wędkarzy feederowych celujących w rekordowe leszcze żerujące w spokojniejszych warkoczach prądowych za główkami. Spinningiści z sukcesami polują tu na bolenie oraz klenie, obławiając krawędzie głównego nurtu przy użyciu szybkich przynęt powierzchniowych. Uciąg rzeki jest tu stabilny i zdecydowany, co sprzyja systematycznemu nęceniu i utrzymywaniu stad ryb w łowisku. Bliskość lasów łęgowych nadaje temu łowisku dziki charakter, mimo technicznego uregulowania koryta przez budowle regulacyjne.', 'PZW Opole');

