-- Spot 668: Lubomia (Rejon Polderu)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70667, 'Odra - Lubomia (Rozlewiska)', 'odra-lubomia', 'RIVER', 50.014949, 18.2776525, 'Śląskie', 'Wodzisław Śląski', 'Odra w Lubomi płynie szeroką doliną w sąsiedztwie Polderu Buków, co nadaje jej charakter rzeki o ogromnym potencjale zalewowym. Koryto posiada tu piaszczysto-muliste dno z licznymi zastoiskami i starorzeczami łączącymi się z nurtem podczas wysokich stanów wody. To wymarzone miejsce dla łowców sumów, którzy wykorzystują głębokie rynny pod brzegowymi faszynami jako swoje dzienne ostoje. Wędkarze gruntowi chętnie nęcą tutejsze płanie, licząc na brania rekordowych leszczy oraz walecznych amurów migrujących ze zbiorników retencyjnych. Uciąg rzeki jest tu łagodny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi oraz precyzyjne nęcenie punktowe. Naturalna rzeźba terenu i bliskość rezerwatu przyrody sprawiają, że rybostan jest tu wyjątkowo bogaty i zróżnicowany gatunkowo.', 'PZW Katowice');

