-- Spot 669: gmina Nowa Sól (Stara Wieś)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70668, 'Odra - Nowa Sól (Kraina Główek)', 'odra-nowa-sol', 'RIVER', 51.8616383, 15.7754705, 'Lubuskie', 'Nowa Sól', 'Odra w gminie Nowa Sól to klasyczny odcinek rzeki nizinnej o bardzo regularnej linii główek regulacyjnych i szerokich klatkach między nimi. Dno jest tu twarde, piaszczysto-żwirowe, co sprzyja bytowaniu rekordowych sandaczy oraz walecznych brzan żerujących w rynnach szczytowych. To strategiczne miejsce dla spinningistów, którzy obławiają warkocze prądowe na styku nurtu głównego i spokojnych zastoisk. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz certy, wykorzystując metodę ciężkiego feedera dla stabilizacji zestawu na dnie. Uciąg rzeki jest zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką aktywność ryb nawet podczas letnich upałów. Dobra dostępność brzegów oraz specyfika lubuskiej Odry czynią to łowisko popularnym punktem spotkań wędkarzy z całego regionu.', 'PZW Zielona Góra');

