-- Spot 670: Pomorsko (Przeprawa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70669, 'Odra - Pomorsko (Rynna Promowa)', 'odra-pomorsko', 'RIVER', 52.0419165, 15.4963624, 'Lubuskie', 'Sulechów', 'Odcinek w Pomorsku charakteryzuje się obecnością przeprawy promowej, która wymusza na rzece utrzymanie głębokiej i stabilnej rynny w korycie głównym. Rzeka żłobi tu dno o piaszczystym charakterze z wyraźnymi uskokami, które stanowią bankowe stanowiska dla sumów oraz sandaczy. To doskonałe łowisko dla spinningistów polujących na bolenie, wykorzystujących turbulentną wodę na styku nurtu i brzegowych zastoisk. Wędkarze gruntowi chętnie nęcą tutejsze płanie żwirowe, celując w dorodne klenie oraz waleczne brzany żerujące w nurcie. Uciąg wody jest tu silny i żywy, co wymaga stosowania dociążonych koszyków zanętowych dla poprawnej prezentacji przynęty. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z niewypłoszoną rybą w otoczeniu sielskiego, lubuskiego krajobrazu.', 'PZW Zielona Góra');

