-- Spot 671: Głogów (Odcinek Dolny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70670, 'Odra - Głogów (Wielki Nurt)', 'odra-glogow-dolna', 'RIVER', 51.6767019, 16.0336842, 'Dolnośląskie', 'Głogów', 'Odra w dolnej części Głogowa to potężna rzeka nizinna o szerokim korycie i technicznych brzegach umocnionych faszyną oraz głazami. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z głębokimi rynnami wymytymi na łukach rzeki, stanowiącymi ostoje dla sumów. To strategiczne miejsce dla łowców okazowych leszczy, którzy wykorzystują systematyczne nęcenie na piaszczystych blatach koryta głównego. Spinningiści z sukcesami obławiają tutejsze opaski brzegowe, szukając sandaczy oraz okazowych okoni stacjonujących w nurcie. Uciąg jest zdecydowany i stabilny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. Dobra infrastruktura miejska i liczne stanowiska sprawiają, że jest to chętnie wybierane miejsce na wielogodzinne zasiadki.', 'PZW Legnica');

