-- Spot 672: Ceber
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70671, 'Odra - Ceber (Dzikie Zakola)', 'odra-ceber', 'RIVER', 51.7062215, 15.9667981, 'Dolnośląskie', 'Głogów', 'Odcinek w Cebrze charakteryzuje się naturalnym przebiegiem koryta z wyraźnie zaznaczonymi rynnami prądowymi na łukach i dzikimi burtami. Rzeka tworzy tu liczne, piaszczyste przykosy wychodzące daleko w główny nurt, które są ulubionym miejscem żerowania boleni. To wymarzone stanowisko dla wędkarzy feederowych celujących w duże płocie oraz leszcze żerujące na krawędzi nurtu i zastoiska. Podłoże jest piaszczysto-żwirowe, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb spokojnego żeru. Uciąg wody jest tu żywy i zmienny, co wymaga od wędkarza umiejętnego czytania prądów oraz wirów wstecznych. Niska presja wędkarska oraz utrudniony dostęp do brzegów gwarantują spokój i kontakt z dziką naturą rzeki swobodnie płynącej.', 'PZW Legnica');

