-- Spot 673: gmina Siedlisko (Zamek)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70672, 'Odra - Siedlisko (Pod Zamkiem)', 'odra-siedlisko', 'RIVER', 51.7302694, 15.9029246, 'Lubuskie', 'Nowa Sól', 'Odra w Siedlisku to jedno z najbardziej malowniczych łowisk w regionie, płynące szerokim korytem u stóp historycznego zamku rycerskiego. Rzeka posiada tu twarde, kamienisto-żwirowe dno z głębokimi rynnami wymytymi pod wysokimi burtami brzegowymi. To doskonałe miejsce dla spinningistów polujących na okazowe klenie oraz sandacze stacjonujące w cieniu zatopionych korzeni i faszyn. Wędkarze stacjonarni z sukcesami łowią tu waleczne brzany oraz rekordowe leszcze, wykorzystując systematyczne nęcenie w głównym nurcie. Uciąg wody jest zdecydowany i stabilny, co sprzyja wysokiej kondycji ryb oraz ich dużej aktywności żerowej. Unikalna sceneria oraz wysoka rybność odcinka czynią to miejsce absolutnie obowiązkowym punktem na mapie każdego fana rzecznego spinningu.', 'PZW Zielona Góra');

