-- Spot 674: Przytoczki (k. Sulechowa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70673, 'Odra - Przytoczki (Łachy)', 'odra-przytoczki', 'RIVER', 51.9905687, 15.6612073, 'Lubuskie', 'Sulechów', 'Odcinek w Przytoczkach słynie z rozległych piaszczystych łach i przykos, które dynamicznie zmieniają swój kształt przy każdym wezbraniu rzeki. Rzeka płynie tu dostojnie, oferując wędkarzom piaszczysto-muliste dno z licznymi zastoiskami idealnymi dla ryb spokojnego żeru. To strategiczne miejsce dla łowców szczupaków oraz sandaczy, którzy obławiają krawędzie roślinności zanurzonej przy brzegach. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w dorodne leszcze oraz wyrośnięte krąpie migrujące korytem głównym. Uciąg wody jest łagodny i przewidywalny, co pozwala na komfortowe operowanie delikatnymi zestawami spławikowymi z długim wędziskiem. Niska presja w tym rejonie zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z niewypłoszoną, dużą rybą rzeczną.', 'PZW Zielona Góra');

