-- Spot 675: gmina Czerwieńsk (Laski)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70674, 'Odra - gmina Czerwieńsk (Laski)', 'odra-czerwiensk-laski', 'RIVER', 52.0605195, 15.4242459, 'Lubuskie', 'Zielona Góra', 'Odra w gminie Czerwieńsk, w rejonie miejscowości Laski, charakteryzuje się głębokimi rynnami przydennymi i silnie zarysowaną linią główek regulacyjnych. Podłoże jest tu twarde, piaszczysto-żwirowe, co tworzy idealne warunki dla sandaczy żerujących wzdłuż uskoków dna. To strategiczne miejsce dla spinningistów szukających boleni, które agresywnie atakują drobnicę w turbulentnych warkoczach za szczytami ostróg. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w dorodne stadne leszcze oraz waleczne brzany żerujące w głównym nurcie. Uciąg rzeki jest zdecydowany i stabilny, co wymaga stosowania dociążonych koszyków zanętowych dla poprawnej prezentacji przynęty. Dzika natura brzegów i niska presja wędkarska sprawiają, że jest to jedno z najciekawszych łowisk w regionie lubuskim.', 'PZW Zielona Góra');

