-- Spot 676: Nietków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70675, 'Odra - Nietków (Piaszczyste Przykosy)', 'odra-nietkow', 'RIVER', 52.0470969, 15.3485974, 'Lubuskie', 'Zielona Góra', 'Odcinek w Nietkowie słynie z rozległych piaszczystych przykos, które dynamicznie zmieniają swój kształt przy każdym wezbraniu rzeki. Koryto posiada tu piaszczyste dno z wyraźnymi rynnami na łukach, stanowiącymi bezpieczną ostoję dla dorodnych leszczy oraz krąpi. To doskonałe łowisko dla spinningistów polujących na szczupaki, którzy obławiają krawędzie roślinności wynurzonej przy brzegowych zastoiskach. Uciąg wody jest tu żywy i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb spokojnego żeru. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera klasycznego, celując w ryby migrujące korytem głównym w poszukiwaniu pokarmu. Malowniczy krajobraz pradoliny Odry zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z niewypłoszoną rybą.', 'PZW Zielona Góra');

