VALUES (70675, 'Nizinna Wielka', 'Szeroka, przykosy', 155.0, 2.8, 'Piaszczyste', 'Przykosy piaszczyste', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', true);

-- Spot 677: Cigacice (Mosty)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70676, 'Odra - Cigacice (Port i Mosty)', 'odra-cigacice', 'RIVER', 52.0300738, 15.6143493, 'Lubuskie', 'Zielona Góra', 'Cigacice to techniczne łowisko o ogromnym potencjale, charakteryzujące się obecnością portu rzecznego oraz głębokich rynien pod filarami mostów. Podłoże jest tu twarde, piaszczysto-kamieniste, co przyciąga sandacze oraz duże okonie szukające schronienia w cieniu konstrukcji hydrotechnicznych. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie doły wymyte przez silny nurt pod mostami jako swoje dzienne ostoje. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni oraz kleni żerujących w turbulentnym nurcie rzeki. Uciąg wody jest stabilny, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w polu łowienia przez wiele godzin. Dobra infrastruktura turystyczna i łatwy dostęp do wody czynią to miejsce popularnym punktem spotkań wędkarzy.', 'PZW Zielona Góra');

