VALUES (70676, 'Nizinna Wielka', 'Uregulowana, techniczna', 170.0, 4.0, 'Piasek i kamień', 'Port, mosty, śluzy', 'Sandacz, Sum, Boleń', 'Kraina leszcza', true);

-- Spot 678: Będów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70677, 'Odra - Będów (Starorzecza)', 'odra-bedow', 'RIVER', 52.0587064, 15.2772092, 'Lubuskie', 'Czerwieńsk', 'Odra w Będowie charakteryzuje się obecnością licznych zatok i starorzeczy, które łączą się z nurtem głównym podczas wysokich stanów wody. Rzeka żłobi tu dno o charakterze piaszczysto-mulistym z bogatą roślinnością wynurzoną, co sprzyja aktywności szczupaków i okoni. To doskonałe łowisko dla wędkarzy gruntowych celujących w dorodne liny oraz rzeczne leszcze w zacisznych klatkach między główkami. Uciąg wody jest umiarkowany i przewidywalny, co pozwala na precyzyjne nęcenie punktowe i stosowanie delikatnych zestawów spławikowych. Spinningista znajdzie tutaj dogodne miejsca do prowadzenia przynęt powierzchniowych wzdłuż brzegowych wiklin w poszukiwaniu drapieżników. Niska presja wędkarska w tym rejonie gwarantuje spokój i doskonałe warunki do całodniowego odpoczynku z wędką.', 'PZW Zielona Góra');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70677, 'Nizinna Wielka', 'Szeroka, liczne zatoki', 160.0, 2.5, 'Piasek i muł', 'Zatoki, starorzecza', 'Szczupak, Lin, Leszcz', 'Kraina leszcza', true);

-- Spot 679: Gostchorze (Kamieniste Rafy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70678, 'Odra - Gostchorze (Przelew)', 'odra-gostchorze', 'RIVER', 52.0661452, 15.2035899, 'Lubuskie', 'Krosno Odrzańskie', 'Gostchorze to legendarne łowisko słynące z kamienistych raf i silnych warkoczy prądowych na środku nurtu głównego rzeki. Podłoże jest tu twarde, piaszczysto-żwirowe, co stwarza idealne warunki tlenowe dla walecznych brzan oraz rekordowych sandaczy. To strategiczne stanowisko dla spinningistów, którzy wykorzystują turbulentną wodę na przelewach do łowienia boleni żerujących agresywnie na uklejach. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując metodę feedera klasycznego z dociążonym zestawem na krawędzi nurtu. Uciąg rzeki jest zdecydowany, co wymaga od wędkarza umiejętnego czytania prądów oraz wirów wstecznych dla poprawnej prezentacji przynęty. Malowniczy krajobraz nadodrzański oraz wysoka rybność odcinka czynią to łowisko jednym z najciekawszych na mapie regionu.', 'PZW Zielona Góra');

