-- Spot 680: Chyże
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70679, 'Odra - Chyże (Łęgi)', 'odra-chyze', 'RIVER', 52.0468006, 15.1332321, 'Lubuskie', 'Krosno Odrzańskie', 'Odcinek w Chyżach charakteryzuje się szerokimi płaniami o wyrównanym dnie i obecnością piaszczystych przykos wychodzących daleko w nurt. Rzeka płynie tu dostojnie przez rozległe łęgi, oferując wędkarzom piaszczysto-muliste dno z licznymi podmyłymi burtami brzegowymi. To doskonałe łowisko dla wędkarzy feederowych celujących w dorodne leszcze oraz rzeczne płocie migrujące głównym korytem. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając szczupaków czatujących w cieniu nadrzecznej roślinności brzegowej. Uciąg wody jest stabilny i przewidywalny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w łowisku. Miejsce to zapewnia intymną atmosferę i szansę na kontakt z niewypłoszoną rybą w surowym krajobrazie pradoliny Odry.', 'PZW Zielona Góra');

