-- Spot 681: Marcinowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70680, 'Odra - Marcinowice (Rynny Szczytowe)', 'odra-marcinowice-2', 'RIVER', 52.0578457, 15.0563317, 'Lubuskie', 'Krosno Odrzańskie', 'Odra w Marcinowicach to odcinek słynący z głębokich rynien przy szczytach główek oraz piaszczystych płani wewnątrz klatek międzyostrogowych. Dno jest tu twarde i piaszczysto-żwirowe, co sprzyja bytowaniu sandaczy oraz walecznych kleni żerujących w głównym nurcie. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe przy użyciu ciężkich jigów prowadzone w agresywnym opadzie przy samym dnie. Wędkarze stacjonarni nęcą rynny na krawędzi nurtu, licząc na brania rekordowych leszczowych stad migrujących korytem głównym. Uciąg wody jest stabilny i zdecydowany, co zapewnia doskonałe warunki tlenowe rybom nawet podczas letnich niżówek rzeki. To technicznie wymagające łowisko nagradza wytrwałych wędkarzy szansą na kontakt z potężną, rzeczną rybą w surowym krajobrazie lubuskim.', 'PZW Zielona Góra');

