-- Spot 682: Sarbia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70681, 'Odra - Sarbia (Piaszczyste Przykosy)', 'odra-sarbia', 'RIVER', 52.0526236, 14.9830554, 'Lubuskie', 'Krosno Odrzańskie', 'Odcinek Odry w Sarbii charakteryzuje się szerokim korytem i obecnością licznych piaszczystych przykos, które dynamicznie zmieniają swój kształt po przyborach. Rzeka żłobi tu dno o piaszczysto-mulistym charakterze, tworząc dogodne ostoje dla sumów oraz sandaczy w głębokich rynnach na łukach. To doskonałe łowisko dla spinningistów polujących na bolenie, które agresywnie atakują ukleje na styku głównego nurtu i brzegowych zastoisk. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, celując w dorodne płocie oraz rzeczne krąpie na metodę klasycznego feedera. Uciąg rzeki jest umiarkowany i przewidywalny, co sprzyja precyzyjnemu nęceniu punktowemu przy użyciu dużych klatek zanętowych z grubą frakcją. Malowniczy krajobraz pradoliny Odry oraz niska presja wędkarska w tym rejonie gwarantuje spokój podczas całodniowych sesji nad wodą.', 'PZW Zielona Góra');

