-- Spot 683: Połęcko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70682, 'Odra - Połęcko (Bystrza i Prom)', 'odra-polecko', 'RIVER', 52.0471373, 14.9048825, 'Lubuskie', 'Krosno Odrzańskie', 'Odra w Połęcku to techniczne łowisko o ogromnym potencjale, charakteryzujące się obecnością przeprawy promowej i specyficznym ukształtowaniem rynny głównej. Podłoże jest tu twarde, żwirowe z wyraźnymi rynnami prądowymi, które stanowią bankowe stanowiska dla brzan oraz rzecznych kleni. To strategiczne miejsce dla spinningistów, którzy obławiają podmyte faszynowe opaski w poszukiwaniu szczupaków oraz dużych, rzecznych okoni. Uciąg wody jest tu żywy i zdecydowany, co sprzyja doskonałemu natlenieniu wody oraz wysokiej aktywności ryb reofilnych przez cały rok. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie na stokach głębokich rynien koryta głównego. Bliskość ujścia rzeki Bóbr sprawia, że rybostan jest tu wyjątkowo zróżnicowany i regularnie zasilany migracjami ryb z dopływów.', 'PZW Zielona Góra');

