-- Spot 684: Siedlisko (k. Nowej Soli)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70683, 'Odra - Siedlisko (Pod Zamkiem)', 'odra-siedlisko-2', 'RIVER', 51.7520928, 15.8109846, 'Lubuskie', 'Nowa Sól', 'Odcinek w Siedlisku to kwintesencja lubuskiej Odry z potężnymi ostrogami brzegowymi i głębokimi klatkami o piaszczystym podłożu dna. Rzeka płynie tu szerokim korytem, oferując wędkarzom techniczne stanowiska na szczytach główek idealne do polowania na rekordowe bolenie. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając sandaczy stacjonujących w cieniu podwodnych kamiennych nasypów i raf. Wędkarze gruntowi nęcą tutejsze spowolnienia nurtu, celując w rekordowe leszcze oraz rzadziej spotykane, dorodne liny rzeczne. Uciąg rzeki jest stabilny i przewidywalny, co pozwala na komfortowe operowanie zestawami feederowymi z dociążonym koszykiem zanętowym. Malownicza okolica z widokiem na ruiny zamku w Siedlisku nadaje każdej wyprawie wędkarskiej wyjątkowego i historycznego klimatu.', 'PZW Zielona Góra');

