-- Spot 685: Stara Wieś
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70684, 'Odra - Stara Wieś (Łęgi)', 'odra-stara-wies', 'RIVER', 51.7855156, 15.748839, 'Lubuskie', 'Nowa Sól', 'Odra w Starej Wsi to rzeka o dojrzałym, nizinnym charakterze z licznymi zastoiskami i starorzeczami łączącymi się okresowo z nurtem głównym. Koryto posiada tu piaszczysto-muliste dno z wyraźnymi uskokami na krawędzi nurtu, gdzie chętnie grupują się duże leszczowe stada. To wymarzone miejsce dla łowców szczupaków, którzy obławiają pasy roślinności zanurzonej przy brzegowych opaskach faszynowych i w klatkach. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy nadrzecznych nawisach gęstych wiklin. Uciąg wody jest łagodny, co sprzyja naturalnej prezentacji przynęty przy użyciu techniki spławikowej z długim wędziskiem rzecznym. Niska presja wędkarska oraz bogactwo ryb spokojnego żeru czynią ten odcinek rzeki bardzo atrakcyjnym punktem na mapie regionu.', 'PZW Zielona Góra');

