-- Spot 686: Jurcz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70685, 'Odra - Jurcz (Kamieniste Rafy)', 'odra-jurcz', 'RIVER', 51.2978713, 16.4210673, 'Dolnośląskie', 'Ścinawa', 'Odra w Jurczu to technicznie wymagające łowisko o urozmaiconym dnie i silnie zarysowanej linii brzegowej z naturalnymi kamienistymi rafami. Rzeka żłobi tu głębokie rynny w twardym, żwirowym podłożu, co stwarza doskonałe warunki tlenowe dla walecznych i silnych brzan. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając okazowych kleni oraz sandaczy żerujących na granicy głównego nurtu. Uciąg jest tu zdecydowany i żywy, co wymaga stosowania dociążonych przynęt dla stabilnej prezentacji zestawu spinningowego blisko dna. Wędkarze gruntowi chętnie nęcą tutejsze płanie żwirowe, licząc na brania rekordowych cert oraz rzecznych świnek wchodzących w rzekę. Malowniczy krajobraz pradoliny Odry oraz dziki charakter brzegów zapewniają wędkarzowi całkowity spokój i szansę na kontakt z surową naturą.', 'PZW Legnica');

