-- Spot 687: Malczyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70686, 'Odra - Malczyce (Portowy Nurt)', 'odra-malczyce', 'RIVER', 51.2269002, 16.4906952, 'Dolnośląskie', 'Środa Śląska', 'Odra w Malczycach to historyczny odcinek portowy o głębokim korycie i technicznych brzegach umocnionych faszyną. Miejsce to słynie z potężnych sandaczy, które chętnie stacjonują w cieniu starych konstrukcji hydrotechnicznych i betonowych nabrzeży. Wędkarze gruntowi z sukcesami nęcą tutejsze rynny, licząc na brania rekordowych leszczy oraz dorodnych cert. Uciąg jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet w najgorętsze dni lata 2026 roku. Podłoże jest twarde, piaszczysto-żwirowe, co ułatwia precyzyjne prowadzenie ciężkich przynęt spinningowych w pobliżu dna. Odcinek ten pozostaje jednym z najbardziej przewidywalnych łowisk drapieżników na całym Dolnym Śląsku.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70686, 'Nizinna Wielka', 'Uregulowana, portowa', 110.0, 3.5, 'Twardy piasek', 'Nabrzeża portowe', 'Sandacz, Leszcz, Certa', 'Kraina leszcza', true);

-- Spot 688: Boraszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70687, 'Odra - Boraszyn (Główki)', 'odra-boraszyn', 'RIVER', 51.377928, 16.4701869, 'Dolnośląskie', 'Wołów', 'Odcinek w Boraszynie to klasyczne łowisko nizinne z regularną linią główek i głębokimi klatkami między nimi. Rzeka żłobi tu dno o charakterze piaszczystym, tworząc idealne ostoje dla stad leszczy oraz walecznych brzan żerujących w warkoczach. Spinningiści z sukcesami obławiają szczyty ostróg brzegowych, szukając boleni patrolujących turbulentną wodę na styku nurtu. Spokojniejsze zastoiska w klatkach to doskonałe miejsca na nocne zasiadki w poszukiwaniu rzecznych sumów oraz lina. Uciąg rzeki w tym miejscu jest stabilny, co pozwala na komfortowe nęcenie i utrzymywanie ryb w polu łowienia. Miejsce to zapewnia intymną atmosferę dzięki dzikim, gęsto porośniętym wikliną brzegom.', null);

