VALUES (70687, 'Nizinna Wielka', 'Uregulowana, główki', 125.0, 2.8, 'Piasek', 'Główki, zastoiska', 'Leszcz, Brzana, Boleń', 'Kraina leszcza', true);

-- Spot 689: Przyborów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70688, 'Odra - Przyborów (Meandry)', 'odra-przyborow', 'RIVER', 51.4217407, 16.4445998, 'Dolnośląskie', 'Ścinawa', 'Odra w Przyborowie charakteryzuje się naturalnym przebiegiem koryta z wyraźnie zaznaczonymi rynnami prądowymi na łukach. Podłoże jest tu piaszczysto-żwirowe z licznymi podmyłymi burtami, które stanowią bezpieczną ostoję dla rekordowych kleni. To strategiczne miejsce dla spinningistów polujących na bolenie, wykorzystujących piaszczyste przykosy jako punkty obserwacyjne drapieżników. Wędkarze stacjonarni nęcą tutejsze płanie, celując w dorodne płocie oraz rzadziej spotykane w tym rejonie świnki. Uciąg rzeki jest żywy i zmienny, co wymaga od wędkarza umiejętnego czytania prądów oraz wirów wstecznych. Niska presja wędkarska gwarantuje spokój i szansę na kontakt z niewypłoszoną rybą w malowniczym krajobrazie.', null);

