VALUES (70688, 'Nizinna Wielka', 'Naturalna, meandrująca', 130.0, 2.2, 'Piasek i żwir', 'Podmyte brzegi', 'Kleń, Boleń, Leszcz', 'Kraina leszcza', true);

-- Spot 690: Ciechłowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70689, 'Odra - Ciechłowice (Jamy Sumowe)', 'odra-ciechlowice', 'RIVER', 51.491894, 16.4535896, 'Dolnośląskie', 'Rudna', 'Odcinek w Ciechłowicach słynie z wyjątkowo głębokich rynien i dołów wymytych w twardym, gliniastym dnie koryta. Jest to wymarzone stanowisko dla łowców sumów, którzy wykorzystują tutejsze jamy jako główne ostoje podczas dziennego odpoczynku drapieżników. Spinningiści z sukcesami obławiają uskoki dna w poszukiwaniu sandaczy żerujących na stadach krąpi i uklei. Uciąg rzeki jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji walecznych brzan. Wędkarze gruntowi chętnie nęcą piaszczyste blaty na wejściu w rynny, licząc na brania okazałych, rzecznych leszczy. Dzikie i trudnodostępne brzegi sprawiają, że ryby czują się tu bezpiecznie i osiągają imponujące rozmiary.', null);

