VALUES (70689, 'Nizinna Wielka', 'Szeroka, głębokie rynny', 140.0, 4.2, 'Glina i piasek', 'Głębokie jamy', 'Sum, Sandacz, Brzana', 'Kraina leszcza', true);

-- Spot 691: Chobienia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70690, 'Odra - Chobienia (Przeprawa i Most)', 'odra-chobienia', 'RIVER', 51.5371995, 16.4586589, 'Dolnośląskie', 'Chobienia', 'Odra w Chobieni to techniczne łowisko o urozmaiconej rzeźbie dna w pobliżu mostu i dawnej przeprawy promowej. Pod filarami konstrukcji rzeka wymyła głębokie rynny, które są doskonałym stanowiskiem dla sandaczy oraz dużych okoni. To strategiczne miejsce dla spinningistów, którzy wykorzystują turbulentne warkocze prądowe do polowania na rekordowe bolenie. Wędkarze stacjonarni z sukcesami łowią tu okazałe klenie i jazie, stosując technikę przepływanki z ciężkim spławikiem rzecznym. Uciąg wody jest stabilny, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu w polu łowienia. Dobra infrastruktura oraz łatwy dostęp do wody czynią to łowisko popularnym punktem na wędkarskiej mapie Dolnego Śląska.', null);

