-- Spot 692: Bartošovice (Czechy - Poodří)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70691, 'Odra - Bartošovice (Rezerwat Poodří)', 'odra-bartosovice', 'RIVER', 49.6877213, 18.033194, 'Morawsko-Śląski', 'Nový Jičín', 'Odra w Bartošovicach płynie przez chroniony obszar rezerwatu Poodří, zachowując swój pierwotny, dziki charakter meandrującej rzeki. Koryto jest tu wąskie, usiane zwalonymi drzewami i korzeniami, co tworzy idealne kryjówki dla pstrągów potokowych i lipieni. To wymarzone miejsce dla muszkarzy oraz spinningistów ceniących dyskretne łowienie w krystalicznie czystej wodzie. Uciąg rzeki jest żywy, tworząc liczne bystrza i mikro-rynny o kamienistym dnie, bogatym w naturalny pokarm. Ze względu na status ochronny, presja wędkarska jest tu minimalna, co sprzyja populacji dzikich, niewypłoszonych ryb. Każda wyprawa w to miejsce w 2026 roku to powrót do korzeni wędkarstwa w otoczeniu nienaruszonej przyrody.', null);

