VALUES (70691, 'Górska', 'Dzika, meandrująca', 12.0, 0.7, 'Kamień i żwir', 'Zwalone drzewa', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina lipienia', false);

-- Spot 693: Velká Střelná (Obszar Wojskowy Libavá)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70692, 'Odra - Velká Střelná (Źródliskowa)', 'odra-velka-strelna', 'RIVER', 49.6133883, 17.5200005, 'Ołomuniecki', 'Město Libavá', 'Odra w rejonie Velkiej Střelnej to niemal źródliskowy odcinek rzeki płynący przez ściśle chroniony teren poligonu wojskowego Libavá. Koryto ma tu charakter wąskiego potoku górskiego o krystalicznie czystej wodzie i dnie usianym drobnymi łupkami oraz żwirem. To idealne miejsce dla pasjonatów mikro-jigingu, którzy szukają dzikich pstrągów potokowych w niewielkich wymytych rynnach pod korzeniami drzew. Ze względu na lokalizację w strefie militarnej, dostęp do wody jest ograniczony i wymaga specjalnych pozwoleń, co skutkuje niemal zerową presją wędkarską. Nurt jest tu bardzo bystry, a liczne kaskady i powalone pnie tworzą unikalne, mikro-stanowiska dla ryb łososiowatych. Każda wyprawa w to miejsce w 2026 roku jest traktowana jako wędkarska ekspedycja w jeden z najdzikszych zakątków dorzecza.', 'VLS ČR (Military Forests)');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70692, 'Górska', 'Wąski potok górski', 4.0, 0.4, 'Łupek i żwir', 'Naturalne kaskady', 'Pstrąg potokowy, Głowacz', 'Kraina pstrąga', false);

-- Spot 694: Dřemovice u Města Libavá
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70693, 'Odra - Dřemovice (Górskie Bystrza)', 'odra-dremovice', 'RIVER', 49.6913961, 17.566488, 'Ołomuniecki', 'Město Libavá', 'Odra w Dřemovicach to techniczne łowisko pstrągowe o charakterze podgórskim, charakteryzujące się dużym spadkiem koryta i zimną wodą. Rzeka żłobi tu dno o kamienistym podłożu, tworząc techniczne warkocze prądowe idealne do łowienia metodą krótkiej nimfy. To wymarzone miejsce dla muszkarzy celujących w lipienie zbierające suchą muchę w płytkich, natlenionych przelewach rzeki. Uciąg jest tu zdecydowany i żywy, co wymaga od wędkarza dyskretnego podejścia i precyzyjnego podania przynęty pod prąd. Naturalne przeszkody skalne tworzą głębsze dołki na łukach potoku, które stanowią bezpieczną ostoję dla większych egzemplarzy ryb łososiowatych. Spokój okolicy oraz surowy klimat Gór Odrzańskich nadają każdemu wędkowaniu w tym miejscu wyjątkowego, sportowego charakteru.', 'VLS ČR (Military Forests)');

