VALUES (70693, 'Górska', 'Bystry potok leśny', 6.0, 0.6, 'Kamień i skała', 'Naturalne bystrza', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- Spot 695: Rudoltovice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70694, 'Odra - Rudoltovice (Dolina Przełomowa)', 'odra-rudoltovice', 'RIVER', 49.72894, 17.6051212, 'Ołomuniecki', 'Město Libavá', 'Odcinek w Rudoltovicach charakteryzuje się malowniczym przebiegiem przez głęboką dolinę przełomową Gór Odrzańskich o naturalnym profilu koryta. Rzeka płynie tu dynamicznie, tworząc liczne meandry i żwirowe łachy, które są naturalnym tarliskiem dla pstrąga potokowego. Podłoże jest stabilne, kamienisto-żwirowe, co ułatwia bezpieczne brodzenie w poszukiwaniu najlepszych rynien prądowych rzeki. Spinningiści z sukcesami obławiają tutejsze turbulentne dołki pod brzegowymi nawisami traw w poszukiwaniu kleni oraz pstrągów. Uciąg wody jest tu zmienny, co pozwala na eksperymentowanie z wieloma technikami prezentacji muszek i mikro-jigów w nurcie. Dzięki izolacji terenu i specyficznemu mikroklimatowi, ryby zachowują tu dziki charakter i doskonałą kondycję przez cały sezon.', 'ČRS / VLS ČR');

