VALUES (70694, 'Górska', 'Naturalne meandry górskie', 8.0, 0.7, 'Żwir i kamień', 'Zwalone drzewa', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 696: Rąpice (Pogranicze)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70695, 'Odra - Rąpice (Uregulowana Wielka)', 'odra-rapice', 'RIVER', 52.089143, 14.734304, 'Lubuskie', 'Cybinka', 'Odra w Rąpicach to potężna rzeka nizinna charakteryzująca się szerokim korytem i obecnością licznych piaszczystych przykos wychodzących w nurt. Rzeka żłobi tu głębokie rynny na krawędzi nurtu głównego, stanowiące bankowe stanowiska dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców boleni, które agresywnie atakują drobnicę przy turbulentnych warkoczach prądowych ostróg brzegowych. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, celując w rekordowe leszcze oraz rzeczne płocie migrujące korytem. Uciąg rzeki jest tu stabilny i zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. Malowniczy krajobraz pogranicza polsko-niemieckiego oraz wysoka rybność odcinka przyciągają pasjonatów ciężkiego feedera i spinningu.', 'PZW Zielona Góra');

