-- Spot 697: Eisenhüttenstadt (Kanał Oder-Spree)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70696, 'Odra - Eisenhüttenstadt (Węzeł)', 'odra-eisenhuettenstadt-1', 'RIVER', 52.122628, 14.683707, 'Brandenburgia', 'Eisenhüttenstadt', 'Odra w rejonie Eisenhüttenstadt to techniczne łowisko o ogromnym potencjale, zlokalizowane przy wylocie kanału Odra-Szprewa łączącego rzekę z systemem dróg wodnych. Woda w tym miejscu jest głęboka i posiada twarde, piaszczysto-betonowe dno, co przyciąga duże okonie oraz sandacze szukające schronienia. To strategiczne miejsce dla spinningistów, którzy wykorzystują konstrukcje śluz i nabrzeża do precyzyjnego prowadzenia ciężkich jigów w nurcie. Uciąg jest uzależniony od pracy urządzeń hydrotechnicznych, co wymusza na wędkarzu częstą adaptację techniki i obciążenia zestawu. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz krąpie, wykorzystując systematyczne nęcenie na stokach toru wodnego. Miejsko-industrialny krajobraz niemieckiego portu zapewnia komfortowy dostęp do linii brzegowej i ciekawą specyfikę łowienia w nurcie rzeki.', 'LAV Brandenburg');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70696, 'Nizinna Wielka', 'Techniczna, kanałowa', 200.0, 4.5, 'Twardy piasek', 'Śluzy, nabrzeża portowe', 'Sandacz, Okoń, Leszcz', 'Kraina leszcza', true);

-- Spot 698: Eisenhüttenstadt (Północne Główki)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70697, 'Odra - Eisenhüttenstadt (Główki)', 'odra-eisenhuettenstadt-2', 'RIVER', 52.166268, 14.704087, 'Brandenburgia', 'Eisenhüttenstadt', 'Północny odcinek rzeki w Eisenhüttenstadt charakteryzuje się klasycznym systemem główek regulacyjnych o piaszczystych klatkach i głębokich warkoczach. Rzeka płynie tu szeroko, żłobiąc rynny o głębokości do czterech metrów na szczytach ostróg, gdzie chętnie stacjonują sumy. To wymarzone miejsce dla spinningistów szukających boleni patrolujących krawędzie nurtu głównego w poszukiwaniu stad uklei. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na brania rekordowych brzan doskonale czujących się w silnym uciągu. Uciąg wody jest tu stabilny i potężny, co wymaga stosowania dociążonych koszyków zanętowych dla poprawnej stabilizacji zestawu na dnie. Systematyczna regulacja rzeki na tym odcinku sprawia, że łowisko jest technicznie przewidywalne i oferuje ryby o imponujących rozmiarach przez cały rok.', 'LAV Brandenburg');

