-- Spot 699: Aurith (Ujście starego koryta)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70698, 'Odra - Aurith (Graniczne Główki)', 'odra-aurith', 'RIVER', 52.211752, 14.708072, 'Lubuskie', 'Cybinka', 'Odra w Aurith to odcinek o bardzo regularnej linii główek brzegowych, charakteryzujący się głębokimi klatkami o piaszczystym dnie. Rzeka płynie tu szeroko, żłobiąc rynny o głębokości do czterech metrów na końcach ostróg, gdzie chętnie stacjonują rekordowe sumy. To strategiczne miejsce dla spinningistów polujących na bolenie, które agresywnie atakują drobnicę w turbulentnych warkoczach prądowych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz rzeczne krąpie, wykorzystując systematyczne nęcenie na stokach toru wodnego. Uciąg rzeki jest zdecydowany i stabilny, co sprzyja wysokiej aktywności ryb reofilnych i doskonałemu natlenieniu wody. Malowniczy krajobraz pogranicza oraz niska presja wędkarska gwarantują spokój i szansę na kontakt z niewypłoszoną, dużą rybą.', null);

