-- Spot 700: Kunice (Lubuskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70699, 'Odra - Kunice (Warkocze Prądowe)', 'odra-kunice', 'RIVER', 52.256023, 14.69129, 'Lubuskie', 'Słubice', 'Odcinek w Kunicach słynie z wyjątkowo silnego nurtu i twardego, żwirowo-kamienistego dna koryta głównego. Rzeka tworzy tu techniczne stanowiska pod wysokimi opaskami faszynowymi, które skrywają wyrośnięte brzany oraz sandacze żerujące o zmierzchu. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając kleni pod nawisami gęstych nadrzecznych wiklin. To wymarzone miejsce dla wędkarzy feederowych, którzy potrafią utrzymać zestaw w głównym nurcie przy użyciu dociążonych koszyków zanętowych. Uciąg wody jest tu żywy i zmienny, co wymusza na wędkarzu umiejętne czytania prądów i szukania stref odpoczynku ryb. Bliskość Słubic sprawia, że łowisko jest dobrze znane lokalnym pasjonatom, oferując jednocześnie ryby o imponujących rozmiarach.', null);

