-- Spot 701: Lossow (Niemcy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70700, 'Odra - Lossow (Głębokie Jamy)', 'odra-lossow', 'RIVER', 52.270472, 14.620688, 'Brandenburgia', 'Frankfurt (Oder)', 'Odra w rejonie Lossow charakteryzuje się głębokimi rynnami wymytymi na łukach rzeki, dochodzącymi do ponad pięciu metrów głębokości. Podłoże jest tu piaszczysto-muliste w klatkach, przechodząc w twardy żwir w głównym torze wodnym rzeki. To doskonałe łowisko dla łowców sumów, którzy wykorzystują tutejsze jamy jako główne ostoje drapieżników podczas dziennego odpoczynku. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy zatopionych w wodzie karczowiskach i gałęziach. Uciąg rzeki w tym miejscu jest stabilny, co pozwala na precyzyjne nęcenie punktowe rzecznymi mieszankami zanętowymi. Miejsce to łączy w sobie urok naturalnego koryta z technicznym wyzwaniem łowienia w nurcie wielkiej arterii wodnej.', null);

