-- Spot 702: Świecko (Polderowe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70701, 'Odra - Świecko (Przeprawa i Przykosy)', 'odra-swiecko', 'RIVER', 52.309964, 14.581796, 'Lubuskie', 'Słubice', 'Odcinek w Świecku słynie z rozległych piaszczystych przykos i szerokich rozlewisk poniżej ujścia Kanału Odra-Szprewa. Rzeka płynie tu dostojnie, oferując wędkarzom piaszczysto-żwirowe dno z wyraźnymi uskokami na krawędzi nurtu głównego. To strategiczne miejsce dla łowców boleni, które agresywnie atakują drobnicę przy turbulentnych warkoczach prądowych mostów autostradowych. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w dorodne leszcze oraz rzadziej spotykane certy migrujące korytem. Uciąg wody jest umiarkowany i przewidywalny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w łowisku. Bliskość węzła komunikacyjnego zapewnia łatwy dostęp do wody, mimo dzikiego i naturalnego wyglądu nadrzecznych łęgów.', null);

