VALUES (70701, 'Nizinna Wielka', 'Szeroka, przykosy', 250.0, 2.8, 'Piasek i żwir', 'Mosty, poldery', 'Boleń, Leszcz, Certa', 'Kraina leszcza', true);

-- Spot 703: Frankfurt (Oder) / Słubice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70702, 'Odra - Frankfurt/Słubice (Bulwary)', 'odra-slubice-miejska', 'RIVER', 52.351995, 14.5525239, 'Lubuskie', 'Słubice', 'Miejskie łowisko we Frankfurcie i Słubicach charakteryzuje się betonowymi bulwarami i głębokimi rynnami pod mostem granicznym. Podłoże jest tu twarde, kamienisto-betonowe, z licznymi osadami piaszczystymi w spokojniejszych strefach przy murach oporowych. To strategiczne miejsce dla spinningistów szukających sandaczy oraz dużych okoni żerujących na uklejach w cieniu konstrukcji. Warkocze prądowe powstające za filarami mostów są ulubionym żerowiskiem boleni, które polują tu widowiskowo pod samą powierzchnią wody. Uciąg rzeki w rejonie miejskim jest stabilny, co pozwala na komfortowe operowanie metodą feedera klasycznego na krawędzi nurtu. Dobra infrastruktura i oświetlenie brzegów czynią to miejsce doskonałym punktem na bezpieczne, wieczorne sesje wędkarskie.', null);

