VALUES (70702, 'Nizinna Wielka', 'Uregulowana miejska', 200.0, 3.8, 'Twardy piasek', 'Mosty, nabrzeża', 'Sandacz, Boleń, Okoń', 'Kraina leszcza', true);

-- Spot 704: Lebus (Przełom Odry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70703, 'Odra - Lebus (Wysokie Brzegi)', 'odra-lebus', 'RIVER', 52.395708, 14.534331, 'Brandenburgia', 'Lebus', 'Odra w Lebus płynie malowniczym przełomem, gdzie wysokie, morenowe wzgórza schodzą bezpośrednio do szerokiego koryta rzeki. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z głębokimi rynnami pod wysokimi, podmywanymi burtami brzegowymi. To wymarzone miejsce dla łowców okazowych kleni oraz brzan, które znajdują tu doskonałe warunki tlenowe i obfitość pokarmu. Spinningiści z sukcesami obławiają tutejsze główki, szukając sandaczy stacjonujących w cieniu podwodnych kamiennych raf i umocnień. Uciąg jest tu zdecydowany i żywy, co wymaga stosowania dociążonych zestawów gruntowych dla poprawnej stabilizacji przynęty. Specyficzny mikroklimat doliny oraz dzikość brzegów sprawiają, że rybostan jest tu wyjątkowo bogaty i atrakcyjny dla wędkarzy.', null);

