VALUES (70703, 'Nizinna Wielka', 'Przełomowa, szeroka', 260.0, 3.0, 'Piasek i glina', 'Podmyte burty, główki', 'Brzana, Kleń, Sandacz', 'Kraina leszcza', true);

-- Spot 705: Lebus (Głębokie Rynny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70704, 'Odra - Lebus (Północny Nurt)', 'odra-lebus-polnoc', 'RIVER', 52.438579, 14.558493, 'Brandenburgia', 'Lebus', 'Odra w Lebus na tym odcinku charakteryzuje się wyjątkowo głębokimi rynnami sięgającymi ponad cztery metry głębokości. Nurt rzeki jest tu silny i stabilny, co przyciąga rekordowe sandacze czatujące w cieniu podwodnych przeszkód. Wędkarze gruntowi chętnie nęcą piaszczyste płanie, licząc na brania walecznych brzan doskonale czujących się w twardym podłożu. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni patrolujących krawędzie nurtu głównego. Uciąg wody wymaga stosowania dociążonych koszyków zanętowych dla poprawnej prezentacji przynęty na dnie rzeki. To łowisko o ogromnym potencjale, zapewniające w 2026 roku stabilne wyniki nawet przy zmiennych stanach wody.', 'LAV Brandenburg');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70704, 'Nizinna Wielka', 'Szeroka, głębokie rynny', 260.0, 3.8, 'Piasek i kamień', 'Rynny prądowe', 'Sandacz, Brzana, Boleń', 'Kraina leszcza', true);

-- Spot 706: Lebus (Meandry Łęgowe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70705, 'Odra - Lebus (Odcinek Łęgowy)', 'odra-lebus-legi', 'RIVER', 52.47104, 14.611281, 'Brandenburgia', 'Lebus', 'Północny odcinek Lebus to miejsce, gdzie Odra zaczyna szerzej meandrować wśród nadodrzańskich łęgów i rozległych polderów. Koryto posiada tu piaszczysto-żwirowe dno z wyraźnie zaznaczonymi przykosami, które są ulubionym żerowiskiem boleni i kleni. To doskonałe miejsce dla wędkarzy feederowych celujących w dorodne leszcze migrujące korytem w poszukiwaniu pokarmu. Podmyte brzegi porośnięte gęstą wikliną stanowią bezpieczną ostoję dla okoni oraz mniejszych szczupaków żerujących przy brzegu. Uciąg wody jest umiarkowany i przewidywalny, co sprzyja precyzyjnemu nęczeniu i utrzymywaniu stad ryb w łowisku. Malowniczy krajobraz pogranicza polsko-niemieckiego nadaje każdej wyprawie wędkarskiej w tym rejonie wyjątkowego, spokojnego charakteru.', 'LAV Brandenburg');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70705, 'Nizinna Wielka', 'Szeroka, meandrująca', 250.0, 2.8, 'Piasek i żwir', 'Przykosy piaszczyste', 'Boleń, Leszcz, Szczupak', 'Kraina leszcza', true);

-- Spot 707: Ługi Górzyckie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70706, 'Odra - Ługi Górzyckie (Krainy Główek)', 'odra-lugi-gorzyckie', 'RIVER', 52.516726, 14.611027, 'Lubuskie', 'Górzyca', 'Odra w Ługach Górzyckich słynie z rozległych klatek między główkami, które przyciągają potężne stada leszczy i krąpi. Podłoże jest tu piaszczysto-muliste w zatokach, przechodząc w twardy piasek w nurcie głównym wielkiej rzeki. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie jamy na końcach ostróg jako swoje dzienne kryjówki. Spinningiści z sukcesami polują tu na sandacze, wykorzystując technikę ciężkiego opadu w turbulentnych warkoczach prądowych. Uciąg rzeki w tym miejscu jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. Specyfika polderowego krajobrazu zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z bardzo dziką naturą.', 'PZW Gorzów Wielkopolski');

