VALUES (70706, 'Nizinna Wielka', 'Uregulowana, główki', 270.0, 3.2, 'Piasek i muł', 'Główki, warkocze', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 708: gmina Górzyca
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70707, 'Odra - gmina Górzyca (Wielki Nurt)', 'odra-gorzyca', 'RIVER', 52.562388, 14.629104, 'Lubuskie', 'Kostrzyn nad Odrą', 'Odcinek w gminie Górzyca charakteryzuje się technicznie wykształconą linią główek o piaszczystym dnie i urozmaiconej rzeźbie dna. Rzeka żłobi tu głębokie rynny na krawędzi nurtu, które są bankowymi stanowiskami dla brzan oraz rzecznych boleni. To doskonałe łowisko dla spinningistów szukających szczupaków stacjonujących w cieniu nadrzecznych nawisów traw i wikliny. Wędkarze stacjonarni z sukcesami łowią tu okazałe certy, wykorzystując systematyczne nęcenie na stokach toru wodnego. Uciąg rzeki jest stabilny, co pozwala na komfortowe operowanie zestawami feederowymi z dociążonym koszykiem zanętowym. Bliskość Kostrzyna sprawia, że rybostan jest tu wyjątkowo zróżnicowany i regularnie zasilany migracjami ryb z dopływów.', 'PZW Gorzów Wielkopolski');

