-- Spot 709: Neubleyen (Niemcy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70708, 'Odra - Neubleyen (Tor Wodny)', 'odra-neubleyen', 'RIVER', 52.604475, 14.60304, 'Brandenburgia', 'Kietz', 'Odra w Neubleyen to techniczne łowisko o ogromnym potencjale, zlokalizowane na niemieckim brzegu rzeki w pobliżu Kostrzyna. Podłoże jest tu twarde, piaszczysto-żwirowe, z wyraźnymi uskokami dna stanowiącymi idealne kryjówki dla dużych sandaczy. To strategiczne miejsce dla łowców boleni, które agresywnie atakują stada uklei przy turbulentnych warkoczach mostowych. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, celując w dorodne leszcze oraz rzadziej spotykane amury. Uciąg wody jest tu potężny i żywy, co wymaga stosowania dociążonych zestawów gruntowych dla poprawnej stabilizacji przynęty. Miejsko-industrialny charakter okolicy łączy się tutaj z rybnością typową dla największych europejskich arterii wodnych w 2026 roku.', 'LAV Brandenburg');

