-- Spot 710: Kaleńsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70709, 'Odra - Kaleńsko (Przedujście Warty)', 'odra-kalensko', 'RIVER', 52.631354, 14.541597, 'Zachodniopomorskie', 'Kostrzyn nad Odrą', 'Odra w Kaleńsku to odcinek poprzedzający spektakularne ujście Warty, co czyni to miejsce strategicznym węzłem dla ryb migrujących. Rzeka płynie tu szerokim korytem, żłobiąc głębokie rynny o gliniastym dnie, które są naturalną ostoją dla sumów. Spinningiści z sukcesami obławiają tutejsze główki, szukając sandaczy oraz okazowych szczupaków żerujących na bogatym rybostanie białorybu. To wymarzone miejsce dla łowców okazowych leszczy, którzy wykorzystują systematyczne nęcenie w celu zatrzymania stada w silnym nurcie. Uciąg wody jest zdecydowany i wzrasta przy każdorazowych zrzutach z górnych zapór, co wymusza częstą adaptację techniki. Dzikość brzegów oraz bliskość Parku Narodowego Ujście Warty nadają każdemu wędkowaniu w Kaleńsku unikalnego klimatu.', 'PZW Gorzów Wielkopolski');

