VALUES (70709, 'Nizinna Wielka', 'Szeroka, głęboka', 320.0, 4.5, 'Glina i piasek', 'Główki, rynny głębokie', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 711: Letschin (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70710, 'Odra - Letschin (Wielki Zakręt)', 'odra-letschin-poludnie', 'RIVER', 52.6567791, 14.4761052, 'Brandenburgia', 'Kietz', 'Odra w Letschin na tym odcinku charakteryzuje się szerokim, majestatycznym korytem i silnym nurtem po przyjęciu wód Warty. Podłoże jest tu twarde, piaszczysto-żwirowe, co stwarza idealne warunki dla sandaczy żerujących w głębokich rynnach przydennych. To strategiczne miejsce dla łowców okazowych leszczy, które grupują się na krawędzi nurtu głównego w poszukiwaniu pokarmu. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni patrolujących turbulentną wodę na szczytach ostróg. Uciąg rzeki jest zdecydowany i stabilny, co wymaga stosowania dociążonych koszyków zanętowych przy metodzie feederowej. Malowniczy krajobraz nadodrzańskich łęgów oraz wysoka rybność odcinka czynią to łowisko jednym z najciekawszych na mapie pogranicza.', 'LAV Brandenburg');

