-- Spot 712: Letschin (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70711, 'Odra - Letschin (Przykosy)', 'odra-letschin-polnoc', 'RIVER', 52.691842, 14.427249, 'Brandenburgia', 'Letschin', 'Północny odcinek w Letschin słynie z rozległych piaszczystych przykos, które dynamicznie zmieniają swój kształt przy każdym wezbraniu rzeki. Rzeka żłobi tu dno o piaszczystym charakterze, tworząc dogodne ostoje dla stad rzecznych krąpi oraz płoci. To doskonałe łowisko dla spinningistów polujących na szczupaki, którzy obławiają krawędzie roślinności wynurzonej przy brzegowych zastoiskach. Uciąg wody jest tu żywy i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb spokojnego żeru. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera klasycznego, celując w ryby migrujące korytem głównym w poszukiwaniu rynien. Malowniczy krajobraz pradoliny Odry zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z niewypłoszoną, dużą rybą.', 'LAV Brandenburg');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70711, 'Nizinna Wielka', 'Szeroka, piaszczysta', 310.0, 2.8, 'Piasek', 'Przykosy piaszczyste', 'Szczupak, Leszcz, Płoć', 'Kraina leszcza', true);

-- Spot 713: Kłosów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70712, 'Odra - Kłosów (Kraina Suma)', 'odra-klosow', 'RIVER', 52.728416, 14.381781, 'Zachodniopomorskie', 'Mieszkowice', 'Odra w Kłosowie to technicznie wymagające łowisko o urozmaiconej rzeźbie dna i silnie zarysowanej linii główek brzegowych. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z bardzo głębokimi rynnami wymytymi na szczytach ostróg, stanowiącymi ostoje dla sumów. To strategiczne miejsce dla łowców sandaczy, którzy wykorzystują techniczne uskoki dna jako swoje bankowe stanowiska żerowania. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni oraz okazowych okoni stacjonujących w nurcie. Uciąg rzeki w tym miejscu jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji walecznych brzan. Dzikie brzegi porośnięte gęstą roślinnością zapewniają intymną atmosferę i szansę na kontakt z rybą rzeczną o rekordowych rozmiarach.', 'PZW Szczecin');

