-- Spot 714: Gozdowice (Przeprawa Promowa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70713, 'Odra - Gozdowice (Historyczny Nurt)', 'odra-gozdowice', 'RIVER', 52.7598106, 14.3285917, 'Zachodniopomorskie', 'Mieszkowice', 'Odcinek w Gozdowicach to jedno z najbardziej znanych łowisk w regionie, słynące z przeprawy promowej i specyficznego ukształtowania toru wodnego. Rzeka posiada tu twarde, piaszczysto-żwirowe dno z wyraźnymi rynnami wymytymi pod wysokimi burtami brzegowymi. To doskonałe miejsce dla spinningistów szukających sandaczy oraz boleni żerujących agresywnie na stadach uklei przy warkoczach promowych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz certy, wykorzystując systematyczne nęcenie na krawędzi głównego koryta. Uciąg wody jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb reofilnych przez cały rok wędkarski. Piękna okolica oraz historyczne znaczenie miejsca nadają każdemu wędkowaniu w Gozdowicach niepowtarzalnego, patriotycznego klimatu.', 'PZW Szczecin');

