-- Spot 715: Neulewin (Niemcy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70714, 'Odra - Neulewin (Wielkie Płanie)', 'odra-neulewin', 'RIVER', 52.7834787, 14.2644929, 'Brandenburgia', 'Wriezen', 'Odra w Neulewin to potężna rzeka nizinna charakteryzująca się szerokimi płaniami o wyrównanym dnie i obecnością piaszczystych przykos. Koryto posiada tu piaszczysto-muliste podłoże z licznymi podmyłymi burtami, które skrywają wyrośnięte leszczowe stada. To wymarzone miejsce dla łowców szczupaków, którzy obławiają krawędzie roślinności zanurzonej przy brzegowych opaskach faszynowych. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy nadrzecznych nawisach gęstych wiklin. Uciąg wody jest łagodny i przewidywalny, co sprzyja systematycznemu nęceniu i utrzymywaniu białorybu w polu łowienia. Niska presja wędkarska oraz bogactwo ryb spokojnego żeru czynią ten fragment rzeki bardzo atrakcyjnym punktem na mapie regionu.', 'LAV Brandenburg');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70714, 'Nizinna Wielka', 'Szeroka płania, piaszczysta', 350.0, 2.5, 'Piasek i muł', 'Opaski faszynowe', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', true);

-- Spot 716: Oderaue (Niemcy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70715, 'Odra - Oderaue (Ostrogowa)', 'odra-oderaue', 'RIVER', 52.817579, 14.214335, 'Brandenburgia', 'Oderaue', 'Odcinek w Oderaue to klasyczne łowisko nizinne słynące z regularnej linii główek brzegowych i głębokich rynien wymytych na końcach ostróg. Podłoże jest tu twarde, piaszczyste, co stwarza idealne warunki tlenowe dla brzan oraz rekordowych sandaczy stacjonujących w nurcie. Spinningiści z sukcesami obławiają tutejsze turbulentne rynny, szukając boleni żerujących agresywnie na uklejach przy szczytach główek. Wędkarze gruntowi chętnie nęcą tutejsze płanie, licząc na brania rekordowych leszczy oraz rzecznych cert migrujących głównym korytem. Uciąg rzeki w tym miejscu jest zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilizacji zestawu. Malowniczy krajobraz pradoliny Odry oraz wysoka rybność odcinka przyciągają pasjonatów ciężkiego feedera z całych Niemiec.', 'LAV Brandenburg');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70715, 'Nizinna Wielka', 'Uregulowana, główki', 360.0, 3.2, 'Twardy piasek', 'Główki, rynny szczytowe', 'Sandacz, Brzana, Boleń', 'Kraina leszcza', true);

-- Spot 717: Oderaue (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70716, 'Odra - Oderaue (Północny Nurt)', 'odra-oderaue-polnoc', 'RIVER', 52.824942, 14.139919, 'Brandenburgia', 'Oderaue', 'Odra w północnej części Oderaue to odcinek o szerokim korycie i bardzo stabilnej linii brzegowej umocnionej faszyną. Podłoże jest tu twarde, piaszczysto-żwirowe, co stwarza idealne warunki dla sandaczy żerujących w głębokich rynnach koryta głównego. To strategiczne miejsce dla łowców okazowych leszczy, które grupują się na krawędzi nurtu w poszukiwaniu pokarmu niesionego przez rzekę. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni patrolujących turbulentną wodę na szczytach ostróg. Uciąg rzeki jest zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla poprawnej prezentacji zestawu gruntowego na dnie. Malowniczy krajobraz pradoliny Odry oraz wysoka rybność odcinka przyciągają pasjonatów ciężkiego feedera z całego regionu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70716, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 340.0, 3.2, 'Piasek i żwir', 'Opaski faszynowe', 'Sandacz, Leszcz, Boleń', 'Kraina leszcza', true);

-- Spot 718: Bad Freienwalde (Oder)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70717, 'Odra - Bad Freienwalde (Zakole)', 'odra-bad-freienwalde', 'RIVER', 52.869907, 14.151961, 'Brandenburgia', 'Bad Freienwalde', 'Odcinek w Bad Freienwalde charakteryzuje się wyraźnymi meandrami i obecnością piaszczystych przykos wychodzących daleko w główny nurt rzeki. Rzeka żłobi tu dno o piaszczystym charakterze, tworząc dogodne ostoje dla stad rzecznych leszczy oraz krąpi w głębszych rynnach. To doskonałe łowisko dla spinningistów polujących na szczupaki, którzy obławiają krawędzie roślinności wynurzonej przy brzegowych zastoiskach. Uciąg wody jest tu żywy i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb spokojnego żeru. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera klasycznego, celując w ryby migrujące korytem w poszukiwaniu pokarmu. Malowniczy krajobraz doliny Odry zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z niewypłoszoną, dużą rybą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70717, 'Nizinna Wielka', 'Szeroka, meandrująca', 330.0, 2.8, 'Piasek', 'Przykosy piaszczyste', 'Szczupak, Leszcz, Płoć', 'Kraina leszcza', true);

-- Spot 719: Lunow-Stolzenhagen
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70718, 'Odra - Lunow-Stolzenhagen (Rynny)', 'odra-lunow-stolzenhagen', 'RIVER', 52.916088, 14.149276, 'Brandenburgia', 'Angermünde', 'Odra w Lunow-Stolzenhagen to technicznie wymagające łowisko o urozmaiconej rzeźbie dna i silnie zarysowanej linii główek brzegowych. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z bardzo głębokimi rynnami wymytymi na szczytach ostróg, stanowiącymi ostoje dla sumów. To strategiczne miejsce dla łowców sandaczy, którzy wykorzystują techniczne uskoki dna jako swoje bankowe stanowiska żerowania o zmierzchu. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni oraz okazowych okoni stacjonujących w nurcie głównym. Uciąg rzeki w tym miejscu jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji walecznych brzan. Dzikie brzegi porośnięte gęstą roślinnością zapewniają intymną atmosferę i szansę na kontakt z rybą rzeczną o rekordowych rozmiarach.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70718, 'Nizinna Wielka', 'Uregulowana, główki', 350.0, 3.8, 'Glina i piasek', 'Główki, głębokie rynny', 'Sum, Sandacz, Brzana', 'Kraina leszcza', true);

-- Spot 720: Angermünde (Rejon Stolpe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70719, 'Odra - Angermünde (Przełom Stolpe)', 'odra-angermunde-stolpe', 'RIVER', 52.961266, 14.144056, 'Brandenburgia', 'Angermünde', 'Odcinek w rejonie Angermünde, przy miejscowości Stolpe, charakteryzuje się specyficznym ukształtowaniem koryta pod wysokimi brzegami morenowymi. Rzeka posiada tu twarde, piaszczysto-żwirowe dno z wyraźnymi rynnami wymytymi pod burtami, które stanowią bezpieczną ostoję dla rekordowych kleni. To doskonałe miejsce dla spinningistów szukających sandaczy oraz boleni żerujących agresywnie na stadach uklei przy warkoczach prądowych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze oraz certy, wykorzystując systematyczne nęcenie na krawędzi głównego koryta. Uciąg wody jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb reofilnych przez cały rok wędkarski. Piękna okolica oraz bliskość Parku Narodowego Doliny Dolnej Odry nadają wędkowaniu w tym miejscu niepowtarzalnego klimatu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70719, 'Nizinna Wielka', 'Szeroka, nurt żywy', 340.0, 3.5, 'Piasek i żwir', 'Podmyte burty', 'Kleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 721: Schwedt/Oder (Węzeł Wodny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70720, 'Odra - Schwedt (Kanały i Nurt)', 'odra-schwedt', 'RIVER', 52.986762, 14.206173, 'Brandenburgia', 'Schwedt/Oder', 'Odra w Schwedt to potężny węzeł wodny, gdzie główny nurt rzeki sąsiaduje z systemem kanałów żeglugowych i rozlewisk Międzyodrza. Podłoże jest tu twarde, kamienisto-betonowe w rejonie nabrzeży portowych, co przyciąga sandacze oraz duże okonie szukające schronienia. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie rynny toru wodnego jako swoje główne ostoje w ciągu dnia. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni oraz kleni żerujących w turbulentnym nurcie rzeki. Uciąg wody jest stabilny, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w polu łowienia przez wiele godzin. Dobra infrastruktura miejska i liczne stanowiska czynią to łowisko jednym z najpopularniejszych punktów na mapie regionu.', null);

