VALUES (70720, 'Nizinna Wielka', 'Techniczna, portowa', 360.0, 4.5, 'Twardy piasek', 'Nabrzeża, kanały', 'Sandacz, Sum, Boleń', 'Kraina leszcza', true);

-- Spot 722: Zatoń Dolna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70721, 'Odra - Zatoń Dolna (Dolina Miłości)', 'odra-zaton-dolna', 'RIVER', 53.010907, 14.271634, 'Zachodniopomorskie', 'Chojna', 'Odra w Zatoni Dolnej to jeden z najbardziej malowniczych odcinków rzeki, płynący u stóp wzgórz znanych jako Dolina Miłości. Koryto posiada tu piaszczysto-żwirowe dno z wyraźnymi uskokami na krawędzi nurtu głównego, gdzie stacjonują rekordowe sandacze. To wymarzone miejsce dla łowców boleni, które agresywnie atakują drobnicę przy turbulentnych warkoczach prądowych ostróg brzegowych. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na brania rekordowych leszczy oraz wyrośniętych krąpi rzecznych. Uciąg wody jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. Spokój okolicy oraz unikalne ukształtowanie terenu sprawiają, że rybostan jest tu wyjątkowo bogaty i atrakcyjny dla wędkarzy.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70721, 'Nizinna Wielka', 'Szeroka, nurt żywy', 350.0, 3.2, 'Piasek i żwir', 'Główki, rynny', 'Sandacz, Boleń, Leszcz', 'Kraina leszcza', true);

-- Spot 723: Krajnik Dolny (Pogranicze)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70722, 'Odra - Krajnik Dolny (Głębokie Warkocze)', 'odra-krajnik-dolny', 'RIVER', 53.044169, 14.331649, 'Zachodniopomorskie', 'Chojna', 'Odra w Krajniku Dolnym to szeroka rzeka o silnym nurcie i bardzo regularnej linii główek brzegowych. Podłoże jest tu twarde, piaszczysto-żwirowe, co stwarza idealne warunki dla sandaczy żerujących w głębokich rynnach koryta głównego. To strategiczne miejsce dla łowców boleni, które agresywnie atakują drobnicę na styku nurtu i spokojniejszych klatek międzyostrogowych. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w rekordowe leszcze oraz dorodne płocie migrujące korytem. Uciąg wody jest zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla poprawnej stabilizacji zestawu na dnie. Bliskość granicy i dobra infrastruktura przy moście czynią to miejsce popularnym punktem wypraw wędkarzy z obu stron rzeki.', null);

