-- Spot 724: Ognica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70723, 'Odra - Ognica (Rynny Sumowe)', 'odra-ognica', 'RIVER', 53.0887193, 14.3690459, 'Zachodniopomorskie', 'Widuchowa', 'Odcinek w Ognicy charakteryzuje się głębokimi rynnami przydennymi i obecnością licznych piaszczystych przykos wychodzących w nurt. Rzeka żłobi tu dno o piaszczysto-gliniastym charakterze, tworząc idealne ostoje dla rekordowych sumów szukających cienia w głębinach. To doskonałe łowisko dla spinningistów polujących na sandacze, wykorzystujących uskoki dna na krawędzi nurtu głównego. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, stosując metodę ciężkiego feedera z systematycznym nęceniem grubą zanętą. Uciąg wody jest tu żywy i stabilny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. Malowniczy krajobraz nadodrzański oraz niska presja wędkarska gwarantują spokój podczas całodniowych sesji nad wielką wodą.', null);

