-- Spot 725: Widuchowa (Rozwidlenie rzeki)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70724, 'Odra - Widuchowa (Węzeł Rozdzielczy)', 'odra-widuchowa', 'RIVER', 53.135064, 14.383713, 'Zachodniopomorskie', 'Widuchowa', 'Widuchowa to strategiczne miejsce, w którym nurt Odry rozdziela się na ramiona Wschodnie i Zachodnie przy stopniu wodnym. Woda poniżej jazu jest silnie natleniona i turbulentna, co przyciąga rekordowe bolenie oraz sandacze żerujące w warkoczach. To wymarzone stanowisko dla łowców sumów, którzy wykorzystują głębokie doły wymyte przez silny prąd rzeki poniżej śluzy. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w dorodne klenie oraz jazie doskonale czujące się w szybkim nurcie. Uciąg wody zależy od pracy urządzeń hydrotechnicznych, co wymaga od wędkarza częstej adaptacji techniki i obciążenia zestawu. Widok na rozległą dolinę rzeki i techniczna specyfika łowiska nadają temu miejscu unikalnego charakteru na mapie Polski.', null);

