VALUES (70724, 'Nizinna Wielka', 'Techniczna, rozwidlenie', 380.0, 4.8, 'Twardy piasek', 'Jazy, śluzy, filary', 'Sandacz, Boleń, Sum', 'Kraina leszcza', true);

-- Spot 726: Marwice (Międzyodrze)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70725, 'Odra - Marwice (Naturalny Nurt)', 'odra-marwice', 'RIVER', 53.1792851, 14.4078347, 'Zachodniopomorskie', 'Gryfino', 'Odcinek rzeki w Marwicach płynie szerokim korytem przez chroniony obszar Parku Narodowego Doliny Dolnej Odry. Koryto posiada tu piaszczysto-muliste dno z licznymi podmyłymi burtami brzegowymi, które skrywają wyrośnięte leszczowe stada. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w pobliżu nadrzecznych trzcinowisk i zatok. Uciąg wody jest tu nieco łagodniejszy niż w głównym nurcie powyżej, co sprzyja aktywności okoni oraz dorodnych kleni. Wędkarze stacjonarni z sukcesami stosują tu metodę feedera, celując w ryby migrujące między rzeką a kanałami Międzyodrza. Spokój okolicy oraz bogactwo fauny i flory czynią to miejsce idealnym punktem na relaksujące sesje z wędką.', null);

