-- Spot 727: gmina Widuchowa (Polesiny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70726, 'Odra - gmina Widuchowa (Rynny)', 'odra-widuchowa-gmina', 'RIVER', 53.2219619, 14.4435327, 'Zachodniopomorskie', 'Gryfino', 'Odra na północ od Widuchowej charakteryzuje się bardzo głębokimi rynnami szczytowymi i wyraźnie zaznaczoną linią główek regulacyjnych. Podłoże jest tu twarde, piaszczyste, co stwarza idealne warunki dla sandaczy żerujących na uklejach wzdłuż toru wodnego. To strategiczne miejsce dla łowców boleni, które agresywnie atakują drobnicę przy turbulentnych warkoczach prądowych ostróg. Wędkarze gruntowi chętnie nęcą tutejsze piaszczyste płanie, licząc na brania rekordowych leszczy oraz wyrośniętych krąpi rzecznych. Uciąg rzeki jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały rok. Malowniczy krajobraz pradoliny Odry oraz wysoka rybność odcinka przyciągają pasjonatów ciężkiego feedera z całego kraju.', null);

