-- Spot 728: Gryfino (Ciepły Kanał)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70727, 'Odra - Gryfino (Nabrzeże)', 'odra-gryfino-miejska', 'RIVER', 53.2679928, 14.4824943, 'Zachodniopomorskie', 'Gryfino', 'Miejskie łowisko w Gryfinie charakteryzuje się betonowymi bulwarami i głębokimi rynnami pod mostem prowadzącym na stronę niemiecką. Podłoże jest tu twarde, piaszczysto-betonowe, z wyraźnymi uskokami dna przy nabrzeżach, które są bankowymi stanowiskami dla sandaczy. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie doły toru wodnego w pobliżu miejskiej infrastruktury. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy murach oporowych i cumujących jednostkach. Uciąg wody jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb praktycznie przez całą dobę wędkarską. Łatwy dostęp do brzegów oraz bliskość zrzutów wody z elektrowni Dolna Odra czynią to miejsce legendarnym łowiskiem regionu.', null);

