-- Spot 729: Dębce (Brama Międzyodrza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70728, 'Odra - Dębce (Brama Międzyodrza)', 'odra-debce', 'RIVER', 53.3119899, 14.5078915, 'Zachodniopomorskie', 'Gryfino', 'Odra w Dębcach to odcinek o szerokim korycie i malowniczych brzegach porośniętych gęstymi trzcinowiskami. Rzeka płynie tu majestatycznie, żłobiąc piaszczysto-muliste dno z wyraźnymi uskokami na krawędzi nurtu głównego. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie rynny jako dzienne ostoje drapieżników. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe w poszukiwaniu sandaczy oraz okazowych szczupaków żerujących przy brzegach. Uciąg wody jest stabilny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w polu łowienia. Niska presja wędkarska oraz bliskość natury Międzyodrza czynią to łowisko wyjątkowo atrakcyjnym punktem na mapie regionu.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70728, 'Nizinna Wielka', 'Szeroka, naturalna', 380.0, 3.8, 'Piasek i muł', 'Trzcinowiska, rynny', 'Sum, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 730: Szczecin (Podjuchy - Regalica)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70729, 'Odra - Szczecin (Podjuchy)', 'odra-szczecin-podjuchy', 'RIVER', 53.3494048, 14.5507859, 'Zachodniopomorskie', 'Szczecin', 'Regalica w rejonie Podjuch to potężna arteria wodna o dużej dynamice przepływu i technicznym charakterze. Pod filarami mostów rzeka wymyła głębokie doły, które są bankowymi stanowiskami dla sandaczy oraz dużych okoni. To doskonałe łowisko dla wędkarzy feederowych celujących w rekordowe leszcze żerujące w głównym nurcie rzeki. Uciąg wody jest tu zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla poprawnej prezentacji przynęty. Spinningiści z sukcesami polują tu na bolenie, wykorzystując turbulentną wodę na styku nurtu i brzegowych umocnień. Bliskość miejskiej infrastruktury zapewnia łatwy dostęp do wody, mimo dzikiego rybostanu migrującego z Zalewu Szczecińskiego.', 'PZW Szczecin');

