VALUES (70729, 'Nizinna Wielka', 'Uregulowana, głęboka', 420.0, 5.0, 'Twardy piasek', 'Mosty, nabrzeża', 'Sandacz, Leszcz, Okoń', 'Kraina leszcza', true);

-- Spot 731: Szczecin (Zdroje - Odra Wschodnia)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70730, 'Odra - Szczecin (Zdroje)', 'odra-szczecin-zdroje', 'RIVER', 53.3805819, 14.6053149, 'Zachodniopomorskie', 'Szczecin', 'Odra Wschodnia w Zdroju charakteryzuje się głębokimi rynnami toru wodnego i obecnością licznych kanałów bocznych. Podłoże jest tu twarde, piaszczysto-muliste, co przyciąga sandacze oraz sumy szukające schronienia w głębinach. To strategiczne miejsce dla spinningistów polujących na okonie, którzy wykorzystują metodę bocznego troka przy nadrzecznych trzcinowiskach. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz leszcze, wykorzystując systematyczne nęcenie na krawędzi koryta głównego. Uciąg rzeki stabilizuje się w tym rejonie, co pozwala na komfortowe operowanie zestawami spławikowymi i gruntowymi. Bogactwo ryb migrujących oraz specyfika Międzyodrza sprawiają, że rybostan jest tu wyjątkowo zróżnicowany gatunkowo.', 'PZW Szczecin');

