VALUES (70730, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 450.0, 4.5, 'Piasek i muł', 'Kanały, tor wodny', 'Sandacz, Sum, Okoń', 'Kraina leszcza', true);

-- Spot 732: Szczecin (Dąbie - Wlot Regalicy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70731, 'Odra - Szczecin (Wlot Dąbie)', 'odra-szczecin-dabie-wlot', 'RIVER', 53.4244941, 14.6274935, 'Zachodniopomorskie', 'Szczecin', 'Rejon wlotu Regalicy do jeziora Dąbie to kraina wielkiej wody o charakterze delty z licznymi trzcinowymi wyspami. Rzeka rozlewa się tu szeroko, żłobiąc muliste dno z wyraźnymi uskokami stanowiącymi idealne kryjówki dla szczupaków. To wymarzone miejsce dla spinningistów, którzy obławiają krawędzie roślinności wynurzonej w poszukiwaniu rekordowych okoni. Wędkarze stacjonarni z sukcesami łowią tu okazałe liny oraz karasie, wykorzystując zaciszne zatoki o niemal stojącej wodzie. Uciąg rzeki jest tu znikomy i uzależniony od zjawisk "cofki" oraz aktualnego kierunku wiatru. Ogromna przestrzeń wodna i dzikość brzegów czynią to łowisko jednym z najbardziej emocjonujących miejsc w całym węźle.', 'PZW Szczecin');

