VALUES (70731, 'Nizinna Wielka', 'Ujściowa, deltowa', 600.0, 3.5, 'Miękki muł', 'Wyspy trzcinowe', 'Szczupak, Okoń, Lin', 'Kraina leszcza', true);

-- Spot 733: Szczecin (Iński Nurt)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70732, 'Odra - Szczecin (Iński Nurt)', 'odra-szczecin-inski-nurt', 'RIVER', 53.4667222, 14.6633189, 'Zachodniopomorskie', 'Szczecin', 'Iński Nurt to techniczne łowisko o ogromnym potencjale, charakteryzujące się dużą głębokością i silnymi prądami wody. Podłoże jest tu twarde, piaszczysto-żwirowe, co przyciąga sandacze migrujące okresowo między rzeką a wodami Zalewu. To strategiczne miejsce dla łowców drapieżników, którzy wykorzystują uskoki dna toru wodnego do precyzyjnego prowadzenia ciężkich jigów. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w rekordowe płocie oraz leszcze wchodzące w rzekę podczas ciągów. Uciąg wody bywa tu nieprzewidywalny, co wymaga od wędkarza posiadania szerokiego wachlarza obciążeń dla poprawnej prezentacji przynęty. Odcinek ten słynie z obecności ryb o imponujących rozmiarach, rzadko spotykanych w wyższych partiach biegu rzeki.', 'PZW Szczecin');

