VALUES (70732, 'Nizinna Wielka', 'Szeroka, tor wodny', 500.0, 6.5, 'Piasek i żwir', 'Tor wodny', 'Sandacz, Płoć, Leszcz', 'Kraina leszcza', true);

-- Spot 734: Szczecin (Parnica - Port)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70733, 'Odra - Szczecin (Parnica)', 'odra-szczecin-parnica', 'RIVER', 53.4102624, 14.5475814, 'Zachodniopomorskie', 'Szczecin', 'Parnica to typowe łowisko miejsko-portowe o uregulowanym charakterze i dużej głębokości dochodzącej do sześciu metrów. Podłoże jest tu piaszczysto-muliste z licznymi betonowymi nabrzeżami, które są naturalnym stanowiskiem dla okoni oraz sandaczy. To strategiczne miejsce dla spinningistów szukających ryb w cieniu cumujących jednostek i konstrukcji portowych. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie, wykorzystując metodę bata lub tyczki przy murach oporowych. Uciąg rzeki jest tu minimalny, co pozwala na stosowanie najdelikatniejszych zestawów spławikowych z bardzo czułymi sygnalizatorami. Łatwy dostęp do brzegów w samym centrum Szczecina czyni to miejsce idealnym punktem na szybkie sesje wędkarskie.', 'PZW Szczecin');

