VALUES (70733, 'Nizinna Wielka', 'Uregulowana portowa', 150.0, 5.5, 'Piasek i muł', 'Nabrzeża, port', 'Okoń, Sandacz, Płoć', 'Kraina leszcza', true);

-- Spot 735: Ameryka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70734, 'Pasłęka - Ameryka (Górny Potok)', 'pasleka-ameryka', 'RIVER', 53.6112254, 20.3286312, 'Warmińsko-Mazurskie', 'Olsztynek', 'Pasłęka w Ameryce to górny, niezwykle malowniczy odcinek rzeki płynący przez gęste lasy w pobliżu Olsztynka. Koryto jest tu wąskie i usiane zwalonymi przez bobry drzewami, co tworzy idealne kryjówki dla pstrągów potokowych. To techniczne łowisko wymaga od wędkarza dużej dyskrecji oraz precyzyjnych rzutów pod nawisy gałęzi. Dno jest piaszczysto-kamieniste z licznymi mikro-rynnowami, w których stacjonują waleczne ryby łososiowate. Uciąg wody jest żywy i zapewnia doskonałe natlenienie nawet podczas najgorętszych letnich miesięcy. Niska presja wędkarska oraz status rezerwatu bobrów nadają temu miejscu unikalny, niemal pierwotny charakter.', 'PZW Olsztyn');

