VALUES (70734, 'Górska', 'Dzika, leśna', 6.0, 0.6, 'Piasek i kamień', 'Zatory z pni', 'Pstrąg potokowy, Strzebla', 'Kraina pstrąga', false);

-- Spot 736: Gryźliny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70735, 'Pasłęka - Gryźliny (Podgórska Płania)', 'pasleka-gryzliny', 'RIVER', 53.6354974, 20.3488688, 'Warmińsko-Mazurskie', 'Olsztynek', 'W Gryźlinach rzeka zachowuje swój podgórski charakter, wijąc się wśród łąk i zagajników Warmii. Podłoże jest tu zróżnicowane, piaszczyste z lokalnymi partiami żwiru, co sprzyja bytowaniu lipieni oraz jelców. To doskonałe miejsce dla muszkarzy, którzy cenią sobie możliwość brodzenia w krystalicznie czystej i płytkiej wodzie. Spinningiści z sukcesami obławiają tutejsze zakręty, szukając okoni oraz kleni żerujących na granicy nurtu. Uciąg rzeki jest stabilny, co pozwala na naturalną prezentację lekkich przynęt w warkoczach prądowych. Cisza panująca nad brzegami oraz obecność dzikiej zwierzyny sprawiają, że każda wyprawa w ten rejon jest formą aktywnego wypoczynku.', 'PZW Olsztyn');

