VALUES (70735, 'Górska', 'Meandrująca, łąkowa', 10.0, 0.8, 'Piasek i żwir', 'Bystrza żwirowe', 'Lipień, Jelec, Kleń', 'Kraina pstrąga', false);

-- Spot 737: Zezuty (Górne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70736, 'Pasłęka - Zezuty (Jar)', 'pasleka-zezuty-1', 'RIVER', 53.6626068, 20.3451985, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Pasłęka w rejonie miejscowości Zezuty to jeden z najpiękniejszych fragmentów rzeki, charakteryzujący się dzikim i nieuregulowanym korytem. Rzeka płynie tu w głębokim jarze, tworząc liczne bystrza oraz głębokie rynny pod podmywanymi burtami brzegowymi. To wymarzone stanowisko dla łowców pstrągów potokowych, którzy potrafią czytać trudną technicznie, leśną wodę. Dno usiane jest kamieniami i korzeniami drzew, co wymaga od wędkarza stosowania odpornych na przetarcia zestawów. Uciąg wody jest tu bardzo dynamiczny, co sprzyja aktywności ryb reofilnych przez cały sezon wędkarski. Status ochronny rzeki sprawia, że rybostan jest tu zdrowy, a ryby osiągają imponujące rozmiary w naturalnych warunkach.', 'PZW Olsztyn');

