VALUES (70736, 'Górska', 'Przełomowa, leśna', 8.0, 0.9, 'Kamieniste', 'Głazy, podmyte korzenie', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- Spot 738: Zezuty (Meandry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70737, 'Pasłęka - Zezuty (Piaszczyste Łachy)', 'pasleka-zezuty-2', 'RIVER', 53.6845446, 20.3180656, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Nieco niżej w Zezutach rzeka rozlewa się nieco szerzej, tworząc technicznie ciekawe płanie oraz piaszczyste łachy. Koryto jest tu mocno urozmaicone przez działalność bobrów, co skutkuje powstaniem licznych zastoisk idealnych dla mniejszych szczupaków. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz jelce, wykorzystując delikatne zestawy spławikowe. Nurt rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie punktowe wzdłuż linii brzegowej. Czystość wody pozwala na obserwację żerujących ryb, co dodaje emocji każdemu spinningiście badającemu tutejsze tonie. Miejsce to zapewnia intymną atmosferę i doskonałe warunki do technicznego treningu przed wyprawami na większe rzeki.', 'PZW Olsztyn');

