-- Spot 739: Wapnik
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70738, 'Pasłęka - Wapnik (Nizinny Nurt)', 'pasleka-wapnik', 'RIVER', 54.0495755, 20.1172537, 'Warmińsko-Mazurskie', 'Lubomino', 'W Wapniku Pasłęka przybiera charakter rzeki podgórsko-nizinnej z wyraźnie zaznaczonymi rynnami prądowymi i piaszczystym dnem. Rzeka płynie tu dostojnie przez tereny rolnicze i leśne, oferując wędkarzom dogodne stanowiska pod wysokimi brzegami. To strategiczne miejsce dla łowców kleni oraz jazi, które doskonale reagują na małe woblery i obrotówki prowadzone w nurcie. Uciąg wody jest tu umiarkowany, co sprzyja komfortowemu łowieniu metodą lekkiego gruntu lub spławika. W głębszych dołkach pod zwalonymi konarami często stacjonują szczupaki, czekające na spływający z prądem pokarm. Spokojna okolica oraz relatywnie łatwy dostęp do brzegów czynią ten odcinek popularnym punktem na mapie warmińskich wędkarzy.', 'PZW Olsztyn');

