VALUES (70738, 'Nizinna', 'Łagodna, szeroka', 15.0, 1.5, 'Piasek i glina', 'Zwalone konary', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', false);

-- Spot 740: gmina Miłakowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70739, 'Pasłęka - gmina Miłakowo (Leśne Plosy)', 'pasleka-milakowo', 'RIVER', 54.073747, 20.0965605, 'Warmińsko-Mazurskie', 'Miłakowo', 'Pasłęka w gminie Miłakowo płynie malowniczo przez tereny leśne, zachowując swój dziki i nieuregulowany charakter. Koryto rzeki posiada tu piaszczyste dno z wyraźnymi rynnami na łukach, które stanowią bezpieczną ostoję dla rekordowych kleni. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w pobliżu nadrzecznych trzcinowisk i zatok. Uciąg wody jest umiarkowany i przewidywalny, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu. Podmyte brzegi porośnięte gęstą wikliną stanowią naturalną kryjówkę dla dużych okoni oraz rzecznych jazi. Niska presja wędkarska w tym rejonie zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z niewypłoszoną rybą.', 'PZW Olsztyn');

