-- Spot 741: gmina Godkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70740, 'Pasłęka - gmina Godkowo (Bobrowy Nurt)', 'pasleka-godkowo', 'RIVER', 54.0808607, 20.052082, 'Warmińsko-Mazurskie', 'Pasłęk', 'Odcinek w gminie Godkowo to kwintesencja warmińskiej rzeki, gdzie koryto staje się węższe i silnie zarośnięte nadrzeczną roślinnością. Rzeka żłobi tu dno o charakterze piaszczysto-żwirowym, co stwarza idealne warunki tlenowe dla walecznych pstrągów potokowych. To strategiczne miejsce dla spinningistów, którzy wykorzystują liczne zatory z pni drzew do precyzyjnego podawania małych woblerów. Uciąg wody jest tu żywy i zmienny, tworząc techniczne warkocze prądowe idealne do łowienia metodą przepływanki. W głębszych dołkach pod burtami brzegowymi często stacjonują wyrośnięte klenie, które doskonale reagują na owadowe przynęty powierzchniowe. Malowniczy krajobraz oraz status rezerwatu bobrów nadają każdemu wędkowaniu w tym miejscu unikalnego, pierwotnego charakteru.', 'PZW Olsztyn');

