-- Spot 742: Olkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70741, 'Pasłęka - Olkowo (Bystrza)', 'pasleka-olkowo', 'RIVER', 54.1066349, 20.0374303, 'Warmińsko-Mazurskie', 'Orneta', 'Pasłęka w Olkowie to technicznie wymagające łowisko o urozmaiconej rzeźbie dna i kamienistym podłożu koryta głównego. Rzeka płynie tu dynamicznie, tworząc liczne bystrza oraz głębokie rynny pod wysokimi burtami brzegowymi. To wymarzone stanowisko dla łowców pstrągów, którzy potrafią czytać wodę i odnajdywać ryby w mikro-warkoczach za głazami. Uciąg rzeki pozwala na naturalną prezentację przynęty w nurcie przy użyciu technik muchowych oraz ultralekkiego spinningu. Woda zachowuje tu wysoką przejrzystość, co wymusza na wędkarzu zachowanie dużej ostrożności i stosowanie cienkich przyponów. Dzięki naturalnej rzeźbie terenu odcinek ten oferuje jedne z najbardziej malowniczych stanowisk wędkarskich w całym dorzeczu.', 'PZW Olsztyn');

