-- Spot 743: gmina Płoskinia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70742, 'Pasłęka - gmina Płoskinia (Dolna)', 'pasleka-ploskinia', 'RIVER', 54.239137, 19.8845578, 'Warmińsko-Mazurskie', 'Braniewo', 'Odcinek w gminie Płoskinia znajduje się w dolnym biegu rzeki, gdzie koryto staje się znacznie szersze i głębsze. Rzeka żłobi tu dno o piaszczysto-mulistym charakterze, co sprzyja bytowaniu dorodnych leszczy oraz rzecznych płoci. To doskonałe miejsce dla spinningistów szukających szczupaków, którzy obławiają krawędzie roślinności zanurzonej przy brzegowych zastoiskach. Uciąg wody stabilizuje się, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w polu łowienia. Pod nawisami nadrzecznych drzew często stacjonują okazałe klenie, które doskonale reagują na systematyczne nęcenie grubszą zanętą. Dogodny dostęp do brzegów oraz wysoka rybność odcinka przyciągają wędkarzy szukających spokoju w dolinie Dolnej Pasłęki.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70742, 'Nizinna', 'Szeroka, nurt stabilny', 20.0, 2.2, 'Piasek i muł', 'Zwalone drzewa', 'Leszcz, Szczupak, Kleń', 'Kraina leszcza', false);

-- Spot 744: Mostkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70743, 'Pasłęka - Mostkowo (Przełom)', 'pasleka-mostkowo', 'RIVER', 53.8374614, 20.1228975, 'Warmińsko-Mazurskie', 'Łukta', 'Pasłęka w Mostkowie to odcinek leśny o charakterze przełomowym, gdzie rzeka wcina się głęboko w morenowy krajobraz Warmii. Koryto jest usiane dużymi kamieniami i głazami, które tworzą idealne stanowiska dla pstrągów potokowych i lipieni. To techniczne łowisko wymaga od wędkarza umiejętności precyzyjnego rzutu pod prąd i sprawnego poruszania się w trudnym terenie. Uciąg wody jest tu bardzo silny i nieprzewidywalny, co sprzyja doskonałemu natlenieniu wody przez cały sezon. W głębszych rynnach o żwirowym dnie często grupują się świnki, doskonale reagujące na systematyczne nęcenie drobniejszym pelletem. Miejsce to zapewnia absolutną ciszę oraz unikalną szansę na kontakt z dziką, niewypłoszoną rybą w sercu lasu.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70743, 'Górska', 'Przełomowa, skalista', 10.0, 0.8, 'Skała i żwir', 'Głazy w nurcie', 'Pstrąg potokowy, Lipień, Świnka', 'Kraina pstrąga', false);

-- Spot 745: Gamerki Małe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70744, 'Pasłęka - Gamerki Małe (Płanie lipieniowe)', 'pasleka-gamerki-male', 'RIVER', 53.8570052, 20.1551098, 'Warmińsko-Mazurskie', 'Łukta', 'Odcinek w Gamerkach Małych słynie wśród muszkarzy jako jedno z najlepszych stanowisk do łowienia lipieni w północnej Polsce. Rzeka tworzy tu liczne bystrza i szerokie płanie o żwirowym dnie, które są naturalną bazą pokarmową dla ryb łososiowatych. To strategiczne miejsce dla spinningistów, którzy wykorzystują małe woblery i obrotówki do polowania na waleczne klenie. Uciąg rzeki jest żywy, co pozwala na naturalną prezentację muszek oraz mikro-jigów w powierzchniowych partiach wody. Brzegi są niskie i łatwo dostępne, co ułatwia bezpieczne brodzenie bez konieczności używania wysokich spodniobutów. Wysoka przejrzystość wody oraz urokliwy krajobraz doliny Pasłęki czynią to łowisko obowiązkowym punktem na mapie regionu.', 'PZW Olsztyn');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70744, 'Górska', 'Bystra, żwirowa', 12.0, 0.7, 'Żwir i piasek', 'Żwirowe łachy', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 746: Kojdy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70745, 'Pasłęka - Kojdy (Leśny Przełom)', 'pasleka-kojdy', 'RIVER', 53.8810775, 20.1761984, 'Warmińsko-Mazurskie', 'Łukta', 'Rzeka w okolicach Kojd płynie przez zwarty kompleks leśny, zachowując charakter bystrego, podgórskiego potoku. Koryto jest tu dość wąskie i obfituje w liczne zatory z powalonych drzew, które stanowią doskonałe kryjówki dla pstrągów potokowych. Podłoże ma charakter piaszczysto-żwirowy z wyraźnie zaznaczonymi rynnami prądowymi na zakrętach. To strategiczne miejsce dla spinningistów szukających kleni oraz jazi żerujących pod nawisami gałęzi. Uciąg wody jest tu żywy, co sprzyja wysokiemu natlenieniu wody nawet podczas letnich upałów 2026 roku. Dyskrecja nad brzegiem jest kluczowa ze względu na wysoką przejrzystość wody i dziki charakter tego rezerwatu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70745, 'Górska', 'Dzika, leśna', 8.0, 0.7, 'Piasek i żwir', 'Zatory z pni', 'Pstrąg potokowy, Kleń, Jaź', 'Kraina pstrąga', false);

-- Spot 747: Kłobia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70746, 'Pasłęka - Kłobia (Meandry)', 'pasleka-klobia', 'RIVER', 53.907435, 20.1864015, 'Warmińsko-Mazurskie', 'Łukta', 'Pasłęka w Kłobi charakteryzuje się licznymi meandrami i głębokimi dołami wymytymi na zewnętrznych łukach rzeki. Podłoże jest tu bardziej zróżnicowane, z przewagą piasku i gliny, co sprzyja bytowaniu dorodnych szczupaków. Wędkarze stacjonarni z sukcesami łowią tu okazałe płocie oraz jelce, wykorzystując spowolnienia nurtu za zwalonymi konarami. Uciąg rzeki w tym miejscu stabilizuje się, tworząc techniczne płanie idealne do prowadzenia lekkich przynęt spinningowych. To doskonałe łowisko dla osób szukających kontaktu z naturą z dala od popularnych szlaków turystycznych. Woda zachowuje tu pierwszą klasę czystości, co przekłada się na doskonałą kondycję i waleczność tutejszych ryb.', null);

