VALUES (70746, 'Nizinna', 'Naturalna, kręta', 10.0, 1.2, 'Piasek i glina', 'Głębokie dołki', 'Szczupak, Płoć, Jelec', 'Kraina lipienia', false);

-- Spot 748: Kalisty
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70747, 'Pasłęka - Kalisty (Bystrza Żwirowe)', 'pasleka-kalisty', 'RIVER', 53.9343572, 20.1920662, 'Warmińsko-Mazurskie', 'Miłakowo', 'W rejonie miejscowości Kalisty rzeka przyspiesza, płynąc po twardym, kamienisto-żwirowym dnie o wysokim stopniu natlenienia. Jest to strategiczne miejsce dla muszkarzy, którzy celują w lipienie żerujące na bogatej faunie dennej. Spinningiści z sukcesami obławiają tutejsze bystrza, szukając pstrągów potokowych stacjonujących w cieniu większych głazów. Uciąg jest zdecydowany, co wymaga precyzyjnego dociążenia przynęt w celu sprowadzenia ich w pobliże dna. Brzegi są tu nieco wyższe i porośnięte olszami, co stwarza doskonałe warunki do podchodu pod ostrożne ryby. Status rezerwatu bobrów zapewnia nienaruszony ekosystem, co w 2026 roku owocuje stabilną populacją ryb łososiowatych.', null);

