VALUES (70747, 'Górska', 'Bystra, kamienista', 12.0, 0.9, 'Kamień i żwir', 'Bystrza', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 749: Konradowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70748, 'Pasłęka - Konradowo (Płanie)', 'pasleka-konradowo', 'RIVER', 53.959709, 20.2078912, 'Warmińsko-Mazurskie', 'Lubomino', 'Odcinek w Konradowie charakteryzuje się szerszym korytem i obecnością rozległych płani o piaszczystym podłożu. Rzeka płynie tu dostojnie przez tereny łąkowe, oferując wędkarzom dogodny dostęp do linii brzegowej. To doskonałe łowisko dla wędkarzy feederowych celujących w okazałe klenie oraz jazie, które grupują się w rynnach głównego nurtu. Spinningiści chętnie obławiają krawędzie roślinności zanurzonej, szukając okoni oraz szczupaków czatujących w zastoiskach. Uciąg wody jest umiarkowany, co pozwala na naturalną prezentację przynęt roślinnych oraz małych woblerów. Czystość wody i brak uregulowań hydrotechnicznych sprawiają, że ryby żerują tu bardzo odważnie przez cały sezon.', null);

