VALUES (70749, 'Nizinna', 'Naturalna, głęboka', 14.0, 1.8, 'Piasek i glina', 'Podmyte burty', 'Leszcz, Szczupak, Kleń', 'Kraina leszcza', false);

-- Spot 751: Raciszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70750, 'Pasłęka - Raciszewo (Żwirowe Łachy)', 'pasleka-raciszewo', 'RIVER', 54.0028335, 20.150414, 'Warmińsko-Mazurskie', 'Lubomino', 'Odcinek w Raciszewie charakteryzuje się przejściem rzeki w charakter podgórsko-nizinny z licznymi żwirowymi łachami w nurcie. Rzeka płynie tu szeroko, oferując wędkarzom twarde podłoże idealne do bezpiecznego brodzenia w poszukiwaniu najlepszych stanowisk. To doskonałe łowisko dla łowców jazi i kleni, które doskonale reagują na systematyczne nęcenie drobną frakcją zanętową. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając okoni oraz pstrągów potokowych spływających z wyższych partii rzeki. Uciąg wody jest stabilny i zapewnia świetne warunki do łowienia metodą lekkiego gruntu z koszyczkiem. Cisza i spokój panujące w tej okolicy czynią Raciszewo jednym z najbardziej relaksujących punktów na mapie całej Pasłęki.', null);

