VALUES (70750, 'Nizinna', 'Szeroka, żwirowa', 16.0, 1.3, 'Żwir i piasek', 'Żwirowe łachy', 'Jaź, Kleń, Okoń', 'Kraina leszcza', false);

-- Spot 752: Świękity
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70751, 'Pasłęka - Świękity (Rezerwat)', 'pasleka-swiekity', 'RIVER', 54.0305858, 20.1530429, 'Warmińsko-Mazurskie', 'Lubomino', 'Pasłęka w Świękitach płynie głębokim jarem, zachowując swój najbardziej pierwotny i dziki charakter rezerwatu przyrody. Koryto rzeki jest tu mocno zablokowane licznymi zwalonymi przez bobry drzewami, co wymusza na wędkarzu techniczne łowienie w krótkich rynnach. Podłoże jest piaszczysto-żwirowe z wyraźnymi uskokami dna, które stanowią bezpieczną ostoję dla walecznych jazi oraz kleni. To doskonałe łowisko dla spinningistów szukających pstrągów potokowych w cieniu podmytych brzegów i korzeni nadrzecznych olch. Uciąg wody jest tu żywy i zapewnia świetne warunki do łowienia metodą przepływanki z bardzo czułym spławikiem. Cisza panująca w tej okolicy oraz brak jakiejkolwiek infrastruktury nadają temu miejscu unikalnego, warmińskiego klimatu.', null);

