-- Spot 753: Pierzchały (Elektrownia i Zapora)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70752, 'Pasłęka - Pierzchały (Pod Zaporą)', 'pasleka-pierzchaly', 'RIVER', 54.2893924, 19.848356, 'Warmińsko-Mazurskie', 'Braniewo', 'Odcinek rzeki w Pierzchałach znajduje się bezpośrednio poniżej elektrowni wodnej, co gwarantuje silne natlenienie wody i wysoką aktywność ryb. Podłoże jest tu twarde, kamienisto-żwirowe z licznymi dołami wymytymi przez zrzuty wody z turbin zapory. To strategiczne miejsce dla łowców szczupaków oraz sandaczy, które grupują się tu w poszukiwaniu łatwego pokarmu płynącego ze zbiornika. Spinningiści z sukcesami obławiają tutejsze turbulentne warkocze prądowe, szukając okoni stacjonujących przy betonowych umocnieniach koryta. Uciąg wody jest uzależniony od pracy elektrowni, co wymaga od wędkarza częstej adaptacji ciężaru zestawów gruntowych. Bliskość jeziora Pierzchalskiego sprawia, że rybostan jest tu wyjątkowo zróżnicowany i zasilany migracjami ryb z górnego biegu.', null);

