VALUES (70752, 'Nizinna', 'Techniczna, pod zaporą', 22.0, 2.5, 'Kamień i beton', 'Jaz, elektrownia', 'Szczupak, Sandacz, Okoń', 'Kraina leszcza', false);

-- Spot 754: Wielewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70753, 'Pasłęka - Wielewo (Rynny)', 'pasleka-wielewo', 'RIVER', 54.3164132, 19.8519479, 'Warmińsko-Mazurskie', 'Braniewo', 'Pasłęka w Wielewie płynie szerokim, nizinnym korytem przez tereny łąkowe o piaszczysto-gliniastym podłożu dna. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach, które stanowią bezpieczną ostoję dla dorodnych leszczy i rzecznych płoci. To doskonałe miejsce dla wędkarzy feederowych, którzy cenią sobie spokój i możliwość nęcenia stad ryb białego żeru w mniejszym uciągu. Spinningiści chętnie obławiają krawędzie nadrzecznych trzcinowisk, szukając szczupaków czatujących na przybrzeżną drobnicę. Uciąg rzeki stabilizuje się na tym odcinku, co sprzyja precyzyjnemu podawaniu przynęt przy użyciu technik spławikowych. Niska presja wędkarska oraz urokliwy krajobraz doliny Dolnej Pasłęki zapewniają wędkarzowi całkowity odpoczynek nad wodą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70753, 'Nizinna', 'Łąkowa, szeroka', 25.0, 2.0, 'Piasek i glina', 'Trzcinowiska', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', false);

-- Spot 755: Zawierz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70754, 'Pasłęka - Zawierz (Ujściowa Płania)', 'pasleka-zawierz', 'RIVER', 54.3409661, 19.8326662, 'Warmińsko-Mazurskie', 'Braniewo', 'Odcinek w Zawierzu charakteryzuje się dużym urozmaiceniem koryta z licznymi zastoiskami i piaszczystymi łachami wychodzącymi w nurt. Rzeka płynie tu dostojnie, oferując wędkarzom dogodny dostęp do brzegów oraz twarde podłoże idealne do ustawienia stanowiska. To strategiczne miejsce dla łowców jazi i kleni, które doskonale reagują na małe woblery i systematyczne nęcenie roślinne. W głębszych rynnach o wolniejszym przepływie często stacjonują wyrośnięte leszcze, migrujące okresowo z dolnego odcinka rzeki. Uciąg wody jest tu łagodny, co pozwala na stosowanie najdelikatniejszych technik spławikowych z czułymi sygnalizatorami brań. Bliskość Braniewa sprawia, że łowisko jest dobrze znane lokalnym pasjonatom, zachowując jednocześnie wysoką jakość rybostanu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70754, 'Nizinna', 'Szeroka, łagodna', 30.0, 2.2, 'Piasek', 'Zastoiska piaszczyste', 'Jaź, Kleń, Leszcz', 'Kraina leszcza', false);

-- Spot 756: Rudłowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70755, 'Pasłęka - Rudłowo (Przedmieścia)', 'pasleka-rudlowo', 'RIVER', 54.3677087, 19.8457322, 'Warmińsko-Mazurskie', 'Braniewo', 'Pasłęka w Rudłowie to ostatni naturalny odcinek przed wpłynięciem rzeki w zurbanizowane rejony Braniewa. Koryto rzeki posiada tu piaszczysto-muliste dno z szerokimi pasami roślinności wynurzonej, co sprzyja aktywności szczupaków i dorodnych okoni. To doskonałe łowisko dla wędkarzy feederowych celujących w ryby spokojnego żeru wchodzące okresowo z Zalewu Wiślanego. Uciąg wody bywa tu zmienny i uzależniony od zjawiska cofki, co wymusza na wędkarzu posiadanie zestawów o różnej gramaturze. Pod nawisami nadrzecznych wiklin często stacjonują klenie, które doskonale reagują na owadowe przynęty powierzchniowe w letnie wieczory. Spokojna okolica oraz relatywnie łatwy dostęp do wody czynią to łowisko popularnym punktem na mapie warmińskich wędkarzy.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70755, 'Nizinna', 'Szeroka, meandrująca', 35.0, 2.8, 'Piasek i muł', 'Pas roślinności', 'Szczupak, Okoń, Płoć', 'Kraina leszcza', false);

-- Spot 757: Braniewo (Bulwary i Nurt)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70756, 'Pasłęka - Braniewo (Miejska)', 'pasleka-braniewo-miejska', 'RIVER', 54.3892075, 19.8170641, 'Warmińsko-Mazurskie', 'Braniewo', 'Miejski odcinek Pasłęki w Braniewie to techniczne łowisko o uregulowanych brzegach i dużej głębokości toru wodnego. Podłoże jest tu twarde, piaszczysto-betonowe, co przyciąga sandacze oraz sumy szukające schronienia pod murami oporowymi i mostami. To strategiczne miejsce podczas wiosennych ciągów płoci, kiedy tysiące rekordowych ryb wchodzą z Zalewu Wiślanego w rzekę. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy nadrzecznych konstrukcjach hydrotechnicznych. Uciąg wody jest tu stabilny, ale bywa odwracany przez silne wiatry północne powodujące napływ wód morskich. Dobra infrastruktura i oświetlenie brzegów czynią to miejsce idealnym punktem na bezpieczne i skuteczne sesje wędkarskie w samym centrum miasta.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70756, 'Nizinna', 'Uregulowana miejska', 45.0, 3.5, 'Twardy piasek', 'Bulwary, mosty', 'Sandacz, Płoć, Okoń', 'Kraina leszcza', true);

-- -- Spot 758: Braniewo (Dolna Pasłęka)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70757, 'Pasłęka - Braniewo (Wylot)', 'pasleka-braniewo-wylot', 'RIVER', 54.4136195, 19.7963633, 'Warmińsko-Mazurskie', 'Braniewo', 'Dolny odcinek Pasłęki w Braniewie to szeroka rzeka o charakterze żeglownym, płynąca w kierunku otwartych wód Zalewu. Koryto posiada tu piaszczysto-muliste dno z wyraźnym torem wodnym, który przyciąga stada sandaczy i sumów. To strategiczne miejsce podczas jesiennych ciągów okazowych płoci, które szukają tu schronienia przed prądami Zalewu Wiślanego. Uciąg rzeki jest tu zmienny i silnie uzależniony od zjawiska cofki, co wymusza na wędkarzu stosowanie zestawów o różnej gramaturze. Brzegi są częściowo umocnione faszyną, tworząc dogodne stanowiska dla wędkarzy feederowych celujących w białą rybę. W 2026 roku odcinek ten cieszy się sławą jednego z najbardziej rybnych miejsc ujściowych w północnej Polsce.', null);

