-- VALUES (70757, 'Nizinna', 'Szeroka, uregulowana', 50.0, 3.8, 'Piasek i muł', 'Nabrzeża, faszyna', 'Sandacz, Płoć, Leszcz', 'Kraina leszcza', true);

-- -- Spot 759: Nowa Pasłęka (Ujście)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70758, 'Pasłęka - Nowa Pasłęka (Ujście)', 'pasleka-nowa-pasleka', 'RIVER', 54.4279132, 19.7560929, 'Warmińsko-Mazurskie', 'Braniewo', 'Odcinek rzeki w Nowej Pasłęce to finalny fragment toku przed ujściem do wód Zalewu Wiślanego. Koryto rozszerza się tutaj znacznie, a dno przyjmuje charakter piaszczysto-mulisty z grubą warstwą osadów organicznych. To strategiczne miejsce dla łowców okazowych sandaczy oraz okoni migrujących okresowo z wód słonawych w górę rzeki. Uciąg wody jest tu znikomy i niemal całkowicie uzależniony od zjawiska cofki oraz kierunku wiatrów północnych. Brzegi są gęsto porośnięte pasem trzcinowisk, co stanowi naturalne tarlisko dla wielu gatunków ryb spokojnego żeru. W 2026 roku jest to jeden z najpopularniejszych punktów do polowania na rekordowe płocie wchodzące masowo z wód morskich.', null);

