-- VALUES (70758, 'Nizinna', 'Ujściowa, deltowa', 70.0, 4.2, 'Miękki muł', 'Trzcinowiska, port jachtowy', 'Sandacz, Okoń, Płoć', 'Kraina leszcza', true);

-- -- Spot 760: Śródka
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70759, 'Pasłęka - Śródka (Leśne Zakola)', 'pasleka-srodka', 'RIVER', 53.6970204, 20.2552279, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Pasłęka w okolicach Śródki płynie przez gęste kompleksy leśne, tworząc dzikie i nieuregulowane koryto o dużym spadku. Rzeka żłobi tu dno piaszczysto-żwirowe, które jest usiane licznymi zwalonymi przez bobry drzewami i korzeniami. To wymarzone miejsce dla spinningistów szukających dzikich pstrągów potokowych w głębokich rynnach pod burtami. Uciąg wody jest tu żywy i bardzo dynamiczny, co sprzyja doskonałemu natlenieniu wody przez cały sezon. Ze względu na status rezerwatu, presja wędkarska jest tu minimalna, co pozwala rybom osiągać naturalne, rekordowe rozmiary. Dyskretne podejście do stanowiska jest tu kluczowe ze względu na wyjątkową przejrzystość wody i ostrożność drapieżników.', null);

