-- VALUES (70759, 'Górska', 'Dzika, leśna', 10.0, 0.9, 'Piasek i żwir', 'Zwalone drzewa', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- -- Spot 761: Tomaryny (Most Kolejowy)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70760, 'Pasłęka - Tomaryny (Przełom)', 'pasleka-tomaryny', 'RIVER', 53.7185322, 20.2274278, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Odcinek w Tomarynach to jeden z najbardziej technicznych fragmentów Pasłęki, słynący z kamienistego dna i silnego uciągu pod historycznym mostem. Rzeka tworzy tu liczne bystrza i mikro-warkocze za głazami, które są naturalnymi stanowiskami dla lipieni oraz dorodnych kleni. To doskonałe łowisko dla muszkarzy, którzy mogą tu bezpiecznie brodzić po twardym, kamienisto-żwirowym podłożu. W głębszych dołkach poniżej filarów mostu często stacjonują wyrośnięte pstrągi potokowe, czekające na spływający z nurtem pokarm. Woda zachowuje tu krystaliczną czystość, co wymaga od wędkarza stosowania bardzo cienkich i niewidocznych przyponów z fluorocarbonu. Malowniczy krajobraz i szum wody nadają temu miejscu unikalny, niemal górski klimat w samym sercu Warmii.', null);

