-- VALUES (70760, 'Górska', 'Przełomowa, kamienista', 12.0, 0.7, 'Kamień i głazy', 'Filar mostu, bystrza', 'Lipień, Kleń, Pstrąg potokowy', 'Kraina pstrąga', false);

-- -- Spot 762: Woryty
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70761, 'Pasłęka - Woryty (Meandry Łąkowe)', 'pasleka-woryty', 'RIVER', 53.7387418, 20.1971571, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Pasłęka w Worytach płynie wśród malowniczych łąk, tworząc szerokie meandry o urozmaiconym, piaszczysto-gliniastym dnie. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach koryta, które są ulubionym miejscem żerowania okazowych jazi i kleni. To strategiczne stanowisko dla wędkarzy feederowych, którzy z sukcesami łowią tu waleczne brzany doskonale czujące się w silnym nurcie. Uciąg rzeki jest tu stabilny, co pozwala na precyzyjne nęcenie stad ryb białego żeru na krawędzi nurtu głównego. Spinningiści chętnie obławiają tutejsze podmyte burty brzegowe, szukając okoni oraz szczupaków czatujących w cieniu nadrzecznej roślinności. Spokojna okolica i relatywnie łatwy dostęp do brzegów czynią to miejsce popularnym punktem wypraw wędkarzy z Olsztyna i okolic.', null);

