-- -- Spot 763: Łęguty (Wypływ z jeziora Isąg)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70762, 'Pasłęka - Łęguty (Wypływ)', 'pasleka-leguty', 'RIVER', 53.7545493, 20.1601417, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Odcinek w Łęgutach to unikalne miejsce, gdzie Pasłęka opuszcza wody jeziora Isąg, niosąc ze sobą bogaty rybostan jeziorny. Woda jest tu nieco cieplejsza i bardzo żyzna, co sprzyja niezwykle szybkiej aktywności ryb spokojnego żeru wczesną wiosną. Koryto posiada piaszczyste dno z licznymi kępami roślinności podwodnej, stanowiącej idealne kryjówki dla dużych szczupaków i okoni. To doskonałe łowisko dla spinningistów, którzy wykorzystują naturalne spowolnienie nurtu poniżej jeziora do prowadzenia lekkich przynęt. Uciąg wody stabilizuje się tu po kilkuset metrach, przechodząc w charakterystyczny dla środkowej Pasłęki żywy i zdecydowany prąd. Bliskość jeziora i lasu sprawia, że jest to punkt o ogromnym potencjale wędkarskim, łączący gatunki rzeczne z jeziorowymi.', null);

