-- Spot 764: Dąbrówka (Górny Przełom)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70763, 'Pasłęka - Dąbrówka (Leśny Jar)', 'pasleka-dabrowka-1', 'RIVER', 54.1166535, 19.9944627, 'Warmińsko-Mazurskie', 'Orneta', 'Pasłęka w Dąbrówce płynie głębokim jarem, tworząc liczne bystrza oraz głębokie rynny pod podmywanymi burtami brzegowymi. Koryto rzeki jest tu wąskie i usiane zwalonymi przez bobry drzewami, co tworzy idealne kryjówki dla pstrągów potokowych. To techniczne łowisko wymaga od wędkarza dużej dyskrecji oraz precyzyjnych rzutów pod nawisy nadrzecznych olch i wiklin. Podłoże jest piaszczysto-kamieniste z wyraźnymi rynnami prądowymi, w których stacjonują waleczne ryby łososiowate. Uciąg wody jest żywy i zapewnia doskonałe natlenienie rzeki nawet podczas letnich upałów 2026 roku. Status rezerwatu bobrów zapewnia nienaruszony ekosystem i niemal zerową presję wędkarską w tym odosobnionym rejonie.', null);

