-- Spot 765: Dąbrówka (Meandry)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70764, 'Pasłęka - Dąbrówka (Zakola)', 'pasleka-dabrowka-2', 'RIVER', 54.1397952, 19.9705106, 'Warmińsko-Mazurskie', 'Orneta', 'Nieco niżej w Dąbrówce rzeka zaczyna silniej meandrować, tworząc technicznie ciekawe płanie oraz piaszczyste łachy na łukach. Koryto posiada tu piaszczysto-żwirowe dno z licznymi podmyłymi burtami, które skrywają wyrośnięte klenie oraz rzeczne jazie. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w pobliżu nadrzecznych trzcinowisk i zatok. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na naturalną prezentację lekkich przynęt w powierzchniowych partiach wody. Woda zachowuje tu krystaliczną czystość, co wymaga od wędkarza stosowania niewidocznych przyponów z fluorocarbonu. Spokojna okolica oraz brak jakiejkolwiek infrastruktury nadają temu łowisku unikalnego, dzikiego charakteru na mapie Warmii.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70764, 'Nizinna', 'Naturalna, meandrująca', 11.0, 1.2, 'Piasek i żwir', 'Podmyte brzegi', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', false);

-- Spot 766: Wilczęta (Bystrza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70765, 'Pasłęka - Wilczęta (Kamienisty Przełom)', 'pasleka-wilczeta-1', 'RIVER', 54.1624938, 19.9454265, 'Warmińsko-Mazurskie', 'Pasłęk', 'Pasłęka w Wilczętach to jedno z najbardziej technicznych łowisk w regionie, słynące z kamienistego dna i silnego uciągu wody. Rzeka tworzy tu liczne bystrza i mikro-warkocze za głazami, które są naturalnymi stanowiskami dla lipieni oraz dorodnych kleni. To doskonałe łowisko dla muszkarzy, którzy mogą tu bezpiecznie brodzić po twardym, kamienisto-żwirowym podłożu koryta. W głębszych dołkach pod burtami brzegowymi często stacjonują wyrośnięte pstrągi potokowe, czekające na pokarm spływający z nurtem. Uciąg rzeki jest tu bardzo dynamiczny, co sprzyja doskonałemu natlenieniu wody przez cały rok wędkarski. Malowniczy krajobraz oraz wysoka rybność odcinka czynią to miejsce obowiązkowym punktem na mapie każdego fana rzecznego spinningu.', null);

