VALUES (70765, 'Górska', 'Przełomowa, kamienista', 12.0, 0.7, 'Kamień i żwir', 'Bystrza skalne', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 767: Wilczęta (Łęgi)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70766, 'Pasłęka - Wilczęta (Piaszczyste Płanie)', 'pasleka-wilczeta-2', 'RIVER', 54.1891498, 19.952702, 'Warmińsko-Mazurskie', 'Pasłęk', 'Odcinek rzeki poniżej Wilcząt charakteryzuje się szerszym korytem i obecnością rozległych płani o piaszczystym podłożu dna. Rzeka płynie tu dostojnie przez nadodrzańskie łęgi, oferując wędkarzom dogodny dostęp do brzegów oraz liczne zatoki brzegowe. To strategiczne miejsce dla łowców jazi i kleni, które doskonale reagują na małe woblery oraz systematyczne nęcenie roślinne. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając okoni oraz szczupaków czatujących w cieniu nadrzecznych wiklin. Uciąg wody jest stabilny i przewidywalny, co sprzyja systematycznemu nęczeniu i utrzymywaniu stad białorybu w łowisku. Cisza i spokój panujące w tej okolicy czynią ten fragment rzeki idealnym na relaksujące sesje z wędką.', null);

