VALUES (70766, 'Nizinna', 'Szeroka, piaszczysta', 15.0, 1.4, 'Piasek i glina', 'Zatoki brzegowe', 'Jaź, Kleń, Szczupak', 'Kraina leszcza', false);

-- Spot 768: gmina Wilczęta (Głębokie Rynny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70767, 'Pasłęka - gmina Wilczęta (Jamy)', 'pasleka-wilczeta-gmina', 'RIVER', 54.2118502, 19.9258223, 'Warmińsko-Mazurskie', 'Pasłęk', 'Pasłęka na północ od Wilcząt charakteryzuje się bardzo głębokimi rynnami szczytowymi na łukach i wyraźnie zaznaczoną linią brzegową. Podłoże jest tu twarde, piaszczysto-gliniaste z licznymi podmyłymi burtami, które stanowią bezpieczną ostoję dla rekordowych kleni. To doskonałe łowisko dla wędkarzy feederowych celujących w okazałe leszcze oraz rzeczne płocie żerujące w mniejszym uciągu. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy zatopionych w wodzie karczowiskach i gałęziach. Uciąg rzeki w tym miejscu jest stabilny, co pozwala na precyzyjne nęcenie punktowe rzecznymi mieszankami zanętowymi. Malowniczy krajobraz pradoliny rzeki oraz niska presja wędkarska w tym rejonie gwarantują spokój podczas całodniowych sesji.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70767, 'Nizinna', 'Szeroka, głęboka', 16.0, 2.0, 'Piasek i glina', 'Podmyte burty, karcze', 'Leszcz, Kleń, Okoń', 'Kraina leszcza', false);

-- Spot 769: Pelnik (Wypływ z jeziora Isąg)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70768, 'Pasłęka - Pelnik (Ujście z Jeziora)', 'pasleka-pelnik', 'RIVER', 53.7839612, 20.1487451, 'Warmińsko-Mazurskie', 'Łukta', 'Odcinek w Pelniku to unikalne miejsce, gdzie Pasłęka opuszcza wody jeziora Isąg, niosąc ze sobą bogaty rybostan jeziorny. Woda jest tu nieco cieplejsza i bardzo żyzna, co sprzyja niezwykle szybkiej aktywności ryb spokojnego żeru wczesną wiosną. Koryto posiada piaszczyste dno z licznymi kępami roślinności podwodnej, stanowiącej idealne kryjówki dla dużych szczupaków i okoni. To doskonałe łowisko dla spinningistów, którzy wykorzystują naturalne spowolnienie nurtu poniżej wypływu do prowadzenia lekkich przynęt. Uciąg wody stabilizuje się tu po kilkuset metrach, przechodząc w charakterystyczny dla środkowej Pasłęki żywy i zdecydowany prąd. Bliskość jeziora i lasu sprawia, że jest to punkt o ogromnym potencjale wędkarskim, łączący gatunki rzeczne z jeziorowymi.', null);

