VALUES (70768, 'Nizinna', 'Wypływ z jeziora', 18.0, 1.2, 'Piasek i roślinność', 'Kępy roślin podwodnych', 'Szczupak, Okoń, Leszcz', 'Kraina leszcza', false);

-- Spot 770: Łabędź (Górna Pasłęka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70769, 'Pasłęka - Łabędź (Pstrągowy Jar)', 'pasleka-labedz', 'RIVER', 53.8106473, 20.1409478, 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Pasłęka w rejonie miejscowości Łabędź płynie w głębokim, zalesionym jarze, zachowując charakter bystrego potoku podgórskiego. Koryto rzeki jest tu wąskie, usiane licznymi zwalonymi przez bobry drzewami, które tworzą idealne stanowiska dla pstrągów potokowych. Podłoże jest twarde, kamienisto-żwirowe z wyraźnymi bystrzami, zapewniającymi doskonałe natlenienie wody przez cały rok. To techniczne łowisko wymaga od wędkarza dużej dyskrecji i precyzyjnych rzutów spinningowych pod nawisy nadrzecznych wiklin. Uciąg wody jest bardzo żywy, co sprzyja aktywności ryb łososiowatych żerujących w mikro-rynnie głównego nurtu. Status rezerwatu i brak uregulowań hydrotechnicznych czynią to miejsce jednym z najdzikszych zakątków dorzecza w 2026 roku.', null);

