-- Spot 771: Piórkowo (Przedpole Pierzchał)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70770, 'Pasłęka - Piórkowo (Rynny Sandaczowe)', 'pasleka-piorkowo', 'RIVER', 54.2577865, 19.8460435, 'Warmińsko-Mazurskie', 'Braniewo', 'Odcinek w Piórkowie to dolny bieg rzeki o szerokim korycie, znajdujący się pod silnym wpływem cofki zbiornika elektrowni Pierzchały. Rzeka żłobi tu głębokie rynny w piaszczysto-mulistym dnie, które stanowią bezpieczną ostoję dla rekordowych sandaczy i sumów. To strategiczne miejsce dla wędkarzy feederowych, którzy z sukcesami nęcą tutejsze płanie w poszukiwaniu dorodnych leszczy i jazi. Uciąg wody stabilizuje się w tym rejonie, co pozwala na precyzyjne podawanie przynęt roślinnych oraz małych woblerów w nurcie. Spinningiści chętnie obławiają krawędzie nadrzecznych trzcinowisk, szukając szczupaków czatujących na przybrzeżną drobnicę migrującą z jeziora. Łatwy dostęp do brzegów oraz wysoka rybność odcinka przyciągają wędkarzy szukających stabilnych wyników w dolinie Dolnej Pasłęki.', null);

