-- Spot 772: Gapinin-Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70771, 'Pilica - Gapinin-Kolonia (Przykosy)', 'pilica-gapinin-kolonia', 'RIVER', 51.5858181, 20.3960542, 'Łódzkie', 'Inowłódz', 'Pilica w Gapininie to klasyczna rzeka nizinna o piaszczystym dnie i licznych, przemieszczających się okresowo przykosach. Nurt jest tu umiarkowany, tworząc idealne warunki dla stad jazi oraz kleni żerujących na granicy głównego prądu i spokojnej wody. To strategiczne miejsce dla spinningistów polujących na bolenie, które agresywnie atakują ukleje na piaszczystych łachach przy brzegach. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie, licząc na brania dorodnych leszczy oraz rzecznych płoci migrujących korytem. Uciąg wody jest stabilny i przewidywalny, co sprzyja precyzyjnemu nęceniu punktowemu przy użyciu lekkich koszyczków zanętowych. Malowniczy krajobraz doliny Pilicy zapewnia w 2026 roku całkowity spokój i doskonałe warunki do technicznego treningu rzecznego.', null);

