-- Spot 773: Domaniewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70772, 'Pilica - Domaniewice (Płanie)', 'pilica-domaniewice', 'RIVER', 51.6163593, 20.4522761, 'Łódzkie', 'Nowe Miasto nad Pilicą', 'Odcinek w Domaniewicach charakteryzuje się szerszym korytem i obecnością rozległych, piaszczystych płani o wyrównanym podłożu dna. Rzeka płynie tu dostojnie, oferując wędkarzom dogodny dostęp do brzegów oraz liczne zastoiska z bogatą roślinnością wynurzoną. To doskonałe łowisko dla wędkarzy feederowych celujących w białą rybę migrującą okresowo w górę biegu rzeki w poszukiwaniu tlenu. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając szczupaków czatujących w cieniu nadrzecznych wiklin i gęstych trzcin. Uciąg wody jest łagodny, co pozwala na stosowanie najdelikatniejszych technik spławikowych z bardzo czułymi sygnalizatorami brań. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz szansę na kontakt z niewypłoszoną rybą w sielskim krajobrazie.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70772, 'Nizinna', 'Szeroka, nurt łagodny', 45.0, 1.5, 'Piasek i muł', 'Zastoiska roślinne', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', true);

-- Spot 774: Czerwona Karczma
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70773, 'Pilica - Czerwona Karczma (Rynny)', 'pilica-czerwona-karczma', 'RIVER', 51.6102452, 20.5247889, 'Łódzkie', 'Nowe Miasto nad Pilicą', 'Pilica w rejonie Czerwonej Karczmy to technicznie ciekawe łowisko z głębokimi rynnami wymytymi na zewnętrznych łukach koryta. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z licznymi podmyłymi burtami stanowiącymi bankowe ostoje dla dużych kleni. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie dołki za naturalnymi przeszkodami jako dzienne kryjówki drapieżników. Spinningiści chętnie obławiają tutejsze warkocze prądowe, szukając okoni oraz szczupaków czatujących na przelewach piaszczystych przykos rzecznych. Uciąg rzeki jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb przez cały sezon wędkarski. Dziki charakter brzegów i brak uregulowań hydrotechnicznych nadają temu miejscu unikalnego, nadpilicznego klimatu.', null);

