-- Spot 775: Pobiedna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70774, 'Pilica - Pobiedna (Łąkowa)', 'pilica-pobiedna', 'RIVER', 51.6103013, 20.5975672, 'Łódzkie', 'Nowe Miasto nad Pilicą', 'Odcinek w Pobiednej płynie wśród malowniczych łąk, tworząc dzikie i nieuregulowane koryto o piaszczysto-żwirowym dnie. Rzeka żłobi tu liczne mikro-rynny prądowe, które są naturalną bazą pokarmową dla stad jelców oraz dorodnych płoci. To doskonałe miejsce dla spinningistów polujących na okonie, którzy wykorzystują liczne zwalone konary drzew jako techniczne punkty podania przynęty. Uciąg wody jest umiarkowany, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w polu łowienia przez wiele godzin. W głębszych dołkach pod burtami często stacjonują szczupaki, doskonale reagujące na systematyczne prowadzenie lekkich przynęt gumowych. Czystość wody i brak infrastruktury technicznej sprawiają, że ryby żerują tu bardzo odważnie w naturalnym rytmie rzeki.', null);

