-- Spot 777: Ulaski Grzmiąckie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70776, 'Pilica - Ulaski Grzmiąckie (Dzika)', 'pilica-ulaski-grzmiackie', 'RIVER', 51.6234422, 20.7414837, 'Mazowieckie', 'Wyśmierzyce', 'Odcinek w Ulaskach Grzmiąckich charakteryzuje się dzikim przebiegiem koryta z dużą ilością zwalonych drzew i zatorów powstałych w wyniku działalności bobrów. Rzeka żłobi tu głębokie rynny w piaszczystym dnie, tworząc idealne stanowiska dla okazowych kleni oraz dużych szczupaków czatujących w nurcie. To techniczne łowisko wymaga od wędkarza precyzyjnych rzutów spinningowych pod nawisy nadrzecznych traw i zwisających wiklin. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i utrzymywaniu ryb w wysokiej kondycji żerowej przez cały rok. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie, wykorzystując technikę przepływanki w rynnach koryta głównego. Izolacja terenu i utrudniony dostęp do brzegów gwarantują absolutną ciszę i kontakt z nienaruszoną naturą doliny Pilicy.', null);

