-- -- Spot 779: Przedbórz (Południe - Zakole)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70778, 'Pilica - Przedbórz (Zakole Południowe)', 'pilica-przedborz-poludnie', 'RIVER', 51.06293, 19.8753731, 'Łódzkie', 'Przedbórz', 'Odcinek Pilicy na południe od Przedborza charakteryzuje się głębokimi rynnami wymytymi na zewnętrznych łukach malowniczych meandrów. Rzeka żłobi tu dno o piaszczysto-gliniastym charakterze, tworząc idealne ostoje dla dorodnych szczupaków oraz dużych okoni. To strategiczne miejsce dla wędkarzy feederowych celujących w okazałe leszcze żerujące w spowolnieniach nurtu za zwalonymi konarami. Uciąg wody jest tu stabilny, co pozwala na precyzyjne nęcenie punktowe i utrzymywanie stad białorybu w polu łowienia. Podmyte brzegi porośnięte gęstą wikliną stanowią bezpieczną kryjówkę dla ryb, wymagając od spinningisty technicznych rzutów. Piękno krajobrazu Przedborskiego Parku Krajobrazowego nadaje każdej wyprawie wędkarskiej w tym rejonie unikalnego klimatu.', null);

