-- Spot 778: Gościencin (Górna Pilica)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70777, 'Pilica - Gościencin (Bystrza Górne)', 'pilica-gosciencin', 'RIVER', 50.9063298, 19.8145614, 'Świętokrzyskie', 'Włoszczowa', 'Pilica w Gościencinie to górny odcinek rzeki o dość wąskim korycie i żywym, podgórskim nurcie. Podłoże jest tu twarde, kamienisto-żwirowe, co stwarza doskonałe warunki tlenowe dla pstrągów potokowych i lipieni. To techniczne łowisko wymaga od wędkarza dużej precyzji w podawaniu małych przynęt pod nawisy nadrzecznych olch. Uciąg wody jest zdecydowany, tworząc liczne mikro-rynny i bystrza, w których stacjonują waleczne ryby reofilne. Spinningiści z sukcesami polują tu na klenie, wykorzystując naturalne zatory z gałęzi jako punkty obserwacyjne drapieżników. Niska presja wędkarska w tym rejonie zapewnia w 2026 roku poczucie obcowania z rzeką niemal dziewiczą i bardzo rybną.', null);

