-- Spot 784: Łany Małe (Źródliskowa Pilica)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70783, 'Pilica - Łany Małe (Potok)', 'pilica-lany-male', 'RIVER', 50.4747718, 19.8156559, 'Śląskie', 'Żarnowiec', 'Pilica w Łanach Małych to jeden z początkowych odcinków rzeki o charakterze wartkiego potoku nizinnego. Koryto jest tu bardzo wąskie, rzadko przekraczające kilka metrów szerokości, z dnem piaszczystym i licznymi kępami roślinności wodnej. To doskonałe miejsce dla spinningistów szukających pstrągów potokowych, które zasiedlają tutejsze chłodne i czyste wody. Podmyte brzegi pod korzeniami drzew stanowią strategiczne kryjówki dla ryb reofilnych w tym mikro-ekosystemie. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu koryta nawet w okresach letnich. Niska presja wędkarska sprawia, że w 2026 roku jest to idealny punkt dla pasjonatów wędrówek z lekkim zestawem.', null);

