-- Spot 785: Brzeziny (Górna Pilica)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70784, 'Pilica - Brzeziny (Bystrza)', 'pilica-brzeziny-kieleckie', 'RIVER', 50.5245481, 19.8455137, 'Świętokrzyskie', 'Szczekociny', 'Odcinek rzeki w Brzezinach charakteryzuje się piaszczysto-żwirowym dnem i licznymi meandrami o naturalnym przebiegu koryta. Pilica płynie tu dość bystro, tworząc techniczne rynny na zakrętach, które skrywają dorodne klenie oraz jazie. To doskonałe łowisko dla spinningistów polujących na pstrągi potokowe spływające z wyższych partii dorzecza. Uciąg wody jest stabilny i zapewnia świetne warunki do łowienia metodą przepływanki z lekkim spławikiem. Brzegi są niskie i łatwo dostępne, co ułatwia bezpieczne brodzenie w poszukiwaniu najlepszych stanowisk w nurcie. W 2026 roku miejsce to pozostaje oazą ciszy, oferując kontakt z rybami rzecznymi w czystej, przejrzystej wodzie.', null);

