-- Spot 786: Dąbrowica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70785, 'Pilica - Dąbrowica (Głębokie Rynny)', 'pilica-dabrowica-swietokrzyskie', 'RIVER', 50.5716116, 19.8445629, 'Świętokrzyskie', 'Szczekociny', 'Pilica w Dąbrowicy to technicznie ciekawe łowisko z wyraźnie zaznaczonymi rynnami prądowymi i piaszczystymi przykosami. Rzeka żłobi tu dno o charakterze piaszczystym, tworząc głębokie dołki pod podmywanymi burtami, będące ostoją dla dużych kleni. To strategiczne miejsce dla łowców szczupaków, którzy obławiają krawędzie nadrzecznych trzcinowisk w poszukiwaniu drapieżników. Uciąg rzeki jest tu żywy, co sprzyja wysokiej aktywności ryb spokojnego żeru, takich jak dorodne jelce oraz płocie. Spinningiści chętnie wykorzystują liczne zwalone drzewa jako techniczne punkty podania przynęty w turbulentnym nurcie. Malowniczy krajobraz doliny górnej Pilicy zapewnia wędkarzowi całkowity spokój oraz szansę na kontakt z niewypłoszoną rybą.', null);

