INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70786, 'Pilica - Chałupki (Łąkowy Nurt)', 'pilica-chalupki', 'RIVER', 50.6192201, 19.856711, 'Świętokrzyskie', 'Koniecpol', 'Odcinek w Chałupkach płynie wśród rozległych łąk, tworząc dzikie i nieuregulowane koryto o urozmaiconym, piaszczystym podłożu dna. Rzeka rozlewa się tu nieco szerzej, tworząc dogodne płanie dla stad jazi oraz kleni patrolujących krawędzie nurtu. To doskonałe łowisko dla wędkarzy feederowych celujących w białą rybę żerującą na piaszczystych blatach rzecznych. Uciąg wody jest umiarkowany, co pozwala na komfortowe nęcenie i utrzymywanie stad białorybu w polu łowienia. Spinningiści z sukcesami obławiają tutejsze zakola, szukając okoni oraz szczupaków czatujących w cieniu nadrzecznych wiklin. Niska presja wędkarska sprawia, że ryby żerują tu bardzo odważnie w naturalnym rytmie rzeki w 2026 roku.', null);

