-- Spot 788: Bógdał
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70787, 'Pilica - Bógdał (Leśne Zakole)', 'pilica-bogdal', 'RIVER', 50.6480535, 19.8023081, 'Śląskie', 'Koniecpol', 'Pilica w rejonie Bógdała to jeden z najbardziej dzikich fragmentów rzeki, charakteryzujący się gęstą roślinnością brzegową i licznymi zatorami. Koryto żłobi tu dno piaszczysto-gliniaste, tworząc głębokie rynny pod burtami, które są bankowymi ostojami dla sumów oraz sandaczy. To strategiczne miejsce dla spinningistów, którzy wykorzystują liczne zwalone konary jako punkty obserwacyjne drapieżników. Uciąg rzeki jest tu żywy i zmienny, co wymusza na wędkarzu umiejętne czytanie prądów oraz wirów wstecznych. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i leszcze, stosując metodę ciężkiej przepływanki w nurcie. Izolacja terenu i utrudniony dostęp do brzegów gwarantują absolutną ciszę i kontakt z nienaruszoną naturą dorzecza.', null);

