-- Spot 789: Tomaszów Mazowiecki (Poniżej Tamy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70788, 'Pilica - Tomaszów Maz. (Miejska)', 'pilica-tomaszow-miejska', 'RIVER', 51.5172365, 20.0301225, 'Łódzkie', 'Tomaszów Mazowiecki', 'Pilica w Tomaszowie Mazowieckim to odcinek o charakterze miejskim, znajdujący się poniżej zapory Zbiornika Sulejowskiego. Woda jest tu silnie natleniona i posiada stabilną temperaturę, co sprzyja obecności rekordowych okazów drapieżników. Podłoże jest twarde, piaszczysto-kamieniste, z wyraźnymi rynnami pod filarami mostów i wzdłuż betonowych umocnień. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni oraz sandaczy żerujących na licznej drobnicy. Wędkarze gruntowi chętnie nęcą piaszczyste płanie poniżej miejskich kaskad, licząc na brania dużych leszczy i cert. W 2026 roku odcinek ten pozostaje jednym z najbardziej technicznych i rybnych łowisk w całym dorzeczu środkowej Pilicy.', null);

