-- Spot 790: Taras
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70789, 'Pilica - Taras (Meandry)', 'pilica-taras', 'RIVER', 51.1506391, 19.9103004, 'Łódzkie', 'Przedbórz', 'Pilica w Tarasie płynie głębokim korytem, tworząc widowiskowe meandry o bardzo zróżnicowanej strukturze piaszczystego dna. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach, które stanowią bezpieczną ostoję dla rekordowych brzan oraz dużych kleni. To strategiczne miejsce dla spinningistów szukających szczupaków czatujących w pobliżu nadrzecznych wiklin i licznych zwalonych konarów. Uciąg wody jest tu żywy i zdecydowany, co sprzyja doskonałemu natlenieniu wody nawet podczas letnich upałów. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując systematyczne nęcenie na krawędzi głównego nurtu. Malowniczy krajobraz Przedborskiego Parku Krajobrazowego zapewnia w 2026 roku całkowity spokój oraz kontakt z nienaruszoną naturą.', null);

