-- Spot 791: Skotniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70790, 'Pilica - Skotniki (Szeroka Płania)', 'pilica-skotniki', 'RIVER', 51.1956715, 19.920972, 'Łódzkie', 'Sulejów', 'Odcinek w Skotnikach charakteryzuje się szerszym korytem i obecnością rozległych piaszczystych przykos wychodzących daleko w nurt. Rzeka płynie tu dostojnie, oferując wędkarzom dogodny dostęp do brzegów oraz piaszczyste dno idealne do bezpiecznego brodzenia. To wymarzone miejsce dla łowców boleni, które agresywnie atakują drobnicę na płytkich przelewach piaszczystych łach. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w dorodne jazie oraz jelce doskonale czujące się w żywym prądzie. Uciąg wody jest umiarkowany, co pozwala na precyzyjne nęcenie punktowe i stosowanie delikatnych zestawów spławikowych. Czystość wody w tym rejonie jest wzorcowa, co przekłada się na wysoką aktywność i waleczność tutejszego rybostanu.', null);

