-- Spot 792: Załęże (Górna Pilica)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70791, 'Pilica - Załęże (Bystrza Górne)', 'pilica-zaleze', 'RIVER', 50.8260083, 19.7275085, 'Śląskie', 'Koniecpol', 'Pilica w Załężu zachowuje charakter podgórskiego potoku o twardym, żwirowo-kamienistym dnie i krystalicznej wodzie. Rzeka płynie tu dość bystro, tworząc liczne bystrza i mikro-rynny, które są naturalnym stanowiskiem dla pstrągów potokowych. To techniczne łowisko wymaga od wędkarza dużej dyskrecji i precyzyjnych rzutów spinningowych pod nawisy nadrzecznych drzew. Spinningiści z sukcesami polują tu na klenie, wykorzystując małe woblery i obrotówki prowadzone w turbulentnym nurcie. Uciąg wody jest tu zdecydowany, co zapewnia świetne natlenienie koryta rzeki przez cały rok wędkarski. Niska presja wędkarska sprawia, że w 2026 roku jest to idealny punkt dla pasjonatów wędrówek z lekkim zestawem pstrągowym.', null);

