-- Spot 793: Kuźnica Grodziska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70792, 'Pilica - Kuźnica Grodziska (Zakola)', 'pilica-kuznica-grodziska', 'RIVER', 50.8702204, 19.7417327, 'Śląskie', 'Koniecpol', 'Odcinek w Kuźnicy Grodziskiej charakteryzuje się naturalnym przebiegiem koryta z licznymi zastoiskami i piaszczystymi łachami. Rzeka żłobi tu dno o charakterze piaszczystym, tworząc dogodne ostoje dla dorodnych płoci oraz jelców w głębszych dołkach. To doskonałe łowisko dla wędkarzy spławikowych, którzy wykorzystują spowolnienia nurtu za zwalonymi konarami drzew. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu. Pod nawisami traw często stacjonują klenie, które doskonale reagują na owadowe przynęty powierzchniowe w letnie wieczory. Spokojna okolica i dzikość brzegów zapewniają wędkarzowi całkowity odpoczynek w naturalnym rytmie rzeki.', null);

