INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70793, 'Pilica - Ciemiętniki (Przełom)', 'pilica-ciemietniki', 'RIVER', 50.949061, 19.8371083, 'Świętokrzyskie', 'Przedbórz', 'Pilica w Ciemiętnikach to jeden z najbardziej malowniczych fragmentów rzeki, gdzie koryto wcina się w morenowy krajobraz regionu. Rzeka posiada tu twarde, piaszczysto-żwirowe dno z wyraźnymi rynnami wymytymi pod wysokimi, podmywanymi burtami. To strategiczne miejsce dla łowców okazowych kleni oraz jazi, które doskonale reagują na techniki spinningowe w silnym nurcie. Uciąg wody jest tu zdecydowany, co sprzyja wysokiej kondycji ryb oraz ich dużej aktywności żerowej przez cały sezon. Wędkarze stacjonarni z sukcesami łowią tu waleczne certy oraz brzany, wykorzystując systematyczne nęcenie w rynnie głównego koryta. Malowniczy krajobraz doliny i wysoka rybność odcinka czynią to łowisko obowiązkowym punktem na mapie środkowej Pilicy.', null);

