VALUES (70800, 'Nizinna Wielka', 'Szeroka, piaszczysta', 65.0, 1.3, 'Piasek', 'Przykosy piaszczyste', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 802: Biejków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70801, 'Pilica - Biejków (Rynny prądowe)', 'pilica-biejkow', 'RIVER', 51.6903646, 21.0043443, 'Mazowieckie', 'Białobrzegi', 'Odcinek rzeki w Biejkowie to technicznie ciekawe łowisko o urozmaiconej rzeźbie dna i silnie zarysowanych rynnach na łukach koryta. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z licznymi podmyłymi burtami stanowiącymi bankowe ostoje dla dużych kleni. To doskonałe miejsce dla spinningistów polujących na szczupaki, którzy obławiają krawędzie nadrzecznych trzcinowisk i zatopione karcze. Uciąg wody jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. W głębszych dołkach pod burtami brzegowymi często stacjonują wyrośnięte okonie, doskonale reagujące na systematyczne prowadzenie przynęt gumowych. Niezakłócona przyroda i brak uregulowań hydrotechnicznych nadają temu miejscu unikalnego, dzikiego charakteru na mazowieckiej mapie Pilicy.', null);

