VALUES (70801, 'Nizinna Wielka', 'Naturalna, meandrująca', 60.0, 1.8, 'Piasek i glina', 'Podmyte burty', 'Kleń, Szczupak, Okoń', 'Kraina leszcza', true);

-- Spot 803: Michałów Dolny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70802, 'Pilica - Michałów Dolny (Wyspy)', 'pilica-michalow-dolny', 'RIVER', 51.710311, 21.070578, 'Mazowieckie', 'Warka', 'Pilica w Michałowie Dolnym to kraina piaszczystych wysp i rozległych łach, które dzielą nurt rzeki na kilka mniejszych odnóg. Takie ukształtowanie koryta stwarza idealne warunki dla jazi i kleni, które znajdują tu obfitość naturalnego pokarmu w nurcie. To strategiczne miejsce dla łowców boleni, którzy obławiają szczyty piaszczystych wysp, gdzie woda gwałtownie przyspiesza na przelewach. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie żwirowe, licząc na brania walecznych leszczy oraz dużych jazi. Uciąg wody jest zmienny i uzależniony od aktualnego stanu rzeki, co wymaga od wędkarza częstej adaptacji obciążenia zestawu. Malowniczy krajobraz rozlewisk oraz wysoka rybność odcinka przyciągają pasjonatów technicznego wędkarstwa rzecznego z całego regionu.', null);

