VALUES (70802, 'Nizinna Wielka', 'Rozwidlona, wyspowa', 75.0, 1.2, 'Piasek i żwir', 'Piaszczyste wyspy', 'Kleń, Jaź, Boleń', 'Kraina leszcza', true);

-- Spot 804: Warka (Most i Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70803, 'Pilica - Warka (Miejska)', 'pilica-warka-miejska', 'RIVER', 51.7596814, 21.147265, 'Mazowieckie', 'Warka', 'Miejskie łowisko w Warce charakteryzuje się uregulowanymi brzegami i dużą głębokością toru wodnego w pobliżu mostu kolejowego i drogowego. Podłoże jest tu twarde, piaszczysto-kamieniste, z wyraźnymi rynnami pod filarami mostów, które są bankowymi stanowiskami dla sandaczy. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie doły wymyte przez nurt w rejonie miejskiej infrastruktury. Spinningiści z sukcesami polują tu na okonie, wykorzystując metodę bocznego troka przy betonowych umocnieniach i murach oporowych. Uciąg wody jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb praktycznie przez całą dobę wędkarską. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko jednym z najpopularniejszych punktów w dolnym biegu rzeki.', null);

