VALUES (70803, 'Nizinna Wielka', 'Uregulowana miejska', 80.0, 2.5, 'Twardy piasek', 'Mosty, nabrzeża', 'Sandacz, Sum, Okoń', 'Kraina leszcza', true);

-- Spot 805: Warka (Odcinek Dolny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70804, 'Pilica - Warka (Łęgowa)', 'pilica-warka-dolna', 'RIVER', 51.7880634, 21.2142386, 'Mazowieckie', 'Warka', 'Dolny odcinek w Warce płynie szerokim korytem przez rozległe nadpiliczne łęgi, charakteryzując się naturalnym, dzikim brzegiem. Rzeka żłobi tu głębokie rynny na krawędzi nurtu, które są ulubionym żerowiskiem boleni patrolujących koryto główne. To doskonałe łowisko dla wędkarzy feederowych celujących w okazałe leszcze oraz rzeczne certy migrujące okresowo w górę rzeki. Uciąg wody jest stabilny, co pozwala na precyzyjne nęcenie i utrzymywanie stad ryb białego żeru w polu łowienia. Pod nawisami nadrzecznych wiklin często stacjonują klenie, które doskonale reagują na owadowe przynęty powierzchniowe w letnie wieczory. Spokojna okolica oraz unikalny mikroklimat dolnej Pilicy sprawiają, że rybostan jest tu wyjątkowo bogaty i atrakcyjny dla wędkarzy w 2026 roku.', null);

