VALUES (70804, 'Nizinna Wielka', 'Szeroka, nurt stabilny', 85.0, 2.0, 'Piasek i glina', 'Podmyte brzegi', 'Leszcz, Boleń, Certa', 'Kraina leszcza', true);

-- Spot 806: Mniszew (Ujście do Wisły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70805, 'Pilica - Mniszew (Ujście)', 'pilica-mniszew-ujscie', 'RIVER', 51.8339578, 21.2718429, 'Mazowieckie', 'Mniszew', 'Odcinek w Mniszewie to finalny fragment biegu Pilicy przed jej spektakularnym ujściem do wód Wisły. Koryto rzeki rozszerza się tu znacznie, tworząc rozległe piaszczyste rozlewiska z licznymi łachami i głębokim torem wodnym. To strategiczny węzeł migracyjny dla ryb wisłślanych, takich jak sumy, sandacze oraz bolenie, które wchodzą w Pilicę na żerowanie. Uciąg wody jest tu potężny i uzależniony od aktualnych stanów Wisły, co wymusza na wędkarzu stosowanie najcięższych zestawów gruntowych. Piaszczyste dno z wyraźnymi uskokami stanowi idealne żerowisko dla rekordowych leszczy oraz cert szukających pokarmu w żyznym ujściu. Każda wyprawa w to miejsce w 2026 roku to szansa na kontakt z największymi okazami ryb nizinnych w Polsce.', null);

