-- Spot 807: Ostrów (Strefa wejściowa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70806, 'Pilica - Ostrów (Przedzalewowa)', 'pilica-ostrow', 'RIVER', 51.2923126, 19.9063519, 'Łódzkie', 'Sulejów', 'Pilica w Ostrowie to ostatni naturalny odcinek rzeki przed jej wpłynięciem w wody cofki Zalewu Sulejowskiego. Koryto jest tu dość szerokie, o piaszczystym dnie usianym licznymi przykosami i głębszymi rynnami na łukach. To strategiczne miejsce dla wędkarzy feederowych, którzy polują na duże leszcze i jazie migrujące między rzeką a zbiornikiem. Uciąg jest tu odczuwalny, ale spowolniony, co sprzyja systematycznemu nęceniu i utrzymywaniu stad ryb białego żeru. Spinningiści z sukcesami obławiają podmyte burty, szukając szczupaków czatujących w cieniu nadrzecznych wiklin. W 2026 roku miejsce to pozostaje oazą spokoju przed bardziej obleganymi stanowiskami na samym zalewie.', null);

