-- Spot 808: Sulejów (Cofka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70807, 'Pilica - Sulejów (Początek Zalewu)', 'pilica-sulejow-cofka', 'RIVER', 51.3370658, 19.8916663, 'Łódzkie', 'Sulejów', 'Odcinek w Sulejowie to strefa przejściowa, gdzie rzeka zaczyna się rozlewać, tworząc płytką, mulistą cofkę zbiornika. Podłoże jest tu miękkie, bogate w osady organiczne, co przyciąga ogromne stada leszczy i krąpi na żerowanie. To wymarzone miejsce dla łowców karpi i amurów, którzy wykorzystują rozległe trzcinowiska jako naturalne kryjówki ryb. Nurt jest tu niemal niewyczuwalny, co pozwala na stosowanie bardzo lekkich zestawów spławikowych i precyzyjne nęcenie. Spinningiści polują tu głównie na szczupaki, prowadząc przynęty nad dywanami roślinności podwodnej w płytkich zatokach. W 2026 roku jest to kluczowe tarlisko i miejsce wczesnowiosennych zasiadek za rybą spokojnego żeru.', null);

