-- Spot 809: Sulejów (Miejskie/Klasztor)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70808, 'Pilica - Sulejów (Pod Mostem)', 'pilica-sulejow-miejska', 'RIVER', 51.3781385, 19.8604424, 'Łódzkie', 'Sulejów', 'Miejskie łowisko w Sulejowie charakteryzuje się głębszym korytem i obecnością filarów mostu drogowego, które generują turbulentne warkocze prądowe. Podłoże jest tu twarde, piaszczysto-kamieniste, co czyni ten odcinek atrakcyjnym dla okoni oraz sandaczy żerujących o zmierzchu. To techniczne łowisko wymaga umiejętnego czytania prądów wodnych omijających umocnienia brzegowe i betonowe nabrzeża. Wędkarze stacjonarni z sukcesami łowią tu okazałe jazie i klenie, wykorzystując metodę przepływanki z cięższym spławikiem. Uciąg wody bywa tu zmienny, uzależniony od aktualnych zrzutów wody i poziomu piętrzenia na głównym zbiorniku. Bliskość zabytkowego opactwa cystersów nadaje wędkowaniu w tym miejscu unikalnego, historycznego klimatu.', null);

