-- Spot 810: Zarzęcin (Centrum Zalewu)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70809, 'Pilica - Zarzęcin (Zalew Sulejowski)', 'pilica-zarzecin', 'RIVER', 51.4194411, 19.9176875, 'Łódzkie', 'Opoczno', 'Zarzęcin to jedno z najpopularniejszych łowisk na Zalewie Sulejowskim, słynące z piaszczystych plaż i gwałtownie opadających stoków starego koryta. Podłoże jest tu zróżnicowane, od piaszczystych blatów po muliste rynny, w których stacjonują rekordowe sandacze. To strategiczne miejsce dla wędkarzy łodziowych, którzy wykorzystują echosondy do namierzania twardych "blatów" pod wodą. Wędkarze brzegowi chętnie nęcą stoki toru wodnego, licząc na brania dużych leszczy oraz nocnych sumów żerujących na uklejach. Wiatr na tym odcinku potrafi wytworzyć sporą falę, co wymusza stosowanie cięższych zestawów gruntowych dla stabilizacji przynęty. W 2026 roku Zarzęcin pozostaje synonimem sandaczowych emocji dla wędkarzy z całej centralnej Polski.', null);

