-- Spot 811: Swolszewice Małe (Zapora)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70810, 'Pilica - Swolszewice (Zapora)', 'pilica-swolszewice', 'RIVER', 51.4629775, 19.9817077, 'Łódzkie', 'Tomaszów Mazowiecki', 'Łowisko w Swolszewicach Małych znajduje się w najgłębszej części Zalewu Sulejowskiego, bezpośrednio przy zaporze w Smardzewicach. Woda jest tu chłodniejsza i bardzo głęboka, co sprzyja bytowaniu największych sumów dorzecza Pilicy szukających schronienia przy dnie. To strategiczne miejsce dla spinningistów łowiących z łodzi, celujących w sandacze stacjonujące na krawędziach betonowych umocnień zapory. Brzegi są tu wysokie i często umocnione, co wymaga od wędkarzy gruntowych stosowania długich wędzisk do bezpiecznego holu ryb. Uciąg wody jest znikomy, ale pionowe prądy przy zrzutach mogą wpływać na aktywność ryb w strefie przydennej. Miejsce to w 2026 roku jest symbolem wędkarstwa trofealnego, gdzie każdy kij może zostać przetestowany przez rekordowy okaz.', null);

