-- Spot 812: Korne (Pilica Pomorska) - UWAGA: INNA RZEKA
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70811, 'Pilica (Pomorska) - Korne', 'pilica-pomorska-korne', 'RIVER', 54.1347841, 17.8629228, 'Pomorskie', 'Kościerzyna', 'Pilica w miejscowości Korne to niewielka, niezwykle malownicza rzeka Pojezierza Kaszubskiego, będąca dopływem Trzebiochy. Koryto jest tu wąskie, o krystalicznej wodzie i piaszczysto-żwirowym dnie, płynące głównie przez tereny leśne i łąkowe. To wymarzone łowisko dla pasjonatów mikro-jigingu i lekkiego spinningu, celujących w potokowe pstrągi oraz dorodne okonie. Uciąg rzeki jest żywy, tworząc liczne meandry i zatory z powalonych drzew, które są naturalną bazą pokarmową ryb. Ze względu na niewielką presję wędkarską, ryby zachowują tu dziki charakter i dużą ostrożność przy pobieraniu przynęty. W 2026 roku jest to ukryty klejnot Pomorza, oferujący spokój i techniczne wyzwania w otoczeniu dzikiej natury.', null);

