-- Spot 813: Teofilów (Inowłódz)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70812, 'Pilica - Teofilów (Odcinek Dolny)', 'pilica-teofilow', 'RIVER', 51.5313252, 20.1611835, 'Łódzkie', 'Inowłódz', 'Pilica w Teofilowie, poniżej Tomaszowa Mazowieckiego, charakteryzuje się bardzo czystą i dobrze natlenioną wodą dzięki zrzutom ze zbiornika. Koryto posiada tu piaszczysto-żwirowe dno z wyraźnymi rynnami wymytymi pod wysokimi brzegami, gdzie stacjonują okazowe klenie. To strategiczne miejsce dla łowców brzan, które doskonale czują się w żywym i stabilnym nurcie tego odcinka. Spinningiści z sukcesami polują tu na bolenie, wykorzystując piaszczyste przykosy jako punkty obserwacyjne atakujących drapieżników. Uciąg rzeki jest tu zdecydowany, co sprzyja metodzie przepływanki z ciężkim spławikiem rzecznym i systematycznemu nęceniu. Malownicze krajobrazy Spalskiego Parku Krajobrazowego nadają każdemu wędkowaniu w 2026 roku unikalnego, relaksującego klimatu.', null);

