-- Spot 814: Kozłowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70813, 'Pilica - Kozłowiec (Łęgowa)', 'pilica-kozlowiec', 'RIVER', 51.5454953, 20.2882427, 'Mazowieckie', 'Inowłódz', 'Odcinek w Kozłowcu to dzika rzeka nizinna płynąca szerokim korytem przez rozległe nadpiliczne łęgi i tereny leśne. Podłoże jest tu piaszczyste, z licznymi podmyłymi burtami i zatopionymi korzeniami nadrzecznych olszyn. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w zastoiskach za naturalnymi przeszkodami w nurcie. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze oraz rzeczne płocie, wykorzystując systematyczne nęcenie w rynnach koryta głównego. Uciąg wody jest umiarkowany i przewidywalny, co sprzyja precyzyjnemu podawaniu przynęt przy użyciu techniki feedera. Niska presja wędkarska oraz wyjątkowa cisza sprawiają, że w 2026 roku Kozłowiec jest cenionym punktem dla osób szukających ucieczki od miejskiego zgiełku.', null);

