-- Spot 815: Palaty
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70814, 'Prosna - Palaty (Dziki Nurt)', 'prosna-palaty', 'RIVER', 51.500069, 18.1319072, 'Wielkopolskie', 'Grabów nad Prosną', 'Prosna w Palatach to odcinek o naturalnym, silnie meandrującym korycie i piaszczysto-żwirowym dnie. Rzeka płynie tu wśród łąk, żłobiąc głębokie rynny na zewnętrznych łukach, które są doskonałą ostoją dla dorodnych kleni. To strategiczne miejsce dla spinningistów polujących na szczupaki, którzy wykorzystują liczne zatory z powalonych drzew jako punkty podania przynęty. Uciąg wody jest tu żywy i zmienny, co sprzyja doskonałemu natlenieniu wody przez cały sezon wędkarski 2026 roku. Wędkarze stacjonarni z sukcesami łowią tu okazałe jazie, stosując metodę lekkiej przepływanki z systematycznym nęceniem. Dzikość brzegów i niska presja wędkarska gwarantują spokój oraz kontakt z nienaruszoną naturą doliny Prosny.', null);

