VALUES (70814, 'Nizinna', 'Naturalna, meandrująca', 12.0, 1.1, 'Piasek i żwir', 'Podmyte brzegi', 'Kleń, Jaź, Szczupak', 'Kraina leszcza', false);

-- Spot 816: Biernacice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70815, 'Prosna - Biernacice (Rynny)', 'prosna-biernacice', 'RIVER', 51.5266906, 18.1392096, 'Wielkopolskie', 'Grabów nad Prosną', 'Odcinek w Biernacicach charakteryzuje się urozmaiconą rzeźbie dna z wyraźnymi uskokami na krawędzi nurtu głównego. Rzeka żłobi tu dno o piaszczysto-gliniastym charakterze, tworząc idealne warunki dla stad rzecznych płoci oraz dorodnych jelców. To doskonałe łowisko dla wędkarzy feederowych celujących w białą rybę żerującą w spowolnieniach nurtu za naturalnymi przeszkodami. Spinningiści z sukcesami obławiają tutejsze podmyte burty, szukając okoni oraz szczupaków czatujących w cieniu nadrzecznych wiklin. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie i utrzymywanie stad ryb w polu łowienia. Malowniczy krajobraz oraz krystaliczna czystość wody przyciągają tu pasjonatów technicznego wędkarstwa rzecznego.', null);

