-- Spot 817: Żydów (Przedmieścia Kalisza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70816, 'Prosna - Żydów (Płanie)', 'prosna-zydow', 'RIVER', 51.7024537, 18.1093321, 'Wielkopolskie', 'Kalisz', 'Prosna w Żydowie płynie szerokim korytem, przygotowując się do wpłynięcia w zurbanizowane rejony Kalisza. Podłoże jest tu piaszczyste z licznymi kępami roślinności zanurzonej, stanowiącej idealne kryjówki dla dużych szczupaków i okoni. To strategiczne miejsce dla łowców kleni, które doskonale reagują na owadowe przynęty powierzchniowe w letnie wieczory. Uciąg wody jest umiarkowany, co sprzyja komfortowemu łowieniu metodą lekkiego gruntu lub spławika na krawędzi nurtu. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie w głębszych rynnach koryta głównego. Niska presja wędkarska sprawia, że ryby żerują tu bardzo odważnie w naturalnym rytmie rzeki 2026 roku.', null);

