VALUES (70816, 'Nizinna', 'Szeroka, łąkowa', 18.0, 1.4, 'Piasek', 'Kępy roślin podwodnych', 'Kleń, Szczupak, Leszcz', 'Kraina leszcza', false);

-- Spot 818: Kalisz (Miejskie Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70817, 'Prosna - Kalisz (Park Miejski)', 'prosna-kalisz-miejska', 'RIVER', 51.7294394, 18.1085449, 'Wielkopolskie', 'Kalisz', 'Miejskie łowisko w Kaliszu charakteryzuje się betonowymi nabrzeżami i głębokimi rynnami pod mostami historycznego centrum. Podłoże jest tu twarde, piaszczysto-kamieniste, co przyciąga sandacze oraz duże okonie szukające schronienia przy konstrukcji bulwarów. To strategiczne miejsce dla spinningistów, którzy wykorzystują techniczne warkocze prądowe do polowania na bolenie patrolujące koryto. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i krąpie, wykorzystując metodę bata lub tyczki przy murach oporowych. Uciąg wody jest stabilny, ale bywa modyfikowany przez pracę jazów, co wymaga od wędkarza częstej adaptacji zestawu. Dobra infrastruktura i łatwy dostęp do brzegów czynią to miejsce idealnym na bezpieczne sesje wędkarskie w 2026 roku.', null);

