VALUES (70817, 'Nizinna', 'Uregulowana miejska', 25.0, 2.0, 'Twardy piasek', 'Bulwary, mosty, jazy', 'Sandacz, Okoń, Płoć', 'Kraina leszcza', false);

-- Spot 819: Stary Olesiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70818, 'Prosna - Stary Olesiec (Dolna)', 'prosna-stary-olesiec', 'RIVER', 51.9568673, 17.8826173, 'Wielkopolskie', 'Chocz', 'Prosna w Starym Oleścu to szeroka rzeka nizinna o bardzo silnie meandrującym korycie i gliniasto-piaszczystym dnie. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach, które stanowią bezpieczną ostoję dla rekordowych sumów i sandaczy. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w cieniu nadrzecznych trzcinowisk i zatok. Uciąg wody jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, stosując metodę ciężkiego feedera z systematycznym nęceniem grubą zanętą. Malowniczy krajobraz doliny Dolnej Prosny oraz niska presja wędkarska gwarantują w 2026 roku spokój podczas całodniowych sesji.', null);

