VALUES (70818, 'Nizinna', 'Szeroka, meandrująca', 30.0, 2.5, 'Glina i piasek', 'Głębokie jamy', 'Sum, Sandacz, Szczupak', 'Kraina leszcza', true);

-- Spot 820: Mazury (Wielkopolskie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70819, 'Prosna - Mazury (Przykosy)', 'prosna-mazury-wlkp', 'RIVER', 51.9776222, 17.8543724, 'Wielkopolskie', 'Gizałki', 'Odcinek w miejscowości Mazury charakteryzuje się piaszczystym dnem i licznymi, przemieszczającymi się przykosami rzecznymi. Rzeka płynie tu szeroko, oferując wędkarzom dogodny dostęp do brzegów oraz twarde podłoże idealne do bezpiecznego brodzenia. To wymarzone miejsce dla łowców boleni, które agresywnie patrolują płytkie przelewy piaszczystych łach w nurcie głównym. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w dorodne jazie oraz rzeczne certy migrujące korytem. Uciąg wody jest tu umiarkowany, co pozwala na stosowanie bardzo delikatnych zestawów spławikowych i gruntowych z czułymi sygnalizatorami. W 2026 roku miejsce to pozostaje popularnym punktem wypraw dla osób szukających ryb reofilnych w naturalnej scenerii.', null);

