-- Spot 821: Kwileń (Ujście Prosny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70820, 'Prosna - Kwileń (Przedujściowa)', 'prosna-kwilen', 'RIVER', 51.99677, 17.82222, 'Wielkopolskie', 'Gizałki', 'Odcinek w Kwileniu to finalny fragment toku Prosny przed jej wpłynięciem w wody Warty, co czyni to miejsce strategicznym węzłem. Koryto rozszerza się tu znacznie, a dno przyjmuje charakter piaszczysto-mulisty z głębokimi rynnami stanowiącymi ostoje dla sumów. To strategiczne miejsce dla łowców sandaczy, którzy wykorzystują uskoki dna toru wodnego do precyzyjnego prowadzenia ciężkich jigów. Uciąg wody bywa tu zmienny i uzależniony od zjawiska cofki z rzeki Warty, co wymaga od wędkarza częstej adaptacji techniki. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w rekordowe leszcze oraz certy wchodzące w Prosnę na żerowanie. Każda wyprawa w to miejsce w 2026 roku to szansa na kontakt z największymi okazami ryb nizinnych migrujących między rzekami.', null);

