-- Spot 822: Giżyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70821, 'Prosna - Giżyce (Meadow Flow)', 'prosna-gzyce', 'RIVER', 51.5412229, 18.1761124, 'Wielkopolskie', 'Grabów nad Prosną', 'Prosna w Giżycach płynie leniwie przez tereny łąkowe, charakteryzując się piaszczysto-mulistym dnem. Meandrujący charakter rzeki tworzy tu liczne głębokie dołki na zewnętrznych łukach, które są idealną ostoją dla dorodnych kleni. To doskonałe miejsce dla wędkarzy spławikowych celujących w jelce oraz płocie żerujące w spowolnieniach nurtu. Spinningiści z sukcesami obławiają krawędzie nadrzecznych trzcinowisk, szukając szczupaków czatujących na drobnicę. Uciąg wody jest stabilny, co pozwala na precyzyjne nęcenie punktowe rzecznymi mieszankami zanętowymi. W 2026 roku miejsce to cieszy się sławą spokojnego łowiska o bardzo wysokiej przejrzystości wody.', null);

