-- Spot 823: Kania
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70822, 'Prosna - Kania (Bobrowy Nurt)', 'prosna-kania', 'RIVER', 51.5679189, 18.1845718, 'Wielkopolskie', 'Grabów nad Prosną', 'Odcinek w okolicach Kani to technicznie wymagająca woda z dużą ilością zwalonych przez bobry drzew i karczowisk. Rzeka żłobi tu dno o twardym, gliniasto-piaszczystym charakterze, co sprzyja bytowaniu walecznych kleni oraz jazi. To strategiczne miejsce dla spinningistów szukających szczupaków czatujących w cieniu podwodnych przeszkód i korzeni. Głębokie rynny w nurcie głównym skrywają dorodne okonie, które doskonale reagują na małe przynęty gumowe. Uciąg wody jest tu żywy i zmienny, co wymaga od wędkarza umiejętnego czytania prądów wstecznych. Utrudniony dostęp do brzegów gwarantuje w 2026 roku niską presję wędkarską i szansę na kontakt z rekordowym okazem.', null);

