-- Spot 824: Nowa Kakawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70823, 'Prosna - Nowa Kakawa (Przykosy)', 'prosna-nowa-kakawa', 'RIVER', 51.5870417, 18.1538793, 'Wielkopolskie', 'Kalisz', 'Prosna w Nowej Kakawie oferuje szerokie rozlewiska z licznymi piaszczystymi przykosami i żwirowymi łachami. Nurt jest tu wyjątkowo żywy, co stwarza idealne warunki do łowienia kleni metodą muchową oraz lekkiego spinningu. Wędkarze feederowi z sukcesami obławiają krawędzie głównego nurtu, celując w dorodne leszcze oraz rzeczne płocie. Piaszczyste dno dynamicznie zmienia swój kształt po wiosennych przyborach, co wymaga od wędkarza każdorazowego sondowania głębokości. Spinningiści polują tu na bolenie, które agresywnie atakują stada uklei na płytkich przelewach nurtu. Piękny, otwarty krajobraz doliny rzeki zapewnia doskonałą widoczność i komfort łowienia z brzegu.', null);

