-- Spot 825: Wielowieś
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70824, 'Prosna - Wielowieś (Głębokie Rynny)', 'prosna-wielowies', 'RIVER', 51.5999178, 18.1154416, 'Wielkopolskie', 'Kalisz', 'Odcinek w Wielowsi charakteryzuje się głębokimi rynnami wymytymi pod wysokimi, gliniastymi burtami brzegowymi. Rzeka posiada tu twarde podłoże, które jest naturalną bazą pokarmową dla stad dużych leszczy oraz rzadziej spotykanych brzan. To doskonałe łowisko dla spinningistów polujących na okonie, wykorzystujących techniczne uskoki dna jako swoje główne stanowiska. Uciąg wody w głównym nurcie jest zdecydowany, co sprzyja doskonałemu natlenieniu koryta przez cały sezon 2026 roku. Nocne zasiadki gruntowe często owocują braniami sumów, które patrolują głębsze partie rzeki w poszukiwaniu pokarmu. Miejsce to łączy w sobie urok dzikiej rzeki z technicznym wyzwaniem łowienia w trudnym, zaczepowym terenie.', null);

