-- Spot 826: Masanów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70825, 'Prosna - Masanów (Zastoiska)', 'prosna-masanow', 'RIVER', 51.6211627, 18.0877824, 'Wielkopolskie', 'Ostrzeszów', 'Prosna w okolicach Masanowa tworzy liczne zakola z wolniejszym nurtem i rozległymi zastoiskami przy brzegach. Piaszczysto-muliste dno sprzyja rozwojowi roślinności zanurzonej, stanowiącej idealne schronienie dla lina oraz dorodnych karasi. To strategiczne miejsce dla łowców drapieżników, szczególnie sandaczy, które szukają uklei w głębszych dołkach przy wylotach starorzeczy. Uciąg wody jest tu łagodny, co pozwala na zastosowanie delikatnych technik spławikowych z czułymi sygnalizatorami brań. Wysoka różnorodność biologiczna w 2026 roku sprawia, że rybostan jest tu stabilny i bogaty gatunkowo. Spokojna okolica i relatywnie łatwy dostęp do wody czynią to łowisko popularnym punktem na mapie regionu.', null);

