-- Spot 827: Sławin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70826, 'Prosna - Sławin (Gliniane Burty)', 'prosna-slawin', 'RIVER', 51.6473405, 18.0770079, 'Wielkopolskie', 'Ostrów Wielkopolski', 'Odcinek rzeki w Sławinie to klasyczna rzeka nizinna z wyraźnie zaznaczonymi gliniastymi podmyciami i bystrym nurtem. Twarde dno w głównym torze rzeki jest idealnym stanowiskiem dla brzan oraz okazowych kleni szukających pokarmu w prądzie. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając szczupaków oraz boleni żerujących na piaszczystych przykosach. Uciąg wody jest tu przewidywalny, ale silny na łukach, co wymusza stosowanie dociążonych zestawów gruntowych. Wędkarze stacjonarni nęcą tutejsze rynny, licząc na brania rekordowych leszczy oraz walecznych jazi. Dojazd drogami polnymi zapewnia kameralną atmosferę, a obfitość ryb w 2026 roku potwierdza wysoką klasę tego łowiska.', null);

