INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70827, 'Prosna - Biskupice (Szeroki Nurt)', 'prosna-biskupice', 'RIVER', 51.8915272, 17.9610667, 'Wielkopolskie', 'Kalisz', 'Prosna w Biskupicach staje się rzeką szerszą i głębszą, zbliżając się do swojego dolnego biegu. Wysokie gliniaste brzegi skrywają głębokie rynny, które są doskonałym stanowiskiem dla sandaczy oraz okazowych sumów. Metoda feederowa jest tu dominująca, pozwalając na skuteczne połowy rekordowych leszczy oraz jazi w stabilnym nurcie. Uciąg rzeki wymaga stosowania technicznych zestawów z dociążonym koszykiem dla poprawnej stabilizacji przynęty na dnie. Spinningiści z sukcesami obławiają tutejsze zakola, szukając szczupaków żerujących na obrzeżach głównego toru wodnego. W 2026 roku odcinek ten charakteryzuje się bardzo stabilną populacją białorybu i regularnymi braniami drapieżników.', null);

