-- Spot 837: Mirków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70836, 'Prosna - Mirków (Piaszczyste Rynny)', 'prosna-mirkow', 'RIVER', 51.3147343, 18.1559796, 'Łódzkie', 'Wieruszów', 'Prosna w Mirkowie to odcinek o charakterze wybitnie nizinno-łąkowym z piaszczystym dnem i licznymi kępami roślinności wodnej. Rzeka płynie tu dość wąskim korytem, żłobiąc techniczne rynny na łukach, które są idealną ostoją dla stad kleni oraz rzecznych jelców. To doskonałe łowisko dla spinningistów polujących na szczupaki, którzy obławiają krawędzie nadrzecznych trzcinowisk w poszukiwaniu drapieżników. Uciąg wody jest tu stabilny, co sprzyja systematycznemu nęczeniu i utrzymywaniu stad ryb białego żeru w polu łowienia. Spinningiści chętnie wykorzystują podmyte korzenie nadrzecznych olszyn jako strategiczne punkty podania małych przynęt gumowych. W 2026 roku miejsce to pozostaje oazą spokoju, oferując kontakt z rybami w krystalicznie czystej wodzie górnej Prosny.', null);

