VALUES (70836, 'Nizinna', 'Wąska, meandrująca', 10.0, 1.1, 'Piasek', 'Kępy roślin podwodnych', 'Kleń, Jelec, Szczupak', 'Kraina leszcza', false);

-- Spot 838: Wyszanów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70837, 'Prosna - Wyszanów (Przykosy)', 'prosna-wyszanow', 'RIVER', 51.3609442, 18.1739667, 'Łódzkie', 'Wieruszów', 'Odcinek w Wyszanowie charakteryzuje się naturalnym przebiegiem koryta z wyraźnie zaznaczonymi piaszczystymi przykosami i żwirowymi łachami. Rzeka żłobi tu dno o charakterze piaszczysto-żwirowym, tworząc dogodne ostoje dla walecznych jazi oraz okazowych kleni w nurcie. To strategiczne miejsce dla łowców boleni, którzy agresywnie atakują drobnicę na płytkich przelewach piaszczystych łach w głównim korycie. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie, wykorzystując technikę przepływanki z systematycznym nęceniem na stokach rynien. Uciąg wody jest żywy i zapewnia świetne natlenienie koryta rzeki praktycznie przez cały sezon wędkarski. Malowniczy krajobraz nadprośniański oraz wysoka rybność odcinka przyciągają pasjonatów technicznego spinningu i lekkiego feedera klasycznego.', null);

