VALUES (70837, 'Nizinna', 'Naturalna, piaszczysta', 14.0, 1.2, 'Piasek i żwir', 'Piaszczyste przykosy', 'Boleń, Jaź, Kleń', 'Kraina leszcza', false);

-- Spot 839: Plugawice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70838, 'Prosna - Plugawice (Dziki Przełom)', 'prosna-plugawice', 'RIVER', 51.3856854, 18.1918322, 'Wielkopolskie', 'Grabów nad Prosną', 'Prosna w okolicach Plugawic słynie z wyjątkowo dzikiego przebiegu koryta z dużą ilością zwalonych przez bobry drzew i karczowisk. Rzeka żłobi tu głębokie dołki pod wysokimi, podmywanymi burtami brzegowymi, stanowiące naturalne stanowiska dla rekordowych kleni. To technicznie wymagające łowisko dla spinningistów, którzy wykorzystują liczne zatory jako punkty obserwacyjne drapieżników w nurcie. Uciąg wody jest tu zdecydowany i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. W głębszych rynnach o gliniastym dnie często stacjonują duże szczupaki, doskonale reagujące na systematyczne prowadzenie przynęt powierzchniowych. Izolacja terenu i utrudniony dostęp do brzegów gwarantują w 2026 roku absolutną ciszę i kontakt z dziką rzeką.', null);

