VALUES (70838, 'Nizinna', 'Dzika, zatarasowana', 13.0, 1.6, 'Glina i piasek', 'Zwalone drzewa', 'Kleń, Szczupak, Jaź', 'Kraina leszcza', false);

-- Spot 840: Obory
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70839, 'Prosna - Obory (Łęgowa Płania)', 'prosna-obory', 'RIVER', 52.0188304, 17.7960697, 'Wielkopolskie', 'Pyzdry', 'Odcinek w Oborach to dolny bieg Prosny o znacznie szerszym korycie i spokojniejszym nurcie nizinno-łąkowym. Podłoże jest tu piaszczysto-muliste z licznymi kępami roślinności zanurzonej, co sprzyja bytowaniu stad leszczowych oraz rzecznych krąpi. To doskonałe łowisko dla wędkarzy feederowych, którzy z sukcesami nęcą tutejsze płanie w poszukiwaniu ryb spokojnego żeru. Spinningiści chętnie obławiają krawędzie nadrzecznych wiklin, szukając okoni oraz szczupaków czatujących na przybrzeżną drobnicę w zastoiskach. Uciąg wody jest tu łagodny, co pozwala na stosowanie najdelikatniejszych technik spławikowych z bardzo czułymi sygnalizatorami brań. Bliskość ujścia do Warty sprawia, że rybostan jest tu regularnie zasilany migracjami ryb z większej arterii wodnej.', null);

