-- Spot 841: Gizałki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70840, 'Prosna - Gizałki (Kraina Bolenia)', 'prosna-gizalki', 'RIVER', 52.0372464, 17.7635367, 'Wielkopolskie', 'Gizałki', 'Prosna w Gizałkach to techniczne łowisko o piaszczystym dnie i wyraźnie zaznaczonych przykosach wychodzących daleko w nurt rzeki. Rzeka żłobi tu techniczne rynny na krawędzi nurtu głównego, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców boleni, którzy agresywnie atakują stada uklei przy turbulentnych warkoczach powstających na łukach koryta. Wędkarze stacjonarni nęcą tutejsze piaszczyste płanie, licząc na brania rekordowych jazi oraz cert migrujących okresowo korytem. Uciąg wody jest stabilny i zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. Malowniczy krajobraz doliny rzeki oraz wysoka rybność odcinka czynią Gizałki jednym z najpopularniejszych punktów na mapie dolnej Prosny.', null);

