-- Spot 842: Szymanowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70841, 'Prosna - Szymanowice (Ujściowy Tor)', 'prosna-szymanowice', 'RIVER', 52.0461962, 17.7219774, 'Wielkopolskie', 'Pyzdry', 'Odcinek w Szymanowicach to finalny fragment biegu Prosny przed jej wpłynięciem w wody Warty, charakteryzujący się dużą głębokością koryta. Podłoże jest tu twarde, piaszczysto-muliste z wyraźnymi uskokami dna toru wodnego, stanowiącymi ostoje dla rekordowych sumów i sandaczy. To strategiczne miejsce dla spinningistów, którzy wykorzystują dużą masę wody do precyzyjnego prowadzenia ciężkich jigów w pobliżu dna. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w rekordowe leszcze oraz amury wchodzące w rzekę na żerowanie z większej arterii. Uciąg wody bywa tu zmienny i uzależniony od zjawiska cofki z rzeki Warty, co wymusza na wędkarzu częstą adaptację techniki. Każda wyprawa w to miejsce w 2026 roku to szansa na kontakt z największymi okazami ryb nizinnych migrujących między rzekami.', null);

