INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70842, 'Prosna - Miniszew (Przedujściowa)', 'prosna-miniszew', 'RIVER', 52.0691795, 17.6979449, 'Wielkopolskie', 'Żerków', 'Prosna w Miniszewie to potężny, nizinny odcinek rzeki o bardzo silnie meandrującym korycie i gliniastym dnie. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach, które stanowią bezpieczną ostoję dla rekordowych sumów migrujących z Warty. To doskonałe łowisko dla spinningistów szukających sandaczy, wykorzystujących techniczne uskoki dna toru wodnego. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu koryta rzeki przez cały rok wędkarski 2026 roku. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, stosując metodę ciężkiego feedera z systematycznym nęceniem. Dzikość brzegów i bliskość Parku Krajobrazowego gwarantują wędkarzowi absolutną ciszę i kontakt z dziką naturą.', null);

