INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70843, 'Prosna - Kretków (Gliniane Burty)', 'prosna-kretkow', 'RIVER', 52.0906349, 17.6707151, 'Wielkopolskie', 'Żerków', 'Odcinek w Kretkowie charakteryzuje się wysokimi, podmywanymi brzegami i obecnością licznych zwalonych drzew w nurcie. Rzeka posiada tu twarde podłoże o gliniastym charakterze, co sprzyja bytowaniu walecznych kleni oraz dużych jazi. To strategiczne miejsce dla spinningistów, którzy wykorzystują naturalne przeszkody do precyzyjnego podawania przynęt w turbulentnym prądzie. Uciąg rzeki jest żywy, tworząc techniczne warkocze prądowe idealne do polowania na bolenie patrolujące koryto. Wędkarze gruntowi chętnie nęcą tutejsze głębokie rynny, licząc na brania rekordowych brzan doskonale czujących się w tym rejonie. Specyfika terenu sprawia, że łowisko jest technicznie wymagające, ale odwdzięcza się rybami o imponujących rozmiarach.', null);

