-- Spot 845: Komorze Przybysławskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70844, 'Prosna - Komorze (Węzeł Ujściowy)', 'prosna-komorze', 'RIVER', 52.1172361, 17.6627228, 'Wielkopolskie', 'Pyzdry', 'Odcinek w Komorzu to finalny fragment toku Prosny przed jej spektakularnym połączeniem z wodami Warty. Koryto rzeki rozszerza się tu znacznie, tworząc rozległe piaszczyste rozlewiska z licznymi łachami i głębokim torem wodnym. To strategiczny węzeł migracyjny dla drapieżników, które wchodzą w Prosnę na intensywne żerowanie przed wiosennymi przyborami. Uciąg wody bywa tu zmienny i uzależniony od zjawiska cofki z rzeki Warty, co wymaga od wędkarza częstej adaptacji techniki. Wędkarze gruntowi chętnie nęcą tutejsze płanie, celując w rekordowe leszcze oraz certy migrujące okresowo korytem. Miejsce to w 2026 roku pozostaje jednym z najbardziej rybnych i technicznie ciekawych punktów na całej mapie dorzecza.', null);

