-- Spot 847: gmina Wieruszów (Mirków Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70846, 'Prosna - Wieruszów (Piaszczyste Rynny)', 'prosna-wieruszow-gmina', 'RIVER', 51.2699909, 18.1739616, 'Łódzkie', 'Wieruszów', 'Odcinek rzeki na północ od Wieruszowa charakteryzuje się piaszczystym dnem i obecnością licznych kęp roślinności podwodnej. Rzeka płynie tu dostojnie przez tereny łąkowe, oferując wędkarzom dogodny dostęp do brzegów oraz liczne zastoiska brzegowe. To doskonałe łowisko dla łowców jazi i kleni, które doskonale reagują na małe woblery i systematyczne nęcenie roślinne. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając okoni oraz szczupaków czatujących w cieniu nadrzecznych traw. Uciąg wody jest stabilny i przewidywalny, co sprzyja systematycznemu nęceniu i utrzymywaniu stad białorybu w polu łowienia. Czystość wody i brak infrastruktury technicznej sprawiają, że ryby żerują tu bardzo odważnie w naturalnym rytmie rzeki.', null);

