-- Spot 850: gmina Gołuchów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70849, 'Prosna - gmina Gołuchów (Szerokie Płanie)', 'prosna-goluchow', 'RIVER', 51.8422343, 18.0135763, 'Wielkopolskie', 'Kalisz', 'Prosna w gminie Gołuchów charakteryzuje się szerokim korytem i obecnością rozległych piaszczystych przykos wychodzących w główny nurt. Rzeka płynie tu dostojnie, żłobiąc dno o piaszczystym charakterze z wyraźnymi uskokami stanowiącymi idealne kryjówki dla sandaczy. To strategiczne miejsce dla łowców boleni, które agresywnie atakują drobnicę na płytkich przelewach piaszczystych łach. Wędkarze stacjonarni z sukcesami nęcą tutejsze płanie, celując w dorodne leszcze oraz rzeczne płocie migrujące korytem. Uciąg wody jest stabilny i przewidywalny, co sprzyja precyzyjnemu nęceniu punktowemu przy użyciu techniki feedera klasycznego. Malowniczy krajobraz doliny rzeki oraz bliskość zamku w Gołuchowie nadają wędkowaniu w tym rejonie unikalnego klimatu.', null);

