-- Spot 851: Żerniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70850, 'Prosna - Żerniki (Zakole Dolne)', 'prosna-zerniki', 'RIVER', 51.8621302, 17.983255, 'Wielkopolskie', 'Pleszew', 'Odcinek w Żernikach słynie z wyjątkowo dzikiego przebiegu koryta z dużą ilością zwalonych przez bobry drzew i karczowisk. Rzeka żłobi tu głębokie rynny w gliniastym dnie, tworząc idealne ostoje dla rekordowych sumów i dużych szczupaków. To techniczne łowisko wymaga od wędkarza precyzyjnych rzutów spinningowych pod nawisy gęstych nadrzecznych traw i wiklin. Uciąg wody jest tu żywy i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności drapieżników. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, stosując metodę ciężkiego feedera w rynnach głównego nurtu. Izolacja terenu i utrudniony dostęp do brzegów gwarantują w 2026 roku absolutną ciszę i kontakt z dziką rzeką.', null);

