-- Spot 852: gmina Radłów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70851, 'Prosna - gmina Radłów (Górna)', 'prosna-radlow', 'RIVER', 51.0074058, 18.5154629, 'Opolskie', 'Olesno', 'Prosna w gminie Radłów to górny odcinek rzeki o wąskim korycie i charakterze bystrego potoku nizinnego. Koryto posiada piaszczysto-żwirowe dno z licznymi kępami roślinności wodnej, będącej idealną kryjówką dla pstrągów potokowych. To doskonałe łowisko dla spinningistów szukających ryb łososiowatych w bardzo płytkiej i przejrzystej wodzie. Uciąg wody jest tu żywy, co wymaga od wędkarza dużej dyskrecji oraz precyzyjnych rzutów małą przynętą. Podmyte korzenie nadrzecznych drzew stanowią strategiczne punkty żerowania dla ryb reofilnych w tym mikro-ekosystemie. Status wód górskich sprawia, że w 2026 roku jest to miejsce dedykowane pasjonatom delikatnego wędkarstwa technicznego.', null);

