-- Spot 853: Wygiełdów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70852, 'Prosna - Wygiełdów (Rynny Żwirowe)', 'prosna-wygieldow', 'RIVER', 51.0074433, 18.4714513, 'Opolskie', 'Praszka', 'Odcinek w Wygiełdowie zachowuje charakter bystrego, podgórskiego potoku o twardym, żwirowo-kamienistym dnie i dużej dynamice nurtu. Rzeka tworzy tu liczne bystrza oraz techniczne rynny, które są naturalnym stanowiskiem dla pstrągów i lipieni. To strategiczne miejsce dla muszkarzy, którzy cenią sobie możliwość bezpiecznego brodzenia w krystalicznie czystej wodzie. Uciąg rzeki jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody przez cały sezon wędkarski 2026 roku. Spinningiści z sukcesami polują tu na klenie, wykorzystując małe obrotówki i woblery prowadzone na granicy głównego prądu. Malowniczy krajobraz pogranicza województw nadaje każdemu wędkowaniu w tym miejscu unikalnego, relaksującego charakteru.', null);

