-- Spot 854: Szyszków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70853, 'Prosna - Szyszków (Meandry)', 'prosna-szyszkow', 'RIVER', 51.021889, 18.4350826, 'Opolskie', 'Praszka', 'Prosna w Szyszkowie charakteryzuje się naturalnym przebiegiem koryta z licznymi zastoiskami i piaszczystymi łachami wychodzącymi w nurt. Rzeka żłobi tu dno o piaszczystym charakterze, tworząc dogodne ostoje dla stad rzecznych płoci oraz dorodnych jelców. To doskonałe łowisko dla wędkarzy feederowych celujących w białą rybę żerującą w spowolnieniach nurtu za naturalnymi przeszkodami. Spinningiści z sukcesami obławiają tutejsze podmyte burty, szukając okoni oraz szczupaków czatujących w cieniu nadrzecznych trzcinowisk. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie i utrzymywanie stad ryb w polu łowienia. Miejsce to w 2026 roku jest cenione za krystaliczną czystość wody i brak uregulowań hydrotechnicznych.', null);

