INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70854, 'Prosna - Bolesławiec (Warkocze Prądowe)', 'prosna-boleslawiec-lodzkie', 'RIVER', 51.1927735, 18.1787785, 'Łódzkie', 'Wieruszów', 'Odcinek rzeki w Bolesławcu to technicznie wymagająca woda z wyraźnie zaznaczonymi rynnami prądowymi i piaszczystymi przykosami. Rzeka żłobi tu dno o piaszczysto-gliniastym charakterze, tworząc idealne warunki tlenowe dla walecznych pstrągów potokowych. To strategiczne miejsce dla spinningistów, którzy wykorzystują liczne zatory z pni drzew do precyzyjnego podawania małych woblerów. Uciąg wody jest tu żywy i zmienny, tworząc techniczne warkocze prądowe idealne do łowienia metodą przepływanki. W głębszych dołkach pod burtami brzegowymi często stacjonują wyrośnięte klenie, które doskonale reagują na owadowe przynęty powierzchniowe. Malowniczy krajobraz doliny górnej Prosny nadaje każdemu wędkowaniu w tym miejscu unikalnego, pierwotnego charakteru.', null);

