INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70855, 'Prosna - Praszka (Miejska)', 'prosna-praszka-miejska', 'RIVER', 51.0492295, 18.4367721, 'Opolskie', 'Praszka', 'Prosna w Praszce to odcinek o uregulowanym charakterze miejskim z betonowymi umocnieniami i mostami drogowymi. Podłoże jest tu twarde, piaszczysto-kamieniste, co przyciąga sandacze oraz duże okonie szukające schronienia przy filarach. To strategiczne miejsce dla spinningistów, którzy wykorzystują turbulentne warkocze za progami do polowania na bolenie. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i krąpie, wykorzystując metodę bata lub tyczki przy murach oporowych. Uciąg wody jest stabilny, ale uzależniony od pracy okolicznych jazów, co wymaga częstej adaptacji obciążenia. W 2026 roku łowisko to cieszy się dużą popularnością ze względu na łatwy dostęp i regularne zarybienia rybami spokojnego żeru.', null);

