-- Spot 865: Biskupice (Południowe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70865, 'Prosna - Biskupice (Opolskie - Góra)', 'prosna-biskupice-opolskie', 'RIVER', 50.9540169, 18.4869542, 'Opolskie', 'Olesno', 'Odcinek w Biskupicach to jeden z początkowych fragmentów Prosny o charakterze wąskiego, bystrego potoku płynącego przez lasy. Koryto posiada tu piaszczysto-żwirowe dno o szerokości nieprzekraczającej kilku metrów, z licznymi mikro-rynnoami pod burtami. To unikalne miejsce dla pasjonatów mikro-jigingu, szukających okoni i pstrągów potokowych w bardzo czystej, źródlanej wodzie. Uciąg rzeki jest żywy, co zapewnia świetne natlenienie koryta nawet w najpłytszych partiach dorzecza Prosny. Ze względu na niewielką skalę rzeki, wymagana jest tu absolutna cisza i niezwykle delikatne podejście do stanowiska. W 2026 roku jest to miejsce cenione za swój pierwotny charakter i status rzeki rodzącej się w sercu lasu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70865, 'Górska', 'Wąski potok źrodliskowy', 3.0, 0.5, 'Piasek i darń', 'Naturalne kaskady', 'Pstrąg potokowy, Okoń', 'Kraina pstrąga', false);

-- Spot 866: Warszawa (Wilanów/Zawady)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70866, 'Wisła - Warszawa Południe (Łachy)', 'wisla-warszawa-zawady', 'RIVER', 52.1713504, 21.1371824, 'Mazowieckie', 'Warszawa', 'Wisła w rejonie Wilanowa i Zawad zachowuje swój naturalny, nieuregulowany charakter z licznymi piaszczystymi łachami i rozległymi przykosami. To strategiczne miejsce dla łowców boleni, które w 2026 roku licznie patrolują płytkie przelewy w poszukiwaniu drobnicy. Podłoże jest tu piaszczyste, a nurt rzeki dynamicznie zmienia układ rynien po każdym większym przyborze wody. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając sandaczy stacjonujących na krawędziach głębokich dołów. Wędkarze stacjonarni nęcą tutejsze płanie, celując w dorodne leszcze oraz rzeczne płocie migrujące korytem. Spokojna okolica i dzikość brzegów sprawiają, że jest to jeden z najatrakcyjniejszych punktów na mapie warszawskiej Wisły.', null);

