-- Spot 867: Warszawa (Siekiierki/Mokotów)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70867, 'Wisła - Warszawa (Główki Siekierskie)', 'wisla-warszawa-siekiierki', 'RIVER', 52.2112089, 21.099012, 'Mazowieckie', 'Warszawa', 'Odcinek w rejonie Siekierek to klasyczne łowisko techniczne z dobrze zachowanymi systemami ostróg (główek) i opasek kamiennych. Podłoże jest tu zróżnicowane, od piaszczystych klatek między główkami po głębokie, twarde rynny w samym nurcie głównym. To doskonałe miejsce dla spinningistów polujących na sandacze, którzy wykorzystują warkocze prądowe powstające na szczytach ostróg. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze i certy, stosując ciężkie zestawy feederowe odporne na silny uciąg wody. W 2026 roku obecność licznych struktur hydrotechnicznych sprawia, że jest to jedno z najstabilniejszych łowisk sandaczowych w stolicy. Bliskość centrum miasta i dogodny dostęp do brzegów przyciągają tu pasjonatów miejskiego wędkarstwa o każdej porze dnia.', null);

