VALUES (70867, 'Nizinna Wielka', 'Uregulowana, ostrogi', 420.0, 3.5, 'Piasek i kamień', 'Główki, opaski', 'Sandacz, Leszcz, Certa', 'Kraina leszcza', true);

-- Spot 868: Dęblin (Ujście Wieprza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70868, 'Wisła - Dęblin (Węzeł Ujściowy)', 'wisla-deblin-ujscie', 'RIVER', 51.5486394, 21.8324892, 'Lubelskie', 'Dęblin', 'Rejon ujścia Wieprza do Wisły w Dęblinie to jedno z najbardziej zróżnicowanych hydrologicznie łowisk w całym regionie mazowiecko-lubelskim. Mieszanie się wód dwóch rzek tworzy specyficzny mikroklimat, który przyciąga ogromne stada drapieżników oraz ryb spokojnego żeru. Podłoże jest tu mocno zróżnicowane, od piaszczystych przykos po gliniaste rynny wymyte przez silny nurt przy historycznych mostach. To wymarzone miejsce dla łowców sumów, którzy wykorzystują głębokie doły toru wodnego jako swoje główne ostoje dzienne. Spinningiści z sukcesami polują tu na bolenie i sandacze, wykorzystując turbulentną wodę powstającą na styku prądów obu rzek. W 2026 roku odcinek ten pozostaje technicznie wymagający, ale odwdzięcza się wędkarzom rybami o rekordowych rozmiarach.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70868, 'Nizinna Wielka', 'Ujściowa, szeroka', 500.0, 4.0, 'Piasek i glina', 'Filary mostów, ujście', 'Sum, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 869: Przewóz (Gmina Maciejowice)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70869, 'Wisła - Przewóz (Kraina Przykos)', 'wisla-przewoz-maciejowice', 'RIVER', 51.563279, 21.76368, 'Mazowieckie', 'Kozienice', 'Wisła w okolicach Przewozu to kwintesencja dzikiej rzeki o piaszczystym dnie i ogromnej ilości przemieszczających się łach. Koryto rzeki rozlewa się tu szeroko, tworząc liczne warkocze i techniczne rynny, które są naturalnym tarliskiem dla wielu gatunków. To strategiczne miejsce dla łowców boleni, którzy w 2026 roku wykorzystują piaszczyste przelewy do polowania na stadne ukleje. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i jelce, stosując systematyczne nęcenie na stokach piaszczystych blatów. Uciąg wody jest tu żywy i uzależniony od aktualnych stanów rzeki, co wymaga od wędkarza dużej adaptacji techniki. Izolacja tego odcinka i dzikość brzegów zapewniają absolutną ciszę i kontakt z nienaruszoną naturą Doliny Środkowej Wisły.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70869, 'Nizinna Wielka', 'Dzika, meandrująca', 600.0, 2.0, 'Piasek', 'Przykosy, warkocze', 'Boleń, Płoć, Sandacz', 'Kraina leszcza', true);

-- Spot 870: Prażmów (Rezerwat)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70870, 'Wisła - Prażmów (Dzikie Wyspy)', 'wisla-prazmow', 'RIVER', 51.571075, 21.6919577, 'Mazowieckie', 'Kozienice', 'Odcinek w Prażmowie to jeden z najbardziej malowniczych i dzikich fragmentów Wisły, słynący z piaszczystych wysp i gęstych łęgów. Rzeka płynie tu wieloma odnogami, tworząc płytkie bystrza oraz głębokie rynny pod zwalonymi do wody drzewami. To wymarzone łowisko dla spinningistów szukających kleni i jazi, które żerują pod nawisami nadrzecznych wiklin. Podłoże jest głównie piaszczyste, ale obecność zatopionych karczowisk stwarza idealne warunki dla dużych szczupaków i sumów. Uciąg wody jest tu zmienny, co sprzyja doskonałemu natlenieniu i wysokiej aktywności ryb przez cały sezon 2026 roku. Ze względu na status rezerwatu i utrudniony dostęp, presja wędkarska jest tu minimalna, co pozwala rybom osiągać rekordowe rozmiary.', null);

