-- Spot 871: Piotrowice (Gmina Karczew)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70871, 'Wisła - Piotrowice (Dzikie Łachy)', 'wisla-piotrowice', 'RIVER', 51.6053845, 21.6450834, 'Mazowieckie', 'Karczew', 'Wisła w Piotrowicach to klasyczny odcinek środkowego biegu z ogromną ilością piaszczystych przykos i łach. Koryto rzeki rozszerza się tutaj znacznie, tworząc rozległe warkocze prądowe idealne dla boleni. Podłoże jest głównie piaszczyste, jednak w rynnach głównego nurtu można trafić na twardsze, gliniaste fragmenty. To strategiczne miejsce dla spinningistów szukających sandaczy czatujących na krawędziach głębokich dołów. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując systematyczne nęcenie na stokach piaszczystych blatów. W 2026 roku odcinek ten pozostaje oazą dzikiej natury z minimalną presją wędkarską ze względu na trudny dostęp.', null);

