-- Spot 872: Góra Puławska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70872, 'Wisła - Góra Puławska (Ostrogi)', 'wisla-gora-pulawska', 'RIVER', 51.406487, 21.9420945, 'Lubelskie', 'Puławy', 'Łowisko w Górze Puławskiej charakteryzuje się technicznym układem ostróg i opasek kamiennych chroniących lewy brzeg rzeki. Podłoże jest tu twarde, piaszczysto-kamieniste, co przyciąga sandacze oraz sumy szukające schronienia przy strukturach hydrotechnicznych. Filary mostu drogowego generują potężne turbulencje i głębokie rynny, które są bankowymi stanowiskami dla drapieżników. Spinningiści z sukcesami polują tu na bolenie, wykorzystując silny uciąg wody na szczytach główek. Wędkarze feederowi chętnie nęcą klatki między ostrogami, licząc na brania okazałych leszczy i cert. Dobra infrastruktura i bliskość miasta czynią to miejsce jednym z najpopularniejszych punktów na lubelskim odcinku Wisły.', null);

