-- Spot 873: Łęka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70873, 'Wisła - Łęka (Piaszczyste Przelewy)', 'wisla-leka', 'RIVER', 51.4538678, 21.9309293, 'Lubelskie', 'Puławy', 'Wisła w rejonie miejscowości Łęka to odcinek o bardzo zmiennym charakterze, zdominowany przez rozległe piaszczyste rozlewiska. Rzeka żłobi tu głębokie rynny na krawędzi nurtu głównego, które stanowią bezpieczną ostoję dla rekordowych brzan. Podłoże jest piaszczysto-żwirowe z licznymi zastoiskami brzegowymi, w których gromadzi się drobnica. To doskonałe łowisko dla spinningistów polujących na szczupaki, wykorzystujących zatopione karczowiska jako punkty obserwacyjne. Uciąg wody jest tu żywy i uzależniony od aktualnych stanów rzeki, co wymaga stosowania ciężkich zestawów gruntowych. Malowniczy krajobraz pradoliny i dzikość brzegów zapewniają w 2026 roku doskonałe warunki do całodziennych sesji wędkarskich.', null);

