-- Spot 874: Gołąb
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70874, 'Wisła - Gołąb (Rynny Główne)', 'wisla-golab', 'RIVER', 51.4766271, 21.8642315, 'Lubelskie', 'Puławy', 'Odcinek w Gołębiu znajduje się w strategicznym rejonie, gdzie rzeka zaczyna silnie meandrować przed węzłem dęblińskim. Koryto posiada tu piaszczyste dno z wyraźnie zaznaczonymi przykosami, które są naturalną stołówką dla agresywnych boleni. W głębszych rynnach o twardszym podłożu często stacjonują duże sumy, migrujące okresowo w poszukiwaniu natlenionej wody. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i certy, wykorzystując systematyczne nęcenie na krawędzi nurtu. Uciąg wody jest stabilny, co pozwala na precyzyjne nęcenie przy użyciu techniki feedera klasycznego. W 2026 roku Gołąb pozostaje jednym z najbardziej rybnych odcinków środkowej Wisły dzięki doskonałym warunkom tlenowym.', null);

