-- Spot 875: Warszawa (Centrum - Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70875, 'Wisła - Warszawa (Bulwary/Mosty)', 'wisla-warszawa-centrum', 'RIVER', 52.2488811, 21.0210206, 'Mazowieckie', 'Warszawa', 'Warszawski odcinek centralny to techniczne łowisko o uregulowanych brzegach i dużej głębokości toru wodnego. Podłoże jest tu twarde, piaszczysto-betonowe, co przyciąga sandacze oraz duże okonie szukające schronienia pod murami oporowymi. Filary mostów Śląsko-Dąbrowskiego i Świętokrzyskiego tworzą potężne warkocze prądowe, będące ostoją dla sumów. Spinningiści z sukcesami polują tu na bolenie, wykorzystując turbulentną wodę na styku prądów przy betonowych nabrzeżach. Uciąg wody jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb praktycznie przez całą dobę wędkarską. Dobra infrastruktura i oświetlenie brzegów czynią to miejsce idealnym na bezpieczne sesje streetfishingowe w samym sercu stolicy.', null);

