VALUES (70875, 'Nizinna Wielka', 'Uregulowana miejska', 450.0, 4.0, 'Twardy piasek', 'Mury oporowe, filary mostów', 'Sandacz, Sum, Boleń', 'Kraina leszcza', true);

-- Spot 876: Warszawa (Bielany/Młociny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70876, 'Wisła - Warszawa (Północ/Bielany)', 'wisla-warszawa-bielany', 'RIVER', 52.2914102, 20.9881579, 'Mazowieckie', 'Warszawa', 'Wisła w rejonie Bielan i Młocin charakteryzuje się przejściem rzeki w charakter bardziej naturalny z licznymi piaszczystymi łachami. Koryto jest tu szerokie, z wyraźnie zaznaczonymi rynnami prądowymi, które przyciągają stada leszczowe migrujące w górę rzeki. Podłoże jest głównie piaszczyste z piaszczysto-żwirowymi uskokami dna, stanowiącymi idealne żerowisko dla kleni. To doskonałe miejsce dla spinningistów szukających sandaczy czatujących na krawędziach piaszczystych przykos. Uciąg rzeki w tym miejscu jest żywy, co zapewnia świetne natlenienie wody i wysoką kondycję tutejszego rybostanu. Spokojna okolica Lasku Bielańskiego sprawia, że w 2026 roku jest to jeden z najbardziej relaksujących punktów na mapie warszawskiej Wisły.', null);

