-- Spot 877: Siarzewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70877, 'Wisła - Siarzewo (Przełom Kujawski)', 'wisla-siarzewo', 'RIVER', 52.8712214, 18.8479003, 'Kujawsko-Pomorskie', 'Ciechocinek', 'Wisła w Siarzewie charakteryzuje się niezwykle surowym i dynamicznym charakterem ze względu na bliskość stopnia wodnego we Włocławku. Rzeka żłobi tu głębokie rynny w twardym, gliniasto-kamienistym dnie, które jest stale drenowane przez silny uciąg wody. To strategiczne miejsce dla łowców sumów i dużych sandaczy, które stacjonują w głębokich jamach toru wodnego. W 2026 roku odcinek ten jest monitorowany pod kątem planowanych inwestycji hydrotechnicznych, co wpływa na zmienność linii brzegowej. Spinningiści z sukcesami obławiają tutejsze kamieniste opaski, szukając boleni patrolujących krawędzie nurtu. Wędkarstwo w tym miejscu wymaga stosowania najcięższych zestawów gruntowych ze względu na potężną siłę prądu głównego.', null);

