-- Spot 878: Stajenczynki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70878, 'Wisła - Stajenczynki (Piaszczyste Wyspy)', 'wisla-stajenczynki', 'RIVER', 52.9079847, 18.7995395, 'Kujawsko-Pomorskie', 'Ciechocinek', 'Odcinek w Stajenczynkach to kraina piaszczystych wysp i rozległych łach, które dzielą nurt Wisły na kilka mniejszych odnóg. Takie ukształtowanie koryta stwarza idealne warunki dla ryb reofilnych, szukających pokarmu na płytkich, piaszczystych przelewach. To strategiczne miejsce dla łowców boleni, którzy w marcu 2026 roku namierzają stada drobnicy przy turbulentnych warkoczach wyspowych. Podłoże jest tu głównie piaszczyste, ale w głębszych rynnach między wyspami można trafić na twardsze, żwirowe fragmenty. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując systematyczne nęcenie na stokach piaszczystych przykos. Dzikość brzegów i utrudniony dojazd sprawiają, że presja wędkarska jest tu znacznie mniejsza niż w pobliskim Ciechocinku.', null);

