-- Spot 879: Silno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70879, 'Wisła - Silno (Rynna Brzegowa)', 'wisla-silno', 'RIVER', 52.9274224, 18.730849, 'Kujawsko-Pomorskie', 'Toruń', 'Wisła w Silnie płynie jednym, szerokim korytem o bardzo silnie zaznaczonej rynnie przy prawym, wysokim brzegu. Podłoże w głównym nurcie jest twarde i piaszczysto-gliniaste, co przyciąga okazowe sumy oraz sandacze szukające głębokiej wody. To doskonałe łowisko dla spinningistów, którzy wykorzystują głębokie uskoki dna do prowadzenia ciężkich przynęt gumowych w technice opadu. W 2026 roku Silno słynie z regularnych połowów dorodnych brzan, które doskonale czują się w tutejszym zdecydowanym uciągu. Wędkarze feederowi nęcą tutejsze płanie, licząc na brania rekordowych leszczy migrujących w stronę Torunia. Spokojna okolica i stabilne warunki hydrologiczne czynią ten odcinek jednym z najciekawszych punktów na mapie dolnej Wisły.', null);

