-- Spot 880: Grabowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70880, 'Wisła - Grabowiec (System Główek)', 'wisla-grabowiec', 'RIVER', 52.9732919, 18.7002078, 'Kujawsko-Pomorskie', 'Toruń', 'Łowisko w Grabowcu charakteryzuje się klasycznym układem ostróg (główek), które regulują nurt rzeki przed jej wlotem do Torunia. Podłoże jest tu zróżnicowane – piaszczyste wewnątrz klatek i kamieniste na szczytach budowli hydrotechnicznych, co sprzyja różnym technikom łowienia. To strategiczne miejsce dla spinningistów polujących na sandacze, którzy obławiają warkocze prądowe powstające na napływach i zapływach główek. Wędkarze stacjonarni z sukcesami łowią tu okazałe certy oraz leszcze, stosując technikę feedera klasycznego na granicy nurtu. W 2026 roku odcinek ten jest ceniony za dużą populację okonia, który chętnie trzyma się kamienistych umocnień opasek. Dobra infrastruktura i łatwy dostęp do brzegów czynią Grabowiec popularnym miejscem weekendowych wypraw.', null);

