VALUES (70880, 'Nizinna Wielka', 'Uregulowana, ostrogi', 480.0, 3.2, 'Piasek i kamień', 'Główki, opaski', 'Sandacz, Certa, Okoń', 'Kraina leszcza', true);

-- Spot 881: Nowy Dwór Mazowiecki (Ujście Narwi)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70881, 'Wisła - Nowy Dwór Maz. (Węzeł Modliński)', 'wisla-nowy-dwor-maz-ujscie', 'RIVER', 52.4296008, 20.6624978, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Miejsce ujścia Narwi do Wisły to jeden z najbardziej spektakularnych punktów hydrologicznych w Polsce, charakteryzujący się ogromną masą mieszających się wód. Turbulentne prądy na styku obu rzek tworzą głębokie rynny i piaszczyste wiry, które są naturalnym „magnesem” dla wszystkich gatunków drapieżników. To strategiczne miejsce dla łowców sumów, którzy w 2026 roku polują tu na rekordowe okazy stacjonujące w najgłębszych partiach toru wodnego. Spinningiści z sukcesami obławiają granice prądów, szukając sandaczy oraz boleni żerujących na piaszczystych przykosach ujściowych. Podłoże jest tu niezwykle zmienne, piaszczysto-muliste z licznymi twardymi uskokami dna, co wymaga od wędkarza doskonałej znajomości koryta. Bliskość Twierdzy Modlin i unikalna panorama nadają każdemu wędkowaniu w tym miejscu historycznego wymiaru.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70881, 'Nizinna Wielka', 'Ujściowa, szeroka', 800.0, 5.0, 'Piasek i muł', 'Ujście rzeki, mosty', 'Sum, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 882: Zakroczym
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70882, 'Wisła - Zakroczym (Pod Skarpą)', 'wisla-zakroczym', 'RIVER', 52.4289276, 20.5773543, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Wisła w Zakroczymiu płynie u podnóża wysokiej skarpy, co skutkuje głębokim korytem i bardzo zdecydowanym uciągiem wody przy prawym brzegu. Podłoże jest tu twarde, piaszczysto-gliniaste, usiane licznymi karczowiskami i zwalonymi do wody fragmentami brzegu, co sprzyja drapieżnikom. To wymarzone łowisko dla spinningistów szukających sandaczy czatujących w cieniu nadrzecznych wiklin i głębokich rynien. Wędkarze stacjonarni z sukcesami łowią tu dorodne brzany oraz leszcze, wykorzystując systematyczne nęcenie w rynnie głównej rzeki. W 2026 roku odcinek ten jest ceniony za dziki charakter i brak dużych budowli regulacyjnych, co pozwala rybom na naturalne żerowanie. Malowniczy krajobraz i surowość rzeki czynią Zakroczym jednym z najbardziej technicznych i satysfakcjonujących łowisk w regionie.', null);

