VALUES (70882, 'Nizinna Wielka', 'Dzika, pod skarpą', 550.0, 3.5, 'Piasek i glina', 'Zwalone drzewa', 'Sandacz, Brzana, Sum', 'Kraina leszcza', true);

-- Spot 883: Wólka Przybójewska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70883, 'Wisła - Wólka Przybójewska (Kępy)', 'wisla-wolka-pzybojewska', 'RIVER', 52.4112275, 20.4661337, 'Mazowieckie', 'Czerwińsk nad Wisłą', 'Wisła w Wólce Przybójewskiej charakteryzuje się szerokim, wielonurtowym korytem z licznymi piaszczystymi wyspami i łachami. Podłoże jest tu zmienne, piaszczysto-żwirowe, co sprzyja bytowaniu dorodnych kleni i jazi żerujących na piaszczystych przelewach. To strategiczne miejsce dla łowców boleni, które agresywnie atakują drobnicę na szczytach piaszczystych przykos rzecznych. W rynnach głównego nurtu o twardszym dnie często stacjonują sandacze, doskonale reagujące na techniki prowadzenia przynęty w opadzie. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze migrujące głównym korytem rzeki. Dzikość brzegów i brak uregulowań hydrotechnicznych nadają temu łowisku unikalny charakter w marcu 2026 roku.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70883, 'Nizinna Wielka', 'Dzika, wielonurtowa', 650.0, 2.0, 'Piasek i żwir', 'Piaszczyste wyspy', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 884: Piaski Duchowne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70884, 'Wisła - Piaski Duchowne (Przykosy)', 'wisla-piaski-duchowne', 'RIVER', 52.3848202, 20.4011852, 'Mazowieckie', 'Czerwińsk nad Wisłą', 'Odcinek w Piaskach Duchownych to klasyczna kraina przykos, gdzie rzeka niesie ogromne ilości przemieszczającego się piasku. Koryto tworzy tu liczne warkocze prądowe, które są naturalnym stanowiskiem dla drapieżników polujących w silnym nurcie. Spinningiści z sukcesami obławiają stoki piaszczystych łach, szukając sandaczy stacjonujących w cieniu prądowym na krawędzi głębi. Podłoże piaszczyste z wyraźnymi uskokami dna stanowi idealne żerowisko dla stad rzecznych płoci oraz okazowych cert. Uciąg wody jest tu zdecydowany, co wymusza stosowanie cięższych zestawów feederowych dla zapewnienia stabilnej prezentacji przynęty. Malownicza panorama Doliny Środkowej Wisły oraz cisza panująca nad wodą czynią to miejsce wyjątkowo atrakcyjnym łowiskiem.', null);

