-- Spot 885: Czerwińsk nad Wisłą
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70885, 'Wisła - Czerwińsk nad Wisłą (Burta)', 'wisla-czerwinsk', 'RIVER', 52.3912537, 20.3280351, 'Mazowieckie', 'Czerwińsk nad Wisłą', 'Wisła w Czerwińsku płynie pod wysokim, północnym brzegiem, co skutkuje głęboką rynną wzdłuż miejskich umocnień brzegowych. Podłoże jest tu twardsze, piaszczysto-gliniaste, co przyciąga sandacze i sumy szukające schronienia w głębszej partii wody. To strategiczne miejsce dla łowców brzan, które doskonale czują się w żywym i dobrze natlenionym nurcie. Spinningiści wykorzystują kamieniste opaski brzegowe do polowania na okonie oraz okazowe klenie żerujące pod burtami. Wędkarze stacjonarni nęcą tutejsze głębokie rynny, licząc na brania dużych leszczy wchodzących z nurtu głównego rzeki. Bliskość zabytkowego opactwa i urok nadrzecznych bulwarów nadają każdemu wędkowaniu niepowtarzalnego, historycznego klimatu.', null);

