-- Spot 886: Wola
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70886, 'Wisła - Wola (Rozlewiska)', 'wisla-wola-mazowiecka', 'RIVER', 52.3904273, 20.2526262, 'Mazowieckie', 'Wyszogród', 'Odcinek w Woli charakteryzuje się rozległymi piaszczystymi rozlewiskami z licznymi kępami wikliny na niskich brzegach rzeki. Rzeka żłobi tu techniczne rynny prądowe, które są bankowymi stanowiskami dla sandaczy żerujących intensywnie o świcie. To doskonałe łowisko dla spinningistów polujących na bolenie, wykorzystujących turbulentną wodę powstającą na styku prądów. Podłoże piaszczyste z piaszczysto-żwirowymi łachami stanowi idealne tarlisko dla wielu gatunków ryb spokojnego żeru rzecznego. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu. Niska presja wędkarska oraz dziki charakter Wisły w tym rejonie zapewniają w 2026 roku spokój i ciszę.', null);

