VALUES (70886, 'Nizinna Wielka', 'Dzika, szeroka', 750.0, 1.5, 'Piasek', 'Kępy wikliny', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 887: Wyszogród (Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70887, 'Wisła - Wyszogród (Filar)', 'wisla-wyszogrod', 'RIVER', 52.3802481, 20.1744557, 'Mazowieckie', 'Wyszogród', 'Wisła w Wyszogrodzie to technicznie wymagające łowisko o uregulowanych brzegach i silnym nurcie przy filarach mostu drogowego. Podłoże jest tu twarde, piaszczysto-kamieniste, z głębokimi rynnami toru wodnego sięgającymi kilku metrów głębokości pod mostem. To strategiczne miejsce dla łowców sumów i sandaczy, które wykorzystują cienie prądowe za filarami jako swoje ostoje. Spinningiści z sukcesami obławiają kamieniste opaski poniżej przeprawy, szukając kleni i walecznych boleni żerujących w nurcie. Wędkarze feederowi chętnie nęcą płanie powyżej mostu, celując w rekordowe leszcze oraz dorodne certy migrujące rzeką. Bliskość ujścia Bzury sprawia, że rybostan jest tu wyjątkowo bogaty i stale zasilany migracjami ryb między rzekami.', null);

