-- Spot 888: Łady
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70888, 'Wisła - Łady (Karczowiska)', 'wisla-lady', 'RIVER', 52.380897, 20.0867774, 'Mazowieckie', 'Wyszogród', 'Odcinek w Ładach charakteryzuje się naturalnym przebiegiem koryta rzeki z dużą ilością zwalonych do wody karczowisk. Rzeka żłobi tu głębokie rynny pod wysokimi burtami brzegowymi, które skrywają okazowe sandacze oraz duże szczupaki rzeczne. To techniczne łowisko dla spinningistów, wymagające precyzyjnych rzutów w bezpośrednim sąsiedztwie zatopionych pni i gałęzi drzew. Podłoże piaszczysto-gliniaste z wyraźnymi uskokami dna toru wodnego stanowi idealne stanowisko dla nocnych sumów żerujących. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i jelce, wykorzystując spowolnienia nurtu powstające za przeszkodami. W marcu 2026 roku Łady pozostają jednym z najciekawszych punktów dla osób szukających dzikiej, rzecznej przygody.', null);

