-- Spot 889: Uderz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70889, 'Wisła - Uderz (Warkocze)', 'wisla-uderz', 'RIVER', 52.3918489, 20.0101568, 'Mazowieckie', 'Słubice', 'Wisła w Uderzu to kraina piaszczystych wysp i rozległych łach, gdzie rzeka dzieli się na kilka dynamicznych odnóg. Koryto posiada tu piaszczyste dno z licznymi mikro-warkoczami prądowymi idealnymi do łowienia techniką spinningową i muchową. To strategiczne miejsce dla łowców boleni, które patrolują krawędzie nurtu w poszukiwaniu stad uklei na płytkiej wodzie. W rynnach między wyspami o twardszym dnie często stacjonują sandacze, doskonale reagujące na prowadzenie lekkich jigów. Wędkarze feederowi chętnie nęcą piaszczyste blaty, licząc na brania rekordowych leszczy wchodzących w rzekę z nurtu głównego. Malowniczy krajobraz doliny Wisły i krystaliczna przejrzystość wody nadają temu miejscu unikalny, niemal pierwotny klimat.', null);

