-- Spot 890: Kępa Polska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70890, 'Wisła - Kępa Polska (Przełom)', 'wisla-kepa-polska', 'RIVER', 52.4267035, 19.9616366, 'Mazowieckie', 'Wyszogród', 'Wisła w Kępie Polskiej charakteryzuje się zwężonym korytem i bardzo silnym nurtem, co skutkuje wymywaniem głębokich rynien w twardym dnie. Podłoże jest tu piaszczysto-gliniaste z licznymi podmyłymi burtami, które stanowią bankowe stanowiska dla brzan i dużych kleni. To strategiczne miejsce dla łowców boleni, którzy polują w warkoczach prądowych powstających na krawędzi nurtu głównego. Spinningiści z sukcesami obławiają tutejsze kamieniste opaski brzegowe, szukając sandaczy czatujących w cieniu prądowym. Uciąg wody jest tu zdecydowany i stabilny, co wymaga stosowania dociążonych zestawów gruntowych do poprawnej prezentacji przynęty. Malowniczy krajobraz i surowość rzeki czynią Kępę Polską jednym z najbardziej technicznych łowisk w regionie mazowieckim.', null);

