-- Spot 891: Michowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70891, 'Wisła - Michowice (Łachy)', 'wisla-michowice', 'RIVER', 52.4543394, 19.8951056, 'Mazowieckie', 'Płock', 'Odcinek w Michowicach to klasyczna kraina rozległych piaszczystych przykos i łach, które dynamicznie zmieniają swój kształt po zimowych przyborach. Rzeka rozlewa się tu szeroko, tworząc liczne odnogi i warkocze prądowe idealne dla boleni patrolujących krawędzie nurtu. Podłoże jest głównie piaszczyste, jednak w głębszych rynnach między wyspami można trafić na twardsze, żwirowe fragmenty dna. Spinningiści z sukcesami obławiają stoki piaszczystych przykos, szukając sandaczy stacjonujących w głębszych dołkach. Wędkarze stacjonarni nęcą tutejsze piaszczyste płanie, celując w dorodne leszcze oraz rzeczne płocie migrujące korytem. Dzikość brzegów i utrudniony dojazd sprawiają, że w marcu 2026 roku presja wędkarska jest tu minimalna.', null);

