-- Spot 892: Nowy Troszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70892, 'Wisła - Nowy Troszyn (Burta Gliniana)', 'wisla-nowy-troszyn', 'RIVER', 52.4745544, 19.8126667, 'Mazowieckie', 'Płock', 'Wisła w Nowym Troszynie płynie pod wysokim brzegiem, co sprzyja powstawaniu głębokich rynien o twardym, gliniastym podłożu dna rzeki. To wymarzone łowisko dla łowców sumów, którzy wykorzystują liczne karczowiska i zwalone drzewa jako główne ostoje drapieżników. Spinningiści z sukcesami polują tu na okonie oraz okazowe klenie, wykorzystując techniczne uskoki dna toru wodnego. Uciąg rzeki stabilizuje się na tym odcinku, przechodząc powoli w charakterystykę przedzbiornikową, co sprzyja systematycznemu nęceniu. Wędkarze feederowi chętnie obławiają rynny głównego nurtu, licząc na brania rekordowych leszczy wchodzących z dołu rzeki. Spokojna okolica i surowość nadwiślańskiego krajobrazu zapewniają wędkarzowi doskonałe warunki do całodziennej sesji.', null);

