-- Spot 893: Płock (Most Legionów)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70893, 'Wisła - Płock (Centrum - Most)', 'wisla-plock-most', 'RIVER', 52.505465, 19.7574736, 'Mazowieckie', 'Płock', 'Łowisko w centrum Płocka charakteryzuje się ogromną głębokością toru wodnego i obecnością potężnych filarów mostów, które generują silne zawirowania nurtu. Podłoże jest tu twarde, piaszczysto-kamieniste, z głębokimi rynnami sięgającymi nawet 6-8 metrów pod filarami konstrukcji. To strategiczne miejsce dla łowców sumów i sandaczy, którzy wykorzystują techniczne cienie prądowe za filarami jako swoje ostoje. Spinningiści z sukcesami obławiają betonowe nabrzeża, szukając okoni oraz boleni żerujących na stadach uklei w nurcie. Uciąg wody jest tu stabilny, ale potężny, co wymaga stosowania najcięższych dostępnych zestawów gruntowych i spinningowych. Bliskość zabytkowej skarpy płockiej i dobra infrastruktura czynią to miejsce idealnym na techniczny streetfishing.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70893, 'Nizinna Wielka', 'Uregulowana, głęboka', 600.0, 7.0, 'Twardy piasek', 'Filary mostów, bulwary', 'Sum, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 894: Płock (Radziwie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70894, 'Wisła - Płock (Radziwie)', 'wisla-plock-radziwie', 'RIVER', 52.5340263, 19.6967154, 'Mazowieckie', 'Płock', 'Odcinek w Radziwiu to początek Zbiornika Włocławskiego, gdzie nurt rzeki wyraźnie wyhamowuje, a koryto znacznie się rozszerza. Podłoże przyjmuje charakter piaszczysto-mulisty, co sprzyja bytowaniu ogromnych stad leszczy oraz karpi szukających pokarmu w osadach. To strategiczne miejsce dla łowców sandaczy, którzy wykorzystują uskoki starego koryta rzeki do precyzyjnego łowienia w pionie z łodzi. Wędkarze stacjonarni nęcą tutejsze rozległe płanie, licząc na brania rekordowych ryb spokojnego żeru migrujących zbiornikiem. Uciąg wody bywa tu niemal niewyczuwalny, co pozwala na stosowanie lżejszych metod feederowych i spławikowych w marcu 2026 roku. Miejsce to słynie z nocnych połowów sumów, które patrolują płytkie zatoki w poszukiwaniu łatwej zdobyczy.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70894, 'Nizinna Wielka', 'Zbiornikowa, szeroka', 900.0, 5.0, 'Piasek i muł', 'Zatopione koryto', 'Sandacz, Leszcz, Sum', 'Kraina leszcza', true);

-- Spot 895: Wisła (Miasto - Źródła)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70895, 'Wisła - Wisła (Górski Potok)', 'wisla-miasto-gorska', 'RIVER', 49.6161333, 18.9223721, 'Śląskie', 'Wisła', 'Wisła w swoim górskim biegu to krystalicznie czysty, wartki potok o kamienistym dnie usianym licznymi progami i bystrzami. Rzeka żłobi tu głębokie rynny między głazami, które są naturalnym stanowiskiem dla walecznych pstrągów potokowych i lipieni. To techniczne łowisko wymaga od wędkarza dużej precyzji w podawaniu przynęt pod nawisy nadrzecznych drzew i skalne załomy. Uciąg wody jest bardzo dynamiczny, co sprzyja doskonałemu natlenieniu wody przez cały sezon wędkarski 2026 roku. Spinningiści z sukcesami obławiają tutejsze mikro-warkocze, wykorzystując małe woblery i obrotówki do polowania w prądzie. Malowniczy krajobraz Beskidu Śląskiego i status wód górskich czynią to miejsce wyjątkowym punktem na mapie całej rzeki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70895, 'Górska', 'Bystra, kamienista', 8.0, 0.6, 'Kamień i głazy', 'Progi kamienne', 'Pstrąg potokowy, Lipień, Głowacz', 'Kraina pstrąga', false);

-- Spot 896: Kępa Skórecka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70896, 'Wisła - Kępa Skórecka (Dzikie Przykosy)', 'wisla-kepa-skorecka', 'RIVER', 51.8085462, 21.404226, 'Mazowieckie', 'Maciejowice', 'Wisła w Kępie Skóreckiej to kwintesencja dzikiej rzeki o piaszczystym dnie i ogromnej dynamice przemieszczających się łach. Koryto rzeki rozlewa się tutaj szeroko, tworząc liczne warkocze prądowe, które są naturalnym stanowiskiem dla drapieżników polujących w nurcie. To strategiczne miejsce dla łowców boleni, które w marcu 2026 roku agresywnie patrolują płytkie przelewy piaszczystych przykos. Spinningiści z sukcesami obławiają stoki łach, szukając sandaczy stacjonujących w głębszych rynnach na krawędzi prądu. Wędkarze stacjonarni nęcą tutejsze płanie, celując w dorodne leszcze oraz rzeczne certy migrujące korytem głównym. Izolacja tego odcinka i dzikość brzegów gwarantują absolutną ciszę oraz kontakt z nienaruszoną naturą Doliny Środkowej Wisły.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70896, 'Nizinna Wielka', 'Dzika, piaszczysta', 580.0, 2.0, 'Piasek', 'Przykosy, łachy', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 897: Gruszczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70897, 'Wisła - Gruszczyn (Rynna Gówna)', 'wisla-gruszczyn', 'RIVER', 51.8327522, 21.3379441, 'Mazowieckie', 'Wilga', 'Odcinek w Gruszczynie charakteryzuje się zwężonym korytem i bardzo zdecydowanym uciągiem wody przy prawym brzegu rzeki. Podłoże jest tu twardsze, piaszczysto-gliniaste, co sprzyja powstawaniu głębokich rynien będących ostoją dla rekordowych brzan i sumów. To doskonałe łowisko dla spinningistów, którzy wykorzystują głębokie uskoki dna do prowadzenia ciężkich przynęt gumowych w technice opadu. W marcu 2026 roku miejsce to słynie z regularnych połowów dorodnych kleni żerujących pod nawisami nadrzecznych wiklin. Wędkarze feederowi chętnie nęcą tutejsze płanie żwirowe, licząc na brania dużych leszczy wchodzących z nurtu głównego. Bliskość ujścia Wilgi sprawia, że rybostan jest tu wyjątkowo zróżnicowany i stale zasilany migracjami ryb między rzekami.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70897, 'Nizinna Wielka', 'Naturalna, głęboka', 520.0, 3.5, 'Piasek i glina', 'Podmyte brzegi', 'Brzana, Sum, Kleń', 'Kraina leszcza', true);

-- Spot 898: Kępa Podwierzbiańska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70898, 'Wisła - Kępa Podwierzbiańska (Wyspy)', 'wisla-kepa-podwierzbianska', 'RIVER', 51.7340187, 21.4236188, 'Mazowieckie', 'Maciejowice', 'Wisła w rejonie Kępy Podwierzbiańskiej to kraina piaszczystych wysp i rozległych rozlewisk, gdzie rzeka dzieli się na kilka dynamicznych odnóg. Takie ukształtowanie koryta stwarza idealne warunki dla ryb reofilnych, szukających pokarmu na płytkich przelewach piaszczystych łach. To strategiczne miejsce dla łowców boleni, którzy namierzają stada drobnicy przy turbulentnych warkoczach powstających na łukach koryta. Podłoże jest głównie piaszczyste, ale w głębszych rynnach między wyspami można trafić na twardsze, żwirowe fragmenty dna. Wędkarze stacjonarni z sukcesami łowią tu dorodne jazie, wykorzystując systematyczne nęcenie na stokach piaszczystych przykos. Dzikość brzegów i utrudniony dojazd sprawiają, że presja wędkarska jest tu minimalna, co sprzyja osiąganiu rekordowych wyników.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70898, 'Nizinna Wielka', 'Wielonurtowa, wyspowa', 650.0, 1.8, 'Piasek i żwir', 'Wyspy piaszczyste', 'Boleń, Jaź, Leszcz', 'Kraina leszcza', true);

-- Spot 899: Maruszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70899, 'Wisła - Maruszów (Przełom Annopolski)', 'wisla-maruszow', 'RIVER', 50.8830242, 21.8318903, 'Lubelskie', 'Annopol', 'Odcinek w Maruszowie charakteryzuje się surowym, erozyjnym charakterem ze względu na zwężenie doliny rzeki w rejonie Annopola. Podłoże jest tu wyjątkowo twarde, piaszczysto-kamieniste, z licznymi opokami wapiennymi, które tworzą unikalne schronienia dla dużych sandaczy. To strategiczne miejsce dla spinningistów, którzy wykorzystują głębokie rynny pod wysokim brzegiem do precyzyjnego łowienia sandaczy i okoni. Uciąg wody jest tu zdecydowany i potężny, co wymusza stosowanie najcięższych dostępnych zestawów gruntowych i spinningowych. Wędkarze stacjonarni z sukcesami łowią tu waleczne brzany, które doskonale czują się w tym mocno natlenionym fragmencie rzeki. Malowniczy krajobraz przełomu Wisły i wysoka rybność odcinka czynią Maruszów obowiązkowym punktem na mapie każdego fana rzecznego spinningu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70899, 'Nizinna Wielka', 'Przełomowa, wąska', 400.0, 4.2, 'Kamień i opoka', 'Skałki wapienne', 'Sandacz, Brzana, Sum', 'Kraina leszcza', true);

-- Spot 900: Nowe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70900, 'Wisła - Nowe (Rynny pod burtą)', 'wisla-nowe', 'RIVER', 50.93022, 21.8143808, 'Lubelskie', 'Annopol', 'Wisła w okolicach miejscowości Nowe płynie szerokim korytem, uderzając w wysoki brzeg i tworząc głębokie rynny erozyjne. Podłoże jest tu piaszczysto-gliniaste z licznymi uskokami dna, stanowiącymi idealne kryjówki dla dużych sumów i sandaczy. To doskonałe łowisko dla wędkarzy feederowych, którzy z sukcesami nęcą tutejsze płanie w poszukiwaniu dorodnych leszczy. Spinningiści chętnie obławiają krawędzie nadrzecznych wiklin, szukając okoni oraz szczupaków czatujących w zastoiskach brzegowych. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu. W marcu 2026 roku odcinek ten charakteryzuje się bardzo stabilną populacją jazi, które chętnie pobierają małe przynęty w nurcie.', null);

