-- Spot 901: Wesołówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70901, 'Wisła - Wesołówka (Rozlewiska Piaszczyste)', 'wisla-wesolowka', 'RIVER', 50.9801732, 21.8181681, 'Lubelskie', 'Tarłów', 'Odcinek w Wesołówce charakteryzuje się rozległymi piaszczystymi rozlewiskami z licznymi kępami wikliny na niskich brzegach rzeki. Rzeka żłobi tu techniczne rynny prądowe, które są bankowymi stanowiskami dla sandaczy żerujących intensywnie w marcu. To doskonałe łowisko dla spinningistów polujących na bolenie, wykorzystujących turbulentną wodę powstającą na styku prądów przykos. Podłoże piaszczyste z piaszczysto-żwirowymi łachami stanowi idealne tarlisko dla wielu gatunków ryb spokojnego żeru rzecznego. Uciąg rzeki jest tu umiarkowany, co sprzyja komfortowemu łowieniu metodą feedera klasycznego z długim przyponem. Niska presja wędkarska oraz dziki charakter Wisły w tym rejonie zapewniają w 2026 roku spokój i doskonałe wyniki nad wodą.', null);

