VALUES (70901, 'Nizinna Wielka', 'Dzika, szeroka', 600.0, 1.5, 'Piasek', 'Przykosy piaszczyste', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 902: Ciszyca Górna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70902, 'Wisła - Ciszyca Górna (Skarpa)', 'wisla-ciszyca-gorna', 'RIVER', 51.0249, 21.8009913, 'Świętokrzyskie', 'Tarłów', 'Wisła w Ciszycy Górnej płynie u podnóża wysokiej skarpy, co skutkuje głębokim korytem i bardzo zdecydowanym uciągiem wody przy burtach. Podłoże jest tu twarde, piaszczysto-gliniaste, usiane licznymi karczowiskami i zwalonymi do wody fragmentami brzegu, co sprzyja drapieżnikom. To wymarzone łowisko dla spinningistów szukających sandaczy czatujących w cieniu głębokich rynien pod samym brzegiem. Wędkarze stacjonarni z sukcesami łowią tu dorodne brzany oraz leszcze, wykorzystując systematyczne nęcenie w rynnie głównej. Uciąg wody wymaga stosowania dociążonych zestawów, ale odwdzięcza się rybami o niespotykanej kondycji i waleczności. Malowniczy widok ze skarpy na dolinę Wisły nadaje każdemu wędkowaniu w tym miejscu unikalnego, relaksującego charakteru.', null);

