VALUES (70902, 'Nizinna Wielka', 'Dzika, pod skarpą', 540.0, 2.8, 'Glina i piasek', 'Zwalone drzewa, karcze', 'Sandacz, Brzana, Leszcz', 'Kraina leszcza', true);

-- Spot 903: Ostrów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70903, 'Wisła - Ostrów (Kamienny Przełom)', 'wisla-ostrow-lubelskie', 'RIVER', 51.0702261, 21.8020212, 'Lubelskie', 'Józefów nad Wisłą', 'Wisła w Ostrowie charakteryzuje się zwężonym korytem i obecnością twardych, wapiennych formacji skalnych na dnie rzeki. Silny nurt wymywa tu głębokie rynny pod wysokim brzegiem, stanowiące naturalną ostoję dla brzan oraz okazowych sumów. To strategiczne miejsce dla spinningistów szukających sandaczy czatujących w cieniu prądowym podwodnych progów. Podłoże jest piaszczysto-kamieniste, co w marcu 2026 roku sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych. Wędkarze stacjonarni z sukcesami obławiają tutejsze warkocze, stosując najcięższe zestawy gruntowe odporne na napór prądu. Dzikość krajobrazu i surowość rzeki nadają temu łowisku unikalny, niemal górski charakter.', null);

