-- Spot 904: Piotrawin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70904, 'Wisła - Piotrawin (Opoka)', 'wisla-piotrawin', 'RIVER', 51.1155078, 21.7961847, 'Lubelskie', 'Opole Lubelskie', 'Łowisko w Piotrawinie słynie z unikalnych w skali kraju wapiennych klifów oraz twardego, kredowego podłoża rzeki. Nurt uderza tu bezpośrednio w wysoki brzeg, tworząc jamy o głębokości dochodzącej do pięciu metrów pod samymi skałami. To wymarzone miejsce dla spinningistów polujących na sandacze, które wykorzystują szczeliny w opoce jako swoje główne kryjówki. W marcu 2026 roku woda jest tu wyjątkowo przejrzysta, co wymaga od wędkarza stosowania bardzo długich przyponów z fluorocarbonu. Wędkarze feederowi z sukcesami łowią tu dorodne certy oraz jelce, wykorzystując twarde dno do precyzyjnej prezentacji przynęty. Specyfika podłoża sprawia, że jest to jedno z najtrudniejszych technicznie, ale i najbardziej rybnych miejsc na Środkowej Wiśle.', null);

