VALUES (70904, 'Nizinna Wielka', 'Przełomowa, skalista', 420.0, 4.2, 'Opoka wapienna', 'Podwodne progi', 'Sandacz, Brzana, Certa', 'Kraina leszcza', true);

-- Spot 905: Kępa Gostecka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70905, 'Wisła - Kępa Gostecka (Dzika)', 'wisla-kepa-gostecka', 'RIVER', 51.1618218, 21.7845118, 'Lubelskie', 'Łaziska', 'Wisła w Kępie Gosteckiej powraca do charakteru wielonurtowego z rozległymi piaszczystymi łachami i licznymi kępami wikliny. Koryto rozlewa się tutaj szeroko, tworząc mozaikę płytkich przelewów i głębszych rynien toru wodnego idealnych dla boleni. To strategiczne miejsce dla łowców drapieżników, którzy w marcu namierzają stada uklei przy turbulentnych warkoczach wyspowych. Podłoże jest głównie piaszczyste, co sprzyja dynamicznym zmianom ukształtowania dna po każdym wiosennym przyborze wody. Wędkarze stacjonarni z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze migrujące korytem głównym rzeki. Miejsce to pozostaje oazą dzikiej przyrody, oferując w 2026 roku doskonałe warunki do izolacji od cywilizacji.', null);

