-- Spot 906: Las Dębowy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70906, 'Wisła - Las Dębowy (Przykosy)', 'wisla-las-debowy', 'RIVER', 51.2070138, 21.7982447, 'Lubelskie', 'Solec nad Wisłą', 'Odcinek rzeki w rejonie Lasu Dębowego to klasyczne łowisko przykosowe z potężnymi masami przemieszczającego się piasku. Nurt jest tu wyjątkowo żywy, tworząc techniczne warkocze prądowe idealne do polowania na bolenie techniką spinningową. Podłoże piaszczyste z piaszczysto-żwirowymi łachami stanowi naturalną stołówkę dla stad jazi oraz kleni żerujących o zmierzchu. Spinningiści z sukcesami obławiają stoki łach, szukając sandaczy stacjonujących w głębszych dołkach na krawędzi prądu. Uciąg wody jest stabilny i zdecydowany, co sprzyja doskonałemu natlenieniu wody przez cały sezon wędkarski 2026 roku. Dzikość brzegów porośniętych starym drzewostanem łęgowym nadaje temu miejscu unikalnego i surowego klimatu.', null);

