-- Spot 907: Gniazdków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70907, 'Wisła - Gniazdków (System Główek)', 'wisla-gniazdkow', 'RIVER', 51.2523764, 21.8057978, 'Lubelskie', 'Chodel', 'Łowisko w Gniazdkowie charakteryzuje się klasycznym układem ostróg (główek), które regulują nurt rzeki i tworzą techniczne klatki brzegowe. Podłoże jest tu zróżnicowane – piaszczyste wewnątrz klatek i kamieniste na szczytach budowli hydrotechnicznych, co sprzyja różnym technikom łowienia. To strategiczne miejsce dla spinningistów polujących na sandacze, którzy obławiają warkocze prądowe powstające na napływach główek. Wędkarze stacjonarni z sukcesami łowią tu okazałe certy oraz leszcze, stosując technikę feedera klasycznego na krawędzi nurtu. W marcu 2026 roku odcinek ten jest ceniony za dużą populację jazi, które chętnie trzyma się kamienistych umocnień opasek. Dobra infrastruktura i łatwy dostęp do brzegów czynią Gniazdków popularnym miejscem weekendowych wypraw.', null);

