-- Spot 908: Zastów Polanowski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70908, 'Wisła - Zastów Polanowski (Burta)', 'wisla-zastow-polanowski', 'RIVER', 51.2824021, 21.8626265, 'Lubelskie', 'Solec nad Wisłą', 'Wisła w Zastowie Polanowskim płynie u podnóża wysokiej skarpy, co skutkuje głębokim korytem i zdecydowanym uciągiem wody przy burtach. Podłoże jest tu twarde, piaszczysto-gliniaste, usiane licznymi karczowiskami i zwalonymi drzewami stanowiącymi ostoje dla sumów. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w zastoiskach za naturalnymi przeszkodami w nurcie rzeki. W marcu 2026 roku miejsce to słynie z regularnych brani dorodnych jazi, które doskonale reagują na owadowe przynęty spinningowe. Wędkarze stacjonarni nęcą tutejsze głębokie rynny, licząc na brania rekordowych leszczy wchodzących z nurtu głównego Wisły. Malowniczy krajobraz i surowość rzeki czynią Zastów jednym z najbardziej technicznych i satysfakcjonujących łowisk.', null);

