-- Spot 909: Oblasy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70909, 'Wisła - Oblasy (Rynny Torowe)', 'wisla-oblasy', 'RIVER', 51.3156673, 21.9131667, 'Lubelskie', 'Janowiec', 'Odcinek w Oblasach charakteryzuje się głębokimi rynnami toru wodnego wymytymi w twardym, piaszczysto-gliniastym podłożu dna rzeki. Rzeka żłobi tu techniczne doły na krawędzi nurtu głównego, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców sumów, którzy wykorzystują dużą masę wody do precyzyjnego prowadzenia ciężkich zestawów gruntowych. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze oraz certy migrujące okresowo korytem. Uciąg wody jest tu żywy i uzależniony od aktualnych stanów Wisły, co wymaga stosowania dociążonych koszyków zanętowych. Malowniczy krajobraz przełomu Janowieckiego i wysoka rybność odcinka czynią to miejsce wyjątkowo atrakcyjnym punktem na mapie.', null);

