-- Spot 910: Nasiłów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70910, 'Wisła - Nasiłów (Kamieniołom)', 'wisla-nasilow', 'RIVER', 51.3444686, 21.9685328, 'Lubelskie', 'Kazimierz Dolny', 'Wisła w Nasiłowie to technicznie wymagające łowisko o uregulowanych brzegach i twardym, piaszczysto-kamienistym dnie toru wodnego. Sąsiedztwo dawnych kamieniołomów sprawia, że podłoże usiane jest odłamkami opoki, stanowiącej idealne tarlisko i schronienie dla sandaczy. To strategiczne miejsce dla spinningistów polujących na bolenie, wykorzystujących turbulentną wodę na styku prądów przy kamienistych opaskach. Uciąg rzeki jest tu potężny, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji ryb reofilnych w 2026 roku. Wędkarze stacjonarni nęcą głębokie rynny torowe, licząc na brania walecznych brzan oraz okazowych leszczy żerujących w prądzie. Bliskość Kazimierza Dolnego i unikalna panorama skarpy wiślanej nadają każdemu wędkowaniu niepowtarzalnego, historycznego wymiaru.', null);

