-- Spot 911: Chwalibogowice (Ujście Dunajca)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70911, 'Wisła - Chwalibogowice (Węzeł Dunajca)', 'wisla-chwalibogowice', 'RIVER', 50.2618945, 20.7481608, 'Świętokrzyskie', 'Opatowiec', 'Wisła w Chwalibogowicach to miejsce o strategicznym znaczeniu, znajdujące się bezpośrednio powyżej ujścia Dunajca. Koryto rzeki posiada tu piaszczyste dno z wyraźnie zaznaczonymi rynnami, w których stacjonują stada leszczy przygotowujące się do wiosennych wędrówek. To doskonałe łowisko dla spinningistów szukających sandaczy czatujących na krawędzi nurtu głównego. Uciąg wody jest tu stabilny, ale wyraźnie wzrasta w okresach przyborów Dunajca, co wymusza stosowanie cięższych zestawów gruntowych. Wędkarze feederowi z sukcesami obławiają tutejsze płanie, celując w dorodne certy oraz rzeczne płocie. W marcu 2026 roku odcinek ten zachowuje krystaliczną czystość wody, co czyni go jednym z najatrakcyjniejszych punktów w regionie.', null);

