-- Spot 912: Podzamcze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70912, 'Wisła - Podzamcze (Głębie)', 'wisla-podzamcze', 'RIVER', 50.2900192, 20.8033833, 'Małopolskie', 'Koszyce', 'Odcinek w Podzamczu charakteryzuje się naturalnym przebiegiem koryta z głębokimi rynnami wymytymi pod wysokimi burtami brzegowymi. Rzeka żłobi tu dno o charakterze piaszczysto-gliniastym, co sprzyja bytowaniu okazałych sumów i dużych szczupaków. To strategiczne miejsce dla spinningistów, którzy wykorzystują liczne zwalone drzewa i karczowiska jako punkty podania przynęty. Uciąg wody jest tu zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką aktywność ryb reofilnych. W marcu 2026 roku miejsce to słynie z rekordowych kleni, które doskonale reagują na małe woblery prowadzone na granicy głównego prądu. Spokojna okolica i dzikość brzegów gwarantują wędkarzowi absolutną ciszę oraz kontakt z nienaruszoną naturą.', null);

