-- Spot 913: Kanna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70913, 'Wisła - Kanna (Łachy Piaszczyste)', 'wisla-kanna', 'RIVER', 50.2940868, 20.875778, 'Małopolskie', 'Szczucin', 'Wisła w Kannie to kraina rozległych piaszczystych przykos i łach, które dzielą nurt rzeki na kilka dynamicznych odnóg. Takie ukształtowanie koryta stwarza idealne warunki dla boleni, które w marcu agresywnie patrolują płytkie przelewy w poszukiwaniu drobnicy. Podłoże jest głównie piaszczyste, co sprzyja dynamicznym zmianom ukształtowania dna po każdym wiosennym wezbraniu wody. Wędkarze stacjonarni z sukcesami łowią tu dorodne jazie, wykorzystując systematyczne nęcenie na stokach piaszczystych blatów. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie przy użyciu techniki feedera klasycznego. Niska presja wędkarska sprawia, że w 2026 roku Kanna jest cenionym punktem dla osób szukających dzikiej, rzecznej przygody.', null);

