-- Spot 914: Błotnowola
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70914, 'Wisła - Błotnowola (System Główek)', 'wisla-blotnowola', 'RIVER', 50.309759, 20.9430381, 'Świętokrzyskie', 'Nowy Korczyn', 'Łowisko w Błotnowoli charakteryzuje się klasycznym układem ostróg kamiennych, które regulują nurt rzeki i tworzą techniczne klatki brzegowe. Podłoże jest tu zróżnicowane – piaszczyste wewnątrz klatek i twarde, kamieniste na szczytach budowli hydrotechnicznych. To strategiczne miejsce dla spinningistów polujących na sandacze, którzy obławiają turbulentne warkocze prądowe na szczytach główek. Wędkarze gruntowi z sukcesami nęcą tutejsze spowolnienia nurtu, licząc na brania rekordowych leszczy i cert migrujących rzeką. Uciąg wody jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb praktycznie przez całą dobę wędkarską. Dobra infrastruktura i łatwy dostęp do wody czynią to łowisko jednym z najpopularniejszych punktów w regionie nowokorczyńskim.', null);

