-- Spot 915: Laskówka Delastowska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70915, 'Wisła - Laskówka (Burta pod Skarpą)', 'wisla-laskowka', 'RIVER', 50.3138151, 21.0177108, 'Małopolskie', 'Szczucin', 'Wisła w Laskówce Delastowskiej płynie pod wysokim brzegiem, tworząc głęboką rynnę o twardym, gliniasto-żwirowym dnie. To wymarzone łowisko dla łowców sumów, którzy wykorzystują głębokie doły toru wodnego jako swoje główne ostoje dzienne. Spinningiści z sukcesami polują tu na okonie oraz okazowe klenie, wykorzystując techniczne uskoki dna przy podmytych brzegach. Uciąg rzeki jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji ryb w marcu 2026 roku. Wędkarze stacjonarni nęcą tutejsze płanie, licząc na brania rekordowych brzan doskonale czujących się w twardym nurcie. Malowniczy krajobraz i surowość rzeki czynią Laskówkę jednym z najbardziej satysfakcjonujących łowisk dla doświadczonych wędkarzy.', null);

