-- Spot 916: Rataje Karskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70916, 'Wisła - Rataje Karskie (Rynny Torowe)', 'wisla-rataje-karskie', 'RIVER', 50.3342895, 21.0815357, 'Świętokrzyskie', 'Pacanów', 'Odcinek w Ratajach Karskich charakteryzuje się szerokim korytem z wyraźnie zaznaczonym torem wodnym o piaszczystym podłożu. Rzeka żłobi tu techniczne rynny na krawędzi nurtu głównego, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców jazi i kleni, które doskonale reagują na małe woblery i systematyczne nęcenie roślinne. Uciąg wody jest tu stabilny, co pozwala na precyzyjne podawanie przynęt przy użyciu techniki feedera klasycznego. Pod nawisami nadrzecznych wiklin często grupują się stada płoci, doskonale reagujących na wiosenne mieszanki zanętowe. W marcu 2026 roku odcinek ten cieszy się dużą popularnością ze względu na stabilne wyniki wędkarskie i łatwy dostęp.', null);

