-- Spot 917: Gace Słupieckie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70917, 'Wisła - Gace Słupieckie (Cofka Połańca)', 'wisla-gace-slupieckie', 'RIVER', 50.353349, 21.1487711, 'Świętokrzyskie', 'Połaniec', 'Wisła w Gacach Słupieckich znajduje się pod silnym wpływem pobliskiego stopnia wodnego i zrzutów ciepłej wody z elektrowni Połaniec. Podłoże jest tu piaszczysto-muliste z licznymi zastoiskami brzegowymi, które w marcu przyciągają ogromne stada białorybu szukającego cieplejszej wody. To strategiczne miejsce dla łowców okazowych leszczy oraz krąpi, które żerują tu intensywnie przez całą dobę. Spinningiści z sukcesami polują na szczupaki oraz okonie, wykorzystując bogatą roślinność zanurzoną w przybrzeżnych zatokach. Uciąg wody jest tu zmienny, uzależniony od aktualnej pracy turbin elektrowni, co wymaga od wędkarza częstej adaptacji techniki. W 2026 roku Gace pozostają unikalnym łowiskiem, oferującym aktywność ryb wyższą niż w innych odcinkach Wisły.', null);

