-- Spot 918: Gliny Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70918, 'Wisła - Gliny Wielkie (Opaski Kamienne)', 'wisla-gliny-wielkie', 'RIVER', 50.3976559, 21.2807968, 'Podkarpackie', 'Mielec', 'Odcinek w Glinach Wielkich charakteryzuje się obecnością technicznych opasek kamiennych chroniących brzegi rzeki przed erozją. Podłoże jest tu twarde, kamienisto-żwirowe na krawędzi nurtu, co sprzyja obecności brzan oraz okazowych sandaczy. To strategiczne miejsce dla spinningistów, którzy wykorzystują warkocze prądowe powstające przy umocnieniach do polowania na bolenie. Wędkarze stacjonarni z sukcesami nęcą tutejsze głębokie rynny, licząc na brania dużych leszczy i cert wchodzących z dołu rzeki. Uciąg wody jest tu zdecydowany i stabilny, co sprzyja doskonałemu natlenieniu wody przez cały marzec 2026 roku. Bliskość ujścia Wisłoki sprawia, że rybostan jest tu wyjątkowo zróżnicowany, łącząc gatunki typowo nizinne z migrującymi rybami rzecznymi.', null);

