-- Spot 919: Grabie (Niepołomice)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70919, 'Wisła - Grabie (Wypływ z Krakowa)', 'wisla-grabie', 'RIVER', 50.0426452, 20.1077406, 'Małopolskie', 'Niepołomice', 'Wisła w Grabiu to odcinek, na którym rzeka zaczyna przyspieszać po opuszczeniu miejskiego stopnia wodnego Przewóz. Koryto posiada tu piaszczysto-żwirowe dno z wyraźnymi rynnami pod wysokimi brzegami, stanowiącymi idealne kryjówki dla dużych kleni. To strategiczne miejsce dla spinningistów polujących na bolenie, wykorzystujących turbulentną wodę na styku nurtu głównego i spokojniejszych zatok. W marcu 2026 roku woda jest tu dobrze natleniona, co sprzyja wysokiej aktywności ryb spokojnego żeru, takich jak dorodne płocie i jelce. Wędkarze stacjonarni nęcą tutejsze głębokie rynny, licząc na brania rekordowych leszczu wchodzących z dołu rzeki. Spokojna okolica i bliskość Puszczy Niepołomickiej nadają każdemu wędkowaniu unikalny, relaksujący charakter.', null);

