-- Spot 921: Zabierzów Bocheński
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70921, 'Wisła - Zabierzów Bocheński (Główki)', 'wisla-zabierzow-bochenski', 'RIVER', 50.0890072, 20.2919214, 'Małopolskie', 'Niepołomice', 'Wisła w Zabierzowie Bocheńskim charakteryzuje się technicznym układem ostróg (główek), które regulują nurt i tworzą klatki o spowolnionym przepływie. Podłoże jest tu piaszczyste wewnątrz klatek i kamieniste na szczytach budowli, co sprzyja różnym technikom łowienia białorybu i drapieżników. To strategiczne miejsce dla łowców boleni, którzy obławiają turbulentne warkocze prądowe na szczytach główek. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze i certy, stosując metodę feedera klasycznego na granicy nurtu. Uciąg wody jest tu stabilny i zdecydowany, co zapewnia świetne natlenienie koryta rzeki w marcu 2026 roku. Dobra infrastruktura i łatwy dostęp do brzegów czynią to miejsce popularnym punktem wypraw wędkarzy z regionu krakowskiego.', null);

