-- Spot 922: Wawrzeńczyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70922, 'Wisła - Wawrzeńczyce (Płanie Piaszczyste)', 'wisla-wawrzenczyce', 'RIVER', 50.1151027, 20.3498142, 'Małopolskie', 'Nowe Brzesko', 'Odcinek w Wawrzeńczycach charakteryzuje się szerokim korytem i obecnością rozległych, piaszczystych płani o wyrównanym podłożu dna. Rzeka płynie tu dostojnie, oferując wędkarzom dogodny dostęp do brzegów oraz liczne zastoiska z roślinnością wynurzoną. To doskonałe łowisko dla wędkarzy feederowych celujących w białą rybę migrującą okresowo w poszukiwaniu tlenu po wiosennych przyborach. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając szczupaków czatujących w cieniu nadrzecznych wiklin. Uciąg wody jest łagodny, co pozwala na stosowanie delikatnych technik spławikowych z czułymi sygnalizatorami brań w 2026 roku. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz szansę na kontakt z niewypłoszoną rybą w sielskim krajobrazie.', null);

