-- Spot 923: Dąbrówka Morska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70923, 'Wisła - Dąbrówka Morska (Rynny)', 'wisla-dabrowka-morska', 'RIVER', 50.1440712, 20.5658054, 'Małopolskie', 'Szczurowa', 'Wisła w Dąbrówce Morskiej to technicznie ciekawe łowisko z głębokimi rynnami wymytymi na zewnętrznych łukach koryta. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z licznymi podmyłymi burtami stanowiącymi bankowe ostoje dla dużych kleni. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie dołki za naturalnymi przeszkodami jako swoje dzienne kryjówki. Spinningiści chętnie obławiają tutejsze warkocze prądowe, szukając okoni oraz sandaczy czatujących na krawędzi nurtu głównego. Uciąg rzeki jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb przez cały sezon wędkarski 2026 roku. Dziki charakter brzegów i brak uregulowań hydrotechnicznych nadają temu łowisku unikalnego klimatu.', null);

