-- Spot 924: Przemyków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70924, 'Wisła - Przemyków (Przykosy)', 'wisla-przemykow', 'RIVER', 50.1703886, 20.6368864, 'Świętokrzyskie', 'Koszyce', 'Odcinek w Przemykowie charakteryzuje się piaszczystym dnem i obecnością wyraźnych przykos rzecznych wychodzących daleko w nurt rzeki. Rzeka żłobi tu techniczne rynny na krawędzi nurtu głównego, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców boleni, którzy agresywnie atakują drobnicę na płytkich przelewach piaszczystych łach. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w dorodne jazie oraz rzeczne płocie migrujące korytem. Uciąg wody jest tu stabilny i zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb w marcu 2026 roku. Malowniczy krajobraz doliny i relatywnie łatwy dostęp do wody czynią Przemyków popularnym punktem na mapie.', null);

