-- Spot 925: Wola Rogowska (Węzeł Dunajca)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70925, 'Wisła - Wola Rogowska (Ujście Dunajca)', 'wisla-wola-rogowska', 'RIVER', 50.2059056, 20.6815341, 'Małopolskie', 'Szczurowa', 'Wisła w Woli Rogowskiej to jedno z najbardziej zróżnicowanych hydrologicznie łowisk, znajdujące się bezpośrednio powyżej ujścia Dunajca. Mieszanie się wód dwóch rzek tworzy specyficzny mikroklimat, który przyciąga ogromne stada drapieżników oraz ryb spokojnego żeru. Podłoże jest tu mocno zróżnicowane, od piaszczystych przykos po twardsze, żwirowe fragmenty dna toru wodnego. To wymarzone miejsce dla łowców sumów i sandaczy, którzy wykorzystują turbulentną wodę powstającą na styku prądów obu rzek. Spinningiści z sukcesami polują tu na bolenie, wykorzystując piaszczyste łachy ujściowe jako strategiczne punkty obserwacyjne drapieżników. W 2026 roku odcinek ten pozostaje technicznie wymagający, ale odwdzięcza się wędkarzom rybami o rekordowych rozmiarach.', null);

