VALUES (70925, 'Nizinna', 'Ujściowa, szeroka', 200.0, 3.2, 'Piasek i żwir', 'Ujście rzeki, przykosy', 'Sum, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 926: Babice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70926, 'Wisła - Babice (Obwałowania)', 'wisla-babice', 'RIVER', 50.0580595, 19.1796672, 'Małopolskie', 'Oświęcim', 'Wisła w Babicach to odcinek o charakterze uregulowanym, płynący w wysokim obwałowaniu chroniącym okoliczne tereny. Dno jest tu piaszczysto-muliste z licznymi zastoiskami przy brzegach, które sprzyjają bytności ryb spokojnego żeru. To strategiczne miejsce dla łowców białorybu, szczególnie leszczy i krąpi żerujących w spowolnionym nurcie rzeki. Spinningiści z sukcesami polują tu na szczupaki czatujące w pasie przybrzeżnej roślinności i nielicznych zwalonych konarach. Uciąg wody jest tu łagodny, co pozwala na precyzyjne nęcenie i stosowanie delikatnych zestawów spławikowych. W 2026 roku odcinek ten cieszy się uznaniem ze względu na stabilne wyniki w połowie ryb spokojnego żeru.', null);

