-- Spot 927: Oświęcim
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70927, 'Wisła - Oświęcim (Miejska)', 'wisla-oswiecim-miejska', 'RIVER', 50.050261, 19.2849281, 'Małopolskie', 'Oświęcim', 'Miejski odcinek Wisły w Oświęcimiu charakteryzuje się betonowymi umocnieniami i głębokimi rynnami pod mostami drogowymi. Podłoże jest tu twarde, piaszczysto-kamieniste, co przyciąga sandacze szukające schronienia przy filarach betonowych konstrukcji. To doskonałe łowisko dla spinningistów, którzy wykorzystują turbulentną wodę do polowania na bolenie i okazowe okonie. Wędkarze stacjonarni z sukcesami nęcą tutejsze płanie, celując w dorodne płocie oraz klenie żerujące w nurcie. Uciąg wody bywa zmienny, uzależniony od zrzutów z pobliskich dopływów i pracy okolicznych urządzeń hydrotechnicznych. Bliskość infrastruktury miejskiej sprawia, że w 2026 roku jest to popularny punkt szybkich sesji po pracy.', null);

