-- Spot 928: Dwory Drugie (Stopień Wodny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70928, 'Wisła - Dwory Drugie (Zrzut)', 'wisla-dwory-drugie', 'RIVER', 50.0431606, 19.3549007, 'Małopolskie', 'Oświęcim', 'Wisła w Dworach Drugich znajduje się pod silnym wpływem stopnia wodnego, co gwarantuje wysokie natlenienie wody poniżej zrzutu. Koryto posiada tu piaszczysto-betonowe dno z licznymi uskokami i wirami, stanowiącymi idealne żerowisko dla drapieżników. To strategiczne miejsce dla łowców sumów, którzy wykorzystują głębokie jamy toru wodnego jako swoje główne ostoje dzienne. Spinningiści z sukcesami polują tu na sandacze, prowadząc przynęty w warkoczach prądowych bezpośrednio za progiem wodnym. Uciąg rzeki jest tu potężny i dynamiczny, co wymaga stosowania najcięższych dostępnych zestawów gruntowych i spinningowych. W marcu 2026 roku odcinek ten jest uznawany za jeden z najbardziej rybnych fragmentów kaskady górnej Wisły.', null);

