-- Spot 929: Jankowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70929, 'Wisła - Jankowice (Łąkowy Nurt)', 'wisla-jankowice', 'RIVER', 50.0304149, 19.4302174, 'Małopolskie', 'Zator', 'Odcinek w Jankowicach charakteryzuje się szerszym korytem i obecnością rozległych, piaszczystych łach wychodzących okresowo w nurt rzeki. Rzeka płynie tu dostojnie przez tereny łąkowe, oferując wędkarzom dogodny dostęp do brzegów oraz liczne zastoiska brzegowe. To doskonałe łowisko dla wędkarzy feederowych celujących w białą rybę migrującą okresowo w poszukiwaniu pokarmu rzeką. Spinningiści z sukcesami obławiają tutejsze podmyte brzegi, szukając okoni oraz okazowych kleni czatujących pod nawisami traw. Uciąg wody jest umiarkowany, co sprzyja precyzyjnemu nęczeniu i utrzymywaniu stad ryb w polu łowienia. Niska presja wędkarska w tym rejonie gwarantuje spokój oraz szansę na kontakt z niewypłoszoną rybą w 2026 roku.', null);

