-- Spot 930: Kraków (Bielany)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70930, 'Wisła - Kraków (Bielany)', 'wisla-krakow-bielany', 'RIVER', 50.0211862, 19.8013311, 'Małopolskie', 'Kraków', 'Wisła w zachodniej części Krakowa płynie u podnóża wapiennych wzgórz, co skutkuje twardym i kamienistym dnem rzeki. Rzeka tworzy tu technicznie ciekawe rynny i bystrza, które są naturalnym stanowiskiem dla brzan oraz okazowych kleni. To strategiczne miejsce dla spinningistów, którzy wykorzystują silny nurt do prowadzenia przynęt w poszukiwaniu boleni i okoni. W marcu 2026 roku woda zachowuje tu wysoką przejrzystość, co wymaga stosowania niewidocznych przyponów z fluorocarbonu. Wędkarze gruntowi chętnie nęcą tutejsze płanie żwirowe, licząc na brania rekordowych ryb reofilnych w nurcie głównym. Malowniczy krajobraz z widokiem na Srebrną Górę nadaje każdemu wędkowaniu unikalnego, relaksującego wymiaru.', null);

