-- Spot 931: Kraków (Bulwary Wiślane)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70931, 'Wisła - Kraków (Bulwary)', 'wisla-krakow-bulwary', 'RIVER', 50.0381184, 19.8856603, 'Małopolskie', 'Kraków', 'Centralny odcinek Wisły w Krakowie to techniczne łowisko miejskie o głębokim torze wodnym i uregulowanych nabrzeżach betonowych. Podłoże jest tu piaszczysto-muliste z licznymi konstrukcjami, które stanowią doskonałe kryjówki dla dużych sandaczy oraz sumów. To wymarzone miejsce dla pasjonatów streetfishingu, którzy polują na okonie pod murami oporowymi i filarami krakowskich mostów. Uciąg wody jest tu stabilny, ale bywa modyfikowany przez pracę miejskich stopni wodnych, co wymusza częstą adaptację techniki. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie w głębszych spowolnieniach nurtu. W 2026 roku krakowskie bulwary pozostają jednym z najbardziej prestiżowych miejsc na mapie ogólnopolskiego wędkarstwa miejskiego.', null);

