-- Spot 933: Bydgoszcz (Fordon - Most)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70933, 'Wisła - Bydgoszcz (Most Fordoński)', 'wisla-bydgoszcz-fordon', 'RIVER', 53.1457011, 18.177323, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Wisła w Fordonie to strategiczne łowisko o uregulowanym charakterze z potężnymi filarami najdłuższego mostu w regionie. Podłoże jest tu twarde, piaszczysto-kamieniste, z głębokimi rynnami toru wodnego sięgającymi kilku metrów głębokości pod konstrukcją. To strategiczne miejsce dla łowców sumów i sandaczy, którzy wykorzystują cienie prądowe za filarami jako swoje ostoje. Spinningiści z sukcesami obławiają kamieniste opaski brzegowe poniżej przeprawy, szukając okoni oraz walecznych boleni żerujących w nurcie. Uciąg wody jest tu stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb praktycznie przez całą dobę wędkarską. Dobra infrastruktura i łatwy dostęp do brzegów czynią Fordon jednym z najpopularniejszych punktów na mapie bydgoskiego wędkarstwa.', null);

