INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70935, 'Wisła - Zła Wieś (System Główek)', 'wisla-zla-wies', 'RIVER', 53.2332585, 18.2371951, 'Kujawsko-Pomorskie', 'Solec Kujawski', 'Wisła w rejonie Złej Wsi to klasyczne łowisko głowkowe z dobrze zachowanym systemem regulacyjnym i głębokimi klatkami brzegowymi. Podłoże jest tu zróżnicowane – piaszczyste wewnątrz zatok i kamieniste na szczytach budowli, co sprzyja różnym technikom łowienia białorybu. To strategiczne miejsce dla spinningistów polujących na sandacze, którzy obławiają warkocze prądowe powstające na napływach główek. Wędkarze feederowi z sukcesami łowią tu okazałe certy oraz leszcze, stosując technikę feedera klasycznego na granicy nurtu głównego. Uciąg wody jest stabilny, co zapewnia świetne natlenienie koryta rzeki praktycznie przez cały marzec 2026 roku. Malowniczy krajobraz i relatywnie niska presja wędkarska sprawiają, że ryby żerują tu bardzo odważnie.', null);

