-- Spot 936: Grabówko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70936, 'Wisła - Grabówko (Rynny Torowe)', 'wisla-grabowko', 'RIVER', 53.2718343, 18.3112398, 'Kujawsko-Pomorskie', 'Chełmno', 'Odcinek w Grabówku charakteryzuje się prostym przebiegiem koryta z wyraźnie zaznaczonym torem wodnym o twardym, piaszczysto-gliniastym podłożu. Rzeka żłobi tu techniczne rynny na krawędzi nurtu głównego, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców boleni, którzy agresywnie atakują drobnicę na płytkich przelewach piaszczystych przykos. Wędkarze stacjonarni nęcą tutejsze płanie, celując w rekordowe leszcze oraz certy migrujące okresowo rzeką na północ. Uciąg wody jest tu zdecydowany i stabilny, co sprzyja doskonałemu natlenieniu wody przez cały sezon wędkarski 2026 roku. Spokojna okolica i dzikość brzegów porośniętych wikliną nadają temu łowisku unikalnego, relaksującego charakteru.', null);

