-- Spot 939: Żurawia Kępa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70939, 'Wisła - Żurawia Kępa (Wyspy Piaszczyste)', 'wisla-zurawia-kepa', 'RIVER', 53.377127, 18.4437094, 'Kujawsko-Pomorskie', 'Chełmno', 'Odcinek rzeki w rejonie Żurawiej Kępy to kraina piaszczystych wysp i rozległych rozlewisk, gdzie rzeka dzieli się na kilka dynamicznych odnóg. Takie ukształtowanie koryta stwarza idealne warunki dla ryb reofilnych, szukających pokarmu na płytkich przelewach piaszczystych łach. To strategiczne miejsce dla łowców boleni, którzy namierzają stada drobnicy przy turbulentnych warkoczach powstających na łukach koryta. Podłoże jest głównie piaszczyste, co sprzyja dynamicznym zmianom ukształtowania dna po każdym wiosennym przyborze wody w marcu 2026 roku. Wędkarze stacjonarni z sukcesami łowią tu dorodne jazie, wykorzystując systematyczne nęcenie na stokach piaszczystych przykos. Dzikość brzegów i utrudniony dojazd sprawiają, że presja wędkarska jest tu minimalna, co sprzyja osiąganiu rekordowych wyników.', null);

