-- Spot 949: Widlice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70949, 'Wisła - Widlice (Rynny Torowe)', 'wisla-widlice', 'RIVER', 53.723876, 18.8370888, 'Pomorskie', 'Gniew', 'Odcinek w Widlicach charakteryzuje się naturalnym przebiegiem koryta z wyraźnie zaznaczonym torem wodnym o twardym, piaszczysto-gliniastym podłożu. Rzeka żłobi tu techniczne rynny na krawędzi nurtu głównego, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców boleni, którzy agresywnie atakują drobnicę na płytkich przelewach piaszczystych łach. Wędkarze stacjonarni nęcą tutejsze płanie, celując w rekordowe leszcze oraz certy migrujące okresowo rzeką na północ. Uciąg wody jest tu zdecydowany i stabilny, co sprzyja doskonałemu natlenieniu wody przez cały sezon wędkarski 2026 roku. Spokojna okolica i dzikość brzegów porośniętych wikliną nadają temu łowisku unikalnego, relaksującego charakteru.', null);

