-- Spot 950: Lipianki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70950, 'Wisła - Lipianki (Opaski Kamienne)', 'wisla-lipianki', 'RIVER', 53.7744487, 18.8395848, 'Pomorskie', 'Kwidzyn', 'Wisła w Lipiankach posiada techniczny charakter z licznymi opaskami kamiennymi chroniącymi brzegi przed silną erozją w tym rejonie. Podłoże jest tu twarde, piaszczysto-kamieniste, z głębokimi rynnami torowymi stanowiącymi idealne ostoje dla brzan doskonale czujących się w nurcie. To strategiczne miejsce dla spinningistów, którzy wykorzystują warkocze prądowe powstające przy umocnieniach do polowania na sandacze. Wędkarze feederowi z sukcesami nęcą tutejsze rynny, licząc na brania dużych leszczy i cert migrujących w stronę ujścia rzeki. Uciąg wody jest tu zdecydowany, co wymusza stosowanie dociążonych zestawów gruntowych do stabilnej prezentacji przynęty. Malowniczy krajobraz pradoliny Wisły oraz wysoka rybność odcinka przyciągają tu pasjonatów technicznego wędkarstwa rzecznego.', null);

