-- Spot 951: Janowo (Prom)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70951, 'Wisła - Janowo (Ujściowy Nurt)', 'wisla-janowo-pomorskie', 'RIVER', 53.8204871, 18.8396253, 'Pomorskie', 'Kwidzyn', 'Odcinek rzeki w Janowie charakteryzuje się naturalnym przebiegiem koryta rzeki z dużą ilością zwalonych do wody karczowisk i głębokimi dołkami brzegowymi. Rzeka żłobi tu głębokie rynny pod wysokimi burtami brzegowymi, które skrywają okazowe sandacze oraz duże szczupaki rzeczne. To techniczne łowisko dla spinningistów, wymagające precyzyjnych rzutów w bezpośrednim sąsiedztwie zatopionych pni i gałęzi drzew. Podłoże piaszczysto-gliniaste z wyraźnymi uskokami dna toru wodnego stanowi idealne stanowisko dla nocnych sumów żerujących. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i jelce, wykorzystując spowolnienia nurtu powstające za przeszkodami. W marcu 2026 roku Janowo pozostaje jednym z najciekawszych punktów dla osób szukających dzikiej, rzecznej przygody.', null);

