INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70956, 'Wisła - Podłęcze (Burta Erozyjna)', 'wisla-podlecze', 'RIVER', 52.0400721, 21.2207365, 'Mazowieckie', 'Góra Kalwaria', 'Wisła w Podłęczu uderza bezpośrednio w wysoki, zachodni brzeg, tworząc głęboką rynnę erozyjną o twardym podłożu. Jest to strategiczne miejsce dla spinningistów polujących na sandacze, które stacjonują na krawędzi nurtu przy pionowych ścianach gliniastej burty. Woda w marcu 2026 roku jest tu mocno natleniona, co sprzyja aktywności dużych kleni żerujących na spływających z nurtem bezkręgowcach. Wędkarze stacjonarni z sukcesami obławiają spowolnienia nurtu za zwalonymi do wody fragmentami brzegu, licząc na brania rekordowych leszczy. Uciąg wody jest tu potężny, co wymaga stosowania dociążonych zestawów gruntowych i spinningowych. Specyfika tego odcinka czyni go jednym z najbardziej technicznych i satysfakcjonujących punktów na mapie Mazowsza.', null);

