VALUES (70956, 'Nizinna Wielka', 'Naturalna, głęboka', 550.0, 3.8, 'Glina i kamień', 'Podmyte burty', 'Sandacz, Brzana, Kleń', 'Kraina leszcza', true);

-- Spot 957: Gassy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70957, 'Wisła - Gassy (Warkocze Promowe)', 'wisla-gassy', 'RIVER', 52.0870484, 21.2114668, 'Mazowieckie', 'Konstancin-Jeziorna', 'Odcinek w Gassach słynie z dynamicznego nurtu i obecności piaszczystych przykos, które formują się w rejonie przeprawy promowej. Podłoże jest tu głównie piaszczyste, usiane licznymi uskokami dna toru wodnego, co przyciąga agresywne bolenie patrolujące koryto. To doskonałe miejsce dla spinningistów, którzy wykorzystują warkocze prądowe powstające przy umocnieniach brzegowych do prezentacji przynęt powierzchniowych. W marcu 2026 roku obserwuje się tu dużą koncentrację jazi, które grupują się w płytkich zastoiskach o spokojniejszym przepływie. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w dorodne certy migrujące okresowo w górę rzeki. Łatwy dojazd i duża przestrzeń sprawiają, że Gassy są ulubionym miejscem wędkarzy z aglomeracji warszawskiej.', null);

