VALUES (70957, 'Nizinna Wielka', 'Naturalna, szeroka', 580.0, 1.5, 'Piasek', 'Uskoki toru wodnego', 'Boleń, Jaź, Certa', 'Kraina leszcza', true);

-- Spot 958: Kłokoczyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70958, 'Wisła - Kłokoczyn (Górny Przełom)', 'wisla-klokoczyn', 'RIVER', 49.9901238, 19.6400472, 'Małopolskie', 'Skawina', 'Wisła w Kłokoczynie to górny odcinek rzeki o uregulowanym charakterze, płynący w stosunkowo wąskim korycie z kamienistym dnem. Rzeka żłobi tu techniczne rynny pod progami i opaskami, które są naturalnym stanowiskiem dla kleni oraz brzan. To strategiczne miejsce dla spinningistów, którzy wykorzystują silny uciąg wody do polowania na pstrągi potokowe spływające z dopływów beskidzkich. W marcu 2026 roku woda zachowuje tu niską temperaturę i wysoką klarowność, co wymaga od wędkarza dużej dyskrecji. Wędkarze gruntowi chętnie nęcą tutejsze płanie żwirowe, licząc na brania walecznych jelców oraz dorodnych płoci. Bliskość Krakowa i surowość podgórskiego krajobrazu nadają temu łowisku specyficznego, technicznego klimatu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70958, 'Górska/Nizinna', 'Uregulowana, bystra', 80.0, 1.2, 'Kamień i żwir', 'Opaski kamienne', 'Kleń, Brzana, Pstrąg potokowy', 'Kraina pstrąga', false);

-- -- Spot 967: Tarnobrzeg (Północ)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (70967, 'Wisła - Tarnobrzeg (Północny Nurt)', 'wisla-tarnobrzeg-polnoc', 'RIVER', 50.5931615, 21.6663002, 'Podkarpackie', 'Tarnobrzeg', 'Wisła w północnej części Tarnobrzega to szerokie koryto zdominowane przez piaszczyste dno i liczne, przemieszczające się przykosy. W marcu 2026 roku odcinek ten charakteryzuje się dużymi głębokościami w torze wodnym, co przyciąga sandacze żerujące w pobliżu uskoków dna. To strategiczne miejsce dla łowców boleni, którzy polują na piaszczystych przelewach przy wysokich stanach wody. Uciąg rzeki jest tu zdecydowany, co sprzyja doskonałemu natlenieniu koryta i aktywności ryb reofilnych. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w dorodne leszcze oraz rzeczne płocie. Niska presja wędkarska na tym fragmencie pozwala na cieszenie się spokojem w otoczeniu dzikiej, nadrzecznej przyrody.', null);

