-- Spot 973: Wisła (Czarne/Malinka)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70973, 'Wisła - Wisła (Górski Ruczaj)', 'wisla-miasto-potok', 'RIVER', 49.6467009, 18.8708505, 'Śląskie', 'Wisła', 'Wisła w swoim absolutnie początkowym biegu to krystaliczny, wartki potok górski o kamienistym dnie usianym głazami. Rzeka żłobi tu głębokie rynny między skałami, które są naturalnym stanowiskiem dla walecznych pstrągów potokowych. To techniczne łowisko wymaga od wędkarza dużej precyzji w podawaniu małych przynęt pod nawisy skalne i nadrzeczne korzenie. Uciąg wody jest bardzo dynamiczny, co zapewnia doskonałe natlenienie koryta przez cały rok wędkarski 2026. Spinningiści z sukcesami obławiają tutejsze mikro-warkocze, wykorzystując małe woblery i obrotówki do polowania w prądzie. Malowniczy krajobraz Beskidów i status wód górskich czynią to miejsce wyjątkowym punktem startowym na mapie całej rzeki.', null);

