VALUES (70973, 'Górska', 'Bystry potok leśny', 5.0, 0.5, 'Kamień i głazy', 'Naturalne kaskady', 'Pstrąg potokowy, Głowacz', 'Kraina pstrąga', false);

-- Spot 974: Ustroń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70974, 'Wisła - Ustroń (Bystrza Żwirowe)', 'wisla-ustron', 'RIVER', 49.6877229, 18.837675, 'Śląskie', 'Ustroń', 'Odcinek rzeki w Ustroniu charakteryzuje się żwirowym dnem i licznymi, sztucznymi progami kamiennymi (stopniami), które regulują nurt. Poniżej każdego progu tworzą się natlenione rynny, będące bankowymi stanowiskami dla lipieni oraz kleni szukających pokarmu w prądzie. To doskonałe łowisko dla muszkarzy, którzy cenią sobie możliwość bezpiecznego brodzenia po twardym, żwirowym podłożu. Uciąg rzeki jest tu zdecydowany, co sprzyja wysokiej aktywności drapieżników polujących na drobnicę w turbulentnej wodzie. W marcu 2026 roku woda zachowuje tu niską temperaturę, co jest kluczowe dla kondycji ryb łososiowatych stacjonujących w głębszych dołkach. Łatwy dostęp do brzegów i miejska infrastruktura czynią to miejsce idealnym na techniczne sesje spinningowe.', null);

