VALUES (70974, 'Górska', 'Uregulowana, progowa', 15.0, 0.7, 'Żwir i kamień', 'Progi kamienne', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 975: Wola (Górna Wisła)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70975, 'Wisła - Wola (Płanie Żwirowe)', 'wisla-wola-slaskie', 'RIVER', 50.0078558, 19.1190628, 'Śląskie', 'Oświęcim', 'Wisła w Woli to odcinek podgórski, na którym rzeka zaczyna powoli rozszerzać swoje koryto, zachowując jednak twarde dno. Podłoże jest tu piaszczysto-żwirowe z wyraźnymi rynnami torowymi, stanowiącymi idealne żerowisko dla brzan oraz okazowych kleni. To strategiczne miejsce dla spinningistów szukających okoni czatujących w cieniu nadrzecznych wiklin i opasek kamiennych. Uciąg wody jest tu stabilny i zdecydowany, co zapewnia świetne natlenienie koryta nawet przy niskich stanach wody. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i jelce, wykorzystując systematyczne nęcenie na krawędzi nurtu głównego. W marcu 2026 roku odcinek ten jest ceniony za stabilne wyniki i brak dużej presji wędkarskiej typowej dla miast.', null);

