-- Spot 976: Hebdów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70976, 'Wisła - Hebdów (Klasztorna Burta)', 'wisla-hebdow', 'RIVER', 50.1432445, 20.4050884, 'Małopolskie', 'Nowe Brzesko', 'Odcinek w Hebdowie charakteryzuje się naturalnym biegiem koryta z głębokimi rynnami wymytymi pod wysokim, północnym brzegiem rzeki. Podłoże jest tu twarde, piaszczysto-gliniaste, usiane licznymi karczowiskami stanowiącymi bankowe ostoje dla rekordowych sumów. To strategiczne miejsce dla spinningistów polujących na sandacze, którzy wykorzystują techniczne uskoki dna toru wodnego. Uciąg rzeki w marcu 2026 roku jest tu żywy i zapewnia doskonałą kondycję ryb reofilnych żerujących w rynnach głównego nurtu. Wędkarze feederowi chętnie nęcą tutejsze płanie żwirowe, licząc na brania walecznych leszczy oraz cert wchodzących z dołu rzeki. Bliskość zabytkowego opactwa nadaje wędkowaniu w tym miejscu unikalnego, relaksującego i historycznego klimatu.', null);

