VALUES (70976, 'Nizinna', 'Naturalna, głęboka', 120.0, 2.5, 'Glina i żwir', 'Podmyte brzegi', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', true);

-- Spot 977: Wróble-Wargocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70977, 'Wisła - Wargocin (Łachy Piaszczyste)', 'wisla-wargocin', 'RIVER', 51.6282771, 21.5824838, 'Mazowieckie', 'Maciejowice', 'Wisła w Wargocinie to kwintesencja dzikiej rzeki o piaszczystym dnie i ogromnej dynamice przemieszczających się łach. Rzeka rozlewa się tutaj szeroko, tworząc liczne warkocze prądowe idealne dla boleni patrolujących krawędzie najszybszego nurtu. Podłoże jest głównie piaszczyste, z wyraźnymi krawędziami przykos, gdzie sandacze ustawiają się w marcu 2026 roku na polowanie. Spinningiści z sukcesami obławiają stoki piaszczystych przykos, stosując techniki prowadzenia przynęty w agresywnym opadzie. Wędkarze stacjonarni nęcą tutejsze płanie, celując w rekordowe leszcze migrujące głównym korytem rzeki w kierunku północnym. Dzikość brzegów porośniętych wikliną zapewnia wędkarzowi spokój oraz możliwość obserwacji nienaruszonej przyrody Doliny Środkowej Wisły.', null);

