VALUES (70977, 'Nizinna Wielka', 'Dzika, piaszczysta', 550.0, 2.0, 'Piasek', 'Przykosy, łachy', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 978: Kępa Bielańska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70978, 'Wisła - Kępa Bielańska (Archipelag)', 'wisla-kepa-bielanska', 'RIVER', 51.6650257, 21.5284229, 'Mazowieckie', 'Kozienice', 'Odcinek w Kępie Bielańskiej to kraina piaszczystych wysp i rozległych rozlewisk, gdzie Wisła dzieli się na kilka dynamicznych odnóg. Takie ukształtowanie koryta sprzyja bytowaniu ryb reofilnych, które znajdują tu obfitość pokarmu na płytkich, piaszczystych przelewach. To strategiczne miejsce dla łowców boleni, namierzających stada uklei przy turbulentnych warkoczach powstających na łukach koryta. Podłoże piaszczyste dynamicznie zmienia swój profil po wiosennych przyborach, co wymaga od wędkarza częstego sondowania głębokości łowiska. W rynnach między wyspami o twardszym dnie często stacjonują klenie, doskonale reagujące na małe przynęty spinningowe i muchowe. W marcu 2026 roku Kępa pozostaje jednym z najbardziej dzikich i technicznie ciekawych odcinków rzeki w regionie kozienickim.', null);

