-- Spot 979: Wilczkowice Górne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70979, 'Wisła - Wilczkowice Górne (Szeroka Płania)', 'wisla-wilczkowice-gorne', 'RIVER', 51.6849826, 21.4631703, 'Mazowieckie', 'Kozienice', 'Wisła w Wilczkowicach Górnych charakteryzuje się bardzo szerokim korytem i obecnością wyraźnych przykos rzecznych wychodzących daleko w nurt główny. Rzeka żłobi tu techniczne rynny na krawędzi nurtu, które są bankowymi stanowiskami dla drapieżników żerujących o świcie i zmierzchu. To strategiczne miejsce dla łowców boleni, którzy agresywnie patrolują płytkie przelewy piaszczystych łach w poszukiwaniu drobnicy. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w dorodne jazie oraz rzeczne płocie migrujące korytem Wisły. Uciąg wody jest stabilny i zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb spokojnego żeru. W marcu 2026 roku miejsce to cieszy się dużym uznaniem ze względu na stabilne wyniki i naturalny, otwarty krajobraz doliny.', null);

