VALUES (70979, 'Nizinna Wielka', 'Szeroka, piaszczysta', 700.0, 2.2, 'Piasek', 'Przykosy piaszczyste', 'Boleń, Jaź, Leszcz', 'Kraina leszcza', true);

-- Spot 980: Ostrówek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70980, 'Wisła - Ostrówek (System Głowek)', 'wisla-ostrowek', 'RIVER', 51.8676938, 21.2802711, 'Mazowieckie', 'Karczew', 'Odcinek w Ostrówku to technicznie wymagające łowisko o uregulowanych brzegach i obecności głębokich rynien przy kamiennych ostrogach (główkach). Podłoże jest tu twarde, piaszczysto-kamieniste, co przyciąga sandacze oraz duże okonie szukające schronienia przy budowlach hydrotechnicznych. To strategiczne miejsce dla spinningistów, którzy wykorzystują turbulentne warkocze prądowe do polowania na bolenie i klenie w głównym nurcie. Wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze i certy, stosując metodę feedera klasycznego na granicy głównego toru wodnego. Uciąg wody jest tu stabilny, co sprzyja systematycznemu nęczeniu i utrzymywaniu stad ryb w polu łowienia przez wiele godzin. Dobra infrastruktura i bliskość Warszawy czynią Ostrówek popularnym miejscem bezpiecznych i rybnych sesji wędkarskich w 2026 roku.', null);

