VALUES (70980, 'Nizinna Wielka', 'Uregulowana, ostrogi', 450.0, 3.5, 'Piasek i kamień', 'Główki, opaski', 'Sandacz, Boleń, Leszcz', 'Kraina leszcza', true);


-- Spot 981: Ustroń (Zawodzie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70981, 'Wisła - Ustroń (Górskie Kaskady)', 'wisla-ustron-kaskady', 'RIVER', 49.7293595, 18.8112361, 'Śląskie', 'Ustroń', 'Wisła w Ustroniu to górski odcinek o szybkim nurcie i kamienisto-żwirowym podłożu, uregulowany licznymi, sztucznymi kaskadami. Rzeka tworzy tu doskonale natlenione rynny pod progami, które są bankowymi stanowiskami dla pstrągów potokowych i dorodnych kleni. Wędkarze muchowi chętnie obławiają tutejsze bystrza, wykorzystując krystalicznie czystą wodę do precyzyjnego podawania ciężkich nimf. W marcu 2026 roku stabilne przepływy pozwalają na ostrożne brodzenie w poszukiwaniu głębszych dołków za głazami. Spinningiści z sukcesami stosują mikro-jigi, kusząc ryby reofilne ukryte w cieniu prądowym betonowych i kamiennych opasek. Górski charakter rzeki oraz bliskość beskidzkich szczytów gwarantują niezapomniane wędkarskie wrażenia w malowniczej scenerii.', null);

