-- Spot 982: Górki Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70982, 'Wisła - Górki Wielkie (Ujście Brennicy)', 'wisla-gorki-wielkie', 'RIVER', 49.7750514, 18.8140634, 'Śląskie', 'Skoczów', 'Odcinek w Górkach Wielkich zyskuje dodatkową energię i masę wody dzięki zasilaniu przez wpadającą tu rzekę Brennicę. Podłoże jest wciąż niezwykle twarde, piaszczysto-kamieniste, z licznymi wypłyceniami, na których woda gwałtownie przyspiesza. To strategiczne miejsce dla spinningistów, którzy namierzają stanowiska pstrągów i lipieni na krawędziach mieszających się nurtów obu rzek. W marcu 2026 roku niska temperatura wody wymusza szukanie ryb w najgłębszych, dwumetrowych rynnach wyżłobionych pod burtami. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, celując w rzeczne płocie oraz duże jelce. Brak gęstej zabudowy bezpośrednio nad brzegami pozwala na komfortowe, wielogodzinne sesje w kontakcie z naturą.', null);

