-- Spot 983: Wiślica (k. Skoczowa)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70983, 'Wisła - Wiślica (Płanie Podgórskie)', 'wisla-wislica', 'RIVER', 49.8179392, 18.7927151, 'Śląskie', 'Skoczów', 'Wisła w Wiślicy nabiera charakteru podgórskiego, rozlewając się nieco szerzej i tworząc długie, spokojniejsze płanie o żwirowym dnie. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach koryta, które stanowią bezpieczną ostoję dla dorodnych brzan oraz dużych kleni. To doskonałe łowisko dla spinningistów szukających okoni czatujących w cieniu nadrzecznych traw i podmytych korzeni drzew. Uciąg wody jest tu stabilny, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych przez cały sezon. Wędkarze stacjonarni z sukcesami łowią tu okazałe świnki, wykorzystując systematyczne nęcenie w rynnie głównej. Wiosną 2026 roku miejsce to słynie z bardzo dobrej widoczności w wodzie, co wymaga finezyjnego i dyskretnego podejścia.', null);

