VALUES (70983, 'Podgórska', 'Szeroka, żwirowa', 35.0, 1.4, 'Żwir i piasek', 'Podmyte burty', 'Brzana, Kleń, Świnka', 'Kraina brzany', false);

-- Spot 984: Drogomyśl
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70984, 'Wisła - Drogomyśl (Nurt Zmienny)', 'wisla-drogomysl', 'RIVER', 49.8583494, 18.7616444, 'Śląskie', 'Strumień', 'Odcinek w Drogomyślu to przedsmak rozlewisk zbiornika Goczałkowickiego, charakteryzujący się spowolnieniem nurtu i piaszczysto-mulistym dnem. Koryto rzeki tworzy tu liczne meandry i zastoiska, które są naturalnym tarliskiem i żerowiskiem dla ogromnych stad leszczy i płoci. To strategiczne miejsce dla łowców szczupaków, którzy obławiają krawędzie trzcinowisk i wypłycenia z wolniejszą wodą. Uciąg rzeki uzależniony jest od stanów wody w zbiorniku, co w marcu 2026 roku często generuje tzw. cofki. Wędkarze gruntowi z sukcesami łowią tu dorodne liny i karasie, stosując lekkie zestawy feederowe na płytkich blatach. Otoczenie stawów hodowlanych i bogata awifauna czynią ten odcinek niezwykle urokliwym i cichym.', null);

