-- Spot 985: Zabłocie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70985, 'Wisła - Zabłocie (Cofka Goczałkowic)', 'wisla-zablocie', 'RIVER', 49.9032494, 18.7561826, 'Śląskie', 'Strumień', 'Wisła w Zabłociu wpada bezpośrednio w strefę cofkową Zbiornika Goczałkowickiego, co całkowicie zmienia jej rzeczny charakter na jeziorowy. Podłoże jest tu wybitnie muliste, bogate w naturalny pokarm, przyciągający rekordowe karpie, amury i stada potężnych leszczy. To doskonałe łowisko dla spinningistów polujących na sandacze, którzy szukają drapieżników na uskokach starego koryta rzeki pod wodą. Uciąg wody jest tu znikomy, a głębokość rośnie łagodnie w stronę głównej misy zbiornika. W marcu 2026 roku płytkie wody cofki nagrzewają się jako pierwsze, wybudzając ryby spokojnego żeru z zimowego letargu. Przestrzeń i rozległe rozlewiska sprawiają, że jest to jedno z najważniejszych łowisk gruntowych na południu Polski.', null);

