-- Spot 986: Wrzawy (Ujście Sanu)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70986, 'Wisła - Wrzawy (Węzeł Ujściowy Sanu)', 'wisla-wrzawy-ujscie-sanu', 'RIVER', 50.6918048, 21.8210567, 'Podkarpackie', 'Gorzyce', 'Węzeł hydrologiczny we Wrzawach, gdzie San łączy się z Wisłą, to jedno z najbardziej legendarnych łowisk w całym kraju. Mieszanie się potężnych mas wody o różnej termice i mętności tworzy spektakularne warkocze prądowe i gigantyczne rynny do 8 metrów głębokości. To absolutnie strategiczne miejsce dla łowców największych sumów, które stacjonują na styku nurtów, czekając na ogłuszoną drobnicę. Spinningiści z sukcesami obławiają piaszczyste przykosy ujściowe, polując na agresywne bolenie oraz stada dorodnych sandaczy. Wędkarze stacjonarni zmagają się tu z potężnym uciągiem, stosując najcięższe koszyki zanętowe w poszukiwaniu wielkich brzan. Wiosną 2026 roku dynamika tego łowiska nie ma sobie równych, a woda ta potrafi wynagrodzić wytrwałość rybą życia.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70986, 'Nizinna Wielka', 'Ujściowa, bardzo szeroka', 600.0, 5.5, 'Piasek i glina', 'Warkocz ujściowy, głębiny', 'Sum, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 987: Pniów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70987, 'Wisła - Pniów (Piaszczyste Morze)', 'wisla-pniow', 'RIVER', 50.7351457, 21.8421381, 'Podkarpackie', 'Radomyśl nad Sanem', 'Zasilana wodami Sanu, Wisła w Pniowie rozlewa się niezwykle szeroko, niosąc tysiące ton wędrującego po dnie piasku. Koryto rzeki tworzy tu ogromne przykosy i łachy, które z każdym sezonem zmieniają swój profil, zmuszając do ciągłego sondowania łowiska. To doskonałe miejsce dla łowców boleni, którzy w marcu 2026 roku wypatrują widowiskowych ataków drapieżników na płyciznach. Wędkarze gruntowi nęcą tutejsze rozległe płanie, licząc na brania leszczy i cert schodzących powoli w dół rzeki. Spinningiści namierzają stoki przykos, szukając uskoków dna, przy których lubią stacjonować średnie i duże sandacze. Rozmach krajobrazu i ogromna, otwarta przestrzeń potęgują poczucie obcowania z rzeką o nieujarzmionej naturze.', null);

