VALUES (70987, 'Nizinna Wielka', 'Wielonurtowa, piaszczysta', 700.0, 2.2, 'Piasek', 'Wędrujące przykosy', 'Boleń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 988: Chwałowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70988, 'Wisła - Chwałowice (Rynny pod Borem)', 'wisla-chwalowice', 'RIVER', 50.7828578, 21.8600629, 'Podkarpackie', 'Radomyśl nad Sanem', 'Wisła w Chwałowicach płynie szerokim, ale wysoce urozmaiconym korytem, gdzie szybki nurt głównego toru wodnego miesza się ze spokojnymi zatokami. Dno jest tu gliniasto-piaszczyste, a rzeka wymywa pod stromymi brzegami techniczne, głębokie na ponad 3 metry rynny erozyjne. To strategiczne łowisko dla gruntowców specjalizujących się w połowie okazałych brzan, które upodobały sobie ten twardy fragment dna. Spinningiści chętnie obławiają zatopione konary i karczowiska, z których co sezon padają rekordowe wręcz szczupaki i sandacze. Uciąg wody w marcu 2026 roku jest tu bardzo silny, co wymaga użycia ciężkich zestawów i grubych plecionek dla bezpieczeństwa holu. Wysokie, dzikie brzegi skutecznie izolują wędkarza od wiatru, czyniąc to miejsce doskonałym wyborem na wczesnowiosenne zasiadki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70988, 'Nizinna Wielka', 'Naturalna, głęboka rynna', 650.0, 3.5, 'Glina i piasek', 'Zatopione pnie, burty', 'Brzana, Sandacz, Szczupak', 'Kraina leszcza', true);

-- Spot 989: Zabełcze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70989, 'Wisła - Zabełcze (Opaski Annopolskie)', 'wisla-zabelcze', 'RIVER', 50.8295362, 21.8551477, 'Świętokrzyskie', 'Annopol', 'Odcinek w Zabełczu to początek słynnego Przełomu Wisły, gdzie rzeka napotyka na twarde formacje wapienne i uregulowane opaski brzegowe. Koryto ulega tu zawężeniu, a woda nabiera ogromnej dynamiki, żłobiąc techniczne rynny przy kamienistych i betonowych wzmocnieniach brzegów. To wymarzone miejsce dla łowców nocnych sandaczy, którzy woblery prowadzą tuż przy powierzchni wody na napływach opasek. Wędkarze gruntowi z sukcesami łowią tu duże certy i jazie, stosując długie przypony i precyzyjne podawanie koszyka w warkocz prądowy. Podłoże jest twarde, piaszczysto-kamieniste, co gwarantuje świetne warunki tlenowe rybom reofilnym przez cały marzec 2026 roku. Surowość rzeki i potężny uciąg sprawiają, że łowienie w tym rejonie wymaga doskonałego czytania wody i pewnego sprzętu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70989, 'Nizinna Wielka', 'Zawężona, uregulowana', 500.0, 4.0, 'Opoka, kamień', 'Opaski kamienne', 'Sandacz, Certa, Jaź', 'Kraina leszcza', true);

-- Spot 990: Dolany
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70990, 'Wisła - Dolany (Rozlewiska Nizinne)', 'wisla-dolany', 'RIVER', 50.1383947, 20.4754831, 'Małopolskie', 'Bochnia', 'Wisła w Dolanach, poniżej Nowego Brzeska, powraca do swojego nizinnego charakteru, tworząc płytkie piaszczyste blaty i głębsze rynny w zakolach. Podłoże rzeki charakteryzuje się tu stabilnym, piaszczysto-gliniastym dnem z licznymi kępami podwodnej roślinności w przybrzeżnych spowolnieniach nurtu. To doskonałe łowisko dla pasjonatów method feeder i wędkarzy spławikowych, którzy z powodzeniem nęcą ogromne stada rzecznych leszczy i krąpi. Spinningiści patrolują zarośnięte burty, wypatrując aktywności szczupaków oraz okoni żerujących na wylęgu w nagrzewającej się, płytkiej wodzie. W marcu 2026 roku uciąg jest tu łagodny i przewidywalny, co umożliwia niezwykle precyzyjne wędkowanie i czerpanie pełnej radości z finezyjnych brań. Niska presja ze strony wędkarzy i malowniczy, wiejski krajobraz tworzą tu absolutną wędkarską idyllę.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (70990, 'Nizinna', 'Szeroka, spokojna', 150.0, 1.8, 'Piasek i glina', 'Zastoiska, zakola', 'Leszcz, Krąp, Szczupak', 'Kraina leszcza', true);

-- Spot 991: Gdańsk (Martwa Wisła/Przekop)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70991, 'Wisła - Gdańsk (Początek Przekopu)', 'wisla-gdansk-przekop-start', 'RIVER', 54.3074382, 18.9336736, 'Pomorskie', 'Gdańsk', 'Początkowy odcinek Przekopu Wisły w Gdańsku to gigantyczny inżynieryjny kanał zrzutowy, który bezpośrednio kieruje potężne wody rzeki ku morzu. Koryto ma tu uregulowany, niemal geometryczny charakter z betonowo-kamiennymi opaskami na obu brzegach i twardym, piaszczystym dnem głębokiego toru. To strategiczne miejsce dla wędkarzy łodziowych i brzegowych łowców troci wędrownej, która podąża tędy z Bałtyku na swoje naturalne tarliska. Wiosną 2026 roku regularnie łowi się tu okazałe sandacze i ogromne okonie, używając ciężkich jigów do przebicia się przez głęboką rynnę. Uciąg jest potężny, całkowicie zależny od naporu masy wody śródlądowej, co stawia przed wędkarzami wysokie wymagania sprzętowe i techniczne. Surowy, industrialno-morski klimat czyni to miejsce mekką dla poszukiwaczy trofealnych ryb drapieżnych i anadromicznych.', null);

