VALUES (70991, 'Ujściowa', 'Kanał sztuczny, opaski', 400.0, 6.0, 'Twardy piasek i beton', 'Regulowane brzegi', 'Troć wędrowna, Sandacz, Okoń', 'Kraina sandacza', true);

-- Spot 992: Gdańsk (Mewia Łacha)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70992, 'Wisła - Gdańsk (Ujście do Bałtyku)', 'wisla-gdansk-ujscie-morze', 'RIVER', 54.3533112, 18.9475861, 'Pomorskie', 'Gdańsk', 'Ujście Przekopu Wisły do Zatoki Gdańskiej to niezwykły ekosystem, gdzie słodka woda śródlądowa gwałtownie miesza się ze słonymi wodami Bałtyku. Tworzą się tu ogromne, ruchome łachy piaszczyste oraz głębokie rynny wyrzeźbione przez falowanie i zderzenia potężnych prądów wodnych. To absolutnie elitarne łowisko spinningowe i muchowe, zdominowane przez srebro, czyli troć wędrowną i łososia wchodzące na wiosenne żerowanie i ciągi. W marcu 2026 roku stada morskich śledzi i szprotów przyciągają w te okolice nie tylko wielkie drapieżniki, ale i populacje rzecznych okoni i sandaczy. Wędkarze surfcastingowi i gruntowi celują tu w okazałe stornie oraz płastugi, wykorzystując mieszany charakter tego akwenu. Wędkowanie z falochronów i piaszczystych cypli rezerwatu Mewia Łacha dostarcza morskich emocji i szans na złowienie życiowego okazu.', null);

