VALUES (70992, 'Estuarium', 'Morskie ujście, falochrony', 500.0, 7.5, 'Piasek morski', 'Falochrony, łachy', 'Troć wędrowna, Sandacz, Flądra', 'Strefa przymorska', true);

-- Spot 993: Warszawa (Bielany / Tarchomin)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70993, 'Wisła - Warszawa (Tarchomińska Głębia)', 'wisla-warszawa-tarchomin', 'RIVER', 52.3404033, 20.9249686, 'Mazowieckie', 'Warszawa', 'Odcinek Wisły między Bielanami a Tarchominem charakteryzuje się bardzo szerokim korytem, przeplatanym potężnymi wyspami zalesionymi gęstą wikliną. Dno stanowi tu zmienną mozaikę piaszczystych przykos i głębokich na kilka metrów rynien erozyjnych uformowanych wzdłuż brzegowych umocnień. Jest to znakomity teren dla miejskich łowców sandaczy i sumów, którzy wykorzystują ciężki opad w dołkach wymytych poniżej dawnych główek. Wędkarze gruntowi regularnie nęcą rozległe warkocze, by ściągnąć stada wędrujących w marcu 2026 roku płoci, leszczy oraz krąpi. Płytkie, nagrzewające się piaszczyste blaty to rewir widowiskowych ataków boleni rzucających się na drobnicę w promieniach zachodzącego słońca. Łowisko to łączy w sobie surową dzikość wielkiej rzeki ze świetnym dojazdem komunikacją miejską z samego serca Warszawy.', null);

