VALUES (70993, 'Nizinna Wielka', 'Szeroka, wyspowa', 550.0, 3.5, 'Piasek i kamień', 'Wyspy, zatarte główki', 'Sandacz, Boleń, Sum', 'Kraina leszcza', true);

-- Spot 994: Kępa Kiełpińska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70994, 'Wisła - Kępa Kiełpińska (Mazowieckie Rozlewiska)', 'wisla-kepa-kielpinska', 'RIVER', 52.3788178, 20.8858542, 'Mazowieckie', 'Łomianki', 'Tuż za północną granicą Warszawy, w okolicach Kępy Kiełpińskiej, Wisła gwałtownie uwalnia się od miejskich regulacji, przechodząc w stan niemal pierwotny. Rzeka toczy tu swoje wody niezwykle szeroko, odsłaniając niezliczone, przesuwające się łachy piaszczyste, zarośnięte wyspy i skryte starorzecza. To absolutny raj dla spinningistów uganiających się za brzanami oraz wielkimi jaziami, które upodobały sobie bystrza na krawędzi piaszczystych rynien. Wiosną 2026 roku wędkarze stacjonarni odnajdują tu niezapomniane płanie, na których długie przypony z białą rybą w tle pracują niemal bezbłędnie. Zmienność uciągu oraz struktury dna wymusza niezwykłą czujność, a każdy powrót nad wodę potrafi ukazać rzekę w zupełnie nowym, zmienionym kształcie. Brak gęstej zabudowy i chroniona przyroda czynią to łowisko wymarzoną odskocznią dla poszukujących absolutnej wędkarskiej izolacji.', null);

