VALUES (70994, 'Nizinna Wielka', 'Dzika, naturalna', 650.0, 2.0, 'Piasek', 'Rozległe przykosy', 'Brzana, Jaź, Boleń', 'Kraina leszcza', true);

-- Spot 995: Pieńków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70995, 'Wisła - Pieńków (Wyspy i Kępy)', 'wisla-pienkow', 'RIVER', 52.3866898, 20.8093636, 'Mazowieckie', 'Łomianki', 'Wisła w Pieńkowie to klasyczny odcinek dzikiej rzeki z licznymi wyspami i dynamicznie zmieniającymi się piaszczystymi przykosami. Podłoże jest tu zmienne, piaszczysto-żwirowe, co sprzyja bytowaniu dorodnych kleni i jazi żerujących na płytkich przelewach. To strategiczne miejsce dla łowców boleni, które w marcu 2026 roku agresywnie atakują drobnicę przy turbulentnych warkoczach. W rynnach głównego nurtu o twardszym dnie często stacjonują sandacze, doskonale reagujące na woblery sprowadzane w strefę denną. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze migrujące głównym korytem. Bliskość Warszawy, przy jednoczesnym zachowaniu naturalnego charakteru brzegów, czyni to miejsce bardzo popularnym na weekendowe sesje.', null);

