-- Spot 996: Czosnów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70996, 'Wisła - Czosnów (Dzikie Łachy)', 'wisla-czosnow', 'RIVER', 52.406579, 20.7380055, 'Mazowieckie', 'Nowy Dwór Mazowiecki', 'Odcinek w Czosnowie charakteryzuje się bardzo szerokim, wielonurtowym korytem z ogromną masą wędrującego po dnie piasku. Rzeka żłobi tu techniczne rynny na krawędzi łach, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To doskonałe łowisko dla spinningistów polujących na bolenie, wykorzystujących płytkie blaty jako tło do prowadzenia przynęt powierzchniowych. Podłoże piaszczyste z pojedynczymi, twardszymi uskokami stanowi idealne żerowisko dla stad rzecznych płoci oraz okazowych cert. Uciąg wody jest tu żywy i przewidywalny, co pozwala na precyzyjne nęcenie przy użyciu techniki feedera klasycznego. Wiosną 2026 roku warto szukać tu cieplejszych zastoisk, w których jako pierwsze budzą się ryby spokojnego żeru.', null);

