-- Spot 997: Brwilno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70997, 'Wisła - Brwilno (Początek Zalewu)', 'wisla-brwilno', 'RIVER', 52.5673206, 19.5589911, 'Mazowieckie', 'Płock', 'Wisła w Brwilnie to strefa przejściowa, gdzie rzeka wyhamowuje swój bieg, wchodząc w obszar cofki Zbiornika Włocławskiego. Koryto staje się tu znacznie głębsze, a podłoże zmienia charakter na piaszczysto-muliste z wyraźnymi stokami starego toru wodnego. To strategiczne miejsce dla łowców sandaczy, którzy wykorzystują echosondy do namierzania drapieżników ustawionych na krawędzi głębi. Wędkarze stacjonarni z sukcesami łowią tu potężne leszcze, stosując zanęty o grubej frakcji na łagodnie opadających blatach. Spowolniony uciąg wody pozwala na stosowanie lżejszych zestawów gruntowych, co w marcu 2026 roku ułatwia sygnalizację delikatnych brań. Zróżnicowana linia brzegowa z kępami roślinności zapewnia doskonałe stanowiska dla wędkarzy szukających izolacji i spokoju.', null);

