-- Spot 998: Rokicie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70998, 'Wisła - Rokicie (Zatopione Koryto)', 'wisla-rokicie', 'RIVER', 52.6023954, 19.4546935, 'Mazowieckie', 'Płock', 'Odcinek w Rokiciu posiada już pełny charakter jeziorowo-zbiornikowy z rozległą powierzchnią wody i głębokościami przekraczającymi kilka metrów. Podłoże pokrywa tu warstwa żyznego mułu, pod którą kryje się twarde, piaszczysto-gliniaste dno dawnego koryta Wisły. To wymarzone łowisko dla wędkarzy łodziowych szukających rekordowych sumów, które w 2026 roku stacjonują w najgłębszych partiach zalewu. Spinningiści chętnie obławiają zatopione struktury i dawne opaski, celując w potężne szczupaki i grube okonie. Wędkarze feederowi operujący z brzegu muszą korzystać z bardzo dalekich rzutów, aby osiągnąć stoki starego koryta rzeki. Ze względu na dużą powierzchnię wody, łowienie tutaj wymaga ciągłego monitorowania siły i kierunku wiatru, który potrafi stworzyć morską falę.', null);

