-- Spot 999: Dąb Wielki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (70999, 'Wisła - Dąb Wielki (Stoki Zbiornika)', 'wisla-dab-wielki', 'RIVER', 52.6236782, 19.382249, 'Kujawsko-Pomorskie', 'Włocławek', 'Wisła w Dębie Wielkim to potężny akwen Zbiornika Włocławskiego, gdzie szerokość lustra wody zmusza do korzystania z jednostek pływających. Dno jest tu mocno zróżnicowane, oferując płytkie blaty muliste oraz gwałtowne uskoki prowadzące do zatopionego, twardego koryta. To strategiczne łowisko sandaczowe, na którym kluczem do sukcesu jest precyzyjne prowadzenie przynęt silikonowych techniką wertykalną wzdłuż uskoków. Stacjonarni łowcy karpi i amurów z sukcesami nęcą tutejsze płytsze zatoki, wykorzystując naturalne ocieplanie się wody wczesną wiosną. Znikomy uciąg wody sprawia, że metody gruntowe nie wymagają ciężkich koszyków, a jedynie precyzji w lokowaniu zestawu na odpowiedniej głębokości. W marcu 2026 roku to miejsce stanowi arenę zmagań dla poszukiwaczy trofealnych ryb, gotowych na wielogodzinne biczowanie wody.', null);

