-- Spot 1000: Dobiegniewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71000, 'Wisła - Dobiegniewo (Głęboczki)', 'wisla-dobiegniewo', 'RIVER', 52.6255999, 19.3074707, 'Kujawsko-Pomorskie', 'Włocławek', 'Łowisko w Dobiegniewie zlokalizowane jest w środkowej, niezwykle szerokiej części Zbiornika Włocławskiego o charakterze wyraźnie jeziorowym. Stoki zatopionego koryta Wisły są tu bardzo strome, co tworzy idealne warunki dla sandaczy patrolujących twarde, piaszczysto-gliniaste krawędzie. To doskonałe miejsce dla wędkarzy łowiących z łodzi, którzy dysponują sprzętem sonarowym do analizy twardości dna i namierzania stad białorybu. Brzegowi wędkarze feederowi z powodzeniem łowią tu ogromne leszcze i krąpie, sypiąc duże ilości gliny i robactwa na stokach. Wczesną wiosną 2026 roku ogromne znaczenie ma tu wiatr, który potrafi napędzić cieplejszą wodę powierzchniową do wybranych zatok, aktywizując ryby. Dzika, często zalesiona linia brzegowa oferuje wiele osłoniętych stanowisk, gwarantujących wielodniowe, spokojne zasiadki.', null);

