-- Spot 1001: Wistka Królewska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71001, 'Wisła - Wistka Królewska (Zatoki)', 'wisla-wistka-krolewska', 'RIVER', 52.6422035, 19.2347656, 'Kujawsko-Pomorskie', 'Włocławek', 'Odcinek w Wistce Królewskiej oferuje głęboką, spokojną wodę z licznymi zatokami i wypłyceniami bogatymi w zatopione pnie drzew. Podłoże muliste na blatach płynnie przechodzi w twardą, rzeczną glinę na krawędzi dawnego koryta, oddalonego znacznie od brzegu. To znakomite terytorium dla łowców gigantycznych sumów, którzy w 2026 roku zakładają tu stacjonarne obozy z zestawami wywożonymi pontonem na głębię. Spinningiści z sukcesami penetrują strefy przybrzeżne w poszukiwaniu szczupaków, które ustawiają się przy krawędzi zeszłorocznych trzcinowisk. Uciąg jest niemal zerowy, co pozwala na stosowanie klasycznych, lekkich wędzisk spławikowych przy brzegowym połowie dorodnych płoci i wzdręg. Rozległa perspektywa wodna i stabilność rybostanu czynią ten rejon jednym z najchętniej odwiedzanych fragmentów Kujawskiego Morza.', null);

