-- Spot 1002: Włocławek (Przed Zaporą)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71002, 'Wisła - Włocławek (Zapora Górna)', 'wisla-wloclawek-zbiornik', 'RIVER', 52.6566468, 19.1603896, 'Kujawsko-Pomorskie', 'Włocławek', 'Łowisko zlokalizowane tuż powyżej tamy we Włocławku to najgłębsza część całego zbiornika zaporowego, o profilu całkowicie stojącym. Twarde, wymyte dno w pobliżu betonowych konstrukcji oporowych szybko opada na kilkanaście metrów, tworząc schronienie dla największych drapieżników rzeki. To strategiczny punkt dla zaawansowanych łowców sandaczy i sumów, łowiących ciężko w pionie z łodzi w bezpośrednim sąsiedztwie zapory. Wędkarze gruntowi muszą mierzyć się tu ze specyficznymi prądami pionowymi i zwrotnymi, wymuszającymi stosowanie dociążonych i stabilnych zestawów. W marcu 2026 roku woda w tej strefie nagrzewa się wolniej, co wymusza poszukiwanie ryb w najgłębszych, stabilnych termicznie partiach zbiornika. Bliskość monumentalnej architektury hydrotechnicznej nadaje tej lokalizacji niezwykle industrialny i surowy, techniczny klimat.', null);

