VALUES (71002, 'Nizinna Wielka', 'Zbiornik zaporowy, głęboki', 1200.0, 11.0, 'Piasek i beton', 'Zapora, umocnienia', 'Sandacz, Sum, Leszcz', 'Kraina leszcza', true);

-- Spot 1003: Włocławek (Poniżej Zapory)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71003, 'Wisła - Włocławek (Zrzut Wody)', 'wisla-wloclawek-rzeka', 'RIVER', 52.6601141, 19.0846984, 'Kujawsko-Pomorskie', 'Włocławek', 'Wisła tuż poniżej tamy we Włocławku to absolutnie ekstremalne łowisko, gdzie potężne zrzuty wody generują ryczący, wysokotlenowy nurt. Zjawisko erozji dennej całkowicie wypłukało tu piasek, pozostawiając twarde, kamienisto-betonowe podłoże z wyrwami przekraczającymi osiem metrów głębokości. To elitarne stanowisko dla wędkarzy polujących na rzeczne potwory, w tym rekordowe sumy i ogromne bolenie atakujące w warkoczach turbin. Spinningiści muszą stosować najcięższe dostępne jigi oraz woblery stawiające mały opór, by w ogóle sprowadzić przynętę w strefę żerowania ryb. Wędkarze stacjonarni zmagają się tu z niszczycielską siłą wody, która jest jednak magnesem dla największych wiślanych brzan i kleni w 2026 roku. Ostrożność i najwyższej jakości sprzęt są tu bezwzględnie wymagane, gdyż każdy błąd może skutkować natychmiastową stratą zestawu lub ryby.', null);

