-- Spot 1004: Łęg-Witoszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71004, 'Wisła - Łęg-Witoszyn (Kamieniste Rynny)', 'wisla-leg-witoszyn', 'RIVER', 52.6884539, 19.0251794, 'Kujawsko-Pomorskie', 'Włocławek', 'Odcinek w Łęgu-Witoszynie to strefa silnej erozji wgłębnej, w której Wisła mozolnie odbudowuje swoje piaszczyste koryto po opuszczeniu tamy. Dno pozostaje tu wciąż wyjątkowo twarde, złożone ze żwiru, gliny i wymytych kamieni, oferując znakomite warunki tlenowe dla ryb reofilnych. To strategiczne terytorium dla łowców brzan, które w marcu 2026 roku masowo gromadzą się w głębokich na cztery metry, szybkich rynnach torowych. Spinningiści z sukcesami prowadzą tu ciężkie przynęty gumowe, wyłuskując grube sandacze czatujące za rzadkimi, twardymi uskokami dna. Wędkarze klasycznego feedera używają koszyków z pazurami, by powstrzymać znoszenie zestawu przez nieustępliwy, silny nurt środka rzeki. Okolica zachwyca surowością i potęgą odradzającej się, dzikiej Wisły, stanowiąc wyzwanie dla najbardziej doświadczonych rzecznych wyjadaczy.', null);

