-- Spot 1005: Stary Bógpomóż
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71005, 'Wisła - Stary Bógpomóż (Odzyskany Nurt)', 'wisla-stary-bogpomoz', 'RIVER', 52.7301044, 18.985624, 'Kujawsko-Pomorskie', 'Nieszawa', 'Wisła w rejonie miejscowości Stary Bógpomóż powraca do swojej dzikiej, roztokowej natury z ogromnymi, wędrującymi przykosami piaszczystymi. Rzeka niesie tu tysiące ton piasku, tworząc płytkie przelewy i dynamiczne warkocze, za którymi woda gwałtownie zapada się w mroczne rynny. To doskonałe miejsce dla łowców boleni, którzy mogą liczyć na widowiskowe, powierzchniowe ataki drapieżników na płyciznach obfitujących w ukleje. Podłoże składa się z piasku przemieszanego z łachami żwiru, co sprzyja tarłu i bytowaniu dorodnych jazi oraz kleni wczesną wiosną. Wędkarze stacjonarni świetnie radzą sobie na stokach przykos, gdzie systematyczne nęcenie w 2026 roku owocuje regularnymi braniami grubych płoci. Cicha, wiejska okolica oraz dzikie, piaszczyste wyspy tworzą tu krajobraz idealny na długie, odcięte od cywilizacji wyprawy wędkarskie.', null);

