-- Spot 1006: Bobrowniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71006, 'Wisła - Bobrowniki (Ruiny i Opaski)', 'wisla-bobrowniki', 'RIVER', 52.7704481, 18.9528119, 'Kujawsko-Pomorskie', 'Nieszawa', 'Łowisko w Bobrownikach charakteryzuje się podwyższonym, historycznym brzegiem z ruinami zamku i silnym uciągiem wody przyczepionym do burt. Podłoże jest tu twarde, gliniasto-kamieniste, nierzadko usiane pozostałościami starych opasek, co kreuje perfekcyjne kryjówki dla dużych drapieżników. To strategiczny rejon dla spinningistów łowiących z brzegu, którzy poszukują szczupaków i sandaczy w cieniach prądowych za zwalonymi do wody drzewami. Wędkarze gruntowi z powodzeniem obławiają wymyte, pięciometrowe rynny u stóp skarpy, polując na wąsate sumy i piękne, wiślane brzany. Uciąg rzeki w marcu 2026 roku jest tu zdecydowany i stały, świetnie natleniając wodę i zapewniając rybom doskonałą kondycję po trudach zimy. Kulturalno-historyczny aspekt tego miejsca, połączony z technicznym, głębokim korytem, czyni Bobrowniki łowiskiem absolutnie niepowtarzalnym.', null);

