-- Spot 1007: Przypust
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71007, 'Wisła - Przypust (Warkocze Prądowe)', 'wisla-przypust', 'RIVER', 52.8187904, 18.9121013, 'Kujawsko-Pomorskie', 'Nieszawa', 'Wisła w Przypuście to klasyczny odcinek nizinny, gdzie koryto ujęto w długi i stary system kamiennych główek oraz opasek brzegowych. Pomiędzy ostrogami uformowały się piaszczyste, spokojne klatki, podczas gdy na szczytach budowli woda gwałtownie przyspiesza, rozbijając się o kamienie. To wymarzone miejsce dla uniwersalnych wędkarzy spinningowych, mogących jednego dnia łowić tuż pod powierzchnią bolenie, a w głębokim opadzie sandacze. Fani klasycznego feedera i spławika znajdują tu eldorado wśród stad cert, leszczy oraz krąpi grupujących się w osłoniętych zatokach. Wiosną 2026 roku odcinek ten wyjątkowo szybko budzi się do życia, co owocuje agresywnymi braniami białorybu na mocno aromatyzowane przynęty. Stabilność układu koryta i łatwy dojazd brzegiem sprawiają, że Przypust jest niezwykle pewnym i przewidywalnym łowiskiem na mapie Dolnej Wisły.', null);

