-- Spot 1008: Piekło
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71008, 'Wisła - Piekło (Dolne Główki)', 'wisla-pieklo', 'RIVER', 53.9282744, 18.8613766, 'Pomorskie', 'Sztum', 'Wisła w rejonie miejscowości Piekło to potężna, nizinna arteria o uregulowanych brzegach i klasycznym układzie głębokich klatek między ostrogami. Dno jest tu twarde, piaszczysto-kamieniste, co w połączeniu z silnym uciągiem tworzy doskonałe warunki dla ryb reofilnych. To strategiczne miejsce dla łowców sandaczy, którzy w marcu 2026 roku z sukcesami obławiają stoki rynien wyżłobionych na szczytach główek. Wędkarze stacjonarni wykorzystują spokojniejszą wodę wewnątrz klatek, nęcąc stada okazałych leszczy i krąpi schodzących w stronę delty. Potężna siła nurtu wymaga stosowania ciężkich zestawów gruntowych z koszykami wyposażonymi w metalowe wąsy zapobiegające znoszeniu. Surowy krajobraz Dolnej Wisły i duża przestrzeń gwarantują komfortowe łowienie nawet podczas weekendowego oblężenia brzegów.', null);

