-- Spot 1009: Cygany
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71009, 'Wisła - Cygany (Rozmyte Opaski)', 'wisla-cygany', 'RIVER', 53.9748606, 18.8648765, 'Pomorskie', 'Kwidzyn', 'Odcinek w Cyganach charakteryzuje się rozległymi systemami starych opasek i ostróg, które na przestrzeni lat uległy częściowemu rozmyciu. Rzeka wymyła tu głębokie warkocze prądowe, odsłaniając twarde, żwirowo-gliniaste podłoże idealne dla drapieżników. Spinningiści z uwagą obławiają te techniczne spowolnienia, szukając dużych szczupaków oraz wczesnowiosennych boleni. Wędkarze łowiący z gruntu celują w rzeczne certy, które w marcu grupują się w osłoniętych przed najsilniejszym nurtem rynnach brzegowych. Ze względu na wahania poziomu wody, kluczowe jest tu precyzyjne namierzenie krawędzi, na której twarde dno przechodzi w miękki piasek. Brak gęstej zabudowy i dzikość nadrzecznych łęgów nadają temu miejscu unikalny, odizolowany charakter.', null);

