-- Spot 1010: Mątowy Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71010, 'Wisła - Mątowy Wielkie (Wrota Żuław)', 'wisla-matowy-wielkie', 'RIVER', 54.0190141, 18.8368738, 'Pomorskie', 'Miłoradz', 'Wisła w Mątowach Wielkich wkracza w obszar Żuław, zachowując jednak swój potężny, uregulowany ostrogami charakter. Koryto rzeki jest tu niezwykle szerokie, a głębokość w torze wodnym regularnie przekracza cztery metry. Jest to wymarzone łowisko dla łowców sumów, którzy w 2026 roku wykorzystują najgłębsze rynny jako miejsca wywózki ciężkich zestawów. Spinningiści z sukcesami polują tu na sandacze, stosując technikę ciężkiego opadu w strefach styku szybkiej i wolnej wody. Wędkarze feederowi z powodzeniem łowią dorodne płocie, nęcąc precyzyjnie na krawędziach piaszczystych blatów wewnątrz klatek. Potęga rzeki w tym rejonie zmusza do używania sprzętu najwyższej klasy, zdolnego wytrzymać walkę z trofealnym okazem w silnym nurcie.', null);

