-- Spot 1011: Bałdowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71011, 'Wisła - Bałdowo (Rynny Torowe)', 'wisla-baldowo', 'RIVER', 54.0645981, 18.8152653, 'Pomorskie', 'Tczew', 'Łowisko w Bałdowie to klasyczny odcinek dolnej Wisły o stabilnym uciągu i wyraźnie zaznaczonych, głębokich rynnach torowych. Podłoże stanowi tu mieszanka twardego piasku i kamieni naniesionych wokół historycznych wzmocnień brzegowych. To doskonałe miejsce dla spinningistów, którzy namierzają wiosenne sandacze na stromych stokach wyżłobionych przez główny nurt. W marcu 2026 roku rosnąca temperatura wody aktywizuje tu ogromne stada leszczy, doskonale reagujące na method feeder z użyciem peletów. Uciąg na środku rzeki jest bezlitosny, dlatego stacjonarne łowienie skupia się głównie w strefach przybrzeżnych i rozległych zatokach. Bliskość Tczewa zapewnia świetny dojazd, czyniąc Bałdowo niezwykle popularnym miejscem treningowym dla pomorskich wędkarzy.', null);

