-- Spot 1012: Dąbrowa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71012, 'Wisła - Dąbrowa (Wymyte Burty)', 'wisla-dabrowa-pomorskie', 'RIVER', 54.110109, 18.8187674, 'Pomorskie', 'Tczew', 'Odcinek w Dąbrowie charakteryzuje się ogromną dynamiką wód, wymywających pod wysokimi brzegami nawet sześciometrowe głębie. Dno jest tu zróżnicowane, piaszczysto-gliniaste, z licznymi karczowiskami zatopionymi podczas wyższych stanów rzeki. Takie techniczne struktury to bankowe stanowiska dla łowców okazowych sumów oraz grubych, rzecznych szczupaków. Spinningiści chętnie wykorzystują warkocze prądowe przy ostrogach, rzucając woblerami w poszukiwaniu boleni i kleni. Wędkarze gruntowi muszą mierzyć się z dużą siłą uciągu, co wymaga stosowania ciężkich, rzecznych koszyków zanętowych. Malownicze położenie i ogromny potencjał łowiska sprawiają, że to jedno z najciekawszych miejsc na mapie Dolnej Wisły.', null);

