VALUES (71012, 'Nizinna Wielka', 'Głęboka rynna brzegowa', 480.0, 6.0, 'Glina i piasek', 'Zatopione drzewa, opaski', 'Sum, Szczupak, Boleń', 'Kraina leszcza', true);

-- Spot 1013: Koźliny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71013, 'Wisła - Koźliny (Żuławskie Zatoki)', 'wisla-kozliny', 'RIVER', 54.156714, 18.8377082, 'Pomorskie', 'Suchy Dąb', 'Wisła w rejonie Koźlin to potężna, nizinna woda o piaszczystym korycie poprzecinanym systemami długich główek. Wewnątrz rozległych klatek tworzą się spokojne zatoki z mulisto-piaszczystym dnem, idealne dla ryb spokojnego żeru. Wiosną 2026 roku te nagrzewające się płycizny przyciągają stada jazi i płoci, stanowiąc doskonały cel dla wędkarzy spławikowych. Na szczytach główek i w głównym nurcie królują spinningiści, obławiający stoki rynien w poszukiwaniu sandaczy. Stabilny przepływ wody pozwala na wypracowanie skutecznej strategii nęcenia, utrzymującej białoryb w łowisku przez długie godziny. Otwarty krajobraz Żuław i silne wiatry wymagają odpowiedniego ubioru, ale wędkarskie wyniki często wynagradzają ten trud.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71013, 'Nizinna Wielka', 'Szeroka, zatoki', 600.0, 3.5, 'Piasek i muł', 'Główki, klatki', 'Jaź, Płoć, Sandacz', 'Kraina leszcza', true);

-- Spot 1014: Gniazdowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71014, 'Wisła - Gniazdowo (Strefa Przedujściowa)', 'wisla-gniazdowo', 'RIVER', 54.1989804, 18.8999386, 'Pomorskie', 'Cedry Wielkie', 'Łowisko w Gniazdowie to obszar, gdzie Wisła zbliża się do swojego ujściowego charakteru, niosąc potężne masy wody w szerokim korycie. Dominują tu twarde, piaszczysto-żwirowe blaty oraz strome uskoki na krawędzi nawigacyjnego toru wodnego. To strategiczny punkt dla spinningistów polujących na trocie wędrowne, które w marcu rozpoczynają tu swoje wędrówki. Wędkarze gruntowi z powodzeniem łowią okazałe certy i leszcze, rzucając zestawy na pogranicze nurtu i spowolnień. Silny uciąg rzeki w 2026 roku wymaga bezkompromisowego, mocnego sprzętu, zwłaszcza przy nastawieniu się na ryby dwuśrodowiskowe. Surowość rozległego, żuławskiego krajobrazu dodaje każdemu wyjazdowi specyficznego, niemal morskiego klimatu.', null);

