VALUES (71014, 'Nizinna Wielka', 'Szeroka, nurt jednolity', 650.0, 5.5, 'Piasek i żwir', 'Tor wodny', 'Troć wędrowna, Certa, Leszcz', 'Kraina sandacza', true);

-- Spot 1015: Piaskowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71015, 'Wisła - Piaskowiec (Wpływy Cofki)', 'wisla-piaskowiec', 'RIVER', 54.2383407, 18.9433325, 'Pomorskie', 'Stegna', 'Odcinek w Piaskowcu znajduje się już w strefie wyraźnych wpływów estuarium, co objawia się szerokim i zrównoważonym przepływem. Dno stanowi tu mozaika grubego piasku i naniesionego żwiru, poprzecinana rynnami wyżłobionymi przez cofki morskie. To elitarne stanowisko dla wędkarzy łowiących z plaży oraz łowców troci, którzy używają tu błystek wahadłowych. W cieplejszych, płytkich zatokach wiosną 2026 roku masowo gromadzą się stada okoni, doskonale reagujących na metodę bocznego troka. Uciąg jest zmienny, zależny od wiatrów z Zatoki Gdańskiej, co determinuje konieczność ciągłego dostosowywania taktyki. Sąsiedztwo rozległych wałów przeciwpowodziowych i dzikiej przyrody tworzy idealne tło dla wymagającego, nizinnego wędkarstwa.', null);

