VALUES (71015, 'Estuarium', 'Szeroka, pływowa', 700.0, 4.5, 'Piasek i żwir', 'Płycizny przybrzeżne', 'Troć wędrowna, Okoń, Sandacz', 'Strefa przymorska', true);

-- Spot 1016: Miejsce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71016, 'Wisła - Miejsce (Rynny Brzanowe)', 'wisla-miejsce-malopolskie', 'RIVER', 50.0299638, 19.5021404, 'Małopolskie', 'Zator', 'Przenosimy się na Górną Wisłę do miejscowości Miejsce, gdzie rzeka płynie meandrującym, węższym korytem. Podłoże jest tu niezwykle twarde, kamienisto-żwirowe, a nurt szybki i bogaty w życiodajny tlen. To absolutnie bankowe stanowisko dla łowców potężnych brzan, które upodobały sobie tutejsze głębokie, wyerodowane rynny. Spinningiści z sukcesami obławiają opaski brzegowe, szukając okazałych kleni oraz wiosennych jazi. W marcu 2026 roku woda zachowuje tu krystaliczną czystość, wymuszając na wędkarzach finezyjne łowienie na cienkich żyłkach. Spokojna okolica rolnicza gwarantuje minimalną presję wędkarską i pełen relaks w otoczeniu budzącej się przyrody.', null);

