VALUES (71016, 'Podgórska', 'Bystra, meandrująca', 60.0, 1.8, 'Kamień i żwir', 'Rynny, bystrza', 'Brzana, Kleń, Jaź', 'Kraina brzany', false);

-- Spot 1017: Kamień
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71017, 'Wisła - Kamień (Bystrza Żwirowe)', 'wisla-kamien-malopolskie', 'RIVER', 50.0081114, 19.5642851, 'Małopolskie', 'Czernichów', 'Wisła w rejonie Kamienia to klasyczny, podgórski odcinek o bystrym nurcie i licznych żwirowych wypłyceniach. Rzeka żłobi tu techniczne rynny pod brzegami, tworząc mikrosiedliska idealne dla pstrągów potokowych i lipieni. Wędkarze muchowi oraz fani lekkiego spinningu z powodzeniem penetrują tu warkocze prądowe za dużymi głazami. Wędkarze stacjonarni korzystają ze spowolnień nurtu, łowiąc na przepływankę świnki, certy oraz rzeczne płocie. Marzec 2026 roku przyciąga tu pasjonatów wędkarstwa reofilnego, gdyż woda jest doskonale natleniona i wolna od letnich zakwitów. Unikalny, kamienisty charakter dna sprawia, że łowienie wymaga świetnej znajomości czytania wody i sprawnego omijania zaczepów.', null);

