VALUES (71017, 'Podgórska', 'Naturalna, kamienista', 70.0, 1.5, 'Żwir i głazy', 'Warkocze prądowe', 'Pstrąg potokowy, Lipień, Świnka', 'Kraina pstrąga', false);

-- Spot 1018: Kępa Oborska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71018, 'Wisła - Kępa Oborska (Dziki Archipelag)', 'wisla-kepa-oborska', 'RIVER', 52.1276701, 21.1759276, 'Mazowieckie', 'Konstancin-Jeziorna', 'Wracamy na Środkową Wisłę do Kępy Oborskiej, gdzie rzeka toczy się niezwykle szerokim, dzikim korytem pełnym piaszczystych wysp. Dno zbudowane jest z grubego piasku, który formuje dynamicznie przemieszczające się przykosy i głębokie warkocze prądowe. To strategiczny obszar dla łowców wielkich boleni, które widowiskowo atakują stada uklei na płytkich przelewach. Spinningiści z uwagą badają stoki tych łach, poszukując sandaczy odpoczywających w cieniu prądowym na skraju głębiny. Fani wędkarstwa gruntowego zmagają się z żywym uciągiem, nęcąc rynny w poszukiwaniu rekordowych leszczy i krąpi. Wiosną 2026 roku teren ten zachwyca dzikością rezerwatu i całkowitym odcięciem od zgiełku pobliskiej aglomeracji warszawskiej.', null);

