-- Spot 1019: Goczałkowice-Zdrój (Zbiornik)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71019, 'Wisła - Goczałkowice (Cofka Jeziorna)', 'wisla-goczalkowice-zbiornik', 'RIVER', 49.9325496, 18.8275623, 'Śląskie', 'Goczałkowice-Zdrój', 'Łowisko w Goczałkowicach-Zdroju leży w bezpośredniej strefie Zbiornika Goczałkowickiego, oferując typowo jeziorowe warunki. Podłoże jest tu miękkie i muliste, z łagodnie opadającymi stokami, które wiosną szybko pochłaniają promienie słoneczne. W marcu 2026 roku te płytkie zatoki stają się wędkarskim eldorado, gdyż to tu najszybciej budzą się liny, karasie i okazałe płocie. Spinningiści poszukują tu wczesnowiosennych szczupaków, obławiając granice budzących się do życia trzcinowisk. Ze względu na znikomą siłę uciągu, do łowienia gruntowego wystarczą najdelikatniejsze wędki typu picker i klasyczne spławikówki. Piękna panorama Beskidów i mikroklimat uzdrowiska nadają temu miejscu unikalny, niezwykle relaksujący charakter.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71019, 'Nizinna', 'Zbiornik zaporowy', 2500.0, 3.0, 'Muł i piasek', 'Trzcinowiska, zatoki', 'Lin, Szczupak, Karaś', 'Kraina leszcza', true);

-- -- Spot 1020: Toruń (Wschód - Bulwary)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71020, 'Wisła - Toruń (Bulwary Filadelfijskie)', 'wisla-torun-bulwary', 'RIVER', 53.014269, 18.663207, 'Kujawsko-Pomorskie', 'Toruń', 'Miejski odcinek Wisły w Toruniu charakteryzuje się głębokim korytem o twardym, kamienisto-żwirowym dnie i uregulowanych nabrzeżach. Podłoże pod filarami mostów drogowych jest silnie wymyte, tworząc rynny sięgające nawet sześciu metrów głębokości. To strategiczne miejsce dla spinningistów polujących na sandacze, które w marcu 2026 roku stacjonują w cieniu prądowym murów oporowych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie w spowolnieniach nurtu za filarami. Uciąg rzeki jest tu stabilny, ale zdecydowany, co sprzyja doskonałemu natlenieniu wody i aktywności ryb reofilnych. Panorama Starego Miasta i dobra infrastruktura czynią to miejsce idealnym na bezpieczny streetfishing o każdej porze dnia.', null);

