-- -- Spot 1023: Wielka Nieszawka
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71023, 'Wisła - Wielka Nieszawka (Łachy)', 'wisla-wielka-nieszawka', 'RIVER', 53.0369272, 18.4136809, 'Kujawsko-Pomorskie', 'Toruń', 'Wisła w Wielkiej Nieszawce to klasyczna kraina rozległych przykos i piaszczystych łach, które dynamicznie zmieniają swój profil po zimowych wezbraniach. Rzeka rozlewa się tu szeroko, tworząc mozaikę płytkich przelewów i głębszych rynien, idealnych dla żerujących boleni. To strategiczne miejsce dla łowców drapieżników, którzy w marcu namierzają stada uklei przy turbulentnych warkoczach powstających na łukach koryta. Podłoże jest głównie piaszczyste, co wymaga od wędkarza częstego sondowania głębokości łowiska w poszukiwaniu nowych uskoków dna. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i certy, wykorzystując systematyczne nęcenie na stokach piaszczystych blatów. Dzikość brzegów i brak gęstej zabudowy zapewniają wędkarzowi spokój oraz możliwość obserwacji dzikiej przyrody Doliny Wisły.', null);

