-- -- Spot 1024: Przyłubie
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71024, 'Wisła - Przyłubie (Techniczne Główki)', 'wisla-przylubie', 'RIVER', 53.0638834, 18.3361767, 'Kujawsko-Pomorskie', 'Solec Kujawski', 'Odcinek w Przyłubiu słynie z dobrze zachowanych i długich ostróg kamiennych, które skupiają główny nurt rzeki w wąskim torze. Podłoże jest tu twarde, piaszczysto-kamieniste na szczytach budowli i mulisto-piaszczyste wewnątrz głębokich klatek między główkami. To doskonałe łowisko dla spinningistów polujących na sandacze, którzy wykorzystują głęboki opad w warkoczach prądowych. W marcu 2026 roku miejsce to staje się mekką dla łowców okazowych leszczy, grupujących się w osłoniętych od nurtu zatokach. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji tutejszego rybostanu. Izolacja od dużych aglomeracji sprawia, że jest to jeden z najspokojniejszych technicznych odcinków Wisły na Kujawach.', null);

