-- Spot 1020: Toruń (Wschód - Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71020, 'Wisła - Toruń (Bulwary Filadelfijskie)', 'wisla-torun-bulwary', 'RIVER', 53.014269, 18.663207, 'Kujawsko-Pomorskie', 'Toruń', 'Miejski odcinek Wisły w Toruniu charakteryzuje się głębokim korytem o twardym, kamienisto-żwirowym dnie i uregulowanych nabrzeżach. Podłoże pod filarami mostów drogowych jest silnie wymyte, tworząc rynny sięgające nawet sześciu metrów głębokości. To strategiczne miejsce dla spinningistów polujących na sandacze, które w marcu 2026 roku stacjonują w cieniu prądowym murów oporowych. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze, wykorzystując systematyczne nęcenie w spowolnieniach nurtu za filarami. Uciąg rzeki jest tu stabilny, ale zdecydowany, co sprzyja doskonałemu natlenieniu wody i aktywności ryb reofilnych. Panorama Starego Miasta i dobra infrastruktura czynią to miejsce idealnym na bezpieczny streetfishing o każdej porze dnia.', null);

