-- Spot 1021: Toruń (Zachód - Port Zimowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71021, 'Wisła - Toruń (Zachodni Nurt)', 'wisla-torun-zachod', 'RIVER', 53.0020761, 18.5845834, 'Kujawsko-Pomorskie', 'Toruń', 'Wisła na zachodnich obrzeżach Torunia przechodzi w charakter bardziej naturalny, z licznymi systemami ostróg kamiennych chroniących brzegi. Podłoże jest tu zróżnicowane – od piaszczystych klatek po twarde, gliniaste rynny w głównym nurcie toru wodnego. To doskonałe łowisko dla spinningistów polujących na bolenie, które wiosną 2026 roku patrolują warkocze prądowe powstające na szczytach główek. Wędkarze feederowi z sukcesami łowią tu okazałe certy i jazie, stosując technikę klasycznego feedera na krawędzi nurtu. Uciąg wody jest żywy, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji przynęty. Spokojniejsza okolica w porównaniu do centrum miasta pozwala na komfortowe obławianie technicznych struktur brzegowych.', null);

