-- Spot 1022: Mała Nieszawka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71022, 'Wisła - Mała Nieszawka (Rynny pod Skarpą)', 'wisla-mala-nieszawka', 'RIVER', 53.0083361, 18.5104248, 'Kujawsko-Pomorskie', 'Toruń', 'Odcinek w Małej Nieszawce charakteryzuje się głębokimi rynnami wymytymi pod wysokim, lewym brzegiem rzeki. Dno jest tu twarde, piaszczysto-żwirowe z licznymi podmyłymi burtami, które stanowią bankowe ostoje dla rekordowych brzan i sumów. Spinningiści z sukcesami obławiają tutejsze warkocze, szukając sandaczy stacjonujących w cieniu prądowym naturalnych przeszkód. W marcu 2026 roku woda zachowuje tu wysoką przejrzystość, co wymusza na wędkarzach stosowanie finezyjnych zestawów i dyskretne podejście. Wędkarze stacjonarni nęcą tutejsze płanie, celując w dorodne leszcze oraz certy wchodzące w rzekę z nurtu głównego. Malowniczy widok na przeciwny brzeg i dzikość rzeki nadają temu miejscu unikalnego, relaksującego charakteru.', null);

