-- Spot 1023: Wielka Nieszawka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71023, 'Wisła - Wielka Nieszawka (Łachy)', 'wisla-wielka-nieszawka', 'RIVER', 53.0369272, 18.4136809, 'Kujawsko-Pomorskie', 'Toruń', 'Wisła w Wielkiej Nieszawce to klasyczna kraina rozległych przykos i piaszczystych łach, które dynamicznie zmieniają swój profil po zimowych wezbraniach. Rzeka rozlewa się tu szeroko, tworząc mozaikę płytkich przelewów i głębszych rynien, idealnych dla żerujących boleni. To strategiczne miejsce dla łowców drapieżników, którzy w marcu namierzają stada uklei przy turbulentnych warkoczach powstających na łukach koryta. Podłoże jest głównie piaszczyste, co wymaga od wędkarza częstego sondowania głębokości łowiska w poszukiwaniu nowych uskoków dna. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i certy, wykorzystując systematyczne nęcenie na stokach piaszczystych blatów. Dzikość brzegów i brak gęstej zabudowy zapewniają wędkarzowi spokój oraz możliwość obserwacji dzikiej przyrody Doliny Wisły.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71023, 'Nizinna Wielka', 'Naturalna, piaszczysta', 500.0, 2.5, 'Piasek', 'Przykosy, łachy', 'Boleń, Certa, Płoć', 'Kraina leszcza', true);

-- Spot 1024: Przyłubie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71024, 'Wisła - Przyłubie (Techniczne Główki)', 'wisla-przylubie', 'RIVER', 53.0638834, 18.3361767, 'Kujawsko-Pomorskie', 'Solec Kujawski', 'Odcinek w Przyłubiu słynie z dobrze zachowanych i długich ostróg kamiennych, które skupiają główny nurt rzeki w wąskim torze. Podłoże jest tu twarde, piaszczysto-kamieniste na szczytach budowli i mulisto-piaszczyste wewnątrz głębokich klatek między główkami. To doskonałe łowisko dla spinningistów polujących na sandacze, którzy wykorzystują głęboki opad w warkoczach prądowych. W marcu 2026 roku miejsce to staje się mekką dla łowców okazowych leszczy, grupujących się w osłoniętych od nurtu zatokach. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji tutejszego rybostanu. Izolacja od dużych aglomeracji sprawia, że jest to jeden z najspokojniejszych technicznych odcinków Wisły na Kujawach.', null);

