-- Spot 027: Rzeszów (Zapora/Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71027, 'Wisłok - Rzeszów (Zalew/Zapora)', 'wislok-rzeszow-zapora', 'RIVER', 50.0204756, 22.0000259, 'Podkarpackie', 'Rzeszów', 'Odcinek Wisłoka powyżej zapory w Rzeszowie ma charakter szerokiego, spowolnionego rozlewiska o mulisto-piaszczystym dnie. W marcu 2026 roku to strategiczne miejsce dla łowców białorybu, szczególnie dorodnych leszczy i płoci, które gromadzą się w płytszych, szybciej nagrzewających się partiach zalewu. Spinningiści z sukcesami polują tu na okonie, wykorzystując liczne konstrukcje betonowe oraz pasy trzcinowisk jako naturalne kryjówki drapieżników. Uciąg wody jest tu minimalny, co pozwala na stosowanie bardzo delikatnych zestawów spławikowych i drgającej szczytówki. Ze względu na systematyczne odmulanie koryta, ukształtowanie dna bywa zmienne, co wymaga od wędkarza bieżącego sondowania głębokości. Popularność bulwarów sprawia, że jest to idealne miejsce na techniczny streetfishing w samym sercu stolicy Podkarpacia.', null);

