-- Spot 028: Rzeszów (Most Zamkowy/Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71028, 'Wisłok - Rzeszów (Centrum - Rynny)', 'wislok-rzeszow-centrum', 'RIVER', 50.0440255, 22.0210531, 'Podkarpackie', 'Rzeszów', 'Wisła w centrum Rzeszowa płynie uregulowanym korytem, gdzie nurt wyraźnie przyspiesza poniżej stopnia wodnego. Podłoże jest tu twardsze, piaszczysto-żwirowe, z głębokimi rynnami wymytymi pod filarami mostów Zamkowego i Narutowicza. To strategiczne miejsce dla spinningistów polujących na klenie i jazie, które w marcu chętnie ustawiają się w warkoczach prądowych za betonowymi konstrukcjami. Wędkarze stacjonarni z sukcesami łowią tu metodą przepływanki, wykorzystując natlenioną wodę i systematyczne nęcenie drobną zanętą. Uciąg rzeki jest zdecydowany, co sprzyja doskonałej kondycji ryb reofilnych żerujących w rynnie głównej. Dobra infrastruktura i oświetlenie brzegów czynią ten odcinek bezpiecznym i komfortowym miejscem na wieczorne wyprawy wędkarskie.', null);

