-- Spot 029: Rzeszów (Ciepłownia/Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71029, 'Wisłok - Rzeszów (Zrzut/Ciepłownia)', 'wislok-rzeszow-cieplownia', 'RIVER', 50.0714806, 22.024998, 'Podkarpackie', 'Rzeszów', 'Północny odcinek Wisłoka w rejonie rzeszowskiej ciepłowni charakteryzuje się podwyższoną temperaturą wody ze względu na zrzuty technologiczne. W marcu 2026 roku to absolutny magnes na ryby białego żeru, które grupują się tu masowo, szukając cieplejszych prądów przed zbliżającym się tarłem. Podłoże jest tu piaszczysto-muliste z licznymi zastoiskami brzegowymi, w których gromadzą się stada leszczy, płoci i krąpi. Spinningiści z sukcesami obławiają granice ciepłego nurtu, szukając okoni oraz szczupaków zwabionych obecnością ogromnej ilości drobnicy. Uciąg wody jest umiarkowany, co pozwala na precyzyjne nęcenie i stosowanie technik feederowych z krótkim przyponem. Odcinek ten słynie z rekordowych wyników wczesnowiosennych, będąc jednym z najgorętszych punktów na mapie Podkarpacia.', null);

