-- Spot 030: Nowa Wieś
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71030, 'Wisłok - Nowa Wieś (Dzikie Meandry)', 'wislok-nowa-wies', 'RIVER', 50.09221, 22.0531403, 'Podkarpackie', 'Rzeszów', 'Wisłok w Nowej Wsi odzyskuje swój naturalny, meandrujący charakter z licznymi podmyłymi burtami i piaszczystymi łachami. Rzeka żłobi tu głębokie rynny na zewnętrznych łukach koryta, które są bezpieczną ostoją dla dużych kleni i brzan. Podłoże jest żwirowo-piaszczyste z licznymi zatopionymi korzeniami drzew, co wymaga od wędkarza dużej precyzji w prowadzeniu przynęty. To wymarzone miejsce dla spinningistów szukających jazi, które w marcu 2026 roku doskonale reagują na małe woblery i obrotówki. Uciąg rzeki jest żywy i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji tutejszego rybostanu. Dzikość brzegów i brak uregulowań hydrotechnicznych nadają temu łowisku unikalny, podgórski klimat.', null);

