-- Spot 031: Jasionka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71031, 'Wisłok - Jasionka (Bystrza)', 'wislok-jasionka', 'RIVER', 50.1137121, 22.0787499, 'Podkarpackie', 'Rzeszów', 'Wisłok w rejonie Jasionki charakteryzuje się bystrym nurtem i licznymi żwirowymi wypłyceniami, które tworzą techniczne bystrza i warkocze. Podłoże jest tu twarde, kamienisto-żwirowe, co sprzyja bytowaniu ryb reofilnych szukających pokarmu w najszybszym prądzie wody. To doskonałe łowisko dla spinningistów polujących na pstrągi potokowe, które okresowo spływają tu z górnych partii dopływów. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, celując w dorodne świnki i certy stacjonujące w głębszych rynnach. W marcu 2026 roku woda zachowuje tu wysoką klarowność, co wymaga stosowania finezyjnych zestawów i dyskretnego zachowania nad brzegiem. Spokojna okolica i malowniczy krajobraz doliny Wisłoka czynią to miejsce idealnym na całodzienne wyprawy z lekkim sprzętem.', null);

