-- Spot 032: Wólka Podleśna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71032, 'Wisłok - Wólka Podleśna (Zakola)', 'wislok-wolka-podlesna', 'RIVER', 50.112895, 22.1208625, 'Podkarpackie', 'Sokołów Małopolski', 'Odcinek w Wólce Podleśnej to kraina głębokich zakoli i zatarasowanych zwalonymi drzewami rynien, stanowiących bankowe kryjówki drapieżników. Wisłok płynie tu leniwiej, osadzając piasek na piaszczystych przykosach i tworząc rozległe płanie o spokojniejszym nurcie. To strategiczne miejsce dla łowców szczupaków, którzy obławiają zastoiska za zatorami z gałęzi i podmokłe brzegi. W marcu 2026 roku wędkarze feederowi z sukcesami łowią tu okazałe leszcze i krąpie, nęcąc precyzyjnie w głębszych partiach koryta. Podłoże jest tu piaszczysto-gliniaste, co zapewnia rybom białą obfitość naturalnego pokarmu i stabilne żerowanie. Dzikość terenu i utrudniony dostęp do niektórych brzegów sprawiają, że presja wędkarska jest tu znacznie mniejsza niż w pobliżu Rzeszowa.', null);

