-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71033, 'Wisłok - Medynia Łańcucka (Zakola)', 'wislok-medynia-lancucka', 'RIVER', 50.1117393, 22.1632827, 'Podkarpackie', 'Rzeszów', 'Wisłok w Medyni Łańcuckiej płynie głębokim korytem o piaszczysto-gliniastym dnie z licznymi, podmyłymi burtami brzegowymi. Rzeka tworzy tu techniczne rynny na zewnętrznych łukach koryta, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców kleni, które w marcu 2026 roku doskonale reagują na małe woblery prowadzone wzdłuż nawisów traw. Wędkarze stacjonarni nęcą tutejsze płanie, celując w dorodne leszcze oraz rzeczne płocie migrujące korytem. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji ryb reofilnych. Malowniczy krajobraz doliny Wisłoka i relatywnie niska presja wędkarska sprawiają, że ryby żerują tu bardzo odważnie.', null);

