-- -- Spot 034: Czarna
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71034, 'Wisłok - Czarna (Zwalone Drzewa)', 'wislok-czarna', 'RIVER', 50.1111352, 22.2057812, 'Podkarpackie', 'Łańcut', 'Odcinek Wisłoka w miejscowości Czarna charakteryzuje się naturalnym przebiegiem z dużą ilością zwalonych do wody karczowisk i konarów drzew. Takie techniczne struktury tworzą idealne schronienia dla dużych sumów oraz szczupaków rzecznych czatujących w zastoiskach za przeszkodami. Podłoże jest tu mocno zróżnicowane, piaszczysto-żwirowe z licznymi uskokami dna toru głównego rzeki. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając jazi i okoni stacjonujących w cieniu prądowym pni. W marcu 2026 roku miejsce to słynie z regularnych brań dorodnych jazi, które doskonale reagują na owadowe przynęty spinningowe. Dzikość brzegów i utrudniony dojazd do niektórych zakoli zapewniają wędkarzowi spokój oraz możliwość obserwacji nienaruszonej przyrody.', null);

