INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71041, 'Wisłok - Gniewczyna Tryniecka (Bystrza)', 'wislok-gniewczyna-tryniecka', 'RIVER', 50.1174915, 22.5000597, 'Podkarpackie', 'Przeworsk', 'Wisłok w Gniewczynie Trynieckiej przyspiesza swój bieg, tworząc liczne żwirowe wypłycenia i techniczne bystrza o twardym dnie. Podłoże jest tu kamienisto-żwirowe, co zapewnia doskonałe natlenienie wody i wysoką aktywność ryb reofilnych przez cały sezon. To strategiczne miejsce dla łowców brzan, które upodobały sobie tutejsze głębokie rynny na krawędzi głównego nurtu. Spinningiści z sukcesami obławiają warkocze prądowe, szukając boleni oraz okazowych kleni czatujących na drobnicę w prądzie. W marcu 2026 roku woda bywa tu krystaliczna, co wymaga od wędkarza stosowania finezyjnego sprzętu i długich przyponów z fluorocarbonu. Malowniczy krajobraz doliny i surowość rzeki nadają temu łowisku unikalnego, niemal podgórskiego charakteru.', null);

