-- Spot 042: Chodaczów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71042, 'Wisłok - Chodaczów (Zatorowiska)', 'wislok-chodaczow', 'RIVER', 50.1395054, 22.5246183, 'Podkarpackie', 'Leżajsk', 'Odcinek w Chodaczowie charakteryzuje się naturalnym przebiegiem koryta z dużą ilością zwalonych drzew i podwodnych przeszkód. Takie zatarasowane rynny stanowią bankowe kryjówki dla dużych sumów oraz szczupaków rzecznych czatujących w zastoiskach. Podłoże jest tu mocno zróżnicowane, piaszczysto-gliniaste z głębokimi dołkami wymytymi pod zwalonymi konarami. To techniczne łowisko wymaga od spinningisty precyzyjnych rzutów i umiejętnego prowadzenia przynęty wśród naturalnych zaczepów. W marcu 2026 roku wędkarze stacjonarni z sukcesami łowią tu dorodne leszcze, wykorzystując systematyczne nęcenie w spowolnieniach nurtu za przeszkodami. Dzikość terenu i utrudniony dojazd do niektórych partii rzeki zapewniają wędkarzowi absolutny spokój i brak presji.', null);

