VALUES (71042, 'Nizinna', 'Dzika, zatarasowana', 65.0, 2.5, 'Piasek i glina', 'Zwalone drzewa', 'Sum, Szczupak, Leszcz', 'Kraina leszcza', false);

-- Spot 043: Tryńcza (Węzeł Kolejowy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71043, 'Wisłok - Tryńcza (Pod Mostami)', 'wislok-tryncza-mosty', 'RIVER', 50.1627745, 22.5482342, 'Podkarpackie', 'Przeworsk', 'Wisłok w Tryńczy to technicznie wymagające łowisko o uregulowanych brzegach i silnym nurcie przy potężnych filarach mostu kolejowego i drogowego. Podłoże jest tu twarde, piaszczysto-betonowe, z głębokimi rynnami toru wodnego sięgającymi kilku metrów głębokości pod mostem. To strategiczne miejsce dla łowców sandaczy i sumów, które wykorzystują cienie prądowe za filarami jako swoje główne ostoje. Spinningiści z sukcesami obławiają kamieniste opaski poniżej przepraw, szukając kleni i walecznych boleni żerujących w nurcie. W marcu 2026 roku miejsce to słynie z dużej populacji jazi, które doskonale reagują na lekkie zestawy feederowe. Bliskość ujścia do Sanu sprawia, że rybostan jest tu wyjątkowo bogaty i stale zasilany migracjami ryb między obiema rzekami.', null);

