-- Spot 044: Głogowiec (Ujście do Sanu)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71044, 'Wisłok - Głogowiec (Ujście Wisłoka)', 'wislok-glogowiec-ujscie', 'RIVER', 50.1914355, 22.5442301, 'Podkarpackie', 'Leżajsk', 'Miejsce ujścia Wisłoka do Sanu w Głogowcu to jedno z najważniejszych miejsc hydrologicznych w regionie, charakteryzujące się mieszaniem wód o różnej termice. Turbulentne prądy na styku obu rzek tworzą głębokie rynny i piaszczyste wiry, które są naturalnym „magnesem” dla wszystkich gatunków drapieżników. To strategiczne miejsce dla łowców sumów, którzy w 2026 roku polują tu na rekordowe okazy stacjonujące w najgłębszych partiach toru wodnego. Spinningiści z sukcesami obławiają warkocz ujściowy, szukając sandaczy oraz boleni żerujących na piaszczystych przykosach ujściowych. Podłoże jest tu niezwykle zmienne, piaszczysto-muliste z licznymi twardymi uskokami dna, co wymaga od wędkarza doskonałej znajomości koryta. Malowniczy krajobraz połączenia dwóch rzek i ogromna rybność czynią Głogowiec obowiązkowym punktem na mapie każdego spinningisty.', null);

