VALUES (71044, 'Nizinna Wielka', 'Ujściowa, szeroka', 120.0, 4.0, 'Piasek i muł', 'Ujście rzeki, warkocze', 'Sum, Sandacz, Boleń', 'Kraina leszcza', true);

-- Spot 045: Strzyżów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71045, 'Wisłok - Strzyżów (Bystrza Podgórskie)', 'wislok-strzyzow', 'RIVER', 49.8665229, 21.7939562, 'Podkarpackie', 'Strzyżów', 'Wisła w Strzyżowie to klasyczny, podgórski odcinek o bystrym nurcie i kamienistym dnie usianym licznymi progami skalnymi. Rzeka żłobi tu techniczne rynny między głazami, które są naturalnym stanowiskiem dla walecznych pstrągów potokowych i lipieni. To doskonale natlenione łowisko wymaga od wędkarza dużej precyzji w podawaniu przynęt pod nawisy nadrzecznych drzew i skalne załomy. Uciąg wody jest bardzo dynamiczny, co sprzyja wysokiej aktywności ryb reofilnych przez cały sezon wędkarski 2026 roku. Spinningiści z sukcesami obławiają tutejsze mikro-warkocze, wykorzystując małe woblery i obrotówki do polowania na klenie. Malowniczy krajobraz Pogórza Strzyżowskiego i krystaliczna woda nadają temu miejscu unikalny, niemal górski klimat, przyciągający pasjonatów lekkiego łowienia.', null);

