VALUES (71045, 'Podgórska', 'Bystra, kamienista', 40.0, 1.2, 'Kamień i skała', 'Progi skalne', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 046: Krosno (Bulwary/Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71046, 'Wisłok - Krosno (Miejskie Bystrza)', 'wislok-krosno-centrum', 'RIVER', 49.6994933, 21.7592528, 'Podkarpackie', 'Krosno', 'Wisłok w centrum Krosna ma charakter rzeki podgórskiej o kamienistym dnie i uregulowanych, betonowo-kamiennych nabrzeżach. Nurt jest tu wartki, z licznymi bystrzami i rynnami wymytymi pod filarami mostów, co sprzyja doskonałemu natlenieniu wody. To strategiczne miejsce dla spinningistów polujących na klenie i okonie, które chętnie ustawiają się w warkoczach prądowych za przeszkodami. W marcu 2026 roku woda zachowuje tu wysoką klarowność, co wymaga stosowania cienkich przyponów z fluorocarbonu i dyskrecji przy podchodzeniu do stanowiska. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie metodą przepływanki, wykorzystując głębsze rynny w nurcie głównym. Bliskość starówki i dogodny dostęp do brzegów czynią rzeszowski Wisłok idealnym miejscem na szybki streetfishing.', null);

