VALUES (71046, 'Podgórska', 'Uregulowana miejska', 35.0, 1.2, 'Kamień i żwir', 'Mosty, progi skalne', 'Kleń, Okoń, Płoć', 'Kraina brzany', false);

-- Spot 047: Kalembina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71047, 'Wisłok - Kalembina (Przełom pod Skarpą)', 'wislok-kalembina', 'RIVER', 49.8641363, 21.6817194, 'Podkarpackie', 'Strzyżów', 'Wisłok w Kalembinie to jeden z najbardziej malowniczych odcinków rzeki, płynący u stóp wysokich, zalesionych wzniesień Pogórza Strzyżowskiego. Koryto żłobi tu głębokie rynny w litej skale i glinie, tworząc naturalne jamy będące ostoją dla rekordowych kleni oraz sumów. Podłoże jest tu niezwykle twarde, kamienisto-żwirowe, co zapewnia rybom reofilnym idealne warunki do żerowania w marcu 2026 roku. Spinningiści z sukcesami obławiają tutejsze warkocze, rzucając przynęty pod nawisy nadrzecznych wiklin i zwalone do wody pnie drzew. Uciąg wody jest żywy i zmienny, uzależniony od ukształtowania koryta, co wymaga od wędkarza świetnego „czytania rzeki”. Izolacja od dużych aglomeracji i dzikość brzegów sprawiają, że presja wędkarska jest tu minimalna.', null);

