-- Spot 048: Wysoka Strzyżowska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71048, 'Wisłok - Wysoka Strzyżowska (Meandry)', 'wislok-wysoka-strzyzowska', 'RIVER', 49.8666809, 21.7491005, 'Podkarpackie', 'Strzyżów', 'Odcinek w Wysokiej Strzyżowskiej charakteryzuje się licznymi zakolami o wysokich brzegach i zdecydowanym uciągu rzeki. Dno jest tu piaszczysto-żwirowe z wyraźnie zaznaczonymi rynnami na zewnętrznych łukach, które stanowią bankowe stanowiska dla brzan i świnek. Spinningiści z sukcesami polują tu na jazie, które w marcu 2026 roku grupują się w spowolnieniach nurtu za naturalnymi zatorami z gałęzi. Woda o tej porze roku jest doskonale natleniona, co sprzyja wysokiej kondycji ryb migrujących w górę Wisłoka na tarło. Wędkarze stacjonarni nęcą tutejsze płanie żwirowe, celując w dorodne klenie i rzeczne płocie łowione metodą drgającej szczytówki. Spokojna okolica rolnicza gwarantuje wędkarzowi relaks i możliwość obserwacji bogatej awifauny nadrzecznej.', null);

