-- Spot 049: Glinik Zaborowski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71049, 'Wisłok - Glinik Zaborowski (Żwirowe Bystrza)', 'wislok-glinik-zaborowski', 'RIVER', 49.8857755, 21.8234556, 'Podkarpackie', 'Strzyżów', 'Wisłok w Gliniku Zaborowskim to techniczne łowisko charakteryzujące się szerokimi płaniami żwirowymi i dynamicznymi bystrzami. Podłoże składa się z grubego żwiru i otoczaków, co tworzy idealne warunki dla lipieni oraz pstrągów potokowych okresowo spływających z dopływów. To strategiczne miejsce dla spinningistów polujących na klenie, którzy wykorzystują turbulentną wodę na styku prądów do prezentacji małych woblerów. W marcu 2026 roku poziom wody sprzyja namierzaniu głębszych rynien wyżłobionych w twardym dnie toru głównego rzeki. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, celując w waleczne jelce oraz certy stacjonujące w nurcie. Otwarty charakter brzegów pozwala na dalekie rzuty i komfortowe przemieszczanie się wzdłuż linii rzeki.', null);

