-- Spot 050: Zaborów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71050, 'Wisłok - Zaborów (Głębiny pod burtą)', 'wislok-zaborow', 'RIVER', 49.9131771, 21.8248182, 'Podkarpackie', 'Czudec', 'Odcinek Wisłoka w Zaborowie słynie z wysokich, podmytych brzegów i głębokich rynien wymytych w gliniastym podłożu dna rzeki. To wymarzone łowisko dla łowców dużych sumów, którzy wykorzystują liczne zwalone drzewa i zatory jako naturalne schronienia drapieżników. Spinningiści z sukcesami obławiają tutejsze uskoki dna, szukając sandaczy oraz szczupaków czatujących w cieniu prądowym na krawędzi nurtu. W marcu 2026 roku aktywność jazi i kleni w tym rejonie jest bardzo wysoka, co przyciąga pasjonatów lekkiego spinningu i method feedera. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne nęcenie i utrzymywanie stad białorybu w polu łowienia. Dziki krajobraz pradoliny Wisłoka i surowość nadrzecznych wiklin nadają temu miejscu unikalny charakter.', null);

