-- Spot 051: Czudec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71051, 'Wisłok - Czudec (Kolejowe Zakole)', 'wislok-czudec', 'RIVER', 49.938743, 21.8386911, 'Podkarpackie', 'Czudec', 'Wisłok w Czudcu płynie urokliwym, meandrującym korytem o zróżnicowanym dnie – od piaszczystych przykos po żwirowe rynny. Bliskość nasypu kolejowego tworzy techniczne wzmocnienia brzegowe, w których chętnie stacjonują klenie i okonie szukające twardszego podłoża. To doskonałe łowisko dla wędkarzy feederowych, którzy z sukcesami nęcą tutejsze płanie w poszukiwaniu dorodnych leszczy oraz cert. W marcu 2026 roku poziom wody w Czudcu jest zazwyczaj stabilny, co sprzyja precyzyjnemu lokowaniu przynęt w głębszych rynnach toru głównego. Spinningiści chętnie wykorzystują podmyte korzenie drzew do polowania na szczupaki czatujące w spowolnieniach nurtu. Malowniczy krajobraz Pogórza i łatwy dostęp do rzeki czynią Czudec popularnym punktem weekendowych wypraw dla wędkarzy z regionu.', null);

