-- Spot 052: Babica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71052, 'Wisłok - Babica (Bystrza i Głębiny)', 'wislok-babica', 'RIVER', 49.9328615, 21.880091, 'Podkarpackie', 'Rzeszów', 'Wisłok w Babicy to odcinek o niezwykle dynamicznym charakterze, łączący szybkie bystrza z głębokimi dołami wymytymi na ostrych zakrętach koryta. Podłoże jest tu twarde, piaszczysto-żwirowe, co przyciąga rekordowe brzany oraz klenie żerujące intensywnie w marcu 2026 roku. Spinningiści z sukcesami obławiają warkocze prądowe powstające na styku głównego nurtu i spokojnych zatoczek brzegowych. Wędkarze gruntowi nęcą tutejsze głębokie rynny, licząc na brania dużych leszczy i jazi migrujących w stronę Rzeszowa. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu koryta i wysokiej kondycji ryb reofilnych. Strategiczne położenie przy trasie wylotowej ze stolicy województwa sprawia, że jest to jedno z najchętniej odwiedzanych łowisk w tym rejonie.', null);

