-- Spot 053: Siedliska (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71053, 'Wisłok - Siedliska (Południe)', 'wislok-siedliska-poludnie', 'RIVER', 49.9471369, 21.9169801, 'Podkarpackie', 'Rzeszów', 'Wisłok w południowej części Siedlisk charakteryzuje się naturalnym, meandrującym korytem o urozmaiconym, piaszczysto-żwirowym dnie. Rzeka tworzy tu techniczne rynny na zewnętrznych łukach, które w marcu 2026 roku stanowią główne ostoje dla dorodnych kleni i jazi. To strategiczne miejsce dla spinningistów, którzy wykorzystują liczne podmyte burty do prowadzenia lekkich przynęt wzdłuż krawędzi nurtu. Wędkarze stacjonarni z sukcesami łowią tu metodą drgającej szczytówki, nęcąc precyzyjnie spowolnienia za naturalnymi zatorami z gałęzi. Uciąg rzeki jest tu żywy, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji ryb reofilnych po okresie zimowym. Spokojna okolica i łatwy dostęp do wielu stanowisk brzegowych czynią Siedliska popularnym punktem na mapie podkarpackich wędkarzy.', null);

