-- Spot 054: Siedliska (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71054, 'Wisłok - Siedliska (Północ)', 'wislok-siedliska-polnoc', 'RIVER', 49.9656601, 21.9481766, 'Podkarpackie', 'Rzeszów', 'Odcinek Wisłoka w północnej części Siedlisk to miejsce, gdzie rzeka zaczyna powoli rozszerzać swoje koryto przed wpłynięciem do Boguchwały. Podłoże jest tu zróżnicowane, z przewagą twardego piasku i licznymi żwirowymi wypłyceniami, które tworzą techniczne bystrza. To wymarzone łowisko dla łowców brzan, które w marcu 2026 roku gromadzą się w głębszych rynnach toru głównego rzeki. Spinningiści chętnie obławiają warkocze prądowe powstające na styku nurtu i spokojniejszych zatoczek brzegowych w poszukiwaniu szczupaków. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze migrujące okresowo z dolnego biegu Wisłoka. Dzikość brzegów porośniętych gęstą wikliną zapewnia wędkarzowi spokój oraz doskonałą osłonę przed wczesnowiosennym wiatrem.', null);

