-- Spot 055: Boguchwała
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71055, 'Wisłok - Boguchwała', 'wislok-boguchwala', 'RIVER', 49.9913452, 21.9647139, 'Podkarpackie', 'Rzeszów', 'Wisłok w Boguchwale to technicznie wymagające łowisko o uregulowanym charakterze brzegów i zróżnicowanej głębokości toru wodnego. Podłoże jest tu twarde, piaszczysto-kamieniste, z licznymi opaskami i rynnami wymytymi pod filarami konstrukcji hydrotechnicznych. To strategiczne miejsce dla spinningistów polujących na sandacze, które w marcu 2026 roku stacjonują w cieniu prądowym betonowych umocnień. Wędkarze stacjonarni z sukcesami łowią tu dorodne płocie i certy, wykorzystując systematyczne nęcenie w spowolnieniach nurtu za ostrogami. Uciąg rzeki jest stabilny i zdecydowany, co wymaga stosowania dociążonych zestawów gruntowych dla precyzyjnej prezentacji przynęty. Bliskość aglomeracji rzeszowskiej i dobra infrastruktura czynią Boguchwałę idealnym miejscem na szybkie sesje wędkarskie po pracy.', null);

