VALUES (71055, 'Podgórska', 'Uregulowana miejska', 55.0, 2.0, 'Kamień i piasek', 'Mosty, opaski', 'Sandacz, Certa, Płoć', 'Kraina brzany', false);

-- Spot 056: Wojkówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71056, 'Wisłok - Wojkówka', 'wislok-wojkowka', 'RIVER', 49.7793287, 21.6815607, 'Podkarpackie', 'Krosno', 'Wisłok w Wojkówce to jeden z najbardziej malowniczych i dzikich odcinków rzeki, charakteryzujący się bystrym nurtem i kamienistym dnem. Rzeka żłobi tu głębokie rynny w twardym, skalno-żwirowym podłożu, tworząc idealne warunki dla pstrągów potokowych i lipieni. To doskonale natlenione łowisko wymaga od wędkarza dużej precyzji w podawaniu małych przynęt pod nawisy skalne i nadrzeczne gałęzie. W marcu 2026 roku woda zachowuje tu wysoką klarowność, co wymusza stosowanie finezyjnych zestawów i dyskrecję podczas przemieszczania się brzegiem. Spinningiści z sukcesami obławiają tutejsze bystrza i warkocze prądowe, szukając walecznych kleni żerujących w najszybszym nurcie. Surowość podgórskiego krajobrazu i krystaliczna woda nadają temu miejscu unikalny, elitarny charakter wędkarski.', null);

