-- Spot 057: Łęki Strzyżowskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71057, 'Wisłok - Łęki Strzyżowskie', 'wislok-leki-strzyzowskie', 'RIVER', 49.7985837, 21.6517597, 'Podkarpackie', 'Strzyżów', 'Odcinek w Łękach Strzyżowskich charakteryzuje się naturalnym przebiegiem koryta z licznymi żwirowymi wypłyceniami i głębokimi dołkami brzegowymi. Rzeka tworzy tu techniczne zakola, na których nurt wyraźnie przyspiesza, wymywając twarde, piaszczysto-żwirowe rynny idealne dla brzan. To strategiczne miejsce dla łowców kleni, które w marcu 2026 roku doskonale reagują na owadowe przynęty spinningowe prowadzone w dryfie. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, celując w dorodne świnki i certy stacjonujące poniżej bystrz. Uciąg wody jest żywy i zmienny, co sprzyja wysokiej aktywności drapieżników polujących na drobnicę w cieniu prądowym naturalnych przeszkód. Malowniczy krajobraz pogranicza Pogórza Dynowskiego i Strzyżowskiego czyni to łowisko wyjątkowo atrakcyjnym wizualnie.', null);

