VALUES (71057, 'Podgórska', 'Naturalna, meandrująca', 40.0, 1.4, 'Żwir i piasek', 'Zakola, bystrza', 'Brzana, Świnka, Kleń', 'Kraina brzany', false);

-- Spot 058: Widacz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71058, 'Wisłok - Widacz', 'wislok-widacz', 'RIVER', 49.8215225, 21.629526, 'Podkarpackie', 'Strzyżów', 'Wisłok w miejscowości Widacz to odcinek o niezwykle urozmaiconym dnie, gdzie twarde rynny skalne przeplatają się z piaszczystymi płaniami. Rzeka płynie tu szerzej, oferując wędkarzom dogodny dostęp do brzegów i liczne zastoiska bogate w naturalny pokarm rzeczny. To doskonałe łowisko dla spinningistów szukających szczupaków czatujących w spowolnieniach nurtu za zwalonymi do wody konarami drzew. W marcu 2026 roku stada płoci i jazi grupują się w najgłębszych rynnach, co sprzyja skutecznemu nęceniu i łowieniu techniką feedera klasycznego. Uciąg wody stabilizuje się na prostych odcinkach koryta, co pozwala na precyzyjne podawanie przynęt i komfortowe wędkowanie nawet przy wyższych stanach rzeki. Niska presja wędkarska oraz dziki charakter Wisłoka w tym rejonie gwarantują spokój i szansę na kontakt z rekordowymi okazami ryb.', null);

