VALUES (71058, 'Podgórska', 'Naturalna, szeroka', 45.0, 1.6, 'Piasek i skała', 'Zwalone drzewa, rynny', 'Szczupak, Jaź, Płoć', 'Kraina brzany', false);

-- Spot 059: Wisłok - Pułanki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71059, 'Wisłok - Pułanki', 'wislok-pulanki', 'RIVER', 49.8483973, 21.6229546, 'Podkarpackie', 'Strzyżów', 'Wisłok w Pułankach to klasyczny odcinek podgórski z dnem usianym grubym żwirem i licznymi otoczakami. Rzeka tworzy tu dynamiczne bystrza, które w marcu 2026 roku są doskonale natlenione i przyciągają stada walecznych brzan. Spinningiści z sukcesami obławiają tutejsze warkocze, szukając okazałych kleni czatujących w cieniu prądowym dużych głazów. Podłoże jest stabilne, co sprzyja brodzeniu, jednak należy uważać na głębokie rynny wyżłobione przy podmytych burtach. Wędkarze stacjonarni nęcą spowolnienia nurtu, licząc na brania rekordowych cert migrujących w górę rzeki na tarło. Surowy krajobraz Pogórza Strzyżowskiego nadaje temu łowisku wyjątkowy, techniczny charakter i zapewnia spokój nad wodą.', null);

