-- Spot 060: Wisłok - Odrzykoń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71060, 'Wisłok - Odrzykoń', 'wislok-odrzykon', 'RIVER', 49.7394307, 21.720114, 'Podkarpackie', 'Krosno', 'Wisłok w rejonie Odrzykonia płynie w głębokiej dolinie, charakteryzując się twardym, skalno-żwirowym dnem z licznymi progami naturalnymi. Nurt rzeki uderza tu w wysokie brzegi, tworząc głębokie rynny będące idealną ostoją dla sumów i dużych brzan. To strategiczne miejsce dla spinningistów, którzy wykorzystują turbulentną wodę wokół głazów do polowania na bolenie i okonie. W marcu 2026 roku woda zachowuje wysoką klarowność, co wymusza na wędkarzach stosowanie bardzo finezyjnych zestawów spinningowych. Wędkarze gruntowi z sukcesami łowią tu dorodne klenie, nęcą precyzyjnie spowolnienia nurtu za naturalnymi przeszkodami. Bliskość ruin zamku Kamieniec nadaje każdemu wędkowaniu w tym miejscu unikalnego, historycznego wymiaru.', null);

