-- Spot 061: Wisłok - Wisłok Wielki (Górny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71061, 'Wisła - Wisłok Wielki (Górny)', 'wislok-wielki-gorny', 'RIVER', 49.4003771, 21.979248, 'Podkarpackie', 'Komańcza', 'Górny bieg Wisłoka w rejonie Wisłoka Wielkiego to krystalicznie czysty potok górski o charakterze wybitnie pstrągowym. Koryto rzeki jest tu wąskie, usiane głazami i zwalonymi drzewami, co tworzy niezliczone kryjówki dla ryb łososiowatych. To techniczne łowisko wymaga od wędkarza dużej sprawności fizycznej oraz precyzji w podawaniu małych przynęt pod nawisy skalne. Uciąg wody jest bardzo dynamiczny, zapewniając doskonałe natlenienie koryta przez cały sezon wędkarski 2026 roku. Spinningiści z sukcesami polują tu na waleczne pstrągi potokowe, wykorzystując małe woblery i obrotówki prowadzone z prądem. Całkowita dzikość Beskidu Niskiego i brak presji wędkarskiej czynią ten odcinek prawdziwym rajem dla koneserów górskiego łowienia.', null);

