VALUES (71061, 'Górska', 'Dziki potok górski', 6.0, 0.6, 'Kamień i skała', 'Naturalne kaskady', 'Pstrąg potokowy, Głowacz', 'Kraina pstrąga', false);

-- Spot 062: Wisłok - Wisłok Wielki (Dolny)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71062, 'Wisłok - Wisłok Wielki (Dolny)', 'wislok-wielki-dolny', 'RIVER', 49.4216277, 21.9536302, 'Podkarpackie', 'Komańcza', 'Niższy odcinek rzeki w Wisłoku Wielkim charakteryzuje się szerszym korytem i obecnością rozległych płani żwirowych o umiarkowanym nurcie. Rzeka żłobi tu techniczne rynny pod brzegami, stanowiące naturalne stanowiska dla okazowych kleni i lipieni żerujących o zmierzchu. To doskonałe miejsce dla wędkarzy muchowych, którzy cenią sobie możliwość swobodnego operowania sznurem na otwartej przestrzeni łąkowej. W marcu 2026 roku woda bywa tu krystaliczna, co wymaga stosowania cienkich przyponów i dyskretnego podchodzenia do stanowiska. Spinningiści z sukcesami obławiają bystrza, szukając pstrągów potokowych stacjonujących w cieniu prądowym większych otoczaków. Malowniczy krajobraz górskich łąk i stabilny stan wody czynią to miejsce idealnym na całodzienne wyprawy z lekkim sprzętem.', null);

