VALUES (71062, 'Górska', 'Naturalna, żwirowa', 12.0, 0.8, 'Żwir i kamień', 'Bystrza, płanie', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 063: Wisłok - Darów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71063, 'Wisłok - Darów', 'wislok-darow', 'RIVER', 49.4398129, 21.9229383, 'Podkarpackie', 'Jaśliska', 'Wisłok w Darowie to jeden z najbardziej odizolowanych odcinków rzeki, płynący przez całkowicie wyludnione tereny Beskidu Niskiego. Rzeka ma tu charakter dzikiego potoku o bardzo zmiennym dnie, gdzie głębokie skalne jamy przeplatają się z płytkimi bystrzami. To wymarzone łowisko dla osób szukających kontaktu z pierwotną naturą i walecznymi pstrągami potokowymi o pięknym ubarwieniu. Spinningiści muszą wykazać się tu dużą precyzją rzutów, operując przynętami w ciasnych korytarzach utworzonych przez nadrzeczne olsze. W marcu 2026 roku niska temperatura wody sprzyja aktywności ryb łososiowatych, które gromadzą się w głębszych dołkach o słabszym nurcie. Brak zasięgu telefonicznego i absolutna cisza sprawiają, że wędkowanie w Darowie jest formą głębokiego odpoczynku od cywilizacji.', null);

