-- Spot 064: Wisłok - Puławy (Przełom)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71064, 'Wisłok - Puławy (Przełom Skalny)', 'wislok-pulawy-przelom', 'RIVER', 49.4636612, 21.9028714, 'Podkarpackie', 'Rymanów', 'Odcinek w Puławach to słynny przełom Wisłoka, gdzie rzeka wcina się głęboko w skalne podłoże, tworząc wysokie na kilkanaście metrów ściany. Dno jest tu lite, skalne, z wyżłobionymi przez miliony lat rynnami i potężnymi głazami w nurcie głównym. To strategiczne miejsce dla spinningistów szukających dużych kleni i świnek, które doskonale czują się w tym niezwykle natlenionym fragmencie. W marcu 2026 roku poziom wody pozwala na techniczne obławianie głębokich warkoczy powstających na zakrętach przełomu. Wędkarze muchowi chętnie stosują tu ciężkie nimfy, sprowadzając je w najgłębsze partie rynien, gdzie stacjonują rekordowe lipienie. Niespotykane walory krajobrazowe i surowość rzeki czynią Puławy jednym z najbardziej spektakularnych łowisk w południowej Polsce.', null);

