-- Spot 065: Wisłok - Puławy (Zalew)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71065, 'Wisłok - Puławy (Cofka Sieniawy)', 'wislok-pulawy-zalew', 'RIVER', 49.4908334, 21.907143, 'Podkarpackie', 'Sieniawa', 'Odcinek Wisłoka powyżej zapory w Sieniawie to strefa przejściowa, gdzie nurt rzeki wyraźnie wyhamowuje, a koryto zaczyna się rozszerzać. Podłoże zmienia tu charakter na piaszczysto-muliste, tworząc bogate żerowisko dla ryb spokojnego żeru, takich jak dorodne leszcze i płocie. To strategiczne miejsce dla spinningistów polujących na szczupaki, które w marcu 2026 roku ustawiają się przy krawędzi budzącej się roślinności zanurzonej. Uciąg wody jest tu łagodny, co pozwala na stosowanie lżejszych metod feederowych oraz precyzyjne nęcenie na łagodnie opadających stokach. W rynnach toru głównego wciąż można trafić na duże klenie, które korzystają z żyznej wody niesionej przez rzekę w głąb zbiornika. Spokojna woda i dogodny dostęp do brzegów sprawiają, że jest to miejsce chętnie wybierane na wielogodzinne, wiosenne zasiadki.', null);

