-- Spot 066: Wisłok - Pastwiska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71066, 'Wisłok - Pastwiska (Zrzut Zapory)', 'wislok-pastwiska', 'RIVER', 49.5147461, 21.9269651, 'Podkarpackie', 'Sieniawa', 'Wisła bezpośrednio poniżej stopnia wodnego w Sieniawie to krystalicznie czysty i bardzo wartki odcinek o charakterze górskim. Dzięki zrzutowi wody ze zbiornika, rzeka jest tu doskonale natleniona i posiada stałą, niską temperaturę, co sprzyja bytowaniu pstrągów potokowych i lipieni. To technicznie wymagające łowisko z dnem żwirowo-kamienistym, na którym kluczem do sukcesu jest precyzyjne czytanie mikro-warkoczy za głazami. W marcu 2026 roku stada świdników i jelców doskonale reagują na lekkie zestawy spławikowe prowadzone techniką przepływanki w nurcie. Spinningiści z sukcesami obławiają tutejsze głębokie rynny poniżej progu, szukając walecznych kleni żerujących na spływającym pokarmie. Miejsce to cieszy się dużym uznaniem ze względu na krystaliczną wodę i pewne wyniki nawet przy gorszych warunkach na innych odcinkach.', null);

