-- Spot 067: Wisłok - Pastwiska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71067, 'Wisłok - Pastwiska', 'wislok-pastwiska-gorny', 'RIVER', 49.5420971, 21.9309937, 'Podkarpackie', 'Sanok', 'Wisłok w rejonie Pastwisk to techniczny odcinek o bystrym nurcie, ukształtowany pod silnym wpływem zrzutów wody ze zbiornika w Sieniawie. Koryto rzeki posiada tu twarde, kamienisto-żwirowe dno, które stanowi doskonałe siedlisko dla organizmów bentosowych będących pokarmem pstrągów potokowych. To strategiczne miejsce dla wędkarzy muchowych, którzy w marcu 2026 roku z sukcesami obławiają głębokie rynny na krawędziach głównego prądu. Spinningiści chętnie wykorzystują precyzyjnie prowadzone nimfy i małe woblery, celując w dorodne klenie i lipienie stacjonujące w cieniu prądowym głazów. Uciąg wody jest tu wybitnie dynamiczny i silnie natleniony, co gwarantuje rybom reofilnym doskonałą kondycję zaraz po zimowych mrozach. Zimna, przejrzysta woda zrzutowa wymaga absolutnej ciszy na brzegu i stosowania długich, bezbarwnych przyponów z fluorocarbonu.', null);

