-- Spot 068: Wisłok - Sieniawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71068, 'Wisłok - Sieniawa', 'wislok-sieniawa', 'RIVER', 49.5691101, 21.9295626, 'Podkarpackie', 'Krosno', 'Odcinek rzeki w Sieniawie, bezpośrednio powyżej i poniżej lokalnej zapory, charakteryzuje się zmienną głębokością i potężnymi zawirowaniami wody. Podłoże jest tu niezwykle twarde, zdominowane przez lite skały i naniesiony gruby kamień, co tworzy idealne warunki dla największych pstrągów potokowych. To doskonałe łowisko dla spinningistów polujących na rekordowe klenie, które gromadzą się w głębokich dołach wyrzeźbionych przez spadającą wodę. Wczesną wiosną 2026 roku stabilizacja przepływów poniżej tamy pozwala na komfortowe, punktowe obławianie technicznych warkoczy prądowych. Wędkarze spławikowi z powodzeniem stosują ciężkie zestawy przepływankowe, by sprowadzić przynętę do ryb stacjonujących w niemal stojącej wodzie przy samych opaskach. Surowy, inżynieryjny krajobraz zapory w połączeniu z krystaliczną wodą górską tworzy unikalny, wysoce techniczny klimat tej miejscówki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
