-- Spot 069: Wisłok - Besko (Górne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71069, 'Wisłok - Besko (Górne)', 'wislok-besko-gorne', 'RIVER', 49.5894117, 21.9579378, 'Podkarpackie', 'Sanok', 'Wisłok w Besku tworzy słynny przełom rzeki zwany Jarem Wisłoka, gdzie woda przedziera się przez strome, kilkunastometrowe ściany fliszu karpackiego. Koryto wcina się w lity kamień, generując wąskie, niezwykle głębokie rynny o potężnym uciągu, w których stacjonują potężne brzany i świnki. To elitarne miejsce dla wędkarzy spinningowych, którzy muszą tu stosować ciężkie przynęty, aby przebić się przez zawirowania powierzchniowe. W marcu 2026 roku łowienie w tym rejonie wymaga doskonałej sprawności fizycznej, gdyż śliskie, skalne półki utrudniają dostęp do najlepszych stanowisk. Wędkarze muchowi celują tu w okazałe pstrągi potokowe, prowadząc ciężkie nimfy na długiej żyłce wzdłuż skalnych podmyć. Unikalna geomorfologia i dzikość tego głębokiego jaru sprawiają, że jest to jeden z najpiękniejszych, ale i najtrudniejszych wędkarsko odcinków Podkarpacia.', null);

