VALUES (71069, 'Górska', 'Przełom skalny', 15.0, 2.0, 'Lita skała', 'Kanion skalny, rynny', 'Brzana, Świnka, Pstrąg potokowy', 'Kraina brzany', false);

-- Spot 070: Wisłok - Besko (Dolne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71070, 'Wisłok - Besko (Dolne)', 'wislok-besko-dolne', 'RIVER', 49.6162389, 21.9644594, 'Podkarpackie', 'Sanok', 'Dolny odcinek Wisłoka w Besku charakteryzuje się wyjściem rzeki z wąwozu i przejściem w szerszą dolinę o żwirowym podłożu. Rzeka uspokaja tu nieco swój bieg, rozlewając się na piaszczysto-żwirowych płaniach i tworząc liczne, natlenione bystrza idealne dla kleni. To strategiczny obszar dla wędkarzy łowiących na przepływankę, którzy z sukcesami nęcą tutejsze rynny w poszukiwaniu dorodnych świnek i jazi. Spinningiści z uwagą penetrują granice szybkiego i wolnego nurtu, rzucając małe obrotówki w poszukiwaniu aktywnych pstrągów potokowych i lipieni. W marcu 2026 roku słońce szybko nagrzewa płytkie rozlewiska, co przyspiesza wybudzanie się owadów i stymuluje ryby do powierzchownego żerowania. Otwarty krajobraz i łatwy dostęp do brzegu czynią tę lokalizację bardzo przyjazną dla wielogodzinnych, relaksujących sesji brodzenia.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71070, 'Podgórska', 'Naturalna, żwirowa', 35.0, 1.2, 'Żwir i piasek', 'Bystrza, płanie', 'Kleń, Świnka, Pstrąg potokowy', 'Kraina brzany', false);

-- -- Spot 071: Wisłok - Bzianka
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71071, 'Wisłok - Bzianka', 'wislok-bzianka', 'RIVER', 49.629552, 21.928024, 'Podkarpackie', 'Krosno', 'Wisłok w miejscowości Bzianka to klasyczna rzeka podgórska o urozmaiconym korycie, w którym głębokie doły płynnie przechodzą w żwirowe przelewy. Podłoże jest tu mozaiką żwiru, otoczaków i twardej gliny, co tworzy doskonałe siedlisko dla ryb prądolubnych, takich jak brzany i świnki. To wymarzone łowisko dla spinningistów polujących na jazie, które wiosną chętnie ustawiają się na krawędziach spokojniejszych, przybrzeżnych zastoisk. W marcu 2026 roku niska mętność wody pozwala na skuteczne stosowanie finezyjnych technik spławikowych typu bolońskiego z użyciem cienkich żyłek. Uciąg na środku rzeki jest zdecydowany, co zapewnia doskonałe natlenienie wody i wymusza aktywność drapieżników poszukujących pożywienia znoszonego przez nurt. Malownicza, rolniczo-leśna sceneria tego odcinka gwarantuje wędkarski spokój i brak miejskiej presji.', null);

