-- Spot 072: Wisłok - Haczów (Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71072, 'Wisłok - Haczów (Wschód)', 'wislok-haczow-wschod', 'RIVER', 49.6523958, 21.9052818, 'Podkarpackie', 'Krosno', 'Wschodni fragment Wisłoka w Haczowie płynie szerokim, ale płytkim korytem, dominują tu rozległe żwirowiska i techniczne warkocze prądowe. Dno usiane jest drobnymi kamieniami, co czyni ten odcinek idealnym tarliskiem i żerowiskiem dla ogromnych stad lipieni oraz kleni. To strategiczne miejsce dla wędkarzy muchowych, którzy przy użyciu metody suchej muchy skutecznie kuszą ryby zbierające pokarm z powierzchni. Spinningiści obławiają nieco głębsze rynny pod zwalonymi drzewami, stosując małe jigi w celu sprowokowania pstrągów potokowych do brania. Ze względu na wczesnowiosenną termikę w marcu 2026 roku, najlepsze brania przypadają na ciepłe, popołudniowe godziny, gdy woda delikatnie się nagrzewa. Bezpieczne i twarde podłoże sprzyja brodzeniu, pozwalając na precyzyjne podanie przynęty z niemal każdego miejsca w rzece.', null);

