-- -- Spot 073: Wisłok - Haczów (Zachód)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71073, 'Wisłok - Haczów (Zachód)', 'wislok-haczow-zachod', 'RIVER', 49.6778388, 21.8903378, 'Podkarpackie', 'Krosno', 'Zachodni odcinek Wisłoka w Haczowie charakteryzuje się głębszymi rynnami torowymi wyżłobionymi na zakrętach i podmytych, leśnych burtach. Rzeka płynie tu wolniej, osadzając na dnie mieszankę piasku i żwiru, pod którą kryje się twarda, zwięzła rzeczna glina. To doskonałe łowisko dla wędkarzy feederowych, którzy z powodzeniem używają tu koszyków zanętowych, celując w duże brzany i rzeczne leszcze. W marcu 2026 roku drapieżniki takie jak szczupaki i okonie opuszczają główne bystrza, grupując się w spokojniejszych zatoczkach za powalonymi konarami. Spinningiści z sukcesami prowadzą tu średnie woblery wzdłuż granicy nurtu, wykorzystując wiosenny apetyt ryb po zimowym postoju. Otoczenie bujnych łęgów wierzbowych i stabilny uciąg czynią to łowisko niezwykle atrakcyjnym dla wędkarzy szukających ciszy i technicznego wyzwania.', null);

-- INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
-- VALUES (71073, 'Podgórska', 'Naturalna, meandrująca', 42.0, 1.7, 'Piasek i glina', 'Podmyte burty, zwalone drzewa', 'Brzana, Szczupak, Leszcz', 'Kraina brzany', false);

-- -- Spot 074: Wisłok - Krościenko Wyżne (Wschód)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71074, 'Wisłok - Krościenko Wyżne (Wschód)', 'wislok-kroscienko-wyzne-wschod', 'RIVER', 49.6762407, 21.8486251, 'Podkarpackie', 'Krosno', 'Odcinek Wisłoka na wschodnich obrzeżach Krościenka Wyżnego to dynamiczna woda podgórska, silnie meandrująca wśród łąk i pól. Koryto żłobi tu głębokie doły na zewnętrznych zakrętach rzeki, gdzie kamieniste dno stwarza bezpieczne schronienie dla stacjonarnych kleni oraz świnek. To strategiczne terytorium dla łowców okoni, które obficie żerują w spokojniejszych warkoczach wodnych za naturalnymi zatorami z pni i gałęzi. W marcu 2026 roku wędkarze przepływankowi z powodzeniem nęcą długie rynny na prostkach, utrzymując stada ryb białego żeru w łowisku. Uciąg jest tu zdecydowany, a woda niesie dużo cennego tlenu, co gwarantuje świetną walkę podczas holu na delikatnym sprzęcie. Urokliwy, wiejski krajobraz oraz stabilna głębokość koryta sprawiają, że to miejsce cieszy się sporym uznaniem okolicznych wędkarzy rzecznych.', null);

