-- VALUES (71074, 'Podgórska', 'Naturalna, meandrująca', 38.0, 1.5, 'Kamień i glina', 'Zatory, głębokie zakręty', 'Kleń, Świnka, Okoń', 'Kraina brzany', false);

-- -- Spot 075: Wisłok - Krościenko Wyżne (Zachód)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71075, 'Wisłok - Krościenko Wyżne (Zachód)', 'wislok-kroscienko-wyzne-zachod', 'RIVER', 49.682282, 21.807492, 'Podkarpackie', 'Krosno', 'Zachodni fragment Wisłoka w Krościenku Wyżnym to przedsionek aglomeracji krośnieńskiej, gdzie rzeka stopniowo ulega brzegowym regulacjom hydrotechnicznym. Dno staje się tu wyjątkowo twarde, wysłane opoką i gruboziarnistym żwirem, a sztuczne opaski przyspieszają nurt, tworząc klasyczne rzeczne bystrza. To wymarzone stanowisko dla łowców potężnych brzan, które w 2026 roku gromadzą się na styku najszybszego prądu i głębokich, podmytych rynien. Spinningiści obławiający kamienne umocnienia regularnie notują tu potężne uderzenia dużych pstrągów potokowych i wyrośniętych, rzecznych kleni. Uciąg wody w centrum rynny wymaga dociążonych zestawów, by skutecznie zakotwiczyć przynętę w strefie przydennej. Bliskość miasta Krosno zapewnia rewelacyjny dojazd, co czyni ten odcinek doskonałym miejscem na regularne treningi wędkarzy sportowych.', null);

