-- Spot 076: Wkra - Nick
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71076, 'Wkra - Nick', 'wkra-nick', 'RIVER', 53.2183303, 19.9150963, 'Warmińsko-Mazurskie', 'Lidzbark', 'Wkra w rejonie miejscowości Nick to wąska, dzika rzeka o niezwykle urozmaiconym, leśnym przebiegu koryta. Podłoże jest tu piaszczysto-żwirowe z dużą ilością zatopionych korzeni i powalonych pni, które tworzą naturalne tamy i głęboczki. To strategiczne miejsce dla spinningistów szukających wczesnowiosennych jazi, które chętnie ustawiają się w spowolnieniach nurtu za przeszkodami. W marcu 2026 roku woda bywa tu jeszcze bardzo zimna, co wymusza stosowanie najmniejszych przynęt gumowych i niezwykle wolnego prowadzenia. Wędkarze spławikowi z sukcesami nęcą małe zastoiska, celując w dorodne płocie i jelce szukające pierwszego wiosennego pokarmu. Brak presji wędkarskiej i trudny, zarośnięty brzeg gwarantują pełną izolację oraz kontakt z nienaruszoną przyrodą.', null);

