-- Spot 077: Wkra - Nowy Dwór
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71077, 'Wkra - Nowy Dwór', 'wkra-nowy-dwor', 'RIVER', 53.1975356, 19.8658364, 'Warmińsko-Mazurskie', 'Lidzbark', 'Odcinek Wkry w Nowym Dworze charakteryzuje się licznymi meandrami wymywającymi strome, gliniaste burty na zewnętrznych łukach rzeki. Dno jest tu twardsze, piaszczysto-gliniaste, co sprzyja bytowaniu okazałych kleni, które znajdują schronienie w metrowych rynnach erozyjnych. Spinningiści z uwagą penetrują granice szybkiego i wolnego nurtu, rzucając małe obrotówki pod same nawisy nadrzecznych traw. Wędkarze gruntowi stosują tu lekkie wędziska typu picker, łowiąc wiosenne krąpie i leszczyki z użyciem koszyków o gramaturze nieprzekraczającej 20 gramów. Uciąg wody w marcu 2026 roku jest umiarkowany i przewidywalny, co pozwala na bardzo precyzyjne odczytywanie brań z delikatnych szczytówek. Otwarty, łąkowy krajobraz ułatwia przemieszczanie się wzdłuż brzegów, zachęcając do aktywnego łowienia z podchodu.', null);

