VALUES (71077, 'Nizinna', 'Meandrująca, łąkowa', 15.0, 1.2, 'Glina i piasek', 'Podmyte burty', 'Kleń, Krąp, Płoć', 'Kraina brzany', false);

-- Spot 078: Wkra - Kozilas
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71078, 'Wkra - Kozilas', 'wkra-kozilas', 'RIVER', 53.1610211, 19.8641657, 'Mazowieckie', 'Lubowidz', 'Wkra w rejonie Kozilasu to niezwykle malowniczy fragment, gdzie rzeka wcina się w zalesione tereny, tworząc zacienione i chłodne rynny. Koryto pokrywa tu warstwa jasnego piasku przemieszanego z drobnym żwirem, a liczne zwalone olchy tworzą doskonałe stanowiska dla drapieżników. Jest to klasyczne łowisko szczupakowe, w którym wczesnowiosenne zębate drapieżniki gromadzą się w głębszych, spokojnych zatokach tuż obok głównego nurtu. W marcu 2026 roku spinningiści z sukcesami stosują tu jaskrawe rippery, prowadząc je tuż nad dnem z długimi przerwami w zwijaniu. Fani białorybu odnajdą tu swoje eldorado, łowiąc na przepływankę piękne okazy jazi, które chętnie pobierają przynęty zwierzęce. Niska mętność wody wymusza bezszelestne zachowanie na brzegu i unikanie jaskrawych kolorów odzieży wędkarskiej.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71078, 'Nizinna', 'Leśna, dzika', 16.0, 1.4, 'Piasek i żwir', 'Zwalone drzewa, zatoki', 'Szczupak, Jaź, Kleń', 'Kraina brzany', false);

-- Spot 079: Wkra - Lubowidz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71079, 'Wkra - Lubowidz', 'wkra-lubowidz', 'RIVER', 53.1253696, 19.8535297, 'Mazowieckie', 'Lubowidz', 'Odcinek w Lubowidzu to uregulowany fragment Wkry, płynący przez tereny miejskie z ustabilizowanymi brzegami i łagodnie opadającym dnem. Podłoże jest tu piaszczysto-muliste z nielicznymi wypłyceniami, co tworzy idealne warunki dla wczesnowiosennego żerowania stad płoci i leszczy. To wymarzone stanowisko dla miłośników metody spławikowej, którzy w marcu 2026 roku nęcą tutejsze płanie drobną zanętą z dużą ilością jokersa. Spinningiści skupiają się na obławianiu krawędzi nurtu przy mostach, gdzie w cieniu prądowym filarów często ustawiają się ładne okonie. Uciąg rzeki jest tu wyhamowany i bardzo jednolity, co pozwala na budowanie stabilnych, długo pracujących ścieżek zanętowych w rynnie toru wodnego. Dogodny dojazd i bliskość zabudowań czynią to łowisko bezpiecznym i wygodnym miejscem na krótkie, popołudniowe wypady z lekkim sprzętem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71079, 'Nizinna', 'Miejska, uregulowana', 18.0, 1.5, 'Piasek i muł', 'Mosty, płanie', 'Płoć, Okoń, Leszcz', 'Kraina leszcza', false);

-- Spot 080: Wkra - Bądzyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71080, 'Wkra - Bądzyn', 'wkra-badzyn', 'RIVER', 53.0893432, 19.8517423, 'Mazowieckie', 'Lubowidz', 'Wisła w Bądzynie powraca do swojej roztokowej natury, meandrując pośród podmokłych łąk i formując płytkie, piaszczyste przelewy. Dno jest wybitnie piaszczyste, z wędrującymi, niewielkimi przykosami, za którymi woda gwałtownie rwie, tworząc dotlenione warkocze prądowe. To strategiczny obszar dla łowców rzecznych kleni, które z nadejściem pierwszych cieplejszych dni marca 2026 roku intensywnie żerują na płyciznach. Spinningiści z powodzeniem używają tu mikro-woblerów imitujących pierwsze wylęgające się owady, rzucając je w okolice zalanych traw. Wędkarze gruntowi szukają ryb w głębszych dołkach wyżłobionych tuż przed samymi łukami rzeki, gdzie woda znosi naturalny pokarm. Surowy, łąkowy krajobraz bez osłony drzew wymusza zwracanie uwagi na siłę i kierunek wiatru przy planowaniu techniki łowienia.', null);

