-- Spot 081: Wkra - Poniatowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71081, 'Wkra - Poniatowo', 'wkra-poniatowo', 'RIVER', 53.0553249, 19.8715931, 'Mazowieckie', 'Żuromin', 'Odcinek Wkry w Poniatowie charakteryzuje się głębszym, spokojniejszym korytem i brzegami porośniętymi gęstymi szpalerami wierzb. Rzeka żłobi tu techniczne, ponad dwumetrowe rynny o twardszym, gliniastym podłożu, które przyciągają stada większych leszczy i linów. To wymarzone łowisko dla pasjonatów klasycznego feedera, którzy w marcu 2026 roku notują tu znakomite wyniki, stosując przynęty białkowe. Spinningiści przeczesują najgłębsze strefy za pomocą lekkich jigów, polując na wyrośnięte okonie ukryte pośród podwodnych systemów korzeniowych. Uciąg wody jest w tym miejscu wyraźnie osłabiony, co sprawia, że rzeka niemal stoi, sprzyjając szybszemu nagrzewaniu się wody w słoneczne dni. Mnogość naturalnych stanowisk i zadaszenie z gałęzi tworzą tu niezwykle intymną, kameralną atmosferę do wielogodzinnych zasiadek.', null);

