-- Spot 082: Wkra - Krukowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71082, 'Wkra - Krukowiec', 'wkra-krukowiec', 'RIVER', 50.0219554, 19.8955252, 'Mazowieckie', 'Żuromin', 'Wkra w rejonie Krukowca przyspiesza swój bieg, rozbijając się o liczne przeszkody w postaci zwalonych pni i kamiennych umocnień dawnych młynów. Dno jest tu niezwykle urozmaicone, łącząc ostre, żwirowe blaty z wymytymi w miękkim piasku rynnami o sporej głębokości. To strategiczne terytorium dla łowców szczupaków, którzy muszą wykazać się kunsztem snajperskim, by precyzyjnie podać przynętę w okna wolnej wody między gałęziami. Wiosną 2026 roku stacjonarni wędkarze z sukcesami wyciągają stąd grube płocie, nęcąc strefy na krawędzi szybkiego i wolnego nurtu. Woda płynie tu żywo i natleniona, co doskonale wpływa na kondycję ryb, potęgując ich siłę oporu podczas holu na lekkim sprzęcie. Dzika, nieuregulowana struktura koryta i leśne otoczenie zachęcają do aktywnego pieszego wędkowania i poszukiwania własnych, sekretnych dołków.', null);

