VALUES (71082, 'Nizinna', 'Zatarasowana, bystra', 18.0, 1.6, 'Żwir i piasek', 'Zwalone drzewa, bystrza', 'Szczupak, Płoć, Kleń', 'Kraina brzany', false);

-- Spot 083: Wkra - Strzeszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71083, 'Wkra - Strzeszewo', 'wkra-strzeszewo', 'RIVER', 52.9858981, 19.8885116, 'Mazowieckie', 'Bieżuń', 'Odcinek w Strzeszewie to klasyczna, szeroka pętla rzeczna o łagodnych, piaszczystych brzegach i bardzo wyrównanym profilu dna. Koryto wypełnia tu drobny, jasny piasek, a rzeka toczy swoje wody leniwie, stwarzając wyśmienite warunki do wiosennego nagrzewania się płycizn. To doskonałe łowisko dla amatorów wiosennych jazi, które w marcu 2026 roku masowo odwiedzają tutejsze nasłonecznione blaty w poszukiwaniu larw. Spinningiści z uwagą prowadzą na tych płyciznach małe wahadłówki, co nierzadko kończy się widowiskowym atakiem drapieżnika w zaledwie półmetrowej wodzie. Wędkarze gruntowi powinni tu zachować szczególną ciszę, gdyż na płytkiej wodzie ryby są niezwykle płochliwe i czujne na wibracje brzegu. Sielski krajobraz i rozległa przestrzeń pozwalają na bezpieczne operowanie długimi wędziskami bolońskimi bez ryzyka zaczepów o drzewa.', null);

