-- Spot 084: Wkra - Bieżuń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71084, 'Wkra - Bieżuń', 'wkra-biezun', 'RIVER', 52.9513519, 19.9067455, 'Mazowieckie', 'Bieżuń', 'Wisła w okolicach miasteczka Bieżuń ma charakter rzeki uregulowanej, ujętej w szerokie obwałowania z licznymi, wybudowanymi opaskami umacniającymi brzeg. Dno jest tu znacznie twardsze, piaszczysto-żwirowe, co w połączeniu z przyśpieszonym nurtem generuje świetne warunki dla reofilnych kleni i jazi. To strategiczne stanowisko dla wędkarzy stosujących lekką drgającą szczytówkę, którzy z sukcesami odławiają potężne rzeczne płocie z głębszej, dwumetrowej rynny. W marcu 2026 roku spinningiści poszukują tu okoni przy betonowych przepustach oraz w zawirowaniach wody wokół nielicznych podwodnych przeszkód. Uciąg jest stabilny i przewidywalny, co umożliwia idealne zaplanowanie i utrzymanie linii nęcenia na twardym gruncie. Dobre skomunikowanie z miastem oraz mnogość utwardzonych ścieżek czynią to łowisko niezwykle atrakcyjnym dla wędkarzy w każdym wieku.', null);

