-- Spot 085: Wkra - Pozga
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71085, 'Wkra - Pozga', 'wkra-pozga', 'RIVER', 52.9271741, 19.9522233, 'Mazowieckie', 'Radzanów', 'Odcinek w Pozdze charakteryzuje się wspaniałymi, naturalnymi zakolami, gdzie piaszczyste plaże na łukach wewnętrznych kontrastują ze stromymi burtami. Rzeka podmywa tu korzenie potężnych olch, tworząc pod brzegiem niezwykle obiecujące jamy o gliniastym dnie przekraczające 2 metry głębokości. To jedno z najlepszych miejsc dla łowców wczesnowiosennych szczupaków, które w marcu 2026 roku wciąż czatują w tych głębokich, leniwych zastoiskach. Wędkarze stacjonarni używają tu spławików o dużej wyporności, by płynnie przeprowadzić przynętę tuż obok zawady z zatopionych gałęzi. Woda posiada tu żywy uciąg w nurcie głównym, ale doskonale wyhamowuje pod brzegami, gromadząc naturalny pokarm dla białorybu. Oddalenie od głównych dróg i piękno mazowieckich łąk pozwalają wędkarzowi na pełne wyciszenie i skupienie się na technice łowienia.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71085, 'Nizinna', 'Naturalna, meandrująca', 22.0, 2.0, 'Glina i piasek', 'Podmyte burty, zakola', 'Szczupak, Leszcz, Jaź', 'Kraina brzany', false);

-- Spot 086: Wkra - Siciarz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71086, 'Wkra - Siciarz', 'wkra-siciarz', 'RIVER', 52.932955, 20.0112939, 'Mazowieckie', 'Radzanów', 'Wkra w Siciarzu płynie leniwie przez płaską dolinę, rozlewając się na piaszczyste mielizny, które gęsto porastają letnią porą tatarakiem. Podłoże jest tutaj miękkie, piaszczysto-muliste, a koryto rzeki ma charakter misy bez wyraźnych, głębokich rynien torowych. W marcu 2026 roku te rozległe płycizny pełnią rolę kluczowego żerowiska dla wychudzonych po zimie leszczy i okazałych linów poszukujących ochotki. Spinningiści przeczesują te rewiry za pomocą lekkich błystek obrotowych, licząc na brania agresywnych, rzecznych okoni patrolujących skraje przyszłych trzcinowisk. Uciąg jest niemal niewyczuwalny, co umożliwia niesłychanie delikatne łowienie przy pomocy najlżejszych wędzisk typu quiver i cienkich żyłek. Płaskie, trawiaste brzegi gwarantują wygodne i bezpieczne rozstawienie stanowiska, czyniąc to miejsce przyjaznym dla wędkujących rodzin.', null);

