VALUES (71086, 'Nizinna', 'Płytka, mulista', 26.0, 1.2, 'Piasek i muł', 'Mielizny, trzcinowiska', 'Leszcz, Lin, Okoń', 'Kraina leszcza', false);

-- Spot 087: Wkra - Ratowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71087, 'Wkra - Ratowo', 'wkra-ratowo', 'RIVER', 52.9516736, 20.0653729, 'Mazowieckie', 'Radzanów', 'Odcinek rzeki w Ratowie to fascynujące łowisko ukształtowane w bezpośrednim sąsiedztwie zabytkowego zespołu klasztornego, nadającego miejscu unikalną aurę. Koryto zacieśnia się tutaj nieznacznie, a dno twardnieje, tworząc żwirowo-piaszczyste blaty i niewielkie rynny erozyjne z silniejszym prądem. To prawdziwy raj dla specjalistów od łowienia na bolonkę, którzy wczesną wiosną skutecznie kuszą tu w przepływance stada jazi oraz kleni. W marcu 2026 roku spinningiści obławiają okoliczne zakręty małymi smużkami, wyczekując widowiskowych uderzeń drapieżników w spowolnieniach nurtu. Woda na tym odcinku jest rewelacyjnie natleniona, a jej stabilny przepływ pozwala na precyzyjne planowanie strategii zanętowej. Łącząc wędkarskie rzemiosło z możliwością podziwiania architektury, Ratowo stanowi jeden z najbardziej urokliwych punktów Środkowej Wkry.', null);

