-- Spot 088: Wkra - Józefowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71088, 'Wkra - Józefowo', 'wkra-jozefowo', 'RIVER', 52.9346865, 20.1184685, 'Mazowieckie', 'Radzanów', 'Wkra w rejonie Józefowa charakteryzuje się bardzo dzikim, zarośniętym brzegiem i dużą ilością zatopionego drewna, tworzącego trudne technicznie zatory. Dno rzeki pokryte jest w tym miejscu piaszczysto-gliniastymi garbami, pomiędzy którymi wymyte zostały zaciszne, dwumetrowe jamy. To strategiczne terytorium dla łowców wczesnowiosennych szczupaków, które uwielbiają czatować w cieniu podwodnych gałęzi w oczekiwaniu na ofiarę. W marcu 2026 roku wędkarze gruntowi potrafią tu zaskoczyć pięknymi braniami grubych leszczy, o ile precyzyjnie trafią koszykiem między zaczepy. Uciąg jest tu dość żywy, ale woda szybko wyhamowuje za każdą naturalną przeszkodą, generując małe, wsteczne wiry niosące pokarm. Dzikość i trudna dostępność brzegów odstraszają wędkarską rzeszę, gwarantując nielicznym pasjonatom całkowitą samotność i niezapomniane emocje z holu.', null);

