-- Spot 089: Wkra - Adamowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71089, 'Wkra - Adamowo', 'wkra-adamowo', 'RIVER', 52.9311048, 20.1787051, 'Mazowieckie', 'Strzegowo', 'Odcinek Wkry w Adamowie uosabia klasyczną rzekę nizinną, gdzie szerokie, łagodne zakola płynnie przechodzą w długie, piaszczyste prostki. Podłoże jest tu niezwykle miękkie, piaszczyste, z powoli przemieszczającymi się drobnymi przykosami, które nieustannie modelują głębokość łowiska. Wiosną 2026 roku te płytkie, dobrze nasłonecznione strefy stają się magnesem dla poszukujących owadów jelców oraz pierwszych tegorocznych jazi. Spinningiści z uwagą prowadzą na płytkiej wodzie niewielkie cykady, kusząc drapieżniki ustawione na krawędzi opadającego stoku przykosy. Wędkarze stosujący lekkie zestawy feederowe z cienkimi przyponami wypracowują tu kapitalne wyniki, odławiając dorodne płocie i krąpie z głównego koryta. Malownicza łąkowa sceneria, pozbawiona wysokich przeszkód drzewnych, tworzy komfortowe warunki do precyzyjnego lokowania zestawów na dowolnej odległości.', null);

