-- Spot 090: Wkra - Giełczynek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71090, 'Wkra - Giełczynek', 'wkra-gielczynek', 'RIVER', 52.9095706, 20.2273695, 'Mazowieckie', 'Strzegowo', 'Wkra w Giełczynku zamyka górno-środkowy odcinek rzeki, prezentując piękny, meandrujący profil wyżłobiony głęboko w okolicznych gliniastych glebach. Zewnętrzne łuki rzeki kryją pod wodą głębokie, ponaddwumetrowe rynny erozyjne o twardym dnie, które stanowią bezpieczny azyl dla największych kleni. To świetne stanowisko dla wędkarzy preferujących aktywny spinning, precyzyjnie operujących woblerami w wąskich pasach wolniejszej wody pod samym brzegiem. W marcu 2026 roku stacjonarni łowcy stosują tu taktykę grubego nęcenia w dołkach, celując w solidne rzeczne leszcze i certy. Uciąg na prostych odcinkach pomiędzy zakrętami bywa bardzo żywy, świetnie natleniając rzekę i potęgując waleczność zaciętych tu ryb. Naturalna dzikość rzeki połączona z twardym, gliniastym podłożem tworzy łowisko idealne dla najbardziej wymagających, technicznych poszukiwaczy rzecznych trofeów.', null);

