-- Spot 091: Wkra - Strzegowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71091, 'Wkra - Strzegowo', 'wkra-strzegowo', 'RIVER', 52.8906168, 20.2796227, 'Mazowieckie', 'Strzegowo', 'Odcinek Wkry w Strzegowie charakteryzuje się dość szerokim korytem z naprzemiennie występującymi płyciznami i głębszymi, ponaddwumetrowymi rynnami. Dno jest tu piaszczysto-żwirowe, co wczesną wiosną przyciąga stada jazi i płoci szukających dobrze natlenionej wody przed tarłem. Wędkarze spławikowi z sukcesami stosują tu metodę bolońską, wypuszczając zestawy na długich dystansach wzdłuż warkoczy prądowych. Spinningiści w marcu 2026 roku regularnie punktują tu okazałe klenie, prowadząc niewielkie woblery baryłkowate tuż przy podmytych brzegach. Uciąg na prostkach jest umiarkowany, co pozwala na bardzo precyzyjne nęcenie punktowe zanętą z dużą domieszką gliny wiążącej. Bliskość mostów i infrastruktury miejskiej sprawia, że jest to doskonałe, bezpieczne łowisko na rozpoczęcie rzecznego sezonu.', null);

