-- Spot 092: Wkra - Giżynek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71092, 'Wkra - Giżynek', 'wkra-gizynek', 'RIVER', 52.8568304, 20.3001774, 'Mazowieckie', 'Strzegowo', 'Wkra w rejonie Giżynka powraca do swojej dzikiej, roztokowej natury z dużą ilością zwalonych pni olszowych i wierzbowych. Podłoże jest mocno zróżnicowane, twardy jasny piasek w nurcie głównym sąsiaduje z pasami osadów organicznych naniesionych w zakolach. To strategiczne terytorium dla łowców wczesnowiosennych szczupaków, które w wciąż zimnej wodzie wyczekują ofiar w cieniu zatopionych gałęzi. Wędkarze gruntowi łowiący na lekki picker wyciągają z głębszych dołków dorodne leszcze i krąpie gromadzące się w cieplejszych zastoiskach. W marcu 2026 roku wyjątkowo wysoka przejrzystość wody wymusza na spinningistach stosowanie długich, cienkich przyponów z fluorocarbonu. Izolacja terenu od głównych szos gwarantuje absolutną ciszę, pozwalającą na pełne skupienie przy technicznym, pieszokowym łowieniu.', null);

