-- Spot 093: Wkra - Glinojeck
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71093, 'Wkra - Glinojeck', 'wkra-glinojeck', 'RIVER', 52.823498, 20.27755, 'Mazowieckie', 'Glinojeck', 'Przepływając przez Glinojeck, Wkra zostaje częściowo ujęta w techniczne ramy regulacji, z umocnieniami brzegowymi i betonowymi przepustami. Poniżej dawnych struktur hydrotechnicznych tworzą się głębokie, mocno natlenione baseny o bardzo twardym, kamienisto-żwirowym dnie. Jest to wymarzone miejsce dla pasjonatów przepływanki, którzy w szybkim nurcie z sukcesami poławiają waleczne klenie i duże płocie. Spinningiści z uwagą obławiają krawędzie spowolnień prądowych, używając przeciążonych jigów do kuszenia ospałych w marcu 2026 roku okoni. Zmienny uciąg, dyktowany często pracą lokalnego jazu, zmusza łowców gruntowych do ciągłej rotacji gramaturą koszyków zanętowych. Utwardzone, miejskie nabrzeża pozwalają na wygodne rozstawienie kombajnów wyczynowych, czyniąc to miejsce doskonałym na profesjonalny trening.', null);

