-- Spot 094: Wkra - Ogonowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71094, 'Wkra - Ogonowo', 'wkra-ogonowo', 'RIVER', 52.7735415, 20.3182266, 'Mazowieckie', 'Glinojeck', 'Odcinek w Ogonowie to kraina łagodnych, bardzo rozległych zakoli rzecznych otoczonych łąkami i podmokłymi, wiosennymi terenami. Rzeka systematycznie podmywa tu strome, trawiaste burty, tworząc głębokie nawisy stanowiące bankowe schronienie dla ogromnych jazi. Wędkarze stosujący lekkiego feedera z długimi przyponami święcą tu wczesną wiosną triumfy, kusząc ryby na pęczki czerwonych robaków. Spinningiści w marcu 2026 roku muszą precyzyjnie operować najlżejszymi wahadłówkami w wąskich, płytkich rynnach biegnących środkiem piaszczystego koryta. Uciąg na szerokich płaniach wyraźnie wyhamowuje, co pozwala promieniom słonecznym szybko nagrzewać wodę i wybudzać pierwsze owady z dna. Ze względu na płaski charakter terenu, łowienie bywa tu trudne w wietrzne dni, wymagając od wędkarza obniżenia pozycji.', null);

