VALUES (71094, 'Nizinna', 'Meandrująca, łąkowa', 26.0, 1.4, 'Piasek', 'Podmyte trawy, zakola', 'Jaź, Płoć, Leszcz', 'Kraina leszcza', false);

-- Spot 095: Wkra - Płaciszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71095, 'Wkra - Płaciszewo', 'wkra-placiszewo', 'RIVER', 52.7511171, 20.364997, 'Mazowieckie', 'Glinojeck', 'Wisła w rejonie Płaciszewa płynie dynamicznie, napotykając na swojej drodze na zatopione konary i liczne twarde, żwirowe garby w korycie. Za każdą taką podwodną przeszkodą tworzą się klasyczne cienie prądowe, w których dno zapada się na głębokość ponad dwóch metrów. To absolutnie strategiczny punkt dla spinningistów łowiących z opadu, szukających szczupaków i okoni przyklejonych w marcu do samego dna. Fani spławika znajdują tu wyśmienite warunki do łowienia na przystawkę rzeczną, przytrzymując zestawy na granicy spokojnej i szybkiej wody. Uciąg jest tu niezwykle zróżnicowany, co sprawia, że woda jest doskonale natleniona, a przebywające w niej ryby reofilne walczą niezwykle zaciekle. Dostęp do wody bywa utrudniony przez gęste skupiska nadrzecznej roślinności, co jednak gwarantuje wysoki poziom wędkarskiej prywatności.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71095, 'Nizinna', 'Dzika, zatarasowana', 24.0, 1.7, 'Żwir i piasek', 'Zwalone drzewa, doły', 'Szczupak, Kleń, Okoń', 'Kraina brzany', false);

-- Spot 096: Wkra - Malużyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71096, 'Wkra - Malużyn', 'wkra-maluzyn', 'RIVER', 52.7419129, 20.4228348, 'Mazowieckie', 'Sochocin', 'Odcinek Wkry przepływający przez Malużyn to niezwykle urokliwa woda, łącząca fragmenty o bardzo szybkim nurcie z głębokimi, wręcz sennymi zastoiskami. Piaszczyste dno upstrzone jest w wielu miejscach wymytymi gliniastymi garbami, na których systematycznie zatrzymuje się niesiony rzeką naturalny pokarm. Dla wędkarzy gruntowych to w marcu 2026 roku jedno z najpewniejszych łowisk w poszukiwaniu budzących się po zimie stad dorodnych krąpi i leszczy. Spinningiści z pietyzmem obławiają tutejsze granice światłocienia rzucanego przez monumentalne, stare drzewa, w poszukiwaniu rzecznych kleni. Przepływ wody wymusza korzystanie ze średnio-ciężkich zestawów spławikowych, by precyzyjnie poprowadzić przynętę tuż nad samym dnem rynny. Malownicza okolica starych dworków i dzikiej przyrody sprawia, że Malużyn jest perłą dla każdego poszukiwacza nizinnego, wędkarskiego spokoju.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71096, 'Nizinna', 'Meandrująca, naturalna', 28.0, 1.5, 'Piasek i glina', 'Zastoiska, gliniaste garby', 'Krąp, Leszcz, Kleń', 'Kraina leszcza', false);

-- Spot 097: Wkra - Podsmardzewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71097, 'Wkra - Podsmardzewo', 'wkra-podsmardzewo', 'RIVER', 52.7078217, 20.442408, 'Mazowieckie', 'Sochocin', 'Wkra w rejonie Podsmardzewa rozszerza się, tocząc swoje wody szeroką, płaską doliną o dominującym, twardym piaszczystym dnie. Rzeka jest tu relatywnie płytka, a jej koryto pokrywają wędrujące przykosy, które załamują nurt i tworzą wspaniałe, natlenione przelewy. To idealne warunki dla rzecznych boleni i kleni, które w marcu 2026 roku stają się tu częstym łupem wędkarzy spinningujących małymi przynętami powierzchniowymi. Fani metody feederowej rozstawiają się na rozległych płaniach, posyłając zestawy w głębsze na nieco ponad metr rynienki rzeźbione w piasku. Uciąg jest stabilny, a woda nagrzewa się szybko, co prowokuje ryby do wcześniejszej, wzmożonej aktywności wiosennej. Łagodne zejścia do wody i otwarty brzeg ułatwiają operowanie długimi wędkami, tworząc świetne warunki do rodzinnego wędkowania.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71097, 'Nizinna', 'Szeroka, płytka', 32.0, 1.1, 'Piasek', 'Przykosy, przelewy', 'Kleń, Boleń, Jaź', 'Kraina brzany', false);

-- Spot 098: Wkra - Sochocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71098, 'Wkra - Sochocin', 'wkra-sochocin', 'RIVER', 52.6760856, 20.4716061, 'Mazowieckie', 'Sochocin', 'Wisła w samym Sochocinie przyjmuje charakter rzeki lekko uregulowanej, z wyraźnie pogłębionym nurtem głównym biegnącym środkiem koryta. Dno jest twarde, piaszczysto-żwirowe, co przyciąga gatunki reofilne, poszukujące w marcu 2026 roku pożywienia w szybszym przepływie wody. Wędkarze spławikowi, stosując metodębolońską, wyciągają z rynien dorodne świnki i certy, przytrzymując mocno zestawy w nurcie. Spinningiści cenią ten odcinek za obecność solidnych okoni oraz szczupaków, które kryją się w spowolnieniach pod nielicznymi mostkami i przepustami. Z uwagi na wyczuwalny uciąg, wędkowanie z gruntu wymaga tu zastosowania koszyków o gramaturze co najmniej 40-50 gramów z kolcami stabilizującymi. Dogodny dojazd i bliskość punktów gastronomicznych czynią z Sochocina bardzo wygodną bazę na weekendowe manewry z wędką.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71098, 'Nizinna', 'Uregulowana miejska', 30.0, 1.8, 'Piasek i żwir', 'Rynna środkowa, mosty', 'Świnka, Certa, Okoń', 'Kraina brzany', false);

-- Spot 099: Wkra - Bolęcin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71099, 'Wkra - Bolęcin', 'wkra-bolecin', 'RIVER', 52.6513827, 20.5159339, 'Mazowieckie', 'Sochocin', 'Odcinek w Bolęcinie to fascynujący fragment dzikiej rzeki, meandrującej gwałtownie wśród łąk i zagajników, z podciętymi, stromymi burtami brzegowymi. Woda żłobi tu głębokie nawet na dwa i pół metra jamy, których gliniaste dno stanowi doskonałe schronienie dla odpoczywających drapieżników. Jest to rejon niezwykle ceniony przez wytrawnych spinningistów, tropiących w marcu 2026 roku wielkie, rzeczne szczupaki kryjące się w cieniu nawisów trawiastych. Wędkarze stacjonarni podają w głębokie doły zestawy z pęczkiem czerwonych robaków, z sukcesami polując na zimujące jeszcze stada potężnych leszczy. Prowadzenie zestawów w tych warunkach wymaga zegarmistrzowskiej precyzji, by uniknąć splątania o zatopione, niewidoczne z brzegu korzenie. Kameralny, dziki charakter łowiska sprawia, że rzadko spotyka się tu innych wędkarzy, co daje gwarancję niczym niezmąconego relaksu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71099, 'Nizinna', 'Dzika, strome burty', 25.0, 2.0, 'Glina i piasek', 'Głębokie jamy brzegowe', 'Szczupak, Leszcz, Kleń', 'Kraina leszcza', false);

-- Spot 100: Wkra - Szumlin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71100, 'Wkra - Szumlin', 'wkra-szumlin', 'RIVER', 52.6217094, 20.5497015, 'Mazowieckie', 'Joniec', 'Wisła w rejonie Szumlina uspokaja swój bieg, a jej koryto pokrywa grubsza warstwa osadów organicznych i drobnego piasku. Rzeka toczy się tu leniwie, a rozległe, płytkie blaty boczne stanowią pierwsze miejsce, które nagrzewa się w promieniach wczesnowiosennego słońca. W marcu 2026 roku to właśnie tutaj wędkujący metodą drgającej szczytówki odnotowują masowe brania pięknych jazi oraz budzących się do życia linów. Spinningiści czeszą płycizny najmniejszymi blaszkami w poszukiwaniu ospałych jeszcze okoni, prowadząc przynętę niemal w samym dnie. Brak silnego uciągu pozwala na łowienie bardzo finezyjnymi, cienkimi żyłkami, co diametralnie zwiększa ilość brań białorybu w krystalicznej wodzie. Rozległe pola i piękny starodrzew tworzą zaporę dla wiatru, czyniąc to łowisko niezwykle komfortowym na chłodne, wiosenne poranki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71100, 'Nizinna', 'Spokojna, leniwa', 28.0, 1.3, 'Piasek i muł', 'Mielizny, blaty', 'Jaź, Lin, Okoń', 'Kraina leszcza', false);

-- Spot 101: Wkra - Popielżyn Górny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71101, 'Wkra - Popielżyn Górny', 'wkra-popielzyn-gorny', 'RIVER', 52.6013561, 20.5989173, 'Mazowieckie', 'Joniec', 'Odcinek w Popielżynie Górnym charakteryzuje się szybszym przepływem wody przez piaszczysto-żwirowe rynny i bystrza otoczone malowniczym lasem sosnowym. Koryto zacieśnia się tu naturalnie, wymywając twarde struktury podłoża, za którymi natychmiast ustawiają się ryby prądolubne. Spinningiści uznają to miejsce za wczesnowiosenną ostoję pięknych kleni i jazi, które bezpardonowo atakują małe woblery puszczane w marcu 2026 w dryf. Spławikowcy używają tu cięższych, rzecznych bombek, by skutecznie przytrzymać zestaw w nurcie głównym i sprowokować do brania rzeczne płocie. Stabilny, silnie natleniony nurt gwarantuje, że ryby są tutaj wyjątkowo silne i sprawiają wiele trudności podczas holu na miękkim wędzisku. Piaszczyste skarpy i iglasty bór wokół tworzą swoisty mikroklimat, który urzeka każdego fana wędkarstwa podchodowego.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71101, 'Nizinna', 'Bystra, leśna', 22.0, 1.5, 'Żwir i piasek', 'Rynny torowe, bystrza', 'Kleń, Jaź, Płoć', 'Kraina brzany', false);

-- Spot 102: Wkra - Dobra Wola
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71102, 'Wkra - Dobra Wola', 'wkra-dobra-wola', 'RIVER', 52.569424, 20.6277504, 'Mazowieckie', 'Joniec', 'Wkra w Dobrej Woli prezentuje klasyczny krajobraz meandrującej rzeki równinnej z wysokimi burtami podmywanymi przez zewnętrzny, szybki łuk nurtu. Pod twardą, gliniastą burtą rzeka wymywa potężne wręcz jamy o głębokości do 3 metrów, które stanowią bezpieczne gniazda dla drapieżników. Wiosną 2026 roku z sukcesami łowi się tu okazałe szczupaki, celnie rzucając ciężkim jigiem pod sam nawis i obławiając uskok dna. Wędkarze gruntowi zasiadają na wewnętrznych, piaszczystych plażach, posyłając zestawy feederowe w główne koryto w poszukiwaniu krąpi i leszczy. Silny przepływ w strefie erozji bocznej wymaga precyzji, by zestaw nie został zepchnięty pod zwalone pnie zagrażające natychmiastowym zaczepem. Piękno dzikiej, nieujarzmionej przyrody rekompensuje tu trudny dojazd brzegiem i w pełni angażuje w zmagania z nadrzeczną roślinnością.', null);

