-- Spot 103: Wkra - Borkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71103, 'Wkra - Borkowo', 'wkra-borkowo', 'RIVER', 52.5512569, 20.6798635, 'Mazowieckie', 'Nasielsk', 'Przepływając przez rejon Borkowa, Wkra zbliża się powoli do strefy ujściowej, a jej koryto poszerza się, formując płytkie i rozległe rozlewiska. Dno w głównej mierze stanowi miałki piasek z pojawiającymi się na zakrętach żwirowymi łachami o urozmaiconym profilu wodnym. W marcu 2026 roku stają się one doskonałym terenem polowań dla spinningistów łowiących pierwsze bolenie uganiające się za ławicami uklei na przelewach. Dla zwolenników metody bolońskiej to prawdziwy plac zabaw, umożliwiający długie wypuszczanie spławika za stadem wielkich rzecznych płoci i świnek. Uciąg jest zbalansowany, jednak podczas wiosennych przyborów potrafi nanieść na dno ogromne ilości drobnych gałęzi wymuszających czujność zbrojenia haczyków. Otwarty teren ułatwia lokowanie dalekich rzutów, a relatywna bliskość Warszawy sprawia, że to łowisko jest niezwykle chętnie uczęszczane.', null);

