-- Spot 104: Wkra - Goławice Pierwsze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71104, 'Wkra - Goławice Pierwsze', 'wkra-golawice-pierwsze', 'RIVER', 52.5152288, 20.6824326, 'Mazowieckie', 'Pomiechówek', 'Odcinek w Goławicach Pierwszych to przedsionek ujścia rzeki, gdzie wyraźnie wyczuwalne stają się wahania wód z leżącej poniżej Narwi. Koryto zacieśnia się tu między twardymi skarpami, tworząc głęboką, regularną rynnę główną o dnie usianym żwirem i kamieniami. W marcu 2026 roku ten fragment staje się autostradą migracyjną dla ogromnych jazi oraz kleni wchodzących z wód Narwi na wiosenne żerowanie. Wędkarze operujący ciężkim rzecznym feederem nęcą skutecznie na krawędzi opadu, punktując dorodne krąpie oraz certy w najgłębszych strefach toru. Spinningiści bardzo często spotykają się tu z potężnymi atakami wczesnowiosennych szczupaków patrolujących strefy styku prądów za naturalnymi przeszkodami. Surowość wysokich burt i specyfika przedujściowej wody nakazują posiadanie solidnych podbieraków z długą sztycą, niezbędnych do lądowania trofeów.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71104, 'Nizinna', 'Głęboka, przedujściowa', 30.0, 2.3, 'Żwir i kamień', 'Głęboka rynna, skarpy', 'Jaź, Kleń, Certa', 'Kraina brzany', false);

-- Spot 105: Wkra - Pomiechówek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71105, 'Wkra - Pomiechówek', 'wkra-pomiechowek', 'RIVER', 52.4873885, 20.7200554, 'Mazowieckie', 'Pomiechówek', 'Wkra w Pomiechówku to spektakularny odcinek ujściowy, w którym dynamika mniejszej rzeki miesza się z potężną masą wód Narwi. W korycie pojawiają się wyżłobione przez potężne zawirowania rynny ujściowe, schodzące na twardym, piaskowym dnie do niemal 3 metrów głębokości. To absolutnie elitarne łowisko spinningowe, gdzie w marcu 2026 roku regularnie łowi się wspaniałe sandacze oraz gigantyczne, potorfowe szczupaki z Narwi. Wędkarze gruntowi walczą na tej wodzie z bardzo trudnymi uciągami zwrotnymi, stosując koszyki z wąsami i nęcąc stada pięknych, wiślano-narwiańskich leszczy. Drapieżniki intensywnie żerują tuż przy ujściu wykorzystując warkocze prądowe do dezorientacji migrujących w górę rzeki stad białorybu. Rozbudowana infrastruktura rekreacyjna ułatwia dostęp, czyniąc ten węzeł hydrologiczny fenomenalnym, całorocznym celem mazowieckich miłośników wędkarskiej przygody.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71105, 'Nizinna Wielka', 'Ujściowa, zawirowania', 40.0, 2.8, 'Piasek i kamień', 'Warkocz ujściowy, jamy', 'Sandacz, Szczupak, Leszcz', 'Kraina leszcza', true);

-- Spot 106: Wkra - Pomiechowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71106, 'Wkra - Pomiechowo', 'wkra-pomiechowo', 'RIVER', 52.4540539, 20.7451694, 'Mazowieckie', 'Pomiechówek', 'Wkra w Pomiechowie to głęboki, przedujściowy odcinek o relatywnie wolnym uciągu i piaszczysto-gliniastym dnie. Rzeka formuje tu szerokie zakola, w których woda zatrzymuje nanoszone osady, tworząc idealne warunki dla ryb spokojnego żeru. W marcu 2026 roku stada dorodnych leszczy i krąpi wchodzą tu z pobliskiej Narwi, szukając cieplejszej wody na płytkich blatach. Wędkarze gruntowi z powodzeniem stosują technikę klasycznego feedera z ciężarkami rzędu 40 gramów, nęcąc precyzyjnie w korycie głównym. Spinningiści obławiają strome, podmyte burty, wypatrując wczesnowiosennych szczupaków oraz potężnych jazi patrolujących strefy przybrzeżne. Łatwy dostęp do rzeki i bliskość aglomeracji warszawskiej czynią ten fragment niezwykle popularnym miejscem na rozpoczęcie sezonu.', null);

