-- Spot 107: Wkra - Malinowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71107, 'Wkra - Malinowo', 'wkra-malinowo', 'RIVER', 53.2382163, 20.2474735, 'Warmińsko-Mazurskie', 'Działdowo', 'Górny odcinek Wkry w Malinowie, znany lokalnie jako Działdówka, to wąska i bystra rzeka o wybitnie pstrągowym charakterze. Dno jest tu wyścielone grubym żwirem i kamieniami, a woda nawet wczesną wiosną zachowuje niezwykłą przejrzystość oraz wysokie natlenienie. W marcu 2026 roku to strategiczny rejon dla wędkarzy muchowych i przemieszczających się brzegiem spinningistów, którzy polują na pstrągi potokowe. Wymaga to precyzyjnego rzucania małymi woblerami lub nimfami w niewielkie luki między zwalonymi konarami i podmyciami brzegowymi. Uciąg jest tu dynamiczny, a ryby niezwykle płochliwe, co zmusza do podchodzenia do stanowisk w pełnym kamuflażu i zachowania absolutnej ciszy. Brak miejskiej infrastruktury i dzikie, leśno-łąkowe otoczenie gwarantują tu pełne odcięcie od cywilizacji i kontakt z surową naturą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71107, 'Górska/Podgórska', 'Wąska, bystra', 8.0, 0.8, 'Kamień i żwir', 'Zwalone drzewa, bystrza', 'Pstrąg potokowy, Kleń, Jelec', 'Kraina pstrąga', false);

-- Spot 108: Wkra - Kisiny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71108, 'Wkra - Kisiny', 'wkra-kisiny', 'RIVER', 53.2297277, 20.1889737, 'Warmińsko-Mazurskie', 'Działdowo', 'Wkra przepływająca przez Kisiny to urokliwy, meandrujący strumień o urozmaiconym dnie, w którym żwirowe płycizny przeplatają się z metrowymi rynnami. Koryto zacieśnia się tu pośród łąk, tworząc naturalne bystrza dotleniające wodę, co stwarza świetne warunki dla reofilnych gatunków ryb. To doskonałe łowisko dla fanów ultralekkiego spinningu, którzy w marcu 2026 roku z sukcesami kuszą klenie małymi, smużącymi przynętami. Wędkarze spławikowi stosują tu lekką przepływankę, posyłając zestawy w rynny za zakrętami w poszukiwaniu dorodnych, wiosennych płoci. Krystaliczna, zimna woda zmusza do stosowania żyłek o niewielkiej średnicy, ponieważ grube przypony natychmiast płoszą ostrożne ryby. Meandrujący charakter rzeki na tym otwartym terenie pozwala na wygodne planowanie taktyki i szybkie zmienianie obławianych miejscówek.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71108, 'Podgórska/Nizinna', 'Meandrująca, łąkowa', 10.0, 1.0, 'Żwir i piasek', 'Bystrza, zakola', 'Kleń, Płoć, Jelec', 'Kraina pstrąga', false);

-- Spot 109: Wkra - Zakrzewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71109, 'Wkra - Zakrzewo', 'wkra-zakrzewo', 'RIVER', 53.1958799, 20.1668836, 'Warmińsko-Mazurskie', 'Działdowo', 'Odcinek w Zakrzewie to dzika, zarośnięta część rzeki, gdzie nurt wyraźnie zwalnia, a koryto zaczyna pokrywać warstwa piasku i drobnego mułu. Rzeka rzeźbi tu strome, niedostępne burty, tworząc głębokie doły będące bankowymi kryjówkami dla wyrośniętych szczupaków i okoni. W marcu 2026 roku łowienie wymaga użycia przynęt silikonowych na lekkich główkach jigowych, by precyzyjnie spenetrować wymyte w dnie rynny. Wędkarze stacjonarni z powodzeniem łowią tu dorodne jazie, nęcąc strefy przybrzeżne za pomocą klasycznych, koszyczkowych zestawów gruntowych. Spokojniejszy uciąg wody sprzyja szybszemu nagrzewaniu się płycizn, na których w bezwietrzne dni widać pierwsze oznaki powierzchniowego żerowania białorybu. Zwarta roślinność brzegowa i liczne zatopione gałęzie stanowią duże wyzwanie techniczne, wymagające od łowiących sporej celności.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71109, 'Nizinna', 'Zarośnięta, głęboczki', 12.0, 1.4, 'Piasek i muł', 'Podmyte burty, zatory', 'Szczupak, Jaź, Okoń', 'Kraina brzany', false);

-- Spot 110: Wkra - Gnojenko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71110, 'Wkra - Gnojenko', 'wkra-gnojenko', 'RIVER', 53.1919224, 20.1046966, 'Warmińsko-Mazurskie', 'Działdowo', 'Wkra w rejonie Gnojenka to urokliwy, leśny odcinek o twardym, piaszczysto-żwirowym podłożu i umiarkowanym uciągu. Rzeka formuje tu liczne łachy i przelewy, za którymi woda natychmiast zapada się w ciemne, dotlenione rynny o znacznej głębokości. Spinningiści traktują to miejsce jako doskonały poligon do łowienia kleni, precyzyjnie obławiając warkocze prądowe za naturalnymi przeszkodami w nurcie. W marcu 2026 roku stacjonarni wędkarze świetnie radzą sobie z użyciem method feedera, polując na rzeczne leszcze i grube krąpie. Z uwagi na dużą ilość zatopionych korzeni i zwalonych olch, konieczne jest szybkie i siłowe odciąganie zaciętych ryb od zaczepów. Brak presji wędkarskiej i gęsty las otaczający koryto sprawiają, że to łowisko jest niezwykle ciche i bogate w dziką zwierzynę.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71110, 'Nizinna', 'Leśna, piaszczysta', 14.0, 1.3, 'Piasek i żwir', 'Zwalone drzewa, łachy', 'Kleń, Leszcz, Krąp', 'Kraina brzany', false);

-- Spot 111: Wkra - Gródki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71111, 'Wkra - Gródki', 'wkra-grodki', 'RIVER', 53.2150037, 20.0309819, 'Warmińsko-Mazurskie', 'Działdowo', 'Odcinek rzeki w Gródkach charakteryzuje się dość bystrym nurtem, rzeźbiącym w gliniasto-piaszczystym dnie głębokie rynny pod brzegami. Wkra w tym miejscu mocno meandruje, a na jej zewnętrznych zakrętach tworzą się idealne strefy żerowania dla wczesnowiosennych jazi. Spinningiści z sukcesami penetrują te odcinki małymi cykadami oraz woblerami, szukając drapieżników na styku szybkiej i spokojnej wody. W marcu 2026 roku stada płoci i cert gromadzą się tu w osłoniętych od głównego prądu zatoczkach, dając świetne wyniki wędkarzom spławikowym. Dynamiczny przepływ wody doskonale natlenia łowisko, co bezpośrednio przekłada się na ogromną waleczność ryb reofilnych podczas holu. Ze względu na wysokie i śliskie skarpy brzegowe, operowanie podbierakiem wymaga tu dużej ostrożności i posiadania długiej sztycy.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71111, 'Nizinna', 'Meandrująca, gliniasta', 15.0, 1.5, 'Glina i piasek', 'Rynny brzegowe, skarpy', 'Jaź, Płoć, Certa', 'Kraina brzany', false);

-- Spot 112: Wieprz - Zwierzyniec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71112, 'Wieprz - Zwierzyniec', 'wieprz-zwierzyniec', 'RIVER', 50.6111572, 22.9874573, 'Lubelskie', 'Zwierzyniec', 'Wieprz w Zwierzyńcu to krystalicznie czysta rzeka przecinająca serce Roztoczańskiego Parku Narodowego, charakteryzująca się bystrym nurtem. Piaszczysto-kamieniste dno poprzecinane jest tu licznymi płyciznami oraz głębokimi rynnami podmywającymi zalesione burty. W marcu 2026 roku jest to elitarne łowisko dla wędkarzy muchowych poszukujących dzikich pstrągów potokowych i lipieni. Spinningiści z powodzeniem obławiają zwalone do wody drzewa, precyzyjnie prowadząc niewielkie woblery imitujące narybek. Silny uciąg świetnie natlenionej wody wymusza stosowanie nierzucających się w oczy, cienkich przyponów fluorocarbonowych. Malownicze otoczenie gęstych lasów i rygorystyczne przepisy ochronne tworzą tu prawdziwą mekkę dla łowców ryb szlachetnych.', null);

