-- Spot 113: Wieprz - Żurawnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71113, 'Wieprz - Żurawnica', 'wieprz-zurawnica', 'RIVER', 50.6504632, 22.9529655, 'Lubelskie', 'Zwierzyniec', 'Odcinek w Żurawnicy charakteryzuje się licznymi meandrami o piaszczystym dnie i stromych, gliniastych brzegach porastających trawą. Rzeka wyraźnie tu zwalnia, tworząc głębsze na ponad dwa metry doły na zewnętrznych zakrętach koryta. To doskonałe miejsce dla wędkarzy przepływankowych, którzy wczesną wiosną kuszą tu dorodne płocie i jelce poszukujące pokarmu. Spinningiści cenią ten fragment za liczne kryjówki kleniowe, rzucając małe smużaki pod nawisy trawiastych burt. W marcu 2026 roku niska presja wędkarska oraz dzikość otoczenia pozwalają na niezwykle ciche i skupione łowienie. Przejrzysta po zimie woda wymaga ostrożnego stąpania po brzegu, aby nie spłoszyć przebywających na płyciznach ryb.', null);

