-- Spot 114: Wieprz - Szczebrzeszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71114, 'Wieprz - Szczebrzeszyn', 'wieprz-szczebrzeszyn', 'RIVER', 50.6922372, 22.9792464, 'Lubelskie', 'Szczebrzeszyn', 'Wieprz w okolicy Szczebrzeszyna to urokliwa, równinna rzeka o umiarkowanym uciągu i niezwykle zróżnicowanym, piaszczysto-żwirowym korycie. Pod twardymi burtami wymyte są tu regularne rynny, które stają się idealnymi miejscami żerowania okazałych świnek i kleni. Wędkarze stacjonarni stosują tu z sukcesem lekkie feedery, podając pęczki czerwonych robaków w marcu 2026 roku głodnym rybom. Spinningiści obławiają nieliczne mostki i twardsze przelewy żwirowe w poszukiwaniu wczesnowiosennych szczupaków uaktywniających się na słońcu. Rzeka niesie tu sporo naturalnego pokarmu, co przyciąga z dolnego biegu grube stada wędrujących jazi. Dostępne brzegi i łagodne zejścia do wody czynią to miejsce komfortowym na dłuższe, weekendowe zasiadki.', null);

