-- Spot 115: Wieprz - Liszno-Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71115, 'Wieprz - Liszno-Kolonia', 'wieprz-liszno-kolonia', 'RIVER', 51.0978262, 23.0620593, 'Lubelskie', 'Trawniki', 'Odcinek w Lisznie-Kolonii reprezentuje dziki charakter środkowego Wieprza, pełen zwalonych drzew i nieuregulowanych, zarośniętych brzegów. Koryto zacieśnia się tu między łąkami, przyspieszając nurt i wymywając w piaszczystym dnie głębokie, strome wanny. To strategiczny rejon dla łowców wczesnowiosennych szczupaków, które wyczekują ofiar w spokojniejszych wstecznych prądach za zatorami. W marcu 2026 roku stacjonarni łowcy białorybu notują świetne wyniki, łowiąc leszcze na styku szybkiej i wolnej wody. Skomplikowana budowa dna wymaga od spinningistów precyzyjnego prowadzenia gum na lekkich główkach, by uniknąć trudnych do uwolnienia zaczepów. Izolacja i brak utwardzonych dróg dojazdowych sprawiają, że można tu cieszyć się pełną prywatnością i dziką naturą.', null);

