-- Spot 116: Wieprz - Krasnystaw
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71116, 'Wieprz - Krasnystaw (Południe)', 'wieprz-krasnystaw-poludnie', 'RIVER', 50.9697112, 23.176075, 'Lubelskie', 'Krasnystaw', 'Wieprz powyżej Krasnegostawu płynie szeroką doliną, tworząc malownicze, płytkie przelewy na twardym, gliniasto-piaszczystym dnie. Rzeka jest tu stosunkowo płytka, ale na łukach formuje techniczne dwumetrowe rynny, idealne do utrzymania większych ryb. Spinningiści łowią tu piękne okazy kleni, wypuszczając z prądem małe, pływające woblery tuż pod zarośnięte brzegi. W marcu 2026 roku woda szybko nagrzewa się na płyciznach, przyciągając pierwsze w sezonie, aktywnie żerujące stada jazi. Wędkarze używający przepływanki skutecznie poławiają tu płocie i krąpie, nęcąc wąską ścieżkę w rynnie głównego nurtu. Wygodne łąkowe brzegi ułatwiają operowanie długimi wędziskami, czyniąc ten odcinek wyjątkowo komfortowym i produktywnym wędkarsko.', null);

