VALUES (71116, 'Nizinna', 'Płytka, nasłoneczniona', 25.0, 1.4, 'Glina i piasek', 'Mielizny, rynny na łukach', 'Jaź, Kleń, Płoć', 'Kraina brzany', false);

-- Spot 117: Wieprz - Krasnystaw (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71117, 'Wieprz - Krasnystaw (Północ)', 'wieprz-krasnystaw-polnoc', 'RIVER', 51.0129686, 23.1563354, 'Lubelskie', 'Krasnystaw', 'Północny odcinek Wieprza w Krasnymstawie charakteryzuje się bardziej zrównoważonym, nierzadko uregulowanym brzegiem i stabilną głębokością koryta. Dno jest tu piaszczyste, z wyraźnymi rynnami pod prądowymi burtami, w których woda niesie dużo naturalnego pokarmu. Wiosną 2026 roku to jedno z najpewniejszych miejsc na złowienie dorodnego leszcza techniką klasycznego, rzecznego feedera. Spinningiści patrolują miejskie opaski i umocnienia, szukając aktywnych szczupaków i wyrośniętych okoni wybudzonych po zimie. Równomierny uciąg rzeki pozwala na budowanie precyzyjnych punktów nęcenia z dużą ilością dociążającej gliny rzecznej. Bliskość miejskiej infrastruktury przyciąga tu wielu pasjonatów krótkich wędkarskich wypadów po pracy z lekkim sprzętem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71117, 'Nizinna', 'Miejska, uregulowana', 28.0, 1.8, 'Piasek i glina', 'Opaski, rynny brzegowe', 'Leszcz, Szczupak, Okoń', 'Kraina leszcza', false);

-- Spot 118: Wieprz - Stężyca Łęczyńska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71118, 'Wieprz - Stężyca Łęczyńska', 'wieprz-stezyca-leczynska', 'RIVER', 51.0529476, 23.123061, 'Lubelskie', 'Krasnystaw', 'Wieprz w Stężycy Łęczyńskiej silnie meandruje wśród podmokłych łąk, wycinając pod wysokimi brzegami potężne, gliniaste jamy. Rzeka toczy tu znaczne ilości wypłukanego piasku, budując dynamiczne przykosy, za którymi woda gwałtownie przyspiesza. To doskonałe łowisko dla wędkarzy gruntowych, poszukujących w marcu 2026 r. tłustych krąpi i leszczy w głębokich zakolach. Wędkarze spinningowi z zaangażowaniem obławiają uskoki dna na krawędzi łach w poszukiwaniu czatujących tam szczupaków i sandaczy. Zróżnicowana hydrologia wymaga umiejętnego czytania rzeki, aby trafnie odróżnić płytki, martwy blat od tętniącej życiem rynny. Odcinek ten słynie ze swojej naturalnej, nieokiełznanej formy i oferuje wybitne wrażenia dla łowców dzikich, rzecznych trofeów.', null);

