-- Spot 119: Wieprz - Trawniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71119, 'Wieprz - Trawniki', 'wieprz-trawniki', 'RIVER', 51.1351297, 23.0090163, 'Lubelskie', 'Trawniki', 'Wkra w Trawnikach staje się rzeką o dużej objętości wód, płynącą głębokim korytem z wyraźnie zaznaczonym torem wodnym. Dno pokrywa zwarta glina przemieszana z piaskiem, co zapobiega erozji i tworzy doskonałe warunki dla ryb typowo nizinnych. To elitarne miejsce do połowu wczesnowiosennych brzan, które w marcu zajmują stanowiska w centralnych, najszybszych rynnach rzeki. Spinningiści notują tu świetne wyniki, przeczesując ciężkimi jigami krawędzie dna w poszukiwaniu stacjonarnych sandaczy. Wędkarze łowiący z gruntu używają koszyczków z wąsami o gramaturze ponad 60 gramów, by utrzymać przynętę w mocnym nurcie. Dobry dojazd i otwarte brzegi pozwalają na bezpieczne i skuteczne łowienie w niezwykle pięknej, rzecznej scenerii.', null);

