-- Spot 120: Wieprz - Siostrzytów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71120, 'Wieprz - Siostrzytów', 'wieprz-siostrzytow', 'RIVER', 51.1769206, 22.9823419, 'Lubelskie', 'Trawniki', 'Odcinek Wieprza w Siostrzytowie to mozaika szybkich przelewów i głębokich, spokojniejszych zakoli rzeźbionych w piaszczystym podłożu. Rzeka napotyka tu na nieliczne zwaliska starych wierzb, które skutecznie hamują główny prąd i tworzą bezpieczne tarliska dla białorybu. Wędkarze używający spławikowych bolonek potrafią w marcu 2026 wypracować w tych strefach piękne siatki pełne grubych płoci i jazi. Dla spinningistów to teren pełen zagadek, w którym kluczem jest celne wrzucenie gumowej przynęty tuż za zatopiony korzeń w poszukiwaniu szczupaka. Miejscami woda osiąga głębokość przekraczającą 2.5 metra, co ułatwia utrzymanie zimujących wciąż ryb tuż przy dnie. Dzika i nieprzewidywalna linia brzegowa oferuje mnóstwo małych, klimatycznych głęboczków do kameralnego wędkowania.', null);

