-- Spot 121: Wieprz - Jaszczów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71121, 'Wieprz - Jaszczów', 'wieprz-jaszczow', 'RIVER', 51.2130505, 22.9395805, 'Lubelskie', 'Milejów', 'Wieprz w Jaszczowie płynie szeroko i leniwie, a jego dno pokryte jest większą ilością namułów na krawędziach wewnętrznych zakrętów. Przyspieszenia nurtu można spotkać jedynie w wyżłobionych w twardej glinie rynnach zlokalizowanych przy samych wysokich burtach brzegowych. Wczesną wiosną 2026 to kluczowy punkt na mapie łowców dorodnych linów oraz karasi chętnie żerujących w nagrzewających się, płytkich zatokach. Spinningiści namierzają tutaj pierwsze aktywne okonie oraz szczupaki, wykorzystując błystki obrotowe wolno prowadzone tuż nad dnem. Ze względu na znaczną szerokość koryta, wędkarze feederowi zmuszeni są do precyzyjnych i dalekich rzutów pod przeciwny brzeg rzeki. Okolica charakteryzuje się malowniczym, rolniczym krajobrazem, gwarantując ciszę i brak nadmiernej presji ze strony wielkich aglomeracji.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71121, 'Nizinna', 'Spokojna, szeroka', 40.0, 1.9, 'Glina i muł', 'Wysokie burty, zatoki', 'Lin, Szczupak, Karaś', 'Kraina leszcza', false);

-- Spot 122: Wieprz - Łańcuchów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71122, 'Wieprz - Łańcuchów', 'wieprz-lancuchow', 'RIVER', 51.2581575, 22.9412472, 'Lubelskie', 'Milejów', 'Łowisko na Wieprzu w Łańcuchowie stanowi znakomity przykład dzikiej, meandrującej rzeki o stromych i wysokich brzegach gliniastych. Woda rzeźbi pod tymi skarpami ekstremalnie głębokie rynny, a zatopione w nich pnie drzew to legendarne siedliska rzecznych sumów i potężnych sandaczy. W marcu 2026 spinningiści używają bardzo ciężkich jigów, by sprowadzić przynętę na głębokość 3 metrów w sam środek wymytej dziury. Fani feedera i mocnej gruntówki skutecznie poławiają tu duże rzeczne leszcze i certy, przyklejone do dna w strefach wolnego przepływu. Mimo pozornego spokoju, uciąg w głównym nurcie jest bardzo wymagający i nierzadko tworzy trudne do obłowienia prądy wsteczne. Nienaruszony ekosystem koryta sprawia, że każda zasiadka w Łańcuchowie to wędkarska przygoda pełna dzikich niespodzianek.', null);

