VALUES (71122, 'Nizinna', 'Erozyjna, głęboka', 35.0, 2.5, 'Glina i żwir', 'Strome skarpy, pnie', 'Sum, Sandacz, Leszcz', 'Kraina brzany', false);

-- Spot 123: Wieprz - Zakrzów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71123, 'Wieprz - Zakrzów', 'wieprz-zakrzow', 'RIVER', 51.2808399, 22.8789872, 'Lubelskie', 'Łęczna', 'Odcinek Wieprza w Zakrzowie to piękna, szeroka woda płynąca w otoczeniu rozległych łąk i malowniczych, rzadkich zagajników. Dno rzeki wysłane jest twardym, drobnym piaskiem, uformowanym przez nurt w długie na kilkadziesiąt metrów przykosy i łagodne stoki. To rejon uwielbiany w marcu przez łowców widowiskowych rzecznych kleni, które dają się skusić z powierzchni na delikatnie podane smużaki. Zwolennicy wędkarstwa spławikowego znajdą tu wymarzone tory do przepływanki, z powodzeniem nęcąc stadne płocie oraz świnki stacjonujące za przykosami. Brak zwalonych drzew ułatwia hol dużych ryb, ale wymusza poszukiwanie cieni prądowych i minimalnych uskoków piaszczystego dna. Teren jest wysoce dostępny i świetnie nasłoneczniony, co sprzyja wczesnemu, wiosennemu nagrzewaniu się płycizn brzegowych.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71123, 'Nizinna', 'Szeroka, łąkowa', 40.0, 1.6, 'Piasek', 'Rozległe przykosy', 'Kleń, Płoć, Świnka', 'Kraina brzany', false);

-- Spot 124: Wieprz - Łęczna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71124, 'Wieprz - Łęczna', 'wieprz-leczna', 'RIVER', 51.3200464, 22.843472, 'Lubelskie', 'Łęczna', 'Miejsko-podmiejski odcinek Wieprza w Łęcznej to woda o uregulowanych w części brzegach, wzmocnionych betonowo-kamiennymi opaskami. Pomiędzy umocnieniami nurt wyrzeźbił twarde, bardzo głębokie rynny na środku koryta, do których przylegają płytkie, piaszczyste zatoczki. Wędkarze łowiący z gruntu w marcu 2026 świetnie radzą sobie tu przy pomocy ciężkich feederów rzecznych, polując na kapitalne leszcze. Ze względu na sztuczne zwężenia i bystrza, w wodzie znakomicie czują się również drapieżniki takie jak boleń i wczesnowiosenny szczupak. Uciąg potrafi tu mocno zaskoczyć swoją siłą, wymuszając montowanie koszyczków zanętowych o masie od 60 do 80 gramów. Uporządkowany brzeg i bliskość zabudowań miejskich zapewniają bardzo dużą wygodę dla krótkich, popołudniowych wypadów nad rzekę.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71124, 'Nizinna', 'Uregulowana, bystra', 38.0, 2.0, 'Kamień i piasek', 'Opaski kamienne, bystrza', 'Leszcz, Boleń, Szczupak', 'Kraina leszcza', false);

-- Spot 125: Wieprz - Kijany Kościelne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71125, 'Wieprz - Kijany Kościelne', 'wieprz-kijany-koscielne', 'RIVER', 51.3384823, 22.7773057, 'Lubelskie', 'Łęczna', 'Wieprz w Kijanach Kościelnych to niezwykle widowiskowy odcinek rzeki pełen stromych i piaszczystych skarp, schodzących gwałtownie do nurtu. Woda wymywa tam głębokie doły dochodzące do 3 metrów głębokości o dnie z przewagą zbitej, ciemnej gliny wymieszanej z rzecznym żwirem. To bankowe miejsca na grube wiosenne sandacze, które w marcu bardzo powoli wychodzą ze swoich głębokich, podbrzegowych kryjówek. Wędkarze używający gruntówek z klasycznym koszykiem systematycznie łowią tutaj wyrośnięte brzany, stawiające ogromny opór w wartkim prądzie koryta. Konieczność pokonania wysokich burt sprawia, że lądowanie wyholowanej ryby wymaga tu bezwzględnie wyposażenia w długą, mocną sztycę podbieraka. Majestatyczna okolica i surowa natura rzeki obmywającej wysokie skarpy potęgują wędkarskie wrażenia z każdej spędzonej tu chwili.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71125, 'Nizinna', 'Erozyjna, wysokie skarpy', 42.0, 2.4, 'Glina i żwir', 'Głębokie wanny pod skarpą', 'Sandacz, Brzana, Leszcz', 'Kraina brzany', false);

-- Spot 126: Wieprz - Górka Lubartowska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71126, 'Wieprz - Górka Lubartowska', 'wieprz-gorka-lubartowska', 'RIVER', 51.5120738, 22.6375237, 'Lubelskie', 'Lubartów', 'Odcinek w Górce Lubartowskiej stanowi doskonały przykład dolnego, mocno roztokowego biegu Wieprza z masą naniesionych piasków. Rzeka gwałtownie się tu poszerza, a nurt wypłyca, napędzając nieustanną wędrówkę zjawiskowych, podwodnych wydm oraz obszernych mielizn brzegowych. Z nastaniem pierwszych cieplejszych dni marca 2026 płycizny te przyciągają stada drobnicy, a w ślad za nimi ogromne rzeczne bolenie. Wędkarze gruntowi odnajdują w rynienkach wyżłobionych pomiędzy łachami pewne stanowiska przebywania dorodnych krąpi i wielkich jazi. Czyste dno ułatwia operowanie delikatnymi wędkami o niskim ciężarze wyrzutowym, a niewielki uciąg powala na doskonałą kontrolę zestawu spławikowego. Szeroka dolina i niezakłócona przestrzeń otaczająca koryto stanowią ostateczny dowód na niepowtarzalny urok wędkowania na dzikim Wieprzu.', null);

