-- Spot 127: Wieprz - Leszkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71127, 'Wieprz - Leszkowice', 'wieprz-leszkowice', 'RIVER', 51.5499123, 22.5970545, 'Lubelskie', 'Lubartów', 'Wieprz w Leszkowicach to szeroka, meandrująca rzeka nizinna o piaszczystym korycie poprzecinanym licznymi zwalonymi drzewami. Silny nurt na zewnętrznych łukach wymywa twarde, gliniaste burty, pod którymi tworzą się rynny o głębokości przekraczającej dwa metry. To doskonałe miejsce dla wędkarzy łowiących na przepływankę, którzy w marcu 2026 roku regularnie punktują tu dorodne jazie i klenie. Spinningiści przeczesują najgłębsze doły ciężkimi jigami, polując na rzeczne sandacze i ospałe jeszcze po zimie szczupaki. Uciąg wody wymaga zastosowania koszyków zanętowych o masie od 50 do 70 gramów, aby stabilnie utrzymać zestaw na krawędzi prądu. Malowniczy, dziki krajobraz pradoliny Wieprza sprawia, że jest to jedno z najpiękniejszych łowisk dolnego biegu rzeki.', null);

