-- Spot 128: Wieprz - Czerniejów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71128, 'Wieprz - Czerniejów', 'wieprz-czerniejow', 'RIVER', 51.3987932, 22.7004036, 'Lubelskie', 'Lubartów', 'Odcinek w Czerniejowie charakteryzuje się licznymi wypłyceniami i piaszczystymi łachami, pomiędzy którymi woda rzeźbi wąskie, dotlenione warkocze prądowe. Dno składa się w głównej mierze z drobnego piasku i osadów organicznych gromadzących się w spowolnieniach za wewnętrznymi zakrętami koryta. Wiosną 2026 roku te płytkie, nasłonecznione strefy przyciągają stada białorybu, co stanowi idealną okazję dla wędkarzy operujących lekkim feederem. Spinningiści obławiają obficie zarośnięte latem brzegi, poszukując pierwszych aktywnych okoni oraz niewielkich boleni na granicy płycizn i rynien. Precyzyjne podanie zestawu w węższe strefy głębszej wody jest tu kluczem do odłowienia grubych, wędrujących pod prąd rzecznych płoci. Rozległe przestrzenie łąkowe gwarantują wygodne rozstawienie sprzętu i brak problemów z operowaniem bardzo długimi wędkami.', null);

