-- Spot 129: Wieprz - Łucka-Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71129, 'Wieprz - Łucka-Kolonia', 'wieprz-lucka-kolonia', 'RIVER', 51.4331789, 22.653596, 'Lubelskie', 'Lubartów', 'Wieprz w rejonie miejscowości Łucka-Kolonia płynie urokliwymi meandrami, podmywając strome skarpy i odsłaniając pokłady twardej, zbitej gliny. Te erozyjne rynny, sięgające niekiedy niemal trzech metrów głębokości, stanowią doskonałe, wczesnowiosenne zimowiska dla rzecznych leszczy i potężnych brzan. Wędkarze stacjonarni stosują tu ciężkie zestawy gruntowe z długimi przyponami, by zaprezentować pęczek czerwonych robaków bezpośrednio w rynnie torowej. Spinningiści muszą wykazać się precyzją, prowadząc cięższe wahadłówki lub gumy wzdłuż samego dna, omijając liczne, zatopione w nurcie korzenie. W marcu 2026 roku uciąg rzeki w tym miejscu jest wybitnie silny, co wymusza posiadanie zapasu ciężkich koszyków z pazurami. Dziki i nieustannie zmieniający się charakter brzegów gwarantuje, że po każdej zimie łowisko trzeba czytać i odkrywać na nowo.', null);

