-- Spot 130: Wieprz - Wola Skromowska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71130, 'Wieprz - Wola Skromowska', 'wieprz-wola-skromowska', 'RIVER', 51.6119752, 22.4587414, 'Lubelskie', 'Kock', 'Odcinek Wieprza przepływający przez Wolę Skromowską to szeroka woda o umiarkowanym uciągu i niezwykle piaszczystym, ruchomym dnie. Rzeka formuje tu potężne przykosy, za którymi woda gwałtownie przyspiesza i dotlenia się, stwarzając wyśmienite stanowiska dla drapieżników. To absolutnie topowe łowisko dla łowców wczesnowiosennych boleni, które w marcu 2026 roku intensywnie żerują na płyciznach przy przelewach. Gruntowcy odnajdują tu spokój, nęcąc precyzyjnie krawędzie przykos, gdzie stada cert i jazi zatrzymują się w poszukiwaniu niesionego nurtem pokarmu. Brak gęstych zadrzewień brzegowych umożliwia bardzo wygodne łowienie metodą bolońską z wypuszczaniem spławika na imponujące odległości. Płaski krajobraz wymusza jednak odpowiednie przygotowanie się na podmuchy wiatru, które bywają wczesną wiosną dość uciążliwe.', null);

