-- Spot 131: Wieprz - Serock
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71131, 'Wieprz - Serock', 'wieprz-serock-lubelskie', 'RIVER', 51.5819683, 22.5460925, 'Lubelskie', 'Lubartów', 'Wieprz w okolicach Serocka silnie wije się przez nizinne łąki, tworząc głębokie zakola o gliniastym podłożu i powolnym nurcie. Woda w tych miejscach zatrzymuje osady organiczne, co sprzyja rozwojowi fauny dennej i przyciąga olbrzymie stada rzecznych leszczy. W marcu 2026 roku to jedno z najpewniejszych miejsc na długie zasiadki feederowe, obfitujące w brania ryb spokojnego żeru. Spinningiści z sukcesami obławiają nawisy trawiastych burt, stosując lekkie obrotówki w celu sprowokowania schowanych pod nimi grubych kleni i okoni. Z uwagi na dużą głębokość rynien w zakolach, ryby czują się tu bezpiecznie i często żerują nawet w środku bezchmurnego dnia. Kameralny, dziki charakter rzeki sprawia, że łowisko to jest wyjątkowo atrakcyjne dla wędkarzy szukających odpoczynku z dala od zgiełku.', null);

