-- Spot 132: Wieprz - Bożniewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71132, 'Wieprz - Bożniewice', 'wieprz-bozniewice', 'RIVER', 51.604613, 22.3872337, 'Lubelskie', 'Kock', 'Odcinek w Bożniewicach prezentuje bardzo naturalny, zalesiony z jednej strony profil koryta rzeki, w którym roi się od podwodnych przeszkód. Dno rzeki jest tu piaszczysto-żwirowe, z wyraźnymi uskokami wymytymi przez wodę za powalonymi do nurtu potężnymi konarami olch. Dla wędkarzy spinningowych w marcu 2026 roku to wybitne łowisko szczupakowe, wymagające jednak precyzji w prowadzeniu przynęty by uniknąć natychmiastowych zaczepów. Stacjonarni łowcy rzadko tu docierają ze względu na trudny brzeg, co daje ogromną szansę na złowienie wyrośniętego, dzikiego suma. Uciąg jest zróżnicowany i załamuje się na każdej przeszkodzie, dotleniając wodę i tworząc miniaturowe środowiska życia. To łowisko dla ludzi z determinacją, nagradzające wysiłek i umiejętności niezwykłymi okazami drapieżników w prawdziwie dzikiej oprawie.', null);

