-- Spot 133: Wieprz - Ostrów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71133, 'Wieprz - Ostrów', 'wieprz-ostrow-lubelskie', 'RIVER', 51.5942183, 22.3165581, 'Lubelskie', 'Michów', 'Wieprz w rejonie Ostrowa przyjmuje kształt szerokiej, leniwej wstęgi toczącej swoje wody przez rozległe, podmokłe doliny łąkowe. Podłoże jest wybitnie piaszczyste, z płytkimi blatami, które wczesną wiosną nagrzewają się niezwykle szybko w promieniach słońca. W marcu 2026 roku to strategiczny rejon dla łowców wczesnych płoci i jazi, które gromadzą się tuż przy granicy koryta głównego. Spinningiści z uwagą obserwują lustro wody, gdzie często dochodzi do wspaniałych, powierzchniowych ataków rzecznych boleni na stadka drobnicy. Ze względu na znikomy uciąg, wędkarze gruntowi mogą tu z powodzeniem stosować lekkie metody quiverowe, zapewniające niezwykle delikatną sygnalizację brań. Otwarty i dostępny brzeg sprzyja rodzinnemu wędkowaniu i bezpiecznemu biwakowaniu na malowniczych nadwieprzańskich łąkach.', null);

