-- Spot 134: Wieprz - Blizocin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71134, 'Wieprz - Blizocin', 'wieprz-blizocin', 'RIVER', 51.5913214, 22.2443096, 'Lubelskie', 'Jeziorzany', 'Odcinek Wieprza w Blizocinie to fascynujące łowisko rzeczne, gdzie szybkie, płytkie przelewy przeplatają się z potężnymi, wyerodowanymi w glinie rynnami. Podłoże w nurcie rzeki kryje liczne żwirowe garby, stanowiące naturalne tamy zatrzymujące pożywienie nanoszone przez wiosenne wezbrania wody. Jest to wyborne miejsce do łowienia przepływanką, gdzie w marcu 2026 wędkarze spławikowi wyciągają przepiękne świnki oraz duże brzany. Spinningiści obławiający krawędzie głębokich rynien przy pomocy najcięższych kogutów i gum mają tu realną szansę na uderzenie ogromnego, rzecznego sandacza. Skomplikowana hydrodynamika i silny uciąg w środku rzeki wymuszają stosowanie przemyślanych taktyk nęcenia oraz grubych i odpornych na przetarcia żyłek. Kontakt z tą potężną rzeką uczy pokory, oferując w zamian niezapomniane emocje z holu wielkich, rzecznych mocarzy w dzikiej scenerii.', null);

