-- Spot 135: Wieprz - Baranów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71135, 'Wieprz - Baranów', 'wieprz-baranow-lubelskie', 'RIVER', 51.5727749, 22.1543926, 'Lubelskie', 'Baranów', 'Wieprz na wysokości Baranowa mocno rozlewa się po nizinie, tworząc labirynt piaszczystych odnóg, niewielkich wysepek i płytkich warkoczy prądowych. Dno stanowi tu nieustannie przemieszczający się piasek, który z każdym nowym sezonem zmienia całkowicie mapę bezpiecznych i głębokich rynien. Wędkarze spinningowi uganiają się tu w marcu 2026 roku za boleniami, namierzając charakterystyczne ataki tych drapieżników na najpłytszych przelewach. Miłośnicy przystawki spławikowej lub lekkiego gruntu znajdują tu ciche, brzegowe zastoiska pełne płoci oraz pierwszych, wybudzonych wiosną krąpi. Łowienie w tej strefie polega na szybkim lokalizowaniu rynien głównych po zmarszczkach na wodzie, gdyż to one transportują cały wędkarski potencjał. Brak wysokich drzew na piaszczystych skarpach odsłania wędkarza, wymuszając delikatne operowanie sprzętem w słoneczne, przejrzyste dni.', null);

