-- Spot 136: Wieprz - Białki Dolne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71136, 'Wieprz - Białki Dolne', 'wieprz-bialki-dolne', 'RIVER', 51.5723254, 22.071337, 'Lubelskie', 'Ułęż', 'Odcinek w Białkach Dolnych to bardzo klasyczna rzeka nizinna z podmywanymi, wysokimi burtami i głębokimi rynnami sięgającymi ponad dwóch metrów. Twarde, gliniasto-piaszczyste dno stabilizuje rzekę na zakrętach, stwarzając wyborne siedliska dla grubszych ryb z rodziny karpiowatych zimujących w tych dołach. W marcu 2026 roku łowiska te przyciągają rzesze fanów method feedera, polujących z sukcesami na rzeczne leszcze i ostrożne, piękne jazie. Spinningiści cenią ten fragment Wieprza za bardzo przewidywalne usytuowanie szczupaków, które atakują duże rippery tuż zza krawędzi piaszczystej łachy. Uciąg w nurcie głównym jest potężny, natleniając wodę i wspierając świetną kondycję wyciąganych tu z dna, grubych ryb słodkowodnych. Okoliczne sady i naturalne łąki sprawiają, że rejon ten cechuje się niezwykłą estetyką i ciszą pożądaną na weekendowych biwakach wędkarskich.', null);

