VALUES (71136, 'Nizinna Wielka', 'Głęboka, meandrująca', 60.0, 2.2, 'Glina i piasek', 'Wysokie burty, rynny', 'Leszcz, Jaź, Szczupak', 'Kraina leszcza', false);

-- Spot 137: Wieprz - Sarny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71137, 'Wieprz - Sarny', 'wieprz-sarny', 'RIVER', 51.5725085, 21.9989546, 'Lubelskie', 'Ułęż', 'Wieprz w rejonie miejscowości Sarny wchodzi w przedujściową, coraz szerszą fazę, tocząc olbrzymie masy wody przez gęsto zalesione obszary. Podłoże jest mocno zróżnicowane; piaszczyste wypłycenia przeplatają się tu z wymytymi do gołej gliny rynnami i starymi, powalonymi olszynami. W marcu 2026 roku staje się to elitarna arena dla łowców potężnych sandaczy, wchodzących tu na żerowanie przed tarłem z pobliskiej Wisły. Wędkarze stacjonarni z ogromnym sukcesem obławiają ciężkimi zestawami gruntowymi warkocze prądowe, kusząc grube rzeczne brzany do brań na twardym dnie. Rzeka niesie tu bardzo mocno, a obsługa ciężkich wędzisk rzutowych z koszykiem wymaga odpowiedniej tężyzny i nienagannej techniki łowienia w nurcie. Leśna głusza i mroczny charakter zatarasowanego konarami brzegu przypominają pierwotne rzeki Europy, oferując niezapomniane wędkarskie eskapady.', null);

