-- Spot 138: Wieprz - Niebrzegów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71138, 'Wieprz - Niebrzegów', 'wieprz-niebrzegow', 'RIVER', 51.5368769, 21.9538748, 'Lubelskie', 'Puławy', 'Odcinek w Niebrzegowie to ostatnia prosta przed uregulowanym ujściem Wieprza, charakteryzująca się potężnymi, szerokimi zakolami i bardzo głębokimi rynnami. Dno stanowi gliniasta spoina z licznymi kamiennymi wypukłościami, co znakomicie chroni główne koryto przed naniesionymi, niestabilnymi piaskami brzegowymi. Jest to strategiczny obszar przedwiosennych migracji dla wiślanych cert, które w marcu 2026 licznie grupują się w spokojnych nurtach tego odcinka. Spinningiści przeczesują najgłębsze pasma rzeki przy pomocy ciężkich przynęt gumowych, notując częste brania ogromnych szczupaków i wyrośniętych rzecznych okoni. Ekstremalny uciąg rzeki w marcu wymusza rygorystyczne stosowanie koszyków z kolcami oraz używanie wędek feederowych o krzywej ugięcia powyżej 150 gramów. Miejsce to łączy w sobie potęgę niemal estuaryjnej wody i trudną techniczną specyfikę, będąc poligonem dla najbardziej wytrwałych wędkarzy.', null);

