-- Spot 139: Wieprz - Dęblin (Ujście do Wisły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71139, 'Wieprz - Dęblin (Ujście)', 'wieprz-deblin-ujscie', 'RIVER', 51.5289302, 21.8826157, 'Lubelskie', 'Dęblin', 'Ujście Wieprza do Wisły w Dęblinie to jeden z najbardziej fascynujących i najrybniejszych węzłów hydrologicznych całego regionu lubelskiego. Zderzenie wód tworzy tu gigantyczny, obfitujący w tlen warkocz ujściowy, a pod piaszczysto-żwirowym dnem rzeźbią się głębokie doły o silnych wstecznych prądach. W marcu 2026 ten wyjątkowy obszar to prawdziwe eldorado dla spinningistów polujących na wielkie wiślane sandacze oraz żarłoczne, ogromne bolenie i sumy. Dla łowców białorybu to doskonałe stanowisko do połowu wędrujących z Wisły grubych krąpi, leszczy oraz majestatycznych rzecznych jazi o potężnych rozmiarach. Łowienie z gruntu wymaga tu sprzętu wagi ciężkiej i perfekcyjnego dobierania obciążenia ze względu na potężne i stale zmieniające się siły nurtu obu rzek. Industrialno-dziki krajobraz, spotęgowany ogromem przewalającej się wody, pozostawia na każdym wędkarzu niezatarte wspomnienia i wymusza absolutny szacunek do natury.', null);

