-- Spot 140: Wieprz - Majdan Mały
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71140, 'Wieprz - Majdan Mały', 'wieprz-majdan-maly', 'RIVER', 50.538101, 23.3173345, 'Lubelskie', 'Krasnobród', 'Wracamy do pstrągowych źródeł Wieprza w malowniczym regionie Majdanu Małego na sercu Roztocza, gdzie rzeka ma charakter bystrego, czystego potoku. Dno pokrywa lita skała, drobny żwir i rzeczne kamienie, w których niezwykle szybko płynąca i lodowata woda rzeźbi miniaturowe, bezpieczne rynny. W marcu 2026 łowisko to kusi muszkarzy, obławiających techniczne nawisy oraz spowolnienia za kamieniami w poszukiwaniu dzikich, miejscowych pstrągów potokowych. Spinningiści stosują tu ultra-lekki sprzęt, precyzyjnie operując woblerami w krótkich, nasłonecznionych płaniach by skusić czujne ryby wybudzone po zimie. Rzeka jest niezwykle wąska i płytka, a krystaliczna woda całkowicie demaskuje wędkarza, wymuszając podejście do wody z kolan w barwach maskujących. Status górskich wód i nienaruszony ekosystem Roztocza stawiają ten odcinek na czele najpiękniejszych, pstrągowych rzek wschodniej Polski.', null);

