VALUES (71140, 'Górska', 'Bystra, krystaliczna', 5.0, 0.6, 'Skała i żwir', 'Kamienie, rynienki', 'Pstrąg potokowy, Strzebla', 'Kraina pstrąga', false);

-- Spot 141: Wieprz - Majdan Wielki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71141, 'Wieprz - Majdan Wielki', 'wieprz-majdan-wielki', 'RIVER', 50.5449962, 23.2458622, 'Lubelskie', 'Krasnobród', 'Odcinek Wieprza w Majdanie Wielkim powoli zaczyna wychodzić z leśnych jarów, delikatnie rozszerzając koryto w uroczej, podgórskiej dolinie. Podłoże jest tutaj piaszczysto-żwirowe z licznymi twardymi bystrzami, na których woda burzy się, natleniając ten wybitnie pstrągowy ekosystem. Wędkarze z sukcesami poszukują tu w marcu 2026 potężnych, zimujących w rynnach lipieni oraz pstrągów łowiąc na ciężkie i prowadzone dnem nimfy. Spinningiści z pasją obławiają cienie pod wielkimi, wymytymi korzeniami drzew rosnących tuż przy stromych, roztoczańskich burtach. Pomimo niewielkiej szerokości, rzeka potrafi być tutaj głęboka na ponad metr w dołkach, co ułatwia rybom bezpieczne ukrywanie się w chłodne dni. Kameralna otulina drzew, brak tłumów oraz nieziemski urok Roztocza czynią wędkowanie w Majdanie Wielkim niezapomnianą, leśną ucieczką.', null);

