-- Spot 142: Wieprz - Wieprzów Tarnawacki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71142, 'Wieprz - Wieprzów Tarnawacki', 'wieprz-wieprzow-tarnawacki', 'RIVER', 50.5012182, 23.4306507, 'Lubelskie', 'Tomaszów Lubelski', 'Wieprzów Tarnawacki to absolutny początek szlaku tej pięknej rzeki, która w tym miejscu przyjmuje formę wąskiego, płytkiego strumyka o żwirowo-piaszczystym dnie. Krystaliczna woda i gęste zarośla nadrzeczne tworzą tu wybitnie techniczne łowisko, wymagające od wędkarza podchodzenia do stanowisk na kolanach. W marcu 2026 roku muszkarze z sukcesami poszukują w tych mikroskopijnych rynienkach wybarwionych pstrągów potokowych, podając bardzo małe nimfy. Spinningiści operują najkrótszymi wędziskami i mikrojigami, starając się precyzyjnie trafić w wąskie oka czystej wody między licznymi zawadami. Ze względu na niemal potokowy charakter, uciąg jest tu bystry, a woda ekstremalnie zimna i doskonale natleniona. Dzikość tego źródliskowego ekosystemu Roztocza w pełni rekompensuje wszelkie trudy przedzierania się przez gęstwiny w poszukiwaniu rzecznych kropkowańców.', null);

