-- Spot 143: Wieprz - Michalów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71143, 'Wieprz - Michalów', 'wieprz-michalow', 'RIVER', 50.7288849, 23.0217868, 'Lubelskie', 'Szczebrzeszyn', 'Odcinek w Michalowie charakteryzuje się wejściem rzeki w szerszą dolinę, gdzie koryto zaczyna tworzyć klasyczne, nizinne meandry o gliniastych burtach. Pod twardymi, zarośniętymi brzegami wymyte są tu głębokie rynny, które stają się bezpiecznym azylem dla zimujących wciąż rzecznych leszczy i brzan. Wędkarze gruntowi w marcu 2026 roku chętnie stosują w tych miejscach ciężki feeder, starając się utrzymać zestaw na krawędzi wartkiego nurtu. Spinningiści z uwagą obławiają spokojniejsze zastoiska za naturalnymi zatorami z gałęzi, kusząc wczesnowiosenne szczupaki i grube okonie. Przejrzysta woda po zimie pozwala na świetne czytanie dna, na którym wyraźnie widać naprzemienne pasy jasnego piasku i ciemnej gliny. Łatwy dostęp do otwartych łąk pozwala na komfortowe operowanie dłuższą wędką spławikową i wypuszczanie zestawu z nurtem za stadem kleni.', null);

