-- Spot 144: Wieprz - Bondyrz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71144, 'Wieprz - Bondyrz', 'wieprz-bondyrz', 'RIVER', 50.5729323, 23.1033002, 'Lubelskie', 'Zwierzyniec', 'Wieprz w miejscowości Bondyrz to legendarny, roztoczański odcinek o wybitnie pstrągowym charakterze i niezwykle bystrym, chłodnym nurcie. Dno rzeki jest tu wyścielone grubym żwirem oraz kamieniami, pomiędzy którymi wymyte są głębokie dołki stanowiące kryjówki ryb łososiowatych. Marzec 2026 roku to czas, gdy spinningiści brodząc w lodowatej wodzie precyzyjnie prowadzą małe woblery pstrągowe pod zwalonymi pniami olch. Muszkarze obławiają tu techniczne warkocze prądowe, podając ciężkie nimfy bezpośrednio w strefę żerowania pięknych roztoczańskich lipieni. Ogromne natlenienie wody sprawia, że holowane tu ryby wykazują się niesamowitą walecznością, nierzadko wykonując widowiskowe skoki nad powierzchnię. Historyczne zabudowy młynów wodnych i gęsty, sosnowy las nadają temu łowisku niezapomniany, surowy klimat krainy pstrąga i lipienia.', null);

