-- Spot 145: Wieprz - Nielisz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71145, 'Wieprz - Nielisz', 'wieprz-nielisz', 'RIVER', 50.8049453, 23.0368313, 'Lubelskie', 'Zamość', 'Łowisko rzeczne w Nieliszu skupia się wokół potężnej zapory czołowej zbiornika, gdzie zrzut wody kształtuje dynamiczny i głęboki odcinek koryta. Woda wymywa pod betonowymi umocnieniami ogromne, kilkumetrowe wyrwy o twardym, kamienistym dnie, które stają się wielkim magnesem dla drapieżników. W marcu 2026 roku spinningiści poszukują w tych natlenionych rynnach olbrzymich sandaczy i okoni, używając do obławiania dna ciężkich jigów. Wędkarze stacjonarni z powodzeniem łowią w spokojniejszych warkoczach potężne leszcze i krąpie, które chętnie podchodzą pod zaporę w poszukiwaniu pokarmu. Zmienność przepływów wynikająca z pracy elektrowni wymusza na wędkarzach ciągłe dostosowywanie ciężaru koszyków zanętowych i główek spinningowych. Surowy urok inżynierii wodnej w połączeniu z bardzo bogatym rybostanem czyni to miejsce obowiązkowym punktem na mapie każdego rzeczonego specjalisty.', null);

