VALUES (71145, 'Nizinna Wielka', 'Zrzut zapory, bystra', 30.0, 3.5, 'Beton i kamień', 'Konstrukcje oporowe, wyrwy', 'Sandacz, Leszcz, Okoń', 'Kraina leszcza', false);

-- Spot 146: Wieprz - Ujazdów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71146, 'Wieprz - Ujazdów', 'wieprz-ujazdow', 'RIVER', 50.8413185, 23.0790392, 'Lubelskie', 'Zamość', 'Odcinek Wieprza w Ujazdowie płynie szerokimi, bardzo naturalnymi meandrami, wycinając w łąkowym krajobrazie wysokie, gliniaste skarpy. Zewnętrzne łuki rzeki kryją pod wodą rynny erozyjne dochodzące do dwóch i pół metra głębokości, w których stacjonują wczesnowiosenne brzany. Fani wędkarstwa gruntowego stosują tu koszyki z pazurami, aby skutecznie utrzymać przynętę w najsilniejszym nurcie głównego koryta. Spinningiści poszukują wyrośniętych kleni i jazi, precyzyjnie podając smużaki na pograniczu prądu i spokojnej wody pod zwisającymi trawami. W marcu 2026 roku płytsze, piaszczyste wewnętrzne strony zakrętów szybko się nagrzewają, prowokując białoryb do wyjścia z zimowisk na żer. Ze względu na bardzo strome zejścia, operowanie podbierakiem wymaga tu dużej ostrożności oraz bezwzględnego posiadania sztycy o długości co najmniej trzech metrów.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71146, 'Nizinna', 'Erozyjna, meandrująca', 25.0, 2.0, 'Glina i piasek', 'Wysokie skarpy, rynny', 'Brzana, Kleń, Jaź', 'Kraina brzany', false);

-- Spot 147: Wieprz - Wirkowice Pierwsze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71147, 'Wieprz - Wirkowice Pierwsze', 'wieprz-wirkowice-pierwsze', 'RIVER', 50.8848313, 23.097868, 'Lubelskie', 'Izbica', 'Wieprz przepływający przez Wirkowice Pierwsze to kwintesencja nieokiełznanej, nizinnej rzeki o dnie gęsto usianym zwalonymi pniami starych drzew. Gęste korony nadrzecznych olszyn skutecznie zacieniają wodę, tworząc mroczne, głębokie jamy wymyte pod naturalnymi systemami zatopionych korzeni. Marzec 2026 roku to doskonały moment dla spinningistów na namierzenie grubych, rzecznych szczupaków czatujących nieruchomo w tych naturalnych zawadach. Wędkarze spławikowi, stosujący metodę klasycznej przystawki, wyciągają z mniejszych zastoisk piękne płocie i dorodne jazie celowo unikające silnego prądu. Duża ilość zaczepów na dnie wymusza bezkompromisowe i siłowe hole, do których niezbędne są mocne plecionki i grube przypony z fluorocarbonu. Dzikość tego trudno dostępnego odcinka gwarantuje wędkarzowi całkowity spokój, wynagradzając trudne warunki techniczne pięknymi okazami ryb.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71147, 'Nizinna', 'Dzika, zatarasowana', 24.0, 1.9, 'Piasek i glina', 'Zwalone drzewa, zatory', 'Szczupak, Płoć, Jaź', 'Kraina leszcza', false);

-- Spot 148: Wieprz - Hutki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71148, 'Wieprz - Hutki', 'wieprz-hutki', 'RIVER', 50.5546959, 23.1762472, 'Lubelskie', 'Krasnobród', 'Odcinek w Hutkach leży w górnym biegu Wieprza, oferując bystry, płytki nurt i krystalicznie czystą wodę przepływającą przez dzikie lasy Roztocza. Dno rzeki pokrywają tu piaszczyste łachy przeplatane polami drobnego żwiru, stanowiącymi idealne tarliska dla rzecznych ryb łososiowatych. Wędkarze muchowi w marcu 2026 roku z wielkimi sukcesami prowadzą tu suche muchy i nimfy, celując w żerujące ostrożnie pstrągi potokowe. Spinningiści cierpliwie obławiają podmycia brzegowe mikro-jigami, licząc na agresywne brania wyrośniętych kleni, które wykorzystują każdy cień do kamuflażu. Ogromna przejrzystość wody nie wybacza błędów, wymuszając maskujący ubiór oraz oddawanie wysoce precyzyjnych rzutów z dość dużego dystansu. Położenie w otulinie Roztoczańskiego Parku Narodowego sprawia, że jest to jedno z najbardziej malowniczych i rygorystycznie chronionych łowisk w południowo-wschodniej Polsce.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71148, 'Górska', 'Bystra, leśna', 8.0, 0.7, 'Żwir i piasek', 'Łachy żwirowe, bystrza', 'Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 149: Wieprz - Romanów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71149, 'Wieprz - Romanów', 'wieprz-romanow', 'RIVER', 50.9221429, 23.138271, 'Lubelskie', 'Krasnystaw', 'Wieprz w okolicach Romanowa wije się głębokim korytem przez żyzne, rolnicze tereny, niosąc niezwykle spokojnie swoje piaszczysto-gliniaste wody. Rzeka precyzyjnie rzeźbi tu na zakolach klasyczne rynny, w których woda wyhamowuje, osadzając na dnie materię organiczną przyciągającą stada leszczy. W marcu 2026 roku wędkarze feederowi z powodzeniem sypią tu grubą zanętę, by zatrzymać w łowisku dorodne krąpie oraz pierwsze wiosenne liny. Zwolennicy wędkarstwa spinningowego przeczesują najgłębsze partie koryta cięższymi gumami, sprawdzając aktywność sandaczy przyklejonych jeszcze mocno do dna. Zrównoważony uciąg ułatwia utrzymanie zestawów gruntowych bez konieczności stosowania ekstremalnych ciężarów, co zdecydowanie podnosi czułość sygnalizacji brań. Łagodne zejścia brzegowe i łatwy dojazd bezpośrednio na nadbrzeżne łąki sprawiają, że to wspaniałe miejsce na wielogodzinne, wysoce relaksujące sesje.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71149, 'Nizinna', 'Spokojna, meandrująca', 26.0, 2.1, 'Glina i piasek', 'Zakola, rynny', 'Leszcz, Krąp, Sandacz', 'Kraina leszcza', false);

-- Spot 150: Wda - Wojtal
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71150, 'Wda - Wojtal', 'wda-wojtal', 'RIVER', 53.8958458, 18.0297227, 'Pomorskie', 'Czersk', 'Wda w rejonie Wojtala to urokliwy, leśny odcinek o dość szybkim nurcie i dnie pokrytym ciemnym piaskiem oraz żwirem. Woda charakteryzuje się tu specyficzną, brunatną barwą od związków humusowych, co świetnie kamufluje wędkarza na brzegu. W marcu 2026 roku to wyborne łowisko dla spinningistów, którzy poszukują kleni i wczesnych szczupaków za pomocą niewielkich, kontrastowych woblerów. Wędkarze muchowi chętnie przeczesują zwalone do koryta sosny, gdzie w głębszych warkoczach prądowych chronią się pstrągi potokowe i lipienie. Z uwagi na dużą ilość podwodnych zawad, konieczne jest stosowanie mocniejszych przyponów oraz precyzyjne operowanie zestawem w strefie przydennej. Dzikość Borów Tucholskich oraz niska presja wędkarska gwarantują tu ciszę i pełne zanurzenie w rzecznym, technicznym wędkarstwie.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71150, 'Podgórska/Nizinna', 'Leśna, dzika', 16.0, 1.3, 'Piasek i żwir', 'Zwalone sosny, bystrza', 'Kleń, Szczupak, Pstrąg potokowy', 'Kraina pstrąga', false);

-- Spot 151: Wda - Wieck
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71151, 'Wda - Wieck', 'wda-wieck', 'RIVER', 53.8745025, 18.0580259, 'Pomorskie', 'Czarna Woda', 'Odcinek rzeki w miejscowości Wieck mocno meandruje wśród podmokłych łąk i skrajów borów sosnowych, tworząc głębokie do niemal dwóch metrów rynny erozyjne. Podłoże jest tu zmienne, a piaszczyste, jasne łachy kontrastują z zalegającym w zakolach twardym, ciemnym torfem. Spinningiści w marcu 2026 roku z sukcesami wykorzystują ten fakt, prowadząc dnem małe jigi imitujące żaby lub ślizgi, co prowokuje ospałe jeszcze okonie. Fani spławika przepływankowego notują znakomite wyniki, nęcąc strefy spowolnień nurtu w poszukiwaniu pięknych, wybarwionych jazi oraz rzecznych płoci. Uciąg potrafi tu gwałtownie przyspieszać na zwężeniach, co zmusza do stosowania cięższych bombek i błyskawicznej korekty toru spływu przynęty. Dostępność brzegów bywa tu mocno ograniczona przez zwartą roślinność, więc brodzenie w spodniobutach często okazuje się jedynym sposobem na zajęcie optymalnego stanowiska.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71151, 'Nizinna', 'Meandrująca, zakola', 18.0, 1.5, 'Piasek i torf', 'Rynny erozyjne, burty', 'Okoń, Jaź, Płoć', 'Kraina brzany', false);

-- Spot 152: Wda - Czarna Woda (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71152, 'Wda - Czarna Woda (Północ)', 'wda-czarna-woda-polnoc', 'RIVER', 53.8517362, 18.0830162, 'Pomorskie', 'Czarna Woda', 'Górna część Wdy w obrębie miasta Czarna Woda to woda lekko uregulowana, jednak wciąż zachowująca swój zadziorny, bystry charakter. Dno wyściela tu twardy żwir i kamienie wymieszane z grubym piaskiem, co zapobiega nadmiernemu mętnieniu wody wczesną wiosną. W marcu 2026 roku jest to strategiczna baza dla wędkarzy polujących na grube klenie, które z lubością patrolują filary miejskich mostów drogowych. Spinningiści z łatwością operują z twardych brzegów, precyzyjnie posyłając smukłe woblery i obrotówki na krawędzie najszybszego prądu. Łowienie z gruntu wymaga tu koszyczków z metalowymi wąsami, ponieważ rzeka napiera z ogromną siłą, szybko spychając lekkie zestawy pod brzeg. Mimo bliskości zabudowań, rzeka obfituje w okazałe ryby prądolubne, czyniąc to miejsce świetnym punktem na kilkugodzinny streetfishing.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71152, 'Podgórska/Nizinna', 'Uregulowana miejska', 20.0, 1.4, 'Żwir i piasek', 'Mosty, umocnienia', 'Kleń, Okoń, Jelec', 'Kraina brzany', false);

-- Spot 153: Wda - Czarna Woda (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71153, 'Wda - Czarna Woda (Południe)', 'wda-czarna-woda-poludnie', 'RIVER', 53.8299714, 18.1103072, 'Pomorskie', 'Czarna Woda', 'Południowe obrzeża Czarnej Wody to strefa, gdzie Wda ponownie uwalnia się z miejskich opasek, powracając do głębokich, leśnych meandrów. Nurt wymywa tu pod stromymi skarpami ponaddwumetrowe rynny, na dnie których zalegają wypłukane przez zimowe wezbrania korzenie drzew. To znakomite, wczesnowiosenne zimowiska dla stad leszczy oraz płoci, które w marcu 2026 roku z chęcią reagują na czerwoną ochotkę podaną method feederem. Spinningiści przeczesują najciemniejsze zakamarki rzeki z użyciem jaskrawych ripperów, licząc na przebudzenie się potężnych szczupaków, które uwielbiają tę ciemną wodę. Prąd jest tu zdecydowanie spokojniejszy niż w centrum, co ułatwia idealne zbalansowanie ciężaru zestawu i zwiększa widoczność delikatnych brań na szczytówce. Dziki las sosnowy stwarza naturalną ochronę przed wiatrem, gwarantując komfort termiczny podczas mroźnych poranków.', null);

