VALUES (71153, 'Nizinna', 'Leśna, meandrująca', 22.0, 2.0, 'Piasek i glina', 'Strome skarpy, korzenie', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', false);

-- Spot 154: Wda - Zimne Zdroje
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71154, 'Wda - Zimne Zdroje', 'wda-zimne-zdroje', 'RIVER', 53.8256146, 18.1555849, 'Pomorskie', 'Czersk', 'Wda w okolicach Zimnych Zdrojów w pełni zasługuje na swoją nazwę, oferując lodowatą, świetnie natlenioną wodę zasilaną lokalnymi wysiękami. Podłoże jest tu wybitnie kamienisto-żwirowe, a płytkie przelewy przeplatają się z niewielkimi, za to głębokimi dołkami wyżłobionymi za narzutami skalnymi. W marcu 2026 roku to jedno z najbardziej elitarnych łowisk dla muszkarzy poszukujących rodzimych pstrągów potokowych oraz pięknych lipieni na suche i mokre muchy. Spinningiści z pasją obławiają cienie prądowe za pomocą mikrojigów, zmuszając do ataku bardzo czujne i silne klenie. Ekstremalna czystość wody, pomimo jej naturalnego, rdzawego zabarwienia, wymusza stosowanie żyłek o grubości nieprzekraczającej 0.16 mm oraz zachowanie pełnej ciszy. Las otulający koryto sprawia, że rzuty wymagają ogromnej wprawy wędkarskiej, podnosząc rangę każdego wyholowanego tu z sukcesem kropkowańca.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71154, 'Górska', 'Bystra, leśna', 14.0, 1.0, 'Kamień i żwir', 'Bystrza, jamy skalne', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 155: Wda - Schodno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71155, 'Wda - Schodno', 'wda-schodno', 'RIVER', 54.04725, 17.87125, 'Pomorskie', 'Kościerzyna', 'Górny bieg Wdy w Schodnie, na terenie Wdzydzkiego Parku Krajobrazowego, to wąska i niesamowicie dzika rzeka o leśno-torfowym charakterze. Dno stanowi tu zmienną mozaikę białego piasku, drobnego żwiru i ciemnego detrytusu zgromadzonego na zakolach pod nawisami gałęzi. To bankowe łowisko pstrągowe, w którym wczesną wiosną 2026 roku dominuje finezyjny spinning podchodowy z wykorzystaniem najmniejszych woblerków owadowych. Wędkarze spławikowi, cicho wypuszczając zestaw z nurtem, skutecznie odławiają tu stadne płocie oraz świnki, które wpływają z pobliskich jezior na tarło. Szerokość rzeki rzadko przekracza dziesięć metrów, co absolutnie dyskwalifikuje użycie ciężkiego sprzętu na rzecz finezyjnych wędek klasy ultralight. Ekosystem otoczony jest ścisłą ochroną, dlatego każdy złowiony tu drapieżnik smakuje podwójnie dobrze dzięki poczuciu integracji z nienaruszoną przyrodą Kaszub.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71155, 'Górska', 'Wąska, dzika', 9.0, 0.8, 'Piasek i torf', 'Zakola, nawisy', 'Pstrąg potokowy, Płoć, Świnka', 'Kraina pstrąga', false);

-- Spot 156: Wda - Lipusz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71156, 'Wda - Lipusz', 'wda-lipusz', 'RIVER', 54.098603, 17.7842005, 'Pomorskie', 'Kościerzyna', 'Odcinek rzeki w Lipuszu to źródliskowe terytorium Wdy, charakteryzujące się wybitnie krystaliczną wodą i żwirowo-kamienistym korytem przecinającym kaszubskie łąki. Rzeka jest tu płytka, bardzo bystra i wije się dynamicznie, tworząc klasyczne, podmyte burty dające schronienie szlachetnym gatunkom ryb. W marcu 2026 roku jest to poligon doświadczalny dla miłośników wędkarstwa muchowego, którzy z pietyzmem podają tu małe nimfy pstrągom potokowym. Lekki spinning pozwala na wyciągnięcie z głębszych warkoczy walecznych kleni, pod warunkiem perfekcyjnego prowadzenia przynęty równo z tempem uciągu wody. Brodzenie po twardym dnie jest tu bezpieczne i bardzo popularne, jednak wymaga użycia neoprenowych woderów ze względu na lodowatą temperaturę wody. Brak zwartej zabudowy leśnej na brzegach zdecydowanie ułatwia operowanie wędziskiem, pozwalając na dalekie i celne rzuty w samo serce bystrza.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71156, 'Górska', 'Płytka, łąkowa', 12.0, 0.7, 'Żwir i kamień', 'Podmyte burty, bystrza', 'Pstrąg potokowy, Kleń, Lipień', 'Kraina pstrąga', false);

-- Spot 157: Wda - Lipuska Huta
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71157, 'Wda - Lipuska Huta', 'wda-lipuska-huta', 'RIVER', 54.0804288, 17.8183321, 'Pomorskie', 'Kościerzyna', 'Poniżej Lipusza, w rejonie Lipuskiej Huty, Wda nabiera nieco masy, a jej koryto wcina się w zalesione wąwozy rzeźbiące głębokie jamy w gliniastym podłożu. Wymyte przez wodę korzenie sosnowe i powalone pnie dębów tworzą pod wodą istny labirynt, który zatrzymuje masę naturalnego pokarmu. To doskonały teren dla spinningistów uganiających się za wyrośniętymi szczupakami, które w marcu 2026 chętnie wygrzewają się na nasłonecznionych skrajach rynien. Wędkarze gruntowi, rzucając zestawy z drgającą szczytówką między zawady, łowią piękne rzeczne liny i okazyjne leszcze szukające tu ciszy i pożywienia. Dynamiczne zawirowania wody wymuszają doskonałą koordynację podczas holu, by nie pozwolić zaciętej rybie na ucieczkę w gąszcz podwodnych konarów. Surowość otaczającego lasu i niezwykła barwa rzeki tworzą wędkarski klimat, którego próżno szukać na dużych, nizinnych rzekach Polski środkowej.', null);

