-- Spot 158: Wda - Młyńsk
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71158, 'Wda - Młyńsk', 'wda-mlynsk', 'RIVER', 53.8621413, 18.2644535, 'Pomorskie', 'Starogard Gdański', 'Odcinek Wdy w Młyńsku to powrót rzeki do urokliwych, łąkowych meandrów Kociewia, gdzie nurt zdecydowanie uspokaja się na szerokich piaszczystych blatach. Dno jest tu miękkie, piaszczysto-muliste, a na zewnętrznych zakolach formują się klasyczne, ponaddwumetrowe rynny pełne wygłodniałego po zimie białorybu. W marcu 2026 roku to strategiczna lokacja dla fanów metody feederowej, którzy na cienkich przyponach wyciągają potężne jazie i stada rzecznych płoci. Spinningiści koncentrują swoje wysiłki na poszukiwaniu drapieżników w rejonach twardszych przelewów, stosując jaskrawe obrotówki prowokujące zębate szczupaki do ataku. Zrównoważony uciąg sprawia, że woda jest niesłychanie przewidywalna, pozwalając na równe, punktowe budowanie dywanu zanętowego bez ryzyka szybkiego wymycia. Otwarte przestrzenie łąkowe zapraszają do wygodnego wędkowania z koszem, oferując piękny, niczym nieograniczony widok na budzącą się wiosenną przyrodę.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71158, 'Nizinna', 'Łąkowa, spokojna', 24.0, 1.6, 'Piasek i muł', 'Mielizny, rynny', 'Jaź, Płoć, Szczupak', 'Kraina brzany', false);

-- Spot 159: Wda - Borzechowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71159, 'Wda - Borzechowo', 'wda-borzechowo', 'RIVER', 53.8717443, 18.3083387, 'Pomorskie', 'Starogard Gdański', 'Wda w okolicach Borzechowa przepływa rynną otoczoną gęstymi kompleksami borów, nabierając głębokości i wyjątkowo mrocznego, ciemnego odcienia toni. Podłoże kryje tu liczne złoża gliny i torfu wymieszanego z piaskiem, a woda niesie dużo substancji odżywczych wymytych z sąsiednich, rynnowych jezior. Wczesną wiosną 2026 r. to kapitalne miejsce dla stacjonarnych wędkarzy stosujących cięższą przepływankę, mających w zasięgu ręki okazyjne brzany i grube leszcze. Spinningiści obławiający głębokie dołki na zakrętach używają przynęt o silnej fali hydroakustycznej, by sprowokować do brania rzeczne sandacze oraz ospałe sumy. Przez uregulowany, dość wysoki brzeg zejścia do rzeki potrafią być strome i gliniaste, co po opadach deszczu wymaga użycia wkrętów do butów. Ze względu na bliskość Borzechowskiego Jeziora, rybostan jest tu nieprzewidywalny i często zaskakuje łowców rzadkimi, migrującymi do rzeki gatunkami.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71159, 'Nizinna', 'Leśna, mroczna', 26.0, 2.2, 'Glina i torf', 'Wysokie brzegi, głęboczki', 'Leszcz, Brzana, Sandacz', 'Kraina leszcza', false);

-- Spot 160: Wda - Młynki (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71160, 'Wda - Młynki (Północ)', 'wda-mlynki-polnoc', 'RIVER', 53.8680115, 18.3539349, 'Pomorskie', 'Starogard Gdański', 'Wda w północnym rejonie miejscowości Młynki to dziki, leśny odcinek o ciemnej, humusowej wodzie i piaszczysto-żwirowym dnie. Rzeka tworzy tu liczne meandry z głębokimi rynnami, wymytymi pod stromymi, zalesionymi burtami. W marcu 2026 roku to doskonałe miejsce dla łowców szczupaków, którzy obławiają wolniejsze, nagrzewające się zastoiska. Wędkarze spławikowi z sukcesami odławiają tu piękne płocie, nęcąc strefy na krawędzi głównego nurtu i spowolnień. Wymagany jest wytrzymały sprzęt, ponieważ koryto usiane jest zwalonymi do wody drzewami. Kameralny charakter tego fragmentu rzeki gwarantuje pełną izolację od cywilizacji i wędkarski spokój.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71160, 'Nizinna', 'Leśna, meandrująca', 18.0, 1.6, 'Piasek i żwir', 'Zwalone pnie, burty', 'Szczupak, Płoć, Okoń', 'Kraina brzany', false);

-- Spot 161: Wda - Młynki (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71161, 'Wda - Młynki (Południe)', 'wda-mlynki-poludnie', 'RIVER', 53.8409364, 18.3551428, 'Pomorskie', 'Starogard Gdański', 'Południowy odcinek Wdy w Młynkach charakteryzuje się nieznacznie szybszym nurtem, wycinającym w gliniastym podłożu głębsze rynny torowe. Dno jest tu twardsze, co sprzyja wiosennym wędrówkom okazałych rzecznych kleni i jazi. Spinningiści w marcu 2026 roku z sukcesami stosują niewielkie smużaki i obrotówki, podając je tuż pod nawisy gałęzi. Zwolennicy wędkarstwa gruntowego lokują lekkie koszyczki zanętowe na krawędzi nurtu, wyczekując brań wybudzonych z letargu leszczy. Uciąg wody wymaga od łowiących szybkiej reakcji na brania, by ryba nie zaplątała zestawu w zatopionych korzeniach. Bujna, leśna sceneria tego łowiska tworzy mikroklimat chroniący przed zimnymi, wczesnowiosennymi wiatrami.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71161, 'Nizinna', 'Bystra, leśna', 20.0, 1.8, 'Glina i piasek', 'Korzenie, rynny', 'Kleń, Jaź, Leszcz', 'Kraina brzany', false);

-- Spot 162: Wda - Wda (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71162, 'Wda - Wda (Północ)', 'wda-wda-polnoc', 'RIVER', 53.8161796, 18.3740879, 'Pomorskie', 'Skórcz', 'Przepływając przez miejscowość o tej samej nazwie, Wda uspokaja swój bieg, a jej koryto delikatnie się poszerza. Piaszczyste, równe dno sprzyja rozwojowi podwodnej roślinności w cieplejszych miesiącach, ale w marcu odsłania gołe, żerowe blaty. Jest to strategiczny obszar dla wędkarzy stosujących lekką przepływankę z nastawieniem na dorodne, wiosenne stada płoci i krąpi. Spinningiści z uwagą penetrują wolniejszy nurt w poszukiwaniu wczesnych okoni, które chętnie reagują na powolnie opadające jaskrawe gumy. Uciąg jest stabilny, co ułatwia równe i punktowe nęcenie rzecznych gatunków karpiowatych. Dogodny dojazd w okolicach miejscowości sprawia, że to świetny odcinek na krótsze, weekendowe wypady z lekkim sprzętem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71162, 'Nizinna', 'Spokojna, piaszczysta', 22.0, 1.4, 'Piasek', 'Mielizny, spokojny nurt', 'Płoć, Krąp, Okoń', 'Kraina leszcza', false);

-- Spot 163: Wda - Wda (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71163, 'Wda - Wda (Południe)', 'wda-wda-poludnie', 'RIVER', 53.7893584, 18.3876765, 'Pomorskie', 'Skórcz', 'Południowe obrzeża miejscowości Wda to fascynujące łowisko o stromych, piaszczysto-gliniastych skarpy opadających bezpośrednio do głębokiego nurtu. Woda wyrzeźbiła tu doskonałe rynny przybrzeżne o głębokości przekraczającej niekiedy 2 metry, dające schronienie pokaźnym leszczom. W marcu 2026 roku łowcy gruntowi używają tu nieco cięższych zestawów, by stabilnie zaprezentować przynętę w centrum rynny. Spinningiści łowią tu z rzutu pod przeciwny brzeg, sprowadzając przynętę po skosie i kusząc ukryte w cieniach prądowych szczupaki. Wysokie obrzeża wymagają stosowania podbieraków o długiej sztycy do bezpiecznego lądowania ryby. Zachwycająca i surowa natura rzeki w tej okolicy stwarza niepowtarzalny klimat dla każdego pasjonata samotnego wędkowania.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71163, 'Nizinna', 'Erozyjna, głęboka', 20.0, 2.0, 'Glina i piasek', 'Wysokie skarpy, rynny', 'Leszcz, Szczupak, Płoć', 'Kraina leszcza', false);

-- Spot 164: Wda - Smolniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71164, 'Wda - Smolniki', 'wda-smolniki', 'RIVER', 53.7635467, 18.4025923, 'Kujawsko-Pomorskie', 'Osie', 'Wda w rejonie Smolników przyspiesza, przecinając urozmaicony, zalesiony teren i tworząc dzikie bystrza o żwirowym dnie. Woda jest tu niezwykle dobrze natleniona, a twarde podłoże i nieliczne głazy w nurcie tworzą wzorowe stanowiska pstrągowe. W marcu 2026 roku jest to ulubione miejsce spinningistów ceniących pstrągi potokowe oraz okazałe, waleczne klenie. Fani wędkarstwa muchowego z powodzeniem operują tu ciężkimi nimfami, badając głębsze warkocze za kamieniami. Z uwagi na zróżnicowany uciąg i płytką wodę w strefach przelewów, ryby są wyjątkowo płochliwe. Brodzac ostrożnie w górę rzeki można liczyć na spektakularne brania i kontakt z dziewiczą, borowiacką naturą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71164, 'Podgórska/Nizinna', 'Bystra, leśna', 16.0, 1.2, 'Żwir i kamień', 'Bystrza, głazy', 'Pstrąg potokowy, Kleń, Lipień', 'Kraina pstrąga', false);

-- Spot 165: Wda - Skrzynia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71165, 'Wda - Skrzynia', 'wda-skrzynia', 'RIVER', 53.736626, 18.3953408, 'Kujawsko-Pomorskie', 'Osie', 'Odcinek Wdy w miejscowości Skrzynia to urokliwa rzeka nizinna o licznych meandrach i spowolnieniach za piaszczystymi łachami. Płytkie przelewy sąsiadują tu z zacienionymi dołkami, gdzie na dnie zbierają się osady przyciągające białoryb. Wczesną wiosną stacjonarni łowcy białorybu osiągają tu wyborne wyniki w łowieniu jazi i płoci metodą przystawki spławikowej. Dla łowiących aktywnie to rewiry świetne na okonie, które w marcu grupują się blisko zatopionych konarów. Czystość i specyficzna herbaciana barwa wody demaskują wszelkie nienaturalne barwy wędkarskiego ubioru na brzegu. Spokojna tafla i leśna otulina gwarantują fantastyczne warunki do podglądania dzikiej przyrody podczas wędkowania.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71165, 'Nizinna', 'Meandrująca, piaszczysta', 20.0, 1.4, 'Piasek i muł', 'Łachy piaszczyste, zatory', 'Jaź, Płoć, Okoń', 'Kraina brzany', false);

-- Spot 166: Wda - Łuby
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71166, 'Wda - Łuby', 'wda-luby', 'RIVER', 53.7127711, 18.373355, 'Kujawsko-Pomorskie', 'Osie', 'Wda w rejonie osady Łuby płynie dziką rynną, wyciętą głęboko w piaskach rzecznych i chronioną przez stare zadrzewienia. Podmyte korzenie olch i sosen tworzą w wodzie istny gąszcz, zmuszający do łowienia punktowego, blisko naturalnych zawad. Marzec 2026 to w tym miejscu idealny okres do testowania cięższych wędek gruntowych na potężne leszcze zimujące w wykopanych dołach. Spinningiści szukają tu zębatych szczupaków i wyrośniętych, mrocznych okoni celnie sprowadzając rippery na granicę cieni prądowych. Ogromna ilość gałęzi pod wodą czyni hol każdej większej ryby prawdziwym wyzwaniem wytrzymałościowym dla sprzętu i nerwów. Niezwykła kameralność tego łowiska wynagradza trudności rzutowe i pozwala w pełni delektować się kunsztem rzecznego wędkowania.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71166, 'Nizinna', 'Zatarasowana, głęboczki', 18.0, 1.7, 'Piasek i glina', 'Zwalone pnie, korzenie', 'Szczupak, Okoń, Leszcz', 'Kraina leszcza', false);

-- Spot 167: Wda - Gródek (Zalew)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71167, 'Wda - Gródek', 'wda-grodek', 'RIVER', 53.4997334, 18.3744282, 'Kujawsko-Pomorskie', 'Drzycim', 'Wkra w rejonie Gródka całkowicie zmienia swoje oblicze, rozlewając się w szeroki zalew utworzony przed lokalną elektrownią wodną. Znacznie powiększona głębokość i muł zalegający dno stwarzają doskonałe warunki dla rozwoju potężnych ryb jeziorowych i spokojnego żeru. Wędkarze stacjonarni odławiają tu w marcu piękne stada leszczy, używając techniki method feeder i klasycznych koszyków na twardszych blatach. Spinningiści patrolują z łodzi lub z brzegów strome uskoki starego koryta, tropiąc rekordowe sandacze oraz tłuste szczupaki. Praktyczny brak uciągu w głębszych partiach akwenu ułatwia utrzymanie lekkich zestawów w obranym punkcie nęcenia. Dostępność zbiornika oraz jego niebywała malowniczość czynią to miejsce bardzo atrakcyjną opcją na wielogodzinne, relaksujące zasiadki.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71167, 'Nizinna Wielka', 'Cofka elektrowni, szeroka', 120.0, 4.0, 'Muł i piasek', 'Zatopione koryto, uskoki', 'Leszcz, Sandacz, Szczupak', 'Kraina leszcza', true);

-- Spot 168: Wda - Dólsk
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71168, 'Wda - Dólsk', 'wda-dolsk', 'RIVER', 53.4728228, 18.3819589, 'Kujawsko-Pomorskie', 'Świecie', 'Odcinek Wdy w Dólsku, zlokalizowany poniżej kompleksu zbiorników, charakteryzuje się głęboką rynną i bystrym, po-zrzutowym przepływem. Woda jest tu znakomicie natleniona, a usunięty przez silny nurt piasek odsłonił bardzo twarde, kamienisto-żwirowe poszycie dna. To strategiczne stanowisko dla łowców potężnych brzan i kleni, które wczesną wiosną uaktywniają się w rwącym, bogatym w tlen prądzie. Spinningiści z uwagą penetrują przybrzeżne warkocze, używając średnio-ciężkich jigów w celu dotarcia do drapieżników przyklejonych do dna. Uciąg potrafi tu gwałtownie rosnąć wraz ze zrzutami z tamy, co wymusza posiadanie w arsenale ciężkich koszyków z pazurami. To rzeka dla specjalistów, gdzie zmaganie z ekstremalnym prądem kończy się często złowieniem okazu życia.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71168, 'Nizinna Wielka', 'Zrzutowa, szybka', 25.0, 2.5, 'Kamień i żwir', 'Rynny erozyjne', 'Brzana, Kleń, Sandacz', 'Kraina brzany', false);

-- Spot 169: Wda - Świecie (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71169, 'Wda - Świecie (Północ)', 'wda-swiecie-polnoc', 'RIVER', 53.4469126, 18.3959451, 'Kujawsko-Pomorskie', 'Świecie', 'Wda wchodząc w północne obszary miejskie Świecia, ulega silnym regulacjom nabrzeży i płynie w jednolitym, stabilnym rygorze. Dno stanowi tu równy, piaszczysto-żwirowy blat, pozbawiony dużych zatorów drzewnych, co znakomicie ułatwia prowadzenie finezyjnych zestawów wędkarskich. Z początkiem marca 2026 roku staje się to świetny teren do połowu wędrujących z Wisły cert oraz grubych jazi łowionych na klasyczny feeder. Spinningiści obławiają cienie betonowych filarów mostów i umocnień brzegu, regularnie łowiąc wczesnowiosenne okonie i okazyjne szczupaki. Przepływ wody pozwala na bezpieczne nęcenie szerokim pasem, a równy profil koryta zapewnia długą pracę zanęty w wodzie. Wygodne, wybrukowane w części brzegi stanowią doskonałe udogodnienie dla pasjonatów krótkich i technicznych wypadów ze spławikiem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71169, 'Nizinna Wielka', 'Uregulowana miejska', 30.0, 1.8, 'Piasek i żwir', 'Opaski, filary', 'Certa, Jaź, Okoń', 'Kraina leszcza', false);

-- Spot 170: Wda - Kozłowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71170, 'Wda - Kozłowo', 'wda-kozlowo', 'RIVER', 53.4227718, 18.3721278, 'Kujawsko-Pomorskie', 'Świecie', 'Łowisko Wdy w okolicach Kozłowa to głęboka pętla rzeki, położona przed samym miastem Świecie w otoczeniu starych łęgów. Nurt wyhamowuje tu zauważalnie, a woda odkłada warstwy żyznego mułu na wewnętrznych krawędziach rozległych zakrętów rzecznych. Jest to rejon wybitnie leszczy, dokąd w marcu kierują się ogromne stada białorybu w poszukiwaniu budzącego się pokarmu na płyciznach. Spinningiści notują w tych strefach doskonałe wyniki stosując bardzo lekkie główki jigowe, kusząc grube okonie zwalniające przed tarłem. Uciąg jest stabilny, wymagający przy średnim feederze koszyczków rzędu 30-40 gramów dla optymalnego utrzymania zestawu. Płaskie, porośnięte łąką trawiaste brzegi ułatwiają operowanie bolonką oraz komfortowe rozstawienie rozbudowanego stanowiska karpiowego.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71170, 'Nizinna', 'Spokojna, meandrująca', 35.0, 2.2, 'Piasek i muł', 'Głębokie zakola', 'Leszcz, Okoń, Krąp', 'Kraina leszcza', false);

-- Spot 171: Wda - Świecie (Ujście do Wisły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71171, 'Wda - Świecie (Ujście)', 'wda-swiecie-ujscie', 'RIVER', 53.4032033, 18.4048926, 'Kujawsko-Pomorskie', 'Świecie', 'Ujście Wdy do Wisły w Świeciu to spektakularny węzeł hydrologiczny, gdzie woda przybiera na głębokości i gwałtownie przyspiesza w warkoczach. Koryto pełne jest twardych, wymytych dołów i piaszczystych przykos stykających się z potężną masą mętnych wód Wisły. To strategiczne miejsce wędkarskie, przyciągające w marcu łowców ogromnych sumów oraz wchodzących na tarło potężnych jazi i cert. Spinningiści obławiają długimi, ciężkimi wahadłówkami strefę mieszania się prądów, z szansą na kapitalnego, wiślanego bolenia i rzadkiego sandacza. Skomplikowana dynamika dwóch rzek wymusza stosowanie najcięższego rzeczonego rynsztunku oraz wyśmienitego czytania lustra mętnej wody. To wybitnie trudne, surowe łowisko o ogromnym potencjale trofeów, które potrafi rzucić na kolana najwytrwalszych bywalców.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71171, 'Nizinna Wielka', 'Ujściowa, warkocze', 45.0, 3.5, 'Żwir i piasek', 'Warkocz ujściowy, jamy', 'Boleń, Sum, Certa', 'Kraina leszcza', true);

-- Spot 172: Wda - Czarlina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71172, 'Wda - Czarlina', 'wda-czarlina', 'RIVER', 54.0204586, 17.8993343, 'Pomorskie', 'Kościerzyna', 'Przeskok do górnego biegu! Wda w rejonie Czarliny przepływa przez malownicze tereny Wdzydzkiego Parku Krajobrazowego, cechując się dzikim profilem. Rzeka jest tu wąska, ekstremalnie czysta i toczy swe bardzo chłodne wody po piaszczysto-trawiastym dnie pełnym zatopionej wikliny. W marcu 2026 r. muszkarze z zaangażowaniem obławiają krótkie, dobrze nasłonecznione prostki w oczekiwaniu na uderzenie rdzawego pstrąga potokowego. Leciutki spinning z podchodami to absolutna konieczność, jako że nawet najmniejszy hałas na brzegu błyskawicznie płoszy reofilne gatunki. Przepływ wody zachowuje umiarkowane tempo, dzięki czemu w naturalnych basenach zadowalające brania dają małe płotki i wygłodniałe jelce. Nienaruszony, chroniony ekosystem i kaszubska otulina leśna gwarantują, że pobyt na tej wodzie staje się odprężającym przeżyciem wędkarskim.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71172, 'Górska/Podgórska', 'Wąska, czysta', 10.0, 0.8, 'Piasek i roślinność', 'Zarośla brzegowe, rynienki', 'Pstrąg potokowy, Jelec, Płoć', 'Kraina pstrąga', false);

-- Spot 173: Wda - Kozłowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71173, 'Wda - Kozłowiec', 'wda-kozlowiec', 'RIVER', 53.9916904, 17.9119108, 'Pomorskie', 'Dziemiany', 'Wda w okolicach Kozłowca to rzeka o nieco bystrzejszym usposobieniu, gdzie płytkie przelewy sąsiadują z głębszymi podcięciami gliniastych burt. Żwirowo-piaskowe dno zapewnia idealne tarliska, wokół których wczesną wiosną tętni intensywne, chłodnowodne życie lokalnej ichtiofauny. Dla pasjonatów królowej rzek – pstrąga potokowego, marzec to idealna pora na podanie obciążonej nimfy wzdłuż samego koryta. Spinningiści z upodobaniem sięgają tu po mikro-jigi z małymi raczkami, szukając stacjonujących przy dnie walecznych rzecznych kleni. Uciąg na twardszych rynnach jest odczuwalny, co z powodzeniem dotlenia ten wymagający, wąski strumień na krawędzi prastarych borów. Otwarte brzegi poprzecinane krzewami wymuszają rzuty spod siebie i kucanie, czyniąc to łowisko testem umiejętności dla prawdziwych twardzieli.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71173, 'Górska', 'Bystra, gliniasta burta', 12.0, 1.0, 'Żwir i glina', 'Podmyte burty, przelewy', 'Pstrąg potokowy, Kleń, Jelec', 'Kraina pstrąga', false);

-- Spot 174: Wda - Górki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71174, 'Wda - Górki', 'wda-gorki', 'RIVER', 53.9564578, 17.9139683, 'Pomorskie', 'Dziemiany', 'Odcinek w miejscowości Górki oferuje wspaniałe wędkarskie urozmaicenie, rzeka poszerza tu swe ramy wpływając w spokojniejszy, leśny rejon. Piaszczyste tło dna miejscami przecinają zwalone stare sosny, zza których wymywane są głębsze, bardzo ciemne od humusu jamy. Wczesną wiosną, pod koniec marca 2026 roku, szczupaki wykorzystują podwodne gałęzie jako doskonałą, niewidoczną z powierzchni rzeki kryjówkę. Fani delikatnej spławikówki notują w tym miejscu świetne wyniki na czerwone robaczki, kusząc do brania nieufne okazy wybarwionych jazi. Stabilny uciąg, zwolniony leśnym zadrzewieniem brzegów ułatwia nęcenie na krótkim dystansie bez rozpraszania smugi zapachowej. Rzadko uczęszczane brzegi zapewniają nienaruszoną przyrodę, a rzeka obdarowuje wytrwałych fascynującą dynamiką typowo dzikiego, leśnego koryta.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71174, 'Podgórska/Nizinna', 'Leśna, zacieniona', 14.0, 1.4, 'Piasek i korzenie', 'Zwalone pnie, głęboczki', 'Szczupak, Jaź, Okoń', 'Kraina brzany', false);

-- Spot 175: Wda - Papiernia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71175, 'Wda - Papiernia', 'wda-papiernia', 'RIVER', 54.1228592, 17.7548779, 'Pomorskie', 'Lipusz', 'Wda w rejonie Papierni to krystalicznie czysty, górny bieg rzeki o charakterze wybitnie pstrągowym. Koryto jest tu wąskie i płytkie, płynąc dynamicznie po żwirowo-kamienistym dnie z licznymi bystrzami. W marcu 2026 roku to strategiczne miejsce dla muszkarzy, którzy na krótkim dystansie kuszą dzikie pstrągi potokowe. Spinningiści z sukcesami stosują tu mikro-woblery owadowe, prowadząc je precyzyjnie pod nawisy traw i zwalone pnie olch. Woda zachowuje stałą, niską temperaturę, co sprzyja wysokiej aktywności ryb łososiowatych zaraz po zimowych mrozach. Dzikość kaszubskich lasów i brak presji wędkarskiej zapewniają w tym miejscu całkowity spokój i intymność.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71175, 'Górska', 'Bystra, wąska', 7.0, 0.6, 'Żwir i kamień', 'Bystrza, zwalone pnie', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- Spot 176: Wda - Huta Kalna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71176, 'Wda - Huta Kalna', 'wda-huta-kalna', 'RIVER', 53.8368339, 18.1988192, 'Pomorskie', 'Czarna Woda', 'Odcinek rzeki w Hucie Kalnej to malowniczy, leśny fragment o ciemnej toni i umiarkowanym uciągu wody. Podłoże jest tu piaszczysto-gliniaste, z wyraźnymi uskokami dna wymytymi pod zwalonymi do wody starymi sosnami. Spinningiści w marcu 2026 roku z powodzeniem poszukują tu okoni i wczesnych szczupaków, wykorzystując jaskrawe gumy w herbacianej wodzie. Wędkarze stacjonarni nęcą tutejsze głębokie zakola, licząc na brania okazałych płoci i jazi migrujących w górę rzeki. Nurt załamuje się na licznych przeszkodach naturalnych, tworząc doskonale natlenione warkocze prądowe idealne dla kleni. Cisza Borów Tucholskich oraz trudna dostępność niektórych burt gwarantują wędkarzowi wysoką jakość obcowania z naturą.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71176, 'Nizinna', 'Leśna, dzika', 18.0, 1.5, 'Piasek i glina', 'Zwalone sosny, rynny', 'Kleń, Jaź, Szczupak', 'Kraina brzany', false);

-- Spot 177: Wda - Świecie (Ujście/Zamek)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71177, 'Wda - Świecie (Ujście/Zamek)', 'wda-swiecie-ujscie-zamek', 'RIVER', 53.4043281, 18.4520026, 'Kujawsko-Pomorskie', 'Świecie', 'Łowisko w bezpośrednim sąsiedztwie zamku w Świeciu to głęboki, przedujściowy odcinek Wdy o silnym wpływie wód Wisły. Dno jest tu twarde, kamienisto-żwirowe z licznymi podmyciami wokół historycznych murów i mostów. To strategiczny węzeł migracyjny, gdzie w marcu 2026 roku stacjonują potężne jazie, certy oraz rzeczne leszcze. Spinningiści obławiają tutejsze warkocze prądowe ciężkimi wahadłówkami, licząc na kontakt z sumem lub wiślanym boleniem. Uciąg rzeki jest tu zdecydowany i zmienny, całkowicie zależny od poziomu wody w pobliskiej Wiśle. Unikalna architektura w tle i ogromny potencjał rybny czynią to miejsce jednym z najważniejszych punktów na mapie regionu.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71177, 'Nizinna Wielka', 'Ujściowa, głęboka', 40.0, 3.2, 'Kamień i żwir', 'Mury zamkowe, filary', 'Jaź, Certa, Sum', 'Kraina leszcza', true);

-- Spot 178: Wda - Gmina Osie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71178, 'Wda - Osie (Dziki Przełom)', 'wda-osie-gmina', 'RIVER', 53.6877966, 18.3550891, 'Kujawsko-Pomorskie', 'Osie', 'Wda na terenie gminy Osie płynie w głębokim jarze, tworząc jeden z najbardziej technicznych odcinków o bystrym nurcie. Podłoże jest tu wybitnie twarde, wysłane grubym żwirem i otoczakami, co sprzyja bytowaniu ryb reofilnych. To wyśmienite łowisko dla spinningistów polujących na rekordowe klenie, które w marcu 2026 roku doskonale reagują na małe jigi. Wędkarze muchowi z powodzeniem obławiają tutejsze szybkie płanie, celując w lipienie stacjonujące w cieniu prądowym głazów. Silny przepływ wody zapewnia doskonałe natlenienie, co bezpośrednio przekłada się na niesamowitą waleczność zapiętych tu ryb. Izolacja od dróg i surowość terenu wymagają od wędkarza dobrej kondycji fizycznej przy przedzieraniu się brzegiem.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71178, 'Podgórska', 'Bystra, jarowa', 20.0, 1.2, 'Żwir i kamień', 'Głazy, bystrza', 'Kleń, Lipień, Brzana', 'Kraina brzany', false);

-- Spot 179: Wda - Stara Rzeka (Góra)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71179, 'Wda - Stara Rzeka (Góra)', 'wda-stara-rzeka-gora', 'RIVER', 53.6640364, 18.3331319, 'Kujawsko-Pomorskie', 'Osie', 'Górny odcinek rzeki w Starej Rzece charakteryzuje się niezwykle krętym korytem z ogromną ilością naturalnych zatorów. Dno rzeki pokrywa ciemny piasek humusowy, a liczne rynny erozyjne na zakrętach osiągają głębokość ponad dwóch metrów. Marzec 2026 roku to doskonały czas na namierzenie grubych jazi, które gromadzą się w spokojniejszych warkoczach za powalonymi dębami. Spinningiści stosują tu technikę bardzo wolnego prowadzenia przynęt, starając się dotrzeć do drapieżników przyklejonych do samego dna. Przejrzystość wody pozwala na obserwację zachowań ryb, co wymaga od wędkarza pełnego kamuflażu i bezszelestnego poruszania się. Ten fragment rzeki uchodzi za jeden z najbardziej "dzikich" i rybnych w całych Borach Tucholskich.', null);

