VALUES (71179, 'Nizinna', 'Meandrująca, zwaliska', 22.0, 2.0, 'Piasek i torf', 'Naturalne zatory', 'Jaź, Szczupak, Okoń', 'Kraina brzany', false);

-- Spot 180: Wda - Stara Rzeka (Dół)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71180, 'Wda - Stara Rzeka (Dół)', 'wda-stara-rzeka-dol', 'RIVER', 53.6453965, 18.2999201, 'Kujawsko-Pomorskie', 'Osie', 'Dolny fragment Starej Rzeki to kraina szerokich płani i piaszczystych przykos, gdzie rzeka przygotowuje się do wejścia w cofkę zbiornika w Tleniu. Nurt staje się tu nieco bardziej leniwy, co sprzyja rozwojowi bogatej ichtiofauny białego żeru, w tym stadnych leszczy i płoci. W marcu 2026 roku wędkarze spławikowi z sukcesami nęcą tutejsze płaskie blaty, celując w ryby wychodzące z zimowisk na żer. Spinningiści przeczesują granice nurtu i zastoisk, szukając okoni oraz szczupaków wybudzonych promieniami wiosennego słońca. Podłoże jest głównie piaszczyste, z rzadkimi płatami żwiru, co ułatwia precyzyjne podawanie przynęt gruntowych na lżejszych zestawach. Spokojna okolica i łatwiejszy dostęp do brzegów w porównaniu do górnego odcinka czynią to miejsce idealnym na całodzienne wyprawy.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71180, 'Nizinna', 'Szeroka, spokojna', 25.0, 1.8, 'Piasek', 'Przykosy, blaty', 'Leszcz, Płoć, Szczupak', 'Kraina leszcza', false);

-- Spot 181: Wda - Tleń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71181, 'Wda - Tleń (Cofka Żurska)', 'wda-tlen', 'RIVER', 53.6231766, 18.2736842, 'Kujawsko-Pomorskie', 'Osie', 'Wda w Tleniu wchodzi w obszar cofki Zbiornika Żurskiego, co drastycznie zmienia jej charakter na głęboki i niemal stojący. Podłoże pokrywa tu warstwa miękkiego mułu, pod którym kryje się stare, piaszczyste koryto rzeki bogate w naturalny pokarm. To strategiczne łowisko dla łowców wczesnowiosennych szczupaków i sandaczy, którzy w marcu 2026 roku obławiają uskoki starego koryta. Wędkarze gruntowi z sukcesami łowią tu potężne leszcze i liny, nęcąc precyzyjnie płytsze, szybciej nagrzewające się zatoki. Brak silnego uciągu pozwala na stosowanie bardzo delikatnych zestawów feederowych i spławikowych, co podnosi czułość brań. Rozwinięta infrastruktura turystyczna Tlenia zapewnia świetny dojazd i bazę noclegową dla wędkarzy z całej Polski.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71181, 'Nizinna Wielka', 'Cofka zbiornika, głęboka', 60.0, 3.5, 'Muł i piasek', 'Zatopione koryto', 'Szczupak, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 182: Wda - Radańska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71182, 'Wda - Radańska', 'wda-radanska', 'RIVER', 53.5988505, 18.2934835, 'Kujawsko-Pomorskie', 'Osie', 'Odcinek w Radańskiej charakteryzuje się ponownym zwężeniem koryta i powrotem rzeki do meandrującego, leśnego profilu poniżej zapory. Dno jest tu twardsze, piaszczysto-żwirowe, a nurt wyraźnie przyspiesza, wymywając głębokie rynny pod brzegami. To doskonałe łowisko dla spinningistów uganiających się za kleniami, które w marcu 2026 roku stacjonują na styku prądów i zastoisk. Wędkarze spławikowi wykorzystują spowolnienia za piaszczystymi łachami, nęcąc stada pięknych jazi i cert. Woda posiada tu wybitnie mroczny, ciemny kolor, co zmusza do stosowania przynęt o wysokim kontraście lub silnej fali hydroakustycznej. Całkowite odcięcie od cywilizacji i otoczenie wysokim lasem nadają temu miejscu unikalny, niemal pierwotny charakter wędkarski.', null);

