VALUES (71182, 'Nizinna', 'Meandrująca, leśna', 20.0, 1.6, 'Piasek i żwir', 'Rynny, zakola', 'Kleń, Jaź, Certa', 'Kraina brzany', false);

-- Spot 183: Wda - Spławie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71183, 'Wda - Spławie', 'wda-splawie', 'RIVER', 53.575574, 18.3237079, 'Kujawsko-Pomorskie', 'Świecie', 'Wda w Spławiu to szeroki i stosunkowo spokojny odcinek nizinny, płynący wśród rozległych łąk i zagajników Kociewia. Piaszczyste dno tworzy tu liczne mielizny i płytkie blaty, które w słońcu marca 2026 roku stają się doskonałym żerowiskiem dla jazi i jelców. Spinningiści namierzają rzeczne okonie patrolujące krawędzie budzącej się do życia roślinności zanurzonej przy brzegach. Wędkarze feederowi z powodzeniem stosują tu metodę delikatnego nęcenia, punktując dorodne leszcze i krąpie przemieszczające się korytem głównym. Uciąg wody jest tu stabilny i łagodny, co pozwala na komfortowe wędkowanie przy użyciu najlżejszych wędzisk klasy light. Cisza wiejskiego krajobrazu i obfitość białorybu czynią Spławie wyśmienitym miejscem na relaksujący, wiosenny biwak z wędką.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71183, 'Nizinna', 'Łąkowa, szeroka', 28.0, 1.4, 'Piasek', 'Mielizny, blaty', 'Jaź, Leszcz, Okoń', 'Kraina leszcza', false);

-- Spot 184: Wda - Żur
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71184, 'Wda - Żur', 'wda-zur', 'RIVER', 53.5593869, 18.3605988, 'Kujawsko-Pomorskie', 'Osie', 'Odcinek rzeki w Żurze znajduje się bezpośrednio poniżej zapory elektrowni wodnej, co determinuje techniczny i zmienny charakter łowiska. Zrzuty wody tworzą tu głębokie, silnie natlenione rynny o bardzo twardym, kamienistym dnie, które są magnesem dla drapieżników. W marcu 2026 roku spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając potężnych szczupaków i wyrośniętych okoni. Wędkarze stacjonarni nęcą spokojniejsze zatoczki poniżej elektrowni, licząc na brania rzecznych leszczy i krąpi wchodzących z dolnego biegu. Uciąg wody bywa tu ekstremalny, co wymusza stosowanie dociążonych zestawów i precyzyjne czytanie prądów wstecznych. Surowy, industrialny krajobraz zabytkowej elektrowni nadaje temu miejscu unikalny, wysoce techniczny klimat wędkarski.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71184, 'Nizinna Wielka', 'Zrzutowa, szybka', 25.0, 3.0, 'Kamień i beton', 'Zapora, filary', 'Szczupak, Okoń, Leszcz', 'Kraina leszcza', false);

-- Spot 185: Wda - Spławie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71185, 'Wda - Spławie', 'wda-splawie-dolne', 'RIVER', 53.5332994, 18.3731087, 'Kujawsko-Pomorskie', 'Świecie', 'Wda w rejonie Spławia to malowniczy, leśny odcinek o umiarkowanym nurcie i ciemnej, humusowej barwie toni. Rzeka wije się tu wśród Borów Tucholskich, rzeźbiąc pod zalesionymi burtami głębokie rynny z licznymi powalonymi sosnami. W marcu 2026 roku to strategiczne miejsce dla łowców kleni, które doskonale reagują na małe woblery prowadzone w cieniu podmytych korzeni. Wędkarze spławikowi stosują tu metodę przepływanki, wypuszczając zestawy w głęboczki, gdzie grupują się wczesnowiosenne płocie i jazie. Podłoże jest piaszczysto-gliniaste, co zapewnia rybom białą obfitość naturalnego pokarmu i stabilne żerowanie przed tarłem. Izolacja od cywilizacji i szum lasu gwarantują wędkarzowi spokój oraz możliwość pełnego skupienia na precyzyjnym podawaniu przynęty.', null);

