VALUES (71185, 'Nizinna', 'Leśna, meandrująca', 22.0, 1.8, 'Piasek i glina', 'Zwalone drzewa, rynny', 'Kleń, Jaź, Płoć', 'Kraina brzany', false);

-- Spot 186: Wda - Abisynia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71186, 'Wda - Abisynia', 'wda-abisynia', 'RIVER', 53.9193896, 17.9547243, 'Pomorskie', 'Czersk', 'Odcinek rzeki w rejonie Abisynii płynie przez serce borów sosnowych, zachowując wybitnie dziki i nieuregulowany charakter koryta. Dno jest tu wyścielone jasnym piaskiem i drobnym żwirem, a liczne zatory z pni drzew tworzą techniczne baseny o głębokości do dwóch metrów. Marzec 2026 roku to czas aktywności pstrągów potokowych i lipieni, które chętnie zajmują stanowiska w warkoczach za naturalnymi przeszkodami. Muszkarze z sukcesami operują tu ciężkimi nimfami, sprowadzając je w najgłębsze partie rynien bezpośrednio pod nawisami traw. Przejrzystość wody wymusza na wędkarzach zachowanie absolutnej ciszy i stosowanie długich przyponów z cienkiego fluorocarbonu. To łowisko dla pasjonatów wędkarstwa podchodowego, ceniących kontakt z nienaruszoną przyrodą i walecznymi rybami łososiowatymi.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71186, 'Podgórska', 'Dzika, leśna', 15.0, 1.2, 'Piasek i żwir', 'Naturalne zatory', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 187: Wda - Studzienice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71187, 'Wda - Studzienice', 'wda-studzienice', 'RIVER', 54.0980483, 17.6133587, 'Pomorskie', 'Bytów', 'Wda w Studzienicach to górny bieg rzeki, mający formę wąskiego i czystego strumienia łączącego pobliskie systemy jeziorne. Koryto rzeki ma tu charakter torfowo-piaszczysty, co nadaje wodzie specyficzny, ciemny odcień przy jednoczesnym zachowaniu dużej przejrzystości. W marcu 2026 roku to strategiczne żerowisko dla okoni i płoci migrujących między zbiornikami w poszukiwaniu pierwszego wiosennego pokarmu. Spinningiści z powodzeniem stosują tu mikro-przynęty, obławiając niewielkie zakola i spowolnienia nurtu pod nawisami krzewów. Głębokość rzadko przekracza tu jeden metr, co czyni wędkowanie wyzwaniem technicznym wymagającym dużego wyczucia i delikatności. Malowniczy krajobraz pojezierza i bliskość natury tworzą tu idealne warunki dla wędkarzy szukających ciszy i kameralnego łowienia.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71187, 'Górska/Podgórska', 'Wąska, łącznikowa', 8.0, 0.7, 'Piasek i torf', 'Zakola, trzcinowiska', 'Okoń, Płoć, Szczupak', 'Kraina pstrąga', false);

-- Spot 188: Wda - Sominy
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71188, 'Wda - Sominy', 'wda-sominy', 'RIVER', 54.0765112, 17.6472416, 'Pomorskie', 'Bytów', 'Odcinek w Sominach to początkowy bieg Wdy wypływającej z Jeziora Somińskiego, charakteryzujący się bardzo czystą i stosunkowo płytką wodą. Dno jest tu piaszczyste, usiane pozostałościami roślinności zanurzonej, co tworzy doskonałe kryjówki dla narybku i żerującej na nim drobnicy. W marcu 2026 roku wędkarze spławikowi z sukcesami nęcą tutejsze płanie, celując w dorodne jazie i rzeczne płocie. Spinningiści z uwagą penetrują granice koryta i brzegu, szukając wczesnowiosennych szczupaków uaktywniających się w cieplejszych promieniach słońca. Uciąg wody jest łagodny, co pozwala na stosowanie bardzo finezyjnych zestawów i lekkich przynęt bez ryzyka ich szybkiego znoszenia. Łatwy dostęp do brzegów w rejonie wsi Sominy czyni to miejsce wygodnym punktem na spokojną, rodzinną sesję z wędką.', null);

