VALUES (71188, 'Nizinna', 'Płytka, wypływowa', 10.0, 0.9, 'Piasek', 'Roślinność podwodna', 'Jaź, Płoć, Szczupak', 'Kraina leszcza', false);

-- Spot 189: Wda - Skwierawy (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71189, 'Wda - Skwierawy (Południe)', 'wda-skwierawy-poludnie', 'RIVER', 54.0833363, 17.6939897, 'Pomorskie', 'Bytów', 'Wda w południowej części Skwieraw to bystry, podgórski strumień przecinający kaszubskie łąki i nieużytki. Podłoże jest tu twarde, żwirowo-kamieniste, z licznymi mikro-rynienkami, w których woda gwałtownie przyspiesza i dotlenia się. W marcu 2026 roku to wyśmienite łowisko dla spinningistów szukających pstrągów potokowych, które chętnie ustawiają się w cieniu prądowym większych otoczaków. Precyzyjne rzuty mikro-jigami pod same nawisy brzegowe są tu kluczem do sprowokowania bardzo czujnych ryb. Woda jest lodowata i krystaliczna, co wymaga od wędkarza pełnego kamuflażu i unikania gwałtownych ruchów na otwartym brzegu. Kameralna skala rzeki pozwala na jej bardzo dokładne obłowienie w ciągu zaledwie kilku godzin aktywnego marszu.', null);

