VALUES (71189, 'Górska', 'Bystra, łąkowa', 7.0, 0.6, 'Żwir i kamień', 'Bystrza, głazy', 'Pstrąg potokowy, Jelec', 'Kraina pstrąga', false);

-- Spot 190: Wda - Skwierawy (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71190, 'Wda - Skwierawy (Północ)', 'wda-skwierawy-polnoc', 'RIVER', 54.1086715, 17.711646, 'Pomorskie', 'Bytów', 'Północny odcinek w Skwierawach reprezentuje niemal źródliskowy fragment Wdy, gdzie rzeka ma postać wąskiej, energetycznej wstęgi. Dno stanowi tu mozaika grubego piasku i torfu, co w połączeniu z meandrującym korytem tworzy liczne, głębokie dołki na zakrętach. W marcu 2026 roku jest to techniczne wyzwanie dla muszkarzy, którzy używają krótkich wędzisk do podawania nimf w ciasnych przesmykach między gałęziami. Niska mętność wody i niewielka głębokość sprawiają, że ryby są tu niezwykle płochliwe i reagują na najmniejsze drżenie gruntu pod stopami wędkarza. Naturalna dzikość tego odcinka, otoczonego bagnistymi łąkami, gwarantuje wędkarzowi całkowitą izolację i kontakt z pierwotną ichtiofauną Kaszub. To łowisko "jednego rzutu", gdzie błąd w podaniu przynęty zazwyczaj kończy szanse na branie w danym dołku.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71190, 'Górska', 'Wąska, źródliskowa', 5.0, 0.5, 'Piasek i torf', 'Zakola, nawisy', 'Pstrąg potokowy, Strzebla', 'Kraina pstrąga', false);

-- Spot 191: Wisłok - Pastwiska
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71191, 'Wisłok - Pastwiska', 'wislok-pastwiska-ponizej-zapory', 'RIVER', 49.5420971, 21.9309937, 'Podkarpackie', 'Rymanów', 'Odcinek Wisłoka w Pastwiskach znajduje się bezpośrednio poniżej zrzutu wody ze zbiornika Sieniawa, co gwarantuje stałe natlenienie i niską temperaturę wody. Podłoże jest tu wybitnie kamienisto-żwirowe, z głębokimi rynnami erozyjnymi wymytymi przez silny nurt po-zrzutowy. W marcu 2026 roku to strategiczne łowisko dla muszkarzy, którzy na ciężkie nimfy kuszą tu dzikie pstrągi potokowe. Spinningiści z sukcesami obławiają cienie prądowe za dużymi otoczakami, szukając walecznych kleni wybudzonych po zimie. Brak osadów drobnych sprawia, że woda jest tu krystalicznie czysta nawet po opadach, co wymaga stosowania bardzo cienkich przyponów. To technicznie wymagająca woda o charakterze górskim, ceniona przez wędkarzy za stabilność brań i wysoką kondycję ryb.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71191, 'Górska', 'Tailwater, bystra', 20.0, 1.2, 'Kamień i żwir', 'Bystrza, jamy', 'Pstrąg potokowy, Kleń, Lipień', 'Kraina pstrąga', false);

-- Spot 192: Wisłok - Sieniawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71192, 'Wisłok - Sieniawa (Pod Zaporą)', 'wislok-sieniawa-techniczny', 'RIVER', 49.5691101, 21.9295626, 'Podkarpackie', 'Rymanów', 'Wisłok w rejonie zapory w Sieniawie to odcinek o niezwykle dynamicznej hydrologii, silnie uzależniony od aktualnej pracy elektrowni wodnej. Dno jest tu twarde, wysłane narzutem kamiennym i betonowymi elementami wzmacniającymi koryto bezpośrednio przy stopniu. Spinningiści w marcu 2026 roku penetrują tu głębokie wanny, w których grupują się okazałe okonie oraz szczupaki unikające najsilniejszego prądu. Wędkarze spławikowi z sukcesami łowią na przystawkę w warkoczach prądowych, celując w rzeczne płocie i jelce poszukujące pokarmu naniesionego ze zbiornika. Przejrzystość wody jest tu zazwyczaj wyższa niż na odcinkach naturalnych, co demaskuje gruby sprzęt i wymusza finezję. Surowy, industrialny krajobraz zapory kontrastuje z czystą górską rzeką, tworząc unikalne warunki do technicznego łowienia ryb drapieżnych.', null);

