VALUES (71192, 'Górska', 'Uregulowana, głęboka', 25.0, 2.5, 'Skała i beton', 'Zapora, opaski', 'Okoń, Szczupak, Kleń', 'Kraina pstrąga', false);

-- Spot 193: Wisłok - Besko (Górne - Jar)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71193, 'Wisłok - Besko (Jar Wisłoka)', 'wislok-besko-jar', 'RIVER', 49.5894117, 21.9579378, 'Podkarpackie', 'Besko', 'Besko to absolutnie unikalny odcinek przełomowy, gdzie rzeka wycina w litej skale głęboki wąwóz o stromych, kilkunastometrowych ścianach. W marcu 2026 roku Jar Wisłoka to techniczna mekka dla spinningistów polujących na pstrągi w wąskich, skalnych rynnach o potężnym uciągu. Podłoże stanowi tu lita skała z głębokimi rozpadlinami, w których stacjonują rekordowe brzany i wyrośnięte klenie. Wędkarze muchowi stosują tu metodę żyłkową z bardzo ciężkimi nimfami, aby przebić się przez zawirowania powierzchniowe wody. Niesamowita geomorfologia koryta wymusza na wędkarzu ciągłe przemieszczanie się po śliskich, skalnych półkach, co wymaga specjalistycznego obuwia. Dzikość przełomu i huczący nurt tworzą atmosferę niemal alpejskiej rzeki w samym sercu Pogórza Bukowskiego.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71193, 'Górska', 'Przełom skalny', 15.0, 1.8, 'Lita skała', 'Kaskady, rynny skalne', 'Pstrąg potokowy, Brzana, Kleń', 'Kraina pstrąga', false);

-- Spot 194: Wisłok - Besko (Dolne)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71194, 'Wisłok - Besko (Wypływ z Jaru)', 'wislok-besko-dolny', 'RIVER', 49.6162389, 21.9644594, 'Podkarpackie', 'Besko', 'Poniżej przełomu rzeka w Besku uwalnia się ze skalnego uścisku, rozlewając się szerzej na piaszczysto-żwirowych płaniach. Dno staje się tu bardziej wyrównane, usiane licznymi otoczakami, które tworzą naturalne bystrza idealne dla świnek i kleni. Wiosną 2026 roku jest to wyśmienite miejsce na przepływankę, gdzie wędkarze z sukcesami nęcą rynny na krawędzi nurtu głównego. Spinningiści obławiają liczne tu zwalone drzewa i krzaki, wypatrując aktywnych pstrągów potokowych przemieszczających się między dołkami. Uciąg wody jest tu żywy, ale znacznie stabilniejszy niż w samym jarze, co ułatwia precyzyjne podawanie lżejszych przynęt. Malownicza okolica wyjścia rzeki z wąwozu sprzyja długim, pieszym wycieczkom z lekkim wędziskiem spinningowym w dłoni.', null);

