VALUES (71194, 'Podgórska', 'Naturalna, żwirowa', 30.0, 1.0, 'Żwir i kamień', 'Bystrza, zwalone dęby', 'Świnka, Kleń, Pstrąg potokowy', 'Kraina brzany', false);

-- Spot 195: Wisłok - Bzianka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71195, 'Wisłok - Bzianka', 'wislok-bzianka', 'RIVER', 49.629552, 21.928024, 'Podkarpackie', 'Haczów', 'Odcinek w Bziance charakteryzuje się naturalnym, meandrującym korytem o urozmaiconym, piaszczysto-gliniastym dnie. Rzeka podmywa tu wysokie, trawiaste brzegi, tworząc głębokie rynny będące idealną ostoją dla rzecznych leszczy i okazowych kleni. W marcu 2026 roku stacjonarni łowcy białorybu z sukcesem stosują tu metodę drgającej szczytówki, nęcąc spokojniejsze zakola. Spinningiści penetrują podmyte korzenie nadrzecznych olch, szukając wczesnowiosennych szczupaków wygrzewających się na płyciznach. Uciąg rzeki jest tu umiarkowany, co sprzyja systematycznemu nęczeniu bez obawy o zbyt szybkie rozmycie zanęty. Cisza i brak większej presji wędkarskiej na tym rolniczym odcinku gwarantują spokój oraz doskonały kontakt z budzącą się do życia przyrodą.', null);

