VALUES (71195, 'Podgórska/Nizinna', 'Meandrująca, naturalna', 35.0, 1.5, 'Glina i piasek', 'Podmyte burty', 'Leszcz, Kleń, Szczupak', 'Kraina brzany', false);

-- -- Spot 196: Wisłok - Haczów (Wschód)
-- INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
-- VALUES (71196, 'Wisłok - Haczów (Bystrza Żwirowe)', 'wislok-haczow-wschod', 'RIVER', 49.6523958, 21.9052818, 'Podkarpackie', 'Haczów', 'Wisłok w Haczowie to klasyczna rzeka podgórska płynąca szerokim, ale stosunkowo płytkim korytem o wybitnie żwirowym dnie. Rzeka tworzy tu liczne, świetnie natlenione bystrza, które w marcu 2026 roku stają się żerowiskiem dla stad lipieni i świnek. To strategiczny obszar dla wędkarzy muchowych, którzy cenią sobie możliwość bezpiecznego brodzenia po twardym i stabilnym podłożu. Spinningiści z uwagą obławiają granice prądu i spokojniejszej wody za kamiennymi narzutami, szukając jazi i okoni. Przezroczystość wody i brak wysokich drzew na niektórych fragmentach brzegu ułatwiają operowanie długimi wędziskami bolońskimi. Stabilny przepływ wody sprawia, że jest to jedno z najpewniejszych łowisk w regionie dla osób zaczynających swoją przygodę z rybami reofilnymi.', null);

