-- Spot 197: Wisłok - Haczów (Zachód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71197, 'Wisłok - Haczów (Głębokie Zakola)', 'wislok-haczow-zachod', 'RIVER', 49.6778388, 21.8903378, 'Podkarpackie', 'Haczów', 'Zachodni odcinek w Haczowie prezentuje zgoła inny charakter, z głębokimi na ponad dwa metry dołami wyżłobionymi na ostrych zakrętach koryta. Dno jest tu twardsze, piaszczysto-gliniaste, co sprzyja bytowaniu brzan, które w marcu 2026 roku zajmują stanowiska w najgłębszych rynnach głównego nurtu. Wędkarze gruntowi stosują tu ciężkie koszyki zanętowe, starając się zatrzymać w polu nęcenia wędrujące pod prąd stada jazi. Spinningiści obławiają strome, gliniaste skarpy za pomocą gumowych przynęt w jaskrawych kolorach, kusząc drapieżniki w nieco mętnej, wiosennej wodzie. Zróżnicowana głębokość i liczne podwodne przeszkody w postaci korzeni wymuszają precyzję i doskonałą znajomość topografii dna. Wysokie brzegi porośnięte krzewami zapewniają dobrą osłonę przed wczesnowiosennym wiatrem, podnosząc komfort wielogodzinnych zasiadek.', null);

