-- Spot 198: Wisłok - Krościenko Wyżne (Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71198, 'Wisłok - Krościenko Wyżne (Żwirowiska)', 'wislok-kroscienko-wschod', 'RIVER', 49.6762407, 21.8486251, 'Podkarpackie', 'Krosno', 'Wisłok na wschodnich przedpolach Krosna to dynamiczna woda podgórska, silnie meandrująca wśród łąk i zagajników. Koryto wypełnia drobny żwir i rzeczne piaski, tworząc liczne przykosy, za którymi woda gwałtownie rwie, tworząc natlenione warkocze prądowe. Marzec 2026 roku to wyśmienita pora na spinningowe klenie, które na tych odcinkach atakują bardzo agresywnie w zasięgu słońca. Wędkarze przepływankowi z powodzeniem poławiają tu dorodne jelce i płocie, stosując delikatne zestawy z małym dociążeniem. Uciąg na prostych odcinkach jest stabilny, co pozwala na komfortowe wędkowanie metodą lekkiego feedera bez ryzyka częstych zaczepów. Rozległe panoramy Pogórza Dynowskiego i doskonała dostępność brzegów czynią to łowisko idealnym na weekendowe, rodzinne wyprawy z wędką.', null);

