-- Spot 199: Wisłok - Krościenko Wyżne (Zachód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71199, 'Wisłok - Krościenko Wyżne (Opaski)', 'wislok-kroscienko-zachod', 'RIVER', 49.682282, 21.807492, 'Podkarpackie', 'Krosno', 'Zachodni fragment rzeki w Krościenku Wyżnym zbliża się do zabudowań miejskich, co skutkuje większą ilością brzegowych umocnień w postaci opasek kamiennych. Dno staje się tu twardsze, z przewagą wymytych kamieni i zbitej gliny, co tworzy doskonałe rynny torowe dla reofilnych gatunków ryb. Spinningiści w marcu 2026 roku regularnie punktują tu okazałe okonie, obławiając cienie betonowych filarów i kamiennych narzutów przy brzegach. Wędkarze stacjonarni stosują cięższe zestawy bolońskie, przytrzymując przynętę w głębokim nurcie środka rzeki w poszukiwaniu cert i świnek. Uciąg jest tu wyraźnie przyspieszony przez regulację koryta, co zapewnia doskonałe warunki tlenowe nawet przy niższych stanach wód. Bliskość Krosna zapewnia doskonały dojazd, czyniąc ten odcinek jednym z najchętniej odwiedzanych punktów treningowych dla sportowych wędkarzy spławikowych.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71199, 'Podgórska', 'Uregulowana, bystra', 38.0, 1.7, 'Kamień i glina', 'Opaski kamienne, mosty', 'Okoń, Certa, Świnka', 'Kraina brzany', false);

-- Spot 200: Warta - Maniewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71200, 'Warta - Maniewo', 'warta-maniewo', 'RIVER', 52.6156342, 16.9111631, 'Wielkopolskie', 'Oborniki', 'Warta w Maniewie to typowa rzeka nizinna o szerokim korycie i uregulowanych brzegach zabezpieczonych systemem ostróg kamiennych. Dno jest tu piaszczysto-muliste, a w klatkach między główkami gromadzą się znaczne ilości osadów organicznych przyciągających ryby spokojnego żeru. W marcu 2026 roku wędkarze feederowi z sukcesami łowią tu okazałe leszcze i krąpie, nęcąc precyzyjnie w głębszych partiach zastoisk. Spinningiści obławiają szczyty ostróg, szukając wczesnowiosennych boleni żerujących na piaszczystych przelewach. Uciąg wody jest umiarkowany, co pozwala na stosowanie koszyków zanętowych o masie od 40 do 60 gramów dla stabilnej prezentacji przynęty. Malowniczy krajobraz wielkopolskich łąk i łatwy dostęp do brzegów czynią Maniewo popularnym punktem weekendowych wypraw.', null);

