VALUES (71200, 'Nizinna Wielka', 'Uregulowana, ostrogi', 65.0, 1.8, 'Piasek i muł', 'Główki, opaski', 'Leszcz, Krąp, Boleń', 'Kraina leszcza', true);

-- Spot 201: Warta - Gołaszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71201, 'Warta - Gołaszyn', 'warta-golaszyn', 'RIVER', 52.6314291, 16.8408575, 'Wielkopolskie', 'Oborniki', 'Odcinek w Gołaszynie charakteryzuje się żywym nurtem i wyraźnie zaznaczonym torem wodnym o twardszym, piaszczysto-żwirowym dnie. Rzeka żłobi tu głębokie rynny pod brzegami, stanowiące naturalne szlaki migracyjne dla ryb białego żeru przemieszczających się w górę rzeki. To strategiczne miejsce dla spinningistów polujących na klenie, które w marcu 2026 roku doskonale reagują na małe woblery prowadzone wzdłuż opasek. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie, celując w rekordowe certy i jazie wybudzone po zimowym postoju. Uciąg wody wymaga stosowania dociążonych zestawów, by skutecznie zakotwiczyć przynętę na skraju nurtu głównego i spowolnień. Stabilny stan wody i brak gęstej roślinności wynurzonej o tej porze roku ułatwiają lądowanie ryb bez użycia podbieraka.', null);

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71201, 'Nizinna Wielka', 'Naturalna, piaszczysta', 60.0, 1.5, 'Piasek i żwir', 'Opaski kamienne', 'Kleń, Certa, Jaź', 'Kraina leszcza', true);

-- Spot 202: Warta - Uścikówiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71202, 'Warta - Uścikówiec', 'warta-uscikowiec', 'RIVER', 52.6542404, 16.7755747, 'Wielkopolskie', 'Oborniki', 'Warta w Uścikówcu płynie meandrującym korytem z licznymi, podmyłymi burtami brzegowymi o gliniastym podłożu. Rzeka tworzy tu techniczne, ponaddwumetrowe rynny na zewnętrznych łukach koryta, które są bankowymi stanowiskami dla sandaczy żerujących o zmierzchu. To strategiczne miejsce dla łowców szczupaków, którzy w marcu obławiają zastoiska za zwalonymi do wody drzewami i wiklinami. Podłoże piaszczysto-gliniaste zapewnia rybom białym obfitość naturalnego pokarmu, co sprzyja systematycznemu żerowaniu leszczy. Uciąg jest zróżnicowany, co wymusza na wędkarzach precyzyjne dobieranie miejsca nęcenia względem głównego nurtu. Dzikość brzegów i utrudniony dojazd w niektóre partie rzeki zapewniają wędkarzowi spokój i brak nadmiernej presji.', null);

