VALUES (71202, 'Nizinna Wielka', 'Meandrująca, dzika', 55.0, 2.2, 'Glina i piasek', 'Podmyte brzegi', 'Sandacz, Szczupak, Leszcz', 'Kraina leszcza', true);

-- Spot 203: Warta - Bąblin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71203, 'Warta - Bąblin', 'warta-bablin', 'RIVER', 52.6742139, 16.7081375, 'Wielkopolskie', 'Oborniki', 'Odcinek w Bąblinie to kraina rozległych łąk nadwarciańskich, gdzie rzeka rozlewa się szeroko, tworząc płytkie przelewy i piaszczyste łachy. Dno jest tu wybitnie piaszczyste, z dynamicznie przemieszczającymi się przykosami, za którymi tworzą się dotlenione warkocze prądowe. To strategiczny obszar dla łowców boleni, które w marcu 2026 roku intensywnie żerują na drobnej uklei przy powierzchni. Wędkarze gruntowi szukają ryb w głębszych dołkach wyżłobionych tuż przed samymi łukami rzeki, gdzie woda znosi naturalny pokarm. Uciąg wody jest tu łagodniejszy niż w nurcie uregulowanym, co pozwala na stosowanie lżejszych zestawów feederowych. Brak wysokiej roślinności brzegowej sprawia, że jest to doskonałe łowisko do dalekich rzutów spinningowych w stronę środka koryta.', null);

