VALUES (71203, 'Nizinna Wielka', 'Naturalna, płytka', 70.0, 1.3, 'Piasek', 'Przykosy, łachy', 'Boleń, Kleń, Płoć', 'Kraina leszcza', true);

-- Spot 204: Warta - Komorze Przybysławskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71204, 'Warta - Komorze Przybysławskie', 'warta-komorze-przybyslawskie', 'RIVER', 52.1424186, 17.6504013, 'Wielkopolskie', 'Żerków', 'Łowisko w Komorzu Przybysławskim leży w obszarze Żerkowsko-Czeszewskiego Parku Krajobrazowego, oferując unikalny mikroklimat i bogaty rybostan. Rzeka płynie tu szerokim korytem o mulisto-piaszczystym dnie, z licznymi starorzeczami okresowo połączonymi z głównym nurtem. W marcu 2026 roku te spowolnienia stają się eldorado dla łowców grubych leszczy i krąpi, które szukają tu odpoczynku przed tarłem. Spinningiści z sukcesami penetrują pasy trzcinowisk, szukając wczesnowiosennych szczupaków i okoni przyklejonych do krawędzi nurtu. Uciąg rzeki jest tu znikomy, co pozwala na stosowanie bardzo delikatnych zestawów spławikowych i drgającej szczytówki. Niezwykłe walory krajobrazowe doliny Warty i obecność rzadkich gatunków ptaków czynią wędkowanie w tym miejscu czystym relaksem.', null);

