VALUES (71204, 'Nizinna Wielka', 'Szeroka, rozlewiskowa', 80.0, 2.0, 'Piasek i muł', 'Zastoiska, starorzecza', 'Leszcz, Krąp, Szczupak', 'Kraina leszcza', true);

-- Spot 205: Warta - Czeszewo (Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71205, 'Warta - Czeszewo (Lasy)', 'warta-czeszewo-wschod', 'RIVER', 52.1421762, 17.5765685, 'Wielkopolskie', 'Września', 'Odcinek w Czeszewie przepływa przez chronione obszary leśne, charakteryzując się niezwykle dzikim profilem koryta z licznymi powalonymi dębami. Rzeka żłobi tu techniczne rynny pod brzegami, stanowiące naturalną ostoję dla rekordowych sumów i brzan stacjonujących w nurcie. W marcu 2026 roku spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając szczupaków czatujących w cieniu zatopionych konarów. Podłoże jest tu twarde, piaszczysto-żwirowe, co zapewnia rybom reofilnym doskonałe warunki do żerowania przez cały sezon. Ze względu na dużą ilość podwodnych zawad, wymagane jest stosowanie mocniejszych zestawów z odpornymi na przetarcia przyponami. Cisza rezerwatu Czeszewskie Lasy i brak miejskiego zgiełku nadają każdemu wędkowaniu w tym miejscu unikalnego, pierwotnego wymiaru.', null);

