-- Spot 206: Warta - Czeszewo (Prom)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71206, 'Warta - Czeszewo (Przeprawa)', 'warta-czeszewo-zachod', 'RIVER', 52.1433387, 17.5030419, 'Wielkopolskie', 'Września', 'Wisła w rejonie przeprawy promowej w Czeszewie charakteryzuje się dynamicznym nurtem i obecnością technicznych opasek kamiennych wzmacniających brzegi. Podłoże jest tu twarde, piaszczysto-żwirowe, z głębokimi rynnami toru wodnego sięgającymi ponad trzech metrów głębokości pod przeciwległym brzegiem. To strategiczne miejsce dla łowców sandaczy, którzy w marcu 2026 roku wykorzystują turbulentną wodę wokół infrastruktury do polowania z opadu. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze i jazie migrujące okresowo z dolnego biegu. Uciąg wody jest tu zdecydowany i stały, co wymaga stosowania dociążonych zestawów gruntowych dla stabilnej prezentacji przynęty. Bliskość promu zapewnia doskonały punkt orientacyjny i ułatwia przemieszczanie się między najciekawszymi stanowiskami brzegowymi.', null);

