-- Spot 207: Warta - Pięczkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71207, 'Warta - Pięczkowo', 'warta-pieczkowo', 'RIVER', 52.1031103, 17.4695135, 'Wielkopolskie', 'Środa Wielkopolska', 'Odcinek w Pięczkowie to klasyczna kraina rozległych przykos i piaszczystych łach, które dynamicznie zmieniają swój profil po zimowych wezbraniach. Rzeka rozlewa się tu szeroko, tworząc mozaikę płytkich przelewów i głębszych rynien, idealnych dla żerujących w marcu boleni. To strategiczne miejsce dla łowców drapieżników, którzy namierzają stada uklei przy turbulentnych warkoczach powstających na łukach koryta. Podłoże piaszczysto-żwirowe stanowi idealne żerowisko dla stad jelców oraz dorodnych płoci szukających pokarmu w nurcie głównym. Uciąg wody jest żywy i zmienny, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji tutejszego rybostanu. Dzikość brzegów i brak uregulowań hydrotechnicznych nadają temu łowisku unikalny charakter, wymagający od wędkarza umiejętności czytania wody.', null);

