-- Spot 208: Warta - Nowe Miasto nad Wartą
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71208, 'Warta - Nowe Miasto', 'warta-nowe-miasto-nad-warta', 'RIVER', 52.0927668, 17.3966742, 'Wielkopolskie', 'Jarocin', 'Warta w Nowym Mieście płynie uregulowanym korytem o twardym, kamienisto-żwirowym dnie i umocnionych opaskami brzegach. Pod filarami mostu drogowego nurt jest silnie wymyty, tworząc techniczne rynny sięgające nawet czterech metrów głębokości. To strategiczne miejsce dla spinningistów polujących na sandacze, które w marcu 2026 roku stacjonują w cieniu prądowym betonowych konstrukcji. Wędkarze stacjonarni z sukcesami łowią tu okazałe leszcze i certy, wykorzystując systematyczne nęcenie w spowolnieniach nurtu za filarami. Uciąg rzeki jest tu stabilny, ale zdecydowany, co sprzyja doskonałemu natlenieniu wody i aktywności ryb reofilnych. Dobra infrastruktura i łatwy dojazd do brzegów w rejonie miasta czynią Nowe Miasto popularnym punktem wypraw dla lokalnych wędkarzy.', null);

