-- Spot 209: Warta - Solec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71209, 'Warta - Solec', 'warta-solec', 'RIVER', 52.0975115, 17.323368, 'Wielkopolskie', 'Jarocin', 'Warta w Solcu charakteryzuje się szerokimi zakolami oraz obecnością rozległych piaszczystych przykos, które dynamicznie modelują koryto rzeki. Dno jest tu piaszczysto-gliniaste, co w marcu 2026 roku przyciąga stada białorybu szukającego pokarmu na stokach rynien. Spinningiści z sukcesami obławiają tu warkocze prądowe powstające na styku głównego nurtu i spokojniejszych zatoczek. Uciąg rzeki jest umiarkowany, pozwalając na stosowanie klasycznych zestawów feederowych z koszykami o masie około 50 gramów. To strategiczne miejsce dla łowców kleni, które o tej porze roku grupują się w zasięgu słońca przy podmytych brzegach. Okolica jest cicha i zapewnia komfortowe warunki do wielogodzinnych, technicznych zasiadek brzegowych.', null);

