-- Spot 210: Warta - Promnice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71210, 'Warta - Promnice', 'warta-promnice', 'RIVER', 52.5341845, 16.9612717, 'Wielkopolskie', 'Poznań', 'Odcinek rzeki w Promnicach posiada uregulowany charakter z wyraźnie zaznaczonym systemem ostróg kamiennych stabilizujących brzeg. Podłoże wewnątrz klatek między główkami jest mulisto-piaszczyste, natomiast na szczytach budowli dominuje twardy kamień i żwir. W marcu 2026 roku miejsce to słynie z dobrych wyników w połowie sandaczy techniką ciężkiego opadu w torze wodnym. Wędkarze stacjonarni nęcą strefy prądowe za główkami, celując w dorodne certy i jazie wchodzące w rzekę z dolnego biegu. Uciąg jest stabilny i wymusza stosowanie dociążonych zestawów, aby skutecznie utrzymać przynętę w strefie przydennej. Bliskość aglomeracji poznańskiej sprawia, że jest to popularny punkt na szybkie, popołudniowe wyprawy spinningowe.', null);

