-- Spot 211: Warta - Santok (Ujście Noteci)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71211, 'Warta - Santok', 'warta-santok-ujscie', 'RIVER', 52.7354598, 15.4041549, 'Lubuskie', 'Gorzów Wielkopolski', 'Santok to strategiczny węzeł hydrologiczny, gdzie wody Noteci łączą się z Wartą, tworząc szerokie i głębokie koryto o bardzo zmiennych prądach. Dno jest tu niezwykle urozmaicone, piaszczysto-żwirowe z licznymi uskokami i rynnami wyżłobionymi przez zderzające się masy wody. Marzec 2026 roku to czas, w którym drapieżniki takie jak bolenie i szczupaki intensywnie żerują w warkoczu ujściowym. Wędkarze gruntowi z powodzeniem poławiają tu rekordowe leszcze, wykorzystując systematyczne nęcenie w najgłębszych partiach koryta. Złożona dynamika wody wymaga od wędkarza dużej precyzji w doborze obciążenia i umiejętności czytania zawirowań na powierzchni. Historyczne położenie miejscowości i ogromna przestrzeń nad wodą nadają temu łowisku wyjątkowy, majestatyczny klimat.', null);

