-- Spot 212: Warta - Czechów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71212, 'Warta - Czechów', 'warta-czechow', 'RIVER', 52.7274069, 15.3295391, 'Lubuskie', 'Gorzów Wielkopolski', 'Warta w Czechowie to potężna, nizinna rzeka płynąca szerokim korytem o dominującym piaszczystym podłożu i nielicznych kamiennych opaskach. Rzeka formuje tu długie przykosy, za którymi woda gwałtownie zapada się w dotlenione rynny o głębokości dochodzącej do trzech metrów. To doskonałe łowisko dla spinningistów polujących na klenie, które w marcu 2026 roku zajmują stanowiska w cieniu prądowym naturalnych przeszkód. Wędkarze feederowi z sukcesami obławiają piaszczyste blaty, celując w stada płoci i jazi przemieszczających się korytem głównym. Uciąg wody jest tu zdecydowany, co sprzyja wysokiej aktywności ryb reofilnych poszukujących pokarmu niesionego przez nurt. Otwarty krajobraz doliny Warty ułatwia dalekie rzuty i pozwala na swobodne przemieszczanie się wzdłuż linii brzegowej.', null);

