-- Spot 213: Warta - Gorzów Wielkopolski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71213, 'Warta - Gorzów Wielkopolski', 'warta-gorzow-bulwary', 'RIVER', 52.7299259, 15.2540941, 'Lubuskie', 'Gorzów Wielkopolski', 'Miejski odcinek Warty w Gorzowie charakteryzuje się głębokim profilem koryta z silnie uregulowanymi nabrzeżami i potężnymi filarami mostów. Podłoże pod przeprawami drogowymi jest silnie wymyte, tworząc techniczne rynny będące idealnym zimowiskiem dla sandaczy i sumów. W marcu 2026 roku to strategiczne miejsce dla fanów streetfishingu, którzy skutecznie kuszą okonie w cieniu bulwarów miejskich. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za konstrukcjami hydrotechnicznymi, nęcąc stada okazałych leszczy i krąpi. Uciąg rzeki jest tu stabilny, ale potężny, co wymaga stosowania ciężkiego sprzętu gruntowego do stabilnej prezentacji zestawu. Dobra infrastruktura i oświetlenie brzegów pozwalają na bezpieczne wędkowanie również w godzinach wieczornych i nocnych.', null);

