-- Spot 214: Warta - Stryszewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71214, 'Warta - Stryszewo', 'warta-stryszewo', 'RIVER', 52.6289828, 15.793978, 'Lubuskie', 'Międzychód', 'Odcinek w Stryszewie powraca do dzikiej natury, silnie meandrująca pośród lasów i łąk z licznymi podmywanymi burtami. Koryto jest tu usiane zwalonymi do wody drzewami, które tworzą naturalne zatory i głębokie jamy o gliniasto-piaszczystym dnie. To wymarzone łowisko dla spinningistów szukających szczupaków, które w marcu 2026 roku czatują w spokojniejszych zastoiskach brzegowych. Wędkarze spławikowi z sukcesami łowią na przystawkę w cieniu zatopionych korzeni, celując w dorodne płocie i jazie. Uciąg jest zróżnicowany, co wymusza na wędkarzach ciągłe poszukiwanie optymalnych stref nęcenia względem głównego prądu rzeki. Dzikość terenu i utrudniony dostęp do wielu zakoli gwarantują wędkarzowi spokój oraz brak nadmiernej presji.', null);

