-- Spot 215: Warta - Krobielewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71215, 'Warta - Krobielewo', 'warta-krobielewo', 'RIVER', 52.630577, 15.7174615, 'Lubuskie', 'Międzychód', 'Warta w Krobielewie to klasyczna, szeroka rzeka nizinna o naturalnym charakterze z licznymi piaszczystymi łachami i wyspami brzegowymi. Dno składa się w głównej mierze z drobnego piasku, który nieustannie przemieszcza się, formując nowe przykosy i rynny torowe. W marcu 2026 roku te płytkie, dobrze nasłonecznione strefy stają się magnesem dla boleni polujących na stada drobnej uklei. Fani metody feederowej rozstawiają się na rozległych płaniach, posyłając zestawy w głębsze rynienki rzeźbione w dnie przez nurt. Uciąg wody jest umiarkowany, co pozwala na stosowanie lżejszych metod i precyzyjne sygnalizowanie nawet najdelikatniejszych brań. Izolacja od dużych miast i piękno lubuskiej przyrody nadają temu miejscu unikalny, wyciszający charakter wędkarski.', null);

