-- Spot 216: Warta - Krasne Dłusko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71216, 'Warta - Krasne Dłusko', 'warta-krasne-dlusko', 'RIVER', 52.6235998, 15.6422895, 'Lubuskie', 'Skwierzyna', 'Odcinek w Krasnym Dłusku charakteryzuje się dynamicznym nurtem i obecnością technicznych opasek kamiennych chroniących wysokie brzegi rzeki. Podłoże jest tu wyjątkowo twarde, piaszczysto-żwirowe, co w marcu 2026 roku przyciąga rekordowe brzany i klenie żerujące w głównym nurcie. Spinningiści z sukcesami obławiają tutejsze warkocze, rzucając cięższymi woblerami w poszukiwaniu sandaczy stacjonujących przy dnie koryta. Wędkarze gruntowi stosują koszyki o gramaturze powyżej 60 gramów, aby skutecznie utrzymać zestaw na krawędzi piaszczystego stoku rynny. Woda jest tu doskonale natleniona, co sprzyja wysokiej waleczności ryb i ich szybkiemu wybudzaniu się po zimowym postoju. Surowość brzegów i zdecydowany przepływ wody czynią to łowisko wyzwaniem dla technicznie zaawansowanych wędkarzy rzecznych.', null);

