-- Spot 218: Warta - Chojno-Młyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71218, 'Warta - Chojno-Młyn', 'warta-chojno-mlyn', 'RIVER', 52.6835492, 16.1682543, 'Wielkopolskie', 'Wronki', 'Warta w rejonie Chojno-Młyn to jeden z najdzikszych fragmentów rzeki, płynący w głębokim wykopie wśród lasów Puszczy Noteckiej. Koryto silnie tu meandruje, tworząc głębokie rynny na zewnętrznych łukach oraz rozległe piaszczyste łachy po stronie wewnętrznej. Marzec 2026 roku to idealny czas na namierzenie grubych jazi, które gromadzą się w spokojniejszych warkoczach za powalonymi do wody drzewami. Spinningiści z sukcesami obławiają podmyte burty, stosując technikę wolnego prowadzenia przynęt gumowych w poszukiwaniu wczesnowiosennych szczupaków. Dno jest tu piaszczysto-gliniaste, co zapewnia obfitość naturalnego pokarmu i przyciąga stada rzecznych leszczy w głębsze partie koryta. Izolacja od dużych aglomeracji i brak cywilizacyjnego zgiełku nadają temu miejscu unikalny, niemal pierwotny charakter wędkarski.', null);

