-- Spot 219: Warta - Bucharzewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71219, 'Warta - Bucharzewo', 'warta-bucharzewo', 'RIVER', 52.6612085, 16.1021037, 'Wielkopolskie', 'Sieraków', 'Odcinek w Bucharzewie charakteryzuje się bardzo wysokimi, podmywanymi brzegami, które odsłaniają twarde pokłady gliny i systemy korzeniowe starych drzew. Rzeka rzeźbi tu głębokie rynny dochodzące do trzech metrów głębokości, będące bankowymi kryjówkami dla okazowych sumów i sandaczy. W marcu 2026 roku wędkarze stacjonarni z powodzeniem stosują tu metodę przystawki spławikowej, nęcąc strefy cienia prądowego za podwodnymi przeszkodami. Spinningiści muszą wykazać się dużą precyzją rzutów, sprowadzając przynęty w wąskie pasma wolniejszej wody tuż pod zarośniętym brzegiem. Uciąg na środku rzeki jest zdecydowany, co sprzyja doskonałemu natlenieniu łowiska i wysokiej aktywności ryb reofilnych. Surowość terenu i utrudniony dostęp do lustra wody wymagają posiadania podbieraka z długą sztycą do bezpiecznego lądowania ryby.', null);

