-- Spot 220: Warta - Kobylarnia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71220, 'Warta - Kobylarnia', 'warta-kobylarnia', 'RIVER', 52.6385616, 16.0347771, 'Wielkopolskie', 'Sieraków', 'Łowisko w Kobylarni to klasyczna kraina piaszczystych przykos i szerokich rozlewisk, gdzie rzeka rozlewa swe wody na dużej przestrzeni. Dno składa się w głównej mierze z drobnego piasku, który pod wpływem nurtu formuje wędrujące łachy i dotlenione przelewy powierzchniowe. To strategiczne miejsce dla łowców boleni, które w marcu 2026 roku namierzają stada uklei grupujące się na płytszych, nasłonecznionych blatach. Wędkarze feederowi z sukcesami obławiają stoki rynien rzeźbionych między przykosami, celując w dorodne certy oraz rzeczne krąpie. Uciąg jest tu umiarkowany, co pozwala na stosowanie lżejszych zestawów gruntowych i finezyjne sygnalizowanie brań na miękkich szczytówkach. Otwarty krajobraz doliny Warty ułatwia dalekie rzuty i pozwala na swobodne przemieszczanie się wzdłuż piaszczystej linii brzegowej.', null);

