-- Spot 221: Warta - Zatom Stary
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71221, 'Warta - Zatom Stary', 'warta-zatom-stary', 'RIVER', 52.6376766, 15.9594788, 'Wielkopolskie', 'Międzychód', 'Warta w Zatomiu Starym charakteryzuje się uregulowanym nabrzeżem w rejonie przeprawy promowej oraz systemem krótkich ostróg kamiennych. Podłoże jest tu twarde, piaszczysto-żwirowe z wyraźnie zaznaczonym nurtem głównym biegnącym blisko toru nawigacyjnego. Marzec 2026 roku to czas aktywności dużych kleni, które chętnie ustawiają się w turbulentnej wodzie za konstrukcjami hydrotechnicznymi. Wędkarze gruntowi nęcą tutejsze głębokie rynny pod brzegami, licząc na brania rekordowych leszczy migrujących z dolnego biegu rzeki. Uciąg wody jest stabilny i zdecydowany, co wymusza stosowanie dociążonych koszyków zanętowych dla stabilnej prezentacji przynęty. Bliskość promu i dogodna infrastruktura w pobliżu miejscowości czynią to miejsce bardzo komfortowym punktem na kilkugodzinne sesje z wędką.', null);

