-- Spot 222: Warta - Przedlesie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71222, 'Warta - Przedlesie', 'warta-przedlesie', 'RIVER', 52.617147, 15.8925305, 'Wielkopolskie', 'Międzychód', 'Odcinek w Przedlesiu to głęboka rynna rzeczna o twardym, gliniastym dnie i stromych skarpach porośniętych gęstymi wiklinami. Rzeka płynie tu węższym korytem, co przyspiesza nurt i tworzy doskonałe warunki tlenowe dla ryb reofilnych przez cały sezon. Spinningiści w marcu 2026 roku z sukcesami penetrują tutejsze warkocze, szukając sandaczy stacjonujących w cieniu prądowym naturalnych przeszkód brzegowych. Wędkarze stacjonarni stosują ciężkie zestawy feederowe, starając się zatrzymać w polu nęcenia wędrujące pod prąd stada jazi i krąpi. Uciąg wody w tym miejscu bywa bardzo silny, co wymaga od wędkarza dużej siły i odporności zestawu podczas holu większych okazów. Dzikość brzegów i brak gęstej zabudowy w bezpośrednim sąsiedztwie rzeki gwarantują spokój oraz brak nadmiernej presji ze strony innych łowiących.', null);

