-- Spot 223: Warta - Kiszewko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71223, 'Warta - Kiszewko', 'warta-kiszewko', 'RIVER', 52.6888188, 16.6373014, 'Wielkopolskie', 'Oborniki', 'Warta w Kiszewku rozlewa się szeroko wśród nadwarciańskich łąk, formując liczne piaszczyste łachy i płytkie, natlenione warkocze prądowe. Podłoże składa się w głównej mierze z drobnego piasku, który nieustannie przemieszcza się, formując nowe przykosy i rynny torowe na zakrętach. W marcu 2026 roku te płytkie, dobrze nasłonecznione strefy stają się magnesem dla jazi i kleni żerujących na budzącej się do życia faunie dennej. Fani metody feederowej rozstawiają się na rozległych płaniach, posyłając zestawy w głębsze rynienki rzeźbione w piasku przez główny nurt rzeki. Uciąg wody jest tu umiarkowany, co pozwala na stosowanie lżejszych metod i precyzyjne sygnalizowanie nawet najdelikatniejszych brań białorybu. Malowniczy krajobraz wielkopolskiej wsi i łatwy dostęp do brzegu czynią Kiszewko idealnym miejscem na relaksujące, wiosenne wędkowanie.', null);

