-- Spot 224: Warta - Stobnicko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71224, 'Warta - Stobnicko', 'warta-stobnicko', 'RIVER', 52.7124054, 16.5692442, 'Wielkopolskie', 'Oborniki', 'Odcinek w Stobnicku charakteryzuje się szybszym przepływem wody przez piaszczysto-żwirowe bystrza i techniczne opaski kamienne chroniące wysoki brzeg. Rzeka żłobi tu głębokie rynny pod brzegami, stanowiące naturalną trasę dla ryb drapieżnych polujących na drobnicę w nurcie głównym. Spinningiści w marcu 2026 roku regularnie notują tu brania okazałych boleni, które wykorzystują turbulentną wodę na szczytach opasek do ataku. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, celując w dorodne certy i płocie stacjonujące w najgłębszych partiach toru głównego. Uciąg rzeki jest tu zdecydowany, co zapewnia doskonałe warunki tlenowe i przekłada się na wysoką waleczność holowanych tu rzecznych mocarzy. Bliskość puszczańskich lasów i unikalny charakter rzeki o podwyższonym uciągu czynią Stobnicko jednym z najciekawszych technicznie łowisk w tym regionie.', null);

