INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71227, 'Warta - Stare Miasto', 'warta-stare-miasto-wronki', 'RIVER', 52.7029843, 16.3502683, 'Wielkopolskie', 'Wronki', 'Odcinek w Starym Mieście to techniczne łowisko zlokalizowane w rejonie dawnych przepraw, charakteryzujące się umocnionymi kamieniami brzegami. Podłoże jest tu twarde, piaszczysto-żwirowe, z wyraźnie zaznaczonym torem wodnym biegnącym blisko lewego brzegu. Wczesną wiosną 2026 roku miejsce to słynie z obecności wyrośniętych kleni, które doskonale reagują na małe woblery prowadzone w dryfie. Wędkarze feederowi z sukcesami obławiają stoki rynien, licząc na brania rekordowych leszczy i cert gromadzących się przy przeszkodach. Uciąg wody jest stabilny i przewidywalny, co pozwala na precyzyjne budowanie dywanu zanętowego bez ryzyka jego szybkiego rozmycia. Łatwy dojazd i relatywnie twarde brzegi czynią to miejsce bardzo komfortowym punktem na kilkugodzinne sesje z wędką.', null);

