-- Spot 228: Warta - Wartosław
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71228, 'Warta - Wartosław', 'warta-wartoslaw', 'RIVER', 52.7199, 16.2814749, 'Wielkopolskie', 'Wronki', 'Wartosław to jedno z najbardziej znanych łowisk w regionie, słynące z przeprawy promowej i głębokich rynien wymytych w łukach koryta. Dno jest tu niezwykle urozmaicone, piaszczysto-żwirowe z licznymi twardymi uskokami na krawędzi toru nawigacyjnego. Marzec 2026 roku to strategiczny moment dla łowców sandaczy, którzy wykorzystują turbulentną wodę wokół infrastruktury promu. Wędkarze stacjonarni nęcą tutejsze głębokie wanny, z sukcesami poławiając grube rzeczne płocie i krąpie na delikatne zestawy spławikowe. Złożona dynamika wody wymaga od wędkarza dużej precyzji w doborze obciążenia i umiejętności czytania zawirowań prądowych. Malownicze położenie miejscowości i historyczny klimat przeprawy nadają każdemu wędkowaniu w tym miejscu wyjątkowej atmosfery.', null);

