-- Spot 229: Warta - Gogolewko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71229, 'Warta - Gogolewko', 'warta-gogolewko', 'RIVER', 52.1057669, 17.2502064, 'Wielkopolskie', 'Książ Wielkopolski', 'Warta w Gogolewku rozlewa się szeroko wśród nizinnych łąk, formując liczne zakola o mulisto-piaszczystym podłożu. Rzeka płynie tu wolniej, co w marcu 2026 roku sprzyja szybszemu nagrzewaniu się płytszych zatoczek brzegowych i uaktywnianiu białorybu. To wymarzone łowisko dla fanów metody feederowej, którzy precyzyjnie nęcą krawędzie nurtu w poszukiwaniu dorodnych leszczy. Spinningiści obławiają granice budzącej się do życia roślinności zanurzonej, szukając wczesnowiosennych szczupaków i okoni. Uciąg jest stabilny i łagodny, co pozwala na stosowanie bardzo finezyjnych zestawów z cienkimi żyłkami i małymi haczykami. Rozległe panoramy doliny Warty i absolutna cisza sprawiają, że Gogolewko to idealne miejsce na ucieczkę od miejskiego zgiełku.', null);

