-- Spot 230: Warta - Kępa Mała
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71230, 'Warta - Kępa Mała', 'warta-kepa-mala', 'RIVER', 52.0993541, 17.1764041, 'Wielkopolskie', 'Śrem', 'Odcinek w Kępie Małej charakteryzuje się licznymi podmywanymi burtami i głębokimi rynnami wyżłobionymi w twardej, nadwarciańskiej glinie. Podłoże w korycie głównym jest piaszczyste, jednak przy samych brzegach dominują zwalone pnie drzew tworzące doskonałe kryjówki dla sumów. Marzec 2026 roku to czas aktywności jazi i kleni, które chętnie zajmują stanowiska w cieniu prądowym naturalnych przeszkód. Wędkarze gruntowi stosują tu dociążone koszyki zanętowe, starając się dotrzeć do ryb żerujących w najgłębszych partiach koryta. Uciąg rzeki jest tu żywy, co zapewnia doskonałe natlenienie wody i wysoką kondycję tutejszego rybostanu po okresie zimowym. Dzikość brzegów porośniętych gęstą wikliną wymaga od wędkarza determinacji przy przedzieraniu się na najbardziej obiecujące stanowiska.', null);

