-- Spot 231: Warta - Mechlin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71231, 'Warta - Mechlin', 'warta-mechlin', 'RIVER', 52.0997602, 17.1025452, 'Wielkopolskie', 'Śrem', 'Mechlin to klasyczna kraina rozległych przykos i piaszczystych łach, gdzie rzeka nieustannie modeluje swój profil po wiosennych przyborach. Dno składa się w głównej mierze z drobnego piasku, formującego dotlenione przelewy, na których w marcu 2026 roku żerują stada uklei. To strategiczne miejsce dla łowców boleni, które wykorzystują turbulentną wodę na krawędziach łach do błyskawicznych ataków. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w głębsze rynienki rzeźbione przez nurt torowy. Uciąg jest umiarkowany, co ułatwia precyzyjne sygnalizowanie brań i pozwala na stosowanie lżejszych, czulszych wędzisk klasy light. Otwarty i dostępny brzeg sprzyja rodzinnemu wędkowaniu, oferując bezpieczne i wygodne warunki do rozstawienia rozbudowanego stanowiska.', null);

