-- Spot 232: Warta - Śrem
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71232, 'Warta - Śrem (Bulwary)', 'warta-srem-bulwary', 'RIVER', 52.0874995, 17.0320381, 'Wielkopolskie', 'Śrem', 'Miejski odcinek Warty w Śremie charakteryzuje się uregulowanymi nabrzeżami i głębokim profilem koryta o twardym, kamienisto-betonowym dnie. Pod filarami mostów nurt jest silnie wymyty, tworząc rynny sięgające czterech metrów głębokości, będące idealnym zimowiskiem dla sandaczy. W marcu 2026 roku to strategiczne miejsce dla pasjonatów streetfishingu, którzy z sukcesami poławiają okonie wzdłuż murów oporowych bulwarów. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za konstrukcjami hydrotechnicznymi, nęcąc stada okazałych leszczy i cert wchodzących w rzekę. Uciąg rzeki jest tu stabilny, ale zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji przynęty. Dobra infrastruktura miejska, oświetlenie i łatwy dostęp do brzegów czynią Śrem jednym z najwygodniejszych łowisk w regionie.', null);

