-- Spot 233: Warta - Psarskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71233, 'Warta - Psarskie', 'warta-psarskie', 'RIVER', 52.12447, 16.9882633, 'Wielkopolskie', 'Śrem', 'Warta w Psarskim płynie szerokim, spokojnym korytem o dnie zdominowanym przez gruby piasek i drobny żwir. Rzeka formuje tu łagodne zakola, pod którymi w marcu 2026 roku tworzą się rynny będące idealnym stanowiskiem dla cert i dużych płoci. Spinningiści z sukcesami obławiają tu piaszczyste przykosy, szukając boleni aktywujących się przy powierzchni w słoneczne dni. Wędkarze gruntowi stosują lekkie zestawy feederowe, nęcąc strefy na krawędzi nurtu głównego, gdzie woda niesie najwięcej pokarmu. Uciąg jest stabilny i przewidywalny, co pozwala na precyzyjne operowanie zestawami spławikowymi typu bolońskiego. Bliskość Śremu zapewnia dogodny dojazd, a otwarte brzegi ułatwiają dalekie rzuty w stronę toru wodnego.', null);

