-- Spot 234: Warta - Orkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71234, 'Warta - Orkowo', 'warta-orkowo', 'RIVER', 52.1698803, 16.990277, 'Wielkopolskie', 'Śrem', 'Odcinek w Orkowie charakteryzuje się licznymi starorzeczami okresowo połączonymi z głównym nurtem rzeki podczas wiosennych wezbrań. Koryto główne posiada tu piaszczysto-muliste dno z wyraźnie zaznaczonymi spowolnieniami prądu na wewnętrznych łukach meandrów. To strategiczne miejsce dla łowców szczupaków, którzy w marcu 2026 roku obławiają granice budzącej się roślinności zanurzonej. Wędkarze stacjonarni z sukcesami nęcą tutejsze głębokie zatoki, celując w dorodne krąpie i leszcze szukające cieplejszej wody. Uciąg wody jest tu łagodny, co sprzyja stosowaniu delikatnych metod spławikowych i precyzyjnemu nęceniu punktowemu. Malowniczy krajobraz nadwarciańskich łęgów zapewnia wędkarzowi spokój oraz doskonałą osłonę przed wiatrem dzięki gęstym zaroślom brzegowym.', null);

