-- Spot 235: Warta - Radzewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71235, 'Warta - Radzewice', 'warta-radzewice', 'RIVER', 52.2143181, 16.9780621, 'Wielkopolskie', 'Poznań', 'Warta w Radzewicach płynie dynamicznie, podmywając wysokie brzegi i rzeźbiąc głębokie rynny w twardym, gliniastym podłożu. Pod wodą zalegają liczne powalone dęby, które stanowią bankowe kryjówki dla rekordowych sumów i okazowych kleni. Marzec 2026 roku to czas aktywności jazi, które chętnie ustawiają się w turbulentnej wodzie na krawędzi nurtu głównego. Spinningiści muszą wykazać się tu dużą precyzją, prowadząc przynęty w wąskich pasmach wolniejszej wody tuż obok zawad. Uciąg rzeki jest zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych przy metodzie gruntowej. Dziki charakter tego odcinka rzeki i utrudniony dostęp do niektórych stanowisk gwarantują wędkarzowi ciszę i brak nadmiernej presji.', null);

