-- Spot 236: Warta - Rogalin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71236, 'Warta - Rogalin', 'warta-rogalin', 'RIVER', 52.2335219, 16.9115933, 'Wielkopolskie', 'Mosina', 'Legendarny odcinek rzeki w Rogalinie słynie z rozległych piaszczystych plaż i płytkich przykos rozciągających się na dużej przestrzeni. Dno składa się w głównej mierze z drobnego piasku, który nieustannie przemieszcza się, formując nowe rynny torowe po zimowych przyborach. To strategiczne łowisko dla spinningistów polujących na bolenie, które w marcu 2026 roku uganiają się za drobnicą na piaszczystych przelewach. Wędkarze feederowi rozstawiają się na piaszczystych łachach, posyłając zestawy w głębsze partie koryta w poszukiwaniu jazi i cert. Uciąg jest tu umiarkowany, co ułatwia precyzyjne sygnalizowanie brań nawet przy użyciu bardzo delikatnych wędzisk. Unikalne sąsiedztwo wiekowych dębów rogalińskich nadaje temu miejscu niepowtarzalny klimat, czyniąc każdą wyprawę estetycznym przeżyciem.', null);

