-- Spot 237: Warta - Puszczykowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71237, 'Warta - Puszczykowo', 'warta-puszczykowo', 'RIVER', 52.2718237, 16.8722452, 'Wielkopolskie', 'Puszczykowo', 'Odcinek w Puszczykowie to miejsce, gdzie Wda wcina się w zalesione pagórki Wielkopolskiego Parku Narodowego, co nadaje rzece niemal przełomowy charakter. Dno jest tu twardsze, piaszczysto-żwirowe z licznymi kamiennymi opaskami chroniącymi wysokie brzegi w rejonie zabudowań. Spinningiści w marcu 2026 roku regularnie punktują tu okazałe okonie, obławiając cienie prądowe mostów i umocnień. Wędkarze stacjonarni stosują technikę klasycznego feedera, nęcąc głębokie rynny toru wodnego w poszukiwaniu rzecznych leszczy. Uciąg jest tu wyraźnie przyspieszony, co zapewnia doskonałe natlenienie wody i wysoką waleczność zaciętych ryb. Bliskość aglomeracji poznańskiej i rewelacyjny dojazd czynią Puszczykowo jednym z najpopularniejszych łowisk na szybkie sesje wędkarskie po pracy.', null);

