-- Spot 238: Warta - Radomsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71238, 'Warta - Radomsko', 'warta-radomsko', 'RIVER', 51.0258793, 19.403024, 'Łódzkie', 'Radomsko', 'Górny bieg Warty w rejonie Radomska to rzeka o zupełnie innym obliczu, charakteryzująca się wąskim korytem i bystrym nurtem. Podłoże jest tu twarde, kamienisto-żwirowe, co sprzyja bytowaniu ryb reofilnych, takich jak brzany i świnki. W marcu 2026 roku to strategiczne miejsce dla spinningistów szukających kleni, które ustawiają się w warkoczach prądowych za większymi głazami. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, nęcąc precyzyjnie wąskie rynny toru głównego. Uciąg wody jest zdecydowany, co wymusza stosowanie finezyjnych, ale mocnych zestawów zdolnych wytrzymać walkę w nurcie. Bliskość miasta zapewnia łatwy dostęp do rzeki, a urozmaicone dno czyni ten odcinek technicznie wymagającym wyzwaniem dla każdego wędkarza.', null);

