-- Spot 239: Warta - Szczepocice Rządowe
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71239, 'Warta - Szczepocice Rządowe', 'warta-szczepocice', 'RIVER', 51.0249394, 19.3315084, 'Łódzkie', 'Radomsko', 'Warta w Szczepocicach Rządowych zachowuje swój naturalny, meandrujący charakter z licznymi podmywanymi burtami i piaszczystymi łachami. Rzeka żłobi tu techniczne dołki pod zwalonymi do wody drzewami, które w marcu 2026 roku stają się idealną kryjówką dla szczupaków. Podłoże piaszczysto-żwirowe stanowi bogate żerowisko dla jazi i cert migrujących w górę rzeki na tarliska. Spinningiści z uwagą penetrują granice szybkiego nurtu i spokojniejszych zastoisk brzegowych, wykorzystując lekkie woblery. Wędkarze feederowi z sukcesami nęcą tutejsze rynienki, licząc na brania dorodnych płoci i jelców. Dzikość brzegów i niewielka szerokość koryta nadają temu miejscu unikalny, kameralny klimat sprzyjający aktywnemu wędkowaniu z podchodu.', null);

