-- Spot 240: Warta - Kijów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71240, 'Warta - Kijów', 'warta-kijow', 'RIVER', 51.0334778, 19.2611623, 'Łódzkie', 'Kruszyna', 'Odcinek rzeki w Kijowie charakteryzuje się płytkimi, żwirowymi przelewami i dynamicznymi bystrzami o twardym dnie. Woda jest tu znakomicie natleniona, co przyciąga stada świnek oraz waleczne brzany żerujące intensywnie w marcu 2026 roku. Spinningiści obławiają tutejsze warkocze prądowe małymi smużakami, wyczekując widowiskowych uderzeń kleni. Wędkarze spławikowi wykorzystują spowolnienia za kamiennymi narzutami, nęcąc stada pięknych jazi i jelców. Niska mętność wody wymusza na wędkarzach zachowanie absolutnej ciszy i stosowanie długich przyponów z fluorocarbonu. Płaski krajobraz doliny Warty ułatwia operowanie wędziskiem, jednak brak osłony drzew sprawia, że łowienie bywa trudne w wietrzne dni.', null);

