-- Spot 241: Warta - Prusicko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71241, 'Warta - Prusicko', 'warta-prusicko', 'RIVER', 51.0383027, 19.1889527, 'Łódzkie', 'Nowa Brzeźnica', 'Odcinek w Prusicku to fascynujące łowisko rzeczne, gdzie Warta płynie głębokim korytem wyżłobionym w wapiennym podłożu jury. Dno jest tu wybitnie twarde, usiane licznymi kamieniami i fragmentami skał, co tworzy idealne warunki dla największych brzan w regionie. W marcu 2026 roku wędkarze stacjonarni stosują tu ciężkie zestawy gruntowe z pęczkiem czerwonych robaków, polując w najgłębszych rynnach. Spinningiści z sukcesami obławiają strome, podmyte burty, szukając sandaczy i okoni czatujących w cieniu prądowym skalnych załomów. Uciąg wody jest tu stały i silny, co sprzyja wysokiej aktywności ryb praktycznie przez całą dobę wędkarską. Dzikość brzegów porośniętych gęstymi wiklinami zapewnia wędkarzowi poczucie izolacji i możliwość kontaktu z surową, rzeczną naturą.', null);

