VALUES (71241, 'Podgórska', 'Erozyjna, skalista', 32.0, 2.2, 'Skała i kamień', 'Skalne jamy, rynny', 'Brzana, Sandacz, Okoń', 'Kraina brzany', false);

-- Spot 242: Warta - Stoczki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71242, 'Warta - Stoczki', 'warta-stoczki', 'RIVER', 51.0510238, 19.120273, 'Łódzkie', 'Radomsko', 'Górny bieg Warty w Stoczkach charakteryzuje się naturalnym, meandrującym korytem o dnie piaszczysto-żwirowym z licznymi głazami. Rzeka płynie tu w dość głębokim wcięciu, co sprzyja powstawaniu wysokich, podmytych burt stanowiących ostoje dla okazałych kleni. Spinningiści w marcu 2026 roku namierzają tu ryby w głębszych rynnach, stosując technikę powolnego prowadzenia małych woblerów pod prąd. Wędkarze spławikowi z sukcesami łowią dorodne jelce i płocie, nęcąc strefy spowolnienia nurtu za naturalnymi przeszkodami. Uciąg rzeki jest tu żywy, co zapewnia doskonałe natlenienie wody i wysoką kondycję ryb reofilnych przed wiosennym tarłem. Dzikość brzegów i niewielka presja wędkarska czynią to miejsce idealnym dla osób szukających spokoju i technicznego wyzwania.', null);

