VALUES (71242, 'Podgórska', 'Naturalna, meandrująca', 30.0, 1.2, 'Piasek i żwir', 'Podmyte burty, głazy', 'Kleń, Jelec, Płoć', 'Kraina brzany', false);

-- Spot 243: Warta - Konin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71243, 'Warta - Konin (Bulwary)', 'warta-konin-ciepla', 'RIVER', 52.2283793, 18.2919359, 'Wielkopolskie', 'Konin', 'Odcinek Warty w Koninie jest unikalny w skali kraju ze względu na system kanałów zrzutowych ciepłej wody z pobliskich elektrowni. W marcu 2026 roku temperatura wody jest tu znacznie wyższa niż w innych rzekach, co stymuluje ryby do intensywnego żerowania przez całą zimę. To strategiczne miejsce dla łowców amurów i karpi, które w tym mikroklimacie osiągają rekordowe rozmiary i wykazują dużą aktywność. Wędkarze gruntowi stosują ciężkie zestawy feederowe, nęcąc precyzyjnie w nurcie głównym, gdzie stacjonują stada ogromnych leszczy. Spinningiści z sukcesami polują na bolenie i sandacze, wykorzystując turbulentne warkocze powstające przy betonowych umocnieniach bulwarów. Miejska infrastruktura zapewnia rewelacyjny dojazd i komfortowe stanowiska, czyniąc Konin wędkarskim sercem regionu o każdej porze roku.', null);

