VALUES (71243, 'Nizinna Wielka', 'Uregulowana, woda ciepła', 60.0, 2.5, 'Piasek i beton', 'Bulwary, zrzuty ciepłej wody', 'Amur, Leszcz, Sandacz', 'Kraina leszcza', true);

-- Spot 244: Warta - Ciążeń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71244, 'Warta - Ciążeń', 'warta-ciazen', 'RIVER', 52.2063583, 17.8097709, 'Wielkopolskie', 'Słupca', 'Warta w Ciążeniu płynie przez rozległe poldery, charakteryzując się szerokim korytem i dobrze zachowanym systemem ostróg kamiennych. Podłoże wewnątrz klatek między główkami jest mulisto-piaszczyste, co sprzyja gromadzeniu się białorybu w spowolnieniach nurtu. Wiosną 2026 roku wędkarze feederowi z powodzeniem łowią tu dorodne leszcze i krąpie, nęcąc stoki rynien wyżłobionych na szczytach główek. Spinningiści obławiają warkocze prądowe, szukając wczesnowiosennych boleni żerujących na piaszczystych przelewach środka rzeki. Uciąg wody jest stabilny i zdecydowany, co wymaga stosowania koszyków zanętowych o masie od 50 do 80 gramów. Malowniczy krajobraz doliny Warty i brak gęstej zabudowy zapewniają wędkarzowi spokój oraz doskonałe warunki do wielogodzinnych zasiadek.', null);

