-- Spot 245: Warta - Białobrzeg
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71245, 'Warta - Białobrzeg', 'warta-bialobrzeg-wielkopolskie', 'RIVER', 52.1760427, 17.7528661, 'Wielkopolskie', 'Września', 'Odcinek w Białobrzegu to kraina głębokich meandrów i piaszczystych przykos, które dynamicznie zmieniają swój profil po zimowych przyborach wody. Rzeka rzeźbi tu techniczne rynny na zewnętrznych łukach koryta, dochodzące do trzech metrów głębokości, stanowiące ostoje dla sandaczy. W marcu 2026 roku strategicznym celem spinningistów są klenie i jazie, doskonale reagujące na małe przynęty gumowe prowadzone w dryfie. Wędkarze stacjonarni nęcą tutejsze płanie, celując w rekordowe płocie szukające pokarmu na pograniczu głównego nurtu i zastoisk. Podłoże piaszczysto-gliniaste zapewnia rybom obfitość naturalnego pokarmu, co bezpośrednio przekłada się na ich wysoką masę i waleczność. Dzikość brzegów porośniętych gęstymi wiklinami wymaga od wędkarza determinacji w poszukiwaniu najlepszych, ukrytych stanowisk brzegowych.', null);

