-- Spot 246: Warta - Rumin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71246, 'Warta - Rumin', 'warta-rumin', 'RIVER', 52.2091291, 18.1720558, 'Wielkopolskie', 'Konin', 'Warta w Ruminie to szeroka rzeka nizinna płynąca w otoczeniu rozległych polderów zalewowych, co determinuje jej charakter po wiosennych roztopach. Dno jest tu piaszczyste z licznymi wypłyceniami i łachami, które w marcu 2026 roku stają się żerowiskiem dla stad uklei i boleni. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w głębsze rynienki toru głównego w poszukiwaniu cert. Spinningiści z uwagą obserwują lustro wody, namierzając charakterystyczne uderzenia drapieżników na krawędziach przykos rzecznych. Uciąg jest umiarkowany, co ułatwia precyzyjne sygnalizowanie brań nawet przy użyciu bardzo delikatnych wędzisk klasy light. Spokojna okolica i łatwy dostęp do brzegu w wielu miejscach czynią Rumin doskonałym łowiskiem na rozpoczęcie sezonu rzecznego.', null);

