VALUES (71246, 'Nizinna Wielka', 'Szeroka, rozlewiskowa', 75.0, 1.5, 'Piasek', 'Przykosy, poldery', 'Certa, Boleń, Leszcz', 'Kraina leszcza', true);

-- Spot 247: Warta - Karczewice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71247, 'Warta - Karczewice', 'warta-karczewice', 'RIVER', 50.887807, 19.4347388, 'Śląskie', 'Kłomnice', 'Odcinek rzeki w Karczewicach charakteryzuje się wpływem wapiennego podłoża Jury, co skutkuje twardym, kamienisto-żwirowym dnem i bystrym nurtem. Rzeka żłobi tu głębokie rynny w gliniastym podłożu, tworząc idealne warunki dla największych brzan w górnym biegu Warty. W marcu 2026 roku wędkarze stacjonarni stosują tu ciężkie zestawy gruntowe, polując w najgłębszych rynnach na ryby reofilne. Spinningiści z sukcesami obławiają tutejsze bystrza i warkocze prądowe, szukając okazałych kleni stacjonujących za większymi głazami. Woda zachowuje tu zazwyczaj wysoką przejrzystość, co wymaga od wędkarza stosowania finezyjnych zestawów i dyskretnego zachowania na brzegu. Surowy, podgórski charakter rzeki w tym rejonie czyni to łowisko wyzwaniem dla technicznie zaawansowanych poszukiwaczy rzecznych trofeów.', null);

