-- Spot 248: Warta - Częstochowa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71248, 'Warta - Częstochowa (Miejska)', 'warta-czestochowa-centrum', 'RIVER', 50.8240837, 19.2091248, 'Śląskie', 'Częstochowa', 'Miejski odcinek Warty w Częstochowie ma charakter płytkiej rzeki podgórskiej o dnie usianym drobnym kamieniem i żwirem. Nurt jest tu wartki, z licznymi bystrzami i rynnami wymytymi pod filarami miejskich mostów, co sprzyja doskonałemu natlenieniu wody. To strategiczne miejsce dla fanów streetfishingu, którzy w marcu 2026 roku z sukcesami poławiają okonie i klenie w cieniu miejskich zabudowań. Wędkarze spławikowi wykorzystują spowolnienia za kamiennymi narzutami, nęcąc stada pięknych jazi i rzecznych płoci. Uciąg wody jest żywy i zmienny, co wymusza na wędkarzach precyzyjne operowanie lekkim sprzętem klasy ultralight. Dobra infrastruktura, oświetlenie brzegów i łatwy dostęp czynią ten odcinek idealnym miejscem na krótkie, techniczne sesje po pracy.', null);

