-- Spot 249: Warta - Masłońskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71249, 'Warta - Masłońskie (Cofka Poraja)', 'warta-maslonskie', 'RIVER', 50.628159, 19.2337322, 'Śląskie', 'Poraj', 'Łowisko w Masłońskim znajduje się w bezpośredniej strefie cofki Zbiornika Poraj, gdzie nurt Warty gwałtownie zwalnia, a koryto zaczyna się rozszerzać. Podłoże jest tu piaszczysto-muliste z licznymi zastoiskami brzegowymi i pasami trzcinowisk, stanowiącymi idealne tarliska. W marcu 2026 roku to strategiczne miejsce dla łowców wczesnowiosennych płoci, leszczy i krąpi, które masowo wchodzą tu ze zbiornika na żer. Spinningiści z sukcesami obławiają granice budzącej się do życia roślinności zanurzonej, szukając szczupaków i wyrośniętych okoni. Znikomy uciąg wody pozwala na stosowanie najdelikatniejszych metod feederowych i spławikowych, zapewniając wybitną czułość sygnalizacji brań. Malownicze położenie nad zatoką zbiornika i łatwy dostęp do brzegów czynią Masłońskie popularnym punktem na spokojne, rodzinne wędkowanie.', null);

