-- Spot 250: Warta - Korwinów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71250, 'Warta - Korwinów', 'warta-korwinow', 'RIVER', 50.7297668, 19.1772353, 'Śląskie', 'Częstochowa', 'Warta w Korwinowie to wąska i niezwykle bystra rzeka o charakterze podgórskim, płynąca w malowniczej dolinie wśród lasów i łąk. Dno jest tu wybitnie twarde, wysłane drobnym żwirem i licznymi otoczakami, co sprzyja doskonałemu natlenieniu wody przez cały rok. To strategiczne miejsce dla spinningistów szukających kleni, które w marcu 2026 roku chętnie ustawiają się w cieniu prądowym naturalnych zatorów. Wędkarze spławikowi z sukcesami łowią tu dorodne jelce i płocie techniką lekkiej przepływanki w nurcie głównym. Niska mętność wody i niewielka szerokość koryta wymuszają na wędkarzu zachowanie absolutnej ciszy i stosowanie finezyjnych zestawów. Dzikość brzegów i brak zabudowy sprawiają, że jest to jedno z najbardziej urokliwych miejsc na górnej Warcie.', null);

