-- Spot 251: Warta - Wąsosz Dolny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71251, 'Warta - Wąsosz Dolny', 'warta-wasosz-dolny', 'RIVER', 51.0703266, 18.9996998, 'Śląskie', 'Kłobuck', 'Odcinek rzeki w Wąsoszu Dolnym charakteryzuje się licznymi meandrami o zróżnicowanym dnie, gdzie piaszczyste przykosy przeplatają się z gliniastymi rynnami. Rzeka żłobi tu techniczne dołki na zewnętrznych łukach zakoli, które w marcu 2026 roku są bankowymi stanowiskami dla wczesnowiosennych szczupaków. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie, celując w rekordowe krąpie i leszcze przemieszczające się korytem głównym. Spinningiści obławiają podmyte burty brzegowe, wykorzystując małe gumy do kuszenia okoni stacjonujących przy podwodnych przeszkodach. Uciąg wody jest tu umiarkowany, co pozwala na stosowanie lżejszych metod feederowych i precyzyjne sygnalizowanie delikatnych brań. Piaszczyste brzegi i łatwy dostęp do wody czynią to miejsce popularnym punktem na spokojne, weekendowe wyprawy.', null);

