-- Spot 252: Warta - Lelity
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71252, 'Warta - Lelity', 'warta-lelity', 'RIVER', 51.0927698, 18.9362361, 'Śląskie', 'Działoszyn', 'Warta w rejonie Lelit wchodzi w obszar o silniejszym nachyleniu terenu, co skutkuje przyspieszeniem nurtu i wymyciem osadów drobnych z koryta. Podłoże jest tu twarde, piaszczysto-żwirowe, z wyraźnie zaznaczonym nurtem głównym rzeźbiącym głęboką rynnę pośrodku rzeki. To strategiczne stanowisko dla łowców brzan, które w marcu 2026 roku grupują się w najszybszym prądzie bogatym w życiodajny tlen. Spinningiści z uwagą penetrują tutejsze warkocze, szukając okazałych boleni żerujących na piaszczystych przelewach przykos rzecznych. Stabilny przepływ wody sprzyja systematycznemu nęczeniu, co pozwala utrzymać stada białorybu w łowisku przez długie godziny. Dzikość krajobrazu i otoczenie lasów nadają temu miejscu unikalny charakter, wymagający od wędkarza umiejętności czytania wody.', null);

