-- Spot 253: Warta - Przywóz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71253, 'Warta - Przywóz', 'warta-przywoz', 'RIVER', 51.1265843, 18.7092644, 'Łódzkie', 'Wieluń', 'Odcinek w Przywozie leży w sercu Załęczańskiego Parku Krajobrazowego, gdzie rzeka tworzy spektakularny "Wielki Łuk Warty". Koryto płynie tu szerokim korytem o bardzo urozmaiconym profilu dna, gdzie wapienne progi skalne tworzą naturalne bystrza i kaskady. Marzec 2026 roku to idealny czas na namierzenie kleni i cert, które upodobały sobie tutejsze natlenione rynny skalne. Wędkarze muchowi chętnie obławiają głębsze warkocze za głazami, stosując ciężkie nimfy w celu sprowokowania ryb reofilnych. Uciąg wody jest tu zmienny, zależny od ukształtowania skalnego dna, co wymaga od wędkarza dużej precyzji w prowadzeniu zestawu. Niezwykłe walory geomorfologiczne i cisza rezerwatu sprawiają, że wędkowanie w Przywozie to kontakt z zupełnie dziką rzeką.', null);

