-- Spot 254: Warta - Bobrowniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71254, 'Warta - Bobrowniki (Przełom)', 'warta-bobrowniki', 'RIVER', 51.1004725, 18.7759281, 'Łódzkie', 'Działoszyn', 'Warta w Bobrownikach przebija się przez wapienne wzniesienia Jury, tworząc głęboki przełom o niezwykle twardym i kamienistym dnie. Rzeka rzeźbi tu głębokie wanny w skalnym podłożu, które stanowią bezpieczne gniazda dla największych sumów i brzan w regionie. W marcu 2026 roku spinningiści z sukcesami obławiają strome, skaliste burty, wykorzystując woblery o silnej akcji w celu zwabienia drapieżników. Wędkarze stacjonarni stosują ciężkie zestawy gruntowe, starając się zakotwiczyć przynętę w rynnach torowych o silnym uciągu. Przezroczystość wody w tym miejscu jest wybitna, co wymusza stosowanie długich przyponów z fluorocarbonu i dyskretne podejście do krawędzi wody. Surowość skalnego krajobrazu i huczący nurt nadają temu łowisku klimat górskiej rzeki, będąc wyzwaniem dla technicznie zaawansowanych łowców.', null);

