-- Spot 255: Warta - Kochlew
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71255, 'Warta - Kochlew', 'warta-kochlew', 'RIVER', 51.2126825, 18.7877738, 'Łódzkie', 'Działoszyn', 'Łowisko w Kochlewie charakteryzuje się naturalnym przebiegiem koryta z licznymi piaszczystymi wyspami i łachami dzielącymi nurt na mniejsze odnogi. Podłoże jest piaszczysto-żwirowe, a rzeka tworzy tu rozległe płanie o umiarkowanym nurcie, idealne dla ryb spokojnego żeru. W marcu 2026 roku wędkarze feederowi z powodzeniem poławiają tu dorodne leszcze i jazie, nęcąc strefy styku prądów przy wyspach. Spinningiści patrolują piaszczyste przykosy, szukając wczesnowiosennych boleni żerujących na drobnej uklei w płytkiej wodzie. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne podawanie przynęt i komfortowe wędkowanie nawet przy wyższych stanach wody. Malowniczy krajobraz doliny rzeki i dogodny dostęp do wielu stanowisk brzegowych czynią Kochlew doskonałym miejscem na rodzinne zasiadki.', null);

