-- Spot 256: Warta - Działoszyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71256, 'Warta - Działoszyn (Miejska)', 'warta-dzialoszyn-centrum', 'RIVER', 51.1088243, 18.8554822, 'Łódzkie', 'Działoszyn', 'Miejski odcinek Warty w Działoszynie to woda o uregulowanych brzegach, wzmocnionych kamiennymi opaskami i systemem ostróg brzegowych. Dno jest tu twarde, kamienisto-żwirowe, z wyraźnie pogłębionym nurtem głównym biegnącym środkiem koryta. Wczesną wiosną 2026 roku to strategiczne miejsce dla fanów streetfishingu, którzy z sukcesami poławiają okonie w cieniu mostów i bulwarów. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za konstrukcjami hydrotechnicznymi, nęcąc stada okazałych jazi i płoci. Uciąg wody jest tu zdecydowany, co zapewnia doskonałe warunki tlenowe i przekłada się na wysoką waleczność zaciętych ryb reofilnych. Dobra infrastruktura miejska i łatwy dostęp do brzegu w rejonie centrum czynią to łowisko idealnym na szybkie sesje po pracy z lekkim sprzętem.', null);

