-- Spot 257: Warta - Częstochowa (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71257, 'Warta - Częstochowa (Bugaj)', 'warta-czestochowa-poludnie', 'RIVER', 50.7997357, 19.1320079, 'Śląskie', 'Częstochowa', 'Południowy odcinek Warty w Częstochowie, w rejonie Bugaju, charakteryzuje się naturalnym profilem koryta z licznymi podmyciami i żwirowymi bystrzami. Rzeka żłobi tu głębokie rynienki pod brzegami, stanowiące naturalną trasę dla kleni i jazi żerujących intensywnie w marcu 2026 roku. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe małymi smużakami, wyczekując widowiskowych uderzeń drapieżników. Wędkarze spławikowi wykorzystują spowolnienia za kamiennymi narzutami, nęcąc stada rzecznych płoci i jelców na delikatne zestawy. Uciąg wody jest tu żywy i zmienny, co zapewnia doskonałe natlenienie łowiska i wysoką kondycję ryb po okresie zimowym. Spokojniejsza okolica w porównaniu do centrum miasta pozwala na komfortowe wędkowanie w otoczeniu zieleni i budzącej się do życia przyrody.', null);

