VALUES (71257, 'Podgórska', 'Naturalna, bystra', 28.0, 1.0, 'Żwir i kamień', 'Bystrza, rynienki', 'Kleń, Jaź, Jelec', 'Kraina brzany', false);

-- Spot 258: Warta - Zawiercie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71258, 'Warta - Zawiercie', 'warta-zawiercie', 'RIVER', 50.5060921, 19.3934013, 'Śląskie', 'Zawiercie', 'Warta w Zawierciu to początkowy bieg rzeki, mający formę czystego, płytkiego strumienia płynącego po twardym, jurajskim dnie. Podłoże jest tu głównie kamienisto-żwirowe, co w połączeniu z wartkim nurtem stwarza idealne warunki tlenowe dla ryb reofilnych. W marcu 2026 roku to strategiczne miejsce dla spinningistów szukających kleni, które grupują się w niewielkich rynienkach pod nawisami traw. Wędkarze spławikowi z sukcesami łowią tu dorodne jelce, stosując bardzo delikatne zestawy z małym obciążeniem. Niska mętność wody wymaga od wędkarza zachowania szczególnej ostrożności i stosowania cienkich przyponów z fluorocarbonu. Kameralny charakter rzeki w tym rejonie zapewnia spokój i możliwość technicznego łowienia z podchodu na krótkim dystansie.', null);

