-- Spot 259: Warta - Myszków (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71259, 'Warta - Myszków (Południe)', 'warta-myszkow-poludnie', 'RIVER', 50.5520664, 19.3517198, 'Śląskie', 'Myszków', 'Odcinek rzeki w południowej części Myszkowa charakteryzuje się nieznacznym rozszerzeniem koryta i obecnością głębszych dołków na zakrętach. Dno jest tu piaszczysto-kamieniste, z licznymi mikro-warkoczami powstającymi za naturalnymi przeszkodami w nurcie. Wczesną wiosną 2026 roku spinningiści namierzają tu klenie i okonie, prowadząc najmniejsze woblery tuż nad dnem w spowolnieniach prądu. Wędkarze gruntowi stosują tu lekkie wędziska typu picker, nęcąc precyzyjnie wąskie pasma rynien torowych w poszukiwaniu rzecznych płoci. Uciąg jest żywy, ale stabilny, co sprzyja doskonałemu natlenieniu koryta i wysokiej kondycji tutejszego rybostanu. Bliskość infrastruktury miejskiej zapewnia łatwy dojazd, jednak dzikie brzegi pozwalają na odnalezienie cichych i rybnych stanowisk.', null);

