-- Spot 260: Warta - Myszków (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71260, 'Warta - Myszków (Północ)', 'warta-myszkow-polnoc', 'RIVER', 50.5832541, 19.2987025, 'Śląskie', 'Myszków', 'Północny fragment rzeki w Myszkowie to techniczne łowisko o urozmaiconym nurcie i twardym podłożu usianym drobnymi otoczakami. Rzeka rzeźbi tu liczne bystrza i przelewy, które w marcu 2026 roku stają się żerowiskiem dla walecznych stad świdników i kleni. Spinningiści z sukcesami stosują tu metodę aktywnego marszu, obławiając warkocze prądowe małymi przynętami gumowymi. Wędkarze spławikowi wykorzystują głębsze rynienki pod brzegami, nęcąc stada jazi migrujących w stronę Zbiornika Poraj. Woda zachowuje tu wysoką przejrzystość, co zmusza do stosowania finezyjnych technik i zachowania dystansu od lustra wody. Malowniczy krajobraz pogranicza Jury i stabilny przepływ wody czynią ten odcinek wyjątkowo atrakcyjnym dla miłośników lekkiego rzecznego łowienia.', null);

