-- Spot 261: Warta - Waki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71261, 'Warta - Waki', 'warta-waki', 'RIVER', 52.2064011, 18.5107348, 'Wielkopolskie', 'Koło', 'Warta w miejscowości Waki to szeroka, nizinna rzeka o uregulowanych brzegach zabezpieczonych systemem ostróg kamiennych. Podłoże wewnątrz klatek między główkami jest piaszczysto-muliste, co przyciąga w marcu 2026 roku stada dorodnych leszczy i krąpi. Wędkarze feederowi z sukcesami obławiają tutejsze spowolnienia nurtu, stosując spoiste zanęty rzeczne z dużą ilością jokersa. Spinningiści namierzają warkocze prądowe na szczytach główek, poszukując sandaczy stacjonujących w cieniu prądowym betonowych umocnień. Uciąg na środku rzeki jest zdecydowany, co wymaga stosowania koszyków o masie od 60 do 90 gramów dla stabilnej prezentacji. Otwarty krajobraz doliny Warty i dobra dostępność do klatek między główkami czynią to miejsce bardzo wygodnym na długie zasiadki.', null);

