-- Spot 262: Warta - Piersk
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71262, 'Warta - Piersk', 'warta-piersk', 'RIVER', 52.2102709, 18.4374576, 'Wielkopolskie', 'Konin', 'Odcinek rzeki w Piersku słynie z rozległych piaszczystych przykos, które dynamicznie modelują koryto rzeki po wiosennych przyborach wody. Dno składa się w głównej mierze z drobnego piasku, tworzącego dotlenione przelewy idealne dla żerujących w marcu 2026 roku boleni. Fani metody feederowej rozstawiają się na piaszczystych łachach, posyłając zestawy w głębsze rynny rzeźbione przez główny nurt torowy. Spinningiści z uwagą obserwują lustro wody, namierzając ataki drapieżników na stada drobnej uklei gromadzącej się na płyciznach. Uciąg jest tu umiarkowany i bardzo stabilny, co pozwala na stosowanie lżejszych wędzisk i precyzyjne sygnalizowanie brań. Dzikość brzegów i brak gęstej zabudowy w bezpośrednim sąsiedztwie rzeki gwarantują wędkarzowi spokój oraz bezpośredni kontakt z naturą.', null);

