VALUES (71262, 'Nizinna Wielka', 'Naturalna, piaszczysta', 65.0, 1.5, 'Piasek', 'Przykosy, łachy', 'Boleń, Leszcz, Jaź', 'Kraina leszcza', true);

-- Spot 263: Warta - Żrekie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71263, 'Warta - Żrekie', 'warta-zrekie', 'RIVER', 52.2147503, 18.3636283, 'Wielkopolskie', 'Konin', 'Warta w Żrekiem płynie głębokim korytem o twardym, gliniastym dnie i stromych burtach na zewnętrznych łukach meandrów. Rzeka rzeźbi tu techniczne rynny brzegowe dochodzące do trzech metrów głębokości, będące idealnym zimowiskiem dla sandaczy i dużych szczupaków. Spinningiści w marcu 2026 roku z sukcesami stosują technikę ciężkiego opadu, badając krawędzie piaszczystych blatów i głębin. Wędkarze stacjonarni nęcą spokojniejsze zakola, licząc na brania rekordowych leszczy wchodzących w rzekę z dolnego biegu. Uciąg wody jest tu zdecydowany, co zapewnia doskonałe natlenienie łowiska i wysoką aktywność ryb reofilnych. Wysoki brzeg porośnięty krzewami zapewnia doskonałą osłonę przed wiatrem, jednak wymaga posiadania podbieraka z długą sztycą do bezpiecznego lądowania ryb.', null);

