-- Spot 264: Warta - Lutomirów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71264, 'Warta - Lutomirów', 'warta-lutomirow', 'RIVER', 52.1053181, 18.6917868, 'Wielkopolskie', 'Koło', 'Łowisko w Lutomirowie charakteryzuje się bardzo szerokim korytem i obecnością licznych piaszczystych wysp brzegowych dzielących nurt na mniejsze odnogi. Podłoże jest tu piaszczysto-żwirowe, co w marcu 2026 roku przyciąga rekordowe brzany i klenie żerujące w doskonale natlenionej wodzie. Fani metody feederowej rozstawiają się na rozległych płaniach, celując w stada jazi i cert przemieszczających się korytem głównym. Spinningiści obławiają turbulentne warkocze prądowe powstające na styku nurtów przy wyspach, szukając boleni. Uciąg rzeki jest tu żywy i zmienny, co wymusza na wędkarzach ciągłe dostosowywanie gramatury obciążenia do aktualnych warunków. Otwarty krajobraz doliny Warty ułatwia dalekie rzuty i pozwala na swobodne przemieszczanie się wzdłuż piaszczystej linii brzegowej rzeki.', null);

