-- Spot 265: Warta - Ostrowsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71265, 'Warta - Ostrowsko', 'warta-ostrowsko', 'RIVER', 51.9877822, 18.7707413, 'Łódzkie', 'Uniejów', 'Warta w Ostrowsku płynie szerokim łukiem przez tereny nizinne, charakteryzując się znaczną głębokością toru wodnego i piaszczystym dnem. Bliskość Uniejowa i wpływ wód termalnych może nieznacznie podnosić temperaturę wody, co stymuluje ryby do wcześniejszego żerowania w marcu 2026 roku. To strategiczne miejsce dla łowców dużych leszczy, które masowo gromadzą się na stokach rynien toru nawigacyjnego. Spinningiści z sukcesami obławiają tu piaszczyste przykosy, szukając boleni oraz okoni patrolujących krawędzie nurtu głównego. Uciąg wody jest stabilny i zdecydowany, co sprzyja precyzyjnemu nęczeniu i utrzymywaniu stad białorybu w polu łowienia. Szerokie i trawiaste brzegi ułatwiają operowanie długimi wędziskami bolońskimi oraz zapewniają wysoki komfort podczas wielogodzinnych zasiadek gruntowych.', null);

