-- Spot 266: Warta - Góry
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71266, 'Warta - Góry', 'warta-gory', 'RIVER', 52.0236462, 18.7256285, 'Wielkopolskie', 'Uniejów', 'Warta w Górach to klasyczna rzeka nizinna o szerokim korycie i piaszczystym dnie, poprzecinanym licznymi przykosami. Nurt rzeźbi tu regularne rynny na krawędzi toru wodnego, które w marcu 2026 roku stanowią główne szlaki migracyjne dla jazi i cert. Spinningiści z sukcesami obławiają piaszczyste blaty, szukając boleni aktywujących się przy powierzchni w cieplejsze popołudnia. Wędkarze gruntowi stosują tu zestawy feederowe z koszykami o masie 50-70 gramów, nęcąc stoki rynien spoistą zanętą. Uciąg rzeki jest stabilny, co sprzyja precyzyjnemu lokowaniu przynęty w wybranej strefie żerowania ryb. Dziki, łąkowy krajobraz i brak wysokich skarp ułatwiają dostęp do rzeki, czyniąc to miejsce idealnym na całodzienne zasiadki.', 'PZW Konin');

