-- Spot 267: Warta - Tomisławice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71267, 'Warta - Tomisławice (Cofka)', 'warta-tomislawice', 'RIVER', 51.742751, 18.6422849, 'Łódzkie', 'Warta', 'Odcinek w Tomisławicach znajduje się w strefie cofki Zbiornika Jeziorsko, gdzie nurt rzeki wyraźnie zwalnia i rozlewa się na poldery. Podłoże jest tu piaszczysto-muliste z licznymi zastoiskami brzegowymi, które wiosną 2026 roku stają się doskonałym tarliskiem dla białorybu. Spinningiści namierzają tu okonie i wczesnowiosenne szczupaki, obławiając granice budzącej się do życia roślinności wynurzonej. Wędkarze gruntowi nęcą tutejsze rozległe płanie, celując w rekordowe krąpie i leszcze wchodzące w rzekę ze zbiornika. Ze względu na znikomy uciąg, możliwe jest stosowanie bardzo czułych zestawów z drgającą szczytówką i niewielkich obciążeń. Malownicze rozlewiska i bogata awifauna nadają temu miejscu unikalny, wyciszający charakter wędkarski.', 'PZW Sieradz');

