-- Spot 268: Warta - Ostrów Warcki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71268, 'Warta - Ostrów Warcki (Przystań)', 'warta-ostrow-warcki', 'RIVER', 51.7941248, 18.6676597, 'Łódzkie', 'Warta', 'Łowisko w Ostrowie Warckim zlokalizowane jest bezpośrednio przy głównym korycie wpływającym do czaszy zbiornika Jeziorsko. Dno jest tu miękkie, muliste z głębokimi rynnami toru nawigacyjnego, które w marcu 2026 roku gromadzą ogromne stada zimujących leszczy. To strategiczne miejsce dla wędkarzy feederowych, wymagające jednak dalekich rzutów w celu osiągnięcia krawędzi starego koryta. Spinningiści polują tu na sandacze i okonie, prowadząc przynęty gumowe bardzo powoli wzdłuż uskoków dna. Uciąg wody jest niemal niewyczuwalny, co sprzyja precyzyjnemu nęczeniu i utrzymywaniu stad ryb w jednym polu nęcenia. Rozwinięta infrastruktura portowa i dogodne parkingi czynią to miejsce jednym z najwygodniejszych łowisk w całym regionie sieradzkim.', 'PZW Sieradz');

