-- Spot 269: Warta - Łyszkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71269, 'Warta - Łyszkowice (Po-zrzutowa)', 'warta-lyszkowice', 'RIVER', 51.857984, 18.7030192, 'Łódzkie', 'Poddębice', 'Odcinek w Łyszkowicach, położony poniżej zapory Jeziorsko, charakteryzuje się technicznym uciągiem zależnym od aktualnej pracy elektrowni wodnej. Podłoże jest tu twarde, piaszczysto-żwirowe, co zapewnia doskonałe natlenienie wody i wysoką aktywność ryb reofilnych w marcu 2026 roku. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając sandaczy stacjonujących w cieniu prądowym betonowych umocnień. Wędkarze stacjonarni nęcą spokojniejsze zatoczki poniżej tamy, licząc na brania rzecznych leszczy i cert. Zmienność poziomu wody wymusza na wędkarzach ciągłe dostosowywanie gramatury koszyków zanętowych i główek jigowych. Surowy, industrialny krajobraz zapory kontrastuje z rybną rzeką, tworząc wymagające, ale niezwykle efektywne łowisko.', 'PZW Sieradz');

