-- Spot 270: Warta - Sucha
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71270, 'Warta - Sucha (Leśne Zakola)', 'warta-sucha', 'RIVER', 51.6413526, 18.7010467, 'Łódzkie', 'Sieradz', 'Warta w Suchej odzyskuje swój dziki, meandrujący charakter, płynąc w głębokim wcięciu dolinnym porośniętym gęstym lasem. Rzeka żłobi tu techniczne rynny na zewnętrznych łukach koryta, których gliniaste dno stanowi bankowe schronienie dla sumów i kleni. Marzec 2026 roku to czas aktywności jazi, które chętnie ustawiają się w cieniu prądowym licznych zwalonych do wody dębów. Spinningiści muszą wykazać się tu dużą celnością rzutów, podając przynęty w wąskie pasma wolniejszej wody pod samym brzegiem. Uciąg rzeki jest żywy i zmienny, co sprzyja doskonałemu natlenieniu koryta po okresie zimowym. Izolacja od dużych osiedli i dzikość brzegów gwarantują wędkarzowi absolutny spokój i brak presji ze strony innych łowiących.', 'PZW Sieradz');

