VALUES (71270, 'Nizinna Wielka', 'Dzika, zatarasowana', 55.0, 2.2, 'Glina i piasek', 'Zwalone drzewa, burty', 'Jaź, Sum, Kleń', 'Kraina leszcza', true);

-- Spot 271: Warta - Małków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71271, 'Warta - Małków (Wyspy)', 'warta-malkow', 'RIVER', 51.6790769, 18.6605456, 'Łódzkie', 'Sieradz', 'Odcinek w Małkowie charakteryzuje się naturalnym przebiegiem z licznymi piaszczystymi wyspami dzielącymi nurt na mniejsze odnogi. Podłoże jest tu wybitnie piaszczyste, formujące dotlenione przelewy i warkocze prądowe idealne dla żerujących w marcu 2026 boleni. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w głębsze rynienki rzeźbione przez główny nurt rzeki. Spinningiści obławiają turbulentną wodę na styku nurtów przy wyspach, szukając kleni wybudzonych ze stanowisk zimowych. Uciąg rzeki stabilizuje się na prostych odcinkach koryta, co pozwala na precyzyjne podawanie przynęt i komfortowe wędkowanie. Malowniczy krajobraz nadwarciańskich łęgów i łatwy dostęp do brzegu w wielu miejscach czynią Małków popularnym łowiskiem wśród lokalnych pasjonatów.', 'PZW Sieradz');

