VALUES (71271, 'Nizinna Wielka', 'Wielonurtowa, piaszczysta', 75.0, 1.6, 'Piasek', 'Wyspy, łachy', 'Boleń, Jaź, Płoć', 'Kraina leszcza', true);

-- Spot 272: Warta - Konopnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71272, 'Warta - Konopnica (Jurajska)', 'warta-konopnica', 'RIVER', 51.351158, 18.8132913, 'Łódzkie', 'Wieluń', 'Warta w Konopnicy płynie głębokim korytem wyżłobionym w wapiennym podłożu, co nadaje jej charakter rzeki podgórskiej z twardym dnem. Koryto usiane jest licznymi kamieniami i fragmentami skał, tworzącymi techniczne bystrza i doskonale natlenione rynny brzegowe. Marzec 2026 roku to strategiczny moment dla łowców potężnych brzan, które zajmują stanowiska w najgłębszych partiach toru głównego. Spinningiści z sukcesami obławiają strome, podmyte burty, szukając kleni oraz okazowych okoni czatujących w cieniu prądowym głazów. Uciąg wody jest tu zdecydowany i stały, co wymusza stosowanie dociążonych zestawów gruntowych i odpornych na przetarcia przyponów. Wysokie i malownicze skarpy brzegowe w rejonie Konopnicy czynią to łowisko jednym z najpiękniejszych wizualnie odcinków całej Warty.', 'PZW Sieradz');

