VALUES (71272, 'Podgórska/Nizinna', 'Erozyjna, skalista', 45.0, 2.0, 'Skała i żwir', 'Bystrza, rynny skalne', 'Brzana, Kleń, Świnka', 'Kraina brzany', false);

-- Spot 273: Warta - Rychłocice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71273, 'Warta - Rychłocice', 'warta-rychlocice', 'RIVER', 51.3961412, 18.8160166, 'Łódzkie', 'Wieluń', 'Warta w Rychłocicach charakteryzuje się naturalnym, dość głębokim korytem o piaszczysto-żwirowym dnie z licznymi podmyciami. Rzeka tworzy tu techniczne rynny przy wysokich burtach, które w marcu 2026 roku stanowią główne zimowiska i żerowiska dla dorodnych stad jazi. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, wykorzystując małe woblery i obrotówki w celu zwabienia aktywnych kleni. Wędkarze stacjonarni nęcą spokojniejsze płanie, celując w rzeczne płocie i jelce szukające pokarmu na pograniczu nurtu. Uciąg rzeki jest tu zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką waleczność holowanych ryb. Malownicza okolica z dala od głównych szlaków komunikacyjnych gwarantuje wędkarzowi spokój i bliski kontakt z naturą.', 'PZW Sieradz');

