-- Spot 274: Warta - Wielka Wieś B
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71274, 'Warta - Wielka Wieś B', 'warta-wielka-wies-b', 'RIVER', 51.4408181, 18.8246541, 'Łódzkie', 'Sieradz', 'Odcinek rzeki w Wielkiej Wsi charakteryzuje się szerokimi zakolami i obecnością licznych zwalonych do wody dębów tworzących naturalne zatory. Podłoże jest tu twardsze, gliniasto-piaszczyste, co sprzyja powstawaniu głębokich rynien torowych o stabilnym charakterze. W marcu 2026 roku to strategiczne miejsce dla łowców szczupaków, którzy obławiają cienie prądowe za podwodnymi przeszkodami. Wędkarze feederowi z powodzeniem poławiają tu grube leszcze, nęcąc strefy spowolnień nurtu na krawędzi głównego koryta. Uciąg wody wymaga stosowania dociążonych koszyków zanętowych, aby skutecznie zaprezentować przynętę w strefie przydennej. Dzikość brzegów porośniętych gęstą wikliną zapewnia wędkarzowi doskonałą osłonę przed wiatrem i poczucie pełnej izolacji.', 'PZW Sieradz');

