-- Spot 275: Warta - Ligota
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71275, 'Warta - Ligota (Ujście Widawki)', 'warta-ligota', 'RIVER', 51.4839625, 18.8476891, 'Łódzkie', 'Sieradz', 'Łowisko w Ligocie zlokalizowane jest w strategicznym rejonie ujścia Widawki do Warty, co tworzy niezwykle rybny węzeł hydrologiczny. Mieszanie się wód o różnej charakterystyce rzeźbi głębokie doły i piaszczyste przykosy, które są naturalnym magnesem dla drapieżników. Marzec 2026 roku to idealny czas na spinningowe bolenie i sandacze, które intensywnie żerują w warkoczu ujściowym. Wędkarze gruntowi z sukcesami łowią tu rekordowe certy i jazie, wykorzystując zróżnicowany uciąg do precyzyjnej prezentacji przynęt. Podłoże jest tu niezwykle zmienne, od piaszczystych łach po twarde żwirowe rynny, co wymaga od wędkarza umiejętności czytania wody. To jedno z najciekawszych technicznie łowisk w regionie, oferujące szansę na spotkanie z wieloma gatunkami ryb.', 'PZW Sieradz');

