-- Spot 276: Warta - Bobrowniki (Sieradzkie)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71276, 'Warta - Bobrowniki (Nadwiślańskie)', 'warta-bobrowniki-sieradzkie', 'RIVER', 51.5291471, 18.8547647, 'Łódzkie', 'Sieradz', 'Warta w Bobrownikach pod Sieradzem płynie szerokim, spokojniejszym korytem przez rozległe, podmokłe nadwarciańskie łąki. Dno jest tu wybitnie piaszczyste, z łagodnie opadającymi stokami rynien, które w marcu 2026 roku stają się doskonałym żerowiskiem dla stad leszczy. Spinningiści namierzają okonie i klenie patrolujące krawędzie budzącej się do życia roślinności zanurzonej przy brzegach. Wędkarze feederowi z powodzeniem stosują tu metodę delikatnego nęcenia, punktując dorodne płocie przemieszczające się korytem głównym. Uciąg wody jest stabilny i umiarkowany, co pozwala na komfortowe wędkowanie przy użyciu lżejszych wędzisk klasy light. Cisza wiejskiego krajobrazu i obfitość białorybu czynią ten odcinek wyśmienitym miejscem na relaksujący, wiosenny biwak z wędką.', 'PZW Sieradz');

