-- Spot 277: Warta - Chojne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71277, 'Warta - Chojne (Skarpa)', 'warta-chojne', 'RIVER', 51.5640018, 18.8088668, 'Łódzkie', 'Sieradz', 'Odcinek w Chojnem charakteryzuje się wysoką, piaszczystą skarpą i głębokimi rynnami wymytymi bezpośrednio pod brzegiem na ostrych zakrętach. Podłoże jest tu twardsze, piaszczysto-gliniaste, co zapewnia bezpieczne oparcie dla ryb reofilnych takich jak brzany i świnki. Marzec 2026 roku to czas aktywności dużych kleni, które chętnie ustawiają się w cieniu prądowym naturalnych przeszkód brzegowych. Spinningiści z sukcesami penetrują tutejsze warkocze prądowe, szukając sandaczy stacjonujących w najgłębszych partiach koryta. Uciąg rzeki jest tu zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji zestawu. Wysokie brzegi wymagają posiadania podbieraka z dłuższą sztycą, ale oferują w zamian doskonały wgląd w ukształtowanie dna rzeki.', 'PZW Sieradz');

