-- Spot 278: Warta - Kamion
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71278, 'Warta - Kamion', 'warta-kamion', 'RIVER', 51.1654461, 18.7467726, 'Łódzkie', 'Wieluń', 'Warta w Kamionie płynie przez malowniczy teren Załęczańskiego Parku Krajobrazowego, cechując się bystrym nurtem i twardym dnem. Koryto usiane jest tu żwirowymi łachami oraz nielicznymi narzutami skalnymi, które tworzą techniczne bystrza i doskonale natlenione warkocze. W marcu 2026 roku to wyśmienite łowisko dla spinningistów szukających kleni i jazi na bardzo lekkie przynęty. Wędkarze spławikowi z sukcesami łowią tu metodą przepływanki, celując w waleczne jelce i rzeczne płocie stacjonujące w rynnach głównego nurtu. Woda zachowuje tu wysoką przejrzystość, co wymusza na wędkarzu stosowanie finezyjnych zestawów i zachowanie ciszy na brzegu. Dzikość tego odcinka i piękno otaczającej przyrody czynią Kamion jednym z najbardziej elitarnych łowisk górnej Warty.', 'PZW Sieradz');

