-- Spot 279: Warta - Załęcze Wielkie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71279, 'Warta - Załęcze Wielkie', 'warta-zalecze-wielkie', 'RIVER', 51.0909108, 18.6635973, 'Łódzkie', 'Działoszyn', 'Warta w Załęczu Wielkim to jeden z najbardziej widowiskowych odcinków rzeki, gdzie koryto przecina wapienne progi Wyżyny Wieluńskiej. Podłoże jest tu wybitnie twarde, usiane kamieniami i fragmentami skał, co tworzy liczne bystrza o bardzo wysokim stopniu natlenienia. W marcu 2026 roku to strategiczne żerowisko dla kleni i świnek, które gromadzą się w głębszych warkoczach bezpośrednio za przelewami. Spinningiści z sukcesami obławiają tutejsze rynny skalne, stosując małe jigi i woblery prowadzone tuż nad dnem. Uciąg jest żywy i wymagający technicznie, co wymusza na wędkarzu precyzyjne operowanie zestawem w silnym nurcie. Dzikość Załęczańskiego Parku Krajobrazowego i krystaliczna woda nadają temu miejscu unikalny, niemal górski klimat wędkarski.', 'PZW Sieradz');

