-- Spot 280: Warta - Raduczyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71280, 'Warta - Raduczyce', 'warta-raduczyce', 'RIVER', 51.2582537, 18.7872614, 'Łódzkie', 'Osjaków', 'Odcinek w Raduczycach charakteryzuje się naturalnym, meandrującym korytem o urozmaiconym, piaszczysto-gliniastym dnie z licznymi podmyciami. Rzeka żłobi tu głębokie rynny pod brzegami, które w marcu 2026 roku stanowią idealne schronienie dla zimujących jeszcze stad leszczy. Spinningiści penetrują tutejsze zwaliska drzew i zatopione korzenie, szukając wczesnowiosennych szczupaków i okoni. Wędkarze gruntowi z sukcesami nęcą spokojniejsze płanie, celując w dorodne jazie i certy przemieszczające się korytem głównym. Uciąg rzeki jest tu umiarkowany, co pozwala na stosowanie lżejszych metod feederowych i precyzyjne sygnalizowanie brań. Malownicze otoczenie łąk i brak gęstej zabudowy zapewniają wędkarzowi spokój oraz bezpośredni kontakt z budzącą się przyrodą.', 'PZW Sieradz');

