-- Spot 281: Warta - Osjaków
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71281, 'Warta - Osjaków', 'warta-osjakow', 'RIVER', 51.3034255, 18.7918472, 'Łódzkie', 'Wieluń', 'Warta w Osjakowie to klasyczna rzeka podgórska płynąca szerokim korytem o wybitnie żwirowym podłożu i czystej wodzie. Rzeka tworzy tu liczne bystrza i płytkie przelewy, które w marcu 2026 roku są intensywnie patrolowane przez stada świnek i kleni. To doskonałe łowisko dla miłośników przepływanki, którzy z sukcesami nęcą tutejsze rynny torowe na krawędzi nurtu. Spinningiści obławiają granice prądu i spokojniejszej wody za kamiennymi narzutami, licząc na widowiskowe brania walecznych jazi. Uciąg wody jest stabilny i zdecydowany, co zapewnia wyśmienite warunki tlenowe i przekłada się na wysoką kondycję ryb. Łatwy dostęp do wody w rejonie miejscowości i twarde dno sprzyjają komfortowemu wędkowaniu nawet przy wyższych stanach rzeki.', 'PZW Sieradz');

