INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71282, 'Warta - Czapury', 'warta-czapury', 'RIVER', 52.3116354, 16.9086599, 'Wielkopolskie', 'Poznań', 'Miejski odcinek Warty w Czapurach pod Poznaniem to szeroka, uregulowana rzeka o stabilnym nurcie i piaszczystym korycie. Brzegi są tu wzmocnione opaskami kamiennymi, a pod filarami pobliskich mostów tworzą się głębokie rynny toru wodnego. W marcu 2026 roku miejsce to jest strategiczne dla łowców rzecznych leszczy, które grupują się na stokach rynien w poszukiwaniu pokarmu. Spinningiści z sukcesami obławiają tutejsze piaszczyste przykosy, szukając okoni oraz okazyjnych sandaczy stacjonujących przy dnie. Uciąg wody jest zdecydowany i stały, co wymaga stosowania dociążonych koszyków zanętowych przy metodzie feederowej. Bliskość aglomeracji poznańskiej zapewnia rewelacyjny dojazd, czyniąc ten odcinek idealnym na szybkie, techniczne sesje z wędką.', 'PZW Poznań');

