-- Spot 283: Warta - Księże Młyny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71283, 'Warta - Księże Młyny', 'warta-ksieze-mlyny', 'RIVER', 51.8945437, 18.7491337, 'Łódzkie', 'Poddębice', 'Odcinek w Księżych Młynach, położony poniżej zapory Jeziorsko, charakteryzuje się bardzo szybkim nurtem i krystaliczną wodą bogatą w tlen. Dno jest tu twarde, kamienisto-żwirowe, co wynika z wymywania osadów drobnych przez wodę po-zrzutową ze zbiornika. Marzec 2026 roku to wybitny okres dla spinningistów polujących na sandacze i bolenie, które gromadzą się w warkoczach prądowych pod tamą. Wędkarze gruntowi walczą tu z silnym uciągiem, stosując najcięższe koszyki zanętowe z wąsami dla utrzymania zestawu w rynnie. Zmienność przepływów dyktowana pracą elektrowni wymusza na wędkarzu ciągłe dostosowywanie taktyki nęcenia i gramatury obciążeń. Surowość hydrotechnicznego krajobrazu rekompensuje szansa na złowienie okazowych ryb drapieżnych i reofilnych w krystalicznym nurcie.', 'Wody Polskie / PZW Sieradz');

