-- Spot 284: Warta - Łęg Baliński
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71284, 'Warta - Łęg Baliński', 'warta-leg-balinski', 'RIVER', 51.9324742, 18.7909555, 'Łódzkie', 'Uniejów', 'Warta w Łęgu Balińskim powraca do swojej naturalnej formy, meandrując spokojnie pośród rozległych polderów i lasów łęgowych. Dno rzeki jest tu piaszczyste, z wyraźnymi uskokami rzeźbionymi przez nurt na łukach koryta, dochodzącymi do dwóch metrów głębokości. W marcu 2026 roku te nagrzewające się płycizny przyciągają stada jazi i płoci szukających pierwszego wiosennego pożywienia. Spinningiści z sukcesami penetrują podmyte brzegi porośnięte wikliną, wyczekując uderzeń rzecznych kleni i szczupaków. Uciąg wody jest tu łagodny i stabilny, co sprzyja systematycznemu nęczeniu bez obawy o szybkie rozproszenie zanęty w nurcie. Całkowita izolacja od dróg asfaltowych i dziki charakter rzeki gwarantują wędkarzowi spokój oraz możliwość pełnej regeneracji sił.', 'PZW Sieradz');

