VALUES (71284, 'Nizinna Wielka', 'Meandrująca, naturalna', 55.0, 1.8, 'Piasek', 'Podmyte wikliny, rynny', 'Jaź, Płoć, Szczupak', 'Kraina leszcza', true);

-- Spot 285: Warta - Zawiercie (Źródła II)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71285, 'Warta - Zawiercie (Źródła)', 'warta-zawiercie-zrodla', 'RIVER', 50.4780322, 19.4553631, 'Śląskie', 'Zawiercie', 'Najwyższy bieg Warty w Zawierciu to malowniczy, krystaliczny strumień płynący przez tereny Wyżyny Krakowsko-Częstochowskiej po litym, wapiennym podłożu. Rzeka jest tu niezwykle wąska i płytka, a jej koryto usiane jest licznymi kamieniami i korzeniami nadrzecznych drzew. W marcu 2026 roku to strategiczne miejsce dla łowców pstrągów potokowych, którzy w lodowatej wodzie prowadzą najmniejsze nimfy i mikrojigi. Spinningiści z sukcesami obławiają techniczne rynienki pod burtami, celując w małe, ale niezwykle waleczne klenie. Ogromna przejrzystość wody wymusza na wędkarzu stosowanie pełnego kamuflażu oraz oddawanie precyzyjnych rzutów na odległość. Dzikość źródliskowej strefy i huczący nurt krystalicznej wody tworzą niepowtarzalny klimat technicznego wędkarstwa podchodowego.', 'PZW Częstochowa');

