VALUES (71285, 'Górska', 'Źródliskowa, krystaliczna', 6.0, 0.5, 'Kamień i korzenie', 'Bystrza, rynienki', 'Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 286: Warta - Sieradz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71286, 'Warta - Sieradz', 'warta-sieradz-miejska', 'RIVER', 51.6020084, 18.7688163, 'Łódzkie', 'Sieradz', 'Miejski odcinek Warty w Sieradzu charakteryzuje się uregulowanym korytem o twardym, kamienisto-żwirowym dnie i wysokich opaskach brzegowych. Pod filarami mostów nurt jest silnie wymyty, tworząc techniczne rynny sięgające czterech metrów głębokości, będące idealnym zimowiskiem dla sandaczy. W marcu 2026 roku to strategiczne miejsce dla pasjonatów streetfishingu, którzy z sukcesami poławiają okonie wzdłuż murów oporowych. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za konstrukcjami hydrotechnicznymi, nęcąc stada okazałych leszczy i cert wchodzących w rzekę. Uciąg rzeki jest tu stabilny, ale zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji przynęty. Dobra infrastruktura miejska, oświetlenie i łatwy dostęp do brzegów czynią Sieradz jednym z najwygodniejszych łowisk w regionie.', 'PZW Sieradz');

