-- Spot 287: Warta - Sługocinek
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71287, 'Warta - Sługocinek', 'warta-slugocinek', 'RIVER', 52.1925979, 18.0483523, 'Wielkopolskie', 'Golina', 'Odcinek w Sługocinku płynie przez obszar Nadwarciańskiego Parku Krajobrazowego, oferując szerokie koryto i liczne starorzecza okresowo połączone z rzeką. Podłoże jest tu piaszczysto-muliste, a rozległe poldery zalewowe sprzyjają szybszemu nagrzewaniu się wody w marcu 2026 roku. To strategiczne miejsce dla łowców wczesnowiosennych szczupaków, które gromadzą się w spokojniejszych zatokach przed tarłem. Wędkarze gruntowi z sukcesami nęcą tutejsze płanie, celując w rekordowe krąpie i leszcze wchodzące w rzekę z dolnego biegu. Uciąg rzeki jest tu łagodny, co pozwala na stosowanie delikatnych metod feederowych i precyzyjne sygnalizowanie nawet najsłabszych brań. Niezwykłe walory przyrodnicze i cisza polderów sprawiają, że wędkowanie w Sługocinku to kontakt z zupełnie dziką, nizinna naturą.', 'PZW Konin');

