-- Spot 288: Warta - Ratyń
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71288, 'Warta - Ratyń', 'warta-ratyn', 'RIVER', 52.1880476, 17.9744703, 'Wielkopolskie', 'Ląd', 'Warta w Ratyniu charakteryzuje się naturalnym, mocno meandrującym korytem o urozmaiconym, piaszczysto-gliniastym dnie z licznymi podmyciami. Rzeka rzeźbi tu techniczne dołki na zewnętrznych łukach zakoli, które w marcu 2026 roku są bankowymi stanowiskami dla kleni i jazi. Spinningiści z sukcesami obławiają podmyte brzegi porośnięte wikliną, wykorzystując małe woblery i jigi prowadzone w dryfie. Wędkarze stacjonarni nęcą spokojniejsze płanie, celując w rzeczne płocie i jelce szukające pokarmu na krawędzi nurtu głównego. Uciąg rzeki jest umiarkowany i stabilny, co sprzyja systematycznemu nęczeniu bez obawy o szybkie rozproszenie zanęty. Dzikość brzegów i brak gęstej zabudowy zapewniają wędkarzowi spokój oraz bezpośredni kontakt z budzącą się po zimie przyrodą.', 'PZW Konin');

