-- Spot 289: Warta - Zagórów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71289, 'Warta - Zagórów (Poldery)', 'warta-zagorow', 'RIVER', 52.1904427, 17.8992445, 'Wielkopolskie', 'Zagórów', 'Odcinek w gminie Zagórów to klasyczna "Warta Pyzdrska" z rozległymi piaszczystymi łachami i płytkimi, natlenionymi warkoczami prądowymi. Podłoże składa się w głównej mierze z drobnego piasku, który nieustannie przemieszcza się, formując nowe przykosy i rynny torowe. W marcu 2026 roku te płytkie, dobrze nasłonecznione strefy stają się magnesem dla boleni polujących na stada uklei. Fani metody feederowej rozstawiają się na piaszczystych łachach, posyłając zestawy w głębsze rynienki rzeźbione przez nurt torowy. Uciąg wody jest umiarkowany, co pozwala na stosowanie lżejszych metod i precyzyjne sygnalizowanie brań na miękkich szczytówkach. Otwarty i dostępny brzeg sprzyja dalekim rzutom spinningowym, oferując bezpieczne i wygodne warunki do rozstawienia stanowiska.', 'PZW Konin');

