-- Spot 290: Warta - Koło
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71290, 'Warta - Koło', 'warta-kolo-miejska', 'RIVER', 52.1897986, 18.6422395, 'Wielkopolskie', 'Koło', 'Miejski odcinek Warty w Kole charakteryzuje się uregulowanym korytem o twardym dnie i obecnością technicznych opasek kamiennych wzmacniających brzegi. Pod filarami mostów nurt jest silnie wymyty, tworząc rynny sięgające trzech metrów głębokości, będące idealnym zimowiskiem dla sandaczy i okoni. Wczesną wiosną 2026 roku to strategiczne miejsce dla łowców białorybu, którzy z sukcesami poławiają tu dorodne certy i jazie na feeder. Spinningiści z uwagą penetrują tutejsze warkocze prądowe, szukając kleni stacjonujących w cieniu prądowym betonowych konstrukcji. Uciąg rzeki jest tu stabilny i zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką waleczność zapiętych ryb. Dobra infrastruktura miejska i łatwy dostęp do brzegu czynią Koło jednym z najchętnie odwiedzanych łowisk w regionie.', 'PZW Konin');

