-- Spot 291: Warta - Dobrów (Ujście Neru)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71291, 'Warta - Dobrów (Ujście Neru)', 'warta-dobrow-ujscie', 'RIVER', 52.1500634, 18.6843896, 'Wielkopolskie', 'Koło', 'Łowisko w Dobrowie zlokalizowane jest w strategicznym miejscu ujścia Neru do Warty, co tworzy unikalny i niezwykle rybny węzeł hydrologiczny. Mieszanie się wód o różnej charakterystyce rzeźbi głębokie doły i piaszczyste przykosy, które w marcu 2026 roku są magnesem dla drapieżników. Cieplejszy nurt Neru stymuluje białoryb do wcześniejszego żerowania, co czyni ten warkoczyk jednym z najlepszych wczesnowiosennych stanowisk jaziowych. Spinningiści z sukcesami obławiają tu sandacze i bolenie, wykorzystując turbulentną wodę na styku nurtów obu rzek. Uciąg rzeki jest tu żywy i zmienny, co wymusza na wędkarzu precyzyjne operowanie ciężarem zestawu w zależności od miejsca podania przynęty. Podłoże piaszczysto-żwirowe zapewnia rybom reofilnym doskonałe warunki tlenowe i obfitość naturalnego pokarmu.', 'PZW Konin');

