-- Spot 292: Warta - Zawada
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71292, 'Warta - Zawada (Przełom Jurajski)', 'warta-zawada', 'RIVER', 50.8291012, 19.3146315, 'Śląskie', 'Mstów', 'Warta w Zawadzie przebija się przez wapienne skały Jury, tworząc widowiskowy przełom o twardym, kamienistym dnie i bystrym nurcie. Rzeka rzeźbi tu głębokie wanny w skalnym podłożu, które w marcu 2026 roku stanowią idealne kryjówki dla dużych kleni i brzan. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, wykorzystując małe woblery puszczane w dryf pod same skalne nawisy. Wędkarze spławikowi nęcą wąskie rynny na krawędzi bystrzy, celując w waleczne jelce oraz rzeczne płocie szukające pokarmu. Uciąg wody jest tu zdecydowany i stały, co zapewnia doskonałe natlenienie łowiska i wysoką kondycję ryb praktycznie przez całą dobę. Surowość skalnego krajobrazu i krystaliczna woda nadają temu miejscu unikalny, niemal górski klimat technicznego wędkarstwa podchodowego.', 'PZW Częstochowa');

