-- Spot 293: Warta - Kostrzyn nad Odrą (Ujście)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71293, 'Warta - Kostrzyn nad Odrą (Ujście)', 'warta-kostrzyn-ujscie', 'RIVER', 52.5836906, 14.6453151, 'Lubuskie', 'Kostrzyn nad Odrą', 'Ujście Warty do Odry to jeden z najpotężniejszych węzłów hydrologicznych w Polsce, charakteryzujący się ogromną masą wody i głębokimi dołami w warkoczu ujściowym. Dno jest tu twarde, piaszczysto-żwirowe z licznymi kamiennymi umocnieniami brzegowymi, które w marcu 2026 roku stają się bazą dla wchodzących z Odry sandaczy. Wędkarze gruntowi stosują tu najcięższe zestawy rzeczne, nęcąc stada potężnych leszczy i jazi, które gromadzą się w strefie mieszania nurtów. Spinningiści obławiają dalekie rynny ciężkimi wahadłówkami, licząc na kontakt z sumem lub wiślanym boleniem. Skomplikowana dynamika prądów wstecznych wymaga od wędkarza dużej siły fizycznej i precyzyjnego czytania wody. Unikalny krajobraz Parku Narodowego "Ujście Warty" i potęga dwóch rzek czynią to miejsce absolutnie wyjątkowym łowiskiem.', 'PZW Gorzów Wielkopolski');

