-- Spot 294: Warta - Poznań (Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71294, 'Warta - Poznań (Centrum)', 'warta-poznan-centrum', 'RIVER', 52.4253524, 16.95331, 'Wielkopolskie', 'Poznań', 'Miejski odcinek Warty w sercu Poznania charakteryzuje się głębokim korytem ujętym w betonowe bulwary i mury oporowe. Podłoże jest tu twarde, wysłane narzutem kamiennym, a liczne filary mostów tworzą techniczne rynny, będące zimowiskiem dla sandaczy i okoni. W marcu 2026 roku to strategiczne miejsce dla fanów streetfishingu, którzy z sukcesami obławiają cienie prądowe przy murach. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za konstrukcjami mostowymi, nęcąc stada cert i płoci wchodzących w rzekę. Uciąg jest stabilny i przewidywalny, co sprzyja precyzyjnemu nęczeniu bez ryzyka szybkiego rozmycia zanęty. Świetne oświetlenie nabrzeży i łatwy dostęp sprawiają, że jest to jedno z najchętniej odwiedzanych łowisk całodobowych w regionie.', 'PZW Poznań');

