-- Spot 295: Warta - Poznań (Dębina)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71295, 'Warta - Poznań (Dębina)', 'warta-poznan-debina', 'RIVER', 52.3590821, 16.9223364, 'Wielkopolskie', 'Poznań', 'Odcinek w rejonie poznańskiej Dębiny to powrót rzeki do nieco bardziej naturalnego charakteru z licznymi ostrogami kamiennymi i zalesionymi brzegami. Podłoże w klatkach między główkami jest mulisto-piaszczyste, co w marcu 2026 roku przyciąga stada dorodnych leszczy i krąpi szukających spokoju od nurtu głównego. Spinningiści z sukcesami obławiają szczyty główek, szukając wczesnowiosennych boleni żerujących na piaszczystych przelewach. Uciąg na środku koryta jest zdecydowany, co wymaga stosowania dociążonych zestawów feederowych do stabilnej prezentacji przynęty. Dzikość brzegów w tym fragmencie miasta oferuje wędkarzowi poczucie izolacji przy zachowaniu doskonałego dojazdu komunikacją miejską. To strategiczne miejsce dla łowców okazowych kleni, które chętnie ustawiają się w turbulentnej wodzie za przeszkodami.', 'PZW Poznań');

