-- Spot 296: Warta - Poznań (Naramowice)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71296, 'Warta - Poznań (Naramowice)', 'warta-poznan-naramowice', 'RIVER', 52.4683674, 16.9755936, 'Wielkopolskie', 'Poznań', 'Północny odcinek rzeki w Poznaniu, na wysokości Naramowic, charakteryzuje się szerokim korytem i obecnością rozległych piaszczystych przykos. Rzeka tworzy tu liczne mielizny, które w marcu 2026 roku szybko nagrzewają się w promieniach słońca, przyciągając jazie i płocie na żer. Spinningiści namierzają tu rzeczne okonie patrolujące krawędzie rynien toru wodnego, wykorzystując techniki powolnego prowadzenia przynęt. Wędkarze gruntowi rozstawiają się na twardszych płaniach, posyłając zestawy w głębsze partie koryta w poszukiwaniu rzecznych mocarzy. Uciąg wody jest tu umiarkowany, co sprzyja systematycznemu nęczeniu bez obawy o szybkie wymycie dywanu zanętowego. Otwarty krajobraz doliny Warty ułatwia operowanie długimi wędziskami i zapewnia doskonałą widoczność lustra wody.', 'PZW Poznań');

