-- Spot 297: Warta - Skwierzyna (Bulwary)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71297, 'Warta - Skwierzyna (Bulwary)', 'warta-skwierzyna-miejska', 'RIVER', 52.6006342, 15.4990295, 'Lubuskie', 'Skwierzyna', 'Warta w Skwierzynie płynie głębokim korytem o uregulowanych brzegach i twardym, piaszczysto-żwirowym dnie. Rejon miejskich bulwarów i mostów to techniczne łowisko, gdzie nurt jest silnie załamany, tworząc głębokie rynny torowe pod filarami. Marzec 2026 roku to wyśmienity czas na namierzenie grubych cert i leszczy, które masowo gromadzą się w turbulentnej wodzie za umocnieniami. Spinningiści z sukcesami polują na okonie i sandacze, wykorzystując doskonałe natlenienie wody wokół konstrukcji hydrotechnicznych. Uciąg rzeki jest tu stabilny, ale zdecydowany, co wymaga stosowania koszyków zanętowych o masie od 60 gramów wzwyż. Dobra infrastruktura miejska, łatwy dojazd i utwardzone stanowiska czynią Skwierzynę popularnym punktem wypraw w regionie.', 'PZW Gorzów Wielkopolski');

