-- Spot 298: Warta - Gmina Skwierzyna (Lasy)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71298, 'Warta - Skwierzyna (Lasy)', 'warta-skwierzyna-lasy', 'RIVER', 52.6305628, 15.4410973, 'Lubuskie', 'Skwierzyna', 'Odcinek rzeki poniżej Skwierzyny wchodzi w gęste kompleksy leśne, charakteryzując się niezwykle dzikim i nieuregulowanym profilem koryta. Rzeka rzeźbi tu potężne zakola z podmywanymi, wysokimi burtami, pod którymi zalegają liczne zwalone drzewa i krzewy. W marcu 2026 roku to strategiczne miejsce dla łowców szczupaków, którzy obławiają spokojniejsze warkocze prądowe w cieniu zawad. Wędkarze stacjonarni stosują dociążone zestawy gruntowe, starając się zatrzymać w polu nęcenia wędrujące pod prąd stada jazi. Uciąg jest tu zmienny, co wymusza na wędkarzach ciągłe poszukiwanie optymalnych ścieżek prowadzenia przynęty między korzeniami. Całkowita izolacja od dróg i dzikość przyrody gwarantują wędkarzowi absolutny spokój oraz szansę na spotkanie z rekordowymi okazami ryb rzecznych.', 'PZW Gorzów Wielkopolski');

