-- Spot 299: Warta - Brzozowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71299, 'Warta - Brzozowiec', 'warta-brzozowiec', 'RIVER', 52.6671879, 15.3939585, 'Lubuskie', 'Deszczno', 'Warta w Brzozowcu to szeroka rzeka nizinna płynąca wśród rozległych łąk, charakteryzująca się piaszczystym dnem i licznymi mieliznami. Nurt formuje tu dynamiczne przykosy, za którymi woda gwałtownie zapada się w rynny torowe o głębokości do dwóch metrów. Marzec 2026 roku to idealny czas na namierzanie rzecznych boleni, które intensywnie żerują na krawędziach piaszczystych łach. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w spokojniejsze warkocze w poszukiwaniu stadnych krąpi i płoci. Uciąg jest umiarkowany, co pozwala na stosowanie lżejszych metod sygnalizacji brań i podnosi komfort wielogodzinnych zasiadek. Otwarty charakter terenu i doskonały wgląd w lustro wody ułatwiają lokalizację żerujących ryb i dalekie rzuty spinningowe.', 'PZW Gorzów Wielkopolski');

