-- Spot 300: Warta - Gorzów Wielkopolski (Zachód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71300, 'Warta - Gorzów Wielkopolski (Wylot)', 'warta-gorzow-zachod', 'RIVER', 52.7135188, 15.1833071, 'Lubuskie', 'Gorzów Wielkopolski', 'Zachodni odcinek rzeki w Gorzowie to strefa przemysłowo-naturalna, gdzie uregulowane nabrzeża powoli ustępują miejsca dzikszym brzegom. Dno jest tu twarde, wysłane narzutem kamiennym i żwirem, co sprzyja bytowaniu dużych kleni i brzan żerujących w nurcie. Wczesną wiosną 2026 roku to strategiczne miejsce dla łowców białorybu, którzy z sukcesami poławiają tu certy na klasyczny feeder. Spinningiści obławiają cienie betonowych konstrukcji i umocnień brzegowych, szukając okoni oraz okazyjnych sandaczy stacjonujących przy dnie. Uciąg rzeki jest tu zdecydowany, co zapewnia doskonałe warunki tlenowe i przekłada się na wysoką waleczność holowanych ryb. Dogodny dojazd i bliskość zabudowań miejskich zapewniają wygodę, jednak znaczna szerokość koryta wymaga stosowania cięższego sprzętu rzutowego.', 'PZW Gorzów Wielkopolski');

