-- Spot 301: Warta - Lubuczno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71301, 'Warta - Lubuczno', 'warta-lubuczno', 'RIVER', 52.6658331, 15.1746347, 'Lubuskie', 'Gorzów Wielkopolski', 'Warta w Lubucznie to szeroki, nizinny odcinek rzeki o piaszczystym dnie i regularnym systemie ostróg kamiennych brzegowych. W marcu 2026 roku klatki między główkami gromadzą znaczną ilość osadów organicznych, co przyciąga żerujące stada leszczy i krąpi. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni i kleni na piaszczystych przelewach. Uciąg rzeki jest tu stabilny, co pozwala na komfortowe nęcenie przy użyciu klasycznego, rzecznego feedera. Podłoże jest głównie piaszczyste, jednak przy samych szczytach główek dno jest twarde i wyłożone kamiennym narzutem. Rozległe przestrzenie łąkowe i brak wysokich drzew ułatwiają dalekie i precyzyjne rzuty w stronę głównego nurtu.', 'PZW Gorzów Wielkopolski');

