-- Spot 302: Warta - Roszkowice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71302, 'Warta - Roszkowice', 'warta-roszkowice', 'RIVER', 52.6315269, 15.122906, 'Lubuskie', 'Witnica', 'Odcinek w Roszkowicach charakteryzuje się mocno meandrującym korytem z wyraźnie zaznaczonymi rynnami erozyjnymi pod wysokimi burtami. Dno jest tu zmienne, piaszczysto-gliniaste, co w marcu 2026 roku tworzy idealne warunki dla wchodzących w dopływy stad cert i jazi. Wędkarze stacjonarni nęcą tutejsze głębokie zakola, wykorzystując ciężkie koszyki zanętowe z kolcami dla stabilizacji zestawu w nurcie. Spinningiści penetrują podmyte korzenie nadrzecznych olch, szukając wczesnowiosennych szczupaków i wyrośniętych okoni. Uciąg rzeki na zewnętrznych łukach koryta jest zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką kondycję ryb. Dzikość brzegów porośniętych wikliną zapewnia wędkarzowi poczucie izolacji i osłonę przed mroźnym wiatrem.', 'PZW Gorzów Wielkopolski');

