-- Spot 303: Warta - Studzionka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71303, 'Warta - Studzionka', 'warta-studzionka', 'RIVER', 52.6370404, 15.0478261, 'Lubuskie', 'Krzeszyce', 'Warta w rejonie Studzionki rozlewa się szeroko wśród polderów zalewowych, formując liczne piaszczyste łachy i płytkie przelewy powierzchniowe. Dno składa się w głównej mierze z drobnego piasku, który nieustannie przemieszcza się, formując nowe rynny torowe po zimowych przyborach. W marcu 2026 roku te nagrzewające się płycizny przyciągają stada drobnicy, a za nimi żarłoczne rzeczne bolenie. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w spokojniejsze warkocze w poszukiwaniu stadnych leszczy. Uciąg jest umiarkowany i bardzo stabilny, co pozwala na stosowanie lżejszych metod sygnalizacji brań i podnosi komfort łowienia. Otwarty krajobraz doliny rzeki ułatwia lokalizację żerujących ryb i dalekie rzuty spinningowe bez ryzyka zaczepów brzegowych.', 'PZW Gorzów Wielkopolski');

