-- Spot 304: Warta - Oksza
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71304, 'Warta - Oksza', 'warta-oksza', 'RIVER', 52.6436608, 14.9723102, 'Lubuskie', 'Witnica', 'Łowisko w Okszy to techniczny odcinek rzeki o uregulowanych brzegach, wzmocnionych betonowo-kamiennymi opaskami chroniącymi koryto. Dno jest tu twarde, wysłane narzutem kamiennym i żwirem, co sprzyja bytowaniu dużych kleni i brzan żerujących w głębokim nurcie. Wczesną wiosną 2026 roku spinningiści obławiają cienie betonowych konstrukcji, szukając sandaczy stacjonujących przy dnie toru wodnego. Wędkarze gruntowi wykorzystują spowolnienia nurtu za umocnieniami brzegowymi, nęcąc stada okazałych cert i krąpi. Uciąg rzeki jest tu zdecydowany i stały, co wymusza stosowanie dociążonych koszyków zanętowych o masie od 80 gramów wzwyż. Dobra infrastruktura i łatwy dostęp do brzegu czynią Okszę popularnym punktem wypraw dla wędkarzy ceniących komfort i rybną wodę.', 'PZW Gorzów Wielkopolski');

