-- Spot 305: Warta - Kłopotowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71305, 'Warta - Kłopotowo', 'warta-klopotowo', 'RIVER', 52.631484, 14.8994677, 'Lubuskie', 'Witnica', 'Odcinek w Kłopotowie stanowi wrota do Parku Narodowego "Ujście Warty", charakteryzując się niezwykle dzikim i rozlewiskowym profilem koryta. Rzeka płynie tu wśród podmokłych łęgów, tworząc liczne starorzecza i zastoiska będące w marcu 2026 roku rajem dla łowców szczupaków. Podłoże jest piaszczysto-muliste, a liczne kępy wiklin zanurzonych w nurcie stanowią doskonałe kryjówki dla okazowych ryb drapieżnych. Wędkarze gruntowi nęcą tutejsze płaskie blaty, celując w rekordowe leszcze i jazie migrujące okresowo z pobliskiej Odry. Uciąg wody jest tu łagodny, co sprzyja stosowaniu delikatnych metod spławikowych i precyzyjnemu nęczeniu punktowemu. Nieskażona przyroda i obecność rzadkich gatunków ptactwa wodnego nadają każdemu wędkowaniu w tym miejscu unikalny charakter.', 'PZW Gorzów Wielkopolski');

