-- Spot 306: Warta - Witnica (Wschód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71306, 'Warta - Witnica (Wschód)', 'warta-witnica-wschod', 'RIVER', 52.6086491, 14.8105277, 'Lubuskie', 'Witnica', 'Wschodnie przedpola Witnicy to kraina rozległych przykos i piaszczystych łach, które dynamicznie modelują koryto dolnej Warty. Dno składa się w głównej mierze z drobnego piasku, formującego dotlenione przelewy idealne dla żerujących w marcu 2026 roku boleni. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w głębsze rynienki rzeźbione przez nurt torowy. Spinningiści z uwagą obserwują lustro wody, namierzając ataki drapieżników na stada drobnej uklei gromadzącej się na płyciznach. Uciąg jest tu umiarkowany i bardzo stabilny, co pozwala na stosowanie lżejszych wędzisk i precyzyjne sygnalizowanie delikatnych brań. Dzikość brzegów i brak gęstej zabudowy w bezpośrednim sąsiedztwie rzeki gwarantują wędkarzowi spokój oraz bezpośredni kontakt z naturą.', 'PZW Gorzów Wielkopolski');

