-- Spot 307: Warta - Witnica (Zachód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71307, 'Warta - Witnica (Zachód)', 'warta-witnica-zachod', 'RIVER', 52.5983698, 14.7379438, 'Lubuskie', 'Witnica', 'Zachodni odcinek rzeki w Witnicy charakteryzuje się głębokim profilem koryta i obecnością technicznych opasek kamiennych chroniących wysokie brzegi. Podłoże jest tu twardsze, piaszczysto-żwirowe, co w marcu 2026 roku przyciąga rekordowe leszcze i certy żerujące w nurcie głównym. Spinningiści z sukcesami obławiają tutejsze warkocze, rzucając cięższymi woblerami w poszukiwaniu sandaczy stacjonujących przy dnie. Wędkarze gruntowi stosują koszyki o gramaturze powyżej 60 gramów, aby skutecznie utrzymać zestaw na krawędzi piaszczystego stoku rynny. Woda jest tu doskonale natleniona, co sprzyja wysokiej aktywności ryb i ich szybkiemu wybudzaniu się po zimowym postoju. Surowość brzegów i zdecydowany przepływ wody czynią to łowisko wyzwaniem dla technicznie zaawansowanych wędkarzy rzecznych.', 'PZW Gorzów Wielkopolski');

