-- Spot 308: Warta - Poraj (Pod Zaporą)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71308, 'Warta - Poraj (Tailwater)', 'warta-poraj-pod-zapora', 'RIVER', 50.6707601, 19.2055431, 'Śląskie', 'Poraj', 'Odcinek w Poraju zlokalizowany jest bezpośrednio poniżej zapory zbiornika, co nadaje mu charakter wybitnie technicznego łowiska typu tailwater. Woda jest tu znakomicie natleniona i pozbawiona zawiesiny, co w marcu 2026 roku sprzyja wysokiej aktywności okoni oraz pstrągów potokowych. Dno wyściela twardy narzut kamienny oraz betonowe umocnienia koryta, chroniące brzegi przed erozją wywołaną zrzutami wody. Spinningiści stosują tu technikę lekkiego opadu, precyzyjnie penetrują wanny wymyte przez turbulentny nurt bezpośrednio pod progiem. Zmienność przepływów wynikająca z pracy zapory wymusza na wędkarzach ciągłą rotację gramatury stosowanych przynęt i koszyków. Surowy, industrialny krajobraz i krystaliczna woda tworzą tu unikalne warunki do całorocznego wędkowania.', 'PZW Częstochowa');

