-- Spot 309: Warta - Trząska-Zawodzie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71309, 'Warta - Trząska-Zawodzie', 'warta-trzaska-zawodzie', 'RIVER', 50.8617595, 19.3637556, 'Śląskie', 'Kłomnice', 'Warta w Trząsce-Zawodziu płynie w głębokim, naturalnym korycie z licznymi podmyciami wysokich, gliniastych burt brzegowych. Dno jest tu wybitnie twarde, piaszczysto-żwirowe, co w marcu 2026 roku sprzyja aktywności dużych kleni i jazi. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, puszczając małe woblery baryłkowate bezpośrednio pod nawisy traw. Wędkarze gruntowi stosują lekkie koszyki zanętowe, nęcąc strefy spowolnień nurtu powstające bezpośrednio za naturalnymi przeszkodami. Uciąg rzeki jest żywy i zdecydowany, co zapewnia doskonałe natlenienie łowiska zaraz po okresie zimowym. Dzikość brzegów i brak zwartej zabudowy gwarantują wędkarzowi całkowity spokój oraz kontakt z surową, rzeczną naturą.', 'PZW Częstochowa');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
