-- Spot 310: Warta - Zawada
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71310, 'Warta - Zawada (Śląskie)', 'warta-zawada-klomnice', 'RIVER', 50.9328523, 19.4349729, 'Śląskie', 'Kłomnice', 'Odcinek rzeki w Zawadzie charakteryzuje się licznymi, ostrymi meandrami i urozmaiconym dnem z przewagą drobnego żwiru rzecznego. Rzeka rzeźbi tu techniczne rynienki pod brzegami, które w marcu 2026 roku stanowią bankowe stanowiska dla stad świnek. Spinningiści z dużą uwagą penetrują granice prądu i spokojniejszej wody, szukając wczesnowiosennych okoni oraz walecznych kleni. Wędkarze spławikowi wykorzystują głębsze dołki na zakrętach koryta, nęcąc precyzyjnie stada rzecznych płoci i jelców. Uciąg jest tu stabilny i umiarkowany, co ułatwia precyzyjne sygnalizowanie delikatnych brań na finezyjnych zestawach. Piaszczyste łachy i stosunkowo łatwy dostęp do lustra wody czynią to miejsce komfortowym na całodzienne wędkowanie.', 'PZW Częstochowa');

