-- Spot 311: Warta - Pławno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71311, 'Warta - Pławno', 'warta-plawno', 'RIVER', 50.976993, 19.4488156, 'Łódzkie', 'Radomsko', 'Warta w Pławnie to już szeroka rzeka nizinna o piaszczystym dnie i regularnie występujących, ruchomych przykosach. Nurt rzeźbi tu głębokie rynny toru wodnego, które w marcu 2026 roku gromadzą stada dorodnych leszczy szukających pożywienia. Spinningiści obławiają rozległe piaszczyste blaty, szukając rzecznych boleni aktywujących się przy powierzchni w słoneczne dni. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, stosując spoiste zanęty rzeczne mocno dociążone gliną. Uciąg rzeki jest tu zdecydowany i stały, co wymaga stosowania koszyków zanętowych o masie od 60 gramów wzwyż. Trawiaste i płaskie brzegi sprzyjają bardzo wygodnemu rozstawieniu stanowisk oraz dalekim rzutom spinningowym w stronę nurtu głównego.', 'PZW Częstochowa');

