-- Spot 312: San - Rajskie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71312, 'San - Rajskie (Bieszczady)', 'san-rajskie', 'RIVER', 49.291756, 22.4728421, 'Podkarpackie', 'Solina', 'San w Rajskiem to krystalicznie czysta rzeka górska o niezwykle dynamicznym nurcie, płynąca w głębokim wcięciu bieszczadzkich dolin. Podłoże jest tu wybitnie kamienisto-skaliste, z licznymi kaskadami i głębokimi rynnami wymytymi w litej skale. Marzec 2026 roku to strategiczny czas dla muszkarzy, którzy brodząc w lodowatej wodzie, poszukują rekordowych pstrągów potokowych na ciężkie nimfy. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, celując w głowacice i okazałe klenie stacjonujące w cieniu głazów. Uciąg wody bywa tu gwałtowny, co wymusza stosowanie specjalistycznego obuwia z kolcami do bezpiecznego poruszania się po dnie. Dzikość krajobrazu i surowość bieszczadzkiej przyrody czynią to łowisko jednym z najpiękniejszych w południowej Polsce.', 'PZW Krosno');

