-- Spot 313: San - Horodek (Góra)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71313, 'San - Horodek (Cofka Soliny)', 'san-horodek-gora', 'RIVER', 49.3292042, 22.5169788, 'Podkarpackie', 'Polańczyk', 'Odcinek w Horodku znajduje się w strefie cofki Zbiornika Solińskiego, gdzie nurt Sanu gwałtownie zwalnia i zaczyna deponować piaszczysto-żwirowe osady. Rzeka tworzy tu szerokie rozlewiska o zmiennej głębokości, które w marcu 2026 roku są doskonałym miejscem żerowania dla szczupaków i sandaczy. Wędkarze gruntowi nęcą tutejsze głębokie rynny toru nawigacyjnego, licząc na brania rekordowych leszczy i jazi wchodzących z jeziora. Spinningiści obławiają strome, zalesione burty, wykorzystując przynęty gumowe do badania uskoków dna na granicy starego koryta. Uciąg wody jest tu znikomy, co pozwala na stosowanie delikatniejszych zestawów spławikowych i precyzyjne nęcenie punktowe. Cisza i spokój bieszczadzkiej zatoki gwarantują wędkarzowi unikalny klimat i szansę na spotkanie z wielką rybą jeziorową.', 'PZW Krosno');

