-- Spot 314: San - Horodek (Dół)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71314, 'San - Horodek (Zatoka)', 'san-horodek-dol', 'RIVER', 49.3701278, 22.4820569, 'Podkarpackie', 'Polańczyk', 'Dolny odcinek w rejonie Horodka charakteryzuje się typowo jeziorowym profilem rzeki o miękkim, mulistym dnie i znacznej głębokości. Woda rzeźbi tu szerokie zakola wśród wysokich wzgórz, tworząc idealne warunki dla drapieżników czatujących w zatopionych gałęziach i karczach. Wiosną 2026 roku to strategiczne miejsce dla łowców okoni, które masowo gromadzą się na twardych, piaszczystych półkach przed tarłem. Wędkarze stacjonarni stosują metodę method feeder, celując w wyrośnięte płocie i karasie żerujące w nasłonecznionych zatoczkach. Brak odczuwalnego nurtu sprzyja precyzyjnemu lokowaniu zestawów i komfortowemu wędkowaniu z łodzi wzdłuż krawędzi starego koryta. Malownicze krajobrazy i krystalicznie czysta woda sprawiają, że każda sesja w tym miejscu jest niezapomnianym przeżyciem estetycznym.', 'PZW Krosno');

