-- Spot 315: San - Załuż
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71315, 'San - Załuż (Pstrągowe Płanie)', 'san-zaluz', 'RIVER', 49.5242114, 22.3100384, 'Podkarpackie', 'Sanok', 'San w Załużu to klasyczna rzeka podgórska płynąca szerokim korytem o wybitnie żwirowym dnie i czystej, świetnie natlenionej wodzie. Rzeka tworzy tu rozległe płanie i płytkie bystrza, które w marcu 2026 roku są terytorium intensywnego żerowania lipieni i pstrągów. To strategiczne miejsce dla muszkarzy, którzy z sukcesami prowadzą tu nimfy w rynnach toru głównego pod nawisami wierzb. Spinningiści z zaangażowaniem obławiają granice prądu i spokojniejszej wody, szukając kleni i jazi wybudzonych ze stanowisk zimowych. Uciąg rzeki jest stabilny i zdecydowany, co sprzyja wysokiej aktywności ryb reofilnych poszukujących pokarmu w nurcie. Szerokie i otwarte brzegi pozwalają na swobodne przemieszczanie się i oddawanie dalekich rzutów bez ryzyka zaczepienia o roślinność brzegową.', 'PZW Krosno');

