-- Spot 316: San - Reczpol
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71316, 'San - Reczpol (Erozyjne Zakole)', 'san-reczpol', 'RIVER', 49.7665961, 22.5850767, 'Podkarpackie', 'Przemyśl', 'Odcinek w Reczpolu charakteryzuje się potężnym meandrem rzeki wyciętym w wysokim, gliniastym brzegu pogórza przemyskiego. Pod twardymi burtami rzeka wymywa tu głębokie wanny dochodzące do trzech metrów głębokości, które są bankową ostoją dla brzan i świnek. W marcu 2026 roku wędkarze stacjonarni stosują tu ciężkie zestawy gruntowe, starając się zatrzymać przynętę w najsilniejszym nurcie rynny. Spinningiści obławiają tutejsze warkocze prądowe ciężkimi jigami, szukając sandaczy i sumów stacjonujących przy dnie koryta. Uciąg wody na zewnętrznym łuku jest gwałtowny, co zapewnia doskonałe natlenienie wody nawet przy niskich stanach rzeki. Surowość wysokich skarp i trudny dostęp do wody wymagają od wędkarza determinacji, wynagradzając trud szansą na spotkanie z rzecznymi mocarzami.', 'PZW Przemyśl');

