-- Spot 317: San - Głogowiec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71317, 'San - Głogowiec', 'san-glogowiec', 'RIVER', 50.2023557, 22.551575, 'Podkarpackie', 'Przeworsk', 'San w Głogowcu wchodzi w fazę rzeki nizinnej, charakteryzując się szerokim korytem o piaszczystym dnie z licznymi przykosami i łachami. Rzeka płynie tu spokojniej, formując dotlenione przelewy na piaszczystych mieliznach, gdzie w marcu 2026 roku intensywnie żerują bolenie. Fani metody feederowej rozstawiają się na piaszczystych plażach, posyłając zestawy w głębsze rynienki toru głównego w poszukiwaniu cert i jazi. Spinningiści namierzają stada uklei przy turbulentnych warkoczach, wykorzystując technikę szybkiego prowadzenia przynęt powierzchniowych. Uciąg jest tu umiarkowany i stabilny, co pozwala na precyzyjne nęcenie i skuteczne utrzymywanie ryb w polu łowienia. Otwarty krajobraz doliny rzeki i dogodny dostęp do brzegu w wielu miejscach czynią Głogowiec popularnym łowiskiem wśród lokalnych wędkarzy.', 'PZW Przemyśl');

