-- Spot 318: San - Dębno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71318, 'San - Dębno (Przykosy)', 'san-debno-podkarpackie', 'RIVER', 50.233587, 22.5009021, 'Podkarpackie', 'Leżajsk', 'Odcinek rzeki w Dębnie słynie z rozległych piaszczystych pól i dynamicznie przemieszczających się łach, które modelują koryto rzeki po każdym wiosennym przyborze. Dno jest wybitnie piaszczyste, z gwałtownie opadającymi stokami rynien toru wodnego, stanowiącymi idealne żerowisko dla stad rzecznych leszczy. W marcu 2026 roku spinningiści z sukcesami obławiają tutejsze piaszczyste blaty, szukając boleni i kleni aktywujących się w słońcu. Wędkarze gruntowi stosują lżejsze zestawy feederowe, nęcąc strefy spowolnień nurtu powstające za piaszczystymi językami. Uciąg wody jest tu łagodny, co pozwala na komfortowe wędkowanie przy użyciu najczulszych wędzisk klasy light. Malownicze otoczenie łąk i łatwy dojazd do rzeki sprawiają, że jest to doskonałe miejsce na relaksującą, wiosenną sesję z wędką.', 'PZW Rzeszów');

