VALUES (71318, 'Nizinna Wielka', 'Naturalna, piaszczysta', 80.0, 1.6, 'Piasek', 'Przykosy, łachy piaszczyste', 'Leszcz, Boleń, Kleń', 'Kraina leszcza', true);

-- Spot 319: San - Munina
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71319, 'San - Munina (Opaski Miejskie)', 'san-munina', 'RIVER', 50.0031683, 22.7463427, 'Podkarpackie', 'Jarosław', 'San w Muninie pod Jarosławiem posiada uregulowany charakter z wyraźnie zaznaczonym systemem kamiennych opasek brzegowych i ostróg. Podłoże jest tu twarde, piaszczysto-żwirowe, z głębokimi rynnami toru wodnego sięgającymi ponad dwóch metrów bezpośrednio przy umocnieniach. W marcu 2026 roku to strategiczne miejsce dla łowców białorybu, którzy z sukcesami poławiają dorodne certy i jazie na klasyczny feeder. Spinningiści obławiają cienie betonowych konstrukcji i umocnień, szukając okoni oraz okazyjnych sandaczy stacjonujących przy dnie. Uciąg rzeki jest tu stabilny i zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką waleczność zapiętych ryb. Dobra infrastruktura w pobliżu miejscowości i łatwy dostęp do brzegu czynią Muninę jednym z najchętnie odwiedzanych łowisk w regionie jarosławskim.', 'PZW Przemyśl');

