-- Spot 320: San - Szówsko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71320, 'San - Szówsko', 'san-szowsko', 'RIVER', 50.0432835, 22.7027279, 'Podkarpackie', 'Jarosław', 'San w Szówsku charakteryzuje się szerokim korytem z regularnym systemem ostróg kamiennych, które stabilizują piaszczyste dno rzeki. W marcu 2026 roku klatki między główkami stają się doskonałym miejscem żerowania jazi i kleni, wykorzystujących naniesiony osad organiczny. Wędkarze gruntowi nęcą tu precyzyjnie warkocze prądowe, celując w dorodne certy wchodzące z dolnego biegu. Spinningiści obławiają szczyty ostróg, szukając boleni aktywujących się na piaszczystych przelewach środka koryta. Uciąg rzeki jest tu stabilny, co sprzyja systematycznemu nęczeniu bez ryzyka szybkiego rozmycia zanęty w rynnach. Szerokie i trawiaste brzegi ułatwiają operowanie długimi wędziskami bolońskimi oraz zapewniają wysoki komfort wielogodzinnych zasiadek.', 'PZW Przemyśl');

