-- Spot 321: San - Jarosław
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71321, 'San - Jarosław (Miejskie Bulwary)', 'san-jaroslaw-centrum', 'RIVER', 50.0819434, 22.6656617, 'Podkarpackie', 'Jarosław', 'Miejski odcinek rzeki w Jarosławiu charakteryzuje się głębokim profilem koryta ujętego w techniczne opaski kamienne i mury oporowe bulwarów. Pod filarami mostów nurt jest silnie wymyty, tworząc techniczne rynny sięgające trzech metrów głębokości, będące idealnym zimowiskiem dla sandaczy. W marcu 2026 roku to strategiczne miejsce dla pasjonatów streetfishingu, którzy z sukcesami poławiają okonie wzdłuż betonowych umocnień. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za konstrukcjami hydrotechnicznymi, nęcąc stada okazałych leszczy wchodzących w rzekę. Uciąg rzeki jest tu stały i zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji przynęty. Dobra infrastruktura, oświetlenie brzegów i łatwy dostęp czynią Jarosław jednym z najwygodniejszych łowisk całodobowych w regionie.', 'PZW Przemyśl');

