VALUES (71322, 'Nizinna Wielka', 'Naturalna, piaszczysta', 85.0, 1.6, 'Piasek', 'Przykosy, piaszczyste łachy', 'Boleń, Certa, Leszcz', 'Kraina leszcza', true);

-- Spot 323: San - Sieniawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71323, 'San - Sieniawa', 'san-sieniawa-dolna', 'RIVER', 50.1594015, 22.5957978, 'Podkarpackie', 'Sieniawa', 'San w Sieniawie płynie głębokim korytem o twardym, gliniasto-żwirowym dnie i stromych burtach na zewnętrznych łukach meandrów. Rzeka rzeźbi tu techniczne rynny brzegowe dochodzące do trzech metrów głębokości, stanowiące ostoje dla okazowych brzan i sumów. W marcu 2026 roku to strategiczne miejsce dla łowców białorybu, którzy z sukcesami poławiają dorodne leszcze na klasyczny feeder. Spinningiści z uwagą penetrują tutejsze warkocze, szukając sandaczy i okoni czatujących w cieniu prądowym naturalnych przeszkód brzegowych. Uciąg rzeki jest tu zdecydowany, co zapewnia doskonałe natlenienie łowiska i wysoką aktywność ryb reofilnych. Wysoki brzeg wymaga posiadania podbieraka z długą sztycą, ale oferuje doskonały wgląd w ukształtowanie rynien rzecznych.', 'PZW Przemyśl');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71323, 'Nizinna Wielka', 'Meandrująca, głęboka', 70.0, 2.2, 'Glina i żwir', 'Podmyte burty, rynny', 'Brzana, Leszcz, Sum', 'Kraina brzany', true);

-- Spot 324: San - Myczkowce (Pod Zaporą)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71324, 'San - Myczkowce (Tailwater)', 'san-myczkowce-ponizej-zapory', 'RIVER', 49.4311583, 22.4084579, 'Podkarpackie', 'Lesko', 'Odcinek w Myczkowcach to legendarne łowisko typu tailwater, zasilane krystaliczną i lodowatą wodą zrzutową z elektrowni. Podłoże jest tu wybitnie kamienisto-żwirowe, a stała temperatura wody sprzyja niesamowitej aktywności ryb łososiowatych w marcu 2026 roku. To absolutna mekka dla muszkarzy, którzy prowadząc ciężkie nimfy, wypracowują tu brania rekordowych pstrągów potokowych i lipieni. Spinningiści z sukcesami stosują mikro-jigi i woblery pstrągowe, obławiając głębokie wanny wymyte przez turbulentny nurt bezpośrednio pod progiem. Zmienność przepływów wynikająca z pracy zapory wymusza na wędkarzach czujność i precyzyjne dobieranie ciężaru zestawu do aktualnego uciągu. Surowy, bieszczadzki krajobraz i niespotykana przejrzystość wody czynią Myczkowce jednym z najbardziej technicznych łowisk w Polsce.', 'PZW Krosno');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71324, 'Górska', 'Tailwater, techniczna', 30.0, 1.5, 'Skała i żwir', 'Zapora, warkocze, głazy', 'Pstrąg potokowy, Lipień, Głowacica', 'Kraina pstrąga', false);

-- Spot 325: San - Średnia Wieś
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71325, 'San - Średnia Wieś (Kraina Lipienia)', 'san-srednia-wies', 'RIVER', 49.4202496, 22.3411684, 'Podkarpackie', 'Lesko', 'San w Średniej Wsi to klasyczna rzeka górska o szerokim korycie wyścielonym grubym żwirem i licznymi otoczakami. Rzeka tworzy tu rozległe, płytkie bystrza i doskonale natlenione płanie, które w marcu 2026 roku są terytorium intensywnego żerowania lipieni. To strategiczne miejsce dla wędkarzy muchowych, którzy cenią sobie możliwość bezpiecznego brodzenia po twardym i stabilnym dnie rzeki. Spinningiści z zaangażowaniem obławiają granice prądu i spokojniejszej wody pod nawisami wierzb, szukając walecznych pstrągów potokowych. Uciąg jest tu żywy i stały, co sprzyja wysokiej kondycji ryb reofilnych i ich spektakularnym walorom podczas holu. Niska mętność wody wymusza na wędkarzach zachowanie absolutnej ciszy oraz stosowanie długich i bardzo cienkich przyponów z fluorocarbonu.', 'PZW Krosno');

