VALUES (71325, 'Górska', 'Bystra, żwirowa', 45.0, 0.9, 'Żwir i otoczaki', 'Bystrza, płanie', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 326: San - Tyrawa Solna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71326, 'San - Tyrawa Solna', 'san-tyrawa-solna', 'RIVER', 49.6126833, 22.2689242, 'Podkarpackie', 'Sanok', 'San w Tyrawie Solnej to szeroka rzeka podgórska o dnie wyścielonym grubym żwirem i licznymi otoczakami, które tworzą naturalne bystrza. W marcu 2026 roku krystaliczna i zimna woda sprzyja aktywności lipieni oraz pstrągów potokowych stacjonujących w rynnach toru głównego. To strategiczne miejsce dla muszkarzy, którzy brodząc po twardym dnie, z sukcesami podają ciężkie nimfy w głębsze warkocze prądowe. Spinningiści obławiają podmyte burty brzegowe, szukając kleni i jazi wybudzonych ze stanowisk zimowych pod nawisami wierzb. Uciąg wody jest tu żywy i stały, co wymaga od wędkarza dużej precyzji w prowadzeniu zestawu i utrzymaniu przynęty przy dnie. Dzikość krajobrazu Pogórza i brak zwartej zabudowy gwarantują wędkarzowi spokój oraz bezpośredni kontakt z surową naturą.', 'PZW Krosno');

