-- Spot 327: San - Ulucz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71327, 'San - Ulucz', 'san-ulucz', 'RIVER', 49.6541261, 22.2979461, 'Podkarpackie', 'Brzozów', 'Odcinek w Uluczu charakteryzuje się gwałtownymi zakolami rzeki, które wymywają głębokie doły pod wysokimi, piaszczysto-gliniastymi skarpami. Podłoże jest tu niezwykle zróżnicowane, gdzie piaszczyste łachy sąsiadują z twardymi, żwirowymi rynnami toru wodnego o głębokości do dwóch metrów. W marcu 2026 roku to strategiczne żerowisko dla stad świnek i brzan, które zajmują stanowiska w najsilniejszym nurcie głównego koryta. Spinningiści z uwagą obławiają cienie prądowe za zwalonymi do wody drzewami, szukając sandaczy oraz okazowych okoni. Uciąg na zewnętrznych łukach koryta jest zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką kondycję ryb reofilnych. Malownicze położenie pod historycznym wzgórzem z cerkwią nadaje temu łowisku unikalny, wyciszający klimat sprzyjający długim zasiadkom.', 'PZW Krosno');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71327, 'Podgórska', 'Erozyjna, meandrująca', 50.0, 1.8, 'Żwir i glina', 'Podmyte burty, głębokie jamy', 'Świnka, Brzana, Sandacz', 'Kraina brzany', false);

-- Spot 328: San - Witryłów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71328, 'San - Witryłów', 'san-witrylow', 'RIVER', 49.6839509, 22.2449957, 'Podkarpackie', 'Brzozów', 'San w Witryłowie płynie szerokim korytem przez rozległe płanie żwirowe, tworząc liczne przykosy i płytkie, natlenione przelewy. Dno składa się w głównej mierze z drobnego żwiru i piasku, co w marcu 2026 roku przyciąga stada jazi i płoci szukających pierwszego wiosennego pokarmu. Fani przepływanki z sukcesami nęcą tutejsze rynienki, stosując delikatne zestawy spławikowe z niewielkim dociążeniem. Spinningiści patrolują krawędzie najszybszego nurtu, wykorzystując małe woblery pstrągowe do kuszenia aktywnych kleni. Uciąg wody jest tu stabilny, co pozwala na precyzyjne podawanie przynęt gruntowych przy użyciu lżejszych wędzisk klasy light. Dogodny dostęp do brzegu w rejonie kładki pieszej i otwarty teren ułatwiają operowanie długimi wędziskami bolońskimi oraz zapewniają świetną widoczność rzeki.', 'PZW Krosno');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
