-- Spot 329: San - Wołodź
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71329, 'San - Wołodź', 'san-wolodz', 'RIVER', 49.7277811, 22.2267717, 'Podkarpackie', 'Dynów', 'Odcinek w Wołodzi charakteryzuje się obecnością licznych wysp żwirowych, które dzielą nurt rzeki na kilka mniejszych, bystrych odnóg. Podłoże jest tu wyjątkowo twarde, wysłane narzutem kamiennym, co w marcu 2026 roku tworzy idealne warunki dla brzan stacjonujących w głębokich rynnach między wyspami. Spinningiści obławiają turbulentne warkocze prądowe powstające na styku nurtów, szukając boleni i dużych kleni polujących na drobnicę. Wędkarze stacjonarni stosują dociążone zestawy gruntowe z pęczkiem czerwonych robaków, polując w najgłębszych partiach koryta rzeźbionego przez prąd. Uciąg wody w tych przewężeniach bywa gwałtowny, co wymaga od wędkarza dużej siły i odporności sprzętu podczas walki z rybą. Dziki charakter brzegów porośniętych gęstą wikliną zapewnia wędkarzowi poczucie izolacji i osłonę przed silnymi podmuchami wiatru.', 'PZW Krosno');

