-- Spot 330: San - Nozdrzec
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71330, 'San - Nozdrzec', 'san-nozdrzec', 'RIVER', 49.7725342, 22.214071, 'Podkarpackie', 'Dynów', 'San w Nozdrzcu płynie szeroką doliną, charakteryzując się umiarkowanym nurtem i urozmaiconym, piaszczysto-żwirowym dnem z licznymi podmyciami. Rzeka rzeźbi tu techniczne rynny na zewnętrznych łukach meandrów, które w marcu 2026 roku są bankowymi stanowiskami dla dorodnych leszczy. Wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w rekordowe certy i jazie przemieszczające się w górę rzeki. Spinningiści z uwagą penetrują podmyte korzenie nadrzecznych olch, wykorzystując małe gumy do kuszenia wczesnowiosennych szczupaków i okoni. Uciąg wody jest stabilny i przewidywalny, co sprzyja systematycznemu nęczeniu bez ryzyka zbyt szybkiego rozmycia dywanu zanętowego. Malownicze panoramy Pogórza Dynowskiego i łatwy dostęp do brzegów w wielu miejscach czynią Nozdrzec popularnym łowiskiem wśród lokalnych pasjonatów.', 'PZW Krosno / PZW Przemyśl');

