-- Spot 331: San - Dynów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71331, 'San - Dynów (Miejskie Bystrza)', 'san-dynow-centrum', 'RIVER', 49.8124002, 22.2491828, 'Podkarpackie', 'Dynów', 'Miejski odcinek rzeki w Dynowie charakteryzuje się żywym nurtem i twardym, żwirowym dnem poprzecinanym nielicznymi narzutami kamiennymi pod mostem drogowym. Rzeka tworzy tu techniczne warkocze prądowe i rynny torowe, które w marcu 2026 roku przyciągają stada świnek oraz waleczne klenie żerujące w nurcie. Spinningiści z sukcesami obławiają tutejsze bystrza, wykorzystując smużaki i małe woblery do prowokowania ryb reofilnych. Wędkarze spławikowi nęcą wąskie pasma wolniejszej wody za filarami mostów, celując w rzeczne płocie i jelce szukające pokarmu. Uciąg wody jest tu zdecydowany, co zapewnia doskonałe natlenienie łowiska i przekłada się na wysoką waleczność holowanych ryb. Dobra infrastruktura miejska, łatwy dojazd i utwardzone stanowiska brzegowe czynią Dynów idealnym miejscem na krótkie, techniczne sesje.', 'PZW Krosno');

