-- Spot 332: San - Sielnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71332, 'San - Sielnica', 'san-sielnica', 'RIVER', 49.8147412, 22.319868, 'Podkarpackie', 'Dynów', 'San w Sielnicy rozlewa się szeroko, formując klasyczną krainę piaszczystych przykos i głębokich zakoli rzeźbionych w piaszczysto-gliniastym podłożu. Dno jest tu zmienne, z wyraźnie zaznaczonymi rynnami na krawędzi nurtu głównego, które w marcu 2026 roku gromadzą stada dorodnych leszczy. Fani metody feederowej rozstawiają się na piaszczystych łachach, posyłając zestawy w głębsze rynienki rzeźbione przez nurt torowy. Spinningiści z uwagą obserwują lustro wody, namierzając ataki boleni na stada uklei gromadzącej się na płytkich, nasłonecznionych mieliznach. Uciąg wody jest umiarkowany i bardzo stabilny, co pozwala na precyzyjne sygnalizowanie delikatnych brań nawet przy użyciu bardzo finezyjnego sprzętu. Dzikość brzegów i brak gęstej zabudowy w bezpośrednim sąsiedztwie rzeki gwarantują wędkarzowi całkowity spokój oraz kontakt z dziką przyrodą Pogórza.', 'PZW Krosno');

