-- Spot 333: San - Wybrzeże
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71333, 'San - Wybrzeże', 'san-wybrzeze', 'RIVER', 49.8137682, 22.3902852, 'Podkarpackie', 'Dubiecko', 'San w miejscowości Wybrzeże płynie pod malowniczą, wysoką skarpą, oferując głębokie rynny o dnie żwirowo-gliniastym. W marcu 2026 roku rzeka tworzy tu techniczne warkocze prądowe, w których stacjonują stada świnek i dorodnych jazi. Spinningiści z sukcesami obławiają tutejsze podmyte burty, poszukując kleni wybudzonych z zimowego letargu pod nawisami gałęzi. Wędkarze stacjonarni stosują ciężkie zestawy gruntowe, by utrzymać przynętę w głównym nurcie rzeźbionym przez silny prąd rzeki. Uciąg jest tu zdecydowany i stały, co zapewnia doskonałe natlenienie łowiska i wysoką kondycję ryb reofilnych. Dzikość krajobrazu i obecność kładki wiszącej nad rzeką nadają temu łowisku unikalny, bieszczadzko-podgórski klimat.', 'PZW Przemyśl');

