-- Spot 334: San - Iskań
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71334, 'San - Iskań', 'san-iskan', 'RIVER', 49.7905941, 22.450178, 'Podkarpackie', 'Dubiecko', 'Odcinek w Iskani charakteryzuje się szerokimi płaniami żwirowymi oraz występowaniem płytkich, dynamicznych bystrzy. Dno składa się z drobnego żwiru i twardej gliny, co w marcu 2026 roku sprzyja żerowaniu stad cert przemieszczających się korytem głównym. Spinningiści namierzają tu ryby na krawędziach nurtu, wykorzystując lekkie woblery i obrotówki do kuszenia aktywnych kleni. Wędkarze spławikowi nęcą tutejsze rynienki, stosując metodę przepływanki z przytrzymaniem w celu sprowokowania ryb spokojnego żeru. Uciąg rzeki na prostych odcinkach jest stabilny, co pozwala na precyzyjne punktowe nęcenie rzecznym feederem. Malownicza panorama Pogórza Przemyskiego i brak zwartej zabudowy brzegowej gwarantują wędkarzowi ciszę i pełną integrację z naturą.', 'PZW Przemyśl');

