-- Spot 335: San - Ruszelczyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71335, 'San - Ruszelczyce', 'san-ruszelczyce', 'RIVER', 49.8063616, 22.5163652, 'Podkarpackie', 'Krzywcza', 'Łowisko w Ruszelczycach to głęboka rynna rzeczna z licznymi podwodnymi głazami, które tworzą naturalne cienie prądowe dla drapieżników. Podłoże jest tu twarde, wysłane grubym żwirem i kamieniami, co zapobiega nadmiernemu mętnieniu wody po wiosennych opadach w marcu 2026 roku. To strategiczne miejsce dla łowców brzan, które zajmują stanowiska w najgłębszych partiach toru nawigacyjnego rzeki. Spinningiści z sukcesami penetrują tutejsze warkocze, szukając sandaczy i okoni stacjonujących przy dnie za skalnymi narzutami. Uciąg wody jest tu żywy i wymagający technicznie, co wymusza stosowanie dociążonych koszyków i mocnych zestawów spinningowych. Surowość brzegów porośniętych wiklinami zapewnia doskonałe warunki do kameralnego wędkowania z dala od miejskiego zgiełku.', 'PZW Przemyśl');

