-- Spot 336: San - Korytniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71336, 'San - Korytniki', 'san-korytniki', 'RIVER', 49.7797296, 22.6528708, 'Podkarpackie', 'Krasiczyn', 'San w Korytnikach silnie meandruje wśród podmokłych łąk, tworząc rozległe przykosy i piaszczyste łachy na wewnętrznych łukach koryta. Dno jest tu zmienne, gdzie piaszczyste wypłycenia sąsiadują z głębokimi rynnami erozyjnymi wymytymi w twardej, piaszczystej glinie. Marzec 2026 roku to idealny czas na namierzanie cert i jazi, które gromadzą się w spokojniejszych warkoczach przed tarłem. Spinningiści obławiają podmyte korzenie nadrzecznych olch, wykorzystując małe gumy do kuszenia wczesnowiosennych szczupaków. Uciąg rzeki stabilizuje się na szerokich rozlaniach, co pozwala na komfortowe wędkowanie metodą lekkiego feedera bez ryzyka częstych zaczepów. Bliskość zamku w Krasiczynie i piękna dolina Sanu nadają temu miejscu unikalny charakter krajobrazowy.', 'PZW Przemyśl');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71336, 'Podgórska/Nizinna', 'Naturalna, meandrująca', 60.0, 1.6, 'Piasek i glina', 'Przykosy, zwalone drzewa', 'Jaź, Certa, Szczupak', 'Kraina brzany', true);

-- Spot 337: San - Ostrów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71337, 'San - Ostrów', 'san-ostrow-podkarpackie', 'RIVER', 49.7817339, 22.7240713, 'Podkarpackie', 'Przemyśl', 'Odcinek w Ostrowie charakteryzuje się dynamicznym nurtem i obecnością technicznych opasek kamiennych chroniących brzegi przed samym Przemyślem. Podłoże jest tu wyjątkowo twarde, piaszczysto-żwirowe, co w marcu 2026 roku przyciąga rekordowe klenie i jazie żerujące w nurcie głównym. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe, szukając boleni aktywujących się na przelewach przykos rzecznych. Wędkarze gruntowi stosują koszyki o gramaturze powyżej 60 gramów, aby skutecznie utrzymać zestaw na krawędzi piaszczystego stoku rynny. Woda jest tu doskonale natleniona, co zapewnia wysoką aktywność ryb reofilnych i ich spektakularną waleczność podczas holu. Szerokie i otwarte brzegi ułatwiają operowanie długimi wędziskami bolońskimi oraz dalekie rzuty w stronę toru wodnego.', 'PZW Przemyśl');

