-- Spot 338: San - Przemyśl (Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71338, 'San - Przemyśl (Bulwary)', 'san-przemysl-centrum', 'RIVER', 49.8000232, 22.7898926, 'Podkarpackie', 'Przemyśl', 'Miejski odcinek Sanu w Przemyślu posiada uregulowany charakter z wysokimi murami oporowymi bulwarów i licznymi filarami mostów. Pod konstrukcjami mostowymi nurt jest silnie wymyty, tworząc głębokie rynny torowe będące idealnym zimowiskiem dla sandaczy i sumów. W marcu 2026 roku to strategiczne miejsce dla fanów streetfishingu, którzy z sukcesami poławiają okonie wzdłuż betonowych umocnień. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za filarami, nęcąc stada okazałych leszczy i cert wchodzących w rzekę. Uciąg rzeki jest tu stabilny, ale potężny, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji zestawu. Dobra infrastruktura miejska, oświetlenie i łatwy dostęp do brzegów czynią Przemyśl jednym z najwygodniejszych łowisk w regionie.', 'PZW Przemyśl');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71338, 'Nizinna Wielka', 'Uregulowana miejska', 75.0, 2.5, 'Beton i żwir', 'Bulwary, filary mostów', 'Okoń, Sandacz, Leszcz', 'Kraina leszcza', true);

-- Spot 339: San - Bolestraszyce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71339, 'San - Bolestraszyce', 'san-bolestraszyce', 'RIVER', 49.8044275, 22.8605606, 'Podkarpackie', 'Przemyśl', 'Poniżej Przemyśla San w Bolestraszycach rozlewa się szeroko, formując klasyczną krainę piaszczystych przykos i głębokich zakoli. Dno składa się w głównej mierze z drobnego piasku, który nieustannie przemieszcza się, formując nowe rynny torowe po zimowych przyborach wody. W marcu 2026 roku te płytkie, dobrze nasłonecznione strefy stają się magnesem dla jazi i kleni żerujących na budzącej się faunie dennej. Fani metody feederowej rozstawiają się na piaszczystych łachach, posyłając zestawy w spokojniejsze warkocze w poszukiwaniu rzecznych krąpi. Uciąg wody jest umiarkowany, co ułatwia precyzyjne sygnalizowanie brań i pozwala na stosowanie lżejszych wędzisk klasy light. Spokój otaczającej przyrody i bliskość rezerwatu przyrody nadają temu miejscu unikalny, wyciszający charakter wędkarski.', 'PZW Przemyśl');

