VALUES (71339, 'Nizinna Wielka', 'Szeroka, piaszczysta', 80.0, 1.7, 'Piasek', 'Przykosy, piaszczyste łachy', 'Jaź, Kleń, Krąp', 'Kraina leszcza', true);

-- Spot 340: San - Walawa
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71340, 'San - Walawa', 'san-walawa', 'RIVER', 49.8444824, 22.8976563, 'Podkarpackie', 'Jarosław', 'San w Walawie płynie szerokim łukiem przez tereny nizinne, charakteryzując się znaczną głębokością toru wodnego i twardym, piaszczysto-żwirowym dnem. Rzeka tworzy tu techniczne rynny brzegowe dochodzące do trzech metrów głębokości, stanowiące bankowe zimowisko dla rzecznych sandaczy. W marcu 2026 roku wędkarze feederowi z sukcesami nęcą tutejsze płanie, celując w rekordowe leszcze i certy migrujące z dolnego biegu. Spinningiści obławiają tutejsze warkocze prądowe ciężkimi jigami, starając się dotrzeć do drapieżników przyklejonych do dna koryta. Uciąg rzeki jest tu stabilny i zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką waleczność wyholowanych tu ryb. Szerokie i trawiaste brzegi ułatwiają operowanie długimi wędziskami bolońskimi oraz zapewniają wysoki komfort podczas wielogodzinnych zasiadek.', 'PZW Przemyśl');

