-- Spot 341: San - Niziny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71341, 'San - Niziny', 'san-niziny', 'RIVER', 49.8883306, 22.9134963, 'Podkarpackie', 'Jarosław', 'San w miejscowości Niziny charakteryzuje się szerokim korytem o piaszczystym dnie i obecnością technicznych opasek kamiennych stabilizujących brzeg. W marcu 2026 roku rzeka tworzy tu wyraźne warkocze prądowe, na krawędzi których grupują się stada jazi i płoci. Spinningiści z sukcesami obławiają tutejsze przelewy, szukając boleni aktywujących się w słońcu na piaszczystych przykosach. Wędkarze gruntowi nęcą rynny torowe, celując w rekordowe leszcze przemieszczające się w górę rzeki. Uciąg jest stabilny, co pozwala na precyzyjne nęcenie rzecznym feederem z użyciem koszyków o masie 60-80 gramów. Otwarty teren i łatwy dostęp do brzegu sprawiają, że Niziny są bardzo komfortowym łowiskiem na rozpoczęcie wiosennego sezonu.', 'PZW Przemyśl');

