-- Spot 342: San - Święte
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71342, 'San - Święte', 'san-swiete', 'RIVER', 49.9259827, 22.8652074, 'Podkarpackie', 'Jarosław', 'Odcinek rzeki w miejscowości Święte to głębokie zakole z wyraźnie zaznaczoną rynną erozyjną pod wysokim, prawym brzegiem. Dno jest tu twardsze, piaszczysto-gliniaste, co sprzyja bytowaniu brzan i sandaczy czatujących w głębszych partiach koryta. Wiosną 2026 roku to strategiczne miejsce dla łowców białorybu, którzy nęcą spokojniejsze warkocze w poszukiwaniu dorodnych cert. Spinningiści z uwagą penetrują podmyte korzenie nadrzecznych olch, wykorzystując gumy w jaskrawych kolorach przy lekko mętnej wodzie. Uciąg wody jest zdecydowany, co zapewnia doskonałe natlenienie łowiska i wysoką waleczność zaciętych ryb. Wysoki brzeg wymaga posiadania podbieraka z długą sztycą, ale oferuje świetny wgląd w ukształtowanie dna rzeki.', 'PZW Przemyśl');

