-- Spot 343: San - Wysocko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71343, 'San - Wysocko', 'san-wysocko', 'RIVER', 49.9660407, 22.8278332, 'Podkarpackie', 'Jarosław', 'San w Wysocku rozlewa się szeroko, formując klasyczną krainę piaszczystych wysp i łach dzielących nurt na kilka odnóg. Podłoże składa się głównie z drobnego piasku, który nieustannie przemieszcza się, tworząc dotlenione przelewy powierzchniowe idealne dla żerujących boleni. W marcu 2026 roku to wymarzone miejsce dla fanów metody feederowej, którzy rozstawiają się na piaszczystych plażach. Spinningiści obławiają turbulentną wodę na styku nurtów przy wyspach, szukając kleni wybudzonych ze stanowisk zimowych. Uciąg rzeki stabilizuje się na prostych odcinkach, co pozwala na precyzyjne podawanie przynęt i finezyjne sygnalizowanie brań. Malowniczy krajobraz doliny Sanu i brak gęstej zabudowy gwarantują wędkarzowi całkowity spokój i kontakt z naturą.', 'PZW Przemyśl');

