-- Spot 344: San - Kuryłówka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71344, 'San - Kuryłówka', 'san-kurylowka', 'RIVER', 50.284173, 22.4458263, 'Podkarpackie', 'Leżajsk', 'Odcinek w Kuryłówce to potężna rzeka nizinna o piaszczystym dnie, płynąca szerokim korytem przez rozległe kompleksy leśne. Nurt formuje tu dynamiczne przykosy, za którymi woda gwałtownie zapada się w rynny torowe o głębokości do trzech metrów. Marzec 2026 roku to czas aktywności dużych leszczy, które grupują się na stokach piaszczystych wydm w poszukiwaniu pokarmu. Spinningiści z sukcesami obławiają tutejsze warkocze, rzucając cięższymi woblerami w poszukiwaniu sandaczy stacjonujących przy dnie. Uciąg rzeki jest tu stabilny i zdecydowany, co wymaga stosowania dociążonych koszyków zanętowych dla stabilnej prezentacji. Dzikość brzegów i utrudniony dojazd do niektórych zakoli zapewniają wędkarzowi ciszę i brak nadmiernej presji wędkarskiej.', 'PZW Rzeszów');

