-- Spot 345: San - Łazów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71345, 'San - Łazów', 'san-lazow', 'RIVER', 50.3315592, 22.4335587, 'Podkarpackie', 'Leżajsk', 'San w Łazowie płynie w urokliwej dolinie, charakteryzując się licznymi piaszczystymi przykosami i płytkimi przelewami. Dno jest tu wybitnie piaszczyste, co w marcu 2026 roku przyciąga stada uklei, za którymi podążają żarłoczne bolenie. Wędkarze gruntowi rozstawiają się na twardych płaniach żwirowych, celując w rzeczne płocie i certy przemieszczające się głównym nurtem. Spinningiści namierzają drapieżniki na krawędziach rynien, wykorzystując technikę szybkiego prowadzenia przynęt powierzchniowych w zasięgu słońca. Uciąg jest umiarkowany, co pozwala na stosowanie lżejszych metod feederowych i precyzyjne sygnalizowanie nawet delikatnych brań. Kameralna okolica i łatwy dostęp do rzeki w rejonie miejscowości czynią Łazów doskonałym miejscem na wiosenne zasiadki.', 'PZW Rzeszów');

