-- Spot 346: San - Sarzyna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71346, 'San - Sarzyna', 'san-sarzyna', 'RIVER', 50.355273, 22.3730765, 'Podkarpackie', 'Leżajsk', 'Łowisko w Sarzynie to techniczny odcinek rzeki o uregulowanych brzegach, wzmocnionych betonowo-kamiennymi opaskami chroniącymi koryto. Dno jest tu twarde, wysłane narzutem kamiennym i grubym żwirem, co sprzyja bytowaniu dużych kleni i jazi żerujących w nurcie. Wczesną wiosną 2026 roku spinningiści obławiają cienie betonowych konstrukcji, szukając okoni stacjonujących przy dnie toru wodnego. Wędkarze gruntowi wykorzystują spowolnienia nurtu za umocnieniami brzegowymi, nęcąc stada okazałych leszczy i krąpi. Uciąg rzeki jest tu zdecydowany i stały, co wymusza stosowanie dociążonych koszyków zanętowych o masie od 80 gramów wzwyż. Dobra infrastruktura i łatwy dostęp do brzegu czynią Sarzynę popularnym punktem wypraw dla wędkarzy ceniących komfort i rybną wodę.', 'PZW Rzeszów');

