-- Spot 347: San - Krzeszów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71347, 'San - Krzeszów', 'san-krzeszow', 'RIVER', 50.3954579, 22.3365697, 'Podkarpackie', 'Krzeszów', 'San w Krzeszowie to jedna z najbardziej znanych lokalizacji wędkarskich na dolnym Sanie, słynąca z rozległych piaszczystych plaż i głębokich rynien. Dno składa się z drobnego piasku, który nieustannie modeluje koryto, tworząc techniczne wanny na łukach rzeki dochodzące do trzech metrów głębokości. W marcu 2026 roku to strategiczne miejsce dla łowców sandaczy, którzy wykorzystują turbulentną wodę na styku nurtów. Wędkarze stacjonarni nęcą tutejsze głębokie doły, z sukcesami poławiając rekordowe leszcze i certy na klasyczny feeder. Uciąg wody jest zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej kondycji ryb reofilnych. Malownicze położenie miejscowości i historyczny klimat spławu drewna nadają każdemu wędkowaniu w tym miejscu wyjątkowej atmosfery.', 'PZW Tarnobrzeg');

