-- Spot 348: San - Chałupki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71348, 'San - Chałupki', 'san-chalupki', 'RIVER', 50.4281122, 22.287233, 'Podkarpackie', 'Rudnik nad Sanem', 'Odcinek w Chałupkach charakteryzuje się naturalnym przebiegiem koryta z licznymi podmywanymi burtami i piaszczystymi łachami. Rzeka żłobi tu techniczne rynienki pod brzegami, które w marcu 2026 roku stanowią idealne schronienie dla stad jazi i cert. Spinningiści z sukcesami obławiają tutejsze warkocze prądowe małymi woblerami, wyczekując uderzeń aktywnych kleni. Wędkarze gruntowi stosują koszyki zanętowe o gramaturze 60-80 gramów, starając się zatrzymać przynętę na krawędzi nurtu głównego. Uciąg rzeki jest umiarkowany i stabilny, co sprzyja systematycznemu nęczeniu bez ryzyka zbyt szybkiego wymycia dywanu zanętowego. Dzikość brzegów porośniętych gęstą wikliną zapewnia wędkarzowi poczucie izolacji i możliwość kontaktu z rzeczną naturą.', 'PZW Tarnobrzeg');

