INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71349, 'San - Bieliniec', 'san-bieliniec', 'RIVER', 50.4701315, 22.2604527, 'Podkarpackie', 'Ulanów', 'San w Bielińcu to szeroka, nizinna rzeka o bardzo piaszczystym korycie i obecności rozległych przykos rzecznych. Podłoże jest tu niezwykle ruchome, co zmusza wędkarzy do częstego sondowania dna w poszukiwaniu aktualnych rynien i stoków łach. W marcu 2026 roku te płytkie, nasłonecznione strefy stają się magnesem dla boleni polujących na drobnicę na przelewach. Fani metody feederowej rozstawiają się na piaszczystych plażach, celując w rzeczne krąpie i leszcze żerujące w spokojniejszych warkoczach. Uciąg jest żywy, co zapewnia doskonałe natlenienie wody i wysoką waleczność holowanych ryb karpiowatych. Kameralna okolica ujścia rzeki Tanew (nieco poniżej) sprawia, że Bieliniec jest strategicznym punktem na trasie wiosennych wędrówek ryb.', 'PZW Tarnobrzeg');

