-- Spot 350: San - Zarzecze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71350, 'San - Zarzecze', 'san-zarzecze', 'RIVER', 50.5049532, 22.2111133, 'Podkarpackie', 'Nisko', 'San w Zarzeczu to klasyczna, szeroka rzeka nizinna o wybitnie piaszczystym dnie i łagodnym profilu brzegowym. W marcu 2026 roku nurt rzeźbi tu dynamiczne przykosy, za którymi woda gwałtownie zapada się w dotlenione rynny toru głównego. To strategiczne miejsce dla wędkarzy feederowych, którzy z sukcesami nęcą stada cert i jazi wędrujących pod prąd. Spinningiści namierzają tu bolenie żerujące na rozległych piaszczystych płaniach w zasięgu słońca. Uciąg wody jest stabilny, co pozwala na precyzyjne sygnalizowanie nawet najdelikatniejszych brań na czułych szczytówkach. Spokojna okolica i łatwy dostęp do rzeki czynią Zarzecze idealnym punktem na wiosenne otwarcie sezonu rzecznego.', 'PZW Tarnobrzeg');

