-- Spot 351: San - Nisko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71351, 'San - Nisko', 'san-nisko', 'RIVER', 50.5357316, 22.1546367, 'Podkarpackie', 'Nisko', 'Miejski odcinek w Nisku charakteryzuje się twardym, piaszczysto-żwirowym dnem i obecnością technicznych opasek brzegowych. Rzeka formuje tu długie warkocze prądowe, które w marcu 2026 roku są intensywnie patrolowane przez bolenie i duże klenie. Fani metody feederowej rozstawiają się na utwardzonych stanowiskach, posyłając zestawy w głębokie rynny toru wodnego w poszukiwaniu rzecznych płoci. Uciąg jest tu zdecydowany, co zapewnia doskonałe natlenienie wody i wysoką aktywność ryb reofilnych po zimie. Spinningiści z sukcesami obławiają cienie prądowe za mostem, wykorzystując lekkie woblery prowadzone w poprzek nurtu. Dobra infrastruktura i łatwy dojazd do brzegów w rejonie miasta czynią Nisko popularnym łowiskiem wśród lokalnych pasjonatów.', 'PZW Tarnobrzeg');

