-- Spot 352: San - Stalowa Wola (Centrum)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71352, 'San - Stalowa Wola (Centrum)', 'san-stalowa-wola-centrum', 'RIVER', 50.5546034, 22.0897487, 'Podkarpackie', 'Stalowa Wola', 'Odcinek w centrum Stalowej Woli to techniczne łowisko o uregulowanym korycie i znacznej głębokości w nurcie głównym. Pod filarami mostów rzeka wymywa głębokie rynny sięgające czterech metrów, będące idealnym zimowiskiem dla sandaczy i okoni. W marcu 2026 roku to strategiczne miejsce dla fanów streetfishingu, którzy z sukcesami poławiają ryby wzdłuż betonowych umocnień. Wędkarze stacjonarni nęcą spokojniejsze warkocze za konstrukcjami, celując w rekordowe leszcze i certy wchodzące z dołu rzeki. Uciąg rzeki jest tu potężny i stały, co wymaga stosowania ciężkich koszyków zanętowych o masie od 80 gramów wzwyż. Dobra dostępność nabrzeży i oświetlenie brzegów pozwalają na komfortowe wędkowanie również w godzinach wieczornych.', 'PZW Tarnobrzeg');

