-- Spot 353: San - Stalowa Wola (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71353, 'San - Stalowa Wola (Północ)', 'san-stalowa-wola-polnoc', 'RIVER', 50.597446, 22.0648578, 'Podkarpackie', 'Stalowa Wola', 'Północny odcinek w Stalowej Woli to kraina szerokich rozlewisk piaszczystych i rozległych przykos modelowanych przez silny nurt. Dno jest tu wybitnie ruchome, co zmusza wędkarzy do częstego sondowania głębokości w poszukiwaniu aktualnych rynien torowych. Marzec 2026 roku to wyśmienity czas na namierzanie boleni, które wykorzystują turbulentną wodę na styku nurtu głównego i spowolnień. Wędkarze gruntowi rozstawiają się na piaszczystych łachach, posyłając zestawy w głębsze rynienki w poszukiwaniu stadnych krąpi. Uciąg wody jest tu żywy, co zapewnia doskonałe natlenienie łowiska i wysoką kondycję ryb po okresie zimowym. Dzikość brzegów na tym odcinku kontrastuje z industrialnym krajobrazem miasta, oferując unikalne warunki do wędkowania drapieżników.', 'PZW Tarnobrzeg');

