-- Spot 354: San - Kępa Rzeczycka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71354, 'San - Kępa Rzeczycka', 'san-kepa-rzeczycka', 'RIVER', 50.6379497, 22.0320075, 'Podkarpackie', 'Stalowa Wola', 'Warta w Kępie Rzeczyckiej (San) silnie meandruje, tworząc głębokie rynny pod brzegami i rozległe przykosy piaszczyste na wewnętrznych łukach. Podłoże jest tu twarde, piaszczysto-gliniaste, co w marcu 2026 roku przyciąga rekordowe brzany i certy żerujące w nurcie. Spinningiści z sukcesami obławiają podmyte burty porośnięte gęstą wikliną, szukając wczesnowiosennych szczupaków i kleni. Uciąg rzeki na zewnętrznych łukach jest gwałtowny, co wymusza stosowanie dociążonych koszyków zanętowych dla stabilnej prezentacji przynęty. Dzikość brzegów i brak łatwego dojazdu gwarantują wędkarzowi spokój oraz brak nadmiernej presji ze strony innych łowiących. To strategiczne miejsce dla technicznie zaawansowanych łowców brzan, którzy cenią sobie trudne, ale rybne stanowiska rzeczne.', 'PZW Tarnobrzeg');

