-- Spot 355: San - Majdan Zbydniowski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71355, 'San - Majdan Zbydniowski', 'san-majdan-zbydniowski', 'RIVER', 50.657556, 21.9637493, 'Podkarpackie', 'Zaleszany', 'San w Majdanie Zbydniowskim to klasyczna kraina wysp i piaszczystych łach, dzielących nurt na kilka mniejszych, bystrych odnóg. Dno składa się z drobnego piasku i żwiru, co w marcu 2026 roku tworzy idealne warunki dla jazi i kleni żerujących na przelewach. Wędkarze gruntowi rozstawiają się na piaszczystych plażach, celując w rzeczne krąpie i płocie przemieszczające się korytem głównym. Spinningiści obławiają turbulentne warkocze prądowe powstające na styku nurtów przy wyspach, szukając żerujących boleni. Uciąg jest tu umiarkowany, co ułatwia precyzyjne sygnalizowanie brań i pozwala na stosowanie lżejszych wędzisk klasy light. Całkowita izolacja od głównych dróg i dzikość przyrody nadają temu miejscu unikalny, wyciszający charakter wędkarski.', 'PZW Tarnobrzeg');

