-- Spot 356: San - Skowierzyn
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71356, 'San - Skowierzyn (Przed-ujście)', 'san-skowierzyn', 'RIVER', 50.6867122, 21.9028095, 'Podkarpackie', 'Zaleszany', 'Odcinek w Skowierzynie to przedsionek ujścia Sanu do Wisły, charakteryzujący się ogromną masą wody i potężnym korytem o głębokości do trzech metrów. Dno jest tu twarde, piaszczysto-żwirowe, co w marcu 2026 roku staje się strategicznym żerowiskiem dla sandaczy podążających za stadami drobnej uklei. Wędkarze stacjonarni stosują najcięższe zestawy gruntowe, starając się zatrzymać przynętę w głębokich rynnach toru głównego rzeki. Uciąg wody jest tu zdecydowany i stały, co zapewnia doskonałe natlenienie łowiska i wysoką kondycję ryb wędrownych. Spinningiści obławiają dalekie warkocze prądowe, licząc na kontakt z rekordowymi boleniami i okazowymi leszcze. Dzikość brzegów i bliskość wielkiej wody wiślanej sprawiają, że Skowierzyn jest jednym z najbardziej rybnych i technicznych łowisk w dolnym biegu rzeki.', 'PZW Tarnobrzeg');

