-- Spot 357: San - Dąbrówka Pniowska (Ujście do Wisły)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71357, 'San - Dąbrówka Pniowska (Ujście)', 'san-dabrowka-pniowska', 'RIVER', 50.7262833, 21.864529, 'Podkarpackie', 'Sandomierz', 'Finałowy odcinek Sanu w Dąbrówce Pniowskiej to potężna arena zderzenia dwóch największych rzek regionu, charakteryzująca się piaszczystym dnem i ogromnym warkoczem ujściowym. W marcu 2026 roku stabilne stany wód sprzyjają tu łowieniu rekordowych leszczy i cert, które gromadzą się w głębokich rynnach przed wejściem w nurt Wisły. Spinningiści z sukcesami obławiają tutejsze rozległe przykosy, szukając boleni żerujących na piaszczystych przelewach przy samym styku nurtów. Uciąg wody jest tu bardzo złożony, z licznymi prądami wstecznymi, co wymaga od wędkarza dużej precyzji w czytaniu lustra wody. Podłoże jest wybitnie piaszczyste, z dynamicznie przemieszczającymi się łachami, co wymusza częste sondowanie dna zestawem gruntowym. Dzikość brzegów i potęga otwartej wody nadają temu miejscu majestatyczny, niemal surowy klimat wędkarski.', 'PZW Tarnobrzeg');

