-- Spot 358: San - Huzele (Brama Bieszczad)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71358, 'San - Huzele', 'san-huzele', 'RIVER', 49.4643261, 22.3272895, 'Podkarpackie', 'Lesko', 'San w Huzelach to klasyczna rzeka górska o krystalicznej wodzie i dnie usianym grubym żwirem oraz otoczakami. W marcu 2026 roku to strategiczne łowisko dla muszkarzy, którzy w chłodnym nurcie poszukują pstrągów potokowych i lipieni na techniczne nimfy. Rzeka tworzy tu liczne bystrza i szerokie płanie, które są doskonale natlenione, co przekłada się na wysoką waleczność tutejszego rybostanu. Spinningiści z sukcesami penetrują głębsze rynny pod nawisami wierzb, licząc na kontakt z wybudzonymi kleniami i jaziowatymi. Uciąg rzeki jest żywy i stały, co wymaga stosowania finezyjnych zestawów i dyskretnego podejścia do krawędzi wody. Bliskość Leska zapewnia świetny dojazd, przy jednoczesnym zachowaniu dzikiego, górskiego charakteru linii brzegowej.', 'PZW Krosno');

