-- Spot 359: San - Bykowce
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71359, 'San - Bykowce', 'san-bykowce', 'RIVER', 49.5387637, 22.2441937, 'Podkarpackie', 'Sanok', 'Odcinek w Bykowcach charakteryzuje się naturalnym przebiegiem z licznymi podmywanymi burtami i rynnami wyżłobionymi w twardym, gliniastym podłożu. Pod wodą zalegają liczne powalone drzewa i korzenie, które w marcu 2026 roku stanowią naturalną ostoję dla okazowych kleni i brzan. Spinningiści obławiają tu warkocze prądowe powstające na styku nurtu głównego i spokojniejszych zatoczek brzegowych. Wędkarze spławikowi z sukcesami łowią metodą przepływanki z przytrzymaniem, nęcąc strefy spowolnień nurtu w poszukiwaniu jazi. Uciąg wody jest tu zdecydowany, co sprzyja doskonałemu natlenieniu wody i wysokiej aktywności ryb reofilnych po zimie. Dzikość terenu i utrudniony dostęp do niektórych partii rzeki gwarantują wędkarzowi spokój oraz brak nadmiernej presji.', 'PZW Krosno');

