-- Spot 360: San - Sanok (Miejskie Bystrza)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71360, 'San - Sanok (Bulwary)', 'san-sanok-miejska', 'RIVER', 49.5750264, 22.2010151, 'Podkarpackie', 'Sanok', 'Miejski odcinek Sanu w Sanoku charakteryzuje się uregulowanym brzegiem z technicznie rozmieszczonymi opaskami kamiennymi i wysokimi bulwarami. Dno jest tu twarde, żwirowo-kamienne, z głębokimi rynnami torowymi wymytymi pod mostami i w łukach koryta. W marcu 2026 roku to strategiczne miejsce dla fanów streetfishingu, którzy z sukcesami poławiają tu okonie i pstrągi w cieniu miejskiej infrastruktury. Wędkarze stacjonarni wykorzystują spowolnienia nurtu za filarami, nęcąc stada jazi i rzecznych płoci na lekkie zestawy gruntowe. Uciąg rzeki jest tu stabilny i zdecydowany, co zapewnia wyśmienite warunki tlenowe i wysoką waleczność holowanych ryb. Dobra infrastruktura, parkingi przy rzece i łatwy dostęp czynią Sanok idealnym miejscem na krótkie, techniczne sesje.', 'PZW Krosno');

