INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71369, 'San - Boberka (Źródła)', 'san-boberka-granica', 'RIVER', 49.2210645, 22.7199377, 'Podkarpackie', 'Ustrzyki Górne', 'San w rejonie Boberki to najwyższy, niemal źródliskowy odcinek rzeki, pełniący rolę naturalnego inkubatora dla populacji pstrąga potokowego. W marcu 2026 roku woda jest tu lodowata i krystaliczna, a jej poziom jest silnie uzależniony od bieszczadzkich roztopów z wyższych partii gór. Podłoże wyściela gruby żwir i otoczaki, tworząc idealne warunki dla rozwoju fauny bentosowej, stanowiącej główny pokarm tutejszych ryb łososiowatych. Ze względu na niewielką szerokość koryta, wymagane jest stosowanie technik precyzyjnego podchodu i rzutów zza osłony nadrzecznych olszyn. Uciąg jest gwałtowny i techniczny, co sprzyja doskonaleniu umiejętności prowadzenia nimfy w krótkich, ale głębokich rynnach skalnych. Całkowita izolacja od cywilizacji i bliskość granicy państwa nadają temu miejscu unikalny, niemal pierwotny klimat technicznego wędkarstwa podchodowego.', 'PZW Krosno');

