-- Spot 370: San - Procisne
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71370, 'San - Procisne', 'san-procisne', 'RIVER', 49.2046366, 22.6553994, 'Podkarpackie', 'Lutowiska', 'Odcinek w Procisnem to spektakularne miejsce, gdzie San łączy się z Wołosatym, tworząc szerokie koryto o ogromnym potencjale dla muszkarzy. W marcu 2026 roku, przy wiosennych przyborach, rzeka rzeźbi tu potężne warkocze prądowe, w których stacjonują rekordowe pstrągi i głowacice. Podłoże kamienisto-żwirowe z licznymi uskokami dna wymaga od wędkarza dużej wprawy w brodzeniu i stabilnego podparcia w silnym nurcie. Spinningiści z sukcesami obławiają tutejsze głębokie wanny pod mostem, stosując ciężkie woblery pstrągowe prowadzone agresywnie w poprzek prądu. Uciąg wody jest tu zdecydowany i stały, co zapewnia doskonałe natlenienie łowiska i przekłada się na legendarną waleczność bieszczadzkich ryb. Widok na połoniny i huczący nurt rzeki czynią Procisne jednym z najbardziej kultowych punktów na wędkarskiej mapie polskich Bieszczadów.', 'PZW Krosno');

