-- Spot 371: San - Chmiel
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71371, 'San - Chmiel', 'san-chmiel', 'RIVER', 49.2251244, 22.5939024, 'Podkarpackie', 'Lutowiska', 'San w miejscowości Chmiel to techniczne łowisko o charakterze przełomowym, gdzie rzeka wcina się w skalne podłoże u podnóża Otrytu. W marcu 2026 roku rzeka tworzy tu głębokie rynny brzegowe, które są bankowymi stanowiskami dla lipieni wybudzonych po zimowym przestoju. Podłoże skalno-żwirowe z licznymi progami skalnymi generuje turbulentną wodę, idealną do prezentacji ciężkich nimf i streamerów. Spinningiści muszą wykazać się dużą precyzją, sprowadzając przynęty w wąskie pasma wolniejszego nurtu tuż za naturalnymi barierami skalnymi. Uciąg jest tu bardzo dynamiczny, co wymusza stosowanie mocniejszych zestawów z odpornymi na przetarcia o skały przyponami z fluorocarbonu. Dzikość doliny i brak gęstej zabudowy sprawiają, że Chmiel oferuje wędkarzowi poczucie pełnej swobody i jedności z surowym krajobrazem.', 'PZW Krosno');

