-- Spot 372: San - Zatwarnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71372, 'San - Zatwarnica', 'san-zatwarnica', 'RIVER', 49.2484712, 22.5347619, 'Podkarpackie', 'Lutowiska', 'Odcinek w Zatwarnicy to kraina głębokich, ciemnych rynien i potężnych głazów narzutowych, które rzeźbią nurt Sanu w niezwykle urozmaicony sposób. W marcu 2026 roku rzeka niesie tu sporą dawkę tlenu, co stymuluje pstrągi do intensywnego żerowania na krawędziach najgłębszych bystrzy. Podłoże jest tu twarde, skaliste, z licznymi jamami wyżłobionymi przez wodę, stanowiącymi bezpieczne schronienia dla okazowych głowacic. Muszkarze z sukcesami stosują tu duże, puchate streamery, imitujące drobne ryby przemieszczające się w cieniu prądowym nadrzecznych wiklin. Uciąg wody jest wymagający i zmienny, co czyni Zatwarnicę łowiskiem dla doświadczonych wędkarzy, potrafiących czytać zawirowania prądów. Izolacja tej części Bieszczadów i nieskażona natura doliny Sanu nadają każdemu wędkowaniu w tym miejscu wymiar niemal mistycznego przeżycia.', 'PZW Krosno');

