VALUES (71372, 'Górska', 'Bystra, skalista', 28.0, 1.3, 'Skała i głazy', 'Wanny skalne, bystrza', 'Głowacica, Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- Spot 373: Rega - Smolęcin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71373, 'Rega - Smolęcin', 'rega-smolecin', 'RIVER', 53.8784096, 15.2323622, 'Zachodniopomorskie', 'Gryfice', 'Rega w Smolęcinie to klasyczny odcinek pomorskiej rzeki trociowej o bystrym nurcie i piaszczysto-żwirowym dnie. W marcu 2026 roku rzeka niesie tu podwyższoną, pośniegową wodę, co sprzyja migracji srebrniaków oraz spływającym keltom troci wędrownej. Spinningiści obławiają głębokie rynny na zewnętrznych łukach meandrów, prowadząc ciężkie woblery i wahadłówki w poprzek nurtu. Podmyte burty i powalone drzewa tworzą naturalne spowolnienia, gdzie ryby łososiowate odpoczywają podczas wędrówki pod prąd. Uciąg wody jest bardzo silny, co wymusza stosowanie mocnych wędzisk o ciężarze wyrzutu do 40 gramów oraz plecionek odpornych na przetarcia. Dzikie, zalesione brzegi utrudniają przemieszczanie się, ale gwarantują wędkarzowi kontakt z piękną, pomorską naturą.', 'PZW Szczecin');

