-- Spot 374: Rega - Zdrój
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71374, 'Rega - Zdrój', 'rega-zdroj', 'RIVER', 53.9044042, 15.2195818, 'Zachodniopomorskie', 'Gryfice', 'Odcinek rzeki w miejscowości Zdrój charakteryzuje się głębokimi wcięciami koryta i obecnością długich, twardych rynien torowych. Dno wyścieła gruby żwir i kamienie, co zapobiega mętnieniu wody po wiosennych opadach w marcu 2026 roku. To strategiczne miejsce dla łowców troci, którzy metodycznie "czeszą" głęboczki za pomocą ciężkich błystek obrotowych w rozmiarze 3 i 4. Wędkarze stacjonarni z sukcesami szukają tu dorodnych jazi i kleni, które ustawiają się na krawędziach najsilniejszego prądu. Uciąg rzeki jest tu wybitnie żywy, co zapewnia doskonałe natlenienie wody i przekłada się na morderczą waleczność zaciętych ryb. Strome skarpy brzegowe wymagają od wędkarza dużej ostrożności podczas brodzenia i lądowania wypracowanych okazów.', 'PZW Szczecin');

