-- Spot 375: Rega - Gryfice
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71375, 'Rega - Gryfice (Centrum)', 'rega-gryfice', 'RIVER', 53.9312329, 15.2247553, 'Zachodniopomorskie', 'Gryfice', 'Miejski odcinek Regi w Gryficach został uregulowany, oferując szerokie koryto o twardym dnie i umocnionych, betonowo-kamiennych brzegach. W marcu 2026 roku to jedno z najwygodniejszych łowisk trociowych, gdzie ryby wędrowne zwalniają przed progami wodnymi i zaporami. Fani streetfishingu z powodzeniem obławiają cienie prądowe za filarami mostów, szukając okoni oraz wyrośniętych kleni stacjonujących w nurcie. Wędkarze spławikowi wykorzystują miejskie spowolnienia do łowienia grubych płoci, wchodzących w rzekę na wiosenne tarło. Uciąg wody jest stały i silny, co wymusza stosowanie dociążonych zestawów, by utrzymać przynętę w rynnie torowej. Bulwary miejskie zapewniają doskonały dostęp do lustra wody, czyniąc to miejsce idealnym na szybki, wędkarski wypad po pracy.', 'PZW Szczecin');

