-- Spot 376: Rega - Płoty
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71376, 'Rega - Płoty (Pod Zaporą)', 'rega-ploty', 'RIVER', 53.8008094, 15.2682434, 'Zachodniopomorskie', 'Płoty', 'Odcinek w Płotach posiada techniczny charakter z uwagi na istniejące elektrownie wodne i przepławki, które dynamizują przepływ wody. Poniżej zrzutów tworzą się głębokie, natlenione wanny o dnie wyłożonym kamieniami, stanowiące w marcu 2026 doskonałe kryjówki dla pstrągów potokowych. Spinningiści z sukcesami penetrują tutejsze spienione warkocze, rzucając ciężkimi woblerami imitującymi strzeble i małe płotki. Wędkarze stacjonarni nęcą spokojniejsze zatoczki poniżej bystrzy, celując w stada pięknych jazi i cert. Zmienne przepływy wody wymagają od wędkarzy ciągłego dostosowywania stanowisk i wagi obciążenia do aktualnych warunków. Historyczne zamki w Płotach w tle i szum rwącej wody nadają każdemu wędkowaniu niezwykle urokliwą atmosferę.', 'PZW Szczecin');

