VALUES (71376, 'Górska/Nizinna', 'Zrzutowa, techniczna', 22.0, 2.5, 'Skała i kamień', 'Wanny po-zrzutowe, bystrza', 'Pstrąg potokowy, Kleń, Troć', 'Kraina łososia', false);

-- Spot 377: Rega - Karczewie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71377, 'Rega - Karczewie', 'rega-karczewie', 'RIVER', 53.8275965, 15.2766956, 'Zachodniopomorskie', 'Płoty', 'Rega w Karczewiu meandruje wśród urokliwych lasów i łąk, oferując koryto o niezwykle urozmaiconym, żwirowo-piaszczystym dnie. Rzeka rzeźbi tu głębokie dołki na łukach, które w marcu 2026 roku stają się ostoją dla schodzących do morza keltów troci. Spinningiści stosują tu metodę "wachlarza", starannie przeczesując wahadłówkami całą szerokość rynny głównej. Wędkarze muchowi chętnie obławiają płytsze płanie żwirowe, poszukując pierwszych w sezonie wiosennym aktywnych pstrągów. Uciąg rzeki jest szybki, co zapewnia doskonałą kondycję ryb, ale wymaga od wędkarza umiejętnego poprowadzenia przynęty blisko dna. Wysokie, zadrzewione brzegi chronią przed wiatrem, zapewniając doskonałe warunki do kameralnego łowienia w samotności.', 'PZW Szczecin');

