-- Spot 378: Rega - Barkowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71378, 'Rega - Barkowo', 'rega-barkowo', 'RIVER', 53.8507346, 15.2487322, 'Zachodniopomorskie', 'Gryfice', 'Odcinek rzeki w Barkowie charakteryzuje się szybszym przepływem przez płytkie, kamieniste bystrza i szerokie zakola z twardym dnem. Wiosną 2026 roku krystaliczna woda i silny uciąg stwarzają wymarzone środowisko dla łowców potężnych kleni oraz jazi. Spinningiści z uwagą prowadzą tu mikro-woblery w cieniach prądowych za większymi głazami leżącymi w korycie rzeki. Wędkarze łowiący na grunt wykorzystują strome stoki rynien, by precyzyjnie położyć koszyk z zanętą na ścieżce migracyjnej białorybu. Silny nurt wymusza na wędkarzach brodzących zachowanie wyjątkowej ostrożności, szczególnie po większych opadach deszczu. Dzikość krajobrazu Pomorza i brak gęstej zabudowy czynią Barkowo jednym z najciekawszych łowisk pstrągowo-trociowych w regionie.', 'PZW Szczecin');

