-- Spot 379: Rega - Żukowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71379, 'Rega - Żukowo', 'rega-zukowo', 'RIVER', 53.9956366, 15.2827895, 'Zachodniopomorskie', 'Trzebiatów', 'Rega w okolicach Żukowa to już głęboka, majestatyczna rzeka o nieco wolniejszym nurcie i piaszczysto-gliniastym podłożu. W marcu 2026 roku ten dolny odcinek jest strategicznym punktem spotkań z wchodzącymi z Bałtyku, niezwykle walecznymi srebrniakami. Spinningiści zbroją się tu w mocny sprzęt, obławiając powolne, głębokie zakola dużymi gumami i klasycznymi, trociowymi blachami. Wędkarze stacjonarni z sukcesami łowią tu ciężkim feederem, polując na stada wielkich płoci wędrujących na wiosenne tarliska. Uciąg wody jest umiarkowany i stabilny, co pozwala na bardzo precyzyjne podawanie przynęt blisko stref brzegowych porośniętych trzciną. Otwarty, łąkowy krajobraz ułatwia obserwację rzeki i umożliwia bezproblemowe oddawanie najdalszych rzutów w kierunku nurtu.', 'PZW Szczecin');

