-- Spot 380: Rega - Wlewo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71380, 'Rega - Wlewo', 'rega-wlewo', 'RIVER', 54.0155478, 15.2509061, 'Zachodniopomorskie', 'Trzebiatów', 'Odcinek w miejscowości Wlewo charakteryzuje się prostym przebiegiem koryta, które jest głębokie i poprzecinane stromymi stokami dna. Podłoże jest twarde, żwirowo-piaszczyste, co stanowi doskonałą ścieżkę wędrówkową dla troci w marcu 2026 roku. Spinningiści namierzają tu ryby szukające schronienia pod nawisami traw i w głębokich rynnach, oddając rzuty wzdłuż burt brzegowych. Wędkarze łowiący metodą bolońską z sukcesami przepuszczają tu zestawy, polując na stada cert i jazi wchodzących z estuarium. Uciąg rzeki jest tu bardzo stabilny, a brak licznych zawad podwodnych minimalizuje ryzyko utraty drogocennych przynęt spinningowych. Kameralny charakter tego miejsca oraz sąsiedztwo nadmorskich lasów sprawiają, że Wlewo cieszy się dużą popularnością wśród doświadczonych łowców.', 'PZW Szczecin');

