-- Spot 381: Rega - Skalin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71381, 'Rega - Skalin', 'rega-skalin', 'RIVER', 53.9586209, 15.2492117, 'Zachodniopomorskie', 'Gryfice', 'Rega w Skalinie płynie przez malownicze poldery, tworząc rozległe zakola o bardzo zróżnicowanym dnie i głębokości. Wiosną 2026 roku rzeka wylewa tu na pobliskie łąki, a w głębokim korycie rzeźbią się rynny stanowiące zimowiska dla rzecznych drapieżników. Spinningiści z sukcesami łowią tu szczupaki i okonie, które ustawiają się na krawędziach nurtu głównego i spokojniejszej wody zastoisk. Wędkarze feederowi z pasją nęcą tutejsze płaskie blaty, oczekując na brania grubych rzecznych leszczy i krąpi. Uciąg wody na środku rzeki jest zdecydowany, co wymaga dociążenia zestawów dla bezpiecznego zaprezentowania przynęty. Dzikie brzegi i błotniste dojścia wymagają od wędkarza posiadania woderów, ale nagrodą są doskonałe wyniki połowów w ciszy i samotności.', 'PZW Szczecin');

