-- Spot 382: Rega - Trzebiatów
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71382, 'Rega - Trzebiatów', 'rega-trzebiatow', 'RIVER', 54.0496499, 15.2726086, 'Zachodniopomorskie', 'Trzebiatów', 'Miejski odcinek Regi w Trzebiatowie to szerokie, uregulowane koryto o twardym dnie i stałym, dość silnym uciągu. W marcu 2026 roku to absolutnie strategiczne miejsce, gdzie pierwsze wiosenne srebrniaki wchodzą z pobliskiego Bałtyku w górę rzeki. Wędkarze spinningowi z sukcesami łowią tu na długie wahadłówki, obławiając równy i głęboki nurt miejskiej rynny torowej. Fani metody gruntowej wykorzystują spokojniejsze warkocze za filarami mostów, nęcąc stada dorodnych płoci wchodzących z morza. Uregulowane, wyłożone kamieniem brzegi ułatwiają bezpieczne poruszanie się i komfortowe podbieranie wielkich ryb łososiowych. Historyczna zabudowa Trzebiatowa i rewelacyjny wręcz rybostan czynią to łowisko mekką dla łowców troci z całej Polski i zagranicy.', 'PZW Szczecin');

