VALUES (71382, 'Nizinna Wielka', 'Uregulowana miejska', 45.0, 3.0, 'Beton i żwir', 'Mosty, opaski kamienne', 'Troć wędrowna, Łosoś, Płoć', 'Kraina łososia', true);

-- Spot 383: Rega - Bierzwnica
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71383, 'Rega - Bierzwnica (Górna)', 'rega-bierzwnica', 'RIVER', 53.7316584, 15.895836, 'Zachodniopomorskie', 'Świdwin', 'Górny bieg Regi w okolicach Bierzwnicy ma charakter dzikiego, leśnego strumienia o niezwykle bystrym nurcie i piaszczysto-żwirowym dnie. W marcu 2026 roku to wybitne łowisko pstrągowe, gdzie krystaliczna woda pozwala na skuteczne łowienie techniczne z podchodu. Muszkarze z uwagą prezentują suche muchy i nimfy w cieniach prądowych tworzonych przez licznie powalone do wody korzenie i pnie drzew. Spinningiści prowadzą mikro-woblery wzdłuż podmytych burt, wyciągając z ukrycia agresywnie żerujące, kropkowane drapieżniki. Uciąg jest tu gwałtowny, co wymusza na łowiącym zachowanie ciszy oraz użycie bardzo precyzyjnego i krótkiego wędziska. Leśna izolacja i wąskie koryto nadają temu miejscu intymny, niemal mistyczny klimat zarezerwowany dla największych purystów wędkarskich.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
