-- Spot 384: Rega - Smardzko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71384, 'Rega - Smardzko', 'rega-smardzko', 'RIVER', 53.7588486, 15.8927214, 'Zachodniopomorskie', 'Świdwin', 'Odcinek rzeki w Smardzku wije się wśród pagórkowatych łąk, tworząc głębsze rynny rzeczne wyżłobione w gliniasto-żwirowym podłożu. Wczesną wiosną 2026 roku ten fragment Górnej Regi obfituje w doskonale natlenioną wodę, co wybudza duże pstrągi i klenie z zimowego snu. Spinningiści z sukcesami obławiają strome zakola, podając małe wahadłówki precyzyjnie pod nawisy zeschłych, ubiegłorocznych traw. Wędkarze spławikowi przepuszczają delikatne zestawy wzdłuż rynien torowych, polując na wyrośnięte jelce oraz płocie. Prędkość nurtu jest tu zmienna, co nadaje łowisku charakter techniczny i wymaga od wędkarza umiejętnego czytania zawirowań na lustrze wody. Brak zwartej zabudowy i piękno zachodniopomorskich krajobrazów sprawiają, że każda wyprawa w to miejsce jest głęboko relaksująca.', 'PZW Koszalin');

