-- Spot 385: Rega - Sława
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71385, 'Rega - Sława', 'rega-slawa', 'RIVER', 53.7850693, 15.8815732, 'Zachodniopomorskie', 'Świdwin', 'Rega w okolicach miejscowości Sława płynie szybkim nurtem przez obszary zalesione, formując klasyczne, pstrągowe bystrza i szypoty. Podłoże jest wybitnie twarde, wysłane grubym żwirem i otoczakami, co zapewnia krystaliczną przejrzystość wody w marcu 2026 roku. To terytorium zarezerwowane dla muszkarzy łowiących na "krótką nimfę", precyzyjnie sondujących wymyte jamy za większymi przeszkodami. Spinningiści skradają się pod prąd rzeki, wykorzystując cienie prądowe do zaskoczenia największych kropkowanych drapieżników. Uciąg jest bardzo silny, dlatego brodzenie wymaga rozwagi i dobrego obuwia z filcową podeszwą lub kolcami. Kameralny, dziki charakter tego łowiska to prawdziwy sprawdzian cierpliwości i kunsztu dla miłośników lekkiego rzecznego łowienia.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71385, 'Górska', 'Bystra, żwirowa', 12.0, 1.0, 'Żwir i otoczaki', 'Bystrza, szypoty', 'Pstrąg potokowy, Lipień', 'Kraina pstrąga', false);

-- Spot 386: Rega - Niemierzyno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71386, 'Rega - Niemierzyno', 'rega-niemierzyno', 'RIVER', 53.804428, 15.8497506, 'Zachodniopomorskie', 'Świdwin', 'Odcinek w Niemierzynie charakteryzuje się spokojniejszym przepływem i nieco szerszym korytem z dnem pokrytym drobnym piaskiem i żwirem. Wiosną 2026 roku słońce szybko nagrzewa tu płytsze partie wody, aktywując do żerowania pierwsze w sezonie stada jazi i kleni. Wędkarze spławikowi z sukcesami łowią metodą bolońską, przepuszczając zestawy z czerwonym robakiem wzdłuż widocznego nurtu głównego. Spinningiści przeczesują krawędzie rynien małymi gumami, szukając okoni patrolujących strome spadki piaszczystego dna. Uciąg wody jest tu stabilny i czytelny, co ułatwia precyzyjne podawanie przynęt i skuteczne nęcenie punktowe rzecznych karpiowatych. Dogodny dostęp z okolicznych łąk czyni to miejsce komfortowym również dla starszych wędkarzy poszukujących spokojnego brzegu.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71386, 'Podgórska', 'Naturalna, spokojna', 15.0, 1.4, 'Piasek i żwir', 'Rynny torowe, łachy', 'Jaź, Kleń, Płoć', 'Kraina pstrąga', false);

-- Spot 387: Rega - Bystrzynka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71387, 'Rega - Bystrzynka', 'rega-bystrzynka', 'RIVER', 53.8159263, 15.8070692, 'Zachodniopomorskie', 'Świdwin', 'Rega pod Bystrzynką to niezwykle urokliwy odcinek rzeki pełen powalonych drzew, które tworzą labirynt naturalnych, podwodnych kryjówek. Dno jest tu zmienne, z głębokimi, gliniastymi dołami wymytymi przez nurt wokół zatopionych systemów korzeniowych. Marzec 2026 roku to doskonały czas na polowanie na szczupaki, które przed okresem ochronnym zajmują tu najlepsze stanowiska łowieckie. Spinningiści zbroją się w mocne plecionki, łowiąc metodą opadu na duże silikonowe przynęty precyzyjnie omijające gęste zaczepy. Prędkość prądu rzeki oscyluje tu od wartkiego w nurcie po niemal stojącą wodę w rozległych zastoiskach zatorowych. Pokonanie brzegów porośniętych zaroślami wymaga determinacji, lecz nagrodą jest łowisko nietknięte nadmierną presją wędkarską.', 'PZW Koszalin');

