VALUES (71387, 'Podgórska', 'Dzika, zatarasowana', 16.0, 1.8, 'Glina i piasek', 'Zwalone drzewa, zatory', 'Szczupak, Pstrąg potokowy, Okoń', 'Kraina pstrąga', false);

-- Spot 388: Rega - Krosino
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71388, 'Rega - Krosino', 'rega-krosino', 'RIVER', 53.7953419, 15.7738739, 'Zachodniopomorskie', 'Świdwin', 'Odcinek rzeki w miejscowości Krosino to szerokie, płytkie meandry o bardzo twardym, wyścielonym grubym kamieniem i żwirem dnie. W marcu 2026 roku świetnie natleniona woda z wiosennych przyborów przyciąga tu lipienie, które aktywnie oczkują na powierzchni. To rajskie miejsce dla zwolenników suchej muchy, którzy przy bezwietrznej pogodzie potrafią wypracować tu kilkanaście brań podczas jednej sesji. Spinningiści wykorzystują błystki obrotowe typu "long", prowadząc je wolno pod prąd z nadzieją na uderzenie walecznego pstrąga. Uciąg wody jest zdecydowany, co na równej płani pozwala na świetne czytanie wody i szybkie namierzanie rybich stanowisk. Niska mętność rzeki oraz szerokie na kilkanaście metrów koryto czynią Krosino doskonałym miejscem do treningu rzutów muchowych.', 'PZW Koszalin');

