VALUES (71388, 'Górska', 'Szeroka, płytka', 18.0, 0.9, 'Kamień i żwir', 'Płanie żwirowe, bystrza', 'Lipień, Pstrąg potokowy, Kleń', 'Kraina pstrąga', false);

-- Spot 389: Rega - Świdwin
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71389, 'Rega - Świdwin (Centrum)', 'rega-swidwin-miejska', 'RIVER', 53.7682788, 15.7664008, 'Zachodniopomorskie', 'Świdwin', 'Miejski odcinek Regi w Świdwinie to interesujące połączenie dzikiej rzeki z cywilizacją, gdzie woda płynie w uregulowanym, kamiennym korycie. W marcu 2026 roku pod mostami i przepławkami gromadzą się ryby łososiowate, szukające tlenu w najszybszych partiach miejskiego nurtu. Fani lekkiego streetfishingu z powodzeniem uganiają się tu za pstrągami, wykorzystując miejskie mostki jako dogodne punkty rzutowe. Wędkarze spławikowi nęcą wąskie kanały w poszukiwaniu świnek oraz jelców, które licznie występują w tym zasobnym odcinku rzeki. Stabilny i szybki przepływ wymusza stosowanie dociążonych zestawów, a twarde brzegi gwarantują bezpieczne i wygodne wędkowanie w każdym obuwiu. To doskonałe łowisko na szybki, spontaniczny trening wędkarski bez konieczności opuszczania granic miasta.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71389, 'Podgórska', 'Uregulowana miejska', 14.0, 1.3, 'Beton i żwir', 'Mosty, sztuczne progi', 'Pstrąg potokowy, Jelec, Kleń', 'Kraina pstrąga', false);

-- Spot 390: Rega - Gola Dolna
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71390, 'Rega - Gola Dolna', 'rega-gola-dolna', 'RIVER', 53.7501527, 15.7308064, 'Zachodniopomorskie', 'Świdwin', 'Rega na wysokości Goli Dolnej wkracza w obszar zalesiony, tworząc niezwykle dzikie i głębokie wcięcia w gliniastym podłożu. Rzeka rzeźbi tu ciemne, tajemnicze rynny brzegowe, w których w marcu 2026 roku ukrywają się największe sztuki pstrąga potokowego. Spinningiści muszą wykazać się tu niesamowitym kunsztem rzutowym, omijając gęste korony drzew zwieszające się bezpośrednio nad rwącym nurtem. Muszkarze decydują się na technikę streamera, ściągając duże imitacje rybek prosto w paszcze drapieżników stacjonujących pod wymytymi burtami. Uciąg wody jest szybki, a częste zmiany głębokości wymagają ciągłej analizy i adaptacji taktyki do zmieniających się przed wędkarzem warunków. To łowisko dla wędkarskich samotników, którzy w zamian za trud przedzierania się przez puszczę, otrzymują szansę na rybę życia.', 'PZW Koszalin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71390, 'Górska', 'Erozyjna, leśna', 12.0, 1.6, 'Glina i żwir', 'Podmyte burty, głębokie doły', 'Pstrąg potokowy, Szczupak', 'Kraina pstrąga', false);

-- Spot 391: Rega - Słonowice Kolonia
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71391, 'Rega - Słonowice Kolonia', 'rega-slonowice', 'RIVER', 53.7280214, 15.6992198, 'Zachodniopomorskie', 'Świdwin', 'Rega w Słonowicach to malowniczy, dziki odcinek o bystrym nurcie i wybitnie żwirowym dnie poprzecinanym zwalonymi drzewami. W marcu 2026 roku świetnie natleniona, chłodna woda przyciąga tu wyrośnięte pstrągi potokowe szukające kryjówek pod wymytymi burtami. Spinningiści z sukcesami penetrują strefy cienia prądowego, prowadząc mikro-woblery i jigi imitujące drobne ryby denne. Muszkarze wykorzystują technikę nimfy, sondując najgłębsze, dwumetrowe rynny na zakrętach koryta. Uciąg jest tu zdecydowany, co wymusza stosowanie mocniejszych przyponów zapobiegających przetarciom o podwodne korzenie. Leśny, trudno dostępny charakter brzegu zapewnia wędkarzowi pełną izolację i gwarantuje brak nadmiernej presji.', 'PZW Koszalin');

