VALUES (71391, 'Górska', 'Dzika, zatarasowana', 12.0, 1.4, 'Żwir i kamień', 'Zwalone drzewa, rynny', 'Pstrąg potokowy, Lipień, Kleń', 'Kraina pstrąga', false);

-- Spot 392: Rega - Worowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71392, 'Rega - Worowo', 'rega-worowo', 'RIVER', 53.7168161, 15.6572737, 'Zachodniopomorskie', 'Łobez', 'Odcinek rzeki w Worowie wije się wśród zalesionych pagórków, tworząc głębokie na ponad półtora metra wanny erozyjne. Podłoże jest twarde, piaszczysto-żwirowe, co w marcu 2026 roku stwarza idealne warunki dla wczesnowiosennych łowców kleni i pstrągów. Spinningiści precyzyjnie posyłają niewielkie przynęty gumowe w strefy spowolnień za powalonymi pniami dębów i olch. Wędkarze spławikowi z powodzeniem przepuszczają zestawy z czerwonym robakiem, polując na wygłodniałe jelce. Zmienny, pulsujący uciąg wody uczy pokory i wymaga doskonałego czytania rzeki z brzegu. Brak dróg dojazdowych bezpośrednio pod wodę chroni to łowisko przed kłusownikami i gwarantuje ciszę.', 'PZW Szczecin');

