-- Spot 393: Rega - Łobez
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71393, 'Rega - Łobez (Wschód)', 'rega-lobez-wschod', 'RIVER', 53.6977371, 15.6247762, 'Zachodniopomorskie', 'Łobez', 'Wschodnie obrzeża Łobza to rzeka o wyraźnym spadku, gdzie woda przyspiesza na płytkich, kamienistych bystrzach. W marcu 2026 r. nurt jest tu bardzo silny, wymywając głębokie jamy, w których gromadzą się pokaźne pstrągi potokowe. Spinningiści aktywnie brodzą, podając woblery pod prąd i pozwalając im naturalnie spływać w kierunku stanowisk ryb. Wędkarze używający przepływanki nęcą spokojniejsze rynny, celując w rzeczne płocie i klenie. Uciąg wymaga od wędkarzy stosowania cięższych przynęt, by te mogły spenetrować warstwy przydenne. Urokliwe położenie na skraju miasta łączy łatwy dojazd z urokami dzikiej, górskiej rzeki.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71393, 'Górska', 'Bystra, kamienista', 15.0, 1.2, 'Kamień i żwir', 'Bystrza, jamy', 'Pstrąg potokowy, Kleń, Płoć', 'Kraina pstrąga', false);

-- Spot 394: Rega - Jaźwiny
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71394, 'Rega - Jaźwiny', 'rega-jazwiny', 'RIVER', 53.7021993, 15.9735887, 'Zachodniopomorskie', 'Świdwin', 'Górny odcinek Regi w Jaźwinach to wąski, bardzo techniczny ciek płynący w leśnym wąwozie o gliniasto-żwirowym podłożu. W marcu 2026 roku zimna woda i duże zacienienie sprawiają, że pstrągi reagują tu wyłącznie na bardzo precyzyjnie podane przynęty. Muszkarze operują tu na krótkim dystansie, wymachując między gałęziami, by podać nimfę dokładnie za zwalony pień. Spinningiści używają wędzisk do 2 metrów, łowiąc metodą "spod kija" w najtrudniejszych technicznie miejscówkach. Uciąg jest stabilny, ale rzeka pełna jest zdradliwych dołków. Absolutna dzikość tego miejsca sprawia, że jest to rewir wyłącznie dla wytrawnych eksploratorów.', 'PZW Koszalin');

