VALUES (71394, 'Górska', 'Wąska, zatarasowana', 7.0, 0.8, 'Glina i żwir', 'Zwalone drzewa, wąwozy', 'Pstrąg potokowy', 'Kraina pstrąga', false);

-- Spot 395: Rega - Polakowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71395, 'Rega - Polakowo', 'rega-polakowo', 'RIVER', 53.673786, 15.6458659, 'Zachodniopomorskie', 'Łobez', 'Rega pod Polakowem rozszerza się nieznacznie, formując piaszczysto-żwirowe płanie i głębokie, spokojniejsze zakola. Wczesną wiosną 2026 r. nagrzewająca się na płyciznach woda wyciąga z ukrycia duże stada jelców i kleni. Spinningiści obławiają granice bystrego nurtu i spokojnej wody, gdzie drapieżniki czekają na niesiony prądem pokarm. Wędkarze stacjonarni z powodzeniem łowią tu na picker, podając lekkie koszyki w wymyte rynienki. Przepływ rzeki jest tu urozmaicony, dając wędkarzowi pole do stosowania zróżnicowanych technik. Zmienna linia brzegowa oferuje zarówno zalesione skarpy, jak i łagodne łąkowe zejścia do wody.', 'PZW Szczecin');

