-- Spot 396: Rega - Łobez (Południe)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71396, 'Rega - Łobez (Południe)', 'rega-lobez-poludnie', 'RIVER', 53.6477821, 15.6325751, 'Zachodniopomorskie', 'Łobez', 'Południowy odcinek pod Łobzem to rzeka szybka, z dużą ilością twardych, kamienistych raf i progów wymuszających turbulencje. W marcu 2026 roku te świetnie natlenione odcinki są głównym rejonem żerowania pstrągów potokowych po tarle. Wędkarze muchowi stosują tu mokrą muchę i streamera, rzucając w poprzek silnego prądu. Spinningiści używają cięższych obrotówek prowadzonych tuż nad dnem. Ze względu na silny uciąg, brodzenie wymaga filcowych podeszw lub kolców. Wygodny dojazd z miasta czyni ten odcinek świetnym miejscem na kilkugodzinne sesje pstrągowe.', 'PZW Szczecin');

