-- Spot 397: Rega - Łobez (Zachód)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71397, 'Rega - Łobez (Zachód)', 'rega-lobez-zachod', 'RIVER', 53.6242742, 15.6090083, 'Zachodniopomorskie', 'Łobez', 'Zachodnie wyjście Regi z Łobza to teren podmokłych łąk, gdzie rzeka wycina głębokie, gliniaste rynny pod stromymi burtami. Marzec 2026 roku przynosi tu doskonałe wyniki w połowie grubych kleni, które stacjonują w cieniu podmytych traw i korzeni. Spinningiści wypuszczają woblery smużące wzdłuż brzegów, prowokując ryby do agresywnych ataków z dołu. Fani klasycznej przepływanki nęcą głęboczki, polując na zimowe jeszcze stada płoci i jazi. Woda rwie tu mocno środkiem, tworząc z boku idealne zastoiska buforowe. Rozległe przestrzenie pozwalają na długie rzuty i wygodne śledzenie spływającego spławika.', 'PZW Szczecin');

