-- Spot 398: Rega - Unimie
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71398, 'Rega - Unimie', 'rega-unimie', 'RIVER', 53.6407533, 15.5727593, 'Zachodniopomorskie', 'Łobez', 'Rega pod Unimiem to esencja dzikiej rzeki: meandruje wśród starodrzewu, pełna zwalonych pni, zatorów i wymytych dołów. W marcu 2026 r. to trudne technicznie, ale niezwykle rybne łowisko pstrągowe, pełne miejscówek niedostępnych z marszu. Spinningiści tracą tu wiele przynęt, jednak ryzyko opłaca się w postaci uderzeń okazowych pstrągów potokowych spod zawad. Wędkarze stacjonarni odnajdują tu malutkie płanie, by zapolować na wczesne okonie i płocie. Zmienny uciąg, od rwących bystrzy po całkowicie stojące baseny, wymusza ciągłą rotację sprzętu. To rewir dla samotników kochających przedzieranie się przez chaszcze z wędką.', 'PZW Szczecin');

