-- Spot 399: Rega - Przyborze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71399, 'Rega - Przyborze', 'rega-przyborze', 'RIVER', 53.6674296, 15.5644954, 'Zachodniopomorskie', 'Łobez', 'Odcinek rzeki w Przyborzu to szerokie zakola z podłożem piaszczysto-żwirowym i głębokimi rynnami sięgającymi dwóch metrów. Wczesną wiosną 2026 r. woda po roztopach niesie tędy dużo pokarmu, gromadząc stada jazi i kleni w spowolnieniach nurtu. Spinningiści z sukcesami penetrują stoki rynien gumowymi jaskółkami i twisterami. Wędkarze spławikowi, z pomocą metody bolońskiej, dosięgają najdalszych rynien, utrzymując przynętę tuż nad dnem. Płynący tu bystry, zimny prąd rzeki zapewnia rybom odpowiednie natlenienie, gwarantując sportowe emocje przy holu. Łagodne brzegi sprzyjają wędkowaniu rodzinnemu i wygodnemu rozbiciu obozowiska.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71399, 'Podgórska', 'Meandrująca, żwirowa', 20.0, 1.8, 'Żwir i piasek', 'Rynny, zakola', 'Jaź, Kleń, Płoć', 'Kraina pstrąga', false);

-- Spot 400: Rega - Przyborze (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71400, 'Rega - Przyborze (Północ)', 'rega-przyborze-polnoc', 'RIVER', 53.694351, 15.5601592, 'Zachodniopomorskie', 'Łobez', 'Północny fragment w Przyborzu przechodzi w bardziej uregulowany charakter z kamiennymi opaskami chroniącymi zalesione skarpy. Marzec 2026 roku stwarza tu dogodne warunki na pierwsze wiosenne szczupaki oraz dorodne pstrągi potokowe. Spinningiści aktywnie obławiają krawędzie kamiennych umocnień, rzucając woblery równolegle do brzegu. Uciąg wody jest bardzo szybki, co zmusza wędkarzy do używania cięższych główek jigowych. Woda na tym odcinku szybko się oczyszcza po deszczach, dając przewagę łowcom spinningowym. Brzegi bywają tu strome, a poruszanie się po śliskich kamieniach wymaga odpowiedniego obuwia.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71400, 'Podgórska', 'Uregulowana, bystra', 22.0, 2.0, 'Kamień i żwir', 'Opaski kamienne, bystrza', 'Pstrąg potokowy, Szczupak, Kleń', 'Kraina pstrąga', false);

-- Spot 401: Rega - Karwowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71401, 'Rega - Karwowo', 'rega-karwowo', 'RIVER', 53.7189559, 15.5410265, 'Zachodniopomorskie', 'Łobez', 'Rega pod Karwowem zwalnia bieg, rozlewając się na malowniczych, leśnych łąkach z twardym, piaszczysto-żwirowym dnem. Wiosną 2026 roku słońce nagrzewa płycizny, przyciągając liczne owady, a za nimi – potężne klenie i lipienie. Muszkarze chętnie brodzą wzdłuż rzeki, posyłając mokrą muchę lub nimfę w okolice żwirowych garbów. Spinningiści stawiają tu na mikro-obrotówki w miedzianych odcieniach, precyzyjnie przeczesując warkocze prądowe. Rzeka jest tu płytsza, co ułatwia czytanie wody, ale wymusza niezwykle dyskretne zachowanie na brzegu. Doskonały punkt dla estetów wędkarskich, ceniących ciszę i piękne krajobrazy Pomorza Zachodniego.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71401, 'Górska', 'Szeroka, płytka', 25.0, 1.0, 'Żwir i piasek', 'Płanie, żwirowe garby', 'Kleń, Lipień, Pstrąg potokowy', 'Kraina pstrąga', false);

-- Spot 402: Rega - Łagiewniki
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71402, 'Rega - Łagiewniki', 'rega-lagiewniki', 'RIVER', 53.7429363, 15.5200162, 'Zachodniopomorskie', 'Resko', 'Odcinek w Łagiewnikach to głęboka rynna wyżłobiona w gliniastym podłożu, otoczona stromymi brzegami porośniętymi starodrzewem. W marcu 2026 r. to strategiczna ostoja dla troci wędrownych oraz potężnych pstrągów potokowych, kryjących się pod zwalonymi konarami. Spinningiści zbroją się tu w mocny sprzęt, by siłowo odciągać zacięte drapieżniki od gąszczu podwodnych korzeni. Wędkarze łowiący białoryb nęcą głęboczki, przygotowując się na brania dorodnych jazi i płoci. Uciąg jest stabilny, potężny, co wymaga obciążeń potrafiących przebić się przez zawirowania powierzchniowe. Teren podmokły i bagienny wczesną wiosną wymaga wysokich woderów i doskonałej sprawności fizycznej.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71402, 'Nizinna Wielka', 'Erozyjna, głęboka', 26.0, 2.4, 'Glina i piasek', 'Podmyte korzenie, jamy', 'Troć wędrowna, Pstrąg potokowy, Jaź', 'Kraina łososia', false);

-- Spot 403: Rega - Sosnowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71403, 'Rega - Sosnowo', 'rega-sosnowo', 'RIVER', 53.7591572, 15.4830392, 'Zachodniopomorskie', 'Resko', 'Rega przepływa tu przez piaszczyste tereny zalesione, formując klasyczne, łososiowe przykosy i szerokie, twarde płanie. W marcu 2026 roku to jedno z najlepszych łowisk keltów troci, schodzących do Bałtyku z tarlisk. Wędkarze spinningowi prowadzą ciężkie wahadłówki z prądem rzeki, pozwalając im swobodnie spływać po żwirowym dnie. Muszkarze operują ciężkimi, dwuręcznymi wędkami typu switch, rzucając tubowymi muchami (tzw. tubami) w najdalsze rynny. Głęboki i zimny nurt niesie wodę o potężnej sile nośnej, co generuje mordercze hole i spektakularne odjazdy ryb. Szerokie brzegi ułatwiają operowanie długimi wędkami i wygodne podebranie zdobyczy.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71403, 'Nizinna Wielka', 'Szeroka, trociowa', 28.0, 2.0, 'Żwir i piasek', 'Przykosy, rynny torowe', 'Troć wędrowna, Łosoś, Pstrąg', 'Kraina łososia', false);

-- Spot 404: Rega - Prusim
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71404, 'Rega - Prusim', 'rega-prusim', 'RIVER', 53.7702708, 15.4409448, 'Zachodniopomorskie', 'Resko', 'Odcinek rzeki w Prusimiu wije się majestatycznie przez bagniste łąki, a dno charakteryzuje się licznymi dołkami i piaszczystymi łachami. Marzec 2026 r. budzi tu do życia stada dorodnych jazi i wczesnych płoci, które szukają ochłody i tlenu w nurcie głównym. Wędkarze gruntowi stosują precyzyjny feeder rzeczny, celując koszykiem dokładnie na skarpę piaszczystej przykosy. Spinningiści uganiają się tu za wymiarowymi okoniami, przeczesując spowolnienia na wewnętrznych łukach koryta. Uciąg jest tu umiarkowany, stwarzając bardzo dobre warunki do rekreacyjnego łowienia bez ciężkiego ekwipunku. To spokojne, ciche miejsce, w którym wędkarz szybko regeneruje siły z dala od ruchliwych szos.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71404, 'Nizinna Wielka', 'Naturalna, piaszczysta', 30.0, 1.8, 'Piasek', 'Mielizny, rynienki', 'Jaź, Płoć, Okoń', 'Kraina łososia', true);

-- Spot 405: Rega - Resko
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71405, 'Rega - Resko', 'rega-resko', 'RIVER', 53.7725826, 15.3949838, 'Zachodniopomorskie', 'Resko', 'Miejski odcinek w Resku to sztandarowe pomorskie łowisko trociowe z uregulowanym korytem, opaskami i systemem przepławek. Wiosną 2026 r. zapora w mieście gromadzi potężne stada troci wędrownych i łososi, które zwalniają bieg przed przeszkodą. Spinningiści obstawiają każdy metr brzegu poniżej elektrowni, podając woblery i jigi w gęstą, spienioną wodę. Wędkarze stacjonarni nęcą z betonowych bulwarów, polując na grubą rzeczną płoć i certę metodą przepływanki. Szybki nurt wymusza na wędkarzach żelazną dyscyplinę holu, by ryba nie wykorzystała siły wody do ucieczki. Miejska infrastruktura to raj dla tych, którzy cenią dostępność i wygodę połączoną z szansą na życiowe okazy.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71405, 'Nizinna Wielka', 'Zrzutowa, miejska', 32.0, 2.5, 'Kamień i beton', 'Zapora, wanny po-zrzutowe', 'Troć wędrowna, Łosoś, Płoć', 'Kraina łososia', false);

-- Spot 406: Rega - Trzaski
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71406, 'Rega - Trzaski', 'rega-trzaski', 'RIVER', 53.7571066, 15.3569639, 'Zachodniopomorskie', 'Gryfice', 'Rega pod Trzaskami staje się szeroką, nizinną autostradą pełną powalonych drzew brzegowych i długich, prostych odcinków. W marcu 2026 r. głębokie na ponad dwa metry rynny obfitują w stada szczupaków, które ustawiają się tu przed okresem ochronnym na wiosenny żer. Spinningiści prowadzą duże gumy i woblery w strefie przydennej, starając się sprowokować ryby przebywające w głębokim letargu. Wędkarze feederowi rzucają na spokojną wodę za zaporami z gałęzi, kusząc potężne leszcze. Powolny, równy prąd wody pozwala na łowienie przy użyciu lżejszych koszyków zanętowych. Teren bywa grząski, ale oferuje doskonałe punkty widokowe z wysokich, zarośniętych klifów.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71406, 'Nizinna Wielka', 'Szeroka, meandrująca', 34.0, 2.2, 'Piasek i glina', 'Zwalone drzewa, jamy', 'Szczupak, Leszcz, Okoń', 'Kraina łososia', true);

-- Spot 407: Rega - Żerzyno
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71407, 'Rega - Żerzyno', 'rega-zerzyno', 'RIVER', 53.751092, 15.3122111, 'Zachodniopomorskie', 'Gryfice', 'Odcinek w Żerzynie wyróżnia się licznymi piaszczystymi przykosami i wypłyceniami, w których woda przyspiesza na żwirowym podłożu. W marcu 2026 r. rzeka nanosi tu wiele materiału, formując idealne tarliska i żerowiska dla certy i klenia. Wędkarze muchowi chętnie obławiają granicę prądu i spokojnej wody, używając tonących linek. Spinningiści stawiają na małe, agresywne błystki w odcieniach złota i srebra, polując na ryby łososiowate zmierzające do morza. Stały prąd rzeki i przejrzystość zachęcają do brodzenia, ale wymaga to dużego doświadczenia ze względu na ostre spadki dna. Krajobraz łąk i pól to relaksująca odskocznia od twardych, betonowych opasek rzecznych w miastach.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71407, 'Nizinna Wielka', 'Szeroka, piaszczysta', 35.0, 1.8, 'Piasek i żwir', 'Przykosy, płanie', 'Troć wędrowna, Kleń, Certa', 'Kraina łososia', true);

-- Spot 408: Rega - Lisowo
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71408, 'Rega - Lisowo', 'rega-lisowo', 'RIVER', 53.7627784, 15.2675223, 'Zachodniopomorskie', 'Gryfice', 'Rega w Lisowie to długa, prosta rynna torowa ograniczona wysokimi burtami i rzadkimi, starymi drzewami liściastymi. Wiosną 2026 r. to strategiczne stanowisko dla wędkarzy polujących na grube, wędrowne trocie, które odpoczywają w tutejszych głębinach. Spinningiści stosują długie i precyzyjne rzuty, by przepuścić przynętę nad całym, głębokim na prawie 3 metry korytem. Wędkarze preferujący method feeder łowią tu potężne leszcze, ustawiając się na wewnętrznym, płytszym łuku meandra. Uciąg jest równy i umiarkowany, co w połączeniu z twardym dnem daje znakomite warunki techniczne. Dostępność stanowisk jest wyśmienita, co przyciąga łowców stawiających na wygodę i wielogodzinne zasiadki.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71408, 'Nizinna Wielka', 'Uregulowana, głęboka', 36.0, 2.8, 'Glina i żwir', 'Rynny torowe, burty', 'Troć wędrowna, Leszcz, Szczupak', 'Kraina łososia', true);

-- Spot 409: Rega - Trzebiatów (Północ)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71409, 'Rega - Trzebiatów (Północ)', 'rega-trzebiatow-polnoc', 'RIVER', 54.0738142, 15.2505156, 'Zachodniopomorskie', 'Trzebiatów', 'Wylot rzeki na północ od Trzebiatowa to szerokie, pogłębione koryto, będące bezpośrednim korytarzem do ujścia w morzu. W marcu 2026 r. odbywa się tu główna migracja potężnych łososi i srebrniaków, wchodzących z Bałtyku w poszukiwaniu rzecznych tarlisk. Wędkarze spinningowi zbroją się w najmocniejszy sprzęt, prowadząc ciężkie, 30-gramowe wahadłówki z nurtem. Fani przepływanki z przystawką zasadzają się na stada grubych płoci, nęcąc strome stoki rynien pod samymi brzegami. Woda rwie tu mocno i gwałtownie, mieszając się czasami z morską cofką podczas silnych, północnych wiatrów. Betony i opaski brzegowe gwarantują bezpieczne podbieranie największych rzecznych trofeów w iście marynistycznym klimacie.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71409, 'Nizinna Wielka', 'Estuariowa, głęboka', 45.0, 3.5, 'Piasek i kamień', 'Rynny nawigacyjne, opaski', 'Troć wędrowna, Łosoś, Płoć', 'Kraina łososia', true);

-- Spot 410: Rega - Włodarka
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71410, 'Rega - Włodarka', 'rega-wlodarka', 'RIVER', 54.09732, 15.2272865, 'Zachodniopomorskie', 'Trzebiatów', 'Rega pod Włodarką płynie leniwie, szeroko i głęboko, nabierając niemal jeziorowego charakteru w bezpośredniej bliskości wybrzeża. W marcu 2026 r. słonawe prądy denne przynoszą stada morskich ryb wchodzących w rzekę, zmuszając drapieżniki do aktywnego żeru. Spinningiści polują tu na szczupaki, używając dużych, naturalnych gum prowadzonych bardzo wolno przy samym, mulistym dnie. Gruntowcy wyciągają potężne leszcze, krąpie i płocie, stosując dalekie rzuty ciężkim feederem z ciężarkiem rurkowym. Woda płynie powoli, co pozwala na odpoczynek od ciężkich, rzecznych zestawów, dając pole do finezyjnej zabawy z wędką. To łowisko dla ceniących spokój na szerokiej wodzie, gdzie morska bryza miesza się z rzecznym zapachem wilgoci.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71410, 'Nizinna Wielka', 'Szeroka, leniwa', 50.0, 3.8, 'Muł i piasek', 'Głębokie doły, łachy', 'Szczupak, Leszcz, Płoć', 'Kraina łososia', true);

-- Spot 411: Rega - Trzebusz
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71411, 'Rega - Trzebusz', 'rega-trzebusz', 'RIVER', 54.1209154, 15.2496247, 'Zachodniopomorskie', 'Trzebiatów', 'Odcinek estuaryjny w rejonie Trzebusza charakteryzuje się brakiem wyraźnego uciągu i mieszaniem wód śródlądowych z morskimi. Marzec 2026 roku obfituje tu w wejścia wędrownych ryb, a miejscowe głęboczki, sięgające nawet 4 metrów, są doskonałym krygowiskiem sandaczy. Spinningiści pracują metodą opadu, używając jaskrawych kogutów i ciężkich jigów do penetracji najtwardszych struktur dennych. Wędkarze stacjonarni łowią okazałe okonie na filecik lub rosówkę, nęcąc przybrzeżne stoki i zatoczki chroniące przed falowaniem. Uciąg jest niemal niewyczuwalny, o ile nie występuje silna cofka sztormowa wtłaczająca masy wody z Bałtyku w koryto rzeki. Trzciny brzegowe i portowy klimat zwiastują bliskość morza, dając niezapomniane, pomorskie emocje.', 'PZW Szczecin');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71411, 'Nizinna Wielka', 'Estuariowa, głęboka', 55.0, 4.0, 'Muł i piasek', 'Stoki dna, zastoiska', 'Sandacz, Okoń, Troć wędrowna', 'Kraina łososia', true);

-- Spot 412: Rega - Mrzeżyno (Estuarium)
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71412, 'Rega - Mrzeżyno (Ujście)', 'rega-mrzezyno', 'RIVER', 54.139212, 15.2848251, 'Zachodniopomorskie', 'Trzebiatów', 'Wielki finał Regi – ujście rzeki do Morza Bałtyckiego w mrzeżyńskim porcie, otoczone potężnymi, betonowymi falochronami. W marcu 2026 roku to strategiczny rewir łowców belon i morskich troci, które gromadzą się wokół główek portowych. Spinningiści wykonują ekstremalnie dalekie rzuty ciężkimi pilkerami i błystkami, przeczesując styk nurtu rzecznego i fal morskich. Gruntowcy z powodzeniem polują tu na stada fląder i grubych śledzi, używając specjalistycznych zestawów surfcastingowych z ciężarkami z wąsami. Dynamika wody jest zależna całkowicie od wiatru – silna cofka tworzy ryczące warkocze, a flauta zamienia ujście w wielkie jezioro. Surowość betonowych nabrzeży zrekompensowana jest potężną siłą wędrownych ryb, dających mordercze hole w morskich warunkach.', 'Morskie Wody Wewnętrzne (OIRM)');

INSERT INTO map_rivers (id, river_type, channel_character, avg_width, avg_depth, bottom_type, water_structures, dominant_species, fish_region, boat_fishing_allowed)
VALUES (71412, 'Estuarium', 'Morska, portowa', 60.0, 5.0, 'Piasek', 'Falochrony, główki portowe', 'Troć wędrowna, Flądra, Śledź', 'Wody przymorskie', true);

-- Spot 413: Rega - Przyrzecze
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) 
VALUES (71413, 'Rega - Przyrzecze', 'rega-przyrzecze', 'RIVER', 53.6873011, 15.9041775, 'Zachodniopomorskie', 'Świdwin', 'Górny odcinek Regi powracający do swych korzeni pod Przyrzeczem to wartki strumień wycinający głębokie rynny w polodowcowym żwirze. Wiosną 2026 r. zimna woda z roztopów idealnie natlenia bystrza, kumulując potężne pstrągi potokowe pod burtami porośniętymi wysoką trawą. Muszkarze rzucają tu suchą muchą, oczekując na nagłe, widowiskowe "oczka" ryb zbierających wylęgające się owady. Spinningiści przeczesują małe, metrowe rynny leciutkimi jigami, stosując wędki o czułości pozwalającej wyczuć dotknięcie dna. Wartki nurt rzeki wypłukuje osady, odsłaniając jasny kamień i piasek, czyniąc ten odcinek wyjątkowo urokliwym wizualnie. Wędkarstwo w tym miejscu to czysta technika i dyskrecja – nieodpowiedni ruch na brzegu gwarantuje ucieczkę najbardziej płochliwych kropkowańców.', 'PZW Koszalin');

